INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (31,64,NULL,'Sandra',NULL,NULL,NULL,'Bonjour, je pense souffrir de phobie d’impulsion concernant la peur de vouloir me suicider … \n\nCela se traduit par des pensées obsessionnelles à longueur de journée, mais également d’impression de vouloir le faire et une impression de ne plus vouloir vivre c’est hyper horrible… \n\nJ’ai des moments de 2 secs de mieux, mais très vite les vilaines sensations reviennent et nous refont du mal.. \n\nSavez vous expliquer c’est quoi ces sensations de vivre au final comme qqn de suicidaire ? Ou je n’arrive pas à imaginer ma vie dans un futur proche.. \n\nLorsque j’ai une pensée je ne sais pas la laisser passer… c’est plus fort que moi… \n\nPouvez vous me répondre par mail? ????\n\nBien à vous\n\nSandra','approved','2022-09-18 10:46:30',NULL,'2026-05-24 19:21:38','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (32,64,33,'Laura B.',NULL,NULL,NULL,'Bonjour Anne, \n\nJe vous ai répondu sur votre boîte mail.','approved','2022-08-22 16:18:26',NULL,'2026-05-24 19:21:38','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (33,64,NULL,'Degroote',NULL,NULL,NULL,'Bonjour, j ai eu des phobies d impulsion pendant des années qui se sont déclenchées suite à un bad trip.(peur extrême de mourir) . J ai pris du zoloft qui a du me faire du bien, il y a longtemps.. En 2011 ma fille est née et a nouveaux phobie d impulsion qui se sont résorbées. En effet, j ai eu une éducation autoritaire et des valeurs très fortes..\n\nMaintenant, j ai développé d autres peurs comme la peur des maladies incurables et autres. En fait, je passe d une angoisse à une autre.. Je vais tenter l emdr bientôt.. Pensez vous que le traumatisme vécu avec le bad trip peut expliquer mes maux.. Est ce que l emdr peut m aider alors que l événement a eu lieu en 2002 /2003..merci pour votre réponse','approved','2022-08-22 15:22:13',NULL,'2026-05-24 19:21:38','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (34,64,35,'Laura B.',NULL,NULL,NULL,'Bonjour Laura, \n\nJe vous ai répondu sur votre boîte mail.','approved','2022-06-13 15:42:06',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (35,64,NULL,'Laura',NULL,NULL,NULL,'Bonjour, \n\nJe souffre de phobie d’impulsion depuis 1an, entre temps je suis tombé enceinte et j’ai eu mon bébé en très bonne santé et je me retrouve avec la peur de lui faire du mal, peur de le secouer sans raison ou quelques fois je craque, je pleure énormément et je suis en panique à chaque fois. J’ai honte de moi, je culpabilise énormément, mon fils est tellement important pour moi c’est ma vie, je ne supporte plus ces pensée qui m’angoisse. Je vais bien pendant quelques semaines car j’arrive à passer outre mais quelques fois elle reviennent et me hante pendant quelques jours et ces jours là je suis en déprime, j’ai quelques fois peur que mon fils pleure, quand il pleure je me pose direct par peur de faire du mal, j’ai honte d’en parler comme sa.\n\nJ’ai consulté des psy, essayer plusieurs méthode mais quand je vais bien et que j’en parle elle revienne, la dernière fois elle se sont déclenché en regardant une émission sur les bebe secouer.. le soir mon fils a pleurer et je n’ai pas su gérer l’image de lui faire du mal je l’ai poser direct et je suis parti en pleure.\n\nEst ce bien des phobies d’impulsion','approved','2022-06-11 10:21:14',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (36,22,38,'Laura B.',NULL,NULL,NULL,'Bonjour Aurélie, \n\nMerci beaucoup pour votre commentaire, ravie que mon article ait pu vous aider ????','approved','2022-02-27 17:44:25',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
