INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (38,22,NULL,'Masson',NULL,NULL,NULL,'Bonjour,\n\nJe voulais vous remercier, vos paroles mon beaucoup touché, et elles sont justes sans jugement.\n\nEncore merci.\n\nAurelie','approved','2022-02-27 09:03:12',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (39,64,NULL,'Yann',NULL,NULL,NULL,'Bonjour,\n\nTout à commencé en 1995 à la fin de mes études avec l apparition de troubles anxieux et leur cortège d idées intrusives (pédophilie, homosexualité, peur d être agressif, de perdre le contrôle. …)\n\nA cette époque on n’a pas mis de nom sur cette maladie et internet n existait .\n\nAvec un traitement basé sur les antidépresseurs (paroxétine) tout rentrait dans l ordre mais dés que j arrêtait tout revenait.\n\nJ ai décidé avec mon médecin de prendre le Deroxat tout le temps, j ai eu ce traitement jusqu en 2021 ou j ai attrapé le covid et suite à ça les pensées sont revenues. Ce n est plus les mêmes troubles que durant ma jeunesse, aujourd hui c est la peur de perdre le contrôle, d être agressif, peur du suicide……\n\nJ ai été hospitalisé deux fois en 2021 depuis novembre 2021 j ai repris une vie à peu à peu près normale avec des crises plus ou moins fortes. C est en cherchant sur internet (sur des sites comme le votre) que j ai pu nommé ma maladie.\n\nJ ai un traitement avec antidépresseur et du lithium, ce dernier me réussissant plus. Cependant j aimerais trouver un docteur qui pratique les TCC ou EMDR dans ma région (j habite entre Montauban et Toulouse.\n\nEn espérant que mon parcours vous ai appris diverses choses sur la phobie d’impulsion.\n\nCordialement','approved','2022-02-23 09:16:04',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
