INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (45,64,NULL,'BN',NULL,NULL,NULL,'Bonjour \n\nJ’ai souffert de phobie de pedophilie et dhomosexualite, y’a plusieurs année en arrière. J’en suis sortie et pu reprendre une vie normale et je me demandais même comment j’avais pu en arriver là en voyant le caractère absurde de la chose.\n\nPourtant aujourdui je soufre à nouveaux non pas d’avoir peur mais d’avoir eu peur de ces choses là. En tant qu’homme je me sens diminué dans mon estime et ma masculinité. Je suis à nouveaux en dépression\n\nAvez vous vous aussi eu ce contre coup ou suis je le seul. Suis je à nouveau malade mais d’une autre façon ?\n\nMerci à vous si j’ai des réponses','approved','2021-11-27 22:58:09',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (46,64,47,'Laura B.',NULL,NULL,NULL,'Bonjour Valérie,\n\nJe vous ai répondu sur votre boîte mail.','approved','2021-06-21 19:27:11',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (47,64,NULL,'Val',NULL,NULL,NULL,'Bonjour et merci beaucoup pour cette article !! À ce jour j’ai essayé 2 psys sensés être axés TCC dans ma région (j’habite entre Orléans et Pithiviers, ces psys sont sur Orléans) mais une ne m’a même pas parlé de cette technique donc j’ai arrêté et la 2e m’aide car on parle bcp et je suis à l’aise mais ça fait 4 séances et je ne vois pas d’apparition de technique TCC. Qu’en pensez vous et connaissez vous un.e vrai.e comportementaliste dans cette région ? Je vous remercie beaucoup, bien cordialement.','approved','2021-06-20 18:02:52',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (48,64,49,'Laura B.',NULL,NULL,NULL,'Bonjour Laurent, \n\nJe vous ai répondu sur votre boîte mail.','approved','2021-04-29 19:43:31',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (49,64,NULL,'Laurent',NULL,NULL,NULL,'Bonjour\n\nMa femme est également sujette de phobies d’impulsion depuis plusieurs années mais sans que nous puissions mettre un nom sur son mal que dernièrement.\n\nAu début, sa phobie était de renverser quelqu’un. Elle faisait plusieurs fois demi tour afin de vérifier qu’elle n’avait pas heurté un piéton. Depuis les confinements et la mise à l’arrêt de sa profession, sa phobie d’impulsion a basculé sur un autre thème: la peur de faire du mal aux enfants (étant régulièrement confinée avec eux à la maison). Pouvez vous nous conseiller des praticiens dans la région du Grand Est (Metz- Nancy) afin d’en parler et de commencer une TCC.\n\nMerci d’avance pour votre aide.','approved','2021-04-28 10:23:58',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (50,59,51,'Laura B.',NULL,NULL,NULL,'De rien ????','approved','2021-03-29 18:15:44',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
