INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (52,64,53,'Laura B.',NULL,NULL,NULL,'Bonjour, \n\nJe vous ai répondu sur votre boîte mail.','approved','2021-01-24 16:23:35',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (53,64,NULL,'JL',NULL,NULL,NULL,'Bonjour je souffre aussi beaucoup , tout a commencé en 2008 à la suite d’un film ou un bonhomme est séquestré et violé , et c’est là que je me suis dit ,tiens et si toi aussi tu étais homo ? Depuis ma vie n’est plus la même ,je suis déjà très anxieux de nature et je n’ai jamais été attiré par cela .\n\nJe vérifie depuis sans cesse en me testant sans arrêt ,que ce soit dans en regardant un film , en lisant un magasine ou même en ne faisant rien de spécial . J’ai eu beaucoup de conquêtes dans ma vie jusqu’à mes 25 ans environ puis je suis resté plus de dix ans avec mon ex compagne qui est partie du jour au lendemain ..Durant ces dix ans il y a eu quelques changements dans le toc ,je suis passé par la peur d’être pédophile , la peur de lui faire du mal spontanément ce qui m’a parfois obligé à dormir dans une autre chambre, j’ai aussi eu la peur de me jeter d’un pont ou sous une voiture etc etc ,mais avec ,toujours en fond le même sujet ..\n\nJ’ai rapidement retrouvé quelqu’un après cela et tout se passait bien malgré les traditionnelles prises de becs ,depuis huit mois maintenant,cela ressemblait à ce que j’avais vécu auparavant avec mon autre compagne , toujours avec les mêmes préoccupations vérifications liées à cette peur depuis ce film il y a maintenant douze ans .. j’avais même,sous son impulsion commencé à réduire mes cachets ( Xanax) 2mg par jour et venlafaxine le matin ( que je prends depuis justement 2008 )..Depuis une semaine cela dit et plus spécifiquement depuis mardi je fais des crises de panique continuelles très aiguës avec la rumination qui revient au centuple ,je n’ai pas été en mesure d’aller travailler jeudi , je ne mange plus alors que j’avais retrouvé un bon appétit , je ne retrouve un peu de calme que lorsque je suis sur le point d’arriver à m’endormir , et je suis obligé de recommencer à prendre les Xanax pour essayer d’éliminer les crises ,sinon je n’arrive quasiment plus à parler .. J’en suis au point de ne plus pouvoir croiser un homme dans la rue sans me mettre à paniquer ,plus encore , une simple voix me fait entrer en panique la plus totale ,les visages me font particulièrement peur .. Je suis véritablement au bout du rouleau et je songe sérieusement au suicide ou à l’internement, si cela se prolonge ,je pense de toute façon perdre ma copine ,ce que je comprendrai car pour le moment je suis chez moi , seule ma mère et mon frère qui n’habitent pas loin de sont rendus compte de mon état ces quelques derniers jours ,je devais aller la voir ce weekend mais j’ai dû annuler ,je ne m’en sentais pas capable ..Nous devons nous voir vendredi prochain pour quelques jours chez moi ,mais dans cet état je ne sais pas ce qu’il va se passer ..Je n’avais pas été aussi mal depuis plusieurs années,un épisode comme celui ci était apparu justement après la rencontre avec mon ex compagne ,mais je n’arrive plus à savoir exactement de quelle manière je m’en étais sorti ..\n\nJ’ai la sensation de perdre totalement le contrôle ,je n’aspire qu’à redevenir celui que j’étais avant 2008 ,mais cela me semble absolument impossible après tant de temps ,de plus je suis assailli d’une honte énorme, j’ai lu tout les sujets possibles sur internet et je me retrouve énormément dans la plupart,ce qui a crée une autre angoisse.. ” et si j’étais l’exception qui confirme la règle” ,ce matin encore j’ai eu peur en passant devant la douche d’espionner mon frère qui était en train de se laver ,et j’ai vraiment eu le sentiment d’avoir envie de le faire ,en ajoutant à cela des sensations de fourmillement dans l’anus etc etc je ne peux plus reprendre le contrôle , j’ai rdv chez mon médecin généraliste mardi pour essayer de me permettre de reprendre pieds mais je n’arrive pas à y croire . Tout est source d’angoisse et de désespoir partout et tout le temps ,quoi qu’il se passe ..\n\nDésolé pour ce long pavet peu digeste ,je ne suis pas dans mon meilleur jour pour écrire clairement..\n\nPouvez vous m’aider , me dire ce qu’il se passe , ce que je dois faire ? Que m’arrive t’il depuis tout ce temps ? Pourquoi cette semaine est elle si insupportable ,comparée aux autres ,qui ,déjà fort peu agréables ,semblent délicieuses comparées à celle ci ? Avez vous déjà eu des personnes dans ce cas ci? J’ai l’impression d’avoir changé ,de ne plus être le même , d’être un refoulé .. parfois même l’impression d’attendre d’aimer ça ,je ne sais pas comment décrire précisément cela…bref , merci .','approved','2021-01-24 14:37:38',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (54,64,55,'Laura B.',NULL,NULL,NULL,'Bonjour, \n\nJe vous ai répondu sur votre boîte mail.','approved','2021-01-19 17:31:17',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (55,64,NULL,'Lalbo',NULL,NULL,NULL,'Bonjour,\n\nDepuis maintenant 6 mois , j si développé des pensees obsessionnels autour de la peur d etre pedophile. J ai des pensees et images horribles qui viennent dans la tête et dont je n’arrive pas a me debarasser . J ai toujours le le doute comettre certains actes j essaye de me rassurer mais ca revient sans cesse. Parfois ca me fait angoisser , parfois culpabiliser , parfois me sentir degueullasse j ai trop peur d avoir ces pensees pendant des exitations . J ai l impression que mon esprit reste bloque la dessus et j ai plus de problemes de concentration qu avant. J ai eu recemment aussi des angoisses sur sur des choses violentes et j ai douté de moi également avec l l’impression que je pouvais devenir fou. Quand je vois dans l actualite certaines histoires de pédophiles ou autres, j ai l impression que je pourrais etre comme eux. Ca me fait peur \n\nJ aimerais bien avoir de l aide . Si vous connaissez un bon therapeute sur paris ? Je vous remercie beaucoup','approved','2021-01-17 20:40:10',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (56,64,57,'Laura B.',NULL,NULL,NULL,'Bonjour, \n\nJe vous ai répondu sur votre boîte mail.','approved','2021-01-04 15:52:35',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (57,64,NULL,'Lorelei',NULL,'http://vivre-pleinement.fr',NULL,'Bonjour, depuis un mois j’ai des pensées intrusives, peur de devenir pedophile ou zoophile ça détruit ma vie je suis tombé en dépression et je cherche à m’en débarrasser. Comment puis je faire, pouvez vous m’aider?','approved','2021-01-04 10:03:48',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (58,64,59,'Laura B.',NULL,NULL,NULL,'Bonjour, \n\nJe vous ai répondu sur votre boîte mail.','approved','2020-12-15 20:25:02',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (59,64,NULL,'Angela',NULL,NULL,NULL,'Bonjour, (je reposte mon message car je ne sais pas s’il a été publié)\n\nMerci pour votre article très intéressant. \n\nJe souffre de pensées intrusives agressives (insultes, pensées malveillantes/dédaigneuses…) principalement envers les personnes que j’aime le plus, et de quelques phobies d’impulsion. Cela peut se manifester suite à un déclencheur, comme par exemple regarder un film, ou sans aucun stimuli. Je rumine également beaucoup sur le passé et ai énormément de doutes sur moi-même. J’ai fini par me mettre dans la tête que j’ai tous les défauts du monde, que je suis méchante, narcissique, vénale, et j’en passe. (tous les défauts “moraux”) Je me culpabilise beaucoup, et cela a fini par impacter ma qualité de vie car j’appréhende beaucoup les interactions avec mes proches, qui font également partie des déclencheurs de mes pensées. J’ai même parfois des appréhensions avant de regarder une vidéo, car c’est un potentiel déclencheur, même s’il n’y a en apparence aucun rapport avec la nature de mes pensées.\n\nJ’avais entamé une thérapie TCC que j’ai arrêtée car mon psychologue n’avait pas l’air très familier des TOC, et sa méthode (que je ne comprenais d’ailleurs pas) ne me convenait pas et entretenait mon angoisse. Je suis évidemment très anxieuse à la base, et je ne l’ai jamais été autant qu’actuellement.\n\nAujourd’hui je ne sais plus trop quoi faire, alors je subis. Je pense reprendre un antidépresseur, et pour une thérapie eh bien je suis un peu refroidie de mon expérience, j’ai l’impression que le TOC est assez mal connu d’un grand nombre de thérapeutes…','approved','2020-12-13 17:55:44',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (60,64,NULL,'Angela',NULL,NULL,NULL,'Bonjour,\n\nMerci pour votre article très intéressant. \n\nJe souffre de pensées intrusives agressives (insultes, pensées malveillantes/dédaigneuses…) principalement envers les personnes que j’aime le plus, et de quelques phobies d’impulsion. Cela peut se manifester suite à un déclencheur, comme par exemple regarder un film, ou sans aucun stimuli. Je rumine également beaucoup sur le passé et ai énormément de doutes sur moi-même. J’ai fini par me mettre dans la tête que j’ai tous les défauts du monde, que je suis méchante, narcissique, vénale, et j’en passe. (tous les défauts “moraux”) Je me culpabilise beaucoup, et cela a fini par impacter ma qualité de vie car j’appréhende beaucoup les interactions avec mes proches, qui font également partie des déclencheurs de mes pensées. J’ai même parfois des appréhensions avant de regarder une vidéo, car c’est un potentiel déclencheur, même s’il n’y a en apparence aucun rapport avec la nature de mes pensées.\n\nJ’avais entamé une thérapie TCC que j’ai arrêtée car mon psychologue n’avait pas l’air très familier des TOC, et sa méthode (que je ne comprenais d’ailleurs pas) ne me convenait pas et entretenait mon angoisse. Je suis évidemment très anxieuse à la base, et je ne l’ai jamais été autant qu’actuellement.\n\nAujourd’hui je ne sais plus trop quoi faire, alors je subis. Je pense reprendre un antidépresseur, et pour une thérapie eh bien je suis un peu refroidie de mon expérience, j’ai l’impression que le TOC est assez mal connu d’un grand nombre de thérapeutes…','approved','2020-12-13 17:31:48',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
