INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (62,64,NULL,'dupuis',NULL,NULL,NULL,'Bonjour a vous Laura , et si les phobies d’impulsion etaient en effet un desir caché refoulé qui souhaiterai s exprimer , c est vrai et troublant de penser que plusieurs personnes ont en effet divers peur et phobie mais qui n’ont au final pas la meme résultante je men explique, par exemple j’ai eu peur ma premiere phobie d’avoir le sida j’avais peur je men souvient encore de ne pas ete comme les autres de ne pas etre accepter de ne pas trouver de femme et davoir d enfants, mais cette phobie etait passagere car il suffisait de prendre son courage a deux mains et de fr le test, passons histoire regler cette phobie passe, puis je deviens animateur avec les enfants un an et demi a peu pres environ , la premiere fois que j’ai ressenti la pensée et si j ‘etais attiré comme vous dites ca a durer meme pas une seconde dans mon esprit c etait mon premier jour de stage et par la suite elle a disparu j’ai fait mon travail imppecablement sans aucune pensées intruisifs, j’aimais ce travail et j’y etait confiant j ai continué puis un jour dans le detour d’une réunion on a parler de la pedophilie j’ai senti une gene en moi une seconde fois 6 mois plus tard avec la premiere , de la et survenu une agrravtion de mon état mental c est a dire que j’ai commencer a etre angoisser avoir d penssées obsedantes a ce sujet sans pour autant ressentir du désir ou quoi que ce soit vu que j’eprouvais de plus en plus de genes surtout quand les parents venaient chercher leurs enfant j’ai arreter, j’ai poursuivit ma vie on est donc en 2009 il y a internet j’entend parler des phobies d’impulsions ect des fois je me console avec cette idéee des fois je suis perdu triste mes relations avec les autres son modifiés les relations avec les enfants également ca m effraie je change radicalement , j’ai ensuite une seconde peur et si je devenais jaloux de mon meilleur ami j’accelere le temps,phobie de l homosexualité phobie de la perversion narcissique deja tres a la mode en 2010 sur internet jaloux des autres , phobie de ne pas etre bienveillant dans l’evolution de mes enfants , ect et ca tourne fixation sur des personnes qui me font peur par leurs pratiques spirituelles ect etant d origine antillaise et etant de banlieue il y a des fois des personnes qui font de la sorcellerie c dans nos codes j’en est assez peur egalement , enfin voila tout ma question que je me pose c est et si c etait un désir reffoulé qui avait entrainer par la suite toutes ces autre peurs ? si ce n est pas le cas et que vous avez quelque chose a me conseiller comme une therapie spécialisé dans l arret de ces phobies je suis preneur la peur detre jaloux et la peur d etre pedophile sont les plus présentes ancrés installés je fatigue on est aujourdui en 2020 je fatigue pourtant je suis toujours debout.Merci a vous Laura','approved','2020-12-12 11:55:33',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
