INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (64,64,NULL,'Anonyme',NULL,'http://J’en%20ai%20pas',NULL,'Bonjour je préfère garder mon nom anonyme j’ai 14ans et j’ai eu les phobies d’impulsion les plus principale : peur de tuer . Peur de se suicider . Peur de se suicider mais je l’es ai toutes passer la j’ai la pire angoisse du monde les cauchemard c’est la peur d’être pedophile je ne sais pas si je le suis ou pas mais c’est vraiment compliqué si en pratiquant la masturbation ce que je fait très occasionnellement je regarde une fille en manga sur internet ( hentai) si je dit qu’elle a au dessus de 14ans c’est à dire mon âge sa ne m’excite pas mais si elle a 13ans ou 12ans ça m’excite plus de base je suis hétérosexuel c’est à dire que quand je préfère de loin parler à une fille tout ça et penser qu’elle est peut être amoureuse de moi je suis aller sur internet et les pedophiles c’est pareil mais avec les gosses c des pourriture de et g peur dans être une une fois l’année dernière ma cousine était sympa mais elle était toute petite il m’est arriver de faire la réflexion elle est amoureuse de moi ou quoi parce que elle me suivais partout ensuite évidemment j’ai un sens de la logique je me suis dit n’importe quoi ques que tu raconte au contact je ne re sens rien je ne suis pas excité au fait de voir une gamine se faire violer sa me dégoûte s’il vous plais je sais que je suis hétérosexuel mais j’ai très peur et cela va me tuer mentalement si je n’y remédie pas','approved','2020-11-07 10:12:09',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (65,64,66,'Laura B.',NULL,NULL,NULL,'Bonjour Léa, \n\nJe vous ai répondu sur votre boîte mail.','approved','2020-10-04 08:52:35',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (66,64,NULL,'Léa D',NULL,NULL,NULL,'Bonjour\n\nJe vous remercie pour cet article juste super qui m’a fait me sentir moins seule et beaucoup plus comprise. Cela fait 5 ans que je vis avec des pensées intrusives. Je suis constamment en train de me rassurer. J’habite à paris et j’aimerai commencer une TCC. Avez vous des contacts à me donner de bons psys à ce sujet ?\n\nMerci bcp par avance','approved','2020-10-03 10:34:42',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (67,64,NULL,'Léa',NULL,NULL,NULL,'Bonjour Laura,\n\nMerci pour cet article. Il me fait me sentir comprise et c’est si rare quand on vit avec ce trouble. Cela fait 5 ans pour ma part, et j’aimerais m’engager dans une TCC. Après de la psychanalyse, de la prise de médicaments, je souhaite traiter le vrai problème. Avez vous des noms de bons psys qui proposent cela à paris ? J’ai mon email disponible.\n\nMerci pour tout\n\nLéa','approved','2020-10-02 20:06:02',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
