INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (71,64,NULL,'Fred',NULL,NULL,NULL,'Bonjour je souffre de phobies d impulsions et de pensées intrusives depuis 2 ans et cela devient invivable et très handicapant votre article m a rassuré en me disant que non je ne suis pas une mauvaise personne ..\n\nJ’aimerais m engager dans une TCC en midi Pyrénées mais je ne sais vers quel specialiste m orienter si vous pouviez me conseiller je vous en serais très très reconnaissant . Merci d avance pour tout ce que vous faites','approved','2020-08-29 08:58:24',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (72,35,73,'Laura B.',NULL,NULL,NULL,'Bonjour et merci beaucoup pour votre commentaire. Je suis vraiment heureuse que mon article ait pu vous aider ! Portez-vous bien, je vous souhaite une agréable soirée.','approved','2020-06-27 21:31:53',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (73,35,NULL,'bassam samaha',NULL,NULL,NULL,'Tout d’abord, un énorme merci, car votre long article est l’aboutissement d’une longue quête qui, grâce à vous , m’a permis de me familiariser avec avec ma thanatophobie et de l’apprivoiser. J’ai 69 ans et je suis bipolaire surdoué et hypersensible et la pandémie a réactivé ma peur de la mort plus une désillusion mystique et ésotérique dont il serait trop long de parler et qui remonte à ma crise initiale de manie lorsque j’avais 24 ans. Je suis d’origine libanaise, veuf avec un fils unique de 41 ans et après avoir fait un long parcours de quête spirituelle, j’ai abouti à une prise de conscience et une prise de distance avec la métaphysique et l’ésotérisme. Encore une fois merci et je vous souhaite la réussite dans votre entreprise sur le net','approved','2020-06-26 18:22:45',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (74,64,75,'Laura B.',NULL,NULL,NULL,'Bonjour, \n\nJe vous ai répondu directement sur votre boîte mail.','approved','2020-05-21 09:19:10',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (75,64,NULL,'solix',NULL,NULL,NULL,'bonsoir \n\nje ne connaissais pas votre blog et je suis rassuré d’être tombé dessus et de savoir que on peut toujours guérir\n\nj’ai des phobies d’impulsions assez violentes depuis environ 2015 ou même un peu avant mais les souvenirs sont très flous , c’est surtout arrivé après de grandes périodes d’angoisses (diagnostic de dépression+émétophobie+harcèlement) et j’avoue ne plus savoir quoi faire car j’ai l’impression de jamais avoir de solution durable \n\nje vis en bourgogne , et je voulais vous demander , si cela ne vous dérange pas , si vous connaissez des noms de thérapeutes (bourguignons ou non , je ne suis vraiment plus à ça près ) qui saurait soigner les phobies d’impulsions de tout types ? \n\net vous dites que l’EMDR est très utile , tout.e.s les psychothérapeute le pratiquant sont donc informé.e.s sur les phobies d’impulsion ? \n\nmerci d’avance pour votre réponse et également pour cette liste des phobies d’impulsion \n\nbon courage à tout ceux passant par là , également','approved','2020-05-20 22:43:29',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (76,64,77,'Laura B.',NULL,NULL,NULL,'Bonjour, \n\nOui et c’est bien cette peur du désir caché qui entretient cette phobie d’impulsion. C’est terrible comme sensation, je le sais. Mais justement, une personne ayant le désir de passer à l’acte n’en n’aura pas peur, bien au contraire. C’est ce que j’explique justement dans mon article et notamment dans le paragraphe sur le désir caché. \n\nCe doute constant provient d’une trop grande anxiété de fond ainsi que d’un manque de confiance en soi. N’hésitez pas à aller consulter les différents articles de mon blog et notamment la rubrique “développement personnel” afin d’y trouver des solutions pouvant soulager vos angoisses. \n\nBonne continuation à vous !','approved','2020-05-10 18:40:17',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (77,64,NULL,'Herouard',NULL,NULL,NULL,'Pourquoi à ton toujour ce doute et peur et on se dit mais sa se trouve c’est un désir caché horrible','approved','2020-05-10 13:53:18',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
