INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (85,64,86,'Laura B.',NULL,NULL,NULL,'Bonjour Louise, \n\nL’EMDR est une thérapie alternative créée par la thérapeute Francine SHAPIRO en 1987. Traduit en français, cela veut dire : retraitement et désensibilisation par mouvement oculaire.\n\nLors d’une séance, le thérapeute stimule le patient principalement à l’aide de mouvements oculaires spécifiques. Cette thérapie est extrêmement efficace pour résoudre les traumatismes, afin que le patient ne fasse plus de lien négatif entre un souvenir pénible et une émotion le faisant entrer constamment dans un cercle vicieux.\n\nLa phobie d’impulsion fait partie des troubles anxieux. Et les troubles anxieux sont bien souvent irrationnels. Ils proviennent donc très souvent d’un traumatisme, que l’on s’en souvienne ou non. Cela pourrait donc vous aider à modifier votre schéma de pensées.\n\nSi cela vous intéresse, je vous invite à aller consulter sur Internet les thérapeutes pratiquant l’EMDR non loin de chez vous. \n\nJ’espère avoir été claire et vous souhaite une agréable journée !','approved','2020-02-10 12:43:29',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
INSERT INTO `comments` (`id`, `post_id`, `parent_id`, `author_name`, `author_email`, `author_url`, `author_ip`, `content`, `status`, `posted_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (86,64,NULL,'Louise Simard',NULL,NULL,NULL,'Qu’est-ce que l’EMDR ?\n\nJ’aimerais en savoir davantage . Svp pouvez-vous m’aider ?\n\nMerci !\n\nLouise','approved','2020-02-09 21:44:22',NULL,'2026-05-24 19:21:39','2026-06-19 18:19:42');
