INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (1,'Ergophobie (peur du travail) : comment s’en sortir ?','ergophobie-peur-du-travail','L’idée de retourner travailler vous noue l’estomac, au point d’en ressentir une angoisse intense et incontrôlable. Cette anxiété peut apparaître chaque fin de week-end ou tous les matins avant de partir, accompagnée de ruminations et d’une bouffée d’angoisse sur le trajet. Il est important de préciser qu’il ne s’agit pas d’un manque de motivation. L’ergophobie, […]\n','<h2>Ergophobie : qu\'est-ce que c\'est, et est-ce un burn-out ?</h2>\n<p>L\'idée de retourner travailler vous noue l\'estomac, au point d\'en ressentir une <b>angoisse intense et incontrôlable</b> ? Vous souffrez peut-être d\'<b>ergophobie</b>, la phobie du travail. Attention : il ne s\'agit ni de paresse, ni d\'un simple manque de motivation, mais d\'une <b>véritable phobie</b>, avec ses symptômes physiques et sa charge d\'anxiété.</p>\n<p>On la confond souvent avec le <a href=\"/blog/burn-out\">burn-out</a>, mais les deux sont distincts : le burn-out est un <b>épuisement</b> qui survient après avoir trop donné, tandis que l\'ergophobie est une <b>peur anticipée</b> du travail, qui peut exister même sans surmenage. Comprendre cette différence est la première étape pour vous en libérer. Voyons les symptômes, les causes, puis les solutions concrètes.</p>\n<p>L’idée de retourner travailler vous noue l’estomac, au point d’en ressentir une <b>angoisse intense et incontrôlable</b>. Cette anxiété peut apparaître chaque fin de week-end ou tous les matins avant de partir, accompagnée de <b>ruminations </b>et d’une bouffée d’angoisse sur le trajet. Il est important de préciser qu’il ne s’agit pas d’un manque de motivation. <b>L’ergophobie, la peur du travail</b>, est une véritable phobie déclenchée par l’idée même du travail, qui peut, dans le pire des cas, empêcher d’exercer une activité professionnelle et provoquer un profond mal-être, avec un <b>besoin irrépressible de fuir.</b> Il s’agit d’un problème qui dépasse un simple état de mal-être, comme l’ennui ou le stress. Vous avez peur de commettre une erreur, craignez le regard de vos collègues, et appréhendez la surcharge de tâches ? Comment vous libérer de l’ergophobie ?</p>\n<h2>Les symptômes de l’ergophobie (peur du travail) </h2>\n<p>La peur du travail s’accompagne de symptômes émotionnels et physiques souvent très invalidants :</p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">sensation de perte de contrôle; </li>\n<li aria-level=\"1\">boule au ventre;</li>\n<li aria-level=\"1\">sueurs froides, frissons ou bouffées de chaleur;</li>\n<li aria-level=\"1\">vertiges;</li>\n<li aria-level=\"1\">troubles digestifs;</li>\n<li aria-level=\"1\">maux de dos et tensions musculaires;</li>\n<li aria-level=\"1\">maux de tête;</li>\n<li aria-level=\"1\"><a href=\"/fatigue-mentale/\" target=\"_blank\" rel=\"noopener\" title=\"Fatigue mentale\">fatigue mentale</a> et physique intense;</li>\n<li aria-level=\"1\">troubles du sommeil, <a href=\"/angoisse-matinale/\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse matinale\">angoisse matinale;</a></li>\n<li aria-level=\"1\">perte ou augmentation de l’appétit;</li>\n<li aria-level=\"1\">irritabilité;</li>\n<li aria-level=\"1\">sentiment de honte et d’être incompris;</li>\n<li aria-level=\"1\">pleurs;</li>\n<li aria-level=\"1\">tremblements;</li>\n<li aria-level=\"1\">difficultés à respirer;</li>\n<li aria-level=\"1\">palpitations;</li>\n<li aria-level=\"1\">crises d’angoisse.</li>\n</ul>\n<p></p>\n<h2>Les causes de la phobie du travail </h2>\n<p>L’ergophobie peut provenir de plusieurs causes : </p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">traumatismes passés, personnels ou professionnels;</li>\n<li aria-level=\"1\"><a href=\"/confiance-et-estime-de-soi/\" target=\"_blank\" rel=\"noopener\" title=\"Confiance et estime de soi\">confiance et estime de vous</a> fragilisées vous faisant douter de votre capacité à mener à bien vos missions quotidiennes jusqu’à ne plus pouvoir effectuer la moindre tâche sans vous poser des milliers de questions;</li>\n<li aria-level=\"1\">besoin excessif de reconnaissance;</li>\n<li aria-level=\"1\">grande pression hiérarchique;</li>\n<li aria-level=\"1\">humiliation professionnelle, qu’elle vienne de la direction ou de vos collègues;</li>\n<li aria-level=\"1\">sentiment de ne pas mériter votre poste (syndrome de l’imposteur);</li>\n<li aria-level=\"1\"><a href=\"/burn-out/\" target=\"_blank\" rel=\"noopener\" title=\"burnout\">burn-out;</a></li>\n<li aria-level=\"1\">échec professionnel, licenciement;</li>\n<li aria-level=\"1\">peur de l’échec;</li>\n<li aria-level=\"1\">d’autres troubles associés : phobie sociale, anxiété généralisée, agoraphobie;</li>\n<li aria-level=\"1\">pression sociale liée à la réussite professionnelle.</li>\n</ul>\n<p> </p>\n<h2>Les conséquences de la peur d’aller au travail </h2>\n<p>Sur le plan professionnel, l’ergophobie peut freiner l’accès à l’emploi et empêcher également une évolution interne.</p>\n<p>Sur le plan personnel, elle peut entraîner des tensions familiales dues à une baisse de revenus, un isolement social, un sentiment d’inutilité et une perte de motivation.<br>Cette phobie est souvent confondue avec de la paresse, alors qu’il s’agit d’un trouble anxieux réel pouvant mener à une dépression. Si vous souffrez d’ergophobie, cela ne veut absolument pas dire que vous n’aimez pas travailler. </p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"2880\" height=\"1920\" src=\"/storage/blog-images/phobie-travail-scaled.jpg\" alt=\"Comment vaincre la peur d\'aller au travail \" title=\"Conseils pour se libérer de la phobie d\'aller au travail \">\n<h2>Comment se libérer de la phobie de se rendre au travail ? </h2>\n<p>Heureusement, il est possible de vous libérer de l’ergophobie. Voici les clés pour vous permettre d’y parvenir : </p>\n<h3>1- Vous faire aider </h3>\n<p>Vous pouvez déjà vous faire accompagner. Sachez que je propose des accompagnements, d’une durée d’une heure, par téléphone ou en visio. Si cela vous intéresse, vous pouvez cliquer sur le lien ci-dessous pour prendre rendez-vous avec moi : </p>\n<p>Autrement, vous pouvez envisager d’autres thérapies, comme les thérapies cognitivo-comportementales (TCC), la psychanalyse, ou l’EMDR en cas de traumatisme.<br>Un traitement médicamenteux peut également s’avérer nécessaire, comme la prise d’anxiolytiques et/ou d’antidépresseurs, si vraiment vous n’arrivez plus du tout à aller travailler. </p>\n<h3>2 – Accepter et comprendre cette peur </h3>\n<p>Reconnaître et accepter votre peur sans vous juger est une étape clé. Chercher son origine (manque de confiance, traumatisme…) et trouver le besoin qui se cache derrière cette phobie, comme le besoin de reconnaissance, est le premier pas pour vous libérer de l’ergophobie. Renseignez-vous donc au maximum sur votre peur. </p>\n<h3>3 – Vous relaxer </h3>\n<p>Les techniques de relaxation comme la sophrologie, le yoga, la méditation, les exercices de respiration, la relaxation musculaire progressive de Jacobson, et la visualisation positive (imaginer une journée de travail qui se passe bien) peuvent réduire considérablement votre anxiété. La phytothérapie, utilisée en complément, peut également grandement vous aider. N’hésitez donc pas à vous renseigner à ce sujet. </p>\n<h3>4 – Augmenter votre confiance en vous et vous affirmer </h3>\n<p>Travailler votre estime de vous, apprendre à vous affirmer et augmenter votre confiance en vous vous permettra de poser vos limites au travail et de réduire la peur du jugement et de l’échec.</p>\n<h3>5 – En parler à votre employeur</h3>\n<p>Exprimer vos émotions en parlant à votre employeur reste vraiment la solution idéale. Celui-ci pourra mettre en place des aménagements spécifiques pour vous, comme, l’allègement temporaire de certaines tâches, du temps partiel, un bureau plus calme, l’éloignement d’un collègue source de stress, ou du télétravail partiel.<br></p>\n<h3>6 – Changer de job  </h3>\n<p>Parfois, cette phobie est liée à un environnement toxique ou inadapté. Envisager une reconversion ou un changement de poste peut être une solution pour retrouver un cadre professionnel plus serein et votre joie de vivre. </p>\n<p>Vous libérer de <b>l’ergophobie (peur du travail)</b> est possible. Avec un accompagnement adapté, des outils de gestion de l’anxiété et des ajustements professionnels, il est possible de retrouver une relation apaisée au travail et de reprendre confiance en vous et vos capacités.</p>','published',1,'Ergophobie : Comprendre et Vaincre la Peur d\'Aller au Travail','L\'idée d\'aller travailler vous noue l\'estomac ? L\'ergophobie est une vraie phobie, à ne pas confondre avec le burn-out. Symptômes, causes et solutions concrètes.','https://vivre-pleinement.fr/ergophobie-peur-du-travail/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ergophobie-peur-du-travail\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ergophobie-peur-du-travail\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Ergophobie (peur du travail) : comment s\\u2019en sortir ?\",\"datePublished\":\"2026-03-02T20:12:48+00:00\",\"dateModified\":\"2026-03-02T20:12:57+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ergophobie-peur-du-travail\\/\"},\"wordCount\":2173,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ergophobie-peur-du-travail\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2026\\/03\\/ergophobie-scaled.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/ergophobie-peur-du-travail\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ergophobie-peur-du-travail\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/ergophobie-peur-du-travail\\/\",\"name\":\"Ergophobie (peur du travail) : comment s\\u2019en sortir ?\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ergophobie-peur-du-travail\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ergophobie-peur-du-travail\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2026\\/03\\/ergophobie-scaled.jpg\",\"datePublished\":\"2026-03-02T20:12:48+00:00\",\"dateModified\":\"2026-03-02T20:12:57+00:00\",\"description\":\"L\\u2019ergophobie, la peur du travail, est une v\\u00e9ritable phobie d\\u00e9clench\\u00e9e par l\\u2019id\\u00e9e m\\u00eame du travail. Comment s\'en lib\\u00e9rer ?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ergophobie-peur-du-travail\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/ergophobie-peur-du-travail\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ergophobie-peur-du-travail\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2026\\/03\\/ergophobie-scaled.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2026\\/03\\/ergophobie-scaled.jpg\",\"width\":2880,\"height\":1920,\"caption\":\"Comment se lib\\u00e9rer de l\'ergophobie ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ergophobie-peur-du-travail\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Ergophobie (peur du travail) : comment s\\u2019en sortir ?\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2026-03-02 20:12:48',NULL,'2026-05-24 19:19:43','2026-06-19 21:01:43');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (2,'Comment vaincre la cardiophobie ? (peur de la crise cardiaque)','cardiophobie','La cardiophobie, qui est la peur panique de faire une crise cardiaque, fait partie des troubles anxieux. Elle peut être rattachée à l’hypocondrie, qui est la phobie de contracter une maladie grave en général. Elle se caractérise par une crainte intense, irrationnelle et persistante de mourir d’un infarctus, même lorsque tous les examens médicaux passés […]\n','<p>La cardiophobie, qui est la <b>peur panique de faire une crise cardiaque</b>, fait partie des<b> troubles anxieux</b>. Elle peut être rattachée à <b>l’hypocondrie</b>, qui est la phobie de contracter une maladie grave en général. Elle se caractérise par une crainte intense, irrationnelle et persistante de mourir d’un infarctus, même lorsque tous les examens médicaux passés chez un cardiologue ont confirmé qu’il n’existait aucune pathologie. Cette angoisse peut devenir très handicapante, poussant à éviter certaines activités physiques, à consulter plusieurs cardiologues ou à surveiller en permanence son rythme cardiaque. Avec toute cette anxiété, votre cœur risque-t-il quelque chose ? Mais surtout, comment <b>vaincre la cardiophobie ? </b></p>\n<h2><b>Définition de la phobie de faire une crise cardiaque </b></h2>\n<p>La cardiophobie fait donc partie des <a href=\"/angoisse-stress-anxiete/\" target=\"_blank\" rel=\"noopener\" title=\"angoisse stress anxiété\">troubles anxieux</a> et peut être comparée à <a href=\"/hypocondrie/\" target=\"_blank\" rel=\"noopener\" title=\"hypocondrie\">l’hypocondrie</a>, puisqu’il s’agit d’une angoisse liée à un état de santé. Sauf ici, cette anxiété reste focalisée sur le cœur. Il s’agit de la peur constante de faire un malaise cardiaque.<br>Vous pouvez commencer à ressentir un battement de cœur inhabituel, une douleur ou une oppression dans la poitrine. Tout de suite, l’angoisse monte, créant un effet de panique. Cette panique elle-même modifie le rythme de votre cœur… renforçant votre peur d’un infarctus. Vous pouvez donc devenir obsédé par votre rythme cardiaque (tachycardie — le cœur qui bat trop vite — bradycardie — le cœur qui bas trop lentement).</p>\n<p>Et plus vous allez adopter des comportements de réassurance, plus votre cerveau va penser qu’il y a un danger. Vous pouvez également vous sentir incapable de gérer cette angoisse. Un cercle vicieux peut donc commencer à s’installer. </p>\n<p> </p>\n<p><b>Attention cependant : si vous avez le moindre doute sur un problème cardiaque réel, il est essentiel de consulter un médecin ou un cardiologue. Mais si les examens sont normaux, c’est qu’il s’agit bien de cardiophobie.</b></p>\n<h2><b>Symptômes de la cardiophobie</b></h2>\n<p>Lorsque vous êtes en proie à cette phobie, vous pouvez ressentir les symptômes suivants : </p>\n<ul>\n<li aria-level=\"1\">Oppression et/ou douleur dans la poitrine ;</li>\n<li aria-level=\"1\">Palpitations ;</li>\n<li aria-level=\"1\">Vertiges, sueurs, sensation de malaise ;</li>\n<li aria-level=\"1\">Fatigue, tensions musculaires, troubles du sommeil.</li>\n</ul>\n<p>Vous voyez donc bien que ces manifestations peuvent sembler similaires à ceux d’une personne étant vraiment sur le point de faire une crise cardiaque, alors qu’il ne s’agit que d’angoisse. En effet, une anxiété forte peut provoquer des symptômes pouvant faire penser à une maladie, comme la gastro, alors qu’il s’agit simplement… d’anxiété ! </p>\n<h2><b>Causes de la peur de faire un arrêt cardiaque </b></h2>\n<p>La cardiophobie peut avoir différentes origines :</p>\n<p></p>\n<ul>\n<li aria-level=\"1\">Un traumatisme (perte d’un proche suite à un infarctus ou une autre maladie, maladie grave vécue personnellement) ;</li>\n<li aria-level=\"1\">Une période de stress intense (licenciement, déménagement, séparation…) ;</li>\n<li aria-level=\"1\">Un terrain <a href=\"/trouble-anxieux-generalise\" target=\"_blank\" rel=\"noopener\" title=\"trouble anxieux généralisé\">d’anxiété généralisée</a> ou de trouble panique.</li>\n</ul>\n<h2><b>Mécanismes de réassurance entretenant la peur de faire un infarctus</b></h2>\n<p>Si vous souffrez de cette peur, vous pouvez opter pour des comportements qui vont, bien malgré vous, l’entretenir voire même, la renforcer : </p>\n<ul>\n<li aria-level=\"1\">Aller passer plusieurs examens médicaux auprès de différents cardiologues, même s’ils s’avèrent rassurants ;</li>\n<li aria-level=\"1\">Vérifier constamment votre rythme cardiaque ;</li>\n<li aria-level=\"1\">Demander sans cesse de la réassurance à vos proches ;</li>\n<li aria-level=\"1\">Éviter le sport ou les escaliers par peur de déclencher une crise ou faire des pauses régulières ; </li>\n<li aria-level=\"1\">Lire compulsivement des témoignages médicaux sur Internet.</li>\n</ul>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"2880\" height=\"1920\" src=\"/storage/blog-images/phobie-crise-cardiaque-scaled.jpg\" alt=\"Comment se libérer de la phobie de faire une crise cardiaque ?\" title=\"Conseils pour se libérer de la phobie de faire une crise cardiaque\">\n<h2><b>Comment vaincre la cardiophobie ?</b></h2>\n<p>Voici maintenant différents conseils pour vous permettre de guérir de cette phobie handicapante : </p>\n<h3><b>1 — Vous faire aider </b></h3>\n<p>Je peux vous accompagner dans le traitement de votre phobie. Je propose des séances d’accompagnement d’une durée d’une heure, par téléphone ou en visio. Vous trouverez le lien pour prendre rendez-vous à la fin de cet article. </p>\n<p>Autrement, vous pouvez opter pour une Thérapie cognitive et comportementale (TCC), efficace pour casser les mécanismes de peur et de vérification. Dans certains cas, un traitement médicamenteux, comme la prise d’anxiolytiques ou d’antidépresseurs, peut être envisagé avec un médecin ou un psychiatre. </p>\n<h3><b>2 — Vous relaxer au maximum </b><b><br></b></h3>\n<p>En diminuant votre anxiété en général, vous soulagerez cette phobie. Vous pouvez pratiquer des techniques de relaxation et de respiration comme la méditation, le yoga, la cohérence cardiaque ou la méthode Jacobson, lesquelles soulageront autant votre corps que votre esprit. </p>\n<p>Afin d’apaiser l’anxiété, vous pouvez également vous intéresser à des techniques naturelles, comme la phytothérapie.<br></p>\n<h3><b>3 — Comprendre que les palpitations sont inoffensives </b></h3>\n<p>Les palpitations liées à l’anxiété sont inoffensives. Elles ne provoquent pas de crise cardiaque : elles ne sont que la traduction physique d’un état de stress, d’irritabilité ou de fatigue.</p>\n<p>En effet, si les palpitations surviennent indépendamment de l’effort physique, elles sont souvent dues à des tensions musculaires, comme des maux de tête ou à un manque de sommeil. Le syndrome prémenstruel peut également entraîner des palpitations cardiaques.</p>\n<h3><b>4 — Stopper les mécanismes de réassurance</b></h3>\n<p>Tant que vous chercherez à <a href=\"/besoin-rassure/\" target=\"_blank\" rel=\"noopener\" title=\"besoin d\'être rassuré \">vous faire rassurer</a> (par vos proches, les médecins ou les vérifications), votre cerveau restera persuadé qu’il existe un danger.</p>\n<p>Il faut croire les cardiologues. Dites-vous qu’ils ont l’habitude. S’ils disent qu’il n’y a rien, c’est qu’il n’y a rien.</p>\n<p>La clé de la guérison est d’accepter les émotions et sensations désagréables ressenties dans cette phobie sans chercher à les contrôler.</p>\n<p> </p>\n<p><b>Vaincre la cardiophobie</b> est donc possible grâce à la thérapie, la relaxation, l’arrêt des mécanismes de réassurance et l’acceptation progressive des sensations.  </p>\n<p>Rappelez-vous : un cœur qui bat vite sous l’effet de l’angoisse n’est pas un cœur malade, mais un cœur… qui fonctionne normalement face au stress.</p>','published',1,'Comment vaincre la cardiophobie ? (peur de la crise cardiaque)','La cardiophobie, qui est la peur panique de faire une crise cardiaque, fait partie des troubles anxieux. comment vaincre la cardiophobie ?','https://vivre-pleinement.fr/cardiophobie/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/cardiophobie\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/cardiophobie\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Comment vaincre la cardiophobie ? (peur de la crise cardiaque)\",\"datePublished\":\"2025-08-18T19:43:30+00:00\",\"dateModified\":\"2025-08-18T19:53:21+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/cardiophobie\\/\"},\"wordCount\":2400,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/cardiophobie\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2025\\/08\\/cardiophobie-scaled.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/cardiophobie\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/cardiophobie\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/cardiophobie\\/\",\"name\":\"Comment vaincre la cardiophobie ? (peur de la crise cardiaque)\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/cardiophobie\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/cardiophobie\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2025\\/08\\/cardiophobie-scaled.jpg\",\"datePublished\":\"2025-08-18T19:43:30+00:00\",\"dateModified\":\"2025-08-18T19:53:21+00:00\",\"description\":\"La cardiophobie, qui est la peur panique de faire une crise cardiaque, fait partie des troubles anxieux. comment vaincre la cardiophobie ?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/cardiophobie\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/cardiophobie\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/cardiophobie\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2025\\/08\\/cardiophobie-scaled.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2025\\/08\\/cardiophobie-scaled.jpg\",\"width\":2880,\"height\":1920,\"caption\":\"Comment vaincre la cardiophobie ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/cardiophobie\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Comment vaincre la cardiophobie ? (peur de la crise cardiaque)\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2025-08-18 19:43:30',NULL,'2026-05-24 19:19:43','2026-06-19 21:01:43');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (3,'Le Besoin d’être Rassuré dans l’Anxiété : une Guérison Retardée','besoin-rassure','Vous cherchez sans cesse à être rassuré lorsque vous vous sentez anxieux ? Vous n’êtes pas le seul. En effet, quand les troubles anxieux s’installent, le besoin d’être rassuré dans l’anxiété est un réflexe tout à fait naturel. Que ce soit une douleur physique, une sensation étrange, ou une peur intense comme la peur de devenir […]\n','<p>Vous cherchez sans cesse à être rassuré lorsque vous vous sentez anxieux ? Vous n’êtes pas le seul. En effet, quand les troubles anxieux s’installent, <b>le besoin d’être rassuré dans l’anxiété</b> est un réflexe tout à fait <b>naturel</b>. Que ce soit une <b>douleur physique</b>, une <b>sensation étrange</b>, ou une <b>peur intense</b> comme la peur de devenir fou, nous souhaitons savoir si ce que nous ressentons est <b>normal</b>. Mais est-ce que vous faire rassurer en permanence va réellement vous mettre sur le chemin de la <b>guérison </b>ou au contraire, va vous mettre des <b>bâtons dans les roues</b> ? </p>\n<h2>Les symptômes du besoin de réassurance dans les troubles anxieux </h2>\n<p>Lorsque vous souffrez <a href=\"/angoisse-stress-anxiete/\" target=\"_blank\" rel=\"noopener\" title=\"stress anxiété ou angoisse ?\">d’anxiété sévère</a>, votre principal automatisme consistera à tenter de vous faire rassurer. Vous pouvez effectuer cette action auprès de vos proches, mais aussi très souvent sur Internet. Vous allez vous mettre à consulter des forums, à lire des articles, à regarder des vidéos… mais souvent, vous allez vous retrouver avec plus de questions que de réponses. Et ce mécanisme va en plus nourrir votre angoisse ! </p>\n<p>En effet, les forums sont remplis de personnes vivant la même chose, parfois depuis longtemps, mais qui ne guérissent pas. Sur Internet, les articles se répètent, et certains peuvent en outre amplifier vos peurs. Si vous avez peur de devenir fou, par exemple, vous tomberez forcément sur un article sur la schizophrénie et vous allez bien évidemment vous reconnaître dans certains des symptômes de cette maladie. </p>\n<p>De plus, regarder les mêmes vidéos en boucle pour vous rassurer finit par devenir une habitude, voire même une addiction. Cette quête constante de réassurance soulage un moment, mais elle ne fait que repousser la guérison. Une fois que vous avez regardé une vidéo qui vous a fait du bien, regardez-la une deuxième fois pour mieux la comprendre si vous le désirez, mais arrêtez-vous là. Sinon, celle-ci va entretenir, bien malgré elle, votre anxiété. </p>\n<p>Évitez également d’aller consulter un psychologue dès qu’une crise anxieuse apparaît, ou juste dans le but de vous faire rassurer. Ou d’aller en voir plusieurs afin de leur poser la même question pour voir si, oui ou non, vous allez obtenir une réponse différente. En effet, cette attitude va renforcer votre <a href=\"/troubles-de-la-personnalite/\" target=\"_blank\" rel=\"noopener\" title=\"Troubles de la personnalité\">personnalité dépendante</a> et donc, vous empêcher de guérir de vos angoisses.</p>\n<h2>L’efficacité du mécanisme de réassurance dans l’angoisse </h2>\n<p>Il est donc normal de vouloir vous faire rassurer lorsque vous vous sentez trop anxieux. Mais ce comportement est-il bénéfique pour la guérison de vos troubles ? </p>\n<h3>L’inefficacité de la réassurance sur le long terme</h3>\n<p>Le problème, lorsque vous souhaitez vous faire rassurer, c’est que prononcer des phrases du type : est-ce que ce n’est que de l’anxiété ? Ne suffit pas. Aller voir un médecin ou un psychologue reste une bonne démarche. Cependant, revenir sans arrêt avec les mêmes questions : et si le médecin s’était trompé ? Finit par épuiser tout le monde, y compris vous. En gros, le soulagement que provoque la réassurance reste temporaire. Il peut durer une journée, ou seulement quelques minutes, mais l’anxiété reviendra toujours.</p>\n<h3>L’impact négatif du besoin d’être réconforté sur les proches </h3>\n<p>Le problème dans la réassurance, c’est que votre entourage peut vite se lasser de vos demandes répétées. Vous pouvez d’ailleurs percevoir, si vous les observez un petit peu, leur fatigue ou leur lassitude sur leur visage ou dans le ton de leur voix, ce qui peut vous isoler davantage. Pourtant, vous souffrez vraiment et ce n’est pas facile de gérer ce mal-être. Mais tout porte à croire que constamment vous faire rassurer auprès de vos proches ne fera qu’empirer votre situation. </p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"2880\" height=\"1920\" src=\"/storage/blog-images/rassure-troubles-anxieux-scaled.jpg\" alt=\"Comment stopper le besoin de réassurance dans l\'anxiété ? \" title=\"Conseils pour stopper le besoin de réassurance dans l\'anxiété \">\n<h2>Comment se libérer du besoin d’être rassuré dans l’anxiété ? </h2>\n<p>Heureusement, vous pouvez dès maintenant stopper votre besoin de réassurance, et cette attitude vous mènera sur le chemin de la guérison. Voici mes conseils pour vous aider à y parvenir : </p>\n<h3>Stopper définitivement le mécanisme de réassurance </h3>\n<p>La réassurance est tout simplement une drogue qui vous empêche de guérir. Ce besoin vous apporte, certes, un apaisement immédiat, mais il vous empêche de faire confiance à votre corps et à votre esprit. Tant que vous ne supportez pas de rester en présence de l’anxiété, de l’accepter, que vous ressentez une urgence à la faire disparaître, la guérison restera hors de votre portée.</p>\n<h3>Pratiquer le décalage de la question </h3>\n<p>Si arrêter la recherche de réassurance d’un coup est trop difficile, essayez de décaler votre question ou votre recherche. Par exemple, si vous souhaitez demander à votre mari urgemment : crois-tu que j’ai un cancer ? Au lieu de lui poser la question immédiatement dans le but d’apaiser votre angoisse, posez-la-lui dans 5 heures. 5 heures après, soit vous lui posez la question, soit vous n’y penserez même plus, et c’est très souvent ce qu’il va se passer. Et il s’agit d’ailleurs du but recherché. La méthode du décalage de la question va vous aider à réduire le sentiment d’urgence que vous ressentez, à rester en présence de l’anxiété et donc, à <a href=\"/lacher-prise-et-acceptation/\" target=\"_blank\" rel=\"noopener\" title=\"Lâcher prise et acceptation \">lâcher prise</a> et à guérir. </p>\n<h3>Pratiquer la méditation </h3>\n<p>La méditation reste une excellente méthode pour apprendre à rester avec vos sensations désagréables et à tolérer vos pensées sans jugement. Des applications peuvent vous accompagner dans cette méthode. Je pratique personnellement la méditation tous les jours, d’une durée de 15 minutes à chaque fois environ, et utilise pour ce faire l’application Petit Bambou. Avec 7 €/mois seulement, vous aurez d’innombrables séances de méditation à votre disposition ! </p>\n<h3>Stopper les doubles émotions </h3>\n<p>Surtout, ne luttez pas contre votre angoisse et ne vous jugez pas de ressentir cette émotion. En effet, vous demander : pourquoi j’ai ça ? Je suis nul ne fait qu’empirer la situation. Les doubles émotions, comme la <a href=\"/culpabilite/\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse et culpabilité \">culpabilité s’ajoutant à l’angoisse</a>, ne vous permettront aucunement de guérir. Acceptez ce que vous ressentez, sans chercher à le contrôler. Avec le temps, l’anxiété passera, et c’est de cette façon que vous allez retrouver un équilibre. </p>\n<p></p>\n<p>L<b>e besoin d’être rassuré dans l’anxiété</b> est tout à fait compréhensible, mais il freine votre guérison. En apprenant à tolérer l’anxiété et à faire confiance à votre corps et votre esprit, vous allez enfin ressentir un bien-être durable.</p>','published',1,'Le Besoin d’être Rassuré dans l’Anxiété : une Guérison Retardée','Quand les troubles anxieux s’installent, le besoin d’être rassuré dans l’anxiété est un réflexe tout à fait naturel.','https://vivre-pleinement.fr/besoin-rassure/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/besoin-rassure\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/besoin-rassure\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Le Besoin d\\u2019\\u00eatre Rassur\\u00e9 dans l\\u2019Anxi\\u00e9t\\u00e9\\u00a0: une Gu\\u00e9rison Retard\\u00e9e\",\"datePublished\":\"2025-05-12T13:33:20+00:00\",\"dateModified\":\"2025-05-12T13:39:53+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/besoin-rassure\\/\"},\"wordCount\":2541,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/besoin-rassure\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2025\\/05\\/Besoin-reassurance-anxiete-scaled.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/besoin-rassure\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/besoin-rassure\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/besoin-rassure\\/\",\"name\":\"Le Besoin d\\u2019\\u00eatre Rassur\\u00e9 dans l\\u2019Anxi\\u00e9t\\u00e9\\u00a0: une Gu\\u00e9rison Retard\\u00e9e\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/besoin-rassure\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/besoin-rassure\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2025\\/05\\/Besoin-reassurance-anxiete-scaled.jpg\",\"datePublished\":\"2025-05-12T13:33:20+00:00\",\"dateModified\":\"2025-05-12T13:39:53+00:00\",\"description\":\"Quand les troubles anxieux s\\u2019installent, le besoin d\\u2019\\u00eatre rassur\\u00e9 dans l\\u2019anxi\\u00e9t\\u00e9 est un r\\u00e9flexe tout \\u00e0 fait naturel.\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/besoin-rassure\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/besoin-rassure\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/besoin-rassure\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2025\\/05\\/Besoin-reassurance-anxiete-scaled.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2025\\/05\\/Besoin-reassurance-anxiete-scaled.jpg\",\"width\":2880,\"height\":1920,\"caption\":\"Comment arr\\u00eater de se faire rassurer dans l\'anxi\\u00e9t\\u00e9 ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/besoin-rassure\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Le Besoin d\\u2019\\u00eatre Rassur\\u00e9 dans l\\u2019Anxi\\u00e9t\\u00e9\\u00a0: une Gu\\u00e9rison Retard\\u00e9e\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2025-05-12 13:33:20',NULL,'2026-05-24 19:19:43','2026-06-19 21:01:43');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (4,'Contrôler ses pensées intrusives : ces stratégies maintiennent le mal-être','controler-ses-pensees-intrusives-ces-strategies-maintiennent-le-mal-etre','Lorsque vous souffrez de troubles anxieux, et notamment de TOC, Trouble Obsessionnel Compulsif, c’est que bien souvent vous accordez trop d’importance à vos pensées dites intrusives. Souvent, une personne souffrante tente de contrôler ses pensées intrusives pour diminuer l’anxiété. Pour ce faire, elle utilise des stratégies de contrôle. Mais savez-vous que généralement, ce sont vos […]\n','<p>Lorsque vous souffrez de <b>troubles anxieux</b>, et notamment de <b>TOC, </b>Trouble Obsessionnel Compulsif, c’est que bien souvent vous accordez trop d’importance à vos pensées dites intrusives. Souvent, une personne souffrante tente de <b>contrôler ses pensées intrusives</b> pour diminuer l’anxiété. Pour ce faire, elle utilise des stratégies de contrôle. Mais savez-vous que généralement, ce sont vos <b>stratégies de contrôle</b> qui vous maintiennent dans votre angoisse ? Quelles stratégies de contrôle sont à éviter pour pouvoir calmer au plus vite vos idées qui reviennent en boucle ? </p>\n<h2>Contrôler ses pensées intrusives avec des stratégies de contrôle contre-productives </h2>\n<p>Lorsque vous souffrez de pensées intrusives, vous essayez bien souvent de les contrôler par divers moyens pour aller mieux. Or, les stratégies listées ci-dessous, qui semblent fonctionner, vous maintiennent à contrario dans vos pensées envahissantes. Les connaître vous permettra de faire un premier pas sur le chemin de la guérison. Il est certain que vous vous reconnaîtrez dans quelques comportements ci-après. En gros, lorsque des <a href=\"/ruminations/\" target=\"_blank\" rel=\"noopener\">ruminations mentales</a> et désagréables surgissent dans votre esprit, vous pouvez agir de plusieurs façons, toutes improductives : </p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">si une partie de vous pense que vous êtes un raté, une autre partie s’insurge et affirme le contraire en citant toutes vos réalisations passées ;</li>\n<li aria-level=\"1\">vous tentez d’éviter ou de réprimer vos émotions négatives. Or, plus vous allez déployer d’efforts en ce sens, plus vous ressentirez d’émotions désagréables ;</li>\n<li aria-level=\"1\">l’évitement des gens, des endroits ou des situations qui font surgir l’émotion désagréable ;</li>\n<li aria-level=\"1\">boire de l’alcool ;</li>\n<li aria-level=\"1\">vous dénigrer ;</li>\n<li aria-level=\"1\">blâmer les autres ;</li>\n<li aria-level=\"1\">faire de la visualisation ; </li>\n<li aria-level=\"1\">lire des ouvrages de développement personnel ; </li>\n<li aria-level=\"1\">suivre une thérapie avec un psychologue, une TCC (thérapie comportementale) avec un thérapeute ou consulter un coach ; </li>\n<li aria-level=\"1\">prier ;</li>\n<li aria-level=\"1\">vous confier à des amis ; </li>\n<li aria-level=\"1\">manger ; </li>\n<li aria-level=\"1\">dormir ; </li>\n<li aria-level=\"1\">reporter une décision ou un changement important ; </li>\n<li aria-level=\"1\">vous perdre dans le travail, les mondanités ou le sport ;</li>\n<li aria-level=\"1\">vous dire : ça va passer ; </li>\n<li aria-level=\"1\">pratiquer des techniques de respiration, de relaxation.</li>\n</ul>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"2880\" height=\"1920\" src=\"/storage/blog-images/maitriser-pensees-desagreables-scaled.jpg\" alt=\"Comment maîtriser les pensées désagréables ?\" title=\"Conseils pour maîtriser les pensées désagréables\">\n<h2>Pourquoi ces stratégies de contrôle entretiennent les pensées désagréables ?</h2>\n<p>Il est important de comprendre que le problème n’est pas le comportement en lui-même, car après tout, il est indispensable de dormir, de manger, ou très appréciable de se confier à des amis quand nous ne nous sentons pas bien. Le problème est d’utiliser un comportement répétitif dès lors qu’une pensée intrusive survient. En fait, le comportement ne doit pas avoir pour but de neutraliser la pensée intrusive. Autrement, c’est qu’il s’agit d’une stratégie de contrôle.</p>\n<p>Par exemple, vous avez totalement le droit de pratiquer des techniques de relaxation. C’est même d’ailleurs plutôt recommandé ! Admettons que votre but est d’apprendre à apparaître plus calme en toute circonstance et de manière générale dans votre vie. Vous vous mettez alors à pratiquer le yoga tous les matins pendant une demi-heure, Mais si, maintenant, vous ne vous mettez à faire du yoga que lorsqu’une pensée intrusive survient et qu’elle commence à vous faire paniquer, il s’agit d’une stratégie de contrôle. </p>\n<p>À vous donc d’analyser si un des comportements listés ci-dessus ne vous sert qu’à fuir vos pensées qui se répètent sans cesse. Si c’est cela, c’est qu’il s’agit d’une stratégie comportementale de contrôle. Si vos comportements sont plutôt pour vous une philosophie de vie, c’est qu’ils sont sains et efficaces. </p>\n<h2>Exercice pour revoir vos stratégies de contrôle des pensées désagréables </h2>\n<p>Vous avez réussi à détecter vos stratégies de contrôle ? Voici un petit exercice qui vous permettra de prendre conscience que vos stratégies sont clairement contre-productives pour vous libérer de vos pensées récurrentes.</p>\n<p>Déjà, notez sur une feuille de papier les pensées répétitives et les émotions dont vous aimeriez le plus vous débarrasser.  </p>\n<p>Puis, listez les comportements répétitifs que vous utilisez pour tenter de vous libérer de vos pensées obsessionnelles.</p>\n<p>Ensuite, posez-vous les questions suivantes pour chaque stratégie que vous utilisez (vous pouvez le présenter sous forme de tableau). Voici un exemple : </p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">Ma stratégie de contrôle : <a href=\"/addictions/\" target=\"_blank\" rel=\"noopener\">boire de l’alcool </a></li>\n<li aria-level=\"1\"><b>ai-je réussi à me débarrasser à long terme de ces pensées ? </b><i>Non, car dès que la sensation de mieux-être due à l’alcool s’estompe, mes pensées reviennent </i></li>\n</ul>\n<ul>\n<li aria-level=\"1\"><b>quels sont les coûts en temps, en énergie, en argent, en santé, en relations et en vitalité ? </b><i>Je bois quelquefois en me posant sans faire grand-chose, je perds donc du temps. Je pourrais plutôt à la place réaliser des actions constructives. L’alcool coûte tout de même cher et je n’ai aucune vitalité après avoir bu, je vais faire une sieste.</i></li>\n</ul>\n<ul>\n<li aria-level=\"1\"><b>Cela m’a-t-il rapproché d’une vie riche et pleine de sens ? </b><i>Non…</i></li>\n</ul>\n<p><b></b></p>\n<p>C’était un exemple assez simple, puisque nous savons que l’alcool n’est pas très bon pour la santé. Mais si vous aimez boire un petit verre de temps à autre, avec des amis, par exemple, pas de problème. Cela devient une stratégie de contrôle à partir du moment où vous voulez boire pour éviter vos <a href=\"/angoisse-stress-anxiete/\" target=\"_blank\" rel=\"noopener\">pensées anxieuses.</a></p>\n<p> </p>\n<p>Vous l’avez donc compris, <b>contrôler ses pensées intrusives</b>, n’aide pas à s’en libérer ! À vous de faire le point sur les stratégies de contrôle improductives que vous utilisez, et tentez de les tenir à distance. Vous verrez que votre état va grandement s’améliorer. </p>\n<p><a href=\"https://amzn.to/3WObKrL\" target=\"_blank\" rel=\"noopener\">Visitez Amazon pour vous procurer le livre </a>de Russ Harris « Le piège du bonheur : créez la vie que vous voulez »</p>\n<p>(Lien rémunéré par Amazon)</p>','published',1,'Contrôler ses pensées intrusives : ces stratégies maintiennent le mal-être','Une personne souffrante tente de contrôler ses pensées intrusives pour diminuer l’anxiété. Mais vos stratégies de contrôle maintiennent le mal-être.','https://vivre-pleinement.fr/controler-ses-pensees-intrusives-ces-strategies-maintiennent-le-mal-etre/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/controler-ses-pensees-intrusives-ces-strategies-maintiennent-le-mal-etre\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/controler-ses-pensees-intrusives-ces-strategies-maintiennent-le-mal-etre\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Contr\\u00f4ler ses pens\\u00e9es intrusives\\u00a0: ces strat\\u00e9gies maintiennent le mal-\\u00eatre\",\"datePublished\":\"2024-08-18T16:36:45+00:00\",\"dateModified\":\"2024-08-18T16:41:00+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/controler-ses-pensees-intrusives-ces-strategies-maintiennent-le-mal-etre\\/\"},\"wordCount\":1880,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/controler-ses-pensees-intrusives-ces-strategies-maintiennent-le-mal-etre\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2024\\/08\\/controler-pensees-intrusives.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/controler-ses-pensees-intrusives-ces-strategies-maintiennent-le-mal-etre\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/controler-ses-pensees-intrusives-ces-strategies-maintiennent-le-mal-etre\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/controler-ses-pensees-intrusives-ces-strategies-maintiennent-le-mal-etre\\/\",\"name\":\"Contr\\u00f4ler ses pens\\u00e9es intrusives\\u00a0: ces strat\\u00e9gies maintiennent le mal-\\u00eatre\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/controler-ses-pensees-intrusives-ces-strategies-maintiennent-le-mal-etre\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/controler-ses-pensees-intrusives-ces-strategies-maintiennent-le-mal-etre\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2024\\/08\\/controler-pensees-intrusives.jpg\",\"datePublished\":\"2024-08-18T16:36:45+00:00\",\"dateModified\":\"2024-08-18T16:41:00+00:00\",\"description\":\"Une personne souffrante tente de contr\\u00f4ler ses pens\\u00e9es intrusives pour diminuer l\\u2019anxi\\u00e9t\\u00e9. Mais vos strat\\u00e9gies de contr\\u00f4le maintiennent le mal-\\u00eatre.\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/controler-ses-pensees-intrusives-ces-strategies-maintiennent-le-mal-etre\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/controler-ses-pensees-intrusives-ces-strategies-maintiennent-le-mal-etre\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/controler-ses-pensees-intrusives-ces-strategies-maintiennent-le-mal-etre\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2024\\/08\\/controler-pensees-intrusives.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2024\\/08\\/controler-pensees-intrusives.jpg\",\"width\":2200,\"height\":1529,\"caption\":\"Comment se lib\\u00e9rer des pens\\u00e9es intrusives ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/controler-ses-pensees-intrusives-ces-strategies-maintiennent-le-mal-etre\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Contr\\u00f4ler ses pens\\u00e9es intrusives\\u00a0: ces strat\\u00e9gies maintiennent le mal-\\u00eatre\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2024-08-18 16:36:45',NULL,'2026-05-24 19:19:43','2026-06-19 21:01:43');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (5,'L’Effet-Miroir : le Meilleur Moyen de Guérir notre Inconscient','effet-miroir','Vous souvenez-vous de l’expression que nous avons tous dite lorsque nous étions petits : celui qui dit celui qui est ? quand nous disions à quelqu’un : tu es bête, on nous répondait : celui qui dit celui qui est ! L’effet miroir, c’est un peu ça, mais de manière plus élaborée quand même ! \n','<p>Vous souvenez-vous de l’expression que nous avons tous dite lorsque nous étions petits : celui qui dit celui qui est ? quand nous disions à quelqu’un : tu es bête, on nous répondait : celui qui dit celui qui est ! <b>L’effet miroir</b>, c’est un peu ça, mais de manière plus élaborée quand même ! </p>\n<h2>La place du conscient de l’inconscient dans l’effet-miroir</h2>\n<p>Il faut savoir que, non pas que dans les <a href=\"/angoisse-stress-anxiete\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse stress anxiété\">troubles anxieux</a> mais aussi dans notre vie en général, l’inconscient joue énormément dans notre mal-être lorsque nous avons des blocages. Nous ne savons pas d’où cela vient.</p>\n<p>Vous avez déjà sûrement dû entendre parler de ce principe de l’iceberg où l’on ne voit que la pointe de celui-ci. Imaginez un iceberg dans une mer. La toute petite pointe, c’est votre conscient. C’est ce que les gens voient et c’est ce que vous comprenez de vous et du monde. </p>\n<p>Par exemple, je vais me mettre au sport : c’est conscient, clair, net et précis. Vous allez vous adonner à cette activité. Il s’agit de la pointe de l’iceberg.</p>\n<p>Il y a également tout l’inconscient, c’est-à-dire, comme son nom l’indique, ce dont vous n’avez pas conscience. L’inconscient représente l’énorme partie immergée de l’iceberg dans la mer. Et c’est cette partie qui dirige votre vie.</p>\n<p>Prenons l’exemple des affirmations positives. Je suis tombée dans ce jeu aussi. Vous avez dû entendre qu’à force d’affirmer des choses positives, vous allez finir par y croire ou par le devenir. Par exemple, vous n’avez absolument pas <a href=\"/confiance-et-estime-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Confiance et estime de soi \">confiance en vous</a>, et tous les jours, vous vous dites « j’ai confiance en moi, je suis capable », et ça ne marche pas ! Parce que déjà, vous n’y croyez pas et qu’en plus, ces affirmations agissent seulement sur la partie consciente. La grosse portion inconsciente, elle, continue de ne pas confiance en elle. </p>\n<h2>Comment accéder à l’inconscient grâce à l’effet-miroir ?</h2>\n<p>Personnellement, pour guérir, j’ai souvent voulu savoir comment accéder à mon inconscient, mais je ne savais pas comment y parvenir. Il y avait bien l’hypnose, mais ce n’est pas trop mon style de thérapie. Et l’effet miroir m’a permis d’y arriver !</p>\n<h3>Utiliser l’effet-miroir pour découvrir nos parts d’ombre </h3>\n<p>Le principe de l’effet miroir permet de nous connaître au travers des gens et du monde qui nous entourent et plus particulièrement au travers de ceux que nous critiquons. C’est le principe de la projection. La projection est un mécanisme psychologique de défense qui nous pousse à attribuer aux autres personnes des sentiments, des intentions et des pensées qui nous sont propres mais que nous jugeons inacceptables. Du coup, nous les répercutons sur les autres.</p>\n<p>Par exemple, au travail, il y a une personne que vous trouvez très chiante, parce qu’elle est hyper <a href=\"/perfectionnisme\" target=\"_blank\" rel=\"noopener\" title=\"Perfectionnisme\">perfectionniste</a>, qu’elle parle d’un ton un peu sec quand elle est stressée, etc. et vous ne supportez pas ça, cela vous horripile. Eh bien, demandez-vous si vous n’êtes pas comme ça aussi ! </p>\n<p>Le truc, c’est que les défauts qui ne vous dérangent pas chez quelqu’un, vous ne les avez pas ou du moins, ils ne sont pas prédominants chez vous. Par exemple, vous connaissez un proche qui est très narcissique et cela ne vous dérange pas. C’est donc que vous n’êtes pas narcissique ou que du moins, ce trait de caractère n’est pas prédominant chez vous. En gros, ce que nous ne détectons pas chez les autres, nous ne l’avons pas. Ce que nous percevons chez les autres, nous l’avons aussi. </p>\n<p>Par contre, vous pouvez tout de même percevoir qu’une personne est égocentrique, mais si cela ne vous touche pas, c’est que vous n’avez pas ce tempérament. Si son attitude ne vous agace pas, c’est que vous n’avez pas ce défaut ou cette blessure tout simplement.</p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"426\" src=\"/storage/blog-images/effet-miroir-conscient-inconscient.jpg\" alt=\"Le conscient et l’inconscient dans l’effet-miroir \" title=\"Quelle est la place du conscient et de l’inconscient dans l’effet-miroir ?\">\n<h3>Se servir de l’effet-miroir pour prendre conscience de nos qualités </h3>\n<p>Bien évidemment, l’effet miroir ne marche pas que pour le négatif : cela fonctionne aussi pour le positif. Si vous avez des amis, vous ne les choisissez pas en fonction de leurs défauts, mais plutôt en fonction de leurs qualités qui sont similaires aux vôtres. Par exemple, fiable, à l’écoute, avec un gros sens de l’humour, etc. Vous vous identifiez à cette personne et c’est pourquoi elle devient votre amie. C’est ce que l’on appelle les affinités.</p>\n<p>Nous le voyons bien, par exemple dans une salle de classe quand nous étions plus jeunes. Sur 30 élèves, nous n’étions pas tous les 30 main dans la main à nous aimer. Il y a des gens que nous n’aimions pas du tout, d’autres dont on se fichait et d’autres avec qui nous avions une superbe affinité. Nous avons tous été comme ça à l’école, cela s’appelle un feeling. Et le feeling se base sur ce que vous avez de similairement positif avec une autre personne.</p>\n<h3>L’effet-miroir pour découvrir des capacités insoupçonnées </h3>\n<p> Il y a aussi des gens qui peuvent vous inspirer. Cela peut être une célébrité. Car oui, vous allez vous ficher de certaines stars mais pas d’autres. Celle que vous admirez est celle dont vous ne savez pas avoir les mêmes qualités ou dont vous n’osez pas être comme elle. Vous n’osez pas développer la qualité que cette personne possède. Ainsi, si vous n’aviez pas la même qualité que l’autre ou la même capacité à pouvoir être comme l’autre, vous ne le percevriez pas. C’est important de le savoir. </p>\n<h3>L’effet-miroir pour reconnaître nos sentiments négatifs </h3>\n<p>L’effet-miroir marche donc pour le négatif et le positif, mais il existe une exception à la règle. En effet, il y a des gens que vous détesterez, mais cela ne voudra pas forcément dire qu’ils vous ressemblent. Cependant, ceux-ci font ressortir chez vous un sentiment de jalousie, d’infériorité.</p>\n<p>Par exemple, vous êtes une femme, travaillez de 8 h à 17 h et avez deux enfants. Vous devez vous occuper, en rentrant, de toutes les tâches : préparer à manger, vous occuper des enfants, etc. À côté, vous connaissez une personne, qui a deux enfants et un mari comme vous mais la différence, c’est que son mari est millionnaire. Du coup, cette femme ne travaille pas. Elle vous dit : « moi, je vis de ma passion ! » Elle vit ainsi tranquillement de ses passions alors que vous, vous vous démenez au travail. En plus de cela, elle ne supporte pas trop ses enfants et donc, les emmène souvent chez la nounou. En outre, elle veut que son homme, qui rapporte beaucoup d’argent, travaille moins, s’occupe des petits et d’elle. </p>\n<p>Du coup, vous allez détester cette personne, non pas parce qu’elle vous ressemble, mais parce que vous allez être jalouse de ne pas pouvoir vous détendre comme elle peut se détendre. De ne pas pouvoir faire le job de vos rêves car il y a trop de risques pour vous. Vous avez l’impression d’être inférieure à elle, avec un <a href=\"/je-suis-jaloux\" target=\"_blank\" rel=\"noopener\" title=\"Je suis jaloux\">sentiment de jalousie</a>. C’est une sorte d’effet miroir sur vos sentiments négatifs, et non sur le fait de ressembler à cette personne. Pour l’exemple ci-dessus, arrêtez de vous sentir inférieure. Bougez-vous pour faire changer les choses dans votre existence si elles ne vous conviennent pas. </p>\n<p> </p>\n<p>Si vous appliquez<b> l’effet miroir</b> dans votre vie, vous allez être surpris des résultats. C’est comme ça que vous allez découvrir les blessures et les blocages se trouvant dans votre inconscient. Une grande part d’inconscient va devenir consciente, et vous verrez que cela va tout changer chez vous.</p>\n<p>(si mon travail vous aide 🙂)</p>','published',1,'L’Effet-Miroir : le Meilleur Moyen de Guérir notre Inconscient','Vous souvenez-vous de l’expression : celui qui dit celui qui est ? L’effet-miroir, c’est un peu ça, mais de manière plus élaborée !','https://vivre-pleinement.fr/effet-miroir/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/effet-miroir\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/effet-miroir\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"L\\u2019Effet-Miroir\\u00a0: le Meilleur Moyen de Gu\\u00e9rir notre Inconscient\",\"datePublished\":\"2023-10-19T18:15:33+00:00\",\"dateModified\":\"2023-10-19T18:15:35+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/effet-miroir\\/\"},\"wordCount\":2681,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/effet-miroir\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2023\\/10\\/effet-miroir-guerir-inconscient.jpg\",\"articleSection\":[\"D\\u00e9veloppement personnel\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/effet-miroir\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/effet-miroir\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/effet-miroir\\/\",\"name\":\"L\\u2019Effet-Miroir\\u00a0: le Meilleur Moyen de Gu\\u00e9rir notre Inconscient\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/effet-miroir\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/effet-miroir\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2023\\/10\\/effet-miroir-guerir-inconscient.jpg\",\"datePublished\":\"2023-10-19T18:15:33+00:00\",\"dateModified\":\"2023-10-19T18:15:35+00:00\",\"description\":\"Vous souvenez-vous de l\\u2019expression : celui qui dit celui qui est\\u2009? L\\u2019effet-miroir, c\\u2019est un peu \\u00e7a, mais de mani\\u00e8re plus \\u00e9labor\\u00e9e !\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/effet-miroir\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/effet-miroir\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/effet-miroir\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2023\\/10\\/effet-miroir-guerir-inconscient.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2023\\/10\\/effet-miroir-guerir-inconscient.jpg\",\"width\":640,\"height\":451,\"caption\":\"Utiliser l\\u2019effet-miroir pour guerir notre inconscient\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/effet-miroir\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"L\\u2019Effet-Miroir\\u00a0: le Meilleur Moyen de Gu\\u00e9rir notre Inconscient\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2023-10-19 18:15:33',NULL,'2026-05-24 19:19:43','2026-06-19 22:28:14');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (6,'Cause des Troubles anxieux : pourquoi les Connaître ne sert à Rien ?','cause-des-troubles-anxieux','Il y a des gens souffrant de forte anxiété et pas d’autres, c’est un fait. Vous vous demandez pourquoi vous et pas les autres. Quand nous ressentons une anxiété importante, nous voulons connaître la cause : pourquoi je suis comme ça ? Pourquoi moi ? Qu’est-ce qui a fait que je suis comme ça ? Vous pouvez penser à un décès, à quelque chose d’enfoui dans votre inconscient dont vous n’arrivez plus à vous souvenir, à un traumatisme survenu trop jeune, par exemple lorsque vous étiez bébé. En réalité, vous pensez qu’il existe une cause profonde à vos fortes angoisses et qu’en la découvrant, vous allez vous libérer de l’angoisse permanente. Dans cet article, je vais vous expliquer pourquoi il est inutile de trouver la cause des troubles anxieux dont vous êtes victime. \n','<p>Il y a des gens souffrant de forte anxiété et pas d’autres, c’est un fait. Vous vous demandez pourquoi vous et pas les autres. Quand nous ressentons une anxiété importante, nous voulons connaître la cause : pourquoi je suis comme ça ? Pourquoi moi ? Qu’est-ce qui a fait que je suis comme ça ? Vous pouvez penser à un <b>décès</b>, à quelque chose d’enfoui dans votre <b>inconscient </b>dont vous n’arrivez plus à vous souvenir, à un <b>traumatisme </b>survenu trop jeune, par exemple lorsque vous étiez <b>bébé</b>. En réalité, vous pensez qu’il existe une cause profonde à vos fortes angoisses et qu’en la <b>découvrant</b>, vous allez vous <b>libérer </b>de l’angoisse permanente. Dans cet article, je vais vous expliquer pourquoi il est <b>inutile </b>de trouver la <b>cause des troubles anxieux </b>dont vous êtes victime. </p>\n<h2>Découvrir la raison de son angoisse constante pour guérir d’après la psychanalyse </h2>\n<p>La <a href=\"/psychotherapie-et-psychanalyse\" target=\"_blank\" rel=\"noopener\" title=\"Psychothérapie et psychanalyse \">psychanalyse</a>, une méthode de thérapie, a beaucoup participé à cette idée reçue. Durant une séance de psychanalyse, le patient ne fait que parler et le psychologue ne parle pas. Le but est de découvrir la cause profonde dans l’inconscient qui ferait que la personne ressent des angoisses profondes. On nous fait croire qu’il s’agit de la clé de la guérison et honnêtement, j’y ai cru pendant très longtemps. Je me disais : mais ça vient d’où exactement ? Je voulais LA cause qui allait me guérir et apaiser l’angoisse. </p>\n<p> Le problème, c’est que je n’ai jamais trouvé de réponse parce qu’en réalité, une multitude d’événements peut provoquer l’anxiété chronique. Tout simplement car la vie est un parcours jonché d’expériences quotidiennes, positives comme négatives.</p>\n<h2>La raison transgénérationnelle de l’angoisse chronique</h2>\n<p>Dans certains cas, <a href=\"/angoisse-stress-anxiete\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse stress anxiété \">l’angoisse profonde</a> peut se transmettre de façon transgénérationnelle, c’est-à-dire par le biais de vos ancêtres. Cette transmission peut s’effectuer sur trois générations. Par exemple, votre grand-père a souffert d’angoisse intense et vous avez récupéré son anxiété excessive. En gros, cette profonde angoisse ne vous appartient pas : c’est possible. Cependant, bon courage pour chercher la cause exacte de chaque ancêtre ! </p>\n<p>En effet, nous avons déjà du mal, dans notre propre existence, à découvrir la cause exacte d’un état d’angoisse, alors imaginez un grand-père ou un arrière- grand-père ! Comment voulez-vous connaître sa vie dans les moindres détails et la raison précise l’ayant fait devenir anxieux ?  </p>\n<p>Il faut comprendre que l’être humain demeure complexe. Vous ne pouvez connaître la vie de votre grand-père de A à Z. Seulement lui la connaissait, peut-être même pas ses proches. </p>\n<p>Et quand bien même votre grand-père vous aurait transmis stress et angoisse, c’est à vous maintenant de vous libérer de cette inquiétude excessive. Donc, dans tous les cas, savoir qu’il s’agit de votre grand-père ne change rien. </p>\n<h2>Chercher le déclencheur de l’anxiété pathologique dans les vies antérieures </h2>\n<p>On y croit ou pas, mais certaines personnes cherchent dans leurs vies antérieures la cause de leur angoisse diffuse. Elles veulent avoir des souvenirs de leurs vies antérieures et se rendent chez un thérapeute spécialisé dans ce domaine pour y parvenir. </p>\n<p>J’ai personnellement un avis là-dessus. Je trouve que nous avons déjà bien assez de problèmes dans cette vie pour nous occuper des vies d’avant. Je pense que si nous nous rappelions de toutes nos anciennes existences, nous deviendrions dingues… non ?</p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"427\" src=\"/storage/blog-images/Raison-angoisse.jpg\" alt=\"origine anxiete \" title=\"Raison-angoisse\">\n<h2>Connaître la cause des troubles anxieux ne soigne pas </h2>\n<p>Est-ce qu’une seule expérience a provoqué votre trouble d’anxiété ? Je ne pense pas. Cela peut cependant être le cas suite à un <a href=\"/traumatisme\" target=\"_blank\" rel=\"noopener\" title=\"Traumatisme \">traumatisme</a> vécu. Par exemple, tout va bien, vous n’êtes pas une personne anxieuse, et un jour, vous avez un accident assez grave de voiture. Vous en êtes sorti traumatisé et depuis, vous craignez de prendre la voiture. Vous avez développé la phobie de conduire, et ça peut se comprendre. </p>\n<p>Dans cet exemple, la cause est connue. Et est-ce que cela vous fait guérir pour autant ? Malheureusement, non. Au contraire, vous évitez de conduire. </p>\n<p>Un autre exemple. La <a href=\"/thanatophobie\" target=\"_blank\" rel=\"noopener\" title=\"Thanatophobie\">peur de la mort</a> reste commune à chaque être humain. Sauf si nous sommes des êtres mystiques, en général, tout le monde appréhende la mort. Pourquoi ? Car nous savons consciemment que nous sommes mortels. </p>\n<p>Cependant, n’en avons-nous plus peur car nous le savons ? Malheureusement non. Nous avons toujours autant peur de la mort.</p>\n<p>Pour moi, chercher la cause de son anxiété permanente est une perte de temps. Quand bien même vous trouveriez une cause, cela ne vous servirait à rien. </p>\n<p> C’est comme si soudainement, vous allez vous réveiller en vous disant : <i>ah mais oui, c’est ça en fait mon problème, c’est à cause de ça ! </i>Pas sûre que votre problème d’anxiété va partir du jour au lendemain malgré cette découverte.</p>\n<p> Le problème aussi, c’est que plus vous cherchez des causes de votre peur généralisée, plus vous êtes focalisé sur l’angoisse. Et plus vous restez focalisé sur l’angoisse, plus vous vous maintenez votre peur exagérée et donc, diminuez vos chances de guérison. Vous perdez de l’énergie inutilement, laquelle n’est pas focalisée dans la bonne direction.</p>\n<p>Je voulais vous parler de ce sujet car pour moi, le principal piège dans lequel nous tombons au début est que nous souhaitons connaître la <b>cause des troubles anxieux</b> en pensant qu’il s’agit de la clé de la guérison. Je souhaite vous éviter de perdre un temps de dingue comme moi j’ai pu en perdre, simplement parce que je désirais connaître la cause de mon sentiment d’angoisse. Focalisez-vous plutôt sur les solutions, et vous verrez que cela va grandement vous aider !   </p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'Cause des Troubles anxieux : pourquoi les Connaître ne sert à Rien ?','Dans cet article, je vais vous expliquer pourquoi il est inutile de trouver la cause des troubles anxieux dont vous êtes victime.','https://vivre-pleinement.fr/cause-des-troubles-anxieux/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/cause-des-troubles-anxieux\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/cause-des-troubles-anxieux\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Cause des Troubles anxieux\\u00a0: pourquoi les Conna\\u00eetre ne sert \\u00e0 Rien\\u2009?\",\"datePublished\":\"2023-09-21T18:34:45+00:00\",\"dateModified\":\"2023-09-21T18:36:50+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/cause-des-troubles-anxieux\\/\"},\"wordCount\":2000,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/cause-des-troubles-anxieux\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2023\\/09\\/Cause-troubles-anxieux.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/cause-des-troubles-anxieux\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/cause-des-troubles-anxieux\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/cause-des-troubles-anxieux\\/\",\"name\":\"Cause des Troubles anxieux\\u00a0: pourquoi les Conna\\u00eetre ne sert \\u00e0 Rien\\u2009?\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/cause-des-troubles-anxieux\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/cause-des-troubles-anxieux\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2023\\/09\\/Cause-troubles-anxieux.jpg\",\"datePublished\":\"2023-09-21T18:34:45+00:00\",\"dateModified\":\"2023-09-21T18:36:50+00:00\",\"description\":\"Dans cet article, je vais vous expliquer pourquoi il est inutile de trouver la cause des troubles anxieux dont vous \\u00eates victime.\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/cause-des-troubles-anxieux\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/cause-des-troubles-anxieux\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/cause-des-troubles-anxieux\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2023\\/09\\/Cause-troubles-anxieux.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2023\\/09\\/Cause-troubles-anxieux.jpg\",\"width\":640,\"height\":480,\"caption\":\"Connaitre la cause des troubles anxieux ne sert a rien\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/cause-des-troubles-anxieux\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Cause des Troubles anxieux\\u00a0: pourquoi les Conna\\u00eetre ne sert \\u00e0 Rien\\u2009?\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2023-09-21 18:34:45',NULL,'2026-05-24 19:19:43','2026-06-19 22:28:14');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (7,'Ne Rien Attendre des Autres pour une Vie Épanouie ','ne-rien-attendre-des-autres','Dans notre société moderne, nous sommes tous interconnectés, et ce, grâce aux échanges donnant-donnant, lesquels nous permettent de survivre et de combler nos besoins. Nous avons donc besoin des autres, que ce soit d’un médecin pour un examen médical, ou d’un patron pour obtenir un salaire, par exemple. Nous donnons quelque chose pour recevoir autre chose. Ces attentes formelles sont normales et font tourner la société. Le problème, c’est lorsque celles-ci dirigent votre vie, au point de vous rendre anxieux et malheureux. Votre ami ne répond pas à vos messages. Vous travaillez sans relâche dans votre job et votre boss le sait, mais il ne vous augmente pas pour autant. Ce sont principalement ces attentes, basées généralement sur des besoins émotionnels, qui impactent négativement votre existence. Ne rien attendre des autres, est-ce vraiment possible ? Si oui, comment y parvenir ?  \n','<p>Dans notre société moderne, nous sommes tous <b>interconnectés</b>, et ce, grâce aux <b>échanges donnant-donnant</b>, lesquels nous permettent de <b>survivre et de combler nos besoins.</b> Nous avons donc besoin des autres, que ce soit d’un médecin pour un examen médical, ou d’un patron pour obtenir un salaire, par exemple. Nous donnons quelque chose pour recevoir autre chose. Ces attentes formelles sont <b>normales et font tourner la société</b>. Le problème, c’est lorsque celles-ci <b>dirigent votre vie</b>, au point de vous rendre<b> anxieux et malheureux. </b>Votre ami ne répond pas à vos messages. Vous travaillez sans relâche dans votre job et votre boss le sait, mais il ne vous augmente pas pour autant. Ce sont principalement ces attentes, basées généralement sur des <b>besoins émotionnels</b>, qui impactent négativement votre existence. <b>Ne rien attendre des autres, </b>est-ce vraiment possible ? Si oui, comment y parvenir ?  </p>\n<h2>Avons-nous tous des attentes ?</h2>\n<p>Qu’on se l’avoue ou non, nous avons tous des attentes. Cependant, celles-ci demeurent bien souvent inconscientes. En fait, vous ne dites pas directement à quelqu’un : « j’attends de toi que… », car il est normal que cette personne accomplisse telle chose pour vous. Par exemple, un ami doit répondre à votre message. Autrement, c’est qu’il s’en fiche. </p>\n<p>À partir du moment où vous utilisez les termes « il faut, je dois », c’est qu’il y a une attente. La vôtre ou celle de quelqu’un d’autre. Par exemple, si vous vous dites : « je dois faire le ménage le samedi », c’est parce que votre mari, en rentrant du travail, s’attend à ce que la maison soit propre. </p>\n<p>Au final, tout le monde a des attentes, hormis, peut-être, les sages mystiques, mais la plupart d’entre nous ne nous trouvons pas dans cette sphère. Le problème survient lorsque vos attentes élevées vous gâchent la vie avec de nombreuses émotions désagréables, comme l’angoisse, la déception, la tristesse, la colère, etc. </p>\n<h2>Des attentes mutuelles avec la relation donnant-donnant </h2>\n<p>Le problème principal des attentes élevées est la relation que nous avons avec les autres, laquelle est, la plupart du temps, donnant-donnant. Nous pensons cela normal, mais cela ne l’est pas tant que ça. </p>\n<p>Par exemple, un parent va dire aimer inconditionnellement son enfant. Sauf qu’il s’attend à ce que son enfant s’occupe de lui quand il sera vieux. Si maintenant, l’enfant devenu adulte ne donnait plus du tout signe de vie, le parent serait dévasté, en prononçant ce genre de phrase : « après tout ce que j’ai fait pour toi ! » </p>\n<p>Il est dommage d’avoir toujours l’impression de devoir rembourser une dette lorsqu’un proche fait quelque chose pour nous. Par exemple, vous payez le restaurant à un ami, et celui-ci va tout faire pour vite vous en payer un autre. Pourquoi ne pas faire les choses parce que cela nous fait plaisir sans se sentir forcé de devoir rendre la pareille ? </p>\n<p>Bien évidemment, il faut nuancer. Si votre copain profite de vous sans jamais vous rendre un seul service, que vous êtes toujours obligé d’aller vers lui, etc., mieux vaut, dans ce cas, laisser tomber cette relation qui apparaît plutôt toxique. </p>\n<p>Autre exemple : nos collègues au travail nous adorent, parce que nous les soulageons dans leur travail. Nous accomplissons quelque chose pour eux. Si demain, une dépression nous empêche d’aller au travail, ils vont nous oublier et ne plus prendre aucune nouvelle. Car leurs attentes ne seront plus comblées. </p>\n<p>C’est triste, mais c’est la vérité : dans la plupart des relations, (amicale, familiale, professionnelle, etc..) si vous y enlevez toutes les fioritures, ces relations ne dureront pas. Tout simplement, car nous agissons tous sur le modèle donnant-donnant. </p>\n<h2>Les attentes élevées dans la dépendance affective </h2>\n<p>Les personnes ayant une <a href=\"/blessure-dabandon\" target=\"_blank\" rel=\"noopener\" title=\"Blessure d\'abandon\">blessure d’abandon</a> proéminente ont une dépendance affective et ne veulent surtout pas être abandonnées. Elles peuvent donc étouffer les autres, avec leur jalousie, par exemple. Elles ont des attentes bien trop élevées par rapport à leurs semblables du fait de leur peur d’être abandonnées. Leur bonheur dépend entièrement d’autrui, et c’est là que le bât blesse, car lorsque notre bien-être dépend de l’extérieur, il demeurera forcément fluctuant. En effet, on ne peut contrôler les autres et les situations extérieures. </p>\n<p>La dépendance affective impacte la vie de la personne en globalité. Par exemple, une personne va se donner corps et âme au travail dans le but d’être reconnue par son patron et ses collègues. Elle souhaite, inconsciemment, obtenir de l’amour de leur part, alors que ce n’est pas possible, puisque ces personnes n’aiment pas son être, mais les compétences qu’elle apporte. Elle finira donc forcément par être déçue. </p>\n<h2>La différence entre ne rien attendre des autres et une non-attente négative</h2>\n<p>Nous pouvons penser que ne rien attendre des autres est impossible si nous voulons avoir des relations durables. Que puisque nous vivons en société, nous avons forcément besoin des autres, car nous sommes tous connectés. C’est vrai. Mais comme dit plus haut, avoir des attentes n’est pas toujours très sain. </p>\n<p>Par contre, attention de ne pas confondre ne rien attendre d’autrui et fatalité. En effet, j’ai déjà entendu de nombreuses personnes dire : « on n’est jamais aussi bien servi que par soi-même » ou « on ne peut compter sur personne dans la vie. » En général, ces personnes-là ont vécu une grande déception par rapport à quelqu’un qu’elles chérissaient. Elles n’ont donc plus d’attentes envers cette personne, mais cette non-attente est plutôt négative. Elle se vit dans la tristesse et la rancœur.</p>\n<p>Ne rien attendre des autres ce n’est pas ça. C’est de pouvoir vivre en paix même si nos semblables ne répondent pas toujours à nos besoins ou n’agissent pas comme nous le souhaiterions. </p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"452\" src=\"/storage/blog-images/Deception.jpg\" alt=\"Attentes excessives&lt;br /&gt;\n\" title=\"Déception\">\n<h2>Conséquences des attentes élevées  </h2>\n<p>Vous l’aurez compris, avoir des attentes élevées ne rend pas heureux. C’est vrai que lorsqu’une personne répond à nos attentes, cela nous procure de la joie. Mais ce bien-être n’est que de courte durée, puisque si ça se trouve, demain, cette personne ne répondra plus jamais à nos attentes. L’être humain est complexe et on ne sait pas comment il agira demain. Ainsi, si votre bonheur est conditionnel, vous ne risquez pas de vous sentir en paix sur le long terme. Vous aurez surtout l’impression d’être balloté dans tous les sens par les circonstances extérieures. Vous aurez la sensation de ne détenir aucun pouvoir sur votre existence. </p>\n<p>En attendant toujours que l’autre réponde à vos attentes, vous ressentez de l’anxiété, vous posez de nombreuses questions comme : « va-t-il m’envoyer un message ? Est-ce qu’il s’en fiche ? » Vous ne vivez pas du tout dans l’instant présent et perdez du temps à vous inquiéter pour rien. </p>\n<p>Vous savez au fond de vous que vous souffrez de ces attentes élevées. Apprenez maintenant à ne rien attendre des autres en vous sentant bien, quelles que soient les circonstances. </p>\n<h2>Comment ne rien attendre des autres ? </h2>\n<p>Ne rien attendre d’autrui va réellement vous changer l’existence. Les conseils ci-dessous vont vous aider à y parvenir : </p>\n<h3>Comprendre que l’on ne peut contrôler les autres </h3>\n<p>Comme je l’ai indiqué dans mon article, nous ne pouvons absolument pas contrôler la réaction des autres. Votre seule responsabilité est de faire au mieux. Des exemples :</p>\n<ul>\n<li aria-level=\"1\">vous êtes l’un des meilleurs éléments de votre entreprise, mais votre patron ne vous augmente pas pour autant. Il n’a pas l’obligation de le faire et vous ne pouvez pas le forcer. Votre seule responsabilité et de faire avec, ou de changer de travail si votre salaire ne vous convient vraiment plus ;</li>\n<li aria-level=\"1\">vous êtes un homme et tombez amoureux d’une femme, mais pas elle. Que pouvez-vous y faire ? Ce n’est pas contre vous : vous pouvez être beau, gentil, intelligent et pour autant, ne pouvez contrôler ses sentiments. Comme on dit souvent : l’amour ne s’explique pas. </li>\n</ul>\n<p>Par conséquent, vous ne pouvez pas contrôler les autres, leurs actions et leurs émotions, mais votre responsabilité est de ne pas vous laisser affecter par ces évènements.  </p>\n<h3>Accepter les erreurs d’autrui </h3>\n<p>Vous pouvez attendre que vos proches restent toujours aimables avec vous, mais il y a très peu de chances que cela soit constamment le cas. En effet, nous sommes tous uniques et avons donc des façons de percevoir le monde, des réactions et des comportements différents. Vos semblables vont forcément vous blesser à certains moments, même sans le faire exprès. D’ailleurs, vous les blesserez également de temps en temps sans vous en rendre compte. Par conséquent, n’attendez pas que vos proches demeurent irréprochables si vous ne l’êtes pas vous-mêmes. Rappelez-vous que personne n’est parfait. </p>\n<p>Ce que j’ai remarqué aussi, c’est que nous n’avons jamais le droit de revenir sur notre parole. En gros, si nous disons quelque chose, nous devons nous y tenir. Autrement, cela est très mal perçu par l’entourage. </p>\n<p>Par exemple, vous avez dit à votre famille que vous vous retrouverez au restaurant dimanche. Sauf que le samedi soir, vous êtes extrêmement fatigué, car vous avez passé une semaine très harassante. Vous n’avez qu’une envie : comater chez vous le dimanche. En général, si vous annulez au dernier moment, les gens seront très déçus.</p>\n<p>C’est dommage, car quelquefois, nous pouvons nous avancer sur quelque chose et ne pas nous sentir dans la capacité de le faire au moment T. Tout simplement, parce qu’on ne sait pas de quoi demain est fait. Nous devrions tous avoir le droit de revenir sur notre parole sans que cela soit très mal considéré. Nous devrions pouvoir faire ce que nous voulons, tant que nous ne faisons pas de mal à autrui. De la même manière, les autres devraient aussi pouvoir faire ce qu’ils veulent.</p>\n<h3>S’entraîner à ne rien attendre en retour </h3>\n<p>Si vous avez du mal à ne rien attendre des autres, entraînez-vous progressivement à effectuer des actions sans rien attendre en retour. Par exemple, vous inscrire dans une association bénévole peut grandement vous aider à y parvenir. Ou sinon, donnez-vous comme objectif de réaliser une action par jour pour laquelle vous serez certain de n’avoir aucun retour.</p>\n<img decoding=\"async\" width=\"640\" height=\"412\" src=\"/storage/blog-images/attentes-elevees.jpg\" alt=\"Desappointement\" title=\"attentes-élevées\">\n<h3>Augmenter son estime de soi </h3>\n<p>Lorsque vous en attendez trop des autres, c’est bien souvent parce que vous avez un grand besoin de reconnaissance. Ce besoin de validation extérieure provient généralement d’un manque d’estime de soi.</p>\n<p>En fait, puisque vous ne trouvez pas d’amour en vous, vous en cherchez à l’extérieur. Sauf qu’il faut comprendre une chose : même si vous êtes entouré, vous êtes seul. Que vous ayez un mari, une femme, 10 enfants, 10 animaux, 30 amis, etc. personne ne peut vraiment se mettre à votre place. C’est le propre de l’être humain : nous sommes entourés, mais seuls. Durant toute notre existence, nous croiserons de nombreuses personnes sur notre chemin, qui vont et viennent. La seule et unique personne avec qui vous allez passer, à coup sûr, toute votre vie, c’est vous-même. Il est donc essentiel que vous soyez en bonne compagnie, non ? Votre valeur se trouve en vous, et vous uniquement. </p>\n<p>Ainsi, <a href=\"/vivre-linstant-present\" target=\"_blank\" rel=\"noopener\" title=\"Vivre l\'instant présent\">vivez l’instant présent</a> au maximum en faisant des choses que vous aimez, et pas celles que vous imposent les autres dans le seul but d’être aimé. Vous verrez que les gens ne vous rejetteront pas pour autant, bien au contraire. </p>\n<p>Vous pouvez également vous entraîner à <a href=\"/confiance-et-estime-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Confiance et estime de soi\">augmenter votre estime de vous</a> en vous rappelant régulièrement de vos réussites. Notez dans un petit carnet tous vos succès et fiertés, et relisez-le en cas de coup de mou. </p>\n<h3>Vivre pleinement sa propre existence </h3>\n<p>Il ne sert à rien d’attendre désespérément quelque chose de quelqu’un, car en attendant, vous ruminez, vous vous faites des films, ne vivez pas dans l’instant présent. Au lieu de vous occuper des autres et d’attendre un retour de leur part, pourquoi ne pas vivre votre vie ? Concentrez-vous donc un peu sur vous, sur vos activités. Faites-vous plaisir, et donnez-vous surtout comme objectif de vous améliorer de jour en jour. Ne vous comparez qu’à vous-même. Tentez de devenir, chaque jour, meilleur que la veille. </p>\n<h3>Accepter de décevoir </h3>\n<p>Les autres ont aussi des attentes et vous allez inévitablement les décevoir de temps à autre, et quelquefois, sans vous en rendre compte. </p>\n<p>Par exemple, la société a clairement des attentes envers nous : nous devons travailler, nous marier, et avoir des enfants. Et si nous ne le faisons pas, la pression sociale peut être très forte. Et juste pour rester dans les normes, combien de personnes se forcent à faire des choses dont ils n’ont pas envie ? Ce n’est pas parce que certaines personnes ont un besoin en particulier que vous devez avoir le même. Vivez pour vous. Autrement, vous allez passer à côté de votre existence et les regrets vont s’installer. </p>\n<p>Décevoir une personne est également une source d’évolution pour elle. En la décevant, elle pourra peut-être se rendre compte de ses attentes élevées, et y remédier. Vous n’êtes pas responsable des attentes des autres. Par exemple, si vos parents sont tristes, car vous avez décidé de déménager dans un autre pays, ce ne sont pas vos actions qui les rendent malheureux, mais leurs attentes. C’est à eux de prendre leurs responsabilités à ce sujet. </p>\n<p>Je connais également des individus « trop » altruistes. Ce sont les personnalités de type 2 de l’ennéagramme, si vous connaissez. Ces personnes ont tendance à vous rendre des services et à effectuer de nombreuses choses pour vous alors que… vous ne leur avez rien demandé, et que vous n’aviez même pas ces besoins là à combler. Certes, ces personnes veulent faire plaisir. Mais il faut savoir que donner est tout autant un besoin que recevoir, et que l’on entreprend toujours une action pour nous avant tout, qu’on l’admette ou non. Par conséquent, celles-ci cherchent surtout, en vous rendant de nombreux services, votre amour. </p>\n<h3>Accepter que l’autre puisse ne pas vous comprendre</h3>\n<p>Comme je l’ai dit plus haut, nous sommes seuls. Les autres peuvent un peu nous comprendre, si leur personnalité est similaire, mais en aucun cas, ils ne pourront ressentir ce que nous ressentons. </p>\n<p>Cependant, quelquefois, certaines personnes ne vous comprendront absolument pas, au point de même apparaître intolérantes. Et il ne faudra surtout pas vous attendre à ce que celles-ci vous comprennent un jour, car leur parcours de vie a probablement été l’opposé au vôtre. </p>\n<p>Par exemple, si vous souffrez de <a href=\"/angoisse-stress-anxiete\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse stress anxiété\">troubles anxieux</a> (après tout, mon site traite de ce sujet), les personnes n’ayant jamais ressenti d’anxiété de leur vie pourront vous penser faible, sans volonté, ou même croire que vous le faites exprès pour attirer l’attention. Il n’y a qu’un autre anxieux qui pourra vous comprendre, ne perdez donc pas votre temps à essayer de vous justifier auprès d’eux, c’est peine perdue. Votre tempérament, votre éducation et vos expériences de vie sont probablement très différents. </p>\n<p>Il faut le dire : nous ne naissons pas tous égaux. Certaines personnes ont une existence assez linéaire sans vivre de problèmes particuliers. D’autres auront vécu de la maltraitance, de la négligence, des décès très tôt, etc. ainsi, il est normal que dans ces deux cas, les personnes n’aient pas la même perception de l’existence, et que certains aient été plus fragilisés que d’autres, bien que loin d’être plus faibles ! </p>\n<p> </p>\n<p>Lorsque vous apprenez à <b>ne rien attendre des autres,</b> vous allez vous apercevoir, petit à petit, d’un changement dans votre personnalité. Vous allez apparaître, aux yeux des autres, bien plus sage, calme, apaisée, et ceux-ci auront tendance à venir vers vous plus facilement et naturellement, car les échanges seront plus harmonieux et épurés. Et tout cela est logique : en effet, puisque vous allez vous sentir bien intérieurement, vous allez être agréable avec votre environnement. En stoppant vos attentes excessives, vous allez nettement gagner en qualité de vie. </p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'Ne Rien Attendre des Autres pour une Vie Épanouie ','Les attentes trop élevées peuvent vous rendre malheureux. Ne rien attendre des autres, est-ce vraiment possible ? Si oui, comment y parvenir ?','https://vivre-pleinement.fr/ne-rien-attendre-des-autres/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ne-rien-attendre-des-autres\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ne-rien-attendre-des-autres\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Ne Rien Attendre des Autres pour une Vie \\u00c9panouie\\u00a0\",\"datePublished\":\"2023-06-27T15:47:54+00:00\",\"dateModified\":\"2023-06-27T15:48:12+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ne-rien-attendre-des-autres\\/\"},\"wordCount\":4622,\"commentCount\":3,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ne-rien-attendre-des-autres\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2023\\/06\\/Rien-attendre-autres.jpg\",\"articleSection\":[\"D\\u00e9veloppement personnel\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.