/uploads\\/2022\\/06\\/Syndrome-dimanche.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2022\\/06\\/Syndrome-dimanche.jpg\",\"width\":640,\"height\":427,\"caption\":\"Comment vivre au mieux le syndrome du dimanche ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/le-syndrome-du-dimanche-conseils-pour-vivre-au-mieux-ce-moment\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Le Syndrome du Dimanche\\u00a0: Conseils pour Vivre au Mieux ce Moment\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2022-06-09 19:33:42',NULL,'2026-05-24 19:19:44','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (20,'Comment Soigner la Blessure de Rejet ? 8 Conseils Utiles','comment-soigner-la-blessure-de-rejet-8-conseils-utiles','La blessure de rejet fait partie des 5 blessures de l’âme mises en lumière par Lise Bourbeau, fondatrice de l’école de développement personnel Écoute Ton Corps. Il existe également la blessure d’abandon, d’injustice, d’humiliation et de trahison. La blessure de rejet est de loin la plus douloureuse, puisqu’elle touche directement l’être. Voilà pourquoi il est important de vous en libérer si vous en souffrez afin de vous pouvoir vivre une vie pleinement épanouie. Par rapport aux autres, vous vous sentez anormal et fragile. Vous ressentez souvent beaucoup d’anxiété. Vous vous sentez sans cesse attaqué par les autres et apparaissez souvent sur la défensive. La blessure de rejet vous fait profondément souffrir ? Comment soigner la blessure de rejet ? \n','<p>La blessure de rejet fait partie des <b>5 blessures de l’âme </b>mises en lumière par Lise <b>Bourbeau</b>, fondatrice de l’école de développement personnel <b>Écoute Ton Corps.</b> Il existe également la blessure<b> d’abandon, d’injustice, d’humiliation</b> et de <b>trahison</b>. La blessure de rejet demeure de loin la plus <b>douloureuse</b>, puisqu’elle touche directement <b>l’être</b>. Voilà pourquoi il est important de vous en libérer si vous en souffrez afin de vous pouvoir vivre une vie pleinement épanouie. Par rapport à autrui, vous vous sentez <b>anormal </b>et <b>fragile</b>. Vous ressentez souvent beaucoup <b>d’anxiété</b>. Vous vous sentez sans cesse <b>attaqué </b>par les autres et apparaissez fréquemment sur la <b>défensive</b>. La blessure de rejet vous fait profondément souffrir ? <b>Comment soigner la blessure de rejet ? </b></p>\n<h2>1 — Prendre conscience de sa blessure de rejet et l’accepter </h2>\n<p>Prenez déjà conscience de souffrir de cette blessure. En effet, comment voulez-vous agir sur elle si vous n’avez même pas conscience de l’avoir ?</p>\n<p>Il convient ensuite <a href=\"/lacher-prise-et-acceptation\" target=\"_blank\" rel=\"noopener\" title=\"Lâcher-prise et acceptation\">d’accepter</a> cette blessure et toutes les émotions douloureuses qu’elle vous fait ressentir.</p>\n<p>Puis, acceptez le rejet en lui-même. Eh oui, dans votre vie, vous allez réellement subir du rejet. D’ailleurs, plus vous choisissez de vivre en dehors des normes (pas de mari/femme, pas d’enfant, etc.) plus vous allez vous faire juger voire même, exclure. </p>\n<p>Cependant, dites-vous bien que même en ayant une existence correspondant tout à fait aux normes, vous allez vous faire critiquer et rejeter. Car on ne peut pas être aimé par tout le monde et vous n’avez pas de pouvoir sur ce que l’autre pense de vous.</p>\n<p>Mais en règle générale, il est rare qu’une personne vous haïsse au plus haut point, si vous lui avez rien fait de mal. Comprenez alors bien que si une personne vous juge, ce n’est pas sur votre être profond, mais sur un trait de votre caractère ou un de vos comportements. Une minuscule facette de vous en somme. De plus, ce n’est pas parce qu’elle vous critique qu’elle ne vous apprécie pas. D’ailleurs, tout le monde est jugé par tout le monde. Donc, tout le monde se déteste ? Non. Il est urgent de vous défaire de cette croyance qui est «<a href=\"/jugement-des-autres\" target=\"_blank\" rel=\"noopener\" title=\"Jugement des autres\"> on me juge</a> = on ne m’aime pas. »</p>\n<h2>2 — Apprendre la patience pour ne plus se sentir rejeté  </h2>\n<p>Rappelez-vous que la blessure de rejet reste la blessure la plus douloureuse et la plus profonde, d’autant plus si vous la traînez avec vous depuis l’enfance. Donc, restez patient pour la cicatrisation de cette blessure. Certaines personnes vous diront qu’il est impossible de guérir de cette blessure, que vous ne pourrez que la cicatriser, mais je n’y crois pas. Vous pouvez vous en libérer complètement. Le point à retenir, c’est que la guérison n’ira pas aussi vite que vous désirez et que vous vivrez de nombreuses rechutes, car il est difficile de soigner cette blessure. Ne vous démoralisez donc pas en cas de rechute et dites-vous que cette étape est normale. </p>\n<h2>3 — Comment soigner la blessure de rejet en pardonnant </h2>\n<p>Lorsque plusieurs personnes vous rejettent, bien entendu que c’est douloureux. Cependant, pourquoi ne pas transformer cette souffrance une force ? En effet, peut-être qu’il existe un comportement ou un trait de votre caractère qui apparaît difficile à supporter chez l’autre. Dans ce cas, c’est peut-être le moment d’en prendre conscience et de vous perfectionner sur ce point. Voilà pourquoi il est important de vous pardonner : pardonnez-vous de ne pas être parfait et d’avoir des points à corriger chez vous. En vous permettant de vous remettre en question (et ne pas vous dévaloriser), vous allez forcément vous améliorer.</p>\n<p>Lise Bourbeau explique également, dans ses livres, le concept du Triangle de l’Amour. Dans le cas de la blessure de rejet, ce triangle peut s’interpréter ainsi : je me rejette = je rejette les autres = les autres me rejettent. Par conséquent, lorsqu’une personne vous méprise, bien que vous ayez sans doute du mal à le croire, c’est qu’elle souffre de la même blessure que vous. Car si elle vous rejette, c’est qu’elle se rejette elle-même. Vous aurez donc maintenant plus de facilité à pardonner à vos pairs.</p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"426\" src=\"/storage/blog-images/Guerison-peur-repousse.jpg\" alt=\"Guerir la peur d’etre denigre \" title=\"Guérison-peur-repoussé\">\n<h2>4 — Arrêter d’interpréter les situations pour éviter de se sentir repoussé</h2>\n<p>Lorsque vous souffrez de la blessure de rejet, vous vous sentez constamment rejeté. Or, ce n’est pas parce que vous vous sentez repoussé que vous l’êtes réellement. </p>\n<p>Par exemple, peut-être vous êtes-vous senti dénigré dans votre enfance, par rapport à une situation précise ayant été vécue à ce moment. Aujourd’hui, en vous efforçant d’être un simple observateur de cette situation, demandez-vous s’il s’agissait bien de mise à l’écart ou si c’est vous qui l’avez interprété ainsi à l’époque. Votre interprétation était peut-être fausse. </p>\n<p>C’est pareil pour les évènements actuels de votre vie. Lorsque vous prenez mal une parole ou un comportement de quelqu’un, c’est peut-être parce que votre blessure de rejet est activée. Et s’il s’agissait juste d’une interprétation erronée de votre part ? Peut-être que la personne vous ayant blessé n’en avait absolument pas l’intention et qu’elle ne vous juge pas du tout ! </p>\n<p>Donc, lorsque vous commencez à ressentir du rejet, prenez le temps d’observer vos sentiments et vos pensées. Est-ce que votre manière de réagir vous fait du bien ? Probablement pas. Et elle ne fait sans doute pas de bien à vos proches non plus. En effet, avec cette blessure réveillée, vous pouvez avoir tendance à fuir, devenir agressif, bouder, et bien évidemment, à rejeter l’autre également. En prenant conscience d’avoir la blessure de rejet activée lors d’une situation, demandez-vous s’il n’existe pas une réaction qui apparaîtrait plus bénéfique pour vous. Plus vous allez vous introspecter, mieux vous vous sentirez. </p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Séance de yoga pour apaiser l\'anxiété\" title=\"yoga_300x250\"></a>\n\n<h2>5 — Apaiser son anxiété lorsque l’on se sent mis à l’écart </h2>\n<p>Si vous souffrez de la blessure de rejet, vous présentez un grand risque de souffrir d’anxiété voire même, de <a href=\"/angoisse-stress-anxiete\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse stress anxiété\">troubles anxieux.</a> Voici de petits conseils pour apaiser votre angoisse :</p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">faites-vous plaisir. C’est très important pour éviter les ruminations. Bien sûr, il convient de ne pas fuir totalement dans votre monde imaginaire, comportement typique dans la blessure de rejet. Vous devez tout de même agir dans votre vie, en être l’acteur, mais pensez à prendre du temps pour vous ; </li>\n</ul>\n<ul>\n<li aria-level=\"1\">méditez, si vous le pouvez, une dizaine de minutes par jour. Vous entraîner à laisser passer vos pensées vous évitera d’amplifier vos scénarios catastrophes. Cependant, si vous avez de lourds traumatismes, mieux vaut éviter la pratique de la méditation, qui peut vous faire paniquer. En effet, si votre intérieur est trop agité, il est préférable de commencer par des techniques de relaxation plus basées sur le corps, comme le hatha-yoga, par exemple ; </li>\n<li aria-level=\"1\">effectuez du tri dans vos relations. Effectivement, vous pouvez avoir des personnes toxiques dans votre entourage. Il n’existe pas de personnes entièrement toxiques, mais disons que certains comportements d’une personne peuvent apparaître très toxiques pour vous. Vous ne devez pas forcément couper les ponts avec ces personnes, mais au moins prendre des distances. Car deux personnes blessées à peu près de la même manière peuvent se tirer mutuellement vers le bas. Mieux vaut donc éviter ce type de relation ; </li>\n<li aria-level=\"1\">évitez de fuir une situation anxiogène, car cette attitude ne vous rendra que plus anxieux. Dites-vous que, quelle que soit l’émotion extrêmement négative ressentie à ce moment, elle finira inévitablement par passer. Et vous n’en ressortirez que plus fort. </li>\n</ul>\n<img decoding=\"async\" width=\"640\" height=\"256\" src=\"/storage/blog-images/Liberer-crainte-mepris.jpg\" alt=\"Soulager la crainte d’etre mis a l’ecart \" title=\"Liberer-crainte-mépris\">\n<h2>6 — Développer sa confiance en soi lorsque l’on se croit méprisé </h2>\n<p>Dans la blessure de rejet, le manque de confiance et d’estime de soi demeure flagrant. Voici donc de petits conseils pour vous aider à <a href=\"/confiance-et-estime-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Confiance et estime de soi\">reprendre confiance en vous</a> : </p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">osez dire non, et si vous n’êtes pas d’accord avec une personne, dites-lui également. Ce n’est pas simple au début. Mais en apprenant progressivement à vous affirmer, vous y arriverez de mieux en mieux. Oui, quelquefois, vous allez décevoir des personnes en ne répondant pas à leurs attentes. Mais décevoir ne veut pas dire ne pas être aimé ; </li>\n<li aria-level=\"1\">prenez soin de votre apparence et autocomplimentez-vous. D’ailleurs, dès que vous affrontez vos peurs ou que vous vivez une réussite, notez-le dans un petit carnet. Ainsi, lorsque vous aurez une petite baisse de confiance, vous pourrez relire ce carnet pour vous rebooster ; </li>\n<li aria-level=\"1\">listez tout ce qu’il existe de positif en vous au lieu de vous dénigrer en pensant à vos défauts et faiblesses. Oui, vous possédez de nombreuses qualités ! ; </li>\n<li aria-level=\"1\">même si des personnes ne vous aiment pas, vous restez quelqu’un de bien. En fait, nous ne pouvons être aimés de tout le monde, ce qui ne veut pas dire que ce que les autres pensent de nous est vrai. De toute manière, quelle importance ? C’est avec vous que vous allez passer le reste de votre vie, et avec vous que vous allez mourir. Personne ne vous accompagnera dans l’au-delà. Rappelez-vous que la personne la plus importante pour vous, c’est vous-même ; </li>\n<li aria-level=\"1\">osez extérioriser vos fragilités, et aussi vos forces. En vous acceptant comme vous êtes, vous pousserez les autres à se montrer tels qu’ils sont également. N’est-ce pas un pouvoir formidable que vous détenez là ?</li>\n</ul>\n<h2>7 — Écrire pour guérir la blessure de rejet </h2>\n<p>Tous les jours, notez dans un petit carnet des événements, des comportements ou des paroles d’autrui qui contredisent votre sentiment de rejet. Par exemple, votre patron qui vous complimente sur votre travail. Votre collègue qui adore vos chaussures. Une personne inconnue croisée dans la rue qui vous sourit. Et lorsque votre blessure s’active, vous pouvez relire toutes les belles phrases que vous aurez écrites. </p>\n<p>De la même manière, vous pouvez également créer deux colonnes où vous noterez, dans la première, toutes les situations où vous vous êtes senti rejeté. Dans la deuxième colonne, écrivez une interprétation alternative que vous pourriez trouver dans cette même situation et qui contredirait ce sentiment. Vous verrez qu’au fur et à mesure, votre blessure va diminuer.</p>\n<h2>8 — Se faire aider pour arrêter de se sentir dénigré  </h2>\n<p>Si votre blessure de rejet vous gâche réellement l’existence, n’hésitez pas à faire appel à un professionnel de la santé, comme un psychologue. Il n’y a rien de honteux à aller consulter. Au contraire, c’est une preuve de grande force. D’autant plus qu’il s’agit de la blessure de l’âme la plus douloureuse et la plus profonde. </p>\n<p>Vous pouvez également vous tourner vers des médecines alternatives. Certaines d’entre elles, comme la somatothérapie, peuvent retrouver, sur votre corps, des blessures d’origine transgénérationnelle. C’est-à-dire que votre blessure de rejet peut peut-être appartenir, à la base, à un ascendant de votre famille, et ce, sur trois générations. Les secrets de famille peuvent apparaître très lourds et se transmettre, comme une course au relai, de génération en génération, et ce, jusqu’à ce qu’une personne règle le problème.</p>\n<p>Vous savez maintenant<b> comment soigner la blessure de rejet.</b> Vous pouvez apercevoir que vous vous trouvez sur la voie de la guérison lorsque vous éprouvez beaucoup moins d’angoisse et que vous commencez à lâcher-prise. Votre besoin de contrôler s’amenuise. Vous devenez acteur de votre vie au lieu de vous réfugier constamment dans votre imaginaire. Si une personne vous juge, vous comprenez qu’il ne s’agit que d’un de vos comportements et que cette critique ne veut pas dire que vous ne valez rien. Vous arrêtez de vous dévaloriser sans arrêt. Vous sentez que votre confiance en vous grandit.  </p>\n<p><a href=\"https://amzn.to/3NPT9ca\">Visitez Amazon pour vous procurer le livre </a>de Lise Bourbeau « La guérison des cinq blessures ».</p>\n<p>(Lien rémunéré par Amazon)</p>\n<p>(Si mon travail vous aide 🙂)</p>\n<a href=\"https://hypnocaments.com?partnerid=YK5muYugzSoIWDbDWRgT-Q\" title=\"Seances d hypnose en ligne\"><img decoding=\"async\" src=\"https://hypnocaments.com/image/banner_1_750.png\" alt=\"seance hypnose mp3\"></a>','published',1,'Comment Soigner la Blessure de Rejet ? 8 Conseils Utiles','La blessure de rejet est la plus douloureuse, car elle touche l’être. Il est donc important de vous en libérer. Comment soigner la blessure de rejet ?','https://vivre-pleinement.fr/comment-soigner-la-blessure-de-rejet-8-conseils-utiles/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-rejet-8-conseils-utiles\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-rejet-8-conseils-utiles\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Comment Soigner la Blessure de Rejet ? 8 Conseils Utiles\",\"datePublished\":\"2022-05-19T20:01:41+00:00\",\"dateModified\":\"2024-02-13T19:07:53+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-rejet-8-conseils-utiles\\/\"},\"wordCount\":3679,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-rejet-8-conseils-utiles\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2022\\/05\\/Soigner-blessure-rejet.jpg\",\"articleSection\":[\"Blessures de l\'\\u00e2me\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-rejet-8-conseils-utiles\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-rejet-8-conseils-utiles\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-rejet-8-conseils-utiles\\/\",\"name\":\"Comment Soigner la Blessure de Rejet ? 8 Conseils Utiles\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-rejet-8-conseils-utiles\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-rejet-8-conseils-utiles\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2022\\/05\\/Soigner-blessure-rejet.jpg\",\"datePublished\":\"2022-05-19T20:01:41+00:00\",\"dateModified\":\"2024-02-13T19:07:53+00:00\",\"description\":\"La blessure de rejet est la plus douloureuse, car elle touche l\\u2019\\u00eatre. Il est donc important de vous en lib\\u00e9rer. Comment soigner la blessure de rejet ?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-rejet-8-conseils-utiles\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-rejet-8-conseils-utiles\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-rejet-8-conseils-utiles\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2022\\/05\\/Soigner-blessure-rejet.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2022\\/05\\/Soigner-blessure-rejet.jpg\",\"width\":480,\"height\":640,\"caption\":\"Comment soigner la blessure de rejet ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-rejet-8-conseils-utiles\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Comment Soigner la Blessure de Rejet ? 8 Conseils Utiles\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2022-05-19 20:01:41',NULL,'2026-05-24 19:19:44','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (21,'Blessure de Rejet : 9 Symptômes pour la Reconnaître','blessure-de-rejet','La blessure de rejet fait partie des 5 blessures de l’âme que Lise Bourbeau, auteure de nombreux livres de développement personnel, a mises en avant. Il s’agit du fait de se sentir constamment repoussé ou mis à l’écart, dans tous les domaines : professionnel, amoureux, amical, et familial. Cette blessure survient fréquemment dans l’enfance, avec le parent du même sexe. L’enfant devenu adulte accuse son parent de ne pas avoir été un bon modèle pour lui. Le sentiment de rejet peut être fondé, mais aussi imaginaire. Vous adorez rester chez vous, car avez une vie intérieure très riche. Dès que vous vous trouvez dans un groupe d’amis, vous avez l’impression qu’ils ne font pas attention à vous. Vous avez la croyance profonde d’aimer plus vos proches qu’ils ne vous aiment. Vous pensez souffrir de cette blessure ? Comment reconnaître la blessure de rejet ? \n','<p>La <b>blessure de rejet</b> fait partie des <b>5 blessures de l’âme</b> que <b>Lise Bourbeau</b>, auteure de nombreux livres de développement personnel, a mises en avant. Il s’agit du fait de se sentir constamment <b>repoussé </b>ou <b>mis à l’écart,</b> dans tous les domaines : <b>professionnel, amoureux, amical</b>, et <b>familial</b>. Cette blessure survient fréquemment dans <b>l’enfance</b>, avec le <b>parent du même sexe.</b> L’enfant devenu adulte <b>accuse </b>son parent de ne pas avoir été un <b>bon modèle</b> pour lui. Le sentiment de rejet peut être <b>fondé</b>, mais aussi <b>imaginaire</b>. Vous adorez rester <b>chez vous</b>, car avez une <b>vie intérieure</b> très <b>riche</b>. Dès que vous vous trouvez dans un<b> groupe d’amis</b>, vous avez l’impression qu’ils ne font <b>pas attention</b> à vous. Vous avez la croyance profonde <b>d’aimer</b> <b>plus </b>vos proches qu’ils ne vous aiment. Vous pensez souffrir de cette blessure ? Comment <b>reconnaître </b>la blessure de rejet ? </p>\n<h2>1 — Se sentir constamment rejeté </h2>\n<p>La personne se sentant rejetée apprécie en général ne passer du temps qu’avec une seule personne à la fois, notamment dans le domaine amical. Non pas par égocentrisme, mais par peur de se sentir mise à l’écart. Par conséquent, elle évite au maximum de se trouver en groupe et déteste les chiffres impairs ! Par exemple, si elle se trouve à trois personnes, elle reste certaine que les deux autres vont bien plus accrocher, parler et rire ensemble. Elle est, d’après elle, forcément de trop. Le truc, c’est qu’en se conditionnant à se croire rejetée, c’est ce qu’il risque de se passer durant ce moment. En effet, elle va s’autoconditionner au rejet, en parlant peu, en restant discrète, etc. </p>\n<p>Ce sentiment de rejet transparaît dans de nombreux domaines de son existence. Elle a donc l’impression d’être constamment rejetée. C’est le principe du triangle de la vie que Lise Bourbeau développe dans ses livres. Je me rejette = je rejette les autres = les autres me rejettent. Tant que l’individu restera dans ce triangle, sa blessure va perdurer. </p>\n<p>Les rêves peuvent mettre une personne sur la voie lorsqu’elle souffre d’une blessure de l’âme. Pour ma part, je rêve très souvent de me trouver dans un groupe. À un moment donné, les personnes de ce groupe ne font plus du tout attention à moi. Ils partent sans moi, font comme si je n’existais pas, me méprisent, etc. Il s’agit clairement ici de ma blessure de rejet qui s’exprime à travers mes songes. </p>\n<h2>2 — Un corps mince, voire maigre lorsque l’on se sent dénigré </h2>\n<p>Une personne en proie à la blessure de rejet apparaît souvent mince, voire maigre. Les autres peuvent même la penser anorexique. En réalité, plus la blessure de rejet est importante, plus la personne apparaît maigre. Elle peut d’ailleurs réellement souffrir d’anorexie. En outre, elle peut entretenir deux rapports avec la nourriture. Quand elle ressent de vives émotions négatives, elle peut tenter de les apaiser en mangeant énormément. Elle apprécie généralement le sucre. Et lorsqu’elle se sent vraiment mal, elle peut avoir l’appétit totalement coupé. </p>\n<p>Ses yeux apparaissent souvent cernés. Cet aspect mince et cerné qu’aura l’enfant va faire croire aux parents que leur bambin est fragile et ils auront donc tendance à le surprotéger. Cependant, bien que les parents pensent agir de la bonne façon, la surprotection parentale n’apporte rien de bon à l’enfant. En effet, en accomplissant tout à sa place, le petit ne se sent pas aimé, puisqu’il n’est pas accepté tel qu’il est. De plus, il éprouvera, à l’âge adulte, un sentiment fort : celui de se sentir incapable. </p>\n<p>La personne blessée a fréquemment des problèmes de peau, comme de l’acné, de l’eczéma, du psoriasis, etc. C’est une façon pour elle de dire aux autres : « regardez comme je suis repoussante, ne m’approchez pas. »</p>\n<p>Cet individu croise souvent les jambes lorsqu’il est assis. Cette posture lui donne un sentiment de sécurité. </p>\n<h2>3 — Un monde intérieur riche lorsque l’on se croit méprisé </h2>\n<p>L’individu rejeté va souvent se montrer discret dans un groupe. Certains peuvent même ne pas remarquer sa présence ! Cependant, à contrario, cette personne peut parler énormément afin de réguler son stress et pallier son besoin de reconnaissance. </p>\n<p>En général, une personne souffrant de cette blessure n’apprécie pas le monde dans lequel elle vit, lequel lui paraît inintéressant et hostile. Son sentiment de rejet l’empêche de se sentir à l’aise en société. Elle se croit en outre inadaptée socialement et anormale, car elle remarque que les autres personnes, contrairement à elle, vivent avec aisance dans ce monde. Pour se sentir bien, elle va ainsi se réfugier dans son univers intérieur. Elle possède une imagination débordante. Enfant, elle avait beaucoup d’amis imaginaires. Elle imagine de nombreux scénarios où elle est l’héroïne et où la vie apparaît magique, palpitante. Dans son univers, elle se sent en sécurité, puisqu’elle n’a de comptes à rendre à personne et ne ressent aucune <a href=\"/normes-sociales\" target=\"_blank\" rel=\"noopener\" title=\"Normes sociales\">pression sociale. </a></p>\n<p>Elle aime d’ailleurs le domaine spirituel qui l’attire grandement. Elle est généralement peu attachée aux biens matériels, car en s’y attachant, elle aurait trop peur de les perdre. </p>\n<p>Cette personne pense donc qu’elle se sent bien seule et qu’elle n’a pas besoin de ses pairs. Cet aspect de sa personnalité peut paraître, aux yeux de ses semblables, une force. Cependant, cet isolement reflète surtout une crainte des autres, et non une indépendance. Elle a plutôt un besoin absolu d’être aimée ! </p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"443\" src=\"/storage/blog-images/Repousse.jpg\" alt=\"Mis a l’écart \" title=\"Repoussé\">\n<h2>4 — Angoisse et manque de confiance en soi dans la blessure de rejet </h2>\n<p>Les personnes souffrant de la blessure de rejet apparaissent généralement anxieuses et hypersensibles. En effet, une personne hypersensible est avant tout une personne hyperblessée, et la blessure de rejet reste la blessure la plus profonde. Le lien entre hypersensibilité et blessure de rejet est donc flagrant.</p>\n<p>Ces individus ont souvent des <a href=\"/angoisse-stress-anxiete\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse stress anxiété\">troubles anxieux</a>, comme le trouble de l’anxiété généralisée. Ils ont une peur terrible de décevoir les autres, car ils croient qu’en les décevant, ils pourront l’abandonner et la rejeter. Ils s’imaginent que déception = ne plus être aimé. </p>\n<p>Ces personnes adorent leur sécurité et craignent de prendre des risques. Par conséquent, elles se sentent frustrées et insatisfaites de leur existence. Elles se plaignent d’ailleurs beaucoup et pensent souvent à ce qui leur manque et non à ce qu’elles ont déjà. Les mêmes angoisses se répètent, puisqu’elles restent dans un schéma répétitif. </p>\n<p>Cette personne a en outre un grand <a href=\"/confiance-et-estime-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Confiance et estime de soi\">manque de confiance en soi et d’estime de soi.</a> Elle fait également peu confiance aux autres (nous en revenons au triangle de la vie). Elle culpabilise beaucoup et se remet sans cesse en cause. Cet individu se dévalorise énormément par rapport à ses semblables, qu’il trouve forcément meilleurs. </p>\n<p>Avec toutes ces pensées négatives, cette personne peut finir par tomber dans une dépression. </p>\n<h2>5 — Un immense besoin de reconnaissance lorsque l’on se sent repoussé </h2>\n<p>La personne se sentant rejetée a la certitude de ne pas être aimée autant qu’elle aime. Par conséquent, elle va tout faire pour obtenir la validation d’autrui. Elle va donc souvent cacher sa véritable personnalité, qu’elle pense inadéquate, pour faire croire aux autres qu’elle leur ressemble. En réalité, elle croit qu’être comprise = être aimé, alors que nous pouvons très bien aimer une personne même si elle n’a pas les goûts que nous où qu’elle apparaît originale. Elle s’imagine en fait que la seule façon d’exister est d’être reconnue par ses pairs. Elle aimerait être appréciée de tout le monde ! Cette personne demeure ainsi extrêmement dépendante des autres, mais puisqu’elle en a peur, elle les évite au maximum. Elle adopte donc une attitude très ambivalente. Pourquoi avoir autant peur de ses semblables ? Car elle craint fortement d’être critiquée et pour elle, être jugée = ne pas être aimée. Elle crée des raccourcis qui n’apparaissent pas judicieux pour elle. </p>\n<p>Cette personne blessée a également souvent tendance à s’occuper des besoins des autres avant de prendre soin d’elle-même. Elle se dit que si elle fait tout pour eux, ils n’oseront jamais la rejeter.</p>\n<p>Cet individu inspire d’ailleurs au succès, à montrer à ses camarades qu’il a réussi. S’il peut devenir célèbre, c’est encore mieux ! Il pense qu’ainsi, ses semblables l’apprécieront. Enfin, cette personne peut aussi se victimiser pour attirer l’attention et pour pallier son besoin de reconnaissance et d’amour. </p>\n<h2>6 — Un perfectionnisme prononcé dans la blessure de rejet </h2>\n<p>Puisque la personne sujette à cette blessure a un besoin viscéral d’être aimée, elle tente donc de devenir parfaite. En effet, qui peut critiquer la perfection ? Le hic, c’est que la perfection n’existe pas. Par conséquent, en ne réussissant pas à l’atteindre, cette personne va encore plus se rejeter. </p>\n<p>Un individu en proie à cette blessure est d’ailleurs considéré comme un très bon élément à son travail, puisqu’il y est très investi, perfectionniste et productif. Il adore en outre travailler, car cette activité l’empêche de penser et de ruminer : il se sent dans l’instant présent en travaillant. </p>\n<p>Et puisqu’au travail, les autres nous apprécient seulement si l’on travaille bien, la personne blessée se sent aimée, raison de plus pour elle d’apprécier son job. Elle confond, en réalité l’être et le faire, vu qu’au travail, les autres ne l’aiment pas pour ce qu’elle est réellement, mais juste pour ce qu’elle fait. </p>\n<p>Si la perfection devient obsessionnelle, la personne peut commencer à développer des TOC (troubles obsessionnels compulsifs). </p>\n<img decoding=\"async\" width=\"640\" height=\"426\" src=\"/storage/blog-images/Denigre.jpg\" alt=\"Mepris\" title=\"Dénigré\">\n<h2>7 — De l’autosabotage lorsque l’on se sent mis à l’écart </h2>\n<p>La personne souffrant de la blessure de rejet porte le masque social du fuyant. Ce qui veut dire que lorsqu’elle se croit rejetée, elle peut prendre les devants en rejetant la personne qui lui donne cette impression. Elle peut ainsi couper les ponts avec quelqu’un facilement. Si elle vit une belle relation, elle n’arrive pas à croire que quelqu’un l’aime et peut donc saboter ce lien. Nous en revenons donc au triangle de la vie je me rejette = je rejette les autres = les autres me rejettent. </p>\n<p>Quelquefois également, la personne se met tellement la pression pour ne pas décevoir qu’elle finit finalement par décevoir. Par exemple, si elle a peur de gâcher un repas de famille en ayant l’appétit coupé, il y a de fortes chances qu’elle n’ait vraiment pas d’appétit au moment du repas. </p>\n<h2>8 — Tempérament colérique et blessure de rejet </h2>\n<p>Les personnes se sentant rejetées redoutent tellement la critique, puisqu’être critiquées, pour elles, signifie ne pas être aimées, qu’elles ont sans cesse l’impression d’être attaquées. Elles apparaissent ainsi souvent sur la défensive et peuvent faire preuve d’agressivité. Le fuyant, si calme habituellement, peut même avoir d’importants accès de colère lorsqu’il se fait juger, vu qu’il pense se faire rejeter. C’est notamment le cas si la blessure de trahison ou d’injustice cache sa blessure de rejet. Par conséquent, ces individus ont du mal à oublier les remarques faites à leur égard et apparaissent donc généralement rancuniers. Ils peuvent en outre commencer à développer un sentiment de haine si leur blessure est trop forte. </p>\n<a href=\"https://www.ruedesplantes.com/index.php?ref=290&amp;affiliate_banner_id=158\" target=\"_blank\" rel=\"noopener\"><img decoding=\"async\" src=\"https://www.ruedesplantes.com/affiliation_appels_bannieres.php?ref=290&amp;affiliate_banner_id=158\" border=\"0\" alt=\"Rue des Plantes 728*90\"></a>\n<h2>9 — Les maladies possibles lorsque l’on souffre de la blessure de rejet </h2>\n<p>Lorsqu’une personne a la blessure de rejet, elle peut souffrir de différents maux, comme : </p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">les diarrhées, l’arythmie, les vomissements, symptômes dénotant une accélération de l’organisme et donc, de la panique et le rejet d’une situation. La personne utilise d’ailleurs souvent le terme « ça m’écœure » lorsqu’elle est déçue d’une situation ou de quelqu’un ; </li>\n<li aria-level=\"1\">les allergies et problèmes respiratoires, de par une anxiété prononcée ; </li>\n<li aria-level=\"1\">les vertiges et étourdissements lorsqu’elle se sent incapable de gérer une situation ; </li>\n<li aria-level=\"1\">la <a href=\"/phobie-sociale\" target=\"_blank\" rel=\"noopener\" title=\"Phobie sociale\">phobie sociale</a> ou l’agoraphobie, puisqu’elle a peur des autres ; </li>\n<li aria-level=\"1\">les addictions comme l’alcool, qui agit, pour elle, comme un anxiolytique naturel. Elle adore généralement les jeux vidéos, puisqu’ils lui permettent de fuir la réalité.</li>\n</ul>\n<p> </p>\n<p>Dans les cas les plus graves, si cette blessure est extrêmement forte, la personne peut développer : </p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">des troubles psychotiques, si elle se déteste tellement qu’elle souhaite devenir quelqu’un d’autre ; </li>\n<li aria-level=\"1\">un cancer, souvent dû à un sentiment de rancune et de haine provenant d’une situation vécue dans l’isolement. </li>\n</ul>\n<p> </p>\n<p>La<b> blessure de rejet</b> reste la blessure la plus profonde, puisqu’elle touche directement notre être. De nombreuses personnes ne voient pas la différence entre la blessure de rejet et la blessure d’abandon. Lorsqu’une personne se sent abandonnée, c’est qu’un proche disparaît de son existence, mais pour une raison qui n’a rien à voir avec elle, comme un décès, par exemple. Quand une personne se sent rejetée, c’est que quelqu’un la repousse et ne la veut plus dans sa vie. Si vous pensez souffrir de cette blessure, sachez que vous pouvez en guérir. Je vous propose de découvrir <a href=\"/comment-soigner-la-blessure-de-rejet-8-conseils-utiles\" target=\"_blank\" rel=\"noopener\" title=\"Comment soigner la blessure de rejet \">ici les solutions</a> que vous pouvez mettre en place pour vous libérer enfin de cette blessure.  </p>\n<p><a href=\"https://amzn.to/3VGgcry\">Visitez Amazon pour vous procurer le livre</a> de Lise Bourbeau « Les cinq blessures qui empêchent d’être soi-même ».</p>\n<p>(Lien rémunéré par Amazon)</p>\n<p>(Si mon travail vous aide 🙂)</p>\n<a href=\"https://hypnocaments.com?partnerid=YK5muYugzSoIWDbDWRgT-Q\" title=\"Seances d hypnose en ligne\"><img decoding=\"async\" src=\"https://hypnocaments.com/image/banner_1_750.png\" alt=\"seance hypnose mp3\"></a>','published',1,'Blessure de Rejet : 9 Symptômes pour la Reconnaître','La blessure de rejet fait partie des 5 blessures de l’âme. Il s’agit du fait de se sentir constamment mis à l’écart. Comment reconnaître cette blessure ?','https://vivre-pleinement.fr/blessure-de-rejet/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-rejet\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-rejet\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Blessure de Rejet\\u00a0: 9 Sympt\\u00f4mes pour la Reconna\\u00eetre\",\"datePublished\":\"2022-05-02T18:08:45+00:00\",\"dateModified\":\"2024-02-13T19:06:26+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-rejet\\/\"},\"wordCount\":4011,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-rejet\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2022\\/05\\/Blessure-rejet.png\",\"articleSection\":[\"Blessures de l\'\\u00e2me\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-rejet\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-rejet\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-rejet\\/\",\"name\":\"Blessure de Rejet\\u00a0: 9 Sympt\\u00f4mes pour la Reconna\\u00eetre\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-rejet\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-rejet\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2022\\/05\\/Blessure-rejet.png\",\"datePublished\":\"2022-05-02T18:08:45+00:00\",\"dateModified\":\"2024-02-13T19:06:26+00:00\",\"description\":\"La blessure de rejet fait partie des 5 blessures de l\\u2019\\u00e2me. Il s\\u2019agit du fait de se sentir constamment mis \\u00e0 l\\u2019\\u00e9cart. Comment reconna\\u00eetre cette blessure\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-rejet\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-rejet\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-rejet\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2022\\/05\\/Blessure-rejet.png\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2022\\/05\\/Blessure-rejet.png\",\"width\":640,\"height\":386,\"caption\":\"Comment reconnaitre la blessure de rejet ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-rejet\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Blessure de Rejet\\u00a0: 9 Sympt\\u00f4mes pour la Reconna\\u00eetre\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2022-05-02 18:08:45',NULL,'2026-05-24 19:19:44','2026-06-19 22:28:14');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (22,'Comment Soigner la Blessure de Trahison ? 11 Conseils Précieux','comment-soigner-la-blessure-de-trahison','Il existe 5 blessures de l’âme : le rejet, l’humiliation, l’abandon, l’injustice et la trahison. Ces souffrances sont cachées, à l’âge adulte, sous différents masques. Ici, nous allons nous attarder sur la blessure émotionnelle de trahison, mais surtout, sur les diverses actions à mener pour en guérir. Vous devenez de plus en plus contrôlant avec autrui et de ce fait, ce dont vous craignez le plus risque d’arriver. L’autre peut se sentir étouffé par tant de contrôle et souhaitera probablement retrouver sa liberté en s’éloignant. Vous risquez donc de vous sentir encore une fois trahi. Vous éprouvez des angoisses de plus en plus prononcées. Lorsque vos proches vous font de petites réflexions, vous réagissez de façon tellement agressive qu’ils commencent à s’éloigner de vous. Vous êtes certain que la blessure de trahison demeure proéminente chez vous ? Comment soigner la blessure de trahison ? \n','<p>Il existe<b> 5 blessures de l’âme :</b> le <b>rejet, </b>l’<b>humiliation, </b>l’<b>abandon,</b> l’<b>injustice </b>et la <b>trahison. </b>Ces souffrances sont cachées, à l’<b>âge adulte</b>, sous différents<b> masques. </b>Ici, nous allons nous attarder sur la blessure <b>émotionnelle</b> de trahison, mais surtout, sur les diverses actions à mener pour en <b>guérir. </b>Vous devenez de plus en plus <b>contrôlant </b>avec autrui et de ce fait, ce dont vous <b>craignez </b>le plus risque <b>d’arriver</b>. L’autre peut se sentir <b>étouffé </b>par tant de contrôle et souhaitera probablement retrouver sa liberté en <b>s’éloignant</b>. Vous risquez donc de vous sentir encore une fois <b>trahi</b>. Vous éprouvez des <b>angoisses </b>de plus en plus prononcées. Lorsque vos proches vous font de petites <b>réflexions</b>, vous réagissez de façon tellement <b>agressive </b>qu’ils commencent à s’éloigner de vous. Vous êtes certain que la blessure de trahison demeure <b>proéminente </b>chez vous ? <b>Comment soigner la blessure de trahison ? </b></p>\n<h2>1 — Prendre conscience de sa blessure pour ne plus se sentir trahi</h2>\n<p>Nous vivons tous, sans exception, des blessures intérieures provenant de situations de l’existence pas toujours joyeuses. Eh oui, la vie n’est pas un long fleuve tranquille. Sauf que bien souvent, l’impact de ces évènements négatifs va être minimisé voire même, nié par vos soins. Le <a href=\"/le-mal-a-dit\" target=\"_blank\" rel=\"noopener\" title=\"Le mal a dit \">refoulement des émotions</a> empêche la cicatrisation intérieure. Donc, vous aurez fréquemment tendance à répéter les mêmes réactions et conduites dommageables, puisque tous vos gestes sont réalisés inconsciemment. Par conséquent, tant que vous ne vous rendrez pas compte que vous avez une blessure à régler, vous ne pourrez aller mieux. Prendre conscience d’avoir la blessure de trahison est le premier pas vers la guérison. En effet, comment changer vos comportements toxiques si vous n’en avez pas connaissance ? </p>\n<h2>2 — Se pardonner pour guérir la blessure de trahison </h2>\n<p>Pour guérir la blessure de trahison et après l’avoir enfin conscientisée en vous, la deuxième étape reste le pardon. Il faut vous pardonner et vous donner le droit de vous montrer contrôlant, impatient, égocentrique, agressif, anxieux, rancunier, colérique, autoritaire… par moment. Ces facettes de vous sont juste l’expression de votre enfant intérieur blessé. Vous reconnecter à lui vous permettra de ne plus vous en vouloir pour vos comportements et de mieux les tolérer s’ils se manifestent de temps à autre. Car si vous ne vous pardonnez pas, vous ne ferez que vous dévaloriser et votre confiance en vous se trouvera à 0. Il y a donc lieu, dans un premier temps, de vous accepter tel que vous êtes puis de prendre vos responsabilités en passant à l’action pour changer de comportement. Vous allez, à partir de maintenant, reprendre le contrôle sur votre vie. </p>\n<h2>3 — Apprendre à tolérer les autres pour se libérer du mensonge</h2>\n<p>Afin de permettre la cicatrisation de votre blessure intérieure, vous pouvez faire naître en vous une nouvelle croyance sur les autres. Non, une personne n’est pas toujours perfectionniste et ne fait pas constamment preuve de rigidité comme vous. Oui, il existe des gens mous, fainéants, lents, peu débrouillards, peureux et très brouillons dans leur travail. </p>\n<p>Il existe des individus littéralement différents de vous dans leur manière de fonctionner et quoi que vous tentiez, vous ne pourrez les changer et les contrôler : il s’agit de leur personnalité. </p>\n<p>Pour apprendre à déléguer et à faire confiance aux autres, il va falloir booster sa compassion. Pour ce faire, quand vous sentez qu’un comportement commence sérieusement à vous agacer chez l’autre, tentez de vous mettre à sa place. S’il est ainsi, c’est qu’il n’a probablement pas eu le même parcours de vie que vous. Il ne pense et ne réagit donc pas comme vous. </p>\n<p>De plus, si vous cherchez bien, vous trouverez sans doute des qualités en lui que vous ne possédez peut-être pas. Peut-être est-il plus doux, plus patient, plus tolérant, arrive plus à lâcher-prise, etc. Vous pouvez très bien devenir complémentaires et de fait, apprendre à avoir confiance en lui pour ce qu’il peut vous apporter de nouveau. Vous vous rendrez ensuite compte, en commençant à observer l’autre avec compassion et non avec dureté, qu’il est tout aussi formidable que vous, mais juste différent. </p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"427\" src=\"/storage/blog-images/Liberer-mensonge.jpg\" alt=\"Guerir le sentiment d’avoir ete trahi \" title=\"Libérer-mensonge\">\n<h2>4 — Accepter l’échec pour arrêter de se sentir trompé</h2>\n<p>Si vous avez du mal à déléguer, c’est que vous pensez que les autres ne travaillent pas aussi bien que vous et surtout, comme vous le désirez. Cependant, ce comportement peut être un peu plus inconscient et peut également cacher des peurs limitantes et notamment la peur de l’échec. </p>\n<p>En effet, si vous déléguez de plus en plus de tâches à une personne, elle pourrait arriver à un pied d’égalité avec vous. En effet, elle arrive en fin de compte à réaliser exactement la même chose, mais à sa manière. Donc, les autres pourront commencer à lui faire aussi confiance, ce qui risque de vous faire penser que vous ne vous trouvez finalement plus indispensable aux yeux d’autrui. Le drame survient lorsque quelqu’un fait encore mieux que vous : dans ce cas, vous considérez cet évènement comme un échec profond. </p>\n<p>Cependant, au lieu vous diriger tout de suite dans la dévalorisation de soi, pourquoi ne pas voir les choses autrement ? Sachez que la défaite n’existe pas. Si une personne réussit davantage que vous, allez justement vers elle afin qu’elle puisse vous donner des conseils. Ainsi, vous pourrez progresser et vous retrouver, finalement, à son niveau. Lorsque vous savez moins que quelqu’un, c’est plutôt chouette non ? C’est que vous pouvez encore évoluer et apprendre, et donc, rendre votre vie riche et palpitante. </p>\n<h2>5 — Accueillir le changement pour soigner la blessure de trahison</h2>\n<p>Il n’est plus à démontrer que le contrôlant est quelqu’un de rigide. Donc, quand il croit un fait sur quelqu’un ou sur lui-même, il pense que son opinion demeurera la même toute sa vie. Un individu semble inférieur à lui, car il n’a pas confiance en lui et n’a pas de conjoint. Un autre apparaît supérieur parce qu’il gagne plus d’argent et arrive à maîtriser ses émotions. </p>\n<p>Vous l’aurez compris, le contrôlant met les autres ainsi que lui-même dans des cases et il est impossible d’en sortir. Sauf que les gens évoluent. Même si cette évolution peut prendre du temps, ils finissent par changer. Une personne peut de ce fait trouver un conjoint, fonder une famille et prendre confiance en lui. Un individu peut perdre son travail et posséder moins de richesse, ce qui peut entraîner un <a href=\"/traumatisme\" target=\"_blank\" rel=\"noopener\" title=\"Traumatisme\">traumatisme</a> et une difficulté à, dorénavant, gérer ses émotions. Il n’existe pas d’individus meilleurs que d’autres. Il y a juste des personnes vivant des expériences. La vie n’est que mouvement. Inutile donc de se donner des étiquettes ou d’en coller à autrui. En accueillant le changement, vous éviterez de tomber dans le piège de la comparaison sociale et dans le jugement, de vous-même et des autres. </p>\n<h2>6 — S’exprimer en respectant l’autre pour éviter le sentiment de trahison </h2>\n<p>Lorsque vous souffrez de la blessure de trahison, l’égo est assez développé. De ce fait, il est facile d’éprouver rapidement du ressentiment envers autrui. Le challenge à ce niveau pour la personne blessée est de parvenir à la réconciliation en utilisant l’affirmation de soi. Il ne sert à rien en effet de devenir l’offenseur en souhaitant à tout prix blesser quelqu’un. </p>\n<p>De plus, le contrôlant confond bien souvent franchise et authenticité avec attaque et ce quiproquo le maintient dans sa posture autoritaire. Il faut bien comprendre qu’être vrai, ce n’est pas accuser l’autre et se mettre en colère contre lui. Demeurer authentique, c’est surtout s’exprimer, dire ce que l’on pense, oui, mais tout en faisant attention à ce que peut ressentir la personne en face. Le but reste de trouver un terrain d’entente et non de vouloir gagner à tout prix. </p>\n<h2>7 — Apprendre à lâcher-prise pour guérir la blessure de trahison </h2>\n<p>La personne souffrant de la blessure de trahison porte le masque du contrôlant. Et qui dit contrôle dit tout le contraire du lâcher-prise. Le contrôlant, comme son nom l’indique, cherche à tout maîtriser constamment, car il a une grande crainte de l’échec. Sauf que ce comportement le fait grandement souffrir et l’épuise au plus haut point. De plus, trop de contrôle peut impacter la santé mentale de l’individu. La phobie principale de la personne en proie à la blessure de trahison représente d’ailleurs l’angoisse de perdre le contrôle. Les troubles anxieux, les phobies et une peur panique se rencontrent ainsi fréquemment chez cette personne. </p>\n<p>La personne contrôlante a donc tout intérêt à apprendre à lâcher-prise. Pour ce faire, elle peut travailler à faire entrer plus de joie dans sa vie en se concentrant sur le moment présent et à s’entraîner à tolérer l’incertitude. Les approches utilisées pour arriver à cet objectif sont nombreuses. Il existe les techniques de relaxation comme le yoga, la méditation de pleine conscience, la sophrologie, la <a href=\"/respiration\" target=\"_blank\" rel=\"noopener\" title=\"Respiration\">cohérence cardiaque,</a> l’hypnose, etc. À vous de trouver la méthode qui vous convient le mieux.</p>\n<img decoding=\"async\" width=\"640\" height=\"426\" src=\"/storage/blog-images/Guerir-sentiment-tromperie.jpg\" alt=\"Arreter de se sentir trompe \" title=\"Guérir-sentiment-tromperie\">\n<h2>8 — Changer sa perception des choses pour diminuer la blessure de trahison </h2>\n<p>Nos propres blessures demeurent difficiles à cicatriser. Elles restent un grand bagage émotionnel. Par contre, elles ne doivent pas devenir une excuse pour rester dans cet état. Il est vrai que vous ne pouvez changer le passé et que vous avez probablement souffert. Vous n’avez donc pas à minimiser votre souffrance. Cependant, si vous restez victime de votre vie, vous ne changerez pas. Évitez ainsi de bouder, de rejeter la faute sur autrui ou de faire du chantage. Sachez que vous ne pouvez pas tout contrôler dans votre existence et surtout pas autrui. </p>\n<p>En revanche, là où vous détenez un pouvoir total, c’est sur vous. Vous n’êtes pas forcément responsable de votre environnement et de ce que vous font les autres. Néanmoins, les autres demeurent responsables de leurs actes, mais pas de vos émotions. Vous avez donc la capacité de vous laisser affecter par une situation ou non. Vous avez également l’aptitude d’interpréter un évènement en voyant le verre à moitié plein plutôt qu’à moitié vide. Finalement, vous détenez le pouvoir de vous rendre heureux !</p>\n<h2>9 — Accepter sa vulnérabilité pour se libérer de la peur d’être trahi</h2>\n<p>Le contrôlant n’aime pas parler de soi et de ses faiblesses. Se confier peut lui provoquer beaucoup de mal-être et d’insécurité. En effet, il croit qu’il faut se montrer fort aux yeux des autres puisque sinon, ils risquent de lui causer du tort. Il apprécie d’ailleurs beaucoup avoir raison puisqu’il pense que seules ses idées semblent valables. Il accomplit souvent les choses pour prouver sa supériorité et non juste pour le plaisir. Cependant, tous ces comportements dénotent, au fond, un grand attachement au regard d’autrui. C’est dommage, car si vous saviez comme oser être soi peut littéralement vous changer la vie !   </p>\n<p>Déjà, avouez-le : vos semblables peuvent aussi avoir de bonnes idées et ont le droit d’avoir un avis différent du vôtre. </p>\n<p>De plus, si vous apprenez à pratiquer des activités dans l’unique but de vous procurer du plaisir, votre existence deviendra bien plus joyeuse. </p>\n<p>Enfin, savez-vous que nous avons tous des faiblesses et que les exprimer à autrui est surtout l’apanage d’une grande force ? En effet, il est bien plus difficile de montrer ses fragilités que de les cacher. Sauf qu’en les montrant, vous ressentirez un immense soulagement dans votre vie, ainsi qu’une profonde paix intérieure. Nous ne sommes pas forts et nous ne sommes pas fragiles. Nous sommes les deux en même temps. </p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img loading=\"lazy\" decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h2>10 — Persévérer et s’aimer pour soulager la blessure de trahison </h2>\n<p>Vous souhaitez vous lancer dans un processus de guérison émotionnelle de vos vieilles blessures vécues. C’est un énorme pas en avant ! Au début, vous serez extrêmement motivé, mais… du fait de la vie en elle-même, de ses épreuves, de la routine, de la fatigue, etc., vous vivrez, à coup sûr, quelques rechutes. Et c’est normal. On ne change pas une blessure profonde en un claquement de doigts. C’est tout un apprentissage qu’il y a lieu de désapprendre, car votre cerveau s’est habitué à certaines connexions neuronales. </p>\n<p>Donc, en tentant de sortir de votre zone de confort, votre cerveau, n’ayant pas l’habitude de vos nouveaux comportements, va tenter de vous faire revenir à cette zone confortable. Vous pourrez alors ressentir des malaises, de la tristesse et aussi, beaucoup d’impuissance, car vous penserez que vos actions nouvelles ne servent finalement à rien. C’est à ce moment que la confiance en soi peut le plus se dégrader. Et c’est justement là qu’il ne faut rien lâcher ! Lorsque vous ressentez une sorte de régression, ne vous mettez surtout pas la pression en vous disant que ce n’est pas normal. C’est naturel : les rechutes arriveront régulièrement sur la voie de la guérison et elles ne feront que vous rendre plus fort. </p>\n<h2>11 — Comment soigner la blessure de trahison en se confiant</h2>\n<p>Si vos traumatismes et blocages émotionnels vous paraissent vraiment trop importants, n’hésitez surtout pas à vous confier à vos proches et surtout, à des praticiens. Par exemple, à un <a href=\"/psychotherapie-et-psychanalyse\" target=\"_blank\" rel=\"noopener\" title=\"Psychothérapie et psychanalyse\">psychologue, psychothérapeute</a>, hypnothérapeute, etc. Bon nombre de thérapies peuvent aussi soulager vos souffrances, comme l’EMDR, la PNL, l’EFT, etc. je vous invite à naviguer sur Internet afin d’obtenir plus de renseignements sur ces pratiques. </p>\n<p> </p>\n<p>Nos vies sont quelquefois jonchées d’évènements douloureux et de blessures profondes. Grâce à cet article, vous savez dorénavant <b>comment soigner la blessure de trahison. </b>Votre plaie émotionnelle commencera à être guérie lorsque vous ressentirez un épanouissement et un mieux-être général. Rien qu’au niveau corporel, vous allez souvent maigrir au niveau du ventre, là où se matérialise cette blessure. Vous aurez maintenant l’âme d’un vrai leader, poussant les autres vers le haut et osant prendre la parole en public sans vous soucier du regard d’autrui. Votre humour sera bien plus prononcé. </p>\n<p> </p>\n<p>Si vous souhaitez en parler plus en profondeur avec moi, vous pouvez toujours m’adresser un message en passant par le formulaire de contact.</p>\n<p>Vous pouvez bien entendu aussi me laisser un petit commentaire si cet article vous a plu. </p>\n<p><a href=\"https://amzn.to/3NPT9ca\">Visitez Amazon pour vous procurer le livre </a>de Lise Bourbeau « La guérison des cinq blessures ».</p>\n<p>(Lien rémunéré par Amazon)</p>\n<a href=\"https://hypnocaments.com?partnerid=YK5muYugzSoIWDbDWRgT-Q\" title=\"Seances d hypnose en ligne\"><img decoding=\"async\" src=\"https://hypnocaments.com/image/banner_1_750.png\" alt=\"seance hypnose mp3\"></a>','published',1,'Comment Soigner la Blessure de Trahison ? 11 Conseils Précieux','Vous êtes certain que la blessure émotionnelle de trahison demeure proéminente chez vous ? Comment soigner la blessure de trahison ?','https://vivre-pleinement.fr/comment-soigner-la-blessure-de-trahison/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-trahison\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-trahison\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Comment Soigner la Blessure de Trahison\\u2009? 11 Conseils Pr\\u00e9cieux\",\"datePublished\":\"2021-10-11T20:57:45+00:00\",\"dateModified\":\"2024-02-13T19:05:06+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-trahison\\/\"},\"wordCount\":4437,\"commentCount\":18,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-trahison\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2021\\/10\\/Comment-soigner-blessure-trahison.jpg\",\"articleSection\":[\"Blessures de l\'\\u00e2me\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-trahison\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-trahison\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-trahison\\/\",\"name\":\"Comment Soigner la Blessure de Trahison\\u2009? 11 Conseils Pr\\u00e9cieux\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-trahison\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-trahison\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2021\\/10\\/Comment-soigner-blessure-trahison.jpg\",\"datePublished\":\"2021-10-11T20:57:45+00:00\",\"dateModified\":\"2024-02-13T19:05:06+00:00\",\"description\":\"Vous \\u00eates certain que la blessure \\u00e9motionnelle de trahison demeure pro\\u00e9minente chez vous\\u2009? Comment soigner la blessure de trahison\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-trahison\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-trahison\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-trahison\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2021\\/10\\/Comment-soigner-blessure-trahison.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2021\\/10\\/Comment-soigner-blessure-trahison.jpg\",\"width\":640,\"height\":358,\"caption\":\"Comment soigner la blessure de trahison ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/comment-soigner-la-blessure-de-trahison\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Comment Soigner la Blessure de Trahison\\u2009? 11 Conseils Pr\\u00e9cieux\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2021-10-11 20:57:45',NULL,'2026-05-24 19:19:44','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (23,'Reconnaître le Blessure de Trahison en 9 Symptômes','blessure-de-trahison','J’ai découvert les 5 blessures de l’âme avec Lise Bourbeau, écrivaine spécialisée dans le milieu du développement personnel. Il en existe 5 : le rejet, l’abandon, l’humiliation, la trahison et l’injustice. Ici, je m’attarderai sur la blessure de trahison. Cette blessure émotionnelle apparaît généralement entre 2 et 4 ans. Il y a, durant cette période, un déclencheur émanant du parent du sexe opposé. Au travail, quand vous devez former une nouvelle personne, vous ne supportez pas qu’elle éprouve des difficultés à comprendre rapidement. Vous n’arrivez pas à perdre du ventre et des hanches. Si une personne vous fait une remarque, vous ne pouvez pas vous empêcher de lui faire une réflexion encore plus agressive. Vous pensez souffrir de la blessure de trahison ? Comment reconnaître la blessure de trahison ? \n','<h2>C\'est quoi, la blessure de trahison ?</h2>\n<p>La <b>blessure de trahison</b> est l\'une des cinq blessures de l\'âme décrites par Lise Bourbeau. Elle naît souvent dans l\'enfance, lorsqu\'un parent en qui l\'on avait une confiance absolue n\'a pas tenu ses promesses, a déçu, ou a manqué à sa parole. L\'enfant en tire une conviction profonde : <i>« on ne peut compter que sur soi »</i>.</p>\n<p>Devenu adulte, on porte cette blessure sans toujours la reconnaître. Elle se traduit par un besoin de <b>tout contrôler</b>, une grande <b>méfiance</b>, de l\'impatience, parfois de l\'agressivité — et une <a href=\"/blog/trouble-anxieux-generalise\">anxiété</a> qui ne dit pas son nom. Si vous vous demandez si vous en souffrez, les <b>9 signes</b> qui suivent vont vous parler. Et surtout, sachez qu\'on peut <a href=\"/blog/comment-soigner-la-blessure-de-trahison\">en guérir</a>.</p>\n<p>J’ai découvert les<b> 5 blessures de l’âme </b>avec <b>Lise Bourbeau,</b> écrivaine spécialisée dans le milieu du <b>développement personnel.</b> Il en existe 5 : le <b>rejet</b>, l’<b>abandon</b>, l’<b>humiliation</b>, la <b>trahison </b>et l’<b>injustice</b>. Ici, je m’attarderai sur la blessure de trahison. Cette blessure <b>émotionnelle</b> apparaît généralement entre <b>2 et 4 ans.</b> Il y a, durant cette période, un <b>déclencheur </b>émanant du <b>parent du sexe opposé. </b>Au <b>travail</b>, quand vous devez <b>former </b>une nouvelle personne, vous ne supportez pas qu’elle éprouve des difficultés à comprendre <b>rapidement</b>. Vous n’arrivez pas à perdre du <b>ventre </b>et des <b>hanches</b>. Si une personne vous fait une remarque, vous ne pouvez pas vous empêcher de lui faire une <b>réflexion </b>encore plus <b>agressive</b>. Vous pensez souffrir de la <b>blessure de trahison </b>? Comment <b>reconnaître la blessure de trahison ? </b></p>\n<p> </p>\n<h2>1— Une partie du corps plus développée dans la blessure de trahison</h2>\n<p> </p>\n<p>Lise Bourbeau a constaté que la blessure psychologique se reflétait au niveau physiologique. C’est d’ailleurs le moyen le plus visible pour découvrir la souffrance principale d’une personne. </p>\n<p>Lorsque la blessure de trahison apparaît proéminente chez un individu, elle se remarque, au niveau corporel, par une partie du corps plus imposante que le reste. Pour les femmes, il s’agit habituellement du ventre, de la fameuse culotte de cheval et éventuellement de la poitrine. Pour les hommes, nous retrouvons plus souvent un torse bombé avec de larges épaules, mais aussi un ventre plus développé. </p>\n<p>Nous pouvons en outre le voir au niveau des vêtements. En effet, ces personnes aimant plaire, elles vont fréquemment porter des habits moulants, les mettant en valeur. </p>\n<p>Pour la petite anecdote, ces individus préfèrent également les aliments salés et épicés. </p>\n<p> </p>\n<h2>2 — Personnalité très contrôlante et blessure de trahison</h2>\n<p> </p>\n<p>Cette blessure pousse la personne à porter le masque du contrôlant. Son système nerveux se trouve en constante activité, puisqu’elle est une adepte de la planification. Elle vit donc bien souvent dans le futur et non dans l’instant présent. Elle déteste d’ailleurs l’imprévu. </p>\n<p>Dans la mesure où elle a énormément de mal à faire confiance aux autres, elle éprouve de grandes difficultés à déléguer. Elle pense, en effet, que personne ne réalisera la tâche aussi bien qu’elle et surtout, exactement comme elle le veut. Elle demeure ainsi extrêmement exigeante envers elle-même, mais également à l’égard d’autrui. </p>\n<p>Toujours à cause de sa méfiance envers autrui, elle parle très rarement de sa vie privée et de ses faiblesses. Elle reste persuadée que ses semblables s’en serviront contre elle, pour l’humilier et encore la trahir. Cependant, l’inverse n’est pas vrai : assez commère sur les bords, elle adore les potins et les histoires sur les autres ne la concernant pas. </p>\n<p> </p>\n<h2>3 — Une grande impatience lorsque la blessure de trahison est activée</h2>\n<p> </p>\n<p>Les relations sociales, surtout dans la vie professionnelle, peuvent s’avérer délicates. En effet, cette personne apparaît très travailleuse, rapide et productive, mais éprouve une forte intolérance envers les autres ne se comportant pas comme elle. C’est-à-dire les individus assez lents, longs à apprendre et fainéants. Avec elle, il faudrait tout comprendre tout de suite et ne plus poser de questions. Si elle doit former ce type d’employés, elle risque de ne pas avoir de patience. Elle pourra prononcer ce genre de phrase : « mais tu comprends ce que je dis ? » Si les personnes formées sont vulnérables, elles se sentiront sans doute ébranlées par l’attitude assez depostique, intolérante et autoritaire du contrôlant. Si elles savaient que finalement, les personnalités contrôlantes s’avèrent tout aussi sensibles qu’elles de par leurs blessures affectives, mais le cachent avec différents masques…</p>\n<p><!-- /divi:paragraph --></p>\n<p><!-- divi:image {\"align\":\"center\",\"id\":4032,\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"style\":{\"color\":{}}} --></p>\n<p><!-- /divi:image --></p>\n<p><!-- divi:heading --></p>\n<h2>4 — Un ego bien développé avec la blessure de trahison</h2>\n<p> </p>\n<p>Le contrôlant possède un bon leadership. Par conséquent, il aime fêter ouvertement l’accomplissement de ses succès. Il souhaite être le meilleur et peut donc paraître égoïste à certains moments. Il se laisse facilement influencer par certaines célébrités et il espère secrètement leur ressembler. Vivant principalement dans son mental, cette personne demeure très <a href=\"/perfectionnisme\" target=\"_blank\" rel=\"noopener\" title=\"Perfectionnisme\">perfectionniste</a> et échouer est bien trop douloureux pour elle. Elle évite alors au maximum l’échec et adore avoir raison. Pour ce faire, elle n’hésite pas à devenir rigide, froide, autoritaire. Son attitude non verbale paraît dure aux yeux des autres, lesquels, bien souvent, ne vont pas à son encontre. </p>\n<p> </p>\n<h2>5 — L’agressivité, un bon moyen de reconnaître la blessure de trahison </h2>\n<p> </p>\n<p>La personne s’étant sentie trahie va développer des croyances. Les principales sont : « je ne peux faire confiance à personne » et « mieux vaut ne pas s’attacher, si c’est pour être trompée ensuite ». </p>\n<p>Par conséquent, la gestion des conflits ne se fait pas avec <a href=\"/affirmation-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Affirmation de soi\">affirmation</a>. L’individu se conduit de façon agressive envers ses pairs, puisque, trouvant tout injuste, il a constamment l’impression de ne pas se faire respecter. Il se tient donc toujours sur la défensive. Pourtant, il ne se rend pas compte que lui-même a parfois un comportement injustifié. Par exemple, il réagit de manière excessive si on lui coupe la parole, alors qu’il se comporte exactement de la même manière à l’inverse. Si quelqu’un lui fait des réflexions, son réflexe, au lieu de se remettre en question ou de laisser passer car l’autre a le droit d’avoir une opinion, est de l’attaquer directement. Il peut prononcer une phrase comme : « et toi, tu te penses parfait ? On peut en parler, de ton gros défaut qui est…»</p>\n<p>Assez rebelle, le contrôlant ne supporte pas de recevoir des ordres.</p>\n<p>Susceptible et colérique, c’est une personne très rancunière faisant rarement le premier pas. Elle coupe souvent les ponts sans hésitation. Pardonner, pour elle, s’avère impossible. </p>\n<p>Lunatique du fait de ses fragilités qu’elle tente de cacher, elle adopte un comportement dépendant, attachant, plein d’empathie et de compassion. Et subitement, un tempérament ombrageux et irritable. Avec elle, ses proches ne savent pas sur quel pied danser. </p>\n<p> </p>\n<h2>6 — Une tendance à la manipulation lorsque l’on s’est senti trahi </h2>\n<p> </p>\n<p>Inconsciemment, l’individu contrôlant est un bon manipulateur et avec habileté, il modifie fréquemment ses comportements pour arriver à ses fins. Il peut alors bouder, se plaindre, faire du chantage ou séduire par rapport aux circonstances. Il déteste au plus haut point qu’on lui mente. Néanmoins, il n’hésitera pas à mentir de son côté pour ne pas perdre la face. Il ne se rend pas compte qu’il fait aux autres ce qu’il n’aime qu’on lui fasse !</p>\n<p>Aussi, cette personne adore s’engager sans réfléchir aux conséquences. Le moment voulu, elle change souvent d’avis, car le projet ne la tente plus. Elle qui ne supporte pas les promesses non tenues peut donc en faire de même et ainsi, décevoir ses pairs. </p>\n<p><!-- /divi:paragraph --></p>\n<p><!-- divi:image {\"align\":\"center\",\"id\":4035,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} --></p>\n<p><!-- /divi:image --></p>\n<p><!-- divi:heading --></p>\n<h2>7 — Une carapace pour cacher un manque d’amour-propre dans la blessure de trahison </h2>\n<p> </p>\n<p>Ici, nous allons plus nous concentrer sur les effets invisibles de cette souffrance pour les autres. Il s’agit de la panoplie d’émotions négatives ressenties par l’enfant intérieur qui sommeille dans la personnalité contrôlante. Ces émotions sont enfouies sous une carapace agressive et hautaine. En effet, la personne sujette à la blessure de trahison éprouve, contre toute attente, un grand manque de confiance et d’estime de soi. Puisqu’elle ne s’apprécie pas assez, elle recherche l’amour à travers le regard des autres et a donc un fort besoin de reconnaissance. Cependant, elle ne se sent pas assez aimée par ses semblables. De ce fait, avoir peur de la séparation et ressentir une jalousie excessive ne sont pas des faits rares chez elle.</p>\n<p>Mais vu qu’elle n’admet pas sa vulnérabilité, elle tiendra tout de même tête aux personnes qu’elle craint secrètement, c’est-à-dire celles qui arrivent à s’affirmer, sans agressivité. Cependant, elle les fuira discrètement dès qu’elle en aura l’occasion. </p>\n<p>Comment rester soi-même et se donner le droit de montrer ses fragilités avec une telle blessure ?</p>\n<p> </p>\n<h2>8 — Une anxiété profonde dans la blessure de trahison </h2>\n<p> </p>\n<p>Qui dit personnalité contrôlante dit insécurité et difficulté à <a href=\"/lacher-prise-et-acceptation\" target=\"_blank\" rel=\"noopener\" title=\"Lâcher-prise et acceptation\">lâcher-prise</a>. En effet, plus un individu tente de maîtriser son existence, plus il a peur de perdre le contrôle. Le problème, c’est que la vie n’est pas un long fleuve tranquille et que nous ne pouvons tout contrôler. Par conséquent, cette personne développera souvent des troubles anxieux, à force de ruminer et d’entretenir des pensées négatives limitantes. Pour gérer son insécurité comme elle le peut, elle peut même déclencher des troubles obsessionnels compulsifs. Par exemple, en effectuant certains gestes, elle peut penser qu’ils la protègeront contre certains événements du quotidien. </p>\n<p>Il n’est pas rare que l’individu soit atteint de phobie, de panique ou d’agoraphobie. </p>\n<p>Mais bien évidemment, toute cette anxiété reste cachée aux yeux des autres. Le problème, c’est qu’en la refoulant, l’individu peut développer une grande peur irrationnelle, constituant d’ailleurs la principale angoisse du contrôlant : la peur de la folie. </p>\n<p> </p>\n<h2>9 — Problèmes de santé et blessure de trahison </h2>\n<p> </p>\n<p>Si l’individu contrôlant n’arrive pas à apaiser sa blessure émotionnelle de trahison, des ennuis de santé peuvent apparaître. Il s’agira principalement de problèmes au niveau du foie et de l’estomac (le foie étant associé, en médecine chinoise, à la colère). </p>\n<p>Il en est de même pour les affections se terminant en « ite », lesquelles reflètent la frustration et la fureur. Il s’agit d’ailleurs de maladies inflammatoires (personne qui s’enflamme), telles que cystite, gastro-entérite, laryngite, méningite, phlébite, etc.</p>\n<p>L’herpès buccal, aussi fréquent, provient également d’un tempérament stressé et irascible.</p>\n<p>Enfin, les problèmes aux genoux (blocage, arthrose, etc.) sont très répandus chez un contrôlant, puisqu’ils dénotent un refus de plier, de céder à une situation ou à quelqu’un.</p>\n<p>La colère reste, par conséquent, une émotion toxique pouvant provoquer de nombreuses difficultés. </p>\n<p><!-- /divi:paragraph --></p>\n<p><!-- divi:image {\"align\":\"center\",\"id\":2980,\"sizeSlug\":\"full\",\"linkDestination\":\"custom\"} --></p>\n<p><!-- /divi:image --></p>\n<p>La blessure de trahison reste une grande blessure. Ces blessures du passé influent sur la paix intérieure de l’individu, c’est certain. Cependant, si vous avez atterri sur cette page, c’est que vous êtes une personne consciente, puisque vous souhaitez vous renseigner sur vos éventuelles blessures émotionnelles. <b>Reconnaître la blessure de trahison</b> est la première étape pour apprendre à s’en libérer et en guérir. </p>\n<p>Pour vivre pleinement, il faut réussir à rester soi. Le mal-être dû à votre douleur n’est pas inné. </p>\n<p>Si vous estimez, après cette lecture, souffrir de la blessure de trahison, je vous invite à aller consulter la <a href=\"/comment-soigner-la-blessure-de-trahison\" target=\"_blank\" rel=\"noopener\" title=\"Comment soigner la blessure de trahison\">suite dudit article,</a> laquelle vous aidera à cicatriser cette blessure intérieure.</p>\n<p></p>\n<p><!-- /divi:paragraph --></p>\n<p><!-- divi:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\",\"orientation\":\"horizontal\"}} --></p>\n<p><!-- /divi:buttons --></p>\n<p><!-- divi:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\",\"orientation\":\"horizontal\"}} --></p>\n<p><!-- /divi:buttons --></p>\n<p><!-- divi:paragraph -->Si mon blog vous aide, vous pouvez également soutenir mon travail en me faisant un petit don sur mon compte Tipeee :</p>\n<p><!-- /divi:paragraph --></p>\n<p><!-- divi:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\",\"orientation\":\"horizontal\"}} --></p>\n<p><!-- /divi:buttons --></p>\n<p><!-- divi:paragraph --></p>\n<p><!-- /divi:paragraph --></p>\n<p><a href=\"https://amzn.to/3VGgcry\">Visitez Amazon pour vous procurer le livre</a> de Lise Bourbeau « Les cinq blessures qui empêchent d’être soi-même ».</p>\n<p>(Lien rémunéré par Amazon)</p>','published',1,'Blessure de Trahison : 9 Signes pour la Reconnaître (et Guérir)','Contrôle, méfiance, anxiété : la blessure de trahison laisse des traces. Découvrez les 9 signes qui la révèlent et le chemin pour vous en libérer enfin.','https://vivre-pleinement.fr/blessure-de-trahison/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-trahison\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-trahison\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Reconna\\u00eetre le Blessure de Trahison en 9\\u00a0Sympt\\u00f4mes\",\"datePublished\":\"2021-09-02T15:21:58+00:00\",\"dateModified\":\"2024-02-11T19:40:50+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-trahison\\/\"},\"wordCount\":2379,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-trahison\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2021\\/09\\/blessure-trahison-1.jpg\",\"articleSection\":[\"Blessures de l\'\\u00e2me\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-trahison\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-trahison\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-trahison\\/\",\"name\":\"Reconna\\u00eetre le Blessure de Trahison en 9\\u00a0Sympt\\u00f4mes\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-trahison\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-trahison\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2021\\/09\\/blessure-trahison-1.jpg\",\"datePublished\":\"2021-09-02T15:21:58+00:00\",\"dateModified\":\"2024-02-11T19:40:50+00:00\",\"description\":\"Il existe 5 blessures de l\'\\u00e2me : le rejet, l\\u2019abandon, l\\u2019humiliation, la trahison et l\\u2019injustice. Comment reconna\\u00eetre la blessure de trahison\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-trahison\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-trahison\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-trahison\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2021\\/09\\/blessure-trahison-1.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2021\\/09\\/blessure-trahison-1.jpg\",\"width\":900,\"height\":600,\"caption\":\"Comment reconnaitre la blessure de trahison ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/blessure-de-trahison\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Reconna\\u00eetre le Blessure de Trahison en 9\\u00a0Sympt\\u00f4mes\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2021-09-02 15:21:58',NULL,'2026-05-24 19:19:44','2026-06-19 21:01:43');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (24,'Hypersensibilité et Travail : Conseils pour Concilier les Deux','hypersensibilite-au-travail','L’hypersensibilité est une sensibilité exacerbée touchant 20 % de la population. C’est un trait de caractère naturel pouvant demeurer difficile à vivre, notamment dans le cadre du travail. Vous vous sentez inadapté au monde du travail. Vous ne pouvez pas rester dans un job où il règne une mauvaise ambiance. Vous avez du mal avec le côté mécanique du travail, qui demande de savoir gérer ses émotions, les refouler et à rester au même niveau de productivité quoiqu’il arrive. Et si être hypersensible comportait de nombreux avantages ? Comment apprendre à concilier hypersensibilité et travail ? \n','<p>L’hypersensibilité est une sensibilité <b>exacerbée </b>touchant <b>20 %</b> de la population. C’est un trait de caractère <b>naturel </b>pouvant demeurer <b>difficile </b>à vivre, notamment dans le cadre du travail. Vous vous sentez <b>inadapté </b>au monde du travail. Vous ne pouvez pas rester dans un job où il règne une <b>mauvaise ambiance</b>. Vous avez du mal avec le côté <b>mécanique </b>du travail, qui demande de savoir <b>gérer </b>ses émotions, les refouler et à rester au même niveau de <b>productivité </b>quoiqu’il arrive. Et si être hypersensible comportait de nombreux <b>avantages </b>? Comment apprendre à concilier <b>hypersensibilité et travail ? </b></p>\n<h2>Les manifestations de l’hypersensibilité au travail </h2>\n<p>La personne dotée d’une grande sensibilité se sent différente et pense être une inadaptée sociale. Pourtant, le monde de l’entreprise apparaît aussi stressant pour ceux n’ayant pas cette extrême sensibilité. En effet, le milieu professionnel pousse à la concurrence, à la performance, à la critique, à la pression et à mettre ses ressentis de côté, tout ce que la personne profondément sensible exècre. Le domaine professionnel apparaît difficile à gérer pour elle, car elle déteste : </p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">Être surveillée lorsqu’elle travaille ;</li>\n<li aria-level=\"1\">Devoir cacher ses émotions, très vives ; </li>\n<li aria-level=\"1\">Trop de pression continuelle. Elle aime l’adrénaline à petite dose, mais ne supportera pas d’en avoir constamment ;</li>\n<li aria-level=\"1\">Ressentir l’énergie et les sentiments d’autrui ;</li>\n<li aria-level=\"1\">Avoir une activité en open space, puisque tous les stimuli vont vite devenir épuisants ; </li>\n<li aria-level=\"1\">Se trouver en contact permanent avec la clientèle ;</li>\n<li aria-level=\"1\">Appartenir à une entreprise qui ne possède pas ses valeurs ou avoir un « mauvais » patron. Dans ce cas, elle démissionnera ou défiera l’autorité ; </li>\n<li aria-level=\"1\">L’ennui. Une personne <a href=\"/hypersensibilite\" target=\"_blank\" rel=\"noopener\" title=\"Hypersensibilité\">hypersensible</a> peut souvent changer d’emploi et paraître instable, car à un moment, elle ne trouve plus de sens à son job et a besoin de nouveaux challenges. </li>\n</ul>\n<h2>Les avantages de l’hypersensibilité au travail</h2>\n<p>Dites-vous qu’en ayant une sensibilité extrême, vous avez de grandes qualités que les autres ne possèdent pas.</p>\n<p>Étonnamment, même si une hyperémotive est de nature <a href=\"/angoisse-stress-anxiete\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse stress anxiété\">anxieuse</a>, elle résiste mieux au stress que ses collègues dans certaines situations. </p>\n<p>De la même manière, la personne émotive se respecte assez pour ne pas tolérer une mauvaise ambiance trop longtemps. Si tel est le cas, elle finira par partir.</p>\n<p>De plus, cette personne aimant la solitude, elle n’éprouve aucune difficulté à devenir rapidement autonome. </p>\n<p>Enfin, la personne hypersensible ayant une grande empathie naturelle, elle est considérée comme un très bon élément par ses employeurs, notamment pour son contact humain. Elle a la capacité de rendre un client mécontent finalement apaisé et satisfait. </p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"426\" src=\"/storage/blog-images/Sensibilite-exacerbee-profession.jpg\" alt=\"Hypersensibilite emotionnelle dans son metier \" title=\"Sensibilité-exacerbée-profession\">\n<h2>Comment concilier hypersensibilité et travail ? </h2>\n<p>Si votre hypersensibilité émotionnelle vous gâche la vie au travail, sachez qu’il existe de nombreuses solutions pour mieux la vivre dans votre job.</p>\n<h3>S’affranchir du regard des autres </h3>\n<p>La personne sensible a du mal à faire la distinction entre une critique bienveillante pouvant l’aider à évoluer et un reproche gratuit. Donc, quand une remarque émerge, elle devrait prendre du recul sur ledit <a href=\"/jugement-des-autres\" target=\"_blank\" rel=\"noopener\" title=\"Jugement des autres \">jugement</a>.</p>\n<p>La personne hyperémotive est d’ailleurs souvent sujette au syndrome de l’imposteur et se met une grande pression si elle reçoit un compliment. Elle peut se dire : « non, ils se trompent, ils en attendent trop de moi, je vais les décevoir, car je suis nulle, etc. » Cependant, l’employeur ne va pas complimenter un employé ne faisant pas l’affaire. Donc, un éloge est forcément mérité.  </p>\n<p>D’ailleurs, au lieu d’attendre la reconnaissance des autres, et si vous fêtiez vous-même vos victoires lorsque vous pensez avoir travaillé dur ? </p>\n<h3>Prioriser certaines tâches  </h3>\n<p>Si vous avez un caractère sensible, quand vous avez trop de travail, vous pouvez vous sentir très vite submergé. Il y a donc lieu d’apprendre à <a href=\"/lacher-prise-et-acceptation\" target=\"_blank\" rel=\"noopener\" title=\"Lâcher-prise et acceptation\">lâcher-prise.</a> En effet, nous avons souvent trop de tâches à accomplir par jour. Il convient alors de les prioriser. Pourquoi ne pas effectuer les tâches les moins appréciables dès le début ? Vous pourrez ainsi vous sentir plus libre pour la suite de votre journée.</p>\n<h3>Rendre son environnement de travail agréable </h3>\n<p>Essayez de privilégier une profession où il n’existe pas d’open space. Si ce n’est pas envisageable, préférez passer du temps avec des collègues vous tirant vers le haut. Vous pouvez aussi personnaliser votre bureau afin de pouvoir vous sentir le plus à l’aise possible. Mettre une photo des gens que vous aimez, un objet de vos vacances ou qui a une forte symbolique pour vous, etc. </p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h3>Apprendre à maîtriser ses émotions</h3>\n<p>La personne hypersensible peut apparaître très rancunière. Par conséquent, lorsqu’une situation est difficile avec quelqu’un, il vaut mieux ne pas garder tout pour vous, mais l’exprimer à autrui de manière affirmative. Par contre, il est préférable de ne pas le faire à chaud, puisque l’individu sensible apparaît souvent très impulsif et irritable. Il est donc capable de prononcer des paroles regrettables à cause de la surcharge émotionnelle. </p>\n<p>Enfin, par exemple, si un client est très en colère contre la société dans laquelle vous travaillez, il peut s’en prendre à vous. Mais parler avec vous ou quelqu’un d’autre ne change rien pour lui : il aurait réagi de la même manière. Évitez ainsi de prendre les choses personnellement.</p>\n<h3>Se relaxer au travail </h3>\n<p>Voici les astuces qui vont aideront à gérer votre stress au travail :</p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">Acheter un petit roll-on anti-stress à étaler sous le poignet. À inhaler dès que vous vous sentez sous tension ; </li>\n<li aria-level=\"1\">Prendre des pauses afin de couper les pensées anxiogènes et d’avoir les idées plus claires ; </li>\n<li aria-level=\"1\">Fermer les yeux quelques instants pour relaxer l’organisme ; </li>\n<li aria-level=\"1\">Pratiquer des techniques de visualisation. En fermant les yeux, rappelez-vous de bons moments passés et ensuite, trouvez un mot qui vous évoque cette situation. Il s’agit d’une technique d’ancrage. Ainsi, quand vous prononcerez ou penserez à ce mot, vous vous remémorerez également le souvenir agréable, ce qui vous apaisera automatiquement ; </li>\n<li aria-level=\"1\">Vous focaliser sur toutes les parties de votre corps une à une en vous attardant sur les tensions. Vous pouvez souffler en même temps et imaginer mentalement votre souffle se ciblant sur la zone douloureuse et l’apaisant ; </li>\n<li aria-level=\"1\">Si vous vous sentez anxieux, posez-vous et inspirez pendant 5 secondes tout en expirant pendant 5 secondes. Pratiquez cet exercice jusqu’à retrouver le calme. </li>\n</ul>\n<p>Cette technique de respiration se nomme la cohérence cardiaque. J’utilise fréquemment cette méthode et pour m’aider à pratiquer correctement, je me sers d’un petit appareil nommé Zenspire, lequel, grâce à sa vibration et à sa lumière, me permet de respirer  profondément et exactement comme il le faut. Si ce produit vous intéresse et que vous voulez passer commande, sachez qu’en passant par le code JL0620, vous bénéficierez d’une réduction de 10 %. Pour profiter de cette remise et de cette petite merveille, c’est ici :</p>\n<img loading=\"lazy\" decoding=\"async\" width=\"640\" height=\"457\" src=\"/storage/blog-images/hyperemotivite-job.jpg\" alt=\"Grande sensibilite au boulot \" title=\"hyperémotivité-job\">\n<h3>Changer sa perception de la vie </h3>\n<p>Une personne hautement sensible pouvant vite se laisser déborder par ses émotions, elle devrait travailler sur sa façon de voir les évènements. </p>\n<p>Déjà, au lieu de vous imaginer être jugé par tout le monde constamment, vous pouvez vous dire : « les gens ont d’autres préoccupations dans leur vie. » Dès qu’une idée négative commence à envahir votre esprit, à vous de la remplacer par une pensée plus positive. Par exemple, vous vous dites, le lundi matin, « j’en ai assez d’aller travailler ». Pourquoi ne pas penser plutôt : « bon, il en va de ma responsabilité de me rendre à mon poste pour nourrir ma famille. Si j’en ai assez, je vais réfléchir pour m’adonner à une nouvelle activité et passer à l’action.»</p>\n<p>Et si votre métier n’a plus de signification pour vous, pourquoi ne pas vous fixer des objectifs afin de vous rebooster ? Par exemple, vous inscrire à des formations, tenter de monter en grade, etc. </p>\n<h3>Changer de métier </h3>\n<p>La personne très sensible a beaucoup de mal à rester dans un environnement stressant sur le long terme. De plus, elle a un fort besoin de sens dans sa vie et notamment dans son travail. Donc, si elle s’ennuie, elle aura tendance à chercher un nouvel emploi correspondant plus à ses aspirations. D’ailleurs, certains domaines sont recommandés pour elle, comme : </p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">La santé, puisqu’elles restent très altruistes et ont une empathie naturelle pour aider leurs pairs (psychologue, coach, infirmière, médecin, etc.) ; </li>\n<li aria-level=\"1\">La communication, car même si elles ont besoin de calme et de solitude de temps à autre, elles aiment le contact humain. D’ailleurs, elles ont tendance à privilégier le social et à mettre la performance en second plan (manager, gestionnaire d’un service client, etc.) ; </li>\n</ul>\n<ul>\n<li aria-level=\"1\">L’art, étant donné que cette personne demeure très créative et peut réaliser ses œuvres calmement, sans compétition (musicienne, peintre, photographe, dessinatrice, etc.) ;</li>\n</ul>\n<h3>Devenir entrepreneur</h3>\n<p>L’entrepreneuriat correspond très souvent aux personnes hypersensibles. Car puisqu’elles apprécient les moments de solitude, avoir un business à domicile, par exemple, est un bonheur pour elles. Elles ont également un fort besoin de liberté et d’autonomie, valeurs qu’on ne retrouve pas forcément dans le salariat. Le fait de travailler quand elles le souhaitent et aux horaires qu’elles veulent n’a pas de prix pour elles.  </p>\n<p>Le plus difficile pour une personne ayant une sensibilité exacerbée reste le démarchage, puisqu’elle a peu confiance en elle. Mais si elle arrive à dépasser ses peurs, elle deviendra un entrepreneur pleinement épanoui. </p>\n<p> </p>\n<p>Être trop sensible au travail n’est pas toujours facile à vivre. Puisque vous êtes empathique, vous ressentez plus intensément les émotions négatives des autres. Avec des émotions à fleur de peau, vous pouvez apparaître très sensible aux critiques. En tant que grand sensible, les différents stimuli peuvent vous fatiguer. Mais vous l’avez compris avec cet article, il est possible d’apprendre à <b>concilier hypersensibilité et travail.</b> Allez-vous tenir compte des conseils de cet article afin de vous épanouir pleinement ? </p>\n<p> </p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'Hypersensibilité et Travail : Conseils pour Concilier les Deux','L’hypersensibilité est un trait de caractère pouvant demeurer difficile à vivre au travail. Comment apprendre à concilier hypersensibilité et travail ?','https://vivre-pleinement.fr/hypersensibilite-au-travail/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/hypersensibilite-au-travail\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/hypersensibilite-au-travail\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Hypersensibilit\\u00e9 et Travail\\u00a0: Conseils pour Concilier les Deux\",\"datePublished\":\"2021-07-01T16:41:41+00:00\",\"dateModified\":\"2024-02-13T19:10:40+00:00\",