ion\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/zenspire\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/zenspire\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2021\\/05\\/Zenspire-anxiete-insomnie-relaxation-blanc.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2021\\/05\\/Zenspire-anxiete-insomnie-relaxation-blanc.jpg\",\"width\":900,\"height\":333,\"caption\":\"Zenspire-sleep\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/zenspire\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Ma\\u00eetriser rapidement son anxi\\u00e9t\\u00e9 et ses insomnies gr\\u00e2ce \\u00e0 Zenspire\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2021-05-07 16:24:16',NULL,'2026-05-24 19:19:44','2026-06-19 22:28:14');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (26,'La Signification et l’Interprétation des Rêves, une Piste d’Epanouissement','symbolique-des-reves','La signification et l’interprétation des rêves attirent un grand nombre de personnes. Il n’y a qu’à voir les innombrables sites possédant un dictionnaire des rêves. L’interprétation des rêves peut d’ailleurs s’effectuer de différentes manières, comme, par exemple, via la façon de penser de Jung ou de celle de Freud. Certains pensent aussi que les songes sont dus au fonctionnement de l’inconscient durant le sommeil. D’autres y voient plutôt un aspect spirituel, relatif au domaine des anges qui nous guideraient lors un rêve lucide. Certains rêves peuvent apparaître prémonitoires. En période de grand stress, vous faites des cauchemars très violents, comme apercevoir un tsunami tout ravager. Vous rêvez sans cesse d’être en retard et de ne pas réussir à arriver à votre but. Le monde onirique vous fascine ? Comment vos songes peuvent vous aider à avancer dans votre vie ? \n','<h2>Comment interpréter la signification de ses rêves ?</h2>\n<p>Pourquoi rêve-t-on, et nos rêves veulent-ils dire quelque chose ? Depuis toujours, leur <b>signification</b> fascine. S\'il n\'existe pas de dictionnaire universel des rêves — chaque image vous appartient —, ils ne sont pas non plus le fruit du hasard : ils sont une <b>fenêtre sur vos émotions</b>, en particulier celles que vous refoulez à l\'éveil.</p>\n<p>Pour interpréter un rêve, trois clés :</p>\n<ul>\n<li><b>Reliez-le à ce que vous vivez.</b> Un rêve récurrent ou marquant fait souvent écho à une émotion non digérée, un <a href=\"/blog/traumatisme\">traumatisme</a> ou un <a href=\"/blog/angoisse-stress-anxiete\">stress</a> actuel.</li>\n<li><b>Observez la charge émotionnelle</b> plutôt que les détails : c\'est ce que vous avez ressenti qui compte, pas seulement le scénario.</li>\n<li><b>Méfiez-vous des interprétations toutes faites</b> : un même rêve peut avoir plusieurs sens selon votre histoire.</li>\n</ul>\n<p>Dans cet article, nous verrons les origines des rêves, comment interpréter les cauchemars, et ce qu\'ils révèlent de votre monde intérieur.</p>\n<p><b>La signification et l’interprétation des rêves</b> attirent un grand nombre de personnes. Il n’y a qu’à voir les innombrables sites possédant un <b>dictionnaire </b>des rêves. L’interprétation des rêves peut d’ailleurs s’effectuer de différentes manières, comme, par exemple, via la façon de penser de <b>Jung </b>ou de celle de <b>Freud</b>. Certains pensent aussi que les songes sont dus au fonctionnement de <b>l’inconscient </b>durant le sommeil. D’autres y voient plutôt un aspect <b>spirituel</b>, relatif au domaine des <b>anges </b>qui nous guideraient lors un rêve <b>lucide</b>. Certains rêves peuvent apparaître <b>prémonitoires</b>. En période de grand <b>stress</b>, vous faites des cauchemars très <b>violents</b>, comme apercevoir un <b>tsunami </b>tout ravager. Vous rêvez sans cesse d’être en <b>retard </b>et de ne pas réussir à <b>arriver </b>à votre but. Le monde onirique vous <b>fascine </b>? Comment vos songes peuvent vous aider à <b>avancer </b>dans votre vie ? </p>\n<h2>Les différentes origines des rêves</h2>\n<p>Le rêve peut provenir de plusieurs causes, qui ont bien souvent, une relation avec notre vécu. Décrypter les origines de vos rêves peut donc constituer un bon outil de connaissance de soi. Examinons-les ensemble.</p>\n<h3>Le refoulement des émotions </h3>\n<p>Bien souvent, au cours d’une journée, nous nous retenons. Par exemple, si nous travaillons, nous devons garder une certaine retenue. Par conséquent, si un collègue nous tape sur le système, nous le gardons pour nous, sans le montrer. Un conflit interne latent fait donc son apparition. Cette censure de la journée peut alors pousser votre subconscient à vivre pleinement vos émotions dans un rêve, et ce, afin de pouvoir évacuer votre colère via un rêve. Vous pouvez, par exemple, vous retrouver à hurler sur la personne ou même, à lever la main sur elle. </p>\n<h3>Un traumatisme psychologique </h3>\n<p>Les personnes souffrant du syndrome de stress post-traumatique, via leurs rêves, repassent en boucle une scène traumatisante qu’elles ont vécue (une prise d’otage, par exemple). Et c’est normal. En effet, rêver de la sorte ne constitue qu’une étape du processus naturel de cicatrisation dudit <a href=\"/traumatisme\" target=\"_blank\" rel=\"noopener\" title=\"Traumatisme\">traumatisme</a>. Le cerveau, en se remémorant sans cesse l’événement, cherche juste à l’intégrer et à le classer par rapport aux autres souvenirs. C’est ce qui permet à la personne d’aller, par la suite, de l’avant.</p>\n<h3>Un trouble anxieux</h3>\n<p>Plus vous souffrez d’angoisse, inconsciente ou consciente, plus vous risquez de rêver de manière fréquente et vive. Puisque lorsqu’une personne souffre de <a href=\"/angoisse-stress-anxiete\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse stress anxiété\">troubles anxieux</a>, elle a bien souvent le sommeil agité et donc, léger. Et c’est d’ailleurs là que les rêves dont vous vous souvenez apparaissent. </p>\n<h3>Le stress</h3>\n<p>Les rêveurs peuvent aussi faire partie des personnes très stressées. C’est le cas, par exemple, de celles assumant de lourdes responsabilités dans leur job. Elles vont bien souvent stresser également la nuit voire même, se réveiller en pleine nuit en pensant au travail, à ce qu’elles ont peut-être oublié d’accomplir, ce qui les fera encore plus paniquer. Qui dit vie stressante dit sommeil agité et par conséquent, de grandes chances de rêver et surtout, de cauchemarder. </p>\n<h3>Une peur infantile </h3>\n<p>Cette cause est surtout valable si vous faites des rêves fréquents et répétitifs. Car ces rêves proviennent souvent de blessures du passé, lesquelles trouvent fréquemment leur origine dans l’enfance. </p>\n<h3>Un conflit insoluble </h3>\n<p>Lorsque vous vivez ou avez vécu un conflit insoluble avec quelqu’un, qui était une personne importante pour vous, vous pouvez rêver de résoudre ce conflit. Le fait de procéder de manière imaginaire, c’est-à-dire par le rêve pour des conflits insolubles, vous permettra de vous libérer de ce poids vous rongeant dans votre vie. </p>\n<h3>Des souvenirs d’une vie antérieure ou un souvenir du cerveau </h3>\n<p>Ce paragraphe relève plus du domaine de la croyance ou non en la réincarnation. Je ne sais pas si cette situation vous est déjà arrivée. Personnellement, j’ai déjà rêvé de voir une personne, que je ne connais pas en réalité, mais que je connais par contre profondément dans mon rêve (enfin, que je pense connaître). D’ailleurs, je me sens vraiment heureuse de revoir cette personne ! Est-ce donc une personne d’une vie antérieure me rendant visite pendant mon sommeil ? </p>\n<p>Il peut également exister une explication plus rationnelle à ce phénomène. En effet, ne serait-ce que dans une seule journée, nous n’avons pas idée du nombre d’éléments que notre cerveau enregistre inconsciemment. Les sons, les odeurs, les images, les discussions et ce, même si nous avons l’impression de ne pas du tout nous en rappeler. Sauf que notre cerveau imprime tout de même. Donc, voir une personne nous semblant inconnue en rêve peut juste provenir d’une personne que nous avons récemment vue dans notre vie, et ce, sans nous en souvenir. </p>\n<h3>Un deuil </h3>\n<p>Ce genre de rêve arrive très fréquemment quand un individu perd un proche. Il peut apparaître juste après sa mort et aussi de manière régulière des années après et surtout, lors d’une période de fragilité. Car un décès marque un individu, ce phénomène est donc normal. Le travail du rêve est alors d’aider la personne à faire son deuil. À stopper la culpabilité qu’elle ressent suite cette disparition. En effet, lors de ce genre d’événement, nous nous sentons bien souvent coupables de ne pas avoir été assez présents, de ne pas avoir assez communiqué. De ne pas avoir été assez gentil avec la personne lorsqu’elle existait encore. Il s’agit donc d’un processus normal. Certaines personnes pensent aussi que le défunt vient les voir dans leur rêve. Pourquoi pas ? </p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"452\" src=\"/storage/blog-images/Origine-reves.jpg\" alt=\"Monde onirique\" title=\"Origine-rêves\">\n<h2>Pourquoi certaines personnes ne rêvent pas ? </h2>\n<p>Certaines personnes disent ne pas rêver. Cependant, c’est faux et surtout, impossible. Car avoir des rêves est un mécanisme on ne peut plus naturel se déroulant la nuit. Tout le monde est donc un rêveur ou une rêveuse. Mais il est vrai que certains individus se rappellent quasiment constamment de leurs songes, alors que certains pas du tout. Pourquoi ? </p>\n<p>Il y a, en effet, des personnes qui disent rêver beaucoup, mais ils ne rêvent pas plus que les autres. Car tout le monde rêve de manière régulière, et ce, via les différents cycles de sommeil s’enchaînant dans la nuit. La seule raison pour laquelle certaines personnes se souviennent plus de leurs rêves que d’autres est qu’elles dorment plus légèrement. D’ailleurs, quand avons-nous le plus de chances de nous souvenir de nos songes ? Eh bien, la nuit au moment de nous endormir, vu que le sommeil demeure encore très léger à ce moment. Idem au petit matin, pendant que notre cerveau commence à se réveiller. Tandis que quand nous nous trouvons en sommeil profond, nous ne nous souvenons que très rarement de nos songes. Donc forcément, lorsque vous dormez presque toute la nuit légèrement, il est normal de plus vous souvenir de vos rêves. </p>\n<p>Une petite parenthèse cependant. En effet, certaines personnes s’endorment en prenant des somnifères, qu’elles en prennent régulièrement ou non. Et oui, un hypnotique fait dormir. Mais bien souvent, la personne ne se souvient pas du tout de ses rêves en en prenant. En fait, un somnifère assomme la personne et rend son sommeil moins naturel. Les cycles de sommeil ne se jouent donc pas de la même manière avec ces médicaments. </p>\n<h2>L’interprétation des cauchemars</h2>\n<p>Lorsque nous rêvons, il ne s’agit, malheureusement, pas toujours de beaux rêves. En effet, vous pouvez faire des cauchemars. Et surtout si vous êtes une personne avec un psychisme assez actif ; très créative et intuitive. Évidemment, les autres individus peuvent également faire un cauchemar, mais sans doute moins fréquemment. </p>\n<p>Ces cauchemars surviennent souvent lors de la phase d’endormissement, ce qui peut, bien entendu, provoquer une<a href=\"/angoisses-nocturnes\" target=\"_blank\" rel=\"noopener\" title=\"Angoisses nocturnes\"> angoisse nocturne</a>, mais pas que. En effet, les cauchemars, surtout lorsqu’ils sont fréquents, peuvent provenir d’un stress insurmontable. L’individu se sent anormalement submergé dans sa vie et de fait, en cauchemarde la nuit. La personne qui va rêver de la sorte peut également avoir des sueurs nocturnes et aussi, ressentir de l’anxiété au réveil dû à ses problèmes actuels et à ses nuits mouvementées. </p>\n<p>Cependant, doit-on toujours faire une interprétation du rêve lorsqu’il s’agit de cauchemar ? Est-ce forcément prémonitoire ? Non, et ouf ! En effet, rêver de perdre ses dents ou d’avoir un serpent chez soi ne veut pas nécessairement dire que ces situations vont arriver. Et heureusement ! Par contre, ces cauchemars peuvent refléter une angoisse profonde en vous. À vous d’en connaître l’origine. </p>\n<h2>La lune a-t-elle un lien avec les rêves ?</h2>\n<p>La lune, et surtout la pleine lune, demeurerait la voie royale pour les songes et pour l’augmentation des problèmes mentaux. Est-ce véridique ou n’est-ce qu’un mythe ? D’après mon expérience et de ce que j’ai pu en voir d’autres personnes, il est vrai que les moments de pleine lune rendent les individus beaucoup plus irritables, anxieux, etc. Cependant, je pense que la lune joue surtout sur les personnes ayant une forte intuition, mais aussi sur celles éprouvant un certain déséquilibre mental. Pour les individus équilibrés, cet astre n’a strictement aucun effet. Par contre, les personnes avec certains problèmes psychologiques ou émotionnels voient leurs troubles amplifiés. </p>\n<p>Je dirais également que la lune a plus de répercussions sur la femme. Car le cycle menstruel de la femme suit celui de la lune. Voilà pourquoi les femmes peuvent plus surréagir du fait de leurs hormones que les hommes.</p>\n<p>De ce fait, pour ces personnes, la nuit de pleine lune, voire certains jours la précédant ou la succédant, le sommeil peut s’en trouver perturbé. À la clé : une multitude de rêves étranges, puisque le dormeur se réveille souvent de manière fréquente.</p>\n<h2>La paralysie du sommeil, entre rêve et réalité </h2>\n<p>Si vous avez déjà vécu une paralysie du sommeil, vous savez à quel point cette expérience peut apparaître effrayante. Voyons ce phénomène plus en détail.</p>\n<h3>La paralysie du sommeil </h3>\n<p>Pendant le sommeil paradoxal, certaines personnes peuvent vivre une expérience très étrange et désagréable : la paralysie du sommeil. Ce phénomène survient, en réalité, lorsque l’individu apparaît à moitié conscient mais qu’il vit aussi, en même temps, une sorte de rêve éveillé. </p>\n<p>Donc, la personne rêve bien souvent juste avant et se réveille soudainement. Elle peut en plus, à ce moment, ressentir une présence maléfique s’approchant d’elle. Forcément, elle veut crier, bouger, fuir, mais son corps, rempli de fourmillements, ne bouge pas. Puis, elle finit par se réveiller. Je parle d’expérience : se voir sans défense de la sorte est vraiment terrifiant. Pour l’anecdote, j’ai déjà fait une paralysie du sommeil en « voyant » une personne juste au-dessus de moi, accroupie sur le plafond… Imaginez la terreur ! Car oui, il peut également y avoir des hallucinations visuelles, puisque vous êtes tout de même encore assoupi. </p>\n<p>Mais rassurez-vous, malgré les croyances que certaines personnes peuvent avoir à ce sujet (entité démoniaque, par exemple), ce phénomène reste scientifiquement prouvé. En fait, votre cerveau ne se réveille pas au même moment que votre corps. Il se réveille à moitié alors que votre organisme, lui, reste endormi. Ce qui explique pourquoi vous ne pouvez pas bouger, et pourquoi vous pouvez avoir l’impression de rêver encore. Il s’agit, en réalité, d’une discordance entre les deux. </p>\n<p>Après, je peux comprendre que ce phénomène soit très impressionnant à vivre. J’en fais de temps à autre et je pense en faire surtout lors de périodes de grand stress. Il est vrai qu’après avoir vécu une telle expérience, vous pouvez appréhender les prochaines nuits.</p>\n<h3>Le cauchemar </h3>\n<p>Il se peut que certaines fois, vous pensez faire une paralysie du sommeil, alors qu’il n’en est rien. Vous pouvez, disons, rêver de faire une paralysie du sommeil. Ce rêve est, en fait, un cauchemar où vous vous voyez en faire une… ce qui est différent puisque là, vous êtes bien endormi. Il s’agit juste d’un cauchemar. Ce cauchemar arrive souvent chez les personnes qui appréhendent d’en refaire une réelle. Pour ma part, je fais d’ailleurs beaucoup plus de cauchemars de la sorte qu’une vraie paralysie du sommeil.</p>\n<p>Certains rêves peuvent également paraître très étranges, comme le fait de quitter son corps, de rêver de voler dans la pièce en y ressentant toutes les sensations… n’est-ce qu’un songe ou une véritable sortie de notre âme ? Telle est la question…</p>\n<img decoding=\"async\" width=\"600\" height=\"368\" src=\"/storage/blog-images/Decoder-songes.jpg\" alt=\"Symbolique des reves \" title=\"Décoder-songes\">\n<h2>Mon expérience avec les rêves </h2>\n<p>Si je trouve que l’analyse des rêves reste intéressante, c’est parce que je crois que les songes peuvent refléter nos pensées profondes inconscientes de la journée. Je pense également que la symbolique des rêves apparaît très utile dans le cas d’un songe récurrent et aussi si vous faites le même genre de rêve depuis longtemps. Pour illustrer mes propos, je vous parlerai ci-dessous de mes rêves faits avec une certaine répétition. Vous pourrez pareillement, de votre côté, repérer vos rêves répétitifs pour y déceler leurs messages, lesquels peuvent devenir une voie de développement personnel pour vous. </p>\n<h3>Rêver de retard </h3>\n<p>Je tiens à préciser que les trois principaux rêves que je fais interviennent, la plupart du temps, au petit matin. Je rêve très fréquemment d’être en retard et de ne jamais atteindre un certain endroit. Il existe, dans ce songe, un événement qui m’empêche toujours d’arriver à destination. Par exemple, je suis incapable de m’habiller rapidement, il me manque un accessoire, je me perds en chemin, je n’arrive pas à accéder à mon téléphone pour activer le GPS, etc. Ce rêve peut vous paraître familier également. Car ce rêve n’est pas forcément un signe à interpréter. En effet, il peut y avoir une explication scientifique à ce songe. </p>\n<p>En fait, rêver de retard est un message du cerveau vous poussant à, doucement, vous réveiller. C’est comme si, inconsciemment, vous commenciez déjà à vous préparer en vue de la journée qui s’annonce. </p>\n<h3>Rêver de rejet </h3>\n<p>Je me trouve dans un groupe, bien souvent de personnes que je connais déjà. Il peut s’agir d’anciennes amies, de personnes que j’ai connues, d’individus que je côtoie actuellement, etc. Puis, à un moment donné, ces personnes commencent à partir entre elles, à m’ignorer voire même, à me repousser.</p>\n<p>Il n’y a pas de doute que ce rêve ne représente que le reflet de ma blessure de rejet, laquelle reste chez moi, je pense, la plus profonde. Cependant, j’ai l’impression de ne plus éprouver les symptômes de cette blessure, lesquels semblaient bien plus visibles dans mon enfance. En effet, cette blessure a été masquée par la blessure de trahison ou d’injustice s’étant ajoutée, mais n’ayant pas fait disparaître, pour autant, cette blessure. Le message que je retiens de ce rêve est donc de travailler sur la guérison de ma blessure de rejet. </p>\n<h3>Rêver de faire une crise de nerfs </h3>\n<p>Fréquemment également, je rêve d’entrer dans une grande hystérie. De littéralement perdre le contrôle, de vouloir tout casser, de hurler sans pouvoir m’arrêter, de devenir presque dingue. D’être en proie à une rage folle en somme. Idem pour ce songe, il n’y a pas besoin de tenter d’interpréter quoi que ce soit. En réalité, ce rêve apparaît surtout lorsque quelqu’un, ou une situation, me tape tout bonnement sur le système et que je me retiens beaucoup pour ne pas exploser. Donc, pour moi, ce rêve représente tout simplement la colère refoulée, que je contiens dans la journée. Et cette <a href=\"/colere\" target=\"_blank\" rel=\"noopener\" title=\"Colère\">colère</a>, ne pouvant s’exprimer ouvertement, s’exprime alors dans le songe. Il s’agit ainsi du concept de refoulement que je mentionne plus haut dans cet article. </p>\n<h2>La signification et l’interprétation des rêves ont-elles un sens ? </h2>\n<p>Pour conclure, doit-on trouver des significations à tous les songes et chercher à les interpréter constamment ? Eh bien, il existe plusieurs réponses possibles à cette question.</p>\n<h3>Les rêves n’ayant ni queue ni tête </h3>\n<p>Non, tous les rêves ne sont pas à interpréter. C’est notamment valable pour les songes ou, par exemple, vous rêvez de cheval, puisque vous en avez vu un au cours de la journée. Pour le coup, ce sont juste les souvenirs du cerveau qui s’expriment de manière désordonnée. C’est pourquoi, d’ailleurs, certains rêves semblent très désordonnés et sans aucun sens : car c’est le cas. Vous reconnaîtrez facilement ce type de rêve. </p>\n<h3>Les rêves métaphoriques </h3>\n<p>Il s’agit là des songes se montrant sous forme de symbole, de métaphore. Vous pouvez donc, si vous le désirez, chercher la signification des rêves de ce genre. Cependant, il ne faudra pas les prendre au pied de la lettre. C’est le cas, par exemple, de la mort. En effet, si vous rêvez qu’un proche meurt, ce songe ne veut pas dire qu’il va mourir prochainement. Justement, rêver de la mort est d’ailleurs plutôt bon signe. Ou si vous rêvez d’être pris dans un tsunami, vous comprendrez bien, et surtout si vous n’habitez pas près de la mer, que ce drame ne risque pas de vous arriver. Ce rêve peut, par exemple, dire et surtout, si vous survivez à ce raz-de-marée, que vous êtes une personne battante. Vous avez évolué et ne vous laissez plus submerger par vos peurs : vous allez de l’avant malgré l’adversité. </p>\n<a href=\"https://hypnocaments.com?partnerid=YK5muYugzSoIWDbDWRgT-Q\" title=\"Seances d hypnose en ligne\"><img decoding=\"async\" src=\"https://hypnocaments.com/image/banner_1_750.png\" alt=\"seance hypnose mp3\"></a>\n<h3>Les rêves détenant plusieurs interprétations </h3>\n<p>Les songes métaphoriques, lesquels peuvent détenir plusieurs interprétations. En effet, rêver, par exemple, d’incendie peut vouloir dire plusieurs choses différentes. Tout dépend de la situation du moment de l’individu, de son état de stress, de ses soucis, etc. Pour le coup, vous trouverez une multitude de sites sur Internet vous proposant un dictionnaire des rêves avec plusieurs interprétations. À vous de voir quelles significations vous parlent le plus et ressemblent le plus à votre situation actuelle. </p>\n<h3>Les rêves prémonitoires </h3>\n<p>Oui, les rêves apportant un présage existent, mais ils restent rares. Sont-ils des facultés d’un esprit avec des capacités psychiques et intuitives développées ? C’est possible. Certains y croient, d’autres non. Par exemple, une femme peut rêver de tomber enceinte et de le devenir quelques mois plus tard. Une prédiction ? Pas vraiment. Plutôt, un désir inconscient s’étant réalisé. Une personne rêve d’avoir à régler une note d’une somme précise de 3 209 €. Quelques jours après, elle reçoit vraiment une facture avec ce montant. Là, c’est plus impressionnant. </p>\n<p> </p>\n<p>Comprendre <b>la signification et l’interprétation des rêves </b>est, pour moi, un outil de plus pour atteindre l’accomplissement de soi. </p>\n<p> </p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'Signification des Rêves : Comment Interpréter ce qu\'ils Disent','Que signifient vos rêves et cauchemars ? Découvrez les origines des rêves, comment les interpréter et ce qu\'ils révèlent de vos émotions et de votre anxiété.','https://vivre-pleinement.fr/symbolique-des-reves/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/symbolique-des-reves\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/symbolique-des-reves\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"La Signification et l\\u2019Interpr\\u00e9tation des R\\u00eaves, une Piste d\\u2019Epanouissement\",\"datePublished\":\"2021-02-10T20:24:39+00:00\",\"dateModified\":\"2024-02-13T19:12:20+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/symbolique-des-reves\\/\"},\"wordCount\":6312,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/symbolique-des-reves\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2021\\/02\\/Signification-interpretation-reves.jpg\",\"articleSection\":[\"D\\u00e9veloppement personnel\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/symbolique-des-reves\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/symbolique-des-reves\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/symbolique-des-reves\\/\",\"name\":\"La Signification et l\\u2019Interpr\\u00e9tation des R\\u00eaves, une Piste d\\u2019Epanouissement\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/symbolique-des-reves\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/symbolique-des-reves\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2021\\/02\\/Signification-interpretation-reves.jpg\",\"datePublished\":\"2021-02-10T20:24:39+00:00\",\"dateModified\":\"2024-02-13T19:12:20+00:00\",\"description\":\"La signification et l\\u2019interpr\\u00e9tation des r\\u00eaves attirent un grand nombre de personnes. Comment vos songes peuvent vous aider \\u00e0 avancer dans votre vie\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/symbolique-des-reves\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/symbolique-des-reves\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/symbolique-des-reves\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2021\\/02\\/Signification-interpretation-reves.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2021\\/02\\/Signification-interpretation-reves.jpg\",\"width\":640,\"height\":360,\"caption\":\"Comment interpreter ses reves ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/symbolique-des-reves\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"La Signification et l\\u2019Interpr\\u00e9tation des R\\u00eaves, une Piste d\\u2019Epanouissement\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2021-02-10 20:24:39',NULL,'2026-05-24 19:19:44','2026-06-19 22:28:14');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (27,'Lutter Contre la Fatigue Mentale pour Retrouver le Bien-être','fatigue-mentale','La fatigue mentale, plus communément appelée asthénie, peut être considérée comme le mal des temps modernes, surpassant même l’épuisement physique. Car hormis certains métiers, les êtres humains ont, de nos jours, tendance à être plus fatigués mentalement que physiquement. En effet, étant donné que nous vivons dans une société prônant force, compétitivité et productivité, les individus se sentent obligés d’adhérer à ces valeurs. De ce fait, ils se fatiguent de plus en plus, vu qu’ils n’écoutent pas leurs besoins, mais ceux de la société. Vous ne parvenez plus à faire correctement votre ménage, vos mouvements sont au ralenti. Les tâches à effectuer vous paraissent insurmontables. Vous faites des crises d’angoisse et restez sans cesse focalisé sur vos problèmes en voyant tout en noir. Vous n’arrivez plus à dormir, car vous ruminez trop. La fatigue mentale vous submerge ? Comment lutter contre la fatigue mentale ? \n','<p>La<b> fatigue mentale,</b> plus communément appelée <b>asthénie</b>, peut être considérée comme le mal des temps modernes, <b>surpassant </b>même l’épuisement <b>physique</b>. Car hormis certains métiers, les êtres humains ont, de nos jours, tendance à être plus fatigués mentalement que physiquement. En effet, étant donné que nous vivons dans une société prônant force, compétitivité et productivité, les individus se sentent obligés d’adhérer à ces valeurs. De ce fait, ils se fatiguent de plus en plus, vu qu’ils n’écoutent pas leurs <b>besoins</b>, mais ceux de la <b>société</b>. Vous ne parvenez plus à faire correctement votre <b>ménage</b>, vos mouvements sont au <b>ralenti</b>. Les tâches à effectuer vous paraissent <b>insurmontables</b>. Vous faites des<b> crises d’angoisse </b>et restez sans cesse focalisé sur vos problèmes en voyant tout en <b>noir</b>. Vous n’arrivez plus à <b>dormir, </b>car vous <b>ruminez </b>trop. La fatigue mentale vous <b>submerge </b>? Comment <b>lutter contre la fatigue mentale ? </b></p>\n<h2>Qu’est-ce que la fatigue mentale ? </h2>\n<p>Voyons ici de plus près ce que veut dire la fatigue mentale. Vous verrez ainsi si vous vous reconnaissez dans cette description.</p>\n<h3>Un sentiment de blocage</h3>\n<p>La fatigue mentale peut se définir comme un épuisement général et une impression d’être bloqué, de ne plus pouvoir réaliser les tâches habituelles. Il s’agit d’une sorte de paralysie, de figeage invisible. C’est vraiment une sensation très étrange, et très inquiétante, surtout. J’ai déjà vécu cet état une fois. Lors d’un moment de ma vie où j’étais littéralement submergée par mes angoisses, mais aussi, par beaucoup de changements assez négatifs. Je devais faire mon ménage de la semaine habituel. J’avais réussi, mais avec beaucoup plus de lenteur et surtout, chaque tâche me demandait un énorme effort, comme s’il s’agissait d’importants travaux physiques. J’étais donc épuisée, mentalement comme physiquement. J’avais l’impression que mon cerveau « buggait » et devais ainsi sacrément me bouger pour réaliser une simple tâche. </p>\n<h3>Un manque d’énergie le matin, mais pas le soir </h3>\n<p>Afin de savoir si vous souffrez de fatigue mentale, il n’y a qu’à analyser comment vous vous sentez au réveil. En général, vous vous sentez extrêmement épuisée, même si vous avez dormi comme une masse. Se réveiller avec une forme de lassitude dès le matin peut donc vous mettre la puce à l’oreille. Par contre, cet épuisement va s’estomper au fur et à mesure de la journée et vous pouvez alors vous sentir beaucoup moins fatigué le soir, voire même en pleine forme. Illogique, n’est-ce pas ? Pourtant, c’est bien ce qui caractérise la fatigue mentale et il y a une raison à ce phénomène.</p>\n<p>En effet, se sentir mal le matin s’apparente au fait de se penser incapable de surmonter la journée qui s’annonce, de par une trop faible énergie. C’est, en réalité, une peur de l’inconnu. Tandis que le soir, la journée est terminée. La personne a plus l’impression d’être dans le connu et peut enfin se relaxer. Car au coucher du soleil, la société n’attend plus rien d’elle. En tout cas, c’est personnellement ainsi que je le vivais.</p>\n<p>Cette fatigue résulte surtout d’une énergie très basse. Ce trouble reflète donc en général des pensées beaucoup trop présentes et négatives, provenant, habituellement, d’une déprime déjà bien installée voire même, d’une dépression masquée.</p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img fetchpriority=\"high\" decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h3>Fatigue mentale ou physique ?</h3>\n<p>Bien qu’en étant atteint d’asthénie vous pouvez également être fatigué physiquement, les deux restent tout de même différents. La fatigue physique survient, bien souvent, après une journée de travail fatigante et surtout, pour ceux exerçant des métiers plus physiques. Elle peut en outre survenir lors d’une activité physique, comme le sport, mais aussi en cas de stress passager, comme se sentir épuisé après avoir passé un examen. Et la solution contre la fatigue physique, c’est tout simplement un sommeil réparateur. Le lendemain, la personne est donc de nouveau en forme. Au contraire, le repos ne marche pas du tout sur l’épuisement mental.</p>\n<h3>Fatigue mentale ou intellectuelle ?</h3>\n<p>Ces deux-là peuvent en effet se ressembler, de par certains symptômes similaires tels que des troubles de l’appétit, des problèmes de concentration ou de mémoire. Cependant, comme la fatigue physique, la fatigue intellectuelle disparaît au repos. Elle survient, par exemple, si un étudiant a étudié toute la journée et toute la soirée. Il peut commencer à ressentir tous ces symptômes et peut également avoir l’impression d’avoir perdu toutes les connaissances qu’il venait d’acquérir. Il s’agit d’une sorte de black-out, de blanc. Fort heureusement pour lui, il recouvrera toutes ses capacités après une bonne nuit de sommeil, contrairement à la fatigue mentale.</p>\n<h2>Les symptômes de la fatigue nerveuse </h2>\n<p>Voyons donc maintenant quels symptômes peuvent ressentir les personnes atteintes de fatigue mentale.</p>\n<h3>Symptômes physiques</h3>\n<p>–<b> </b>Maux de tête voire migraines, très souvent dus à l’inquiétude, à l’angoisse ;</p>\n<p>– Vertiges ;  </p>\n<p>– Diarrhée ou constipation (tout dépend des personnes) ;</p>\n<p>– Mauvaise digestion <b>;</b></p>\n<p>–<b> </b>Mal-être diffus provoquant des douleurs musculaires dues à la tension physique, comme les maux de dos ; </p>\n<p>– Moins bon système immunitaire entraînant plus de maladies comme les rhumes ; </p>\n<p>– Gros épuisement physique. Même si la fatigue est plus déclenchée par l’émotionnel, la sensation de ne plus avoir de force physique est tout de même présente. Les émotions et le corps sont, de toute manière, liés.</p>\n<h3>Symptômes émotionnels </h3>\n<p>– Sentiment de culpabilité, surtout dû au regard des autres, lesquels peuvent ne pas comprendre cette fatigue et sous-entendre à la personne que tout est dans sa tête. L’individu peut donc se croire faible et culpabilise de ne pas réussir à éprouver autant de vitalité que ses semblables ; </p>\n<p>– Irritabilité et susceptibilité dues, également, à l’incompréhension d’autrui ;</p>\n<p>– Problèmes alimentaires, comme le fait d’avoir l’appétit coupé ou, au contraire, de se ruer sur la nourriture. Tout dépend de la physiologie des personnes ; </p>\n<p>– Somnolence, de par un sommeil non réparateur et d’un trop grand manque d’énergie du fait de ruminations trop importantes ;</p>\n<p>– Troubles du sommeil pouvant conduire à l’insomnie. Bien souvent, la personne s’endort comme une masse, mais se réveille vers 4 h du matin avec de l’anxiété matinale. Et le fait de ne plus se rendormir ensuite, bien qu’elle ait dormi la première partie de la nuit, produira le même effet qu’une nuit blanche. Ce phénomène a d’ailleurs été prouvé scientifiquement ;</p>\n<p>– Troubles de la concentration suite à de trop grandes angoisses ;</p>\n<p>– Dépression ou burn-out si cette fatigue mentale n’est pas traitée.</p>\n<img decoding=\"async\" width=\"480\" height=\"640\" src=\"/storage/blog-images/Fatigue-nerveuse.jpg\" alt=\"Fatigue psychique\" title=\"Fatigue-nerveuse\">\n<h2>Les causes de la fatigue psychique  </h2>\n<p>Voyons également quelles peuvent être les causes de la fatigue mentale.</p>\n<h3>Le surmenage </h3>\n<p>La cause première et la plus basique est la sensation de se sentir submergé de deux façons. Soit par le fait d’avoir beaucoup trop de tâches à accomplir, soit du fait de trop grandes angoisses. Et nous savons bien que l’angoisse mange considérablement l’énergie et épuise rapidement l’individu. Il peut également y avoir trop de ruminations de colère, de rancœur, de débordement d’émotions négatives. Dans tous les cas, l’esprit se sent submergé. Voilà pourquoi la fatigue mentale apparaît.</p>\n<h3>Un événement émotionnel éprouvant </h3>\n<p>Lorsque vous subissez un événement très négatif pour vous, tel que, par exemple, un divorce, un décès, un licenciement, etc., vous penserez forcément plus négativement. Et le fait de continuer à le faire sans cesse devient un cercle vicieux ruminatif et par conséquent, vous fatiguez votre cerveau et donc, votre mental.</p>\n<h3>Un stress répété</h3>\n<p>Le fait d’éprouver un stress continuel, comme, par exemple, une immense pression au travail et ce, tous les jours vous fera forcément ressentir plus de fatigue et de négativité. Et rester sous tension de la sorte sur le long terme peut dangereusement vous mener à la fatigue mentale.</p>\n<h3>Un manque d’estime de soi</h3>\n<p>Un manque d’estime de confiance en soi reste, pour moi, la racine de tout trouble. Et notamment des troubles anxieux, lesquels peuvent mener facilement à la fatigue émotionnelle.</p>\n<h3>L’hypersensibilité</h3>\n<p>Je vous invite à aller consulter mon <a href=\"/hypersensibilite\" target=\"_blank\" rel=\"noopener\" title=\"Hypersensibilité\">article sur l’hypersensibilité</a> afin d’avoir plus d’informations à ce sujet. Personnellement, je pense que tout hypersensible est avant tout un être hyper blessé. Si vous êtes vous-même hypersensible, posez-vous la question suivante : rappelez-vous des premiers souvenirs que vous aviez de vous étant tout petit. Étiez-vous déjà hypersensible ? En général, la réponse est non. Car la sensibilité exacerbée survient surtout au fil du temps, par rapport au parcours de l’individu et des blessures plus ou moins importantes qu’il a pu ressentir.</p>\n<h3>Une mauvaise hygiène de vie </h3>\n<p>Consommer un stimulant, comme l’alcool, le tabac ou la caféine ne peut qu’exciter votre mental. De même que de se trouver dans un environnement trop lumineux en soirée, ce qui ne facilitera pas du tout le sommeil. Idem pour le fait de manger trop lourdement le soir, puisque l’estomac éprouvera des difficultés de digestion et donc, votre sommeil risque également de s’en trouver perturbé. Et c’est justement avec un sommeil perturbé que peut survenir un flot de pensées négatives. Et forcément, un mauvais sommeil a des conséquences néfastes, sur la journée du lendemain et sur le long terme.</p>\n<h3>Un environnement qui ne vous convient plus </h3>\n<p>Lorsque vous vivez continuellement dans un environnement qui ne vous fait plus vibrer, penser positivement va s’avérer de plus en plus compliqué. Par exemple, si vous allez tous les jours à votre travail sans en comprendre le sens et en vous ennuyant, il est fort possible qu’à la longue, une grande fatigue mentale s’installe.</p>\n<h3>Ne pas écouter ses besoins </h3>\n<p>Si vous n’écoutez pas ce qui vous fait vibrer, à cause de la peur : </p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">Du manque (manque d’argent si vous voulez quitter votre travail) ;</li>\n<li aria-level=\"1\">Du regard des autres, de les décevoir (vous n’osez pas refuser d’aller à une soirée) ; </li>\n<li aria-level=\"1\">De ne pas appartenir à la norme sociale,</li>\n</ul>\n<p> </p>\n<p>Forcément, vous pratiquerez des activités qui ne vous intéresseront pas. Vous ne serez pas véritablement vous, vous jouerez alors un rôle. Et sur le long terme, ne pas oser vous montrer tel que vous êtes ne pourra que vous mener vers une vie moyenne et donc, assez terne. Par conséquent, vous pourrez commencer à déprimer inconsciemment et à ressentir de la fatigue mentale.</p>\n<h3>Des valeurs incompatibles</h3>\n<p>Nous avons tous des valeurs. Cependant et sans en avoir conscience, certaines de nos valeurs peuvent demeurer incompatibles entre elles, de par leur opposition naturelle. </p>\n<p>Un exemple pour apparaître plus claire. Vous avez comme valeur principale la liberté. Vous voulez vous émanciper du salariat, devenir entrepreneur, demeurer libre et voler de vos propres ailes. Par contre, vous avez également comme valeur prédominante la sécurité. Vous aimez vivre dans votre bulle, avec votre mari (ou femme) et vos enfants. Vous avez vos petites habitudes, vos petits plaisirs, votre routine, etc. Mais vous comprenez bien que ces deux valeurs apparaissent incompatibles entre elles, puisque la liberté représente tout le contraire de la sécurité. En effet, qui dit liberté, dit prise de risques, adaptation constante au changement, existence mouvementée, débrouillardise, etc. La liberté vous pousse complètement à sortir de votre zone de confort. </p>\n<p>De ce fait, il va falloir choisir entre les deux. L’idéal, bien évidemment, étant de vous émanciper et d’évoluer dans votre vie, la liberté reste la valeur à privilégier. Par conséquent, vous allez devoir laisser tomber la sécurité et ainsi, changer de manière certaine votre vie. Changement qui risque d’apparaître très inconfortable au début, mais essentiel pour votre évolution.</p>\n<p>Voilà pourquoi vous apparaissez fréquemment indécis si vous êtes en proie à deux valeurs opposées. Donc, dans ces moments de dilemme et d’indécision, essayez de voir si vous n’avez pas deux valeurs qui s’opposent.</p>\n<h2>La fatigue mentale dans certaines maladies </h2>\n<p>La fatigue mentale peut provenir de certaines maladies. Donc, vérifiez si vous pouvez vous sentir concerné par ce fait. Par exemple, certaines maladies hormonales, comme les affections thyroïdiennes et surtout, l’hypothyroïdie, peuvent provoquer cette sensation d’épuisement intense. </p>\n<p>Vérifiez également que vous n’êtes pas atteint d’apnée du sommeil. Effectivement, du fait des ronflements nocturnes et des troubles respiratoires que ce trouble provoque dans la nuit, le sommeil ne peut être qu’agité. Par conséquent, la somnolence peut apparaître au cours de la journée. N’hésitez donc pas à aller vous renseigner à ce sujet. </p>\n<h2>Comment lutter contre la fatigue mentale ? </h2>\n<p>Afin de vous débarrasser de votre fatigue nerveuse, vous n’aurez d’autre choix que de changer votre façon de vivre. Voici des clés qui vous permettront de retrouver votre énergie.</p>\n<h3>Aller consulter un professionnel de la santé</h3>\n<p>Vous pouvez déjà envisager une thérapie, telle que la TCC. Je vous invite à aller consulter mon <a href=\"/psychotherapie-et-psychanalyse\" target=\"_blank\" rel=\"noopener\" title=\"Psychothérapie et psychanalyse\">article</a> à ce sujet pour plus d’informations. En effet, vous faire aider par un professionnel de la santé vous aidera à comprendre l’origine de vos troubles et surtout, à chercher des solutions pour aller mieux. Et si votre fatigue psychique est vraiment trop intense, vous pouvez également vous faire prescrire des médicaments, tels que des antidépresseurs et/ou anxiolytiques. Ces traitements vous serviront de béquille en attendant de retrouver un minimum d’énergie pour agir.</p>\n<h3>Changer sa perception de l’existence </h3>\n<p>Lorsque vous souffrez de cette fatigue intense, vous avez tendance à penser très négativement. Et c’est justement cette négativité qui vous provoque cet épuisement. Donc, même si c’est difficile, apprenez à changer votre perception de l’existence, à la voir plus positivement ou en tout cas, de manière plus réaliste. Mais surtout, ne désespérez pas. Cette fatigue peut arriver à n’importe qui, car tout le monde peut vivre des moments difficiles dans sa vie. J’ai également déjà ressenti cette fatigue. Donc, même si vous dramatisez et n’en voyez pas le bout, dites-vous bien que vous ne pouvez pas rester dans cet état toute votre vie. Elle est forcément passagère. </p>\n<h3>Trouver un but </h3>\n<p>Ce sont vos ruminations qui vous provoquent cet épuisement. Et le meilleur moyen de lutter contre les elles, c’est bien l’action. Pour vous aider à agir, rien de tel que vous trouver un but. But qui vous donnera l’envie de vous lever tous les matins, et ce, avec une grande énergie et motivation pour le reste de la journée à passer. Il peut s’agir de devenir entrepreneur, vous inscrire à une association pour rendre service aux autres, suivre un cours de chant, etc. il n’existe aucun objectif supérieur à un autre et n’ayez pas peur de voir grand ! </p>\n<h3>Soigner sa posture </h3>\n<p>Souvent, une personne manquant cruellement de confiance en elle se reconnaîtra facilement par certaines postures. Par exemple, un regard fuyant, un dos voûté, des bras ou des jambes croisés, etc. en réalité, le fait de se tenir de la sorte renforce ce sentiment de manque de confiance en soi. </p>\n<p>Par conséquent, si vous changez votre posture, il y a de fortes chances que votre état émotionnel suive ce changement. De ce fait, dès que vous prenez conscience d’une mauvaise posture, corrigez-la. Redressez-vous, marchez d’un pas déterminé, souriez, regardez votre interlocuteur dans vos yeux, etc. Les postures que vous avez sont loin d’être anodines, faites donc très attention à la manière dont vous vous tenez. </p>\n<img loading=\"lazy\" decoding=\"async\" width=\"480\" height=\"720\" src=\"/storage/blog-images/Epuisement.jpg\" alt=\"Asthenie\" title=\"Epuisement\">\n<h3>Éviter le surmenage </h3>\n<p>Se sentir épuisé psychologiquement provient très fréquemment d’une sensation de surmenage. Donc, quand vous vous sentez débordé, il y a déjà lieu de prioriser vos tâches, de la plus importante pour vous à la moins essentielle. Pour votre santé mentale, vous êtes obligé de le faire. </p>\n<p>Ensuite, parmi ces tâches, voyez celles que vous pouvez déléguer, parce qu’il y en a toujours. Cependant, si vous êtes perfectionniste, vous aurez énormément de mal à le faire. Car vous souhaitez que les choses soient réalisées exactement comme vous le désirez et aussi bien que vous. Sauf que les autres n’accomplissent pas forcément les choses comme vous le voulez ou aussi bien que vous. Du moins, c’est ce que vous croyez. Mais pour votre bien-être, il vous faut absolument réussir à déléguer. Vous verrez, au début, vous allez ressentir une forte gêne. Mais vous constaterez également que la sensation de légèreté que vous ressentirez en n’étant plus surmené primera bien plus que la contrariété d’avoir délégué. Je peux vous le dire, car je me comportais ainsi avant. Donc, pour votre bien, apprenez à déléguer. </p>\n<h3>Profiter de la nature</h3>\n<p>Plus besoin de prouver que la nature a un impact considérable sur le bien-être d’un individu. N’hésitez donc pas à vous trouver le plus souvent possible en contact avec elle. Si vous avez un jardin, vous pouvez vous y promener pieds nus. Profitez au maximum du soleil, lequel apporte naturellement pour votre organisme de la vitamine D. Évitez aussi de rester proche des sources électriques et surtout, lorsque vous dormez. </p>\n<h3>Prendre des vitamines </h3>\n<p>En cas de coup de fatigue et de manque de tonus, vous pouvez vous aider de vitamines et de compléments alimentaires. Bon nombre d’individus en prennent d’ailleurs en hiver, lorsque la baisse de luminosité, le froid et la fin des vacances apparaissent. Le magnésium, notamment, peut vous permettre de retrouver de l’énergie. N’hésitez donc pas à aller vous renseigner sur les vitamines qui pourraient vous correspondre.</p>\n<h3>S’intéresser aux remèdes naturels</h3>\n<p>Pour vous aider à retrouver la sérénité, vous pouvez également vous intéresser aux remèdes naturels via les plantes, comme l’homéopathie. Certaines personnes utilisent les fleurs de BACH. Il en existe pour bon nombre de domaines et vous pouvez même les combiner entre elles afin d’en augmenter les effets. N’hésitez pas à aller vous renseigner à ce sujet. </p>\n<p>Et à un niveau plus puissant, il existe aussi les huiles essentielles. Idem, vous pouvez vous informer là-dessus. Certaines huiles peuvent s’ingurgiter, d’autres se diffusent via un diffuseur, d’autres peuvent se mettre sur l’oreiller, sur le corps, etc. chaque huile possède des vertus particulières. Il existe même des roll-ons anti-stress que vous pouvez, par exemple, appliquer sur les poignets quand vous le souhaitez. Ainsi, vous pouvez les sentir afin de vous apaiser dès que l’envie vous en prendra.</p>\n<h3>S’intéresser aux médecines alternatives</h3>\n<p>Le manque d’énergie provient bien souvent d’un mental survolté, ce qui a, à la longue, des répercussions sur le corps, pouvant lui provoquer des blocages. Ce qui peut réellement faire la différence dans votre vie, c’est de tenter certaines médecines parallèles, lesquelles peuvent vraiment s’avérer être un complément extraordinaire pour votre bien-être. Vous pouvez essayer l’acupuncture, l’Ortho-Bionomy, la somatothérapie, la kinésiologie, la microkinésithérapie, la fasciathérapie, etc. Je vous invite à aller vous renseigner sur ces pratiques alternatives. </p>\n<h3>Augmenter son estime de soi </h3>\n<p>Tout trouble provient, avant tout, d’un manque de confiance et d’estime de soi. Il y a donc lieu de retrouver votre confiance et votre estime de vous voire même, de les découvrir. En effet, vous n’avez peut-être jamais appris à vous aimer et à avoir confiance en vous. Vous trouverez plus d’informations à ce sujet dans cet <a href=\"/confiance-et-estime-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Confiance et estime de soi\">article</a>.</p>\n<h3>Bien dormir </h3>\n<p>Vous entendez souvent qu’il est bon de garder un rythme de sommeil régulier, avec 8 heures de sommeil. Je suis d’accord pour le rythme, car, quand vous êtes trop décalé, il y a de grandes chances que vous ressentez plus d’anxiété. Rien qu’une heure de décalage par rapport à d’habitude peut perturber votre métabolisme. C’est pourquoi il est conseillé de garder le même rythme le week-end, même si c’est difficile. La semaine, par contre, ce n’est pas toujours possible si vous avez un travail avec des horaires changeants. Faites donc comme vous pouvez.</p>\n<p>Cependant, je suis moins d’accord avec les 8 heures de sommeil, car pour moi, chaque personne est différente. Je connais de grands dormeurs ayant besoin de plus de 10 heures de sommeil. Je connais aussi de petits dormeurs, qui ne dorment que 4 heures par nuit, et ce, sans que leur métabolisme en soit, à la longue, affecté. Pour le coup, il va falloir vous écouter afin de savoir quel nombre d’heures de sommeil vous correspond. Réalisez des tests.</p>\n<p>Vous pouvez faire quelques siestes, mais essayez de ne pas dépasser 15/30 minutes, au risque de ne plus dormir le soir. Mais, en réalité, quelles que soient vos heures de sommeil, le principal reste de bien dormir, de manière profonde. Car une personne qui rumine ne dort que légèrement, c’est pourquoi elle a l’impression de rêver beaucoup plus. Et pour retrouver un sommeil profond, il faut se sentir bien dans sa tête.</p>\n<p>Les plus grands sages disent d’ailleurs qu’ils dorment très peu, car leur mental demeurant toujours en repos, ils n’éprouvent quasiment pas besoin de se reposer. </p>\n<h3>Pratiquer des techniques de relaxation </h3>\n<p>Bien évidemment, pour surmonter votre fatigue mentale, il va falloir apprendre à vous relaxer. Vous pouvez pratiquer plusieurs techniques pour y arriver, comme la méditation, le yoga, la sophrologie… et surtout, apprendre à bien respirer. En effet, la respiration demeure pour le bon fonctionnement de votre organisme. C’est elle qui permet de le réguler et donc, de calmer votre esprit. N’hésitez pas à aller consulter mon <a href=\"/respiration\" target=\"_blank\" rel=\"noopener\" title=\"Respiration\">article</a> à ce sujet. </p>\n<p>Personnellement, pour bien respirer, je pratique ce que l’on nomme la cohérence cardiaque. Et pour m’y aider, j’utilise un petit appareil nommé Zenspire, lequel, grâce à sa lumière et à sa vibration, m’aide à réguler ma respiration afin de la rendre efficace et profonde. Si vous êtes intéressé par ce produit et que vous souhaitez passer commande, sachez que vous bénéficierez d’une remise de 10 % en utilisant le code JL0620. Pour en profiter, c’est juste ci-dessous :</p>\n<p>Par contre, certaines méthodes, telles que la méditation ou le kundalini yoga, peuvent être trop puissantes pour vous à l’heure actuelle si vous souffrez de fatigue mentale. Vous risquez, en effet, de vous sentir encore plus mal après avoir réalisé ces techniques. Puisque vos pensées ont formé une tornade, trop regarder à l’intérieur de vous risque d’être très difficile à vivre. Je vous conseille donc de commencer par des pratiques plus douces, comme le hatha-yoga, par exemple, pour, déjà, apprendre à être plus calme. </p>\n<h3>Faire du sport </h3>\n<p>Je pense que vous entendez bien assez souvent un peu partout que la pratique d’une activité physique apparaît primordiale pour votre bien-être physique et mental. Le sport, en effet, stimule la production d’endorphines, hormones soulageant l’anxiété et la dépression. De plus, en pratiquant un sport, vous ressentirez également, juste après la séance, de la fatigue, mais qui n’a rien à voir avec votre épuisement psychique. Pour le coup, il s’agira de bonne fatigue. 3 séances de sport par semaine sont conseillées.</p>\n<p>Sinon, n’hésitez pas à marcher. 30 minutes par jour serait vraiment l’idéal. La marche reste une solution extraordinaire pour soulager la fatigue nerveuse. En effet, le fait de marcher vous permet de prendre l’air, de vous aérer, de regarder les paysages qui vous entourent et donc, de vous concentrer sur autre chose.</p>\n<h3>Manger sainement </h3>\n<p>Ce qui peut grandement vous aider également, c’est d’opter pour une alimentation saine. On dit toujours que l’on se respecte par rapport à ce que l’on ingurgite. C’est-à-dire que si vous ne vous aimez pas, vous vous nourrirez mal. Et si vous vous estimez plus, vous mangerez plus sain. Puisque vous savez que votre corps en a besoin. Bien sûr, mangez des fruits et légumes le plus souvent possible. Vous avez également le droit de vous faire plaisir de temps à autre, car sinon, vous ne tiendrez pas sur le long terme. Renseignez-vous sur le fait de bien manger et d’en plus, y prendre du plaisir ! </p>\n<h3>Faire preuve de compassion et non d’empathie </h3>\n<p>Ce paragraphe concerne surtout les personnes hypersensibles, qui, ayant déjà du mal à gérer leurs émotions, se prennent de plein fouet les émotions négatives de ses semblables. Car elles font preuve d’empathie et non de compassion. C’est-à-dire qu’elles se mettent bien trop à la place de l’autre, ce qui a pour conséquence de lui faire ressentir quasiment les mêmes émotions que lui. La personne est donc devenue une éponge émotionnelle, ce qui est très dommageable. Mais, savez-vous que ce n’est pas une fatalité et que vous pouvez transformer votre empathie en compassion ? </p>\n<p>En effet, compassion signifie prendre en considération la souffrance de l’autre, ne pas le lâcher, mais ne pas prendre la responsabilité de son mal-être. Lui laisser sa tristesse et surtout, ne pas la lui prendre. Il convient donc de prendre de la distance sur les malheurs des autres. </p>\n<p> </p>\n<p>J’espère que cet article pourra vous aider à <b>lutter contre la fatigue mentale.</b> Je vous souhaite de retrouver une belle énergie ! </p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'Lutter Contre la Fatigue Mentale pour Retrouver le Bien-être','La fatigue mentale, considérée comme le mal des temps modernes, peut même surpasser l’épuisement physique. Comment lutter contre la fatigue mentale ?','https://vivre-pleinement.fr/fatigue-mentale/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/fatigue-mentale\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/fatigue-mentale\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Lutter Contre la Fatigue Mentale pour Retrouver le Bien-\\u00eatre\",\"datePublished\":\"2021-01-24T10:37:08+00:00\",\"dateModified\":\"2024-02-13T17:09:54+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/fatigue-mentale\\/\"},\"wordCount\":8510,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/fatigue-mentale\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2021\\/01\\/Lutter-fatigue-mentale.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/fatigue-mentale\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/fatigue-mentale\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/fatigue-mentale\\/\",\"name\":\"Lutter Contre la Fatigue Mentale pour Retrouver le Bien-\\u00eatre\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/fatigue-mentale\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/fatigue-mentale\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2021\\/01\\/Lutter-fatigue-mentale.jpg\",\"datePublished\":\"2021-01-24T10:37:08+00:00\",\"dateModified\":\"2024-02-13T17:09:54+00:00\",\"description\":\"La fatigue mentale, consid\\u00e9r\\u00e9e comme le mal des temps modernes, peut m\\u00eame surpasser l\\u2019\\u00e9puisement physique. Comment lutter contre la fatigue mentale\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/fatigue-mentale\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/fatigue-mentale\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/fatigue-mentale\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2021\\/01\\/Lutter-fatigue-mentale.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2021\\/01\\/Lutter-fatigue-mentale.jpg\",\"width\":640,\"height\":427,\"caption\":\"Comment lutter contre la fatigue mentale ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/fatigue-mentale\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Lutter Contre la Fatigue Mentale pour Retrouver le Bien-\\u00eatre\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2021-01-24 10:37:08',NULL,'2026-05-24 19:19:44','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (28,'Stopper les Ruminations Mentales pour Reprendre le Contrôle de sa Vie','ruminations','Tout le monde peut se faire du souci de temps à autre dans sa vie. Le problème survient lorsque ces soucis deviennent pathologiques et vraiment invalidants : il s’agit des ruminations. Les personnes souffrant de ruminations sévères ont d’ailleurs souvent des troubles anxieux, lesquels peuvent mener, au fur et à mesure, à la dépression. Vous vous trouvez inférieur aux autres et pensez sans cesse à vos prétendues faiblesses. Vous avez vécu un conflit, lequel s’est arrangé, mais vous repassez tout de même la scène en boucle. Vous êtes en proie à des préoccupations irrationnelles et n’arrivez pas à les arrêter. Elles deviennent de plus en plus catastrophiques. Les ruminations vous gâchent la vie ? Comment stopper les ruminations mentales ? \n','<p>Tout le monde peut se faire du <b>souci </b>de temps à autre dans sa vie. Le problème survient lorsque ces soucis deviennent <b>pathologiques </b>et vraiment <b>invalidants </b>: il s’agit des <b>ruminations</b>. Les personnes souffrant de ruminations <b>sévères </b>ont d’ailleurs souvent des <b>troubles anxieux</b>, lesquels peuvent mener, au fur et à mesure, à la <b>dépression</b>. Vous vous trouvez <b>inférieur </b>aux autres et pensez sans cesse à vos prétendues <b>faiblesses</b>. Vous avez vécu un <b>conflit</b>, lequel s’est <b>arrangé, </b>mais vous repassez tout de même la scène en <b>boucle</b>. Vous êtes en proie à des préoccupations <b>irrationnelles </b>et n’arrivez pas à les <b>arrêter</b>. Elles deviennent de plus en plus <b>catastrophiques</b>. Les ruminations vous <b>gâchent </b>la vie ? Comment <b>stopper les ruminations mentales ? </b></p>\n<h2>Qu’est-ce que la rumination mentale ? </h2>\n<p>Les ruminations sont des pensées envahissantes, pouvant se décrire comme des plaintes mentales répétitives et passives. Souvent, ces pensées tournent en boucle et peuvent durer plusieurs heures. Les personnes atteintes de ce trouble n’arrivent pas à les arrêter. En outre, la tendance à ruminer ne sert… à rien ! Elle ne fait, en effet, que faire perdre un temps considérable aux individus, et surtout, les entraîne dans un schéma de pensées vraiment néfaste pour eux sur le long terme.</p>\n<p>Ces ruminations peuvent porter sur des événements passés. La personne peut en effet ressasser ses blessures d’enfance, ou faire une obsession sur un conflit s’étant produit avec un individu. Les ruminations demeurent donc différentes de l’inquiétude que tout un chacun expérimente dans la vie. L’inquiétude est surtout portée sur un événement à venir. Cependant, les inquiétudes excessives peuvent également se transformer en ruminations anxieuses.</p>\n<p>Du coup, les personnes en proie à ce problème apparaissent bien souvent agressives et en colère. Elles reprochent énormément de choses aux autres et apparaissent très sévères dans leurs jugements. Mais, en réalité, ces personnes sont surtout beaucoup plus dures avec elles-mêmes… </p>\n<h2>Les personnes sujettes aux pensées obsédantes </h2>\n<p>Bien souvent, les personnes en proie aux ruminations ont un profil particulier. Ce sont, la plupart du temps, des individus pessimistes et atteints de névrose obsessionnelle. Ils peuvent souffrir des troubles suivants : </p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">État dépressif ;</li>\n<li aria-level=\"1\">TAG (trouble d’anxiété généralisée) ; </li>\n<li aria-level=\"1\">TOC (troubles obsessionnels compulsifs) où nous retrouvons bien là le mécanisme de l’obsession. Les TOC sont, justement, considérés comme la névrose obsessionnelle ; </li>\n<li aria-level=\"1\">Trouble panique ; </li>\n<li aria-level=\"1\">Toutes autres phobies telles que, par exemple, la phobie sociale, la dysmorphobie, etc.</li>\n<li aria-level=\"1\">Troubles alimentaires tels qu’anorexie, boulimie, etc. les ruminations peuvent pousser certaines personnes à se jeter sur la nourriture tandis que pour d’autres, elles peuvent leur couper l’appétit ;</li>\n<li aria-level=\"1\">Addiction comme l’alcool<b>. </b>La personne peut être en proie à des ruminations anxieuses et boit pour se donner du courage. Elle peut en outre subir des ruminations du passé et boire pour oublier.</li>\n</ul>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img fetchpriority=\"high\" decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h2>Quelles sont les causes de la rumination mentale ? </h2>\n<p>Les individus souffrant des troubles ci-dessus sont souvent sujets aux ruminations. Je dirais même que c’est le fait de ruminer sans cesse qui entraîne ces troubles. Les personnes hypersensibles ont pareillement tendance à ruminer. Les individus étant atteints de ruminations utilisent aussi fréquemment le mécanisme de projection. C’est-à-dire que ce qu’ils interprètent de l’extérieur n’est généralement que le reflet de ce qui se passe à l’intérieur d’eux. Mais sinon, dans quels cas peuvent-elles également apparaître ? </p>\n<h3>La compulsion </h3>\n<p>Le fait de ruminer devient vraiment, à la longue, un besoin compulsif, et c’est là le piège. En effet, la personne pense que plus elle va ruminer, plus elle va s’approcher d’une solution, alors qu’il n’en est rien. Car plus elle rumine, plus de nombreuses pensées de plus en plus irrationnelles vont apparaître. Se faire des films deviendra naturel chez elle et elle ne sera donc plus capable de prendre du recul. En fait, ruminer est tout le contraire d’agir et ainsi, aucune solution ne peut être trouvée par ce biais. </p>\n<h3>Le besoin d’être rassuré tout le temps </h3>\n<p>Dans le cas de ruminations anxieuses récurrentes, la personne va tenter de se faire rassurer. Par ses proches, déjà, en leur posant 10 fois la même question. En effet, pratiquer de la sorte la rassure sur le coup, mais malheureusement, de manière très temporaire. C’est ainsi que la même question est reposée indéfiniment, de quoi, à la longue, lasser l’entourage. </p>\n<p>Elle va aussi essayer de se sécuriser via Internet en cas, par exemple, de symptôme physique apparu soudainement et perçu par elle comme anormal. Forcément, en tentant de se faire réconforter sur Internet, c’est encore pire ! Puisqu’Internet va parler du problème le plus bénin (bouton d’acné) au plus grave (cancer). Et étant donné qu’une personne anxieuse ne tolère absolument pas l’incertitude, elle va penser être atteinte d’un cancer. De là, le cercle vicieux apparaît. Elle va alors tenter de trouver de plus en plus d’articles pour contrer le seul article négatif qu’elle a vu, mais qu’elle retient cependant plus que les autres. Elle peut donc rester sur Internet pendant des heures, à la base, dans le but d’être soulagée. Mais malheureusement, cette attitude lui donnera tout l’effet inverse : une angoisse encore plus profonde, une grande perte de temps et aucune solution à son problème. </p>\n<h3>L’effondrement de certaines croyances </h3>\n<p>Nous avons tous des croyances. C’est ce qui fait, nous pouvons dire, notre personnalité. Cependant, certaines d’entre elles, si elles s’effondrent, peuvent déclencher les ruminations. </p>\n<p>Par exemple, si vous avez la croyance que le monde est juste, elle risquera, tôt ou tard, de vous poser problème. En effet, certaines personnes, bien qu’elles sachent plus ou moins que le monde apparaît cruel avec certaines personnes, trouvent qu’il ne l’est pas vraiment à leur égard. C’est le fameux principe de croire que « ça n’arrive qu’aux autres ». Par contre, lorsqu’un malheur surgit, leur croyance d’un monde juste envers elles s’effondre, et de là peuvent apparaître de nombreuses ruminations pessimistes.</p>\n<p>Idem pour les individus pensant que le monde a du sens. C’est-à-dire qu’ils pensent fermement que s’ils restent toujours sympathiques, font le bien, mangent sainement, etc.il ne leur arrivera rien de grave. Comme si le fait de respecter certaines règles les protégeait. C’est le principe du karma. Par contre, si une personne mange sans arrêt sainement et développe soudainement un cancer, imaginez comme il peut être difficile pour elle de voir sa croyance s’effondrer ! Ou imaginez le désarroi d’une personne faisant sans cesse le bien et se rendant compte qu’un individu méchant avec autrui réussit mieux dans l’existence qu’elle. Elle peut donc crier à l’injustice et devenir vraiment pessimiste sur le monde, les autres et la vie en général. </p>\n<h2>Les conséquences des pensées improductives </h2>\n<p>Nous avons vu plus haut que certains profils particuliers peuvent favoriser les ruminations. Mais une personne n’ayant pas tous ces troubles et commençant à ruminer de plus en plus peut en déclencher. Voyons quel retentissement un esprit tourmenté peut avoir sur votre bien-être : </p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">Le déclenchement de l’angoisse, mais aussi, une dépression, le mental ayant complètement pris le contrôle de l’individu, lequel n’arrive plus du tout à gérer ses émotions ; </li>\n<li aria-level=\"1\">Une baisse des défenses immunitaires pouvant provoquer des maladies. Il s’agit surtout de maladies cardiovasculaires et inflammatoires. C’est souvent le cas lorsque la personne ressent beaucoup de peur, de colère (ressentiment, rancœur, etc.) et de tristesse ; </li>\n<li aria-level=\"1\">Une accumulation de ruminations mentales qui mènera à de l’épuisement et à de la fatigue mentale ;</li>\n<li aria-level=\"1\">Une grande perte de confiance et d’estime de soi. La personne se sent incapable et reste passive ;  </li>\n<li aria-level=\"1\">Un manque de discernement. Avec certaines peurs irrationnelles, l’individu n’est plus en mesure d’analyser ce qui est grave et ce qui ne l’est pas ou n’est pas possible ;</li>\n<li aria-level=\"1\">Une altération des relations si l’individu devient vraiment difficile à vivre.</li>\n</ul>\n<h2>Les ressassements et le syndrome de stress post-traumatique </h2>\n<p>La rumination a donc d’énormes conséquences négatives sur la durée. Par contre, savez-vous qu’elle est parfois utile pour continuer à préserver sa santé mentale ? C’est le cas du syndrome de stress post-traumatique survenant lors d’événements extrêmes tels qu’être pris en otage, par exemple. En ruminant sans cesse ces événements après qu’ils aient eu lieu, c’est une manière pour le cerveau d’accepter que ces incidents soient arrivés afin de pouvoir tourner la page<b>. </b>Ces pensées récurrentes aspirent donc, pour ce trouble, à un objectif de guérison. Ce qui explique les flash-back et les cauchemars que les personnes souffrant de stress post-traumatique vivent souvent.    </p>\n<img decoding=\"async\" width=\"600\" height=\"750\" src=\"/storage/blog-images/Pensees-obsessionnelles.jpg\" alt=\"Ressassement \" title=\"Pensées-obsessionnelles\">\n<h2>Comment stopper les ruminations mentales ?  </h2>\n<p>Heureusement, vous pouvez vous libérer des ruminations. Voici quelques clés pour vous aider à y parvenir. </p>\n<h3>Se faire aider par un professionnel de la santé</h3>\n<p>Consulter un thérapeute et notamment, pratiquer une TCC (thérapie comportementale et cognitive) vous fera le plus grand bien. Car un professionnel pourra vous suggérer de nouvelles façons de voir la vie auxquelles vous n’auriez jamais pensé, étant trop focalisé sur le négatif. Le thérapeute vous donnera d’ailleurs des exercices concrets et pratiques qui vous permettront d’agir, tout le contraire, donc, des ruminations. </p>\n<p>Et si le besoin s’en fait sentir, il pourra vous prescrire un traitement médicamenteux, comme la prise d’antidépresseurs ou d’anxiolytiques. Ces médicaments vous serviront de béquille, le temps de retrouver en vous la force de passer à l’action.</p>\n<p>En revanche, je vous déconseille la psychanalyse. En effet, cette thérapie cherche à comprendre le pourquoi du comment, et à trop s’introspecter, ce qui, vous l’aurez compris, renforcera vos ruminations. Elle vous maintiendra dans la passivité en ne vous faisant pas prendre la responsabilité de vos problèmes et de ce fait, vous ne passerez toujours pas à l’action.</p>\n<p>Et puis, il convient parfois de lâcher prise. Si certains jours, vous ne vous sentez vraiment pas bien, ce malaise ne cache pas forcément un trouble profond. Quelquefois, il s’agit juste d’un manque de sommeil, d’un cycle hormonal, d’une journée un peu contrariante, etc. Donc, essayez de prendre du recul.</p>\n<p>N’hésitez pas non plus à vous tourner vers des médecines alternatives comme l’hypnose, par exemple. </p>\n<a href=\"https://hypnocaments.com?partnerid=YK5muYugzSoIWDbDWRgT-Q\" title=\"Seances d hypnose en ligne\"><img decoding=\"async\" src=\"https://hypnocaments.com/image/banner_1_750.png\" alt=\"seance hypnose mp3\"></a>\n<h3>Pratiquer des techniques de relaxation</h3>\n<p>Une personne qui pense constamment a besoin de se relaxer. Et il existe de nombreuses méthodes pour ce faire. </p>\n<p>Vous pouvez apprendre à détendre votre corps grâce à la méthode Jacobson. Cette méthode consiste à contracter puis relâcher chacun de vos muscles. C’est en les relâchant que vous ressentirez le bien-être de votre corps qui se détend. </p>\n<p>Ce qui vous aidera clairement également est la respiration, car en étant anxieux, vous respirez forcément mal. Si vous apprenez à respirer profondément dès que vous en avez la possibilité, vous serez de plus en plus détendu, ce qui, automatiquement, atténuera vos ruminations. N’hésitez donc pas à aller consulter mon <a href=\"/respiration\" target=\"_blank\" rel=\"noopener\" title=\"Respiration\">article</a> sur le sujet.</p>\n<p>Et pour apprendre à vraiment bien respirer, je vous conseille la cohérence cardiaque, méthode que je pratique personnellement.  Pour m’y aider, j’utilise un petit appareil nommé Zenspire. Celui-ci,<strong> </strong>grâce à ses vibrations et à sa lumière, me permet de respirer régulièrement, correctement et profondément. Si vous êtes intéressé par ce produit et souhaitez passer commande, vous pouvez d’ailleurs bénéficier d’une remise de 10 % grâce au code JL0620. C’est plutôt chouette, non ?</p>\n<p>Enfin, vous pouvez pratiquer des techniques comme la sophrologie, le yoga ou la méditation de pleine conscience. Vous apprendrez à laisser passer les pensées qui viennent à votre esprit. Les laisser passer représente tout le contraire d’un état ruminatif, lequel s’accroche aux pensées de manière obsessionnelle. Cette pratique vous aidera également à comprendre que vous n’êtes pas vos pensées et que les pensées ne demeurent que des pensées. Vous ne vous identifierez plus à elles.</p>\n<p>Par contre, en cas de ruminations trop sévères, la méditation n’est pas conseillée ou du moins, pas tout de suite. C’est le cas, par exemple, pour les personnes souffrant de stress post-traumatique. Le fait de méditer pourra leur faire apparaître trop de flashs désagréables et ainsi, empirer leur état. Il y a donc lieu d’y aller progressivement, en commençant par de la détente du corps et de la relaxation moins profonde. </p>\n<h3>Se relaxer avec des infusions</h3>\n<p>Même si elles ne réalisent pas de miracles, les infusions peuvent vous aider. Optez plutôt pour des infusions relaxantes, comme la camomille, la verveine, le tilleul, la valériane, la mélisse, la passiflore, etc. il y en a vraiment pour tous les goûts ! N’hésitez donc pas à vous apaiser grâce à elles.</p>\n<h3>Pratiquer la visualisation</h3>\n<p>Une personne atteinte de ruminations a, forcément, une trop grande activité mentale. Par conséquent, avec son imagination débordante, elle se fait souvent des films. Beaucoup d’images négatives et catastrophiques apparaissent donc dans son esprit. Si c’est votre cas, pourquoi ne pas effectuer tout l’inverse ? C’est-à-dire, vous servir de représentations mentales positives qui serviront dorénavant d’ancres lorsque vous ne vous sentirez pas bien. Vous pouvez, par exemple, vous imaginer dans un lieu où vous vous sentez extrêmement bien, qu’il soit réel ou fictif. Ou encore, vous voir à table, avec vos plats préférés, entouré de tous les gens que vous aimez. Cette méthode vous servira à rediriger votre attention vers des pensées plus bénéfiques, et donc, à casser le cycle de vos ruminations. </p>\n<p>La deuxième manière de visualiser et de vous imaginer, dans le futur, être la personne que vous souhaitez devenir, bien dans sa peau et libérée de toutes ses ruminations. Il faut vraiment que vous réalisiez cette visualisation comme si c’était déjà et que vous fassiez marcher vos 5 sens. Essayez de pratiquer cet exercice tous les jours. Au fur et à mesure, vous reconditionnerez petit à petit votre cerveau de façon extraordinaire, ce qui va réellement vous faire prendre le chemin que vous avez visualisé. </p>\n<h3>Changer ses croyances </h3>\n<p>Un individu souffrant de ruminations possède souvent, excusez-moi du terme, des croyances débilitantes. Ce terme ne veut bien évidemment pas dire qu’il est stupide. Il signifie juste que ses croyances le tirent vers le bas. Il faut donc qu’il puisse se défaire de l’idée qu’il est ainsi et qu’il n’y peut rien, que son tempérament est plus anxieux que les autres. Car c’est faux. Cependant, pour changer ce modèle cognitif qui ne lui apporte rien de bon, il doit modifier ses croyances. Remplacer celles qui le tirent vers le bas par d’autres qui le tirent vers le haut. Je vous laisse aller consulter mon <a href=\"/croyances\" target=\"_blank\" rel=\"noopener\" title=\"Croyances\">article</a> sur ce sujet pour plus de renseignements. </p>\n<h3>Se souvenir de ses réussites</h3>\n<p>Lorsque vous êtes en proie à des pensées envahissantes, il est facile de ne voir que le négatif et de ne vous concentrer que sur vos fragilités. Cependant, n’hésitez pas, dans un petit carnet, à noter toutes les réussites de votre vie. Et dès que vous en avez une nouvelle, notez-la également. Du coup, en agissant ainsi, quand vous aurez un coup de mou, vous pourrez relire votre liste pour vous rappeler que vous êtes capable de réaliser de belles choses. </p>\n<h3>Pratiquer la gratitude </h3>\n<p>Afin de vous libérer de vos idées négatives, rien de tel que de vous focaliser sur ce que vous avez de beau dans votre vie. Car vous remarquerez que, de manière générale, nous oublions ce qu’il y a de génial dans notre existence, puisque ces choses sont devenues une habitude. Sauf que si nous les perdons, c’est tout notre monde qui s’écroule. Donc, pour éviter d’en arriver là, apprenez à éprouver de la reconnaissance pour tout ce que vous avez. En plus, cette attitude vous permettra d’entretenir davantage toutes ces belles choses de votre existence. </p>\n<p>Pour vous y aider, vous pouvez tenir un petit journal de gratitude. Tous les jours, essayez de noter 10 choses pour lesquelles vous éprouvez de la gratitude. Il peut s’agir d’une chose très vaste, telle qu’avoir la possibilité de vivre dans un pays comme la France, qui reste tout de même très sécuritaire. Mais il peut également s’agir d’une chose plus personnelle comme votre mari, vos enfants, votre maison, votre travail, etc. ou d’événements minimes tels que regarder un chaton passer dans votre jardin, le soleil qui se lève ou se couche, etc. Réalisez cet exercice, le matin ou le soir, et ce, jusqu’à ce que vous commenciez à ressentir plus de positivité dans votre vie.</p>\n<h3>Accepter et ressentir ses émotions</h3>\n<p>Le domaine émotionnel reste difficile à gérer pour une personne souffrant de ruminations. Quand elle commence à trop penser, elle a tendance à vouloir refouler et chasser ses émotions. Cependant, le déni empire la situation et peut même, à la longue, provoquer des maladies. Ou alors, la personne se juge et ressent énormément de culpabilité à avoir ces pensées et à sombrer dedans sans avoir l’impression de pouvoir avoir la force de changer. Donc, lorsque vous ressentez une émotion négative qui vous déclenche des pensées négatives, apprenez déjà à l’accueillir, sans la réprimer et sans la juger. Juste l’accepter avec bienveillance. Il ne sert à rien, en effet, de rajouter des ruminations de culpabilité en plus des ruminations initiales ! </p>\n<p>Ensuite, analysez où se situe l’émotion dans votre corps. Si, par exemple, vous éprouvez de la peur, vous pouvez ressentir un mal de ventre, ou des tremblements à telle partie du corps, etc. Il est important de ne pas délaisser votre corps à ce moment en rendant votre émotion tangible. Puis, passez à l’étape de la distraction. </p>\n<img decoding=\"async\" width=\"600\" height=\"900\" src=\"/storage/blog-images/Pensees-improductives.jpg\" alt=\"Inquietude \" title=\"Pensées-improductives\">\n<h3>Se distraire </h3>\n<p>Lorsque vous sentez les ruminations arriver, c’est que vous avez l’esprit occupé et que vous ne vivez pas du tout le moment présent. Donc, à partir de ce moment et après avoir accueilli vos émotions avec bienveillance, vous pouvez vous dire mentalement, ou de vive voix, un grand STOP. Vous pouvez également vous dire que vous n’arriverez pas à trouver de solutions en ruminant, étant donné que vos ruminations n’ont pas de sens. Elles sont improductives. </p>\n<p>En général, l’évitement est déconseillé dans les troubles anxieux. Il est, en effet, conseillé d’affronter ses peurs. Sauf que là, plonger dans vos ruminations ne servira absolument à rien et empirera même votre situation. Donc, pensez à vous distraire dans ces moments. Il y a lieu d’arrêter ce que vous êtes en train d’accomplir pour casser le cercle vicieux des pensées négatives et de vous adonner à une autre activité. Vous pouvez changer de pièce, mettre de l’eau sur vos poignets, vous étirer, etc.</p>\n<h3>Trouver le besoin qui se cache derrière l’émotion</h3>\n<p>Une fois que vous apparaîtrez plus calme, vous pouvez commencer à réfléchir au pourquoi de vos ruminations, car avant, vous serez incapable de raisonner de manière rationnelle. Seulement émotionnelle. C’est-à-dire que vous pouvez essayer de comprendre le besoin qui se cache derrière votre émotion. En effet, lorsque vous ressentez une émotion en ruminant, c’est qu’un de vos besoins n’est plus comblé. Il y a donc lieu de retrouver ce besoin et bien évidemment, de le combler à nouveau. </p>\n<p>Par exemple, une personne vous a mal parlé par message, puis ne donne plus signe de vie. Vous ressassez cette scène sans arrêt, et ce, avec une grande colère. Dans ce cas-là, il peut y avoir le besoin de :</p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">Respect : cette personne m’a manqué de respect ; </li>\n<li aria-level=\"1\">Compréhension : mais pourquoi cet individu a agi de la sorte ? ;</li>\n<li aria-level=\"1\">D’équité : j’ai été blessé, cette personne doit également être blessée en retour. </li>\n</ul>\n<p> </p>\n<p>Ensuite, vous pouvez réfléchir à des actions à mettre en œuvre pour combler à nouveau ces besoins. Pour cet exemple, vous pouvez prendre attache avec cet individu en lui demandant pourquoi il s’est comporté ainsi et que cette façon de vous parler ne vous va pas du tout. Vous vous êtes senti rabaissé et très touché. En disant ce que vous avez sur le cœur, vos besoins seront à nouveau comblés. Vous éviterez la rancœur, laquelle, à la longue, ne fera de mal qu’à vous.</p>\n<h3>Apprendre à avoir confiance en soi et s’estimer</h3>\n<p>Pour éviter de sombrer dans des schémas négatifs, il est primordial d’apprendre à avoir confiance en vous et à vous estimer. Ainsi, vous vous sentirez capable d’aller mieux et de vous aimer comme vous êtes, c’est-à-dire avec vos forces et vos faiblesses. N’hésitez pas à aller consulter mon <a href=\"/confiance-et-estime-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Confiance et estime de soi\">article</a> sur ce sujet.</p>\n<h3>Changer sa perception grâce aux affirmations positives </h3>\n<p>Ce sont vos pensées négatives qui font apparaître les idées fixes. Et vous n’avez que très peu de contrôle sur vos émotions, puisqu’elles apparaissent sans que vous n’ayez rien demandé. D’ailleurs, voici pourquoi j’explique qu’il y a lieu d’accepter vos émotions afin de ne pas les empirer. Par contre, vous détenez du pouvoir sur la manière dont vous contrôlez vos pensées. Vous pouvez donc modifier vos pensées en apprenant à changer votre perception de la vie. </p>\n<p>Par exemple, vous vous dites : « cette personne n’a pas donné suite à mon message depuis deux jours, elle se fiche totalement de moi »<i>. </i>Et si vous vous disiez plutôt : « cette personne ne m’a pas encore répondu, mais elle est très occupée en ce moment, je sais qu’elle m’apprécie dont elle reviendra vers mois quand elle aura plus le temps de le faire. Elle a sa vie, elle aussi ». Entre la première pensée et la deuxième façon de percevoir la situation, les émotions seront loin d’être les mêmes ! Entraînez-vous donc à penser de manière bénéfique pour vous, et ce, dès que vous vous rendez compte que vous êtes en train de tomber à nouveau dans vos ruminations. </p>\n<h3>Améliorer ses relations sociales </h3>\n<p>Une personne rumine également beaucoup lorsqu’elle est seule, puisque si elle se change les idées en parlant avec quelqu’un, elle ne se concentre pas sur ses ruminations. Par conséquent, n’hésitez pas à vous entourer quand vous n’allez pas bien. Vous pouvez exprimer votre mal-être à vos proches ou vos peurs, mais comprenez bien que vos semblables ne sont pas vos éponges émotionnelles. Sachez que vos pensées et émotions négatives les impactent forcément. Donc, parlez-en, mais brièvement, et passez à un autre sujet afin de vous changer les idées et de ne pas les impacter. </p>\n<p>Et bien évidemment, si vous ressentez vraiment le besoin de parler de vos problèmes en profondeur, aller consulter un professionnel de la santé est préférable. En effet, c’est son métier et de plus, il possède des connaissances en la matière, connaissances que votre entourage n’a pas toujours pour vous aider pleinement. </p>\n<h3>Pratiquer un sport </h3>\n<p>Pour vous libérer de vos pensées parasites, rien de tel que la pratique d’une activité physique. En effet, il est bien connu que le sport libère des endorphines, les hormones du bien-être. Voilà pourquoi après un événement stressant ou une journée stressante, il est conseillé d’en faire. À vous de trouver le sport qui vous convient. </p>\n<h3>Pratiquer le lâcher-prise</h3>\n<p>Vos obsessions proviennent également du fait que vous souhaitez tout contrôler. Vous voulez être certain de comment se passera un événement futur, ou sûr de tel sentiment qu’a eu telle personne dans le passé, etc. Sauf qu’on ne contrôle absolument rien, à part nous-mêmes. Il y a donc lieu d’apprendre à lâcher-prise. Je vous invite à aller consulter mon <a href=\"/lacher-prise-et-acceptation\" target=\"_blank\" rel=\"noopener\" title=\"Lâcher-prise et acceptation\">article</a> à ce sujet. </p>\n<p>Une petite parenthèse pour les ruminations nocturnes qui peuvent provoquer une insomnie ou pour celles provenant très tôt le matin. En effet, le fait d’être tourmenté à ces moments est « normal ». Car la nuit, le corps sécrète plus de mélatonine, l’hormone du sommeil. Cependant, à ce moment, vous sécrétez beaucoup moins de sérotonine dans votre corps, l’hormone du bien-être. C’est pourquoi vos pensées nocturnes paraissent bien plus terrifiantes qu’en journée. </p>\n<p>Et pour ceux qui commencent à ruminer en se réveillant vers 4 h du matin, c’est un peu le même principe. Votre organisme produit un pic de cortisol vers cette période, laquelle hormone a pour objectif de vous réveiller progressivement. Cependant, elle est aussi produite en grande quantité par le corps lorsque vous stressez ! De ce fait et même si c’est difficile, il ne faut vraiment pas que vous ne donniez d’importance à vos ruminations nocturnes ou très matinales. Elles apparaissent bien trop irrationnelles.  </p>\n<h3>Lire </h3>\n<p>Afin de vous libérer de vos pensées obsessionnelles, vous pouvez également lire. Bien entendu, des livres vous apportant des émotions positives ! Pour ce faire, je vous conseille les livres de développement personnel. Vous vous sentirez tellement bien après la lecture d’un tel livre ! Et si vous pouviez en plus mettre en application tout ce que vous apprenez dedans, vous n’imaginez même pas comment ce livre peut vous changer ! </p>\n<p>En effet, tout livre de développement personnel, si vous mettez ses conseils en pratique, provoquera un changement positif radical chez vous. Il n’y a pas de meilleur ouvrage que d’autres. Par contre, il y en a peut-être un qui vous correspond plus. </p>\n<h3>Écrire une lettre </h3>\n<p>Un exercice que j’ai récemment découvert est d’écrire lorsque les ruminations mentales apparaissent. Je ne pensais pas qu’un exercice d’écriture puisse provoquer un soulagement de la sorte et je vous invite ainsi à essayer. En effet, quand des individus commencent à ruminer, leurs pensées tournent en boucle et apparaissent assez floues. Le fait de les coucher sur le papier va donc les rendre concrètes et de fait, vous pourrez passer beaucoup plus facilement à l’action pour les faire disparaître. </p>\n<p>Prenons un exemple. Vous vous êtes fâché avec une personne. Vous ruminez constamment sur elle, sur la scène, sur ce que vous auriez dû dire pour la blesser autant qu’elle vous a blessé, vous ne voyez plus que ses défauts, etc. Eh bien, écrivez tout ce que vous avez sur le cœur, et sans réfléchir. Tant pis si vous accusez l’autre, l’insultez, faites sortir toute votre colère contre elle sur le papier. C’est le but. Rédigez jusqu’à ce que vous n’en ressentiez plus le besoin et pensez avoir écrit tout ce que vous désiriez. </p>\n<p>Recommencez le même exercice 2 jours plus tard. Et encore 2 jours après. Et comparez les lettres. En effet, il y a des chances que les dernières apparaissent moins virulentes que la première et aussi, moins longues. Vous comprendrez alors que cet exercice vous aura soulagé.</p>\n<h3>Passer à l’action </h3>\n<p>En conclusion, comment arrêter les ruminations mentales ? Avec l’aide de tous les outils visés plus haut, bien évidemment ! Mais surtout, par le fait d’agir et de cesser de réfléchir. En effet, les ruminations ne servent pas à trouver de solutions car sinon, elles ne s’appelleraient pas des ruminations, mais des réflexions. Si tel était le cas, vous auriez cessé de ruminer depuis bien longtemps. Vous détenez donc la preuve que ce ne sont que des plaintes passives et rien de plus. Par conséquent, si vous devez penser, faites-le à l’aide d’une réflexion concrète qui vous pousse à trouver une solution et surtout, à agir. </p>\n<p> </p>\n<p>L’action est vraiment la solution pour <b>stopper les ruminations mentales</b>, car elle représente tout son contraire.</p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'Stopper les Ruminations Mentales pour Reprendre le Contrôle de sa Vie','Se faire du soucis devient parfois pathologique et invalidant : il s’agit des ruminations ? Comment stopper les ruminations mentales ?','https://vivre-pleinement.fr/ruminations/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ruminations\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ruminations\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Stopper les Ruminations Mentales pour Reprendre le Contr\\u00f4le de sa Vie\",\"datePublished\":\"2021-01-02T11:47:22+00:00\",\"dateModified\":\"2024-02-11T19:55:12+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ruminations\\/\"},\"wordCount\":8298,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ruminations\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2021\\/01\\/Stopper-ruminations-mentales.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/ruminations\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ruminations\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/ruminations\\/\",\"name\":\"Stopper les Ruminations Mentales pour Reprendre le Contr\\u00f4le de sa Vie\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ruminations\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ruminations\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2021\\/01\\/Stopper-ruminations-mentales.jpg\",\"datePublished\":\"2021-01-02T11:47:22+00:00\",\"dateModified\":\"2024-02-11T19:55:12+00:00\",\"description\":\"Se faire du soucis devient parfois pathologique et invalidant : il s\\u2019agit des ruminations\\u2009? Comment stopper les ruminations mentales\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ruminations\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/ruminations\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ruminations\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2021\\/01\\/Stopper-ruminations-mentales.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2021\\/01\\/Stopper-ruminations-mentales.jpg\",\"width\":600,\"height\":900,\"caption\":\"Comment stopper les ruminations mentales ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/ruminations\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Stopper les Ruminations Mentales pour Reprendre le Contr\\u00f4le de sa Vie\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2021-01-02 11:47:22',NULL,'2026-05-24 19:19:44','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (29,'Quel est le But Ultime de la Vie ? Les Différents Points de Vues','quel-est-le-but-de-la-vie','Nous pensons que tous les êtres humains ont une mission à réaliser, car il doit bien y avoir une raison à notre existence, mais laquelle ? Cependant, chaque réponse concernant le sens de l’existence reste subjective. Elle dépend de la personnalité de chaque individu, ainsi que de sa façon d’interpréter les situations. Vous pensez que votre mission est de vivre dans l’amour en fondant une famille. Partir en mission humanitaire est, pour vous, le sens de la vie, qui est d’aider les plus démunis. Vous pratiquez le développement personnel pour atteindre une meilleure version de vous-même. Pour vous, la finalité de la vie est d’évoluer en vue des prochaines existences, car vous croyez en la réincarnation. Vous vous demandez souvent pourquoi vous vous trouvez sur terre ? Quel est le but ultime de la vie ? \n','<p>Nous pensons que tous les êtres humains ont une <b>mission </b>à réaliser, car il doit bien y avoir une <b>raison </b>à notre existence, mais laquelle ? Cependant, chaque réponse concernant le sens de l’existence reste <b>subjective</b>. Elle dépend de la <b>personnalité </b>de chaque individu, ainsi que de sa façon <b>d’interpréter </b>les situations. Vous pensez que votre mission est de vivre dans <b>l’amour </b>en fondant une <b>famille</b>. Partir en mission <b>humanitaire </b>est, pour vous, le sens de la vie, qui est <b>d’aider </b>les plus démunis. Vous pratiquez le <b>développement personnel</b> pour atteindre une meilleure version de vous-même. Pour vous, la finalité de la vie est <b>d’évoluer </b>en vue des prochaines existences, car vous croyez en la <b>réincarnation</b>. Vous vous demandez souvent pourquoi vous vous trouvez sur terre ? <b>Quel est le but ultime de la vie ? </b></p>\n<h2>L’amour comme but ultime de la vie  </h2>\n<p>Vivre dans l’amour peut représenter le but de la vie de bon nombre de personnes. Il convient cependant de ne pas confondre amour inconditionnel et attachement. </p>\n<h3>L’attachement </h3>\n<p>Chaque être humain a besoin d’amour. Nous sommes des animaux sociaux, après tout. C’est d’ailleurs pour cette raison que la plupart des individus se mettent en couple, puis fondent une famille. En général, cette façon de vivre procure de la joie.</p>\n<p>Cependant, beaucoup de personnes confondent amour et attachement. C’est le cas, par exemple, d’un homme qui se suicide parce que sa femme l’a quittée. Ou d’une mère qui tombe en dépression, car ses enfants partent de la maison. Certaines personnes, en effet, pensent ne plus rien valoir si elles perdent l’affection de l’autre. Elles vont donc tout faire pour contrôler les autres (<a href=\"/je-suis-jaloux\" target=\"_blank\" rel=\"noopener\" title=\"Je suis jaloux\">jalousie</a>, autoritarisme, chantage affectif, etc.) ou pour se comporter comme ses semblables veulent qu’elles se comportent. Elles souhaitent juste ne pas perdre leur sympathie. </p>\n<p>Sachez que ce type d’amour n’est pas pur : c’est de l’attachement. La personne comble, en réalité, un besoin qu’elle est incapable de se donner à elle-même. Voilà pourquoi elle cherche impérativement l’amour à l’extérieur. Résultat : elle devient dépendante affective. </p>\n<h3>Le véritable amour </h3>\n<p>Vivre dans l’amour peut représenter un but merveilleux. Mais le véritable amour. C’est-à-dire, apprécier une personne telle qu’elle est, sans essayer de lui plaire ou de la changer. Mais pour en arriver à ce point, il convient déjà d’apprendre à vous <a href=\"/confiance-et-estime-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Confiance et estime de soi\">estimer</a>. inconditionnellement, avec vos forces et vos faiblesses. Le but est en effet d’aimer autrui, mais l’autre ne doit rester qu’un bonus dans votre vie. </p>\n<p>Car si vous mettez votre bien-être entre les mains de quelqu’un d’autre, vous n’avez absolument plus de pouvoir et de contrôle sur votre existence. Votre bonheur ne dépend plus que des aléas extérieurs, vous imaginez ? Il faut donc vivre votre vie et respecter celle votre semblable et sa liberté. De ce fait, si un jour, pour une raison x ou y, cette personne disparaît de votre existence, vous pourrez tout de même aller de l’avant, et ce, grâce à l’amour que vous vous portez.</p>\n<h2>Aider autrui pour donner du sens à sa vie </h2>\n<p>Il existe des individus ayant fait de la bonté, de l’humilité et de la charité le but de leur vie. Pour eux, aider les autres et surtout, les moins bien lotis qu’eux est une évidence. Ce but leur permet de penser qu’ils contribuent à quelque chose de plus grand, dépassant leur petite personne. Leur existence aura donc été utile à l’humanité. </p>\n<p>Cependant, certaines personnes jugent, par exemple, les célébrités faisant de l’humanitaire et se filmant le faire. Pour elles, ces stars font juste semblant d’être généreuses. J’ai envie de vous dire : si elles le font pour les mauvaises raisons, et alors ? Au moins, elles passent tout de même à l’action et de fait, leurs actions auront forcément une utilité pour autrui. </p>\n<p>Honnêtement, je pense que ce n’est pas donné à tout le monde de quitter sa petite sécurité, son confort et son petit train-train quotidien pour aller dans un pays étranger. Prenons l’exemple de l’Afrique, où les cultures ne sont pas du tout les mêmes et où le confort de vie n’a rien à voir avec ce que nous connaissons. Certaines personnes prennent même des risques pour leur santé, le corps n’étant pas habitué à un climat complètement différent. Je pense donc qu’il vaut mieux agir que de rester dans sa zone de confort, car, celui qui passe à l’action n’a pas le temps pour la critique.</p>\n<h2>Transmettre la vie pour trouver du sens à son existence </h2>\n<p>Bon nombre de personnes, notamment les femmes, pensent que le but de la vie est juste de faire des enfants. Voyons ce sujet plus en détail. </p>\n<h3>Faire des enfants dans le but de le rendre heureux et responsables </h3>\n<p>Il existe des personnes dont le but de la vie reste leur progéniture. Honnêtement, pourquoi pas ? Cependant, l’idéal serait de faire un enfant dans le but d’en faire un être rempli d’amour, heureux et capable de voler de ses propres ailes. Élever un enfant dans ce but est vraiment honorable. </p>\n<h3>La dépendance affective </h3>\n<p>Cependant, bon nombre de personnes oublient qu’être parent ne représente qu’un rôle parmi tant d’autres. Nous jouons, en effet, concomitamment plusieurs rôles comme celui de maman, d’employé, de frère, de grand-père, d’ami, d’amant, de consommateur, etc.</p>\n<p>Par conséquent, si une personne fait un enfant dans le but de combler un manque affectif, elle risque de rencontrer de sérieuses difficultés le-ci le jour où ses enfants partiront de la maison. Ce sera également compliqué pour l’enfant, lequel ressentira la dépendance affective que sa mère (ou son père) éprouve à son égard. Cette attitude aura juste pour conséquence de l’étouffer et de le bloquer dans son évolution.</p>\n<h3>La surpopulation</h3>\n<p>Certains individus pensent que faire des enfants est l’unique but de la vie. En effet, si plus personne ne se reproduisait, l’humanité disparaîtrait. C’est un fait. Cependant, nous sommes, à l’heure actuelle, bien trop nombreux sur terre. C’est une réalité aussi. Notre planète n’hésite d’ailleurs pas à nous le rappeler régulièrement, en déclenchant diverses catastrophes naturelles provoquant des décès en masse. Ce qui a pour but la régularisation de l’espèce humaine. Mais en général, les gens s’en fichent tout de même un petit peu, tant que le malheur ne les touche pas personnellement ou ne concerne pas leurs proches. La surpopulation nuit à l’environnement. Il serait donc bon que l’être humain apprenne à devenir plus conscient et responsable. </p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"425\" src=\"/storage/blog-images/Objectif-vie.jpg\" alt=\"Sens de la vie \" title=\"Objectif-vie\">\n<h2>Devenir sage et fort pour trouver sa mission de vie </h2>\n<p>Certains choisissent comme mission de vie d’atteindre la sagesse en développant leur morale, leur spiritualité et en travaillant sur eux constamment. Ils aiment le domaine de la métaphysique et croient en l’évolution et en la réincarnation. </p>\n<h3>Le développement personnel</h3>\n<p>Certaines personnes pensent que le but principal de l’existence est de se rapprocher au maximum de la sagesse. Pour ce faire, elles entament un grand travail intérieur en augmentant leur créativité, leurs compétences, et ce, grâce au développement personnel. Elles souhaitent apprendre des vérités profondes sur la vie, s’intéressent bien souvent à la philosophie et deviennent, avec le temps, plus fortes et sages à l’aide de tous ces éléments. Je trouve personnellement que vivre dans le but de s’améliorer constamment est un excellent état d’esprit. Il est, en effet, bon de s’éloigner de l’égo.</p>\n<h3>L’égo</h3>\n<p>Cependant, il ne faut juste pas tomber dans le piège de détester l’égo et de vouloir l’éradiquer de votre vie. Effectivement, vous entendrez souvent ce genre de propos : « l’égo est un ennemi. » Sauf que c’est faux. Déjà, sachez que vous ne pourrez jamais vous débarrasser de lui. Car il existe dans le but de vous protéger ; même s’il ne s’y prend pas toujours de la bonne manière, vu qu’il agit par rapport à ce qu’il a appris. </p>\n<p>Donc, certaines personnes dénigrent ceux qui prennent soin de leur apparence, qui souhaitent avoir plus d’argent, un meilleur poste ou même, qui aiment le sexe<b>.</b> Elles pensent en réalité que ces individus se trouvent inférieurs à elles, du fait d’un matérialisme et d’une rationalité plus prononcée. </p>\n<h3>Le corps et l’argent </h3>\n<p>Cependant, je trouve qu’il est important de prendre soin de son corps, car il reste tout de même le véhicule de notre âme ! S’il ne demeure pas en bonne santé, votre esprit en souffrira forcément. Et dans la continuité, il est également nécessaire de prendre soin de son apparence, de se trouver beau/belle. Cette attitude apporte réellement un grand regain de confiance, laquelle joue énormément sur le mental. </p>\n<p>L’argent n’est pas sale non plus et ne change pas les gens. Il met juste à jour leur vraie personnalité. Par conséquent, si vous êtes profondément bon, vous ne changerez pas, même en devenant riche. Il est important d’avoir de l’argent afin de pouvoir vivre confortablement. Personne ne peut nier que les soucis financiers peuvent impacter au plus haut point la santé mentale et les relations des individus.</p>\n<p>Donc, une personne matérialiste n’est pas sous-évoluée, car ces thèmes ne sont pas vains. Ils apportent vitalité, confiance et sécurité.</p>\n<h2>Les voyages pour trouver le but de sa vie </h2>\n<p>Pour certaines personnes, le fait de voyager partout dans le monde apporte un sens à leur existence. Découvrir sans cesse de nouveaux lieux et de nouvelles cultures ne peut qu’être enrichissant pour l’esprit humain. C’est de cette façon que l’individu peut changer sa perception de voir la vie. Il peut ainsi pratiquer la gratitude en constatant tout ce qu’il possède par rapport à d’autres biens moins lotis que lui. Acquérir différentes connaissances. Sortir de sa zone de confort et apprendre, tous les jours. C’est un très beau but. Et pour ceux qui vous disent ne pas avoir l’argent pour voyager, sachez que je ne vise pas là les voyages dans des endroits et hôtels luxueux. Je parle des voyages d’aventure. Et ici, même un petit budget peut suffire, car le manque de luxe ne représente pas un frein pour la personne qui désire vraiment voir du pays. </p>\n<h2>La religion pour trouver du sens à son existence </h2>\n<p>Pour d’autres, c’est la religion qui fait vibrer leur vie. Certains n’hésitent pas à prier avec ferveur et à pratiquer la dévotion pour leur Dieu. C’est ce qui leur permet d’engager des actions en vue de s’améliorer de jour en jour dans le but de devenir un être bon. C’est vrai qu’il y a de beaux principes et de belles valeurs dans les religions. Et marcher par la foi permet également de donner un sens à l’existence d’un être humain et surtout, à la mort. </p>\n<p>Croire en une religion peut donc constituer un très beau but. Attention juste à ne pas tout attendre de Dieu, au risque de ne plus du tout prendre la responsabilité de votre vie et ainsi, de ne plus agir. Car dans ce cas, vous laissez le pouvoir à un élément extérieur et donc, pensez que vous n’avez pas de contrôle sur votre vie. Et ça, c’est vraiment une croyance à bannir.</p>\n<h2>Peu d’individus se demandent quel est le but ultime de la vie  </h2>\n<p>Avez-vous remarqué qu’avec la vie d’aujourd’hui, nous n’avons même plus le temps de nous demander quel est le but de l’existence ? Se la poser 20 fois dans la journée n’apparaît pas forcément pertinent, mais ne jamais se la poser peut vous faire passer à côté de ce que vous désirez réellement au fond de vous. </p>\n<h3>La course à l’improductivité</h3>\n<p>Il faut tout de même avouer que, du fait de la façon dont fonctionne la société actuelle, peu de monde se pose vraiment la question du sens de la vie. En effet, la plupart des individus pensent ne pas avoir le temps et passent leur vie à courir, entre leur travail, leur famille et leurs obligations. Ils accomplissent beaucoup de choses, effectivement, mais ne réalisent pas les actions qui leur permettraient de vivre leur existence comme ils le souhaitent réellement. Ils apparaissent donc productifs, mais pour des choses qui ne les rendent pas heureux. </p>\n<p>Il n’y a qu’à voir la réaction des gens dès le dimanche soir. Inquiétudes et humeur maussade font souvent leur apparition, en approche de la nouvelle semaine qui s’annonce. Résultat, ces personnes se lèvent, toute la semaine, sans avoir vraiment envie de vivre leur journée, se mettant en mode robot en attendant impatiemment le vendredi. Ils ne vivent donc pleinement que deux jours par semaine, le week-end. Et encore, bon nombre d’entre eux se tracassent déjà dès le dimanche… pas très alléchant comme programme, vous ne trouvez pas ? </p>\n<h3>Le but de la vie biaisé par la société</h3>\n<p>Il convient donc déjà de commencer à ralentir cette course improductive et de se poser la question suivante : « quel est le but que je peux avoir et qui peut faire vibrer ma vie ? » Par contre, attention. Vous pouvez penser avoir un but alors qu’il ne s’agit, en réalité, que d’un but fixé par la société. Par exemple, votre objectif est de désirer avoir un enfant impérativement à 30 ans au plus tard, parce que c’est ainsi que la société le voit. Cependant, si vous vous écoutez, vous ne souhaitez pas vraiment en avoir. Donc, voyez déjà si ce but est bien le vôtre ou celui que la société vous ordonne d’avoir. Car sinon, vous continuerez votre course folle de l’improductivité. Faites preuve le plus souvent possible de discernement. </p>\n<img decoding=\"async\" width=\"750\" height=\"563\" src=\"/storage/blog-images/Mission-vie.jpg\" alt=\"Finalite de l’existence \" title=\"Mission-vie\">\n<h2>Astuces pour surmonter l’indécision et trouver le but de sa vie </h2>\n<p>Puisque la société ne nous a pas appris à nous écouter pour trouver notre but, forcément, quand nous nous posons la question, bien souvent, nous ne trouvons rien… nous nous trouvons donc fréquemment dans l’indécision. Pour en sortir, vous pouvez essayer ces deux méthodes : </p>\n<h3>Se rappeler de vos souhaits d’enfance </h3>\n<p>Rappelez-vous ce que vous souhaitiez accomplir en étant enfant. Car quand nous sommes des enfants, nous voyons grand. Il n’y a pas encore eu trop de conditionnement dans notre vie et nous sommes donc beaucoup moins soumis à la peur du regard des autres. C’est dans ce moment de « pureté » que le petit sait véritablement ce qu’il veut. Après, vous n’aurez plus forcément les mêmes envies, mais vous pourrez déjà comprendre comment votre esprit fonctionnait à l’époque et quel genre d’activités vous faisaient envie. </p>\n<p>D’ailleurs, si vous souhaitez retrouver cet état naturel c’est-à-dire, oser être authentique et ce, en vous affranchissant du regard des autres, je vous invite à aller consulter le programme de Didier PENISSARD, formateur, coach et auteur dans le développement personnel. Pour en savoir plus, c’est ici :</p>\n<h3>Se poser deux questions</h3>\n<p>La deuxième méthode apparaît très utile lorsque vous êtes indécis sur une décision à prendre. Par exemple : choisir entre rester dans le salariat ou vous lancer dans l’entrepreneuriat. </p>\n<p>J’utilise personnellement cette méthode lorsque je suis en proie à l’indécision, sentiment que j’éprouve encore très souvent aujourd’hui ! En fait, je transforme mon hésitation en questionnement. Pour cet exemple, il s’agira de l’une des questions suivantes : </p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">Dois-je continuer dans le salariat ?</li>\n<li aria-level=\"1\">Dois-je me lancer dans l’entrepreneuriat ?</li>\n</ul>\n<p> </p>\n<p>Vous allez me dire que ces deux questions apparaissent identiques. Eh bien non. Car la réponse se trouve dans votre interrogation. La manière dont vous posez la question constitue une sorte de lapsus, permettant de faire ressurgir ce que votre moi le plus profond désire réellement. </p>\n<p> Attention, cette astuce ne va pas vous faire prendre de bonnes décisions à tous les coups. Prendre de mauvaises décisions vous arrivera forcément. C’est juste que vous aurez écouté ce que vous souhaitez véritablement et dans tous les cas, et n’aurez, du coup, aucun regret. </p>\n<p>Par conséquent, analysez la façon dont vous posez votre question. Si vous l’énoncez de la première façon, c’est sans doute que, pour le moment, vous ne vous sentez pas prêt à entreprendre et donc, il serait plus sage pour vous de rester dans le salariat. Par contre, si vous formulez la question de la deuxième manière, c’est qu’il est temps pour vous d’entreprendre. </p>\n<h2>Mon avis sur le but ultime de la vie : vivre, tout simplement </h2>\n<p>Il existe donc plusieurs manières de trouver un but à la vie sur terre. Tout dépend de la perception que nous avons de l’existence. Je vous donne ici mon avis, à toutes fins utiles. Pour moi, bien que je rejoigne certains buts (aider autrui, acquérir la sagesse, aimer), je me pose la question suivante : pourquoi donner impérativement un sens à notre vie ? L’être humain n’a peut-être rien de divin et de fait, aucune mission à accomplir. Nous ne savons rien sur notre présence sur terre, finalement. Tout ne reste qu’hypothèses. </p>\n<p>Donc, au lieu de se triturer l’esprit, pourquoi ne pas se dire que le but de la vie est tout simplement de vivre ? Est-ce si grave s’il n’y a pas vraiment de finalité à l’existence humaine, animale et végétale ? Ceci reste une hypothèse de ma part, car je n’en sais pas plus que vous. C’est juste ma façon de voir. Et pour m’aider à vraiment trouver du sens à ma vie, je procède comme suit.</p>\n<h3>La vie est un jeu </h3>\n<p>En fait, je considère la vie comme un jeu. J’essaie donc de jouer au maximum, et ce, afin d’évoluer et de progresser, encore et toujours. Chaque semaine, je me lance un défi qu’il est difficile pour moi de réaliser ou même, que je me sens incapable d’accomplir. En agissant de cette manière, j’obtiens un énorme regain de confiance en moi une fois le défi relevé. J’apprends ainsi sans cesse. </p>\n<p>Cette façon nouvelle de mener ma vie m’aide à ne pas tomber dans la routine quotidienne trop facilement. Par conséquent, je plonge beaucoup moins dans certains travers habituels, comme, par exemple, les pensées négatives, les soucis, etc. Agir de la sorte me procure un sentiment d’accomplissement et une motivation exceptionnels !</p>\n<h3>Ne pas avoir de regret sur son lit de mort </h3>\n<p>Afin de savoir si vous vivez vraiment la vie que vous souhaitez, l’astuce est de vous imaginer sur votre lit de mort. Ce n’est pas très agréable, j’avoue, mais essayez quand même. Faites comme si le moment était venu et voyez si vous avez des regrets pour quelque chose. Si oui, c’est l’occasion ou jamais d’agir dessus, tant que vous êtes en vie et en bonne santé. Les regrets peuvent porter sur le fait de : </p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">Travailler trop ; </li>\n<li aria-level=\"1\">Ne pas oser rester vous-même, <a href=\"/etre-authentique\" target=\"_blank\" rel=\"noopener\" title=\"être authentique\">authentique</a> ; </li>\n<li aria-level=\"1\">Ne pas oser accomplir ce que vous voulez vraiment de peur du <a href=\"/jugement-des-autres\" target=\"_blank\" rel=\"noopener\" title=\"Jugement des autres\">regard des autres ; </a></li>\n<li aria-level=\"1\">Regretter d’avoir coupé les ponts avec des personnes chères pour des broutilles ou une histoire d’égo. </li>\n</ul>\n<p> </p>\n<p>À vous d’analyser la situation et d’agir tant qu’il en est encore temps ! </p>\n<p> </p>\n<p>Alors, <b>quel est le but ultime de la vie </b>pour vous qui vous permettra d’être heureux ? </p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'Quel est le But Ultime de la Vie ? Les Différents Points de Vues','Nous pensons que les êtres humains ont une mission à réaliser, car il doit bien y avoir une raison à notre existence. Quel est le but ultime de la vie ?','https://vivre-pleinement.fr/quel-est-le-but-de-la-vie/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/quel-est-le-but-de-la-vie\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/quel-est-le-but-de-la-vie\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Quel est le But Ultime de la Vie\\u2009? Les Diff\\u00e9rents Points de Vues\",\"datePublished\":\"2020-11-24T12:54:54+00:00\",\"dateModified\":\"2024-02-13T19:15:09+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/quel-est-le-but-de-la-vie\\/\"},\"wordCount\":6009,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/quel-est-le-but-de-la-vie\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/11\\/But-ultime-vie.jpg\",\"articleSection\":[\"D\\u00e9veloppement personnel\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/quel-est-le-but-de-la-vie\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/quel-est-le-but-de-la-vie\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/quel-est-le-but-de-la-vie\\/\",\"name\":\"Quel est le But Ultime de la Vie\\u2009? Les Diff\\u00e9rents Points de Vues\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/quel-est-le-but-de-la-vie\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/quel-est-le-but-de-la-vie\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/11\\/But-ultime-vie.jpg\",\"datePublished\":\"2020-11-24T12:54:54+00:00\",\"dateModified\":\"2024-02-13T19:15:09+00:00\",\"description\":\"Nous pensons que les \\u00eatres humains ont une mission \\u00e0 r\\u00e9aliser, car il doit bien y avoir une raison \\u00e0 notre existence. Quel est le but ultime de la vie\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/quel-est-le-but-de-la-vie\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/quel-est-le-but-de-la-vie\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/quel-est-le-but-de-la-vie\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/11\\/But-ultime-vie.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/11\\/But-ultime-vie.jpg\",\"width\":640,\"height\":384,\"caption\":\"Quel est le but ultime de la vie ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/quel-est-le-but-de-la-vie\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Quel est le But Ultime de la Vie\\u2009? Les Diff\\u00e9rents Points de Vues\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2020-11-24 12:54:54',NULL,'2026-05-24 19:19:44','2026-06-19 22:28:14');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (30,'Signification Psychologique des Maux : les Comprendre pour en Guérir','le-mal-a-dit','Le mot maladie peut se décomposer comme suit : le mal a dit. Le mal a un message à nous transmettre. Les maux dont nous faisons l’objet apparaissent utiles, malgré toute la souffrance qu’ils nous font au premier abord. Notre état émotionnel peut provoquer 70 % des maladies connues sur cette planète. Les 30 % restants sont dus à des éléments extérieurs dont nous ne pouvons rien, tels que les virus, par exemple. Cependant, nous ne déclenchons pas volontairement ces maladies. Mais pour retrouver la santé, il est urgent de décoder le message du symptôme que nous ressentons. Dès que vous stressez énormément, une migraine se déclenche et vous ne pouvez plus agir. Vous gardez toujours en vous votre colère, et avez fini par déclencher une maladie de Crohn. Votre corps vous fait souffrir ? Et si vous vous attardiez sur la signification psychologique des maux dont vous souffrez pour en guérir ? \n','<p>Le mot <b>maladie </b>peut se décomposer comme suit : le <b>mal a dit.</b> Le mal a un <b>message </b>à nous transmettre. Les maux dont nous faisons l’objet apparaissent <b>utiles</b>, malgré toute la souffrance qu’ils nous font au premier abord. Notre état <b>émotionnel peut provoquer</b> <b>70 %</b> des maladies connues sur cette planète. Les <b>30 %</b> restants sont dus à des éléments <b>extérieurs </b>dont nous ne pouvons rien, tels que les virus, par exemple. Cependant, nous ne déclenchons pas <b>volontairement </b>ces maladies. Mais pour retrouver la santé, il est urgent de <b>décoder </b>le message du symptôme que nous ressentons. Dès que vous <b>stressez </b>énormément, une <b>migraine </b>se déclenche et vous ne pouvez plus <b>agir</b>. Vous gardez toujours en vous votre <b>colère</b>, et avez fini par déclencher une <b>maladie de Crohn.</b> Votre corps vous fait <b>souffrir </b>? Et si vous vous attardiez sur la <b>signification psychologique des maux</b> dont vous souffrez pour en guérir ? </p>\n<h2>Les causes de la souffrance du corps</h2>\n<p>Il est déjà important de comprendre pourquoi vous avez des problèmes somatiques. Voici les principales causes des maux physiques.</p>\n<h3>Le refoulement des émotions </h3>\n<p>Lorsque le corps délivre un message via une maladie somatique, c’est que vous n’avez pas tenu compte de vos émotions négatives. Vous les avez même sans doute refoulées, en vue d’éviter de souffrir, et ce, de diverses façons : </p>\n<p> </p>\n<p>– Avoir l’impression de n’éprouver aucune émotion ;</p>\n<p>– Faire comme si une situation vous laissait de marbre alors qu’elle vous touche profondément ;</p>\n<p>– Prétendre que tout va bien à la personne en face de vous alors que pas du tout ; </p>\n<p>– Être hyperactif, constamment en action, et ce, dans le but de ne pas avoir le temps de ressentir vos émotions ; </p>\n<p>– Laisser passer la situation qui nous dérange. Ne pas vous affirmer face à la personne concernée ; </p>\n<p>– Boire de l’alcool pour dissiper temporairement une émotion négative. La fuir. </p>\n<p> </p>\n<p>De plus, lorsque les individus commencent à ressentir des symptômes physiques, la plupart d’entre eux tentent de les estomper par le biais de médicaments. Cependant, bien que les médicaments apparaissent utiles quelquefois, le fait de faire taire les symptômes encourage le corps à envoyer des signaux de plus en plus puissants. En effet, l’organisme pense que le premier signal n’a pas été reçu. Le risque, à la longue, est bien évidemment d’attraper une maladie grave. </p>\n<h3>L’égo </h3>\n<p>Nous entendons fréquemment ce genre de phrase : « je suis un homme et un homme ne pleure pas ». Laisser transparaître ses émotions relève de la faiblesse. Et cette croyance est d’ailleurs bien souvent transmise par nos parents et éducateurs. Par exemple, des parents peuvent inculquer à leurs enfants de ne jamais s’énerver, car ce fait appartient aux êtres de niveau inférieur, ne maîtrisant pas leurs émotions. Pour eux, ne pas exprimer ses émotions relève de la supériorité. C’est ce que leur mental croit, en tout cas.</p>\n<p>L’égo pousse également à ne pas toujours exprimer les bonnes émotions. Par exemple, une personne ressent une grande colère envers une autre. En réalité, elle se sent plutôt profondément triste et blessée, mais ne l’avouera pas, car elle pense que cette émotion relève de la faiblesse. Il vaut mieux, pour elle, montrer de l’agressivité, laquelle passe pour de la force de caractère au niveau de l’égo, alors qu’il n’en est rien. C’est ce qui s’appelle les émotions masquées.</p>\n<h3>La blessure transgénérationnelle </h3>\n<p>Nos problèmes actuels peuvent provenir de… nos ancêtres ! Et ce, sur au moins trois générations ! En effet, ce qui a été douloureux émotionnellement pour eux et non réglé au cours de leur vie se transmet à leurs descendants. C’est pourquoi certains maux psychiques ou physiques dont vous souffrez n’ont pas forcément d’explications. Vous n’y croyez pas ? Eh bien, vous pouvez avoir le même nez que votre grand-père, donc pourquoi pas sa dépression ? </p>\n<p>Imaginez qu’il s’agit d’une course de relais. La personne, à la fin de son parcours, confie le relai à une autre afin qu’elle puisse poursuivre la course. Ainsi, en vous refourguant son mal-être, votre ancêtre vous donne comme message : « guéris ce que moi-même je n’ai pu guérir.»</p>\n<p>Ce que je peux vous conseiller si ce sujet vous intéresse, c’est d’aller consulter un somatothérapeute. Ce thérapeute peut, en effet, faire disparaître tous les troubles somatiques qui ne vous appartiennent pas. Et je parle d’expérience. </p>\n<h2>Pourquoi souffrir d’une maladie en particulier ? </h2>\n<p>Pourquoi une personne souffrant d’une maladie souffre-t-elle de cette affection spécifiquement et pas d’une autre ? En fait, chaque partie de notre organisme est associée à un problème émotionnel bien précis. Par exemple, le cœur et l’intestin grêle sont liés à la haine et à l’impatience. La colère et la frustration au foie et à la vésicule biliaire. Les reins et la vessie à la peur, etc.</p>\n<p>La partie concernée par votre émotion douloureuse émotionnelle va ainsi être la partie la plus touchée de votre corps. Cependant, pour compenser, elle va sans cesse absorber vos problèmes émotionnels afin que le reste du corps puisse continuer à fonctionner normalement. Elle absorbera donc de plus en plus de tension, jusqu’au jour où elle atteint ses limites. C’est à ce moment que la pathologie somatique arrive. </p>\n<a href=\"https://hypnocaments.com?partnerid=YK5muYugzSoIWDbDWRgT-Q\" title=\"Seances d hypnose en ligne\"><img decoding=\"async\" src=\"https://hypnocaments.com/image/banner_1_750.png\" alt=\"seance hypnose mp3\"></a>\n<h2>Exemples de signification psychologique des maux  </h2>\n<p>Voici quelques exemples de maladies psychosomatiques et de leurs significations. Pour aller plus loin, je vous conseille deux livres regroupant quasiment toutes les maladies existantes ainsi que leurs messages. Le premier est le livre de Lise BOURBEAU s’intitulant « Ton corps dit : Aime-toi ! Les malaises et maladies et leurs messages ». Le deuxième, dont l’auteur est Jacques MARTEL, se nomme « Le grand dictionnaire des malaises et maladies ». Il en existe évidemment d’autres et je vous laisserai effectuer vos recherches de votre côté si le thème des maladies somatiques vous intéresse. </p>\n<h3>Le cancer </h3>\n<p>La personne a depuis toujours mis de côté ses besoins pour s’occuper des autres. Elle a également souffert de rejet et d’abandon depuis l’enfance, et ce, dans l’isolement. Bien souvent, l’individu en veut fortement à l’un de ses deux parents, mais nie totalement ce fait. Il refoule donc sa souffrance profondément en lui. Le cancer apparaît lorsque la personne a refoulé trop de sentiments négatifs durant des années et des années. Son esprit en est rendu à sa limite. Il s’agit d’un message ultime du corps. La douleur refoulée ronge, au sens propre, la personne de l’intérieur.</p>\n<p>Il y a lieu pour l’individu d’accepter d’avoir ressenti des émotions négatives telles que la rancune, la haine, la colère, etc. puis de se pardonner. Car le fait d’en vouloir à une personne ne fait pas de lui une mauvaise personne, juste un individu souffrant. Il convient également qu’il apprenne à s’aimer. </p>\n<h3>Le diabète </h3>\n<p>Une personne souffrant de diabète demeure très émotive et a beaucoup de désirs. Elle se comporte comme une mère pour autrui et a beaucoup d’attentes envers eux. Elle culpabilise beaucoup quand ses souhaits se réalisent et lorsque ceux des autres ne se concrétisent pas. Cette personne cherche trop l’amour et la tendresse de l’extérieur, ce qui reflète une profonde tristesse intérieure. </p>\n<p>Par contre, le diabète chez un enfant se manifeste lorsqu’il ne se sent pas reconnu. Il ressent un grand chagrin intérieur et cette maladie reste le moyen, pour lui, d’attirer l’attention. </p>\n<p>Il y a lieu d’arrêter de vouloir combler le bonheur et les désirs des autres. La personne doit reconnaître tout ce qu’elle a accompli jusqu’à maintenant. Elle doit entendre qu’au final, tout ce qu’elle accomplit finalement pour ses semblables, elle le réalise surtout pour elle-même, pour obtenir de l’amour de leur part. Cet individu doit savoir se faire plaisir et écouter ses besoins. Il a, en fait, peur que ses pairs apparaissent envieux envers lui. Même si un grand désir ne s’est pas manifesté, il est bon de prendre conscience de tous les autres désirs se manifestant dans le présent. Il est conseillé d’apprendre à lâcher prise et de cesser de vouloir tout contrôler. Éprouver de la gratitude pour ce qu’il a et non de penser à ce qui lui manque. </p>\n<p>Le petit diabétique doit arrêter de croire qu’il est l’enfant perdu de la famille. À lui de trouver sa place. </p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"500\" height=\"750\" src=\"/storage/blog-images/Liens-emotions-maladies.jpg\" alt=\"Somatisation\" title=\"Liens-émotions-maladies\">\n<h3>Les douleurs du genou </h3>\n<p>Une personne ayant mal à l’articulation du genou a généralement un comportement inflexible. Elle est entêtée, refusant de se plier aux idées et conseils des autres et d’autant plus s’ils apparaissent autoritaires. </p>\n<p>L’individu doit apprendre à lâcher prise pour changer sa façon de voir l’existence. Il doit déjà se rendre compte de son inflexibilité. Écouter ses semblables ne veut pas dire se rabaisser devant eux. Une personne ayant du mal avec l’autorité n’assume pas le fait qu’elle-même l’est beaucoup. La personne a peur de devenir comme l’un de ses parents. Il faut cependant qu’elle comprenne qu’elle n’est pas eux et que même s’il existe des similitudes, elle peut toujours diriger sa vie à sa façon. Elle doit également reconnaître que tout le monde a besoin d’être aidé, quelquefois, et que ce n’est pas une honte.</p>\n<h3>L’infarctus </h3>\n<p>Les problèmes de cœur viennent d’un manque de joie. La personne refuse de voir la tristesse en elle et ainsi, refoule ses émotions négatives. Elle prend généralement les choses trop à cœur et en fait trop en souhaitant vouloir plaire à ses semblables. Elle apparaît en outre très critique envers autrui et les juge énormément.</p>\n<p>Cette personne doit donc retrouver sa jovialité en s’apportant des petits plaisirs quotidiens. Elle doit également apprendre à s’aimer au lieu de s’oublier en accomplissant ce que les autres attendent d’elle dans le but d’être aimée par eux.</p>\n<h3>Les maladies inflammatoires  </h3>\n<p>Les maladies inflammatoires surgissent lorsque la personne est en train de réparer une situation qui lui a causé de la colère ainsi que beaucoup d’autres émotions négatives. Elle ne se sent plus en conflit avec la personne ou la situation concernée. En s’éloignant du conflit, elle pense l’avoir réglé. Cependant, s’éloigner d’un différend ne veut pas dire l’avoir résolu. L’inflammation indique qu’il manque l’étape du pardon.</p>\n<h2>Comment se libérer des maux du corps ?</h2>\n<p>Voyons maintenant comment guérir de vos douleurs à l’aide de toutes les solutions que vous trouverez ci-dessous.</p>\n<h3>Soigner son corps </h3>\n<p>Si vous êtes déjà atteint d’une maladie, surtout, n’arrêtez pas de vous faire soigner par la médecine traditionnelle ! Pour moi, la médecine classique demeure incomplète. Il lui manque le mieux-être de l’esprit. Cependant, les médecines alternatives apparaissent également incomplètes. Il leur manque la guérison du corps. L’idéal reste vraiment de combiner les deux. </p>\n<h3>Envisager une thérapie </h3>\n<p>Afin de guérir de vos troubles psychosomatiques, bon nombre de thérapies sont à votre disposition. Vous pouvez vous faire aider par un psychothérapeute pratiquant les TCC ou tenter une psychanalyse. Quelquefois, certains thérapeutes possèdent même des compétences complémentaires, telles que la pratique de l’hypnose, de l’EMDR, de l’EFT, etc. Ces pratiques peuvent considérablement soulager vos maladies physiques provenant de problèmes émotionnels. </p>\n<p>Il y a également la somatothérapie, l’acupuncture… À vous de trouver la médecine psychosomatique qui vous correspond pleinement. </p>\n<h3>Pratiquer des techniques de relaxation</h3>\n<p>Qui dit problème émotionnel dit régulation émotionnelle. Pour y parvenir, rien de tel qu’une bonne relaxation. Et les techniques vous aidant à vous relaxer ne manquent pas. Vous pouvez tenter la méditation en pleine conscience, le yoga, la sophrologie, etc. L’indispensable, dans toutes ces techniques, est de savoir respirer profondément, et ce, afin de réguler l’organisme. N’hésitez d’ailleurs pas à aller consulter mon <a href=\"/respiration\" target=\"_blank\" rel=\"noopener\" title=\"Respiration \">article sur la respiration.</a></p>\n<p>Pour ma part, afin de bien respirer, j’utilise  comme méthode la cohérence cardiaque. Et pour m’aider à pratiquer cette méthode correctement, j’utilise un petit appareil nommé Zenspire, lequel, grâce à ses vibrations et à sa lumière, m’aide à réguler ma respiration et de ce fait, à respirer comme il faut afin d’aller bien. Si vous êtes intéressé par cet appareil, n’hésitez pas à cliquer sur le bouton ci-dessous, étant précisé que si vous passez commande, vous bénéficierez d’une remise de 10 % grâce au code JL0620 :</p>\n<h3>Exprimer ses émotions</h3>\n<p>Pour éviter de développer des maladies, il est primordial d’exprimer vos émotions. C’est cette liberté émotionnelle qui vous sauvera. Pour y arriver, il convient de suivre les étapes suivantes.</p>\n<h4>Être à l’écoute de ses ressentis corporels</h4>\n<p>Lorsque vous commencez à éprouver une émotion, écoutez votre corps. Où se situe cette émotion ? Serait-ce dans l’estomac, sous forme de nœud ? Dans la tête, avec des tensions au front ? Dans vos épaules, avec une sensation de poids sur elles ? Par des palpitations ? Des spasmes musculaires ? Des nausées ? En observant vos manifestations physiques, il sera plus facile de trouver la bonne émotion que vous ressentez. Par exemple, vous ne vous sentez pas trop à votre aise, mais n’arrivez pas à mettre de mots sur ce que vous éprouvez. Par contre, vous commencez à trembler. Vous pouvez, du coup, ressentir de la peur. </p>\n<h4>Accepter ses émotions</h4>\n<p>Une fois que vous savez quelle émotion vous submerge, surtout, ne vous jugez pas. Ne vous dites pas, par exemple, que vous êtes un bon à rien de trembler pour telle ou telle raison. Il faut accepter de ressentir vos émotions, lesquelles sont normales et n’ont rien de honteux. Par conséquent, acceptez-les en éprouvant de la bienveillance pour vous-même. Ainsi, vous allez lâcher-prise plus facilement et éviter le dénigrement de soi et la culpabilité. Rien qu’en acceptant, vos émotions se calmeront. Les émotions vont et viennent et donc les émotions négatives passent. Et quand vous vous trouvez dans une mauvaise passe, apprenez à demeurer tolérant avec vous-mêmes et à prendre soin de vous. </p>\n<p>Il y a également lieu de ne pas confondre les émotions et les sentiments. Une émotion est ressentie sur le coup et part rapidement. Un sentiment s’apparente plutôt à une émotion mal gérée, ruminée et se transformant en sentiment, lequel perdure dans le temps et joue beaucoup plus sur votre humeur générale.</p>\n<p>Par exemple, vous éprouvez de la colère contre une personne. Vous vous êtes exprimé, certes, mais en déversant toute votre agressivité sur elle. Forcément, cette personne vous a attaqué en retour. La situation ne s’est donc pas arrangée. Vous repassez sans cesse la scène de la dispute, en regrettant de ne pas avoir dit telle phrase à tel moment pour la blesser encore plus. Cette émotion de colère mal gérée, étant ruminée sans relâche, se transforme ainsi en sentiment de rancune et de rancœur. Ce sentiment va perdurer, risquant de vous ronger de l’intérieur.</p>\n<h4>Exprimer ses émotions </h4>\n<p>Après avoir découvert votre émotion et l’avoir accueillie avec bienveillance, il y a maintenant lieu de l’exprimer. Et toujours, avec compassion envers l’autre, en lui laissant également l’occasion de prendre la parole. N’hésitez pas à aller consulter mon <a href=\"/affirmation-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Affirmation de soi\">article sur l’affirmation de soi</a> afin d’obtenir plus de renseignements sur ce mode de communication.</p>\n<p>Si vous souhaitez exprimer votre émotion à une personne, mais que vous ne le pouvez plus, en cas de décès, par exemple, essayez de trouver un cliché de cette personne. Parlez-lui, comme si elle se trouvait devant vous. Si vous ne détenez pas de photo, écrivez une lettre à la place. Même si la personne vit encore, vous n’êtes pas obligé de lui adresser le courrier. D’ailleurs, juste exprimer vos émotions pour vous-même sera suffisant.</p>\n<img decoding=\"async\" width=\"500\" height=\"750\" src=\"/storage/blog-images/Mal-a-dit.jpg\" alt=\"Maladie psychosomatique\" title=\"Mal-a-dit\">\n<h4>Découvrir ses besoins non satisfaits</h4>\n<p>Les émotions proviennent, à la base, de besoins non satisfaits. Il y a donc lieu de les satisfaire afin de faire disparaître l’émotion négative, ou de revoir vos besoins s’ils vous apparaissent abusifs. </p>\n<p>La peur, par exemple, provient d’un besoin de sécurité. En ressentant de la peur, vous avez l’impression de manquer de protection. Retrouver votre sécurité fera ainsi disparaître cette émotion. Par exemple, si vous venez de perdre votre job, vous pouvez éprouver de l’angoisse, due à une perte de sécurité de l’emploi. Vous pouvez vous demander comment vous allez faire, sans salaire, si vous allez trouver du travail facilement, etc., et si votre besoin apparaît abusif, c’est-à-dire que juste sortir de chez vous vous fait ressentir une panique irrépressible, c’est à vous d’agir pour vous libérer de ce trouble.</p>\n<p>La colère vient d’un besoin de respect. Vous avez l’impression qu’une personne vous a manqué de respect. La tristesse provient quant à elle d’un besoin de réconfort. À vous de comprendre vos besoins et surtout, de passer à l’action pour les assouvir ou pour les modifier.</p>\n<h3>Soigner sa posture </h3>\n<p>Soigner votre posture peut changer l’état émotionnel dans lequel vous vous trouvez. En réalité, c’est assez logique. Si vous baissez la tête, vous tenez voûté et rasez les murs en traînant les pieds, pouvez-vous avoir une grande confiance en vous ainsi qu’une bonne énergie ? Certainement pas ! </p>\n<p>La posture que vous avez est liée à l’émotion que vous ressentez. Du coup, pourquoi ne pas changer votre posture afin que votre état émotionnel change ? Tentez de vous tenir droit, relevez la tête, regardez vos interlocuteurs dans les yeux, jetez vos épaules un peu en arrière, mettez vos mains sur vos hanches. Voyez ensuite comment vous vous sentez. </p>\n<p>Il a d’ailleurs été prouvé scientifiquement que sourire rend forcément plus joyeux. Donc, même en ressentant des émotions négatives, faites un faux sourire et vous verrez que vous vous sentirez mieux. </p>\n<h3>Stopper les ruminations mentales </h3>\n<p>Afin de régler vos problèmes émotionnels, il est impératif de stopper vos ruminations négatives, lesquelles ne font qu’amplifier vos troubles. Pour y parvenir, il est primordial de changer votre perception des évènements. Dès que vous sentez une pensée négative surgir et durant plusieurs minutes sans que vous ne trouviez de solution pour aller mieux, c’est une rumination.</p>\n<p>À partir de là, tentez de percevoir les situations différemment, d’un point de vue plus apaisé. Il est très important de créer de nouvelles croyances et de nouveaux schémas de pensées plus positifs et dynamisants. Entraînez-vous à systématiquement contrer une rumination dès qu’elle apparaît, et ce, afin d’habituer votre cerveau à voir la vie autrement. C’est difficile, au début, mais vous serez surpris des résultats que vous obtiendrez avec le temps et surtout, avec de la persévérance. </p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h3>Pardonner </h3>\n<p>Pour vous aider à stopper toute émotion négative et par le fait, les ruminations, il y a lieu d’apprendre à pardonner. </p>\n<p>La plupart des individus ne pardonnent pas et restent dans leur rancune, en pensant ainsi blesser l’autre. Sauf que c’est à eux-mêmes qu’ils se font du mal. Et contrairement à ce que l’on peut penser, le temps ne résout pas tous les problèmes. Il peut donner, en effet, une impression d’avoir pris plus de recul sur votre rancœur, mais il n’en est rien. Tant que vous n’aurez pas pardonné véritablement, ladite rancœur continuera de vous ronger inlassablement. </p>\n<p>Pour vous entraîner, essayez de comprendre ce que l’autre ressent. Pourquoi il réagit ainsi, et ce, même si vous n’êtes pas d’accord avec lui. Peut-être a-t-il des traumatismes non résolus. Attention, vous n’avez pas à tout laisser passer à cette personne, sous prétexte desdits traumatismes. Mais le fait de se mettre dans sa peau et d’avoir de l’empathie envers elle vous aidera à mieux la comprendre et donc, à éprouver moins de rancœur à son égard. Pardonner, ce n’est pas accepter le comportement de l’autre. Vous le faites tout simplement pour vous, pour votre santé. </p>\n<h3>Faire du sport </h3>\n<p>Je pense que vous le savez, le sport est bon pour la santé, aussi bien pour votre corps que pour votre mental. Faire du sport, en effet, libère des endorphines, hormones procurant une sensation de bien-être. Et pratiquer une activité physique est également conseillé pour se libérer d’un trop-plein d’émotions négatives. Pourquoi pensez-vous que certains pratiquent la boxe, par exemple ? Ce sport leur permet, bien souvent, d’évacuer leur grande colère intérieure.</p>\n<h3>S’aimer </h3>\n<p>Pour vous sentir bien dans votre peau, il est primordial d’apprendre à<a href=\"/confiance-et-estime-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Confiance et estime de soi \"> vous aimer.</a>  C’est-à-dire, de vous apprécier avec vos forces et vos faiblesses, ce qui vous permettra d’oser rester authentique devant les autres, sans avoir peur de leur jugement. Vous boosterez par la même occasion votre confiance en vous. De plus, vous estimer vous donnera la possibilité de vous sentir bien rien qu’avec vous-même, sans avoir besoin d’obtenir l’amour d’autrui pour ce faire.</p>\n<h3>Devenir responsable</h3>\n<p>Pour apprendre à gérer vos émotions, il est nécessaire de devenir responsable. C’est-à-dire, de ne pas penser qu’il s’agit toujours de la faute des autres ou de vos expériences vécues si vous ressentez telle ou telle émotion négative. Ce comportement ne fait que vous conforter dans une attitude de victime, laquelle ne vous aide en rien à agir. Au contraire, elle vous pousse surtout à vous complaire, inconsciemment bien sûr, dans votre mal-être. N’hésitez pas à aller consulter mon <a href=\"/devenir-responsable\" target=\"_blank\" rel=\"noopener\" title=\"Devenir responsable\">article</a> à ce sujet.</p>\n<h3>Faire le point sur ses fréquentations </h3>\n<p>Nous sommes la moyenne des 5 personnes qui nous entourent. Donc, posez-vous les questions suivantes : ces personnes me tirent-elles vers le haut ? Sont-elles optimistes ? Apparaissent-elles heureuses pour moi quand j’obtiens un succès ? Me font-elles voir la vie en grand ? Aiment-elles la vie ? Vous l’aurez compris : entourez-vous de personnes positives. En effet, comment voulez-vous aller mieux en compagnie d’individus négatifs ? </p>\n<p>Après, il ne faut pas rejeter une personne dépressive suite à un traumatisme vécu, par exemple. Il y a lieu, au contraire, de la soutenir. Puisque tout le monde aura des coups durs dans sa vie. Je parle ici des personnes constamment négatives, toxiques, lesquelles sont à éviter au maximum dans votre existence. Car nous finissons par ressembler aux personnes que nous fréquentons. Nous pouvons fréquenter une personne pendant plus de 20 ans sans nous rendre compte qu’elle nous tire vers le bas. Ou peut-être même qu’il s’agit d’une relation toxique. C’est-à-dire, que vous vous tirez mutuellement vers le bas ! </p>\n<h3>Faire ce que l’on aime </h3>\n<p>Faire ce que vous aimez ne pourra que vous aider à ressentir des émotions positives et dynamisantes. Il peut s’agir de n’importe quelle occupation<b>. </b>Une activité artistique, créative, le bricolage, le jardinage, la lecture, les balades dans la nature, la musique, un sport, les jeux vidéos (avec modération), etc.</p>\n<p>N’hésitez pas non plus à vous trouver un but. Cet objectif vous donnera, en effet, un sacré élan de dynamisme et grâce à lui, vous aurez envie de vous lever tous les matins. Ce but peut être de contribuer au monde à votre manière en vous inscrivant dans une association, par exemple. Ou tenter de devenir entrepreneur et donc, plus libre, ou vouloir gagner en croissance personnelle en vous lançant des défis, etc. il n’y a pas de règles ou de buts meilleurs que d’autres. À vous de voir ce qui vous fait vibrer. </p>\n<p>Et quand tout va bien dans votre vie, cessez d’avoir peur que votre bonheur s’arrête un jour. Profitez vraiment de l’instant heureux, car de toute manière, il y aura des hauts et des bas dans votre existence. La vie n’est pas un long fleuve tranquille. Elle est fluctuante. Donc oui, votre bonheur va s’estomper un jour. Mais il va aussi revenir. Il y a alors lieu de vivre les moments négatifs en faisant de votre mieux à ces moments-là, tout en profitant au maximum des périodes heureuses.</p>\n<p>Connaître la <b>signification psychologique des maux </b>dont vous souffrez demeure primordial pour retrouver votre santé. En comprenant le message de votre corps, vous l’écoutez enfin et pourrez ainsi entamer le processus de guérison : le corps et l’esprit seront réconciliés. </p>\n<p><a href=\"https://amzn.to/3NNlwaM\">Visitez Amazon pour vous procurer le livre </a>de Lise Bourbeau « Ton corps dit : aime-toi ! Les malaises et maladies et leurs messages ».</p>\n<p>(Lien rémunéré par Amazon)</p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'Signification Psychologique des Maux : les Comprendre pour en Guérir','Le mot maladie se décomposer en : le mal a dit. Et si vous vous attardiez sur la signification psychologique des maux dont vous souffrez pour en guérir ?','https://vivre-pleinement.fr/le-mal-a-dit/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/le-mal-a-dit\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/le-mal-a-dit\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Signification Psychologique des Maux\\u00a0: les Comprendre pour en Gu\\u00e9rir\",\"datePublished\":\"2020-11-01T10:11:03+00:00\",\"dateModified\":\"2024-02-11T20:00:27+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/le-mal-a-dit\\/\"},\"wordCount\":7304,\"commentCount\":2,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/le-mal-a-dit\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/11\\/Signification-psychologique-maux.jpg\",\"articleSection\":[\"D\\u00e9veloppement personnel\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/le-mal-a-dit\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/le-mal-a-dit\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/le-mal-a-dit\\/\",\"name\":\"Signification Psychologique des Maux\\u00a0: les Comprendre pour en Gu\\u00e9rir\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/le-mal-a-dit\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/le-mal-a-dit\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/11\\/Signification-psychologique-maux.jpg\",\"datePublished\":\"2020-11-01T10:11:03+00:00\",\"dateModified\":\"2024-02-11T20:00:27+00:00\",\"description\":\"Le mot maladie se d\\u00e9composer en : le mal a dit. Et si vous vous attardiez sur la signification psychologique des maux dont vous souffrez pour en gu\\u00e9rir\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/le-mal-a-dit\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/le-mal-a-dit\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/le-mal-a-dit\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/11\\/Signification-psychologique-maux.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/11\\/Signification-psychologique-maux.jpg\",\"width\":590,\"height\":393,\"caption\":\"Quelle est la signification psychologique des maux ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/le-mal-a-dit\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Signification Psychologique des Maux\\u00a0: les Comprendre pour en Gu\\u00e9rir\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2020-11-01 10:11:03',NULL,'2026-05-24 19:19:44','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (31,'Se Libérer de la Pression Sociale, la Clé du Bien-être','normes-sociales','Les normes sociales se définissent comme un ensemble de règles, concrètes (la Loi) et plus subtiles (la pression sociale) permettant l’intégration des individus. Le concept de norme diffère d’un pays à un autre. Cependant, bien que ces conventions comportent certains avantages, elles possèdent aussi de nombreux inconvénients, notamment la pression sociale. Vous avez 35 ans et certaines personnes vous alertent : il faut à tout prix trouver un partenaire ! En tant que femme de 36 ans, vous ne souhaitez pas d’enfants et les gens autour de vous s’offusquent. Qui va s’occuper de vous quand vous serez plus âgée ? C’est la nouvelle année, vous avez 24 ans et vous ne sortez pas faire la fête. Les autres vous pensent retraité avant l’âge. La pression sociale vous gâche l’existence ? Comment se libérer de la pression sociale ? \n','<p>Les normes sociales se définissent comme un ensemble de <b>règles</b>, <b>concrètes </b>(la <b>Loi</b>) et plus <b>subtiles </b>(la <b>pression sociale</b>) permettant <b>l’intégration </b>des individus. Le concept de norme <b>diffère </b>d’un pays à un autre. Cependant, bien que ces conventions comportent certains <b>avantages</b>, elles possèdent aussi de nombreux <b>inconvénients</b>, notamment la pression sociale. Vous avez <b>35 ans </b>et certaines personnes vous alertent : il faut à tout prix trouver un <b>partenaire </b>! En tant que <b>femme </b>de<b> 36 ans</b>, vous ne souhaitez pas d’enfants et les gens autour de vous s’offusquent. Qui va <b>s’occuper </b>de vous quand vous serez plus <b>âgée </b>? C’est la <b>nouvelle année</b>, vous avez <b>24 ans </b>et vous ne sortez pas faire la <b>fête</b>. Les autres vous pensent <b>retraité </b>avant l’âge. La pression sociale vous <b>gâche </b>l’existence ? Comment <b>se libérer de la pression sociale ? </b></p>\n<h2>Les normes sociales en détail </h2>\n<p>Voyons déjà ensemble les règles, implicites comme explicites, établies par la société et que nous devrions suivre scrupuleusement. </p>\n<h3>Aller à l’école </h3>\n<p>Dès l’enfance, l’individu est conditionné à aller à l’école. Le fait que certains parents refusent d’y mettre leur petit est extrêmement mal perçu par la société. Cependant, l’école possède tout de même certains avantages. </p>\n<p>En effet, elle permet d’apprendre à l’enfant à vivre avec autrui, à faire preuve de politesse. De plus, les matières apprises (bien que la plupart apparaissent inutiles à l’âge adulte) lui servent à développer son intelligence par l’apprentissage, la mémorisation, le travail. </p>\n<p>Cependant, l’institution scolaire actuelle est loin d’être complète. Pour moi, le système éducatif actuel devrait montrer à l’enfant comment exprimer ses émotions. Il devrait aussi lui enseigner le respect des différences, ce qui éviterait le harcèlement scolaire, accentué avec les réseaux sociaux de nos jours. Il y aurait également lieu de créer des disciplines plus utiles, telles que la pratique de la méditation, du yoga, de l’acceptation et du lâcher-prise, de l’authenticité, etc. et non de ne miser que sur des matières intellectuelles. L’urgence reste de rendre l’être humain plus conscient. </p>\n<p>La pression sociale se fait ressentir à l’école par le fait que l’enfant ne peut pas se montrer tel qu’il est. Aucun comportement déviant n’apparaît possible, au risque de devenir le bouc émissaire du groupe. Il n’a donc d’autre choix que de se comporter comme tout le monde. Car un enfant n’a qu’un désir : se faire accepter des siens et se faire des amis.</p>\n<h3>Se mettre en couple </h3>\n<p>L’enfant grandit. Vers 25 ans et étant célibataire, il commence à constater que la majorité des personnes de son entourage est en couple. En effet, la norme implicite indique qu’il faut se mettre en ménage. Pas trop tôt, parce que sinon, nous ne profitons pas de la vie et pas trop tard, car sinon, nous ne pourrons pas avoir d’enfants. </p>\n<p>Personnellement, je n’ai aucun problème avec le fait d’être en couple, puisque cette situation me procure beaucoup de bien-être. Ressentir de l’amour et tout faire pour son partenaire, se sentir aimé… c’est magique. Par contre, l’amour rend très fragile et vulnérable. L’expression « il/elle est ma moitié » est vraiment à prendre au sens propre. Car nous avons réellement l’impression que l’autre est une partie de nous. Résultat, nous entrons dans la dépendance affective et pensons ne plus rien être sans lui.</p>\n<p>En fait, nous ne choisissons pas la personne avec qui nous partageons notre vie par hasard. Nous la choisissons, car elle comble un besoin et un vide en nous. C’est pourquoi, par exemple, un individu exprimant peu ses émotions se retrouvera avec quelqu’un les extériorisant, au contraire, un peu trop. En résumé, l’autre nous apporte ce que nous sommes incapables de nous apporter nous-mêmes. Toutes les relations chères à notre cœur sont ainsi.</p>\n<p>Par conséquent, si une personne apparaît heureuse seule et sans subir le célibat, pourquoi ne pas la laisser tranquille ? Elle fait plutôt preuve d’une grande force, car elle a appris à s’aimer elle-même sans dépendre des autres. </p>\n<h3>Acheter une maison</h3>\n<p>Une fois en couple, les habitudes sociales disent qu’il est bon d’acheter ou de louer un bien en commun. Louer un appartement, c’est bien, mais devenir propriétaire d’une maison, c’est encore mieux. Quoi de plus normal que de vouloir s’installer avec la personne que l’on aime ? C’est vrai. Mais il faut aussi respecter les couples préférant rester chacun chez soi. Ils sont probablement plus autonomes et peuvent apprendre à combler leurs besoins eux-mêmes. </p>\n<p>Les règles informelles nous poussent à devenir propriétaires. Et c’est très bien de posséder un chez-soi. Cependant, les couples se précipitent bien souvent afin de faire comme tout le monde. Mais la société ne nous explique pas qu’avant d’acheter et de nous endetter sur 20 ans minimum, il aurait peut-être fallu entamer certaines démarches. Par exemple, en étant salariés et chez nos parents, nous ne supportons aucune charge. Nous aurions pu tenter d’entreprendre, d’investir dans l’immobilier, de réaliser ce qui nous fait réellement vibrer, etc. Après, il est toujours possible de vous lancer dans l’entrepreneuriat ou dans ce qui fait vraiment battre votre cœur en étant propriétaire. Mais le faire maintenant demande un courage bien plus grand, car quitter votre emploi de salarié sans rien avoir derrière dans l’immédiat s’avère très risqué. </p>\n<h3>Travailler en restant salarié</h3>\n<p>Vers les dernières années de nos études, les professeurs commencent à nous conditionner pour le monde de l’entreprise. Il existe un service des ressources humaines, un directeur général, un service commercial, un comité d’hygiène, de sécurité et des conditions de travail, etc. Nous apprenons donc gentiment que nous faisons partie d’une classe sociale bien spécifique.</p>\n<p>À les entendre, nous serons forcément salariés et aurons inévitablement un patron. Personne ne nous incite à créer notre propre entreprise, à réaliser ce que nous avons vraiment envie d’accomplir. Au contraire, nous entendons ce genre de phrase : « tu dessines tellement bien, dommage qu’il n’y ait pas de boulot dans ce domaine. Va plutôt dans la comptabilité. Là, il y a des débouchés ». </p>\n<p>Tout est donc organisé pour faire de nous de bons petits salariés dociles et jamais pour nous permettre d’entreprendre, de créer notre vie au lieu de travailler pour quelqu’un. Résultat, quand le jeune adulte termine ses études, il postule pour devenir salarié, sans même se poser une seule fois la question sur le fait de pouvoir construire sa propre existence. Car cette idée ne lui vient même pas à l’esprit. Il n’a pas été conditionné pour ce faire et qu’il ne fait pas partie de cette catégorie. </p>\n<h3>Avoir des enfants </h3>\n<p>Il existe une règle concernant les enfants : il faut un garçon et une fille. Autrement, vous commencez à devenir hors-norme. </p>\n<h4>Ne pas vouloir d’enfants </h4>\n<p>Avoir un enfant est formidable. Donner la vie, transmettre ses croyances, ses valeurs, le voir grandir, réussir… que de fierté ! </p>\n<p>Il est donc inconcevable de ne pas vouloir d’enfants. Un être humain faisant ce choix est considéré comme un individu très égoïste. Et surtout, comment l’individu va-t-il faire, en vieillissant ? Et puis, le but de l’existence, c’est de faire des enfants. Sinon, nous avons raté notre vie. Et je ne parle pas des femmes ne souhaitant pas en avoir. Quelle grande transgression des normes ! Car une femme sans enfants reste incomplète. </p>\n<p>Voilà les préjugés sur ce thème. Premièrement, si une personne ne veut pas faire d’enfants pour rester libre et alors ? Si votre petit représente la plus belle chose qui vous soit arrivée, vous ne devriez pas envier l’autre. Donc, pourquoi ce sujet vous fait-il réagir ? N’existerait-il pas, là aussi, de l’égoïsme à faire un enfant pour qu’il devienne votre bâton de vieillesse ? Quelle vie géniale pour lui ! </p>\n<p>Et qui prétend connaître le but de la vie ? Et si la finalité de l’existence, c’était tout simplement de vivre ? De plus, sachez qu’il existe d’autres moyens de transmettre dans la vie. </p>\n<p>Et concernant le préjugé sur la femme incomplète, la société prouve que la femme reste toujours considérée comme un être inférieur. Elle ne sert qu’à enfanter et à réaliser de simples tâches. La preuve : les hommes ont beaucoup moins de pression que les femmes sur ce sujet. S’ils ne souhaitent pas avoir un enfant, les gens n’en font pas toute une histoire. </p>\n<h4>Ne pas avoir le bon nombre d’enfant(s)</h4>\n<p>Un être humain doit avoir deux enfants. De préférence une fille et un garçon. Là, vous aurez vraiment le profil de la famille Ricoré. Et puis, il ne faut pas qu’ils aient un écart d’âge trop important. Pourquoi ? Je ne sais pas. Car personnellement, je m’entends tellement bien avec mon frère, malgré nos 9 ans de différence ! </p>\n<p>Un enfant ? Mais que s’est-il passé pour que vous n’en vouliez pas un deuxième ? En plus, votre bambin va être pourri gâté et malheureux, sans frères ou sœurs. Euh… le fait qu’un petit soit choyé à outrance ne serait-il pas juste le fruit de l’éducation ? Car un petit dernier d’une fratrie de 10 peut très bien avoir été élevé en enfant-roi. Je ne vois personnellement pas le rapport. L’enfant est-il triste seul ? Et que penser des enfants développant une grande blessure d’abandon dès la naissance de leur frère ou de leur sœur ?</p>\n<p>Trois bambins ? C’est trop. Et puis, tous les défauts et névroses de l’enfant viennent forcément de la mère. D’ailleurs, la société culpabilise énormément les mères, qui ne feront, de toute manière, jamais assez bien.</p>\n<p>Et si faire des enfants ou non, en faire 10 ou 1 n’était qu’une question de choix ? Et si tout le monde devenait assez tolérant pour respecter une vie différente de la sienne ? Personnellement, je pars du principe que tant que chacun est heureux dans sa situation, tout va pour le mieux. </p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"386\" src=\"/storage/blog-images/Conventions-sociales.jpg\" alt=\"Lois\" title=\"Conventions-sociales\">\n<h3>Règles diverses </h3>\n<p>Il existe d’autres règles à adopter pour entrer définitivement dans la normalité. Nous allons en voir quelques-unes ci-dessous.</p>\n<h4>Boire de l’alcool et apparaître sociable</h4>\n<p>Le processus de socialisation passe déjà par le fait de boire de l’alcool lors de soirées ou de repas festifs. Sinon, vous passez automatiquement pour une personne coincée, pas drôle et ne profitant pas de la vie. Cependant, nous sommes d’accord que si une personne boit de l’alcool, ce n’est pas juste pour le goût ? C’est surtout pour engendrer un état interne qu’elle n’est pas capable de se procurer elle-même. C’est-à-dire le lâcher-prise, la détente et surtout, ne plus se soucier du regard de l’autre. Car l’alcool reste un anxiolytique naturel. </p>\n<p>Après, je ne critique pas ce comportement. J’aime également boire mon apéritif le week-end ou lors de repas festifs. Mais juste, ne considérez pas les non-buveurs comme des personnes coincées, pas drôles ou n’ayant rien à vous apporter. Elles sont peut-être, justement, plus évoluées, puisqu’elles arrivent à réguler leur état interne d’elles-mêmes, sans avoir besoin de boire pour créer du lien social.</p>\n<p>Et en plus, il faut apprécier sortir et voir du monde, avoir une vie sociale. Sinon, vous passez pour un être casanier, bizarre et anormal. Il n’est pas bien vu d’aimer rester chez soi et d’être un peu réservé. </p>\n<h4>Partir en vacances </h4>\n<p>Il est obligatoire de partir en vacances lors de congés et surtout, pendant les congés estivaux. Et il faut s’adonner à de nombreuses activités en plus d’aller à la plage et bronzer. Rester chez vous pendant cette période vous fait passer pour un individu bizarre, casanier et ne profitant pas de la vie. Il est de votre devoir de passer des vacances performantes pour ensuite les raconter à autrui. </p>\n<p>La personne casanière ne subissant pas la solitude aime peut-être autrui, mais apprécie de se retrouver seule. Elle n’a sans doute pas besoin de partir en vacances et de bronzer, et alors ? Elle ne vous dérange pas. Son attitude prouve qu’elle n’a pas peur de rester avec elle-même, sans devoir sans arrêt se changer les idées avec autrui pour éviter de regarder à l’intérieur d’elle.</p>\n<h4>Ne pas être homosexuel</h4>\n<p>L’homosexualité est de mieux en mieux perçue par la société. En effet, avant, le DSM (Manuel diagnostique et statistique des troubles mentaux) considérait les homosexuels comme malades mentaux. Vous imaginez ? Un choix de vie s’écartant de la norme, une maladie mentale ? Donc oui, il y a eu de l’amélioration depuis. Du moins, en surface. Car combien de parents se disent ne rien avoir contre les homosexuels, mais n’aimeraient pas que leur enfant le soit ? Pourquoi ? Par conséquent, l’homosexualité reste tout de même encore mal perçue. </p>\n<h4>Célébrer toutes les fêtes commerciales</h4>\n<p>Je vous donne ici quelques exemples de fêtes commerciales que l’on se doit de célébrer. </p>\n<p>Déjà, tout le monde se doit de fêter le Nouvel An, avec énormément de personnes et d’alcool. Rester chez vous au calme ? Vous n’êtes qu’un petit vieux ne profitant pas de la vie.</p>\n<p>Il faut également fêter son anniversaire. Il y a Pâques, où nous sommes obligés d’organiser une chasse aux œufs. Et surtout, Noël. </p>\n<p>Normalement, Noël est censé célébrer la naissance de Jésus. Connaissez-vous une seule personne pratiquant Noël pour cette raison ? Demandez juste à un enfant pourquoi il adore Noël. Pour les cadeaux, oui. Et nous avons tous été conditionnés ainsi. Noël n’est donc plus vraiment une fête religieuse, mais plutôt commerciale. </p>\n<p>Honnêtement, je trouve que hormis les enfants, peu de personnes aiment Noël. Car la plupart des individus n’apprécient pas se retrouver en famille, du fait de nombreuses tensions entre certains membres de la famille. Les mauvais souvenirs peuvent également refaire surface ce jour-là (repenser aux personnes décédées, par exemple). Et puis, il faut acheter des cadeaux pour tout le monde. Courir partout. Décorer le sapin. Préparer le repas. En réalité, Noël est devenu une période très stressante pour bon nombre de personnes. </p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h2>Pourquoi avoir peur de suivre son propre chemin ? </h2>\n<p>Cette peur provient de nos ancêtres. Jadis, une personne ne suivant pas le groupe social finissait seule face à tous les dangers l’entourant (prédateurs, intempéries, etc.) et mourrait. Notre cerveau reptilien a donc gardé ces informations en mémoire. Même si ce fait n’apparaît plus d’actualité. </p>\n<p>Nous n’osons également pas demeurer authentiques à cause de nos blessures. Il s’agit surtout des blessures d’abandon et de rejet subies par le passé, lesquelles déclenchent automatiquement une peur intense d’être abandonné ou rejeté. </p>\n<p>Puis, si vous osez sortir des conventions sociales, vous prenez le risque de passer à l’action. Et vous échouerez forcément quelquefois. Or, de nombreux êtres humains ont horreur de l’échec, puisque la pression sociale leur fait croire que l’insuccès fait d’eux des personnes inférieures. Ils font donc tout pour l’éviter et préfèrent ainsi rester dans la norme. Mais dites-vous bien que vous connaîtrez l’échec même en restant dans les normes. Enfin, ce que vous pensez être un échec du fait de la pression sociale. Car la vie n’est pas un long fleuve tranquille. Vous pouvez perdre votre travail, divorcer, etc. </p>\n<p>Nous pouvons constater cette pression en analysant notre comportement et celui des autres face à l’échec. Nous nous éloignons de nos semblables du fait d’un ego blessé ressentant de la honte, se sentant inférieur. C’est notre ego qui nous pousse à croire que nous vivons un insuccès, alors qu’il ne s’agit que d’une étape dans notre existence nous permettant d’en tirer des leçons, puis de changer notre vie pour le meilleur en passant à l’action.</p>\n<h2>Pourquoi certaines personnes détestent ceux qui osent suivre leur propre chemin ?</h2>\n<p>Pourquoi tant d’intolérance et d’agacement envers la déviance ?</p>\n<p>Premièrement, la personne suivant les normes n’ose pas rester elle-même. Par conséquent, voir une personne oser être déviante malgré le rejet qu’elle subit, c’est lui rappeler sa propre incapacité à rester authentique. Elle en ressent dès lors de l’envie et de la frustration.</p>\n<p>Deuxièmement, qui dit suivre son chemin dit bousculement des règles établies. L’individu se rend compte que d’autres chemins et identités restent possibles. Cette prise de conscience remet ainsi en cause la toute-puissance des normes qu’il suit. Et donc, les choix de vie qu’il a fait jusqu’à maintenant. Le fait de se remettre en question et aussi, de se dire qu’il aurait probablement pu prendre une route qui l’aurait rendu plus heureux apparaît inacceptable pour lui.</p>\n<h2>Les normes sociales sont-elles utiles ? </h2>\n<p>L’existence des normes sociales apparaît quelquefois utile. Elle l’était déjà dans des temps très lointains, lorsque rester en groupe était une question de vie ou de mort. Les conventions lient les individus. Elles demeurent également nécessaires au niveau des Lois collectives, lesquelles servent à maintenir l’ordre social. Je reste persuadée que, malgré que l’utilité des certaines Lois se discute, certaines règles restent indispensables pour garder un pays discipliné. Car oui, si nous assassinions toutes les personnes nous irritant, nous n’aurions pas fini ! Il faut tout de même savoir que dans certaines nations où les Lois ne sont pas d’actualité et où l’être humain est livré à lui-même, c’est ce qu’il se passe.</p>\n<p>D’autres règles, telles que le Code de la route, par exemple, sont primordiales ! Car en cas de non-respect de ces règles, il peut y avoir de lourdes conséquences. Imaginez une seconde si chacun avait des comportements déviants sur la route. Il n’y aurait plus beaucoup de personnes encore en vie, pas vrai ?</p>\n<h2>À quoi sert la pression sociale ? </h2>\n<p>Pourquoi doit-on tous suivre le même chemin, alors que si chacun suivait le sien, le monde serait rempli d’individus singuliers et uniques qui rendraient ce monde plus riche ? Eh bien, pour l’argent. </p>\n<p>Les normes nous font systématiquement prendre la route du salariat, et ce, sans que nous nous posions de questions. Mais pourquoi, à votre avis ? Car s’il n’y avait que des entrepreneurs, il n’y aurait pas d’acheteurs ! Donc, ces normes permettent aux individus riches d’obtenir une population quantitative achetant leurs biens. C’est pour cette raison que dès petits, nous sommes conditionnés à penser pareil. Pour éviter la déviance sociale afin que les publicités puissent toucher émotionnellement tout le monde de la même manière. Idem pour les informations. Les médias montrent ce qu’ils veulent bien nous montrer et souvent, notez qu’il s’agit constamment des mêmes informations. </p>\n<p>En résumé, la société nous incite à acheter des maisons, afin que nous fassions un prêt bancaire. Elle nous exhorte à avoir des enfants pour toujours obtenir de nouveaux consommateurs. Elle nous encourage à sortir les week-ends et à partir en vacances pour dépenser toutes nos économies. Et elle nous pousse à célébrer les fêtes commerciales… pour acheter ! </p>\n<p>Vous l’aurez compris, la société a tout intérêt à conformer les individus de la même manière. Pour qu’il n’y ait pas de rébellion et que les classes sociales riches le restent. </p>\n<img loading=\"lazy\" decoding=\"async\" width=\"640\" height=\"392\" src=\"/storage/blog-images/Normes-sociales.jpg\" alt=\"Regles sociales \" title=\"Normes-sociales\">\n<h2>Les conséquences de la pression sociale </h2>\n<p>Vous le vivez déjà sans doute, mais voyons ici les conséquences pour survenir si vous continuez à subir cette pression sociale. </p>\n<h3>Un risque de burn-out </h3>\n<p>La vie d’aujourd’hui ne laisse pas beaucoup le temps à l’individu de souffler. Je pense notamment aux femmes. En effet, la femme se doit de rester active. De travailler, de s’occuper des enfants, de faire le ménage, de gérer les courses, de faire du sport, de faire l’amour et le tout, en restant souriante et constamment de bonne humeur. Mais vous comprendrez bien qu’une femme reste un être humain. Au bout d’un moment, si elle ne prend pas conscience de la surcharge de ses activités et de l’intériorisation de son mal-être, elle risque le burn-out. Et si elle n’écoute toujours pas ses ressentis, son corps finira par lâcher. </p>\n<h3>Un manque de créativité </h3>\n<p>Lorsque tout le monde a les mêmes comportements, l’individu en tant que tel n’apparaît donc pas authentique. Par conséquent, il y a de fortes chances qu’il ne se connaisse pas et ne sache même pas ce qu’il veut vraiment dans la vie. Ainsi, il se contente de suivre la norme, sans prendre conscience de ce qui le fait vibrer, de ses talents cachés et de ce qu’il pourrait apporter au monde. Il lui manque en fait la petite étincelle, qui est d’oser rester authentique et qui pourrait faire de lui un être complet, montrant sa véritable lumière. Car son réel potentiel reste, bien souvent, caché, et c’est vraiment dommage.</p>\n<h3>Pas de solidarité </h3>\n<p>Les individus vivent tous à peu près pareil. C’est-à-dire en famille, dans l’individualisme et se fichant de plus en plus de tout ce qui les entoure. Vous avez probablement entendu ce genre de propos : « il n’y a que la famille qui compte, les autres on s’en fiche. Vivons pour nous et c’est tout ». D’accord, mais pourquoi vous plaignez-vous ensuite de finir seul ? Eh oui, les enfants grandissent et partent vivre leur vie un jour. Donc, si vous avez tout misé sur votre tribu et êtes devenu individualiste, il y a de grandes chances que vous viviez très mal ces départs. Voyez plus grand. Ouvrez-vous aux autres et au monde. Participez à des groupes pour lesquels vous partagez les valeurs. Inscrivez-vous à une association. Ne vivez pas en reclus, au risque de regretter, plus tard, de ne pas avoir assez exploré la vie. </p>\n<h3>Aucun courage </h3>\n<p>Les êtres humains n’ont donc pas le courage de vivre leur propre vie. Une trop grande peur du rejet les oppresse. Et puisqu’ils comprennent bien ne pas avoir l’audace nécessaire, ils se mettent à envier et à critiquer les personnes osant prendre un chemin différent. Et bien souvent, ces personnes ne cessent de trouver d’innombrables excuses : « j’ai des enfants, j’ai une maison, je ne peux plus faire tout ce que je veux, etc. »</p>\n<h2>Comment se libérer de la pression sociale ? </h2>\n<p>Voici maintenant quelques clés qui vous aideront à vous affranchir de la pression sociale.</p>\n<h3>Pratiquer l’acceptation et le lâcher-prise</h3>\n<p>Si vous avez décidé de stopper le conformisme afin de trouver votre individualité, vous subirez inévitablement du rejet de la part d’individus faisant partie de la norme. De ce fait, il y a lieu d’apprendre à l’acceptation et le lâcher-prise. N’hésitez pas à aller consulter mon <a href=\"/lacher-prise-et-acceptation\" target=\"_blank\" rel=\"noopener\" title=\"Lâcher-prise et acceptation\">article sur ce sujet. </a></p>\n<h3>Pratiquer des techniques de relaxation</h3>\n<p>Pour vous aider à accepter le jugement des normes dominantes, n’hésitez pas à pratiquer des techniques de relaxation, telles que le yoga, la méditation, la sophrologie, etc. À vous de voir quelle(s) méthode(s) vous correspond (ent). Il y a également lieu de travailler sur votre respiration pour retrouver le calme et prendre du recul instantanément. </p>\n<p>Personnellement, afin de bien respirer, je pratique comme méthode la cohérence cardiaque. J’utilise pour m’y aider un petit appareil nommé Zenspire lequel, grâce à sa lumière et ses vibrations, régule ma respiration et de ce fait, me permet de respirer profondémment et surtout, correctement. Si ce produit vous intéresse, n’hésitez pas à cliquer sur le bouton ci-dessous. Et si vous passez commande, vous bénéficierez, grâce au code JL0620, d’une réduction de 10 %.</p>\n<h3>S’affirmer </h3>\n<p>N’est-il pas désagréable de devoir constamment se justifier auprès de vos pairs sur les choix que vous faites dans la vie ? Il est grand tant d’exprimer haut et fort les valeurs qui sont les vôtres ! Pour ce faire, il convient de vous affirmer. C’est ainsi que vous gagnerez le respect des autres. J’ai rédigé un article spécialement sur ce sujet. Si vous souhaitez en savoir plus, c’est<a href=\"/affirmation-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Affirmation de soi\"> ici.</a></p>\n<h3>Se libérer du jugement des autres</h3>\n<p>Il est agréable d’appartenir à des groupes. Cependant, les relations sociales apparaissent bien souvent compliquées de par les jugements de tout un chacun. Il est vrai que quand vous souhaitez devenir vous, le regard des autres s’avère très pesant. Vous serez forcément jugé. Et sachez que vous le serez même si vous vous trouvez à 100 % dans les normes. Donc, mieux vaut être vous et vous libérer du jugement d’autrui. Le processus par lequel vous pouvez acquérir cette liberté est détaillé dans mon article que vous trouverez <a href=\"/jugement-des-autres\" target=\"_blank\" rel=\"noopener\" title=\"Jugement des autres\">ici.</a></p>\n<p>Et si vous souhaitez vraiment entamer un processus de libération concernant le regard des autres, je vous suggère le programme de Didier PENISSARD, coach et auteur dans le domaine du développement personnel. N’hésitez pas à aller y jeter un coup d’oeil en cliquant sur le bouton juste en-dessous :</p>\n<h3>Se libérer de la jalousie et de la comparaison  </h3>\n<p>La comparaison sociale est inutile, car personne n’a le même parcours de vie. Vous ne devez vous comparer qu’à vous-même. Pour plus de renseignements sur ce sujet, je vous invite à aller consulter mon article<a href=\"/se-comparer-aux-autres\" target=\"_blank\" rel=\"noopener\" title=\"Se comparer aux autres\"> ici. </a></p>\n<h3>S’aimer </h3>\n<p>Il n’y a pas besoin d’aller jusqu’à la rupture du lien social pour devenir authentique. Certains espaces de socialisation, comme les associations, sont vraiment bénéfiques pour rendre le monde meilleur. Mais les valeurs et les normes qui sont les vôtres se doivent d’être respectées, et surtout, par vous-même. Et le seul moyen dont vous disposez est de vous aimer. </p>\n<p>Il n’y a qu’en vous aimant que le rejet dont vous ferez quelquefois l’objet restera acceptable pour vous. Tout simplement parce que vous saurez que vous avez pris la bonne décision et que vous n’attendrez plus de recevoir de l’amour de l’extérieur pour vous en donner vous-même. Ce n’est pas les éléments extérieurs qui choisiront votre humeur. C’est vous, à partir de maintenant, qui prenez vos responsabilités en décidant de vous sentir bien.</p>\n<p><b>Se libérer de la pression sociale</b> n’est pas facile. Mais en y arrivant, vous éprouverez une grande paix et gagnerez une liberté qui n’a pas de prix !</p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'Se Libérer de la Pression Sociale, la Clé du Bien-être','Les normes sociales comportent certains avantages, mais aussi un grand inconvénient : la pression sociale. Comment se libérer de la pression sociale ?','https://vivre-pleinement.fr/normes-sociales/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/normes-sociales\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/normes-sociales\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Se Lib\\u00e9rer de la Pression Sociale, la Cl\\u00e9 du Bien-\\u00eatre\",\"datePublished\":\"2020-10-06T19:23:48+00:00\",\"dateModified\":\"2024-02-11T20:02:38+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/normes-sociales\\/\"},\"wordCount\":7760,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/normes-sociales\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/10\\/Liberer-pression-sociale.jpg\",\"articleSection\":[\"D\\u00e9veloppement personnel\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/normes-sociales\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/normes-sociales\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/normes-sociales\\/\",\"name\":\"Se Lib\\u00e9rer de la Pression Sociale, la Cl\\u00e9 du Bien-\\u00eatre\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/normes-sociales\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/normes-sociales\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/10\\/Liberer-pression-sociale.jpg\",\"datePublished\":\"2020-10-06T19:23:48+00:00\",\"dateModified\":\"2024-02-11T20:02:38+00:00\",\"description\":\"Les normes sociales comportent certains avantages, mais aussi un grand inconv\\u00e9nient : la pression sociale. Comment se lib\\u00e9rer de la pression sociale\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/normes-sociales\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/normes-sociales\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/normes-sociales\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/10\\/Liberer-pression-sociale.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/10\\/Liberer-pression-sociale.jpg\",\"width\":640,\"height\":453,\"caption\":\"Comment se liberer de la pression sociale ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/normes-sociales\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Se Lib\\u00e9rer de la Pression Sociale, la Cl\\u00e9 du Bien-\\u00eatre\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2020-10-06 19:23:48',NULL,'2026-05-24 19:19:44','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (32,'Calmer les Angoisses Nocturnes pour Retrouver la Paix','angoisses-nocturnes','Bien souvent, lorsqu’une personne souffre de troubles anxieux, elle peut également être sujette à des angoisses nocturnes. Car toute l’angoisse accumulée n’ayant pu être évacuée la journée se manifeste la nuit. Ce trouble peut être un problème temporaire si, par exemple, la personne subit une période de forte pression. Mais il peut aussi survenir pendant plusieurs nuits et devenir quasi chronique. Cette situation est fâcheuse, dans la mesure où l’individu a besoin de dormir. Vous avez peur de vous endormir puisque vous savez que cette angoisse va apparaître. Avec le cœur qui s’emballe, vous craignez toujours de mourir durant votre sommeil. Vous faites beaucoup de cauchemars et vous réveillez dans cet état de terreur. L’anxiété nocturne vous gâche la vie ? Comment calmer les angoisses nocturnes ? \n','<p>Bien souvent, lorsqu’une personne souffre de <b>troubles anxieux</b>, elle peut également être sujette à des angoisses nocturnes. Car toute l’angoisse <b>accumulée </b>n’ayant pu être <b>évacuée </b>la journée se manifeste la nuit. Ce trouble peut être un problème <b>temporaire </b>si, par exemple, la personne subit une période de forte <b>pression</b>. Mais il peut aussi survenir pendant plusieurs nuits et devenir <b>quasi chronique.</b> Cette situation est fâcheuse, dans la mesure où l’individu a <b>besoin </b>de dormir. Vous avez peur de vous <b>endormir </b>puisque vous savez que cette angoisse va <b>apparaître</b>. Avec le <b>cœur </b>qui s’emballe, vous craignez toujours de <b>mourir </b>durant votre sommeil. Vous faites beaucoup de <b>cauchemars </b>et vous réveillez dans cet état de terreur. L’anxiété nocturne vous gâche la vie ? Comment <b>calmer les angoisses nocturnes ? </b></p>\n<h2>Comment débutent les angoisses nocturnes ?</h2>\n<p>Les angoisses nocturnes poussent la personne à se réveiller en pleine nuit. Une multitude de symptômes accompagnent ledit réveil, tout aussi désagréables les uns que les autres. </p>\n<p>Le réveil peut provenir, à la base, d’un cauchemar. À la longue, des troubles du sommeil peuvent survenir chez l’individu, dont l’insomnie. Du fait de ce sommeil perturbé, la personne tente quelquefois de pratiquer l’autosuggestion avant d’aller de coucher. Elle se dit : « il faut à tout prix que je dorme, comment vais-je être au travail demain sinon ? ». Vous comprenez qu’en vous mettant une telle pression, il y a de fortes chances que votre plan tombe à l’eau. C’est plutôt tout le contraire de ce que vous désirez qui se produira.</p>\n<p>À force, la personne peut commencer à prendre des somnifères (nommés également hypnotiques) afin de pouvoir dormir en paix. J’en ai personnellement déjà pris lors de périodes de grand stress, où je n’arrivais plus à dormir. Et c’est vrai qu’avec, je dormais comme un loir. Cependant, le lendemain, je me sentais tout de même somnolente, coupée de mes émotions. Donc, pourquoi ne pas en prendre si ce médicament vous aide temporairement, mais évitez d’en faire une habitude.</p>\n<h2>Les symptômes de l’anxiété nocturne   </h2>\n<p>Les angoisses nocturnes sont des terreurs survenant en pleine nuit. </p>\n<p>L’endormissement peut déjà s’avérer compliqué. En effet, aller se coucher et s’endormir en n’étant pas vraiment relaxé et avec des soucis en tête peut difficilement faire venir un sommeil profond et réparateur. Forcément, le réveil nocturne peut apparaître. Voyons maintenant les principaux symptômes pouvant être ressentis dont certains, vous le remarquerez, sont similaires à ceux apparaissant lors d’une crise de panique : </p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">Réveil brutal accompagné d’un fort sentiment de mal-être. Des cauchemars récurrents peuvent être la cause de ce rude réveil ;</li>\n<li aria-level=\"1\">Grande sensation d’irréalité ;</li>\n<li aria-level=\"1\">Transpiration abondante, sueurs ; </li>\n<li aria-level=\"1\">Palpitations ;</li>\n<li aria-level=\"1\">Respiration difficile ;  </li>\n<li aria-level=\"1\">Nausées voire même, vomissements ;  </li>\n<li aria-level=\"1\">Tremblements musculaires ; </li>\n<li aria-level=\"1\">Présence d’acouphènes ;</li>\n<li aria-level=\"1\">Peur intense de devenir fou ou de mourir.</li>\n</ul>\n<h2>Conséquences de l’angoisse nocturne</h2>\n<p>Dans ces conditions, des conséquences négatives vont forcément survenir, et ce, dès le lendemain. Voyons ci-dessous lesquelles : </p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">Grande fatigue dès le réveil et persistant la journée ; </li>\n<li aria-level=\"1\">Angoisse décuplée dans la journée due au manque de sommeil. De plus, bien souvent, lorsqu’une personne souffre d’angoisses nocturnes, elle souffre également <a href=\"/angoisse-matinale\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse matinale\">d’anxiété matinale ; </a></li>\n<li aria-level=\"1\">Irritabilité ; </li>\n<li aria-level=\"1\">Insomnies chroniques ;  </li>\n<li aria-level=\"1\">Épuisement psychique et physique du fait de l’angoisse et du manque de sommeil. À la longue, des troubles anxieux tels que TOC, phobie, phobie sociale voire même, une dépression, peuvent apparaître. </li>\n</ul>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"334\" src=\"/storage/blog-images/Crise-angoisse-nocturne.jpg\" alt=\"Stress nocturne \" title=\"Crise-angoisse-nocturne\">\n<h2>Comment calmer les angoisses nocturnes ? </h2>\n<p>Afin de vaincre votre anxiété nocturne une bonne fois pour toutes et de retrouver un sommeil réparateur dans les bras de Morphée, je vous ai concocté une liste de solutions. </p>\n<h3>Pratiquer le lâcher-prise  </h3>\n<p>Lorsque vos angoisses nocturnes arrivent, vous devez déjà les accepter et attendre qu’elles passent. Car il est impossible de rationaliser la nuit et donc, de vous calmer et tenter de vous rassurer par le biais de votre mental. Et il existe une explication scientifique à ce phénomène. </p>\n<p>En effet, la nuit, le corps sécrète beaucoup plus de mélatonine, l’hormone du sommeil. Cependant, cette hormone endort totalement votre côté rationnel. Voilà pourquoi vos peurs et les situations qui vous préoccupent vous paraissent bien plus graves qu’elles ne le sont en réalité. Vous constaterez d’ailleurs qu’en pleine journée, vous ne les percevez pas de manière si catastrophique. </p>\n<h3>Se lever du lit <b> </b></h3>\n<p>Pour vous aider à calmer votre angoisse nocturne, vous pouvez vous lever et vous occuper. Allez boire un verre d’eau, allez aux toilettes, mettez de l’eau sur vos poignets, ouvrez une fenêtre, prenez l’air frais, regardez la télévision, bouquinez… occupez-vous un temps, et ce, afin de faire diminuer vos symptômes somatiques.</p>\n<p>Une bonne méthode pour les faire disparaître est de juste les observer et ce, tout en vous blottissant sous un plaid et en vous prenant dans les bras. Concentrez-vous sur les sensations physiques que vous ressentez, et ce, jusqu’à ce qu’elles partent. Il n’y a qu’ensuite que vous pourrez recommencer à rationaliser à nouveau. Car, tant que votre corps n’est pas calmé, vous ne pouvez espérer retrouver un mental calme. </p>\n<h3>Apprendre à bien respirer </h3>\n<p>C’est seulement lorsque votre corps est détendu que les méthodes de relaxation fonctionnent. Vous pouvez donc maintenant pratiquer des techniques de respiration. La respiration reste en effet une puissante méthode pour apaiser votre organisme. Essayez déjà de respirer un peu dans vos mains. Pour plus de renseignements et de conseils pour apprendre à respirer correctement et profondément, je vous invite à aller consulter mon <a href=\"/respiration\" target=\"_blank\" rel=\"noopener\" title=\"Respiration\">article</a> sur le sujet. </p>\n<p>Personnellement, je pratique la cohérence cardiaque. Et j’utilise, pour m’y aider, un petit appareil nommé Zenspire. Celui-ci, grâce à sa lumière et à ses vibrations, m’aide à bien réguler ma respiration en me faisant suivre un certain rythme. Je respire donc profondément et calmement grâce à son aide. Et je vous assure qu’en utilisant cette méthode juste avant d’aller vous coucher, il y a de fortes chances que vous vous endormiez rapidement ! Si ce produit vous intéresse, n’hésitez pas à cliquer sur le bouton ci-dessous, étant précisé que si vous passez commande, vous bénéficierez d’une remise immédiate de 10 % grâce au code JL0620.</p>\n<h3>Se renseigner sur l’apnée du sommeil </h3>\n<p>Si vous vous sentez très anxieux le matin et que vous souffrez également d’angoisses nocturnes, l’élément déclencheur peut être l’apnée du sommeil. Ce syndrome est dû à la survenue, durant la nuit, de pauses respiratoires fréquentes et anormales. Et ce trouble peut provoquer les mêmes effets qu’une crise d’angoisse, avec bon nombre de sensations désagréables pouvant être ressenties le lendemain. Il peut s’agir de maux de tête, de fatigue, de somnolence, d’anxiété, etc. Je vous conseille de vous renseigner à cet égard, déjà sur Internet et ensuite chez un spécialiste de la santé si vous pensez qu’il est possible que ce trouble vous concerne.  </p>\n<h3>Pratiquer des techniques de relaxation </h3>\n<p>Pour diminuer votre angoisse chronique, il est essentiel de pratiquer des techniques de relaxation. Il est bon, si vous le pouvez, de vous relaxer dès le lever et également le soir, et ce, afin de mieux vivre votre journée et de réduire les tensions qui se sont accumulées. À vous d’essayer diverses techniques de relaxation pour trouver celle(s) qui vous correspond (ent). Il y a le yoga, la méditation, la sophrologie, la méthode Jacobson… cette pratique consiste à contracter à fond ses muscles puis à les relâcher dans le but de ressentir une grande détente.</p>\n<p>Si vous vous sentez vraiment trop anxieux, évitez, dans un premier temps, la méditation profonde ou certaines formes de yoga trop intenses. En effet, ces pratiques pourraient vous angoisser encore plus. Essayez déjà quelques relaxations plus douces qui soulageront votre corps, comme la méthode Jacobson, le hatha-yoga, le tai-chi, etc.</p>\n<p>Vous pouvez également vous servir d’huiles essentielles pour vous détendre. N’hésitez pas à aller vous renseigner sur les différents types d’huiles qui pourraient vous correspondre sur Internet. </p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h3>Manger léger le soir </h3>\n<p>Il est bon, afin d’atténuer votre angoisse, d’opter pour une bonne hygiène de vie. Le soir, si vous mangez trop, votre estomac aura beaucoup de mal à digérer. Il va donc être très difficile pour vous de trouver le sommeil. Réalisez l’expérience de manger plus léger, vous ne vous en porterez que mieux. </p>\n<p>Pourquoi ne pas également mettre en place un rituel nocturne avant d’aller vous coucher ? Vous pouvez, par exemple, prendre une tisane pour dormir ou pour faciliter la détente. Les infusions conseillées sont la lavande, la passiflore, la camomille, la valériane, le tilleul, la mélisse, l’aubépine et la verveine. Je vous assure que certaines font dormir !  </p>\n<h3>Éviter les écrans le soir </h3>\n<p>Le soir, il y a lieu d’opter pour une bonne hygiène de sommeil. Évitez les écrans, qui gardent votre organisme trop éveillé. Les jeux vidéos vous demandent de la concentration et vous rendent, par conséquent, trop actif. Vous pouvez éventuellement regarder la télévision, même si ce n’est pas le top, car elle rend plus passif. D’ailleurs, vous vous êtes sans doute déjà endormi devant la télé.</p>\n<p>Évitez aussi le téléphone et les réseaux sociaux. Car les échanges avec autrui vont vous rendre également trop actif. Et si vous commencez à scruter la vie des autres juste avant de dormir, vous risquez de tomber dans le piège de la comparaison sociale. Et vu que les individus ne montrent que leurs réussites sur les réseaux, vous allez certainement penser que votre existence est médiocre. Vous pouvez donc commencer à déprimer et ruminer. </p>\n<p>Le mieux, le soir, reste de vous adonner à une activité qui peut vous détendre, comme lire un bon bouquin dans votre lit. Ou pratiquer des techniques de relaxation.</p>\n<h3>Stopper les ruminations </h3>\n<p>Afin de diminuer votre angoisse de manière générale et de retrouver un bon sommeil, il devient urgent de réduire vos <a href=\"/ruminations\" target=\"_blank\" rel=\"noopener\" title=\"Ruminations\">ruminations</a>. Car avec un système nerveux en alerte, il est difficile d’y arriver. </p>\n<h4>Utiliser des affirmations positives</h4>\n<p>N’hésitez pas à user d’affirmations positives. Forcez-vous à penser positif, à éprouver de la gratitude pour ce que vous avez déjà. </p>\n<p>Je ne parle pas là de la pensée positive qui consiste à complètement nier le négatif de votre existence. Il s’agit de ce genre de phrases : « la vie est toujours belle, tout le monde est beau, etc. ». Je parle plutôt des affirmations positives nuancées. Par exemple : « actuellement, ma vie est difficile. Je subis une forte pression, mais je sais que c’est juste un mauvais moment à passer. Je vais faire de mon mieux en attendant des jours meilleurs ». Car si vous n’êtes pas un minimum réaliste, votre cerveau ne croira pas à ce que vous vous dites. Le but n’est donc pas de nier le négatif de votre vie, mais de l’accepter et de faire de votre maximum pour changer la situation. </p>\n<h4>Pratiquer la visualisation </h4>\n<p>Vous pouvez aussi pratiquer des techniques de visualisation positive. Par exemple, si un événement à venir vous angoisse, essayez de l’imaginer se produire, dans les moindres détails. Imaginez les sons, les odeurs, les scènes, et ce, comme si tout allait bien se passer. Ou encore, visualisez un endroit qui vous apaise en imaginant toutes les sensations que vous ressentez à ce moment. Il peut s’agir d’un lieu fictif, ou que vous connaissez déjà et qui vous rassure. Évitez juste votre chambre, qui reste un cadre un peu trop connu et qui ne vous soulage pas vraiment si vous souffrez d’angoisses nocturnes. Cette méthode peut vous détendre instantanément. </p>\n<img decoding=\"async\" width=\"640\" height=\"425\" src=\"/storage/blog-images/Terreur-nocturne.jpg\" alt=\"Reveil en sursaut impression de mourir \" title=\"Terreur-nocturne\">\n<h3>Suivre une thérapie</h3>\n<p>Si vos angoisses nocturnes vous gâchent trop la vie, vous pouvez vous faire aider par un professionnel de la santé pratiquant la TCC (thérapie comportementale et cognitive). Je parle de ce sujet plus en détail dans <a href=\"/psychotherapie-et-psychanalyse\" target=\"_blank\" rel=\"noopener\" title=\"Psychothérapie et psychanalyse\">cet article.</a> Cette thérapie vous permettra de travailler sur votre anxiété chronique et par la même occasion, sur vos angoisses nocturnes qui ne restent qu’un symptôme. Le thérapeute peut également coupler cette pratique avec un traitement<b>,</b> tel qu’antidépresseurs et/ou anxiolytiques (appelés également benzodiazépines) si besoin. Ces médicaments pourront vous servir de béquille afin d’avoir la force de pratiquer les exercices proposés dans la thérapie. </p>\n<p>Et en complément, vous pouvez aussi essayer les thérapies alternatives, comme l’homéopathie (se soigner par les plantes) ou encore, l’hypnose.</p>\n<h3>Prendre soin de soi</h3>\n<p>Afin de retrouver un sommeil de qualité, il est urgent de commencer à vous occuper de vous. </p>\n<h4>Prendre des pauses </h4>\n<p>Si vous travaillez, n’hésitez pas à prendre des pauses régulièrement. Au moins une toutes les deux heures. Ainsi, vous casserez le cycle de la tension pouvant s’accumuler dans la journée. Sortez prendre l’air si vous le pouvez (et pas forcément pour fumer), étirez-vous sur votre siège, levez-vous pour passer un petit coup d’eau sur les poignets, mangez…</p>\n<h4>S’accorder du plaisir et régler les problèmes</h4>\n<p>Accordez-vous du plaisir. Ayez des loisirs. C’est très important. Ces activités redonneront un peu de joie dans votre vie. De plus, les angoisses nocturnes pouvant provenir de soucis réels, il convient de régler les problèmes que vous avez dans votre existence, si vous le pouvez. Ou de vous faire aider par un professionnel de la santé si vous en ressentez le besoin. Car le souci ne fera qu’impacter votre sommeil. </p>\n<h4>Définir ses objectifs</h4>\n<p>Définissez vos propres buts et objectifs et non ceux exigés par la norme vous provoquant une énorme pression sociale. Car si vous vivez votre vie comme les autres sans vous poser la question de ce qui est bon ou pas pour vous, l’amertume vous gagnera à coup sûr. Restez vous-même. Vous ne voulez pas être en couple ? Restez célibataire ! Vous ne souhaitez pas d’enfants ? N’en faites pas ! Vous désirez devenir autoentrepreneur malgré que votre entourage prétend que c’est impossible ? Suivez votre cœur ! Vous l’avez compris : empruntez votre propre chemin. </p>\n<p>Le seul inconvénient à suivre sa voie est de subir inévitablement, de la plupart des gens dans la norme, du rejet. Car ces personnes n’osent pas vivre leur vie et donc vous envieront. Cependant, mieux vaut être heureux même si nous nous faisons rejeter par certaines personnes plutôt que d’être acceptés par elles, mais être malheureux. La vie est courte, vivez là à fond !  </p>\n<a href=\"https://hypnocaments.com?partnerid=YK5muYugzSoIWDbDWRgT-Q\" title=\"Seances d hypnose en ligne\"><img decoding=\"async\" src=\"https://hypnocaments.com/image/banner_1_750.png\" alt=\"seance hypnose mp3\"></a>\n<h3>Respecter son rythme circadien </h3>\n<p>Lorsque vous souffrez d’angoisses nocturnes, mieux vaut ne pas trop dérégler votre cycle circadien. Les perturbations de l’horloge biologique restent en effet un bon élément déclencheur auxdites angoisses, allant même jusqu’à les empirer. Il y a donc déjà lieu de vous demander si vous êtes une personne plutôt matinale ou vespérale (du soir). Et à partir de là, essayez de vous conformer à votre rythme naturel. Si vous travaillez, vous ne pouvez pas toujours faire comme vous le voulez. Mais faites de votre mieux pour vous en rapprocher, les jours où vous le pouvez.</p>\n<p>Respecter les cycles de sommeil demeure également très important. Vous avez déjà dû entendre dire qu’il fallait se coucher dès lors que vous ressentez de la fatigue. Il est vrai qu’en agissant ainsi, vous vous endormirez instantanément. Mais si l’heure à laquelle vous vous couchez apparaît trop différente de votre heure habituelle, votre rythme circadien va s’en trouver trop perturbé et vous ne vous sentirez pas bien ensuite. Par exemple, si vous rentrez du travail à 17 h et que vous avez vraiment envie de dormir, aller au lit à 17 h risque de complètement dérégler votre horloge biologique. Mieux vaut attendre que la fatigue passe et vous rendormir quand vous êtes fatigué, mais vers vos heures habituelles.</p>\n<p>Et si possible, essayez de respecter vos heures de sommeil. La moyenne recommandée est 8 h. Mais honnêtement, tout dépend des individus. Certains sont en effet de petits dormeurs et ne dorment que 4 h tandis que d’autres ont besoin de 10 h de sommeil. Il n’y a pas de règles. Je pense que vous connaissez le nombre approximatif d’heures de sommeil qui vous sont nécessaires.</p>\n<h3>Avoir des relations </h3>\n<p>Avoir des relations, communiquer et donc, vous changer les idées peut vous vider un peu la tête au coucher. Résultat, vous dormez mieux. Attention cependant au type de discussion que vous avez et surtout en soirée, juste avant d’aller dormir. En effet, si vous parlez de vos problèmes anxieux, comment voulez-vous penser plus positivement ? Il est bon, quelquefois, d’en parler, car l’écoute empathique et la bienveillance d’autrui vous sont d’une grande aide. Mais ne tombez pas dans le piège de vouloir vous faire rassurer en permanence. </p>\n<p>Je parle en connaissance de cause. Cette attitude entretient inévitablement votre anxiété, il est impossible de vous en sortir dans ces conditions. Oui, quand vous en avez pris l’habitude, il reste extrêmement difficile de cesser de vous faire rassurer. Mais allez-y progressivement. Par exemple, essayez de ne plus vous faire rassurer le soir, mais continuez pour le moment le matin. </p>\n<h3>Faire la sieste modérément </h3>\n<p>Vous avez sûrement déjà entendu plusieurs sons de cloches concernant la sieste. Certains vous diront qu’il est nécessaire d’en faire une tous les jours. D’autres prétendront qu’il ne faut jamais en faire, au risque de ne pas dormir la nuit. Nous ressentons, de toute manière, tous un coup de pompe après manger, en début d’après-midi. Je pense qu’il est judicieux de faire un somme à ce moment afin de retrouver de l’énergie, si vous le pouvez. Mais pas plus d’un quart d’heure, voire une demi-heure. Car une sieste plus longue risque de dérégler votre horloge biologique et de vous empêcher de dormir au coucher. </p>\n<h3>Rendre sa chambre confortable</h3>\n<p>Vous devez vous douter que la qualité du sommeil dépend également d’une bonne literie. Forcément, avec une literie de mauvaise qualité, vous risquez de ressentir des fourmillements dans votre corps, ainsi que des douleurs le lendemain. Et le fait de ressentir de l’inconfort ne vous aidera pas à voir l’heure du coucher comme un moment de paix et de détente. Essayez donc de vous procurer de bons oreillers et matelas. </p>\n<p> </p>\n<p>J’espère que cet article vous a donné assez de clés pour <b>calmer les angoisses nocturnes</b> qui vous assaillent. Je vous souhaite dorénavant de passer d’agréables nuits ! </p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'Calmer les Angoisses Nocturnes pour Retrouver la Paix','Lorsqu’une personne souffre de troubles anxieux, elle peut aussi être sujette à des angoisses nocturnes. Comment calmer les angoisses nocturnes ?','https://vivre-pleinement.fr/angoisses-nocturnes/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/angoisses-nocturnes\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/angoisses-nocturnes\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Calmer les Angoisses Nocturnes pour Retrouver la Paix\",\"datePublished\":\"2020-09-24T19:12:24+00:00\",\"dateModified\":\"2024-02-13T17:11:32+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/angoisses-nocturnes\\/\"},\"wordCount\":5766,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/angoisses-nocturnes\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/09\\/Calmer-angoisses-nocturnes.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/angoisses-nocturnes\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/angoisses-nocturnes\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/angoisses-nocturnes\\/\",\"name\":\"Calmer les Angoisses Nocturnes pour Retrouver la Paix\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/angoisses-nocturnes\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/angoisses-nocturnes\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/09\\/Calmer-angoisses-nocturnes.jpg\",\"datePublished\":\"2020-09-24T19:12:24+00:00\",\"dateModified\":\"2024-02-13T17:11:32+00:00\",\"description\":\"Lorsqu\\u2019une personne souffre de troubles anxieux, elle peut aussi \\u00eatre sujette \\u00e0 des angoisses nocturnes. Comment calmer les angoisses nocturnes\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/angoisses-nocturnes\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/angoisses-nocturnes\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/angoisses-nocturnes\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/09\\/Calmer-angoisses-nocturnes.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/09\\/Calmer-angoisses-nocturnes.jpg\",\"width\":640,\"height\":457,\"caption\":\"Comment calmer les angoisses nocturnes ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/angoisses-nocturnes\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Calmer les Angoisses Nocturnes pour Retrouver la Paix\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2020-09-24 19:12:24',NULL,'2026-05-24 19:19:44','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (33,'Angoisse Matinale : se Libérer de ce Fardeau pour Retrouver la Paix','angoisse-matinale','Les personnes souffrant de troubles anxieux peuvent aussi souffrir d’angoisse matinale. Je ne connais que trop bien cette grande appréhension ressentie dès le réveil, laquelle peut survenir même si tout a l’air d’aller bien. Quelle sensation désagréable que de se faire agresser de la sorte ! Comment espérer passer une bonne journée dans ces conditions ? Vous vous endormez facilement, mais vers 4 h du matin, vous vous réveillez et impossible de vous rendormir. Vous êtes en proie à des angoisses irrationnelles, avez des nausées, des tremblements, des diarrhées… lorsque le lever du jour approche, vous n’avez aucune énergie et vous vous demandez comment vous allez pouvoir tenir le coup toute la journée. Vous en avez assez de cette anxiété ressentie presque tous les matins ? Comment soigner l’angoisse matinale ? \n','<p>Les personnes souffrant de <b>troubles anxieux </b>peuvent aussi souffrir d’angoisse matinale. Je ne connais que trop bien cette grande <b>appréhension </b>ressentie dès le réveil, laquelle peut survenir même si tout a l’air d’aller <b>bien</b>. Quelle sensation désagréable que de se faire <b>agresser de la sorte </b>! Comment espérer passer une bonne journée dans ces conditions ? Vous vous endormez <b>facilement, </b>mais vers <b>4 h</b> du matin, vous vous réveillez et <b>impossible </b>de vous rendormir. Vous êtes en proie à des angoisses <b>irrationnelles</b>, avez des <b>nausées</b>, des <b>tremblements</b>, des <b>diarrhées… lorsque </b>le lever du jour approche, vous n’avez aucune <b>énergie </b>et vous vous demandez comment vous allez pouvoir <b>tenir </b>le coup toute la <b>journée</b>. Vous en avez assez de cette anxiété ressentie presque tous les matins ? Comment soigner l’<b>angoisse matinale </b>? </p>\n<h2>Le cercle vicieux de l’angoisse matinale </h2>\n<p>La personne sujette à ce trouble ressent déjà, à la base, une angoisse diffuse. Par conséquent, elle éprouve bien souvent des difficultés d’endormissement, ressassant ses soucis sans relâche. Et quand elle arrive enfin à trouver le sommeil, il n’est pas rare que cette personne se réveille subitement, prise en plus <a href=\"/angoisses-nocturnes\" target=\"_blank\" rel=\"noopener\" title=\"Angoisses nocturnes \">d’anxiété nocturne.</a> Forcément, comment voulez-vous vous réveiller dans de bonnes conditions ? De ce fait, au petit matin, l’individu est en proie à une peur intense, laquelle peut s’apparenter à une crise de panique. </p>\n<p>Donc, en étant déjà anxieux à la base, votre nuit s’en trouvera inévitablement perturbée et bien évidemment, votre réveil également. Et bien sûr, votre journée ! </p>\n<h2>Les symptômes de l’angoisse au réveil </h2>\n<p>Les symptômes de l’angoisse matinale peuvent être les suivants :</p>\n<h3>Symptômes somatiques </h3>\n<p>– Palpitations cardiaques et impression d’oppression au niveau de la poitrine ; </p>\n<p>– Sueurs ; </p>\n<p>– Diarrhées ;</p>\n<p>– Tremblements, spasmes musculaires incontrôlables ; </p>\n<p>– Maux de tête, migraines, lesquels peuvent devenir chroniques ; </p>\n<p>– Nausées voire vomissements ; </p>\n<p>– Vertiges ; </p>\n<p>– Sensation d’étouffement, difficulté à respirer, hyperventilation. </p>\n<p> </p>\n<p>Ces symptômes sont logiques. En effet, lorsque vous subissez une anxiété matinale, l’organisme réagit de la même manière qu’une crise d’angoisse ordinaire. L’ensemble du corps s’emballe, ce qui peut ainsi expliquer les diarrhées et les nausées. L’estomac étant trop sollicité pour fonctionner calmement et correctement, il rejette donc ce qu’il a en lui.</p>\n<h3>Symptômes émotionnels </h3>\n<p>– Panique ; </p>\n<p>– Grand mal-être<b>, </b>sensation d’insécurité ; </p>\n<p>– Irritabilité ; </p>\n<p>– Pleurs ; </p>\n<p>– Ruminations ; </p>\n<p>– Baisse de concentration ; </p>\n<p>– Relations sociales difficiles ; </p>\n<p>– Troubles de l’appétit ; </p>\n<p>– Perte de l’estime de soi. </p>\n<p> </p>\n<p>Ces manifestations émotionnelles se retrouvent également dans le cas d’une crise d’angoisse ordinaire, avec cette sensation de perdre le contrôle de soi, de son corps. Forcément, à la longue, des symptômes plus larges comme un manque de concentration, d’estime de soi ou de grandes ruminations peuvent apparaître. </p>\n<h2>Les conséquences de l’angoisse matinale  </h2>\n<p>Si vous faites une angoisse matinale une fois dans votre vie, il n’y aura pas de répercussions sur le long terme. Mis à part de la fatigue, un manque de concentration et de l’irritabilité dans la journée s’ensuivant. C’est la répétition des angoisses matinales qui s’avère problématique. Voyons ensemble les conséquences pouvant s’ensuivre pour vous à la longue.</p>\n<p>L’épuisement émotionnel peut vous guetter, ce qui est logique. Car commencer la journée de manière si odieuse est une drôle de façon de démarrer. Comment voulez-vous vous sentir bien, mentalement et émotionnellement, en peinant tous les matins de la sorte ? </p>\n<p>Du fait de cet épuisement nerveux, vous vous sentez sous tension permanente. Votre état de nervosité quotidienne vous mène à l’irritabilité, ce qui peut nuire à vos relations.</p>\n<p>Et avec toute cette tension et ces ruminations, vous pouvez être sujet à des troubles du sommeil, de l’insomnie. Puis, à force de ne pas réussir à dormir, votre fatigue mentale devient de plus en plus importante. De ce fait, vous commencez à prendre des somnifères, seul moyen que vous avez trouvé pour retrouver, un tant soit peu, le repos. Sauf que pendant la journée, suite aux effets du médicament, vous pouvez tout de même ressentir de la somnolence. </p>\n<p>Ce cercle vicieux peut devenir pathologique et vous faire développer une anxiété permanente (si ce n’est pas déjà le cas). D’autres troubles peuvent également s’ajouter, comme la phobie, la dépression, l’agoraphobie, la phobie sociale, les TOC, etc. Il est donc urgent, pour vous, de régler ce problème.</p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"426\" height=\"640\" src=\"/storage/blog-images/Chronotype.jpg\" alt=\"Angoisse au reveil \" title=\"Chronotype\">\n<h2>Comment soigner l’angoisse matinale ? </h2>\n<p>L’angoisse matinale ne restant qu’un symptôme, la vaincre ne rime à rien. Il faut apprendre à gérer votre anxiété dans sa globalité. Pour y arriver, voici les clés que je peux vous proposer.</p>\n<h3>Être aligné avec soi-même  </h3>\n<p>Quelquefois, vous souffrez d’angoisse matinale, car vous n’éprouvez pas de plaisir à vivre la journée qui s’annonce. Et si vous manquez de motivation, c’est parce que votre vie actuelle ne vous convient pas. Aimez-vous votre travail ? Les activités que vous réalisez dans la journée ? Votre entourage vous correspond-il ? Analysez donc déjà votre existence et voyez s’il n’existe pas un élément déclencheur à votre mal-être. De là, commencez à passer à l’action pour changer cette situation. Il n’y a pas forcément tout à modifier.</p>\n<p>Il est important de vous trouver un but qui vous donnera l’envie de vous lever le matin. Avoir un objectif, et surtout, vivre pleinement le processus vous permettant de l’atteindre progressivement demeure primordial pour une vie épanouie. C’est donc le moment de vous questionner sur l’existence que vous menez. </p>\n<h3>Combattre les idées reçues sur le sommeil </h3>\n<p>Avez-vous déjà entendu parler du chronotype ? Voyons cet élément plus en détail. Vous verrez ainsi que les idées préconçues sur le sommeil ne sont pas forcément faites pour vous. </p>\n<h4>L’idée de devoir se lever tôt pour être épanoui </h4>\n<p>Bon nombre d’individus dans le milieu du développement personnel vous diront que pour vous sentir bien dans votre vie, il faut se lever tôt. Il s’agirait de l’une des clés pour atteindre l’épanouissement. Je ne suis pas d’accord avec cette affirmation. Car pour moi, chaque personne est différente. Il y a des petits dormeurs. Des gros dormeurs. Des personnes plutôt matinales et d’autres, plus vespérales (du soir). Oubliez donc les recommandations toutes faites, puisqu’elles ne vous correspondent pas forcément. </p>\n<p>Pour ma part, je suis du soir. Et je ressens tout de suite une meilleure forme physique et mentale, lorsque je respecte mon chronotype. Si je me lève tôt et me couche de bonne heure, mon humeur s’en voit fortement impactée. J’apparais plus productive au coucher du soleil. Tout est plus calme, je me sens plus détendue. Je déteste ne pas avoir de temps pour moi le soir. Pour les matinaux, ils pensent exactement comme moi, mais à l’inverse pour le matin. </p>\n<h4>Se coucher dès que la fatigue apparaît </h4>\n<p>La recommandation que l’on entend de plus en plus est de dormir lorsque l’on se sent fatigué. Je ne suis pas trop d’accord avec cette affirmation également. Car si vous rentrez du travail et avez un gros coup de barre à 19 h, vous allez donc vous coucher à cette heure-là et le lendemain vers 23 h ? Le rythme de sommeil va être trop déréglé.</p>\n<p>Personnellement, si je procède ainsi, il y a de fortes chances que j’attrape une migraine dans les 2-3 jours à venir. Par conséquent, si vous en avez la possibilité, essayez de dormir suffisamment et à un rythme régulier, si possible, au risque de vous sentir déphasé dans les jours qui suivent. Cependant, il n’est pas toujours simple de le faire. Dans ce cas, apprenez à être tolérant avec vous-même et faites juste de votre mieux pour l’instant.</p>\n<h3>Accepter et laisser passer l’angoisse matinale </h3>\n<p>L’acceptation reste la clé principale pour résoudre bon nombre de problèmes émotionnels. C’est également valable pour l’angoisse matinale. </p>\n<h4>L’explication scientifique de l’anxiété au réveil </h4>\n<p>L’angoisse matinale commence vers 3-4 h du matin environ. C’est à partir de ces heures-là que l’individu va commencer à penser à la journée qui s’annonce. Sauf que cette anticipation est vue avec les yeux de la peur. Cette personne va imaginer cette journée au travers de nombreuses pensées négatives et surtout, incontrôlables.</p>\n<p>Il existe en réalité, une explication scientifique à ce phénomène. En fait, vers 4 h du matin, l’organisme produit principalement de la mélatonine, l’hormone du sommeil. Il y a également un pic de cortisol le matin, l’hormone du stress. Et donc, le corps manquant clairement de sérotonine à ce moment (l’hormone du bien-être), les personnes anxieuses peuvent être sujettes à des crises de panique matinales. Et à ce moment-là, inutile d’essayer de vous raisonner avec des pensées rationnelles. C’est impossible. Vous ne pouvez penser que de manière irrationnelle. </p>\n<h4>Stopper les ruminations mentales </h4>\n<p>Si vous n’arrivez vraiment plus à dormir, assailli par des angoisses irrationnelles, n’hésitez pas à couper ce cercle vicieux en vous levant. Vous pouvez, par exemple, regarder un peu la télévision, prendre l’air frais en ouvrant votre fenêtre, vous mettre de l’eau froide sur les poignets… et si vous ressentez des manifestations somatiques comme des tremblements, vous pouvez vous asseoir sur votre canapé, vous blottir dans un plaid et vous prendre dans les bras. Focalisez vous sur vos symptômes somatiques et rien d’autre et ce, jusqu’à ce que votre corps revienne à la normale. De toute manière, vous ne pouvez pas rationaliser pendant une crise de panique. Il y a donc déjà lieu de calmer les troubles physiques. N’hésitez pas à essayer ces méthodes, car elles fonctionnent ! </p>\n<h4>Vivre au mieux la journée </h4>\n<p>Même si vous êtes très angoissé en vous levant, acceptez de vous sentir ainsi. Dites-vous que cette situation demeure passagère et vivez votre journée comme d’habitude. Car si vous commencez à fuir devant certaines tâches à accomplir, l’angoisse n’est pas prête de disparaître ! Ne perdez pas espoir et faites de votre mieux, et ce, malgré votre état de stress et de fatigue.</p>\n<h3>Pratiquer des techniques de relaxation </h3>\n<p>Il est bon de calmer l’anxiété de manière globale et non de se focaliser uniquement sur l’angoisse matinale. Il est donc conseillé de pratiquer des techniques de relaxation, le soir en vue de décompresser pour la nuit, mais également au réveil.</p>\n<p>Libre à vous d’effectuer une activité qui vous correspond : méditation, yoga, sophrologie, etc. la méthode Jacobson est vivement conseillée pour soulager l’angoisse. Il s’agit de contracter à fond ses muscles un par un puis de les détendre. N’hésitez pas à aller vous renseigner sur cette méthode sur Internet. Bon nombre de vidéos peuvent vous aider à pratiquer cette technique. </p>\n<p>Entraînez-vous également à bien respirer, ce qui vous détendra instantanément. Oubliez la respiration thoracique, laquelle ne vous fait que stagner dans un état de stress. Je vous laisse aller consulter mon <a href=\"/respiration\" target=\"_blank\" rel=\"noopener\" title=\"Respiration\">article sur la respiration</a> pour plus de renseignements et pour y trouver des exercices pratiques.</p>\n<p>Pour ma part, afin de bien respirer, j’utilise la méthode de la cohérence cardiaque. Je m’aide, pour ce faire, d’un appareil nommé Zenspire. Celui-ci, grâce à ses vibrations et la lumière qu’il émet, aide notre organisme à respirer calmement, régulièrement et profondément. Si cela vous intéresse, n’hésitez pas à cliquer sur le bouton ci-dessous, étant précisé que si vous passez commande, vous bénéficierez d’une remise de 10 % grâce au code JL0620 :</p>\n<img decoding=\"async\" width=\"550\" height=\"366\" src=\"/storage/blog-images/Anxiete-matin.jpg\" alt=\"Ruminations mentales \" title=\"Anxiété-matin\">\n<h3>Manger sainement  </h3>\n<p>Afin de bien dormir et de vous sentir mieux dans votre corps et votre tête, il y a lieu d’opter pour une bonne hygiène de vie alimentaire. Si vous souhaitez avoir des idées pour pouvoir vous nourrir sainement, vous pouvez aller consulter mon <a href=\"/reequilibrage-alimentaire\" target=\"_blank\" rel=\"noopener\" title=\"Rééquilibrage alimentaire \">article sur le rééquilibrage alimentaire. </a></p>\n<p>Et si possible, surtout en soirée à partir de 17 h, abstenez-vous de consommer trop de café ou d’excitants, tels que le Coca, l’alcool, le thé, etc., et évitez aussi de trop manger au point de ne plus pouvoir bouger de votre canapé ! Sinon, votre pauvre ventre éprouvera de grandes difficultés à digérer et la nuit risque de ne pas se passer très bien pour vous et donc, votre réveil également.  </p>\n<p>Connaissez-vous la synergie alimentaire ? C’est un mode d’alimentation créé par Rémi MOHA, coach sportif et nutrition diplômé. Celui-ci consiste à combiner certains aliments entre eux et ce, afin de décupler votre santé, vos performances, votre bien-être général et faciliter la perte de poids. Si vous souhaitez en savoir plus, je vous invite à cliquer sur le bouton juste ci-dessous et ce, afin de prendre connaissance du programme qu’il a créé à ce sujet :</p>\n<h3>Marcher </h3>\n<p>Si vous souffrez d’angoisse matinale, c’est que votre système nerveux est déjà bien perturbé et épuisé. Et pour calmer votre système nerveux, rien de tel que la pratique d’une bonne activité physique. Celle que je vous recommande et qui reste accessible à tous est la marche. 30 minutes par jour en dehors de chez vous feront l’affaire. </p>\n<p>Marcher, en effet, calme beaucoup la fatigue nerveuse que l’on ne ressent que trop bien lorsque l’on souffre de troubles anxieux. Car en marchant, vous bougez en vous aérant dans la nature et en observant le paysage autour de vous. Vos ruminations finissent donc par disparaître. 30 minutes, c’est rapide. Un petit tour du pâté de maisons et le tour est joué. Essayez et vous verrez que vous passerez de bien meilleures nuits.</p>\n<h3>Prendre plusieurs pauses dans la journée </h3>\n<p>Effectuez des pauses dans votre journée, d’autant plus si vous avez un job et qui plus est, dans un bureau ! Une pause toutes les heures et demie est recommandée. À ces moments, vous pouvez sortir (même si vous ne fumez pas), pratiquer une technique de respiration, vous étirer, etc. Essayez d’effectuer cette pause pendant au moins 5 minutes. </p>\n<p>Faire une pause apparaît primordial pour éviter que la tension de la journée ne s’accumule. Cette coupure casse ce trop-plein de stress qui pourrait avoir lieu.</p>\n<h3>Casser le lien entre angoisse et matin </h3>\n<p>Bien souvent, l’anxiété matinale peut devenir chronique. En fait, le corps prend l’habitude d’angoisser tous les matins. </p>\n<p>Le matin peut également avoir une origine traumatique pour l’individu, ce qui peut expliquer ledit trouble (par exemple, avoir appris le décès d’un être cher aux aurores). Du coup, il convient de casser le lien qui a été créé entre angoisse et matin.</p>\n<p>D’abord, quand vous devez vous lever, inutile de le faire rapidement, dans la tension. Car votre corps n’est pas réveillé, lui. Il y a donc déjà lieu de réveiller votre organisme. En premier lieu, frottez-vous les mains l’une contre l’autre. En effet, les mains possèdent une forte concentration de terminaisons nerveuses. Vous stimulerez ainsi votre organisme. Vous n’avez ensuite plus qu’à placer vos mains sur vos yeux afin de commencer à stimuler votre corps. En second lieu, prenez votre temps, étirez-vous bien et souriez. Il a été prouvé scientifiquement que même un faux sourire procure du bien-être à votre cerveau. Et, si possible, roulez ensuite sur le côté droit pour vous lever. </p>\n<p>Enfin, entraînez votre esprit à voir la vie positivement. Nous avons tendance à l’oublier, mais nous sommes tous mortels. Vous, vous vous êtes réveillé ce matin. Mais vous n’imaginez pas le nombre de personnes qui n’ont pas eu cette chance. Vos proches sont également vivants ? Que demander de plus ? Apprenez donc à cultiver la gratitude. </p>\n<h3>Réduire les ruminations de manière générale </h3>\n<p>Les <a href=\"/ruminations\" target=\"_blank\" rel=\"noopener\" title=\"Ruminations \">ruminations</a> restent l’une des causes principales des angoisses matinales. Voyons ensemble comment les arrêter. </p>\n<h4>La méthode STOP</h4>\n<p>Pour diminuer l’angoisse, il y a lieu de réduire vos ruminations de manière globale. Je vous ai déjà donné plus haut quelques méthodes afin de pouvoir y arriver, comme casser vos ruminations en réalisant tout de suite une autre activité. Vous pouvez également, lorsque vous sentez que votre cerveau commence à chauffer un peu trop, crier (dans votre tête, c’est bon aussi) le mot STOP, en visualisant un panneau. Cette astuce ne règlera pas la cause profonde de vos problèmes, mais pourra vous éviter une bonne crise d’angoisse ou de déprime en cassant l’hyperactivité de votre mental. C’est donc un outil simple et très puissant.</p>\n<h4>Utiliser les affirmations positives</h4>\n<p>Vous pouvez, tous les jours, reprogrammer petit à petit votre cerveau par le biais d’affirmations positives. Si votre cerveau est habitué à la négativité, il va, bien entendu, résister et lesdites affirmations sonneront faux pour vous. Mais comme vous avez appris à être angoissé, vous pouvez désapprendre à l’être. Donc, persévérance et passage à l’action restent vos meilleurs alliés. Vous pouvez établir une liste personnelle d’affirmations positives en vous aidant de livres, d’Internet, etc. pour découvrir les affirmations qui vous correspondent le plus. N’hésitez pas à varier les sujets. Vous pouvez trouver des affirmations positives sur le travail, l’argent, votre rôle de conjointe, de mère, votre façon de vous voir, de considérer les autres et le monde en général, etc.  </p>\n<h4>Changer sa vision du travail</h4>\n<p>Si vous travaillez et que c’est votre emploi qui vous provoque des angoisses matinales, il vous faut impérativement changer votre vision sur votre métier. Par exemple, vous prononcez des phrases telles que « je m’ennuie dans mon job » ou « je n’en peux plus de me lever si tôt tous les matins ». Vous pouvez prendre vos responsabilités en tenant un autre discours. Comme, « il en va de ma responsabilité d’aller travailler, et ce, en vue de subvenir à mes besoins et à ceux de ma famille »<i>. </i>Ou « ce travail n’est pas plaisant, mais ce n’est pas la fin du monde. Je vais chercher ailleurs en attendant et prendre du recul, vu que je sais que ce job n’est que passager ». Vous avez, je pense, compris le principe.</p>\n<h3>Voir du monde </h3>\n<p>Même si vous êtes casanier et n’aimez pas trop le monde, essayez tout de même de sortir un minimum de vos habitudes et de voir du monde. Le fait de discuter avec d’autres personnes vous permettra tout de même de vous changer un peu les idées, de moins ruminer et donc, de réduire vos angoisses matinales. Vous trouverez en outre, auprès des autres, de la bienveillance et du réconfort.</p>\n<h3>Envisager une TCC </h3>\n<p>Si vos angoisses matinales deviennent vraiment trop pénibles pour vous, n’hésitez pas à aller consulter un professionnel de la santé. Vous pouvez envisager une psychothérapie comme la thérapie comportementale et cognitive. Elle peut aussi s’accompagner, si besoin, d’un traitement médicamenteux, tel que la prise d’antidépresseurs et/ou d’anxiolytiques. Ces médicaments peuvent vous servir de béquille en attendant d’aller mieux. Le thérapeute vous aidera à modifier vos croyances et vos pensées de manière bénéfique. Il vous prescrira également des exercices pratiques pour vous pousser à passer à l’action.</p>\n<p>J’espère que cet article va vous aider à vous libérer de l’<b>angoisse matinale. </b>Vous retrouverez aide cette façon une sensation de paix au réveil et pourrez ainsi débuter votre journée en toute sérénité.  </p>\n<p>(Si mon travail vous aide 🙂)</p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img loading=\"lazy\" decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Séance de yoga pour apaiser l\'anxiété\" title=\"yoga_300x250\"></a>\n','published',1,'Angoisse Matinale : se Libérer de ce Fardeau pour Retrouver la Paix','Les personnes souffrant de troubles anxieux peuvent aussi souffrir d’angoisse matinale. Quelle sensation désagréable ! Comment soigner l’angoisse matinale ?','https://vivre-pleinement.fr/angoisse-matinale/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/angoisse-matinale\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/angoisse-matinale\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Angoisse Matinale\\u00a0: se Lib\\u00e9rer de ce Fardeau pour Retrouver la Paix\",\"datePublished\":\"2020-09-08T16:54:40+00:00\",\"dateModified\":\"2024-02-13T17:12:44+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/angoisse-matinale\\/\"},\"wordCount\":6157,\"commentCount\":2,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/angoisse-matinale\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/09\\/Angoisse-matinale.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/angoisse-matinale\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/angoisse-matinale\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/angoisse-matinale\\/\",\"name\":\"Angoisse Matinale\\u00a0: se Lib\\u00e9rer de ce Fardeau pour Retrouver la Paix\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/angoisse-matinale\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/angoisse-matinale\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/09\\/Angoisse-matinale.jpg\",\"datePublished\":\"2020-09-08T16:54:40+00:00\",\"dateModified\":\"2024-02-13T17:12:44+00:00\",\"description\":\"Les personnes souffrant de troubles anxieux peuvent aussi souffrir d\\u2019angoisse matinale. Quelle sensation d\\u00e9sagr\\u00e9able ! Comment soigner l\\u2019angoisse matinale\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/angoisse-matinale\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/angoisse-matinale\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/angoisse-matinale\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/09\\/Angoisse-matinale.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/09\\/Angoisse-matinale.jpg\",\"width\":640,\"height\":425,\"caption\":\"Comment soigner l\\u2019angoisse matinale ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/angoisse-matinale\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Angoisse Matinale\\u00a0: se Lib\\u00e9rer de ce Fardeau pour Retrouver la Paix\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2020-09-08 16:54:40',NULL,'2026-05-24 19:19:44','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (34,'Jalousie Maladive : s’en Libérer pour Retrouver la Paix Intérieure','je-suis-jaloux','Qui n’a jamais ressenti de la jalousie ? Cette émotion, bien que désagréable, reste un sentiment normal. Par contre, lorsqu’elle prend trop d’ampleur en devenant maladive et pathologique, la jalousie peut vraiment devenir dévastatrice. Elle peut faire souffrir la personne concernée ainsi que ses proches. De plus, cette émotion apparaît comme honteuse et reste, de ce fait, fréquemment refoulée. Votre partenaire a beaucoup d’amies et vous ne supportez pas cette situation. Vous avez peur d’être moins bien qu’elles et qu’il finisse par vous quitter. Vous avez l’impression que votre sœur a plus de privilèges auprès de vos parents que vous et vous sentez mal aimé. En tant que belle-mère, vous n’arrivez pas à accepter que votre fils puisse aimer une autre femme en plus que vous. La jalousie vous ronge ? Comment soigner la jalousie maladive ? \n','<p>Qui n’a jamais ressenti de la jalousie ? Cette émotion, bien que <b>désagréable</b>, reste un sentiment <b>normal</b>. Par contre, lorsqu’elle prend trop d’ampleur en devenant maladive et <b>pathologique</b>, la jalousie peut vraiment devenir dévastatrice. Elle peut faire <b>souffrir </b>la personne concernée ainsi que ses <b>proches</b>. De plus, cette émotion apparaît comme <b>honteuse </b>et reste, de ce fait, fréquemment <b>refoulée</b>. Votre partenaire a beaucoup <b>d’amies </b>et vous ne supportez pas cette situation. Vous avez peur d’être moins bien qu’elles et qu’il finisse par vous <b>quitter</b>. Vous avez l’impression que votre sœur a plus de <b>privilèges </b>auprès de vos parents que vous et vous sentez <b>mal aimé. </b>En tant que belle-mère, vous n’arrivez pas à accepter que votre fils puisse aimer une autre femme en <b>plus </b>que vous. La jalousie vous <b>ronge </b>? Comment soigner la <b>jalousie maladive ? </b></p>\n<h2>Qu’est-ce que la jalousie maladive ?  </h2>\n<p>La jalousie est, de manière générale, due à la peur de la perte. Perte d’une relation, qu’elle soit amoureuse, amicale ou familiale. Mais aussi perte d’habitudes comme, par exemple, un changement de collègue dans le cadre d’un travail. Elle peut apparaître à la suite d’un événement particulier, mais pas forcément. Du fait de son apparition, la personne ressent un profond sentiment d’insécurité et peut également ressentir d’autres émotions en plus. Comme la tristesse et la colère, pouvant même se transformer en insatisfaction, dégoût, agressivité et fureur.</p>\n<p>Attention à ne pas confondre la jalousie avec l’envie. L’envie consiste à jalouser une personne sur ce qu’elle a, ses compétences, etc., et que vous pensez ne pas avoir. Vous n’avez pas peur de perdre. Vous ressentez plutôt de la frustration sur ce qu’il vous manque par rapport aux autres. L’envie ressemble en fait à la comparaison sociale, laquelle fait l’objet d’un article complet sur mon blog que je vous invite à aller consulter <a href=\"/se-comparer-aux-autres\" target=\"_blank\" rel=\"noopener\" title=\"Se comparer aux autres\">ici.</a></p>\n<h2>La jalousie en amour  </h2>\n<p>La jalousie dans le couple peut prendre différentes formes et apparaître de différentes manières. </p>\n<h3>La jalousie du début  </h3>\n<p>Il y a d’abord la jalousie du début de relation, laquelle arrive à bon nombre de personnes, même si elles ne sont pas trop sujettes à la jalousie à la base. Et c’est parfaitement naturel. En effet, à ce moment, nous ne pouvons faire confiance à 100 % à notre partenaire, puisque nous ne le connaissons pas encore bien. </p>\n<h3>La jalousie suite à une infidélité</h3>\n<p>Il y a également la jalousie, assez compréhensible, survenant après une infidélité. Quelquefois, la personne trompée, bien que souhaitant préserver son couple, n’arrive plus à gérer la souffrance qu’elle ressent. Cette tromperie devient une véritable obsession et la personne se rend compte qu’elle n’arrivera plus à faire confiance à son conjoint. De là, la rupture s’avère souvent inévitable. </p>\n<p>D’ailleurs, certains individus infidèles apparaissent très jaloux. En effet, ils utilisent le mécanisme de projection. C’est-à-dire qu’ils projettent sur leur partenaire leur propre infidélité. Puisqu’ils sont capables de tromper, pourquoi leur partenaire ne le ferait-il pas ? </p>\n<h3>La jalousie imaginaire  </h3>\n<p>La jalousie la plus difficile à vivre et la plus pathologique reste celle survenant dans l’imaginaire. Dans ce cas-là, la personne présente bien souvent un côté paranoïaque, la poussant à surveiller son conjoint de manière compulsive. Fouiller dans son téléphone, ses réseaux sociaux, lui poser d’innombrables questions afin de se faire rassurer, etc. De ce fait, de nombreuses crises de jalousie ne manqueront pas de déclencher des disputes dans la vie de couple. Le partenaire peut avoir de plus en plus de mal à supporter cette situation le privant de sa liberté. Si cette jalousie extrême n’est pas prise en charge, la plus grande peur du jaloux, qui est de perdre son conjoint, risque malheureusement d’arriver. </p>\n<h3>La jalousie possessive  </h3>\n<p>Dans la possessivité, l’individu va vouloir « s’accaparer » son amoureux. C’est-à-dire qu’il souhaitera le plus souvent possible être avec lui, mais qu’avec lui. Il peut alors être jaloux de toute personne avec qui son partenaire passe du temps, même s’il s’agit de sa famille. Le bonheur du possessif tient donc au fait d’avoir son conjoint rien que pour lui. De se sentir sur un piédestal, sentimentalement parlant, par rapport aux autres. Et pour arriver à ses fins, il va tout faire pour que son partenaire devienne dépendant de lui, en demeurant constamment aux petits soins à son égard. Une petite technique de manipulation en somme.</p>\n<p> </p>\n<h2>La jalousie familiale </h2>\n<p>Le sentiment de jalousie peut également survenir dans la famille, et ce n’est d’ailleurs pas un cas rare. </p>\n<h3>Les rivalités entre frères et sœurs</h3>\n<p>Il y a déjà le cas fréquent d’un bébé venant de naître. Bien souvent, le grand frère ou la grande sœur, pour qui toute l’attention était auparavant portée, va devoir, dorénavant, partager l’amour de ses parents. Et, même s’il (ou elle) aime son petit frère ou sa petite sœur, il éprouvera tout de même de la jalousie à son égard. C’est généralement à ce moment que certains enfants commencent à ressentir un sentiment d’abandon, bien qu’il ne reste qu’imaginaire.</p>\n<h3>La jalousie envers le gendre ou la belle-fille </h3>\n<p>Il peut également y avoir des accès de jalousie envers une personne que certains nomment la « pièce rapportée » de la famille. C’est le cas, par exemple, d’un enfant qui se marie et qui part faire sa vie. Quelquefois, les parents peuvent avoir beaucoup de mal à tolérer qu’une personne étrangère à leur clan vienne briser leurs habitudes familiales et leur relation avec leur progéniture. Cependant, le lien n’est, la plupart du temps, absolument pas brisé, mais juste transformé. Mais ils peuvent s’imaginer que leur enfant a changé, qu’il n’est plus le même, etc. </p>\n<h3>La jalousie envers les grands-parents</h3>\n<p>La jalousie envers les grands-parents est très fréquente également. C’est le cas où les enfants disent clairement préférer les grands-parents aux parents. Cependant, il est vain de le prendre mal. C’est normal que les enfants éprouvent ce genre de sentiment. En effet, les grands-parents n’ont pas pour rôle d’éduquer (ce qui est moins drôle), mais plutôt de gâter, d’amuser, etc. Inutile donc de se comparer à une personne n’ayant pas le même rôle que le vôtre. </p>\n<h3>La jalousie envers les enfants </h3>\n<p>Il y a également des cas où une mère jalouse sa fille, de par son plus jeune âge, par exemple. Ou par le fait que toute l’attention se porte sur la petite et non plus sur la maman. </p>\n<p>Cependant, ce type de jalousie reste assez difficile à avouer et apparaît particulièrement tabou. En effet, une mère se doit d’aimer son enfant inconditionnellement et ainsi, ne ressent pas de sentiment négatif à son égard. Si vous êtes maman et que vous ressentez cette émotion, sachez que vous êtes loin de vous trouver seule dans ce cas. Votre jalousie n’est pas anormale, elle est naturelle. Mais forcément, les autres ne vous avoueront pas éprouver cette jalousie. Donc, s’il vous plaît, ne culpabilisez pas. Vous n’êtes pas une mauvaise mère pour autant. </p>\n<h2>La jalousie en amitié </h2>\n<p>La jalousie peut également provenir d’une relation amicale. Bien souvent, ce ne sera qu’avec un ami en particulier. Celui dont nous nous trouvons le plus proche. Ce type de jalousie se rencontre beaucoup plus dans les relations entre filles, les hommes étant moins de cette nature. Cette jalousie se ressent généralement lorsque nous avons une meilleure amie. Pourquoi ? Car nous choisissons des amis qui nous ressemblent. Nous pouvons donc considérer qu’une meilleure amie n’est, en réalité, que notre miroir. Un énorme processus d’identification se met alors en place. </p>\n<p>C’est d’ailleurs là que les problèmes commencent. Quand un sentiment d’exclusivité, de possessivité, comme dans un couple finalement, apparaît. Notre amie n’a plus le droit d’avoir d’autres copines, de peur que ces filles nous remplacent. De nombreuses rivalités peuvent donc apparaître, étant donné que nous ne pouvons empêcher notre amie de fréquenter différentes personnes.</p>\n<p>Ce sentiment possessif peut également, comme dans une union conjugale, être une jalousie de projection. C’est-à-dire qu’une personne ayant une autre amitié attitrée quelque part ne supportera pas que son amitié exclusive officielle ait plusieurs amies…</p>\n<p>D’ailleurs, nous pouvons penser que ce type de jalousie n’est qu’un comportement enfantin ne concernant que des amitiés de lycéens. Cependant, il n’en est rien. Une véritable amitié peut vraiment être forte et faire apparaître ce sentiment. Il n’y a donc pas de honte à avoir si vous éprouvez cette émotion. </p>\n<p>Enfin, si la jalousie devient trop maladive, l’amie en question peut en avoir assez de cette privation de liberté et ainsi, provoquer une rupture amicale.</p>\n<h2>La jalousie au travail</h2>\n<p>Il peut également y avoir de la jalousie à l’égard, par exemple, d’un collègue dans le cadre de son métier. Il peut s’agir de la peur de perdre son travail depuis qu’une nouvelle personne a été embauchée. Ce sentiment est loin d’être rare alors, n’ayez pas honte de cette émotion. C’est humain. Cependant, essayez de vous mettre à la place de la nouvelle arrivée. Ce n’est pas évident de commencer un nouveau job, où l’on est surveillés et jugés. Le stress se trouve à son paroxysme à ce moment-là. De ce fait, inutile de mal l’accueillir juste par peur de perdre son poste. </p>\n<p>Dans une activité, chaque personne apporte une pierre à l’édifice. Il n’y a donc aucune raison que quelqu’un perde son emploi par rapport à quelqu’un d’autre. Le droit du travail n’autorise pas n’importe quoi, rassurez-vous. Et surtout, prenez confiance en vous et en vos compétences !</p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"550\" height=\"367\" src=\"/storage/blog-images/Rivalite.jpg\" alt=\"Peur abandon \" title=\"Rivalité\">\n<h2>Les causes de la jalousie maladive  </h2>\n<p>Vous vous demandez probablement pourquoi vous demeurez beaucoup plus jaloux que certains. En fait, il y a plusieurs origines à la jalousie maladive. De manière générale, cette émotion prend naissance à la suite d’un événement <a href=\"/traumatisme\" target=\"_blank\" rel=\"noopener\" title=\"Traumatisme\">traumatique</a> non digéré. Une blessure profonde et bien souvent, inconsciente s’est alors installée. Voyons maintenant ensemble les différentes causes possibles de la jalousie.</p>\n<h3>Une faible estime de soi </h3>\n<p>Pour moi, le <a href=\"/confiance-et-estime-de-soi/\" target=\"_blank\" rel=\"noopener\" title=\"Confiance et estime de soi\">manque d’estime de soi</a> se trouve à l’origine de la plupart des troubles émotionnels dont la jalousie fait partie. </p>\n<p>D’une manière générale, la personne ne s’aime pas suffisamment et donc, recherche activement l’amour de l’extérieur. Cependant, puisqu’elle ne s’apprécie pas, elle pense que tout le monde est meilleur qu’elle et peut la remplacer. Une femme peut très rapidement séduire son homme. Sa meilleure amie peut très vite la remplacer par une copine plus gentille, plus rigolote, plus intéressante. Sa nouvelle collègue a de meilleures compétences, apparaît plus sociable, les autres vont forcément la préférer à elle, etc.</p>\n<p>D’ailleurs, si vous avez des problèmes d’estime et de confiance en vous, je vous suggère le programme de Didier PENISSARD que vous trouverez en cliquant sur le bouton ci-dessous. Vous pouvez toujours y aller jeter un oeil : </p>\n<h3>Une blessure d’abandon </h3>\n<p>Il existe, dans la jalousie, une crainte de perdre l’amour que l’on nous porte. Il peut donc y avoir une forte dépendance affective envers les personnes que nous aimons. Ladite dépendance provient en réalité d’une grande peur de l’abandon. Se sentir aimé, lorsque l’on ressent cette blessure, est vital. </p>\n<p>Dans cette situation, l’individu tiendra souvent ce genre de discours : « si mon mari me quitte, je me suicide, vu que je ne suis rien sans lui ». Dans le cadre familial, un enfant peut commencer à se sentir abandonné par ses parents lorsqu’un petit frère ou une petite sœur voit le jour. Une maman peut se sentir abandonnée par les autres lorsque sa fille naît, ne se trouvant plus au centre de l’attention. Une amie se rapprochant trop d’une autre peut nous faire penser que nous ne sommes plus assez bien, car sinon, elle ne chercherait pas l’amitié ailleurs. </p>\n<h3>Une trop grande identification </h3>\n<p>Trop vous identifier à une personne vous fait un peu oublier votre propre identité. Du coup, vous pouvez déclencher de la jalousie dans le cadre d’un trop grand attachement à son égard. Mais cette jalousie pourrait être évitée si aucune identification ne se fait. En clair, il vaut mieux ne pas avoir de meilleure amie, mais plutôt plusieurs amis avec lesquels vous vous sentez bien. Car les amis ont le droit d’en avoir d’autres, vous ne pouvez rien leur dire. Avoir trop d’attentes envers une personne ne pourra, de toute façon, vous mener qu’à la déception. </p>\n<h3>De l’égoïsme </h3>\n<p>La jalousie peut aussi se retrouver chez des personnes souhaitant avoir l’exclusivité et apparaissant assez possessives. L’autre personne n’a, en effet, pas le droit de fréquenter trop longtemps d’autres individus, mis à part le possessif. Comme si elle était son objet. Lui peut voir du monde, mais pas l’autre, qui lui appartient. Est-ce de l’égoïsme ? C’est possible. Cet individu a peut-être été élevé en enfant-roi, pensant que tout lui est toujours dû, et ce, au détriment d’autrui. Cependant, je pense que cet égoïsme reflète également un manque d’estime de soi et aussi, une blessure d’abandon.</p>\n<h2>Le refoulement de la jalousie </h2>\n<p>Bien que tout le monde apparaisse plus ou moins jaloux, certains présentent un niveau de jalousie pathologique. Et généralement, avouer à autrui que vous êtes jaloux relève presque de l’impossible. Car vous pensez ce sentiment tabou et avez donc honte de le ressentir. Vous n’acceptez pas cette émotion, et de ce fait, avez tendance à la refouler. </p>\n<p>Voilà pourquoi, par exemple, une amie coupe les ponts avec son amie pour laquelle elle ressent une trop grande jalousie, mais sans vraiment en avoir conscience. Elle préfère perdre une amitié pour ne plus éprouver cette jalousie. C’est un mécanisme de défense, mais très mal adapté. Elle se dit (et cette attitude reste valable pour les relations amoureuses) : pour ne plus souffrir, je préfère rester seule et ne plus ressentir d’amour pour les autres. </p>\n<p>Bien évidemment, refouler un sentiment n’est jamais bon. L’émotion s’exprimera dans tous les cas, mais d’une autre manière. Et bien souvent, elle le fera par le corps (troubles somatiques, maladies, malaises).</p>\n<img decoding=\"async\" width=\"600\" height=\"400\" src=\"/storage/blog-images/Possessivite.jpg\" alt=\"Manque d’estime de soi \" title=\"Possessivité\">\n<h2>Comment vaincre la jalousie maladive ? </h2>\n<p>De nombreuses solutions existent pour soigner votre jalousie maladive. Examinons-les ensemble. </p>\n<h3>Accepter la jalousie  </h3>\n<p>Afin de vous débarrasser de cette émotion excessive, la première étape reste de prendre conscience et de<a href=\"/lacher-prise-et-acceptation/\" target=\"_blank\" rel=\"noopener\" title=\"Lâcher-prise et acceptation\"> l’accepter.</a> Dites-vous bien que ressentir de la jalousie est parfaitement naturel dans certaines circonstances. C’est la nature humaine qui est ainsi. C’est juste que les gens ne l’avouent généralement pas.</p>\n<p>Donc, ne culpabilisez surtout pas et acceptez de ressentir parfois des sentiments que vous pensez honteux, mais qui sont tout simplement humains. Ne culpabilisez également pas si quelquefois, votre jalousie vous paraît être un comportement enfantin.</p>\n<p>Il est bon de souligner que la honte et la culpabilité à ressentir de la jalousie, laquelle reste pourtant une émotion normale, est monnaie courante. Elle provient principalement de l’importante que l’on accorde au regard des autres. Afin de vous aider à passer au-dessus de tout cela, n’hésitez pas à aller consulter le programme de Didier PENISSARD que vous trouverez en cliquant sur le bouton ci-dessous :</p>\n<h3>Trouver l’origine de la jalousie maladive</h3>\n<p>Une fois ce sentiment accepté, vous pouvez vous demander d’où il peut provenir. Vous êtes-vous senti abandonné à une période de votre vie ? Avez-vous été un enfant-roi étant devenu assez possessif avec les autres, voire un peu égoïste sur les bords ? Manquez-vous d’estime de vous et pensez-vous donc que toute autre personne apparaît bien plus aimable que vous ? Ce ne sont là que des exemples. Après avoir trouvé la réponse, passez à l’action afin de changer d’attitude. Et si vous ne savez vraiment pas cette jalousie peut provenir, ce n’est pas grave. Vous pouvez tout de même travailler sur le changement de votre comportement et heureusement ! </p>\n<h3>Communiquer </h3>\n<p>Si vous ressentez de la jalousie, n’hésitez pas à en parler à la personne concernée. Elle pourra sans doute vous rassurer, ce qui aura pour effet de faire disparaître le sentiment que vous ressentez. Par exemple, si vous êtes jaloux d’un individu que fréquente votre amie, faites-lui part de votre émotion en lui expliquant d’où votre jalousie pourrait provenir. En exprimant vos sentiments de façon respectueuse, votre copine fera preuve de compassion et de compréhension à votre égard.</p>\n<p>Dans le cadre d’une vie de couple, la communication reste primordiale. N’hésitez pas à parler de votre jalousie à la personne aimée. Vous éviterez alors de fouiller dans ses affaires de manière compulsive en son absence. Il faut réellement arrêter ce genre de comportement, lequel ne vous apportera que des problèmes. Donc, à vous de prendre votre courage à deux mains et de vraiment vous affirmer, et ce, avec respect. Ainsi, la confiance dans le couple va finir par apparaître. </p>\n<h3>Ne pas attendre de changement de la part des autres</h3>\n<p>Vous êtes la seule personne capable de soigner votre jalousie maladive. Personne ne peut le faire à votre place. Les autres peuvent vous rassurer, certes, mais attention à ce que ce besoin de réassurance ne devienne pas compulsif. Vous ne changerez de toute manière pas les gens et ne pourrez pas les empêcher d’avoir différentes fréquentations. Apprenez donc à leur faire confiance et surtout, à faire confiance à l’amour qu’ils vous portent. Mais pour ce faire, un travail sur vous apparaît nécessaire. </p>\n<h3>Se faire aider par un professionnel de la santé </h3>\n<p>Enfin, si malgré tous ces conseils votre jalousie continue à vous ronger, n’hésitez pas à aller consulter un professionnel de la santé. Parler à un thérapeute extérieur et objectif dans le cadre d’une thérapie peut vraiment vous faire du bien. Il pourra vous aider à éclaircir l’origine de votre jalousie (psychanalyse). Il pourra aussi, vous faire réaliser de petits exercices et actions concrètes afin de vous permettre de vaincre ce sentiment (psychothérapie).</p>\n<p>Une technique marchant apparemment assez bien reste l’hypnose. Ce qui n’est pas étonnant, puisque l’hypnose agit sur l’inconscient. N’hésitez donc pas à tenter également cette pratique. </p>\n<p> </p>\n<p>Grâce à cet article, vous possédez maintenant des clés pour vous libérer de votre<b> jalousie maladive.</b> Allez-y progressivement et ne vous mettez pas la pression. Petit à petit, vous allez y arriver ! </p>\n<p>(Si mon travail vous aide 🙂)</p>\n<a href=\"https://hypnocaments.com?partnerid=YK5muYugzSoIWDbDWRgT-Q\" title=\"Seances d hypnose en ligne\"><img decoding=\"async\" src=\"https://hypnocaments.com/image/banner_1_750.png\" alt=\"seance hypnose mp3\"></a>','published',1,'Jalousie Maladive : s’en Libérer pour Retrouver la Paix Intérieure','La jalousie peut faire souffrir la personne concernée ainsi que ses proches. La jalousie vous ronge ? Comment soigner la jalousie maladive ?','https://vivre-pleinement.fr/je-suis-jaloux/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/je-suis-jaloux\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/je-suis-jaloux\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Jalousie Maladive\\u00a0: s\\u2019en Lib\\u00e9rer pour Retrouver la Paix Int\\u00e9rieure\",\"datePublished\":\"2020-06-01T13:17:38+00:00\",\"dateModified\":\"2024-02-12T19:04:54+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/je-suis-jaloux\\/\"},\"wordCount\":5999,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/je-suis-jaloux\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/06\\/Jalousie-maladive.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/je-suis-jaloux\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/je-suis-jaloux\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/je-suis-jaloux\\/\",\"name\":\"Jalousie Maladive\\u00a0: s\\u2019en Lib\\u00e9rer pour Retrouver la Paix Int\\u00e9rieure\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/je-suis-jaloux\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/je-suis-jaloux\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/06\\/Jalousie-maladive.jpg\",\"datePublished\":\"2020-06-01T13:17:38+00:00\",\"dateModified\":\"2024-02-12T19:04:54+00:00\",\"description\":\"La jalousie peut faire souffrir la personne concern\\u00e9e ainsi que ses proches. La jalousie vous ronge\\u2009? Comment soigner la jalousie maladive\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/je-suis-jaloux\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/je-suis-jaloux\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/je-suis-jaloux\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/06\\/Jalousie-maladive.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/06\\/Jalousie-maladive.jpg\",\"width\":640,\"height\":416,\"caption\":\"Comment soigner la jalousie maladive ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/je-suis-jaloux\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Jalousie Maladive\\u00a0: s\\u2019en Lib\\u00e9rer pour Retrouver la Paix Int\\u00e9rieure\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2020-06-01 13:17:38',NULL,'2026-05-24 19:19:45','2026-06-19 22:28:14');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (35,'Soigner la Thanatophobie pour Retrouver le Bien-être','thanatophobie','Depuis toujours, l’être humain est fasciné par la mort, de par son côté énigmatique. Mais surtout, la mort terrorise. En effet, bien que la mort ne demeure finalement que le cycle, on ne peut plus naturel, de la vie, ressentir la crainte de mourir est monnaie courante. En développer une obsession se nomme la thanatophobie. Tous les jours, vous avez peur que votre conjoint meurt en voiture. Lorsque vous parlez de la mort et de ce qu’il peut y avoir après avec quelqu’un, vous ressentez une angoisse existentielle avec une sensation de déréalisation. Vous tentez sans cesse de vous rassurer sur une éventuelle après-vie. Disparaître et perdre toute relation avec vos proches est une pensée qui vous apparaît insupportable. La peur de la mort impacte trop votre existence ? Comment soigner la thanatophobie ? \n','<p>Depuis toujours, l’être humain est <b>fasciné </b>par la <b>mort</b>, de par son côté <b>énigmatique</b>. Mais surtout, la mort <b>terrorise.</b> En effet, bien que la mort ne demeure finalement que le <b>cycle</b>, on ne peut plus <b>naturel, </b>de la vie, ressentir la crainte de mourir est monnaie courante. En développer une <b>obsession </b>se nomme la thanatophobie. Tous les jours, vous avez peur que votre <b>conjoint meurt </b>en <b>voiture</b>. Lorsque vous parlez de la mort et de ce qu’il peut y avoir après avec quelqu’un, vous ressentez une <b>angoisse existentielle </b>avec une sensation de <b>déréalisation</b>. Vous tentez sans cesse de vous <b>rassurer </b>sur une éventuelle <b>après-vie.</b> Disparaître et <b>perdre </b>toute <b>relation </b>avec vos proches est une pensée qui vous apparaît <b>insupportable</b>. La peur de la mort impacte trop votre existence ? Comment <b>soigner la thanatophobie </b>? </p>\n<h2>Qu’est-ce que la thanatophobie ?</h2>\n<p>La thanatophobie est la phobie de mourir, ou que son entourage proche décède. Il s’agit de l’appréhension de la mort en général. Voyons ensemble cette peur plus en détail. </p>\n<h3>Les principaux symptômes </h3>\n<p>Les manifestations de cette angoisse peuvent varier d’une personne à une autre. L’individu peut donc ressentir les symptômes suivants : </p>\n<p> </p>\n<p>— Peur excessive de la mort en général. C’est-à-dire, de sa propre disparition et également, de celle de ses proches ; </p>\n<p>— Troubles anxieux. Les crises de panique s’accompagnent de sensations désagréables, comme l’hyperventilation, les sueurs, les nausées, etc. ; </p>\n<p>— Anxiété en allant se coucher. Les personnes ressentent une terreur de mourir dans leur sommeil. Ce sentiment de mort imminente peut entraîner des symptômes leur faisant croire en leur peur, comme les palpitations cardiaques. Les insomnies chroniques s’installent ; </p>\n<p>— Forte angoisse en allant à un enterrement, au cimetière, dans un hôpital, aux pompes funèbres, etc. à tous les lieux pouvant rappeler la mort. Cette anxiété entraîne l’évitement de ces lieux. Certaines attitudes peuvent également apparaître, comme l’impossibilité de voir un cadavre dans un film d’horreur ou de rouler par peur de faire un accident mortel. </p>\n<h3>La peur de vivre </h3>\n<p>La peur de mourir cache, en réalité, la peur de vivre. Cette peur veut vous montrer que votre vie ne vous convient pas et que vous devez la changer. Mais bien souvent, même une personne n’aimant pas son existence ne voudra pas disparaître. Car elle préfère tout de même vivre une existence médiocre plutôt que d’avoir affaire à l’inconnu ultime. </p>\n<p>Quelquefois, afin de mieux pouvoir supporter la thanatophobie, certains d’entre nous vont développer des convictions sur la vie après la mort. Elles peuvent, en effet, aider. Mais généralement, au moment de la grande faucheuse, je ne suis pas certaine que de grandes croyances arriveront à dissiper totalement la peur de mourir. </p>\n<h2>Les causes de la peur de la mort  </h2>\n<p>Pourquoi certaines personnes ont plus peur de la mort que d’autres ? Voici ici les principales causes de la thanatophobie.  </p>\n<h3>La vieillesse </h3>\n<p>Les personnes atteintes de thanatophobie peuvent être âgées. Il peut être logique de penser de plus en plus à la mort avec l’âge. Ces personnes sont bien conscientes, en effet, de se trouver plus proches de la fin que du début. L’incapacité progressive de leur corps à accomplir les tâches de la vie de tous les jours leur montre bien. C’est à partir de là que certaines commencent à chercher des croyances sur l’au-delà.</p>\n<h3>Un traumatisme </h3>\n<p>Il est faux de penser que seules les personnes âgées ont peur de la mort<b>.</b> Il suffit, en effet, d’un événement traumatique survenant dans la vie d’un individu. Par exemple, avoir frôlé la mort lors d’un accident, être atteint d’une maladie assez grave, avoir perdu un proche ou un animal, etc. Ce traumatisme fait prendre soudainement conscience à la personne, quel que soit son âge, de sa mortalité et surtout, que tout peut arriver à n’importe quel moment et à n’importe qui.</p>\n<p>Le traumatisme peut même être dû à un événement plus anodin. Par exemple, un jeune enfant peut avoir été traumatisé en regardant un film d’horreur… il n’y a pas de règle.</p>\n<h3>L’incertitude </h3>\n<p>La mort fait peur, puisqu’elle nous met devant le fait que nous ne savons rien, au final. Oui, il existe des témoignages sur l’après-vie (EMI). Certaines personnes, nommées médiums, prétendent pouvoir communiquer avec les morts. Malgré tout, on ne sait pas ce qu’il se passe exactement après. Car aucun défunt n’est jamais revenu de l’autre côté pour nous expliquer en détail ce qui nous attend ensuite. </p>\n<p>Donc, mises à part certaines croyances ou hypothèses, personne n’a de certitude sur l’au-delà. Vous pouvez chercher la réponse partout. Sur Internet, dans les livres, les témoignages, etc. Vous n’obtiendrez jamais LA réponse. Et c’est bien cette incertitude, cette angoisse de ne pas savoir, qui vous met dans un tel état devant l’idée de mourir un jour.</p>\n<p>Enfin, même si nous savons que nous mourrons tous, personne ne peut nous dire quand exactement et comment. Cette incertitude peut donc terroriser une personne. Va-t-on souffrir ? Mourir en paix ? Allons-nous disparaître jeunes ? Âgé ? Comment le savoir ? Eh bien, on ne le peut pas, malheureusement. Ou heureusement, d’ailleurs, vous ne trouvez pas ? </p>\n<h3>La peur originelle</h3>\n<p>Vu qu’on ne sait pas ce qu’il y a après, l’imagination peut vite devenir débordante. Va-t-on aller au paradis ? Ou plutôt, en enfer ? Avons-nous effectué d’assez bonnes actions dans notre vie ? Car, même si l’individu n’a pas opté pour ce type de croyance, il y a fort à parier qu’il se posera tout de même la question lorsque son heure viendra. </p>\n<p>Et puis, il y a la peur de ne pas vraiment être mort et de finir enterré vivant. Ou brûlé vif, pour ceux ayant choisi l’incinération. La phobie de se voir souffrir sans pouvoir rien faire reste donc l’une des peurs majeures de mourir. Et c’est normal. </p>\n<p>Enfin, il y a cette terreur du « rien ». Nous avons tellement construit, dans cette vie ! Nous avons tous des proches qui nous aiment et que nous aimons. Il est impossible pour nous d’imaginer qu’ils ne seront plus un jour et que nous non plus. Que ces liens seront définitivement brisés. La peur de la solitude ultime, en somme. Il est difficile pour les personnes de se dire qu’à leur mort, elles ne se rappelleront même plus des proches ayant fait battre leur cœur alors qu’eux se souviendront toujours d’elles.</p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"640\" src=\"/storage/blog-images/Peur-mort.jpg\" alt=\"Deces \" title=\"Peur-mort\">\n<h3>Le sentiment d’immortalité </h3>\n<p>Toutes ces peurs peuvent pousser la personne à faire comme si la mort n’existait pas. Elle va ainsi en parler le moins souvent possible et devenir hyperactive. Le fait d’être occupé de la sorte pousse donc l’individu à ne plus penser du tout à la mort et même, d’avoir une illusion d’immortalité. </p>\n<p>De plus, une personne peut rédiger un testament, informer ses proches de comment elle souhaite mourir, enterrée ou incinérée, dans quel cimetière, etc. Cette attitude prouve bien qu’elle n’a pas véritablement conscience de la mort. Car sinon, elle se ficherait bien de savoir dans quel cimetière elle serait « installée ». Comme s’il allait devenir son nouveau domicile. </p>\n<p>On dit d’ailleurs que toutes les nuits, s’endormir s’apparente à une petite mort. Ce n’est pas vrai. Car lorsque nous dormons, notre corps continue de fonctionner. Notre cœur bat encore, nous continuons de respirer, notre cerveau construit des rêves, etc. Notre organisme entier fonctionne toujours, alors que pour la mort, notre système n’existe plus. Je ne pense donc pas que dormir et mourir puisse être comparable. </p>\n<p>Enfin, il est bon de comprendre que les personnes se suicidant ne souhaitaient pas vraiment quitter ce monde. Elles désiraient juste stopper leur souffrance et n’ont réussi à trouver que ce moyen. </p>\n<h3>Le tabou de la mort dans la famille</h3>\n<p>Lors d’un enterrement, les personnes apparaissent bien souvent tristes, mais juste après, elles reprennent le cours de leur vie. Elles plaisantent entre elles, discutent de divers sujets et ne parlent plus de la personne décédée. J’exagère, bien sûr. Mais c’est un peu l’idée. Est-ce que ces gens s’en fichent ? Je ne pense pas. C’est surtout qu’ils sont mal à l’aise et qu’ils refoulent la notion de mort. Mais pourquoi agir ainsi ? Car ce sujet est devenu tabou.</p>\n<p>Peu de parents abordent naturellement ce thème avec leur enfant. Certains refusent même d’en parler et deviennent gênés si leur bambin leur pose des questions à cet égard. Sauf qu’en se comportant de la sorte, le petit va ressentir cette gêne. Il va donc penser que quelque chose ne va pas avec la mort. Qu’elle est dangereuse et anormale. </p>\n<h3>La notion de mort aujourd’hui versus la notion de mort autrefois  </h3>\n<p>À des périodes lointaines, les mourants décédaient dans leur lit, accompagnés d’un prêtre et entourés de leur famille, et même des enfants. Et à leur décès, c’est bien généralement les proches qui s’occupaient de laver le corps, de l’habiller, etc. la mort était donc on ne peut plus naturelle. </p>\n<p>Il n’y a qu’à voir aux enterrements. Bien souvent, les parents n’amènent pas leur bambin, car souhaitent les préserver. Je comprends tout à fait ce genre de comportement. Il est normal de vouloir protéger son enfant et lui donner le meilleur. Mais, en y réfléchissant un peu plus, je ne suis pas sûre que cette attitude rende service à l’enfant. En effet, en agissant ainsi, le petit ne sera jamais confronté à la mort. Elle sera devenue taboue et donc, dangereuse, anormale. De ce fait, lorsque ce petit subira des deuils dans sa vie à l’âge adulte (ce qui arrivera inévitablement), il risque de rencontrer des problèmes. Car la mort, bien qu’étant naturelle, ne sera pas du tout considérée comme telle. </p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h3>La façon de mourir de nos jours </h3>\n<p>La peur de mourir est compréhensible de nos jours. Aujourd’hui, la plupart du temps en cas de maladies, la personne meurt seule, dans un lit d’hôpital. Ayant pour unique compagne sa morphine, laquelle l’aidera à éviter de trop souffrir. </p>\n<p>En outre, à l’annonce d’une maladie grave et incurable, même les médecins ne disent pas clairement à une personne qu’elle va quitter ce monde. Tout reste flou, tabou. Personne n’en parle et tout le monde fait comme si de rien n’était. Sauf que le malade n’est pas idiot. Il comprend bien que son entourage a changé. Certaines personnes peuvent d’ailleurs le fuir. Non pas par méchanceté. Mais parce qu’elles se sentent impuissantes, gênées. Elles ont peur de faire souffrir l’autre par des propos maladroits. De plus, le fait de voir un proche dans cet état leur fait rappeler leur propre mortalité. Cette idée demeure de ce fait insupportable pour elles et tout est alors, à nouveau, refoulé. </p>\n<p>Par conséquent, le malade ne peut pas exprimer ses craintes, ses regrets, ce qu’il a sur le cœur. Pourtant, c’est dans ce genre de moment qu’il en aurait le plus besoin. Il mourra donc ainsi. Dans le tabou le plus complet. </p>\n<p>C’est triste, j’en conviens. Mais cette situation risque de continuer si les personnes ne changent pas le regard qu’elles ont sur la mort. </p>\n<h2>Les personnes sujettes à la crainte obsédante de la mort  </h2>\n<p>Les personnes souffrant de thanatophobie sont bien souvent déjà anxieuses à la base. En effet, les individus angoissés sont allergiques à l’incertitude et l’incertitude représente la nature même de la mort. </p>\n<p>Généralement, un tempérament hypersensible est couplé avec le caractère anxieux. Ces personnes sont des adeptes des questions existentielles, ce qui n’est pas l’idéal pour se libérer de la peur de la mort. Elles peuvent d’ailleurs se poser des questions philosophiques comme : « Pourquoi vivre si c’est pour mourir un jour ? »</p>\n<h2>Que provoque le refoulement de l’angoisse amplifiée de la mort ? </h2>\n<p>Dans certains cas, la phobie de la mort n’est pas consciente. Elle est, en effet, masquée par d’autres troubles, plus superficiels. Il s’agit des troubles anxieux en général, lesquels peuvent prendre la ou les forme(s) suivant(e)s : </p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">Un TOC (trouble obsessionnel compulsif) accompagné de rituels, d’obsessions et de pensées intrusives ; </li>\n<li aria-level=\"1\">L’anxiété généralisée, faisant ressentir à la personne une angoisse diffuse ; </li>\n<li aria-level=\"1\">L’hypocondrie, rendant l’individu alerte sur toutes les sensations physiques qu’il pourrait éprouver pouvant lui faire penser à une maladie grave ; </li>\n<li aria-level=\"1\">Une dépression ; </li>\n<li aria-level=\"1\">Une phobie. L’objet phobique peut être très varié et prendre plusieurs formes. Phobie sociale, agoraphobie, claustrophobie (pouvant masquer l’angoisse d’être enterré vivant ou incinéré vif), peur de l’avion, des serpents, des araignées, etc. </li>\n</ul>\n<p> </p>\n<p>L’individu essaie ainsi de maîtriser ses peurs par différents moyens. Il tente donc d’avoir un contrôle sur la mort. </p>\n<img decoding=\"async\" width=\"640\" height=\"359\" src=\"/storage/blog-images/Angoisse-existentielle.jpg\" alt=\"cimetiere \" title=\"Angoisse-existentielle\">\n<h2>Comment soigner la thanatophobie ? </h2>\n<p>Heureusement, des solutions existent pour se libérer de la peur de la mort et commencer à vivre véritablement. Analysons-les ensemble. </p>\n<h3>Pratiquer l’acceptation et le lâcher-prise  </h3>\n<p>Nous ne pouvons contrôler la mort et n’obtiendrons jamais de réponses à nos questions, sauf au moment de notre dernière heure. Il y a donc lieu d’accepter notre condition d’être humain mortel et de lâcher-prise sur cette notion de mort. N’hésitez pas à aller consulter mon <a href=\"/lacher-prise-et-acceptation\" target=\"_blank\" rel=\"noopener\" title=\"Lâcher-prise et acceptation \">article</a> sur ce sujet.</p>\n<h3>Envisager une thérapie </h3>\n<p>Il peut être difficile de vivre avec la thanatophobie. Donc, afin de soulager ces angoisses profondes, n’hésitez pas à en parler à un professionnel de la santé. Plusieurs thérapies peuvent vous être conseillées. Il y a la psychanalyse, laquelle vous aidera peut-être à comprendre l’origine de votre phobie de la mort. Il y a aussi la psychothérapie, notamment la TCC (thérapie comportementale et cognitive). Pour ce type de thérapie, le thérapeute vous aidera à adopter de nouvelles croyances et comportements bénéfiques. Je décris ces thérapies dans <a href=\"/psychotherapie-et-psychanalyse\" target=\"_blank\" rel=\"noopener\" title=\"Psychothérapie et psychanalyse \">cet article. </a></p>\n<p>S’il en voit la nécessité, le thérapeute peut également vous conseiller de compléter votre thérapie par un traitement médicamenteux prescrit par un psychiatre. Je vous invite, à ce sujet, à aller consulter mon <a href=\"/antidepresseurs-et-anxiolytiques\" target=\"_blank\" rel=\"noopener\" title=\"Antidépresseurs et anxiolytiques \">article</a> sur les antidépresseurs et les anxiolytiques (benzodiazépines). Cependant, il est bon que ces médicaments ne restent qu’une béquille temporaire<b>, </b>au risque d’en devenir dépendant et de ne pas trouver la source de votre problème. C’est pourquoi il est judicieux de ne pas les prendre seuls, mais couplés à une thérapie pratiquée avec un professionnel de la santé. </p>\n<h3>Éviter les regrets </h3>\n<p>Bien souvent, lorsque nous avons peur de la mort, c’est que nous craignons d’avoir des regrets, de ne pas avoir vécu pleinement. Quelquefois, les personnes sur le point de mourir ont l’air en paix. Elles disent d’ailleurs : « je ne regrette rien. J’ai bien vécu. Je peux partir, maintenant ». </p>\n<p>L’être humain se pense immortel, et se prend alors fréquemment la tête pour rien. Il vit au jour le jour, sans trop se poser de questions, dans sa petite sécurité et sans avoir de grands projets. Bien évidemment, le jour J, les personnes vont éprouver des regrets si elles ont agi de la sorte et donc, ne vont pas vouloir disparaître. Les principaux regrets éprouvés peuvent être les suivants : </p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">Avoir passé son temps à travailler constamment ; </li>\n<li aria-level=\"1\">Avoir coupé les ponts avec des personnes chères ; </li>\n<li aria-level=\"1\">Ne pas avoir réalisé ce qui vous faisait vibrer à cause du regard des autres ; </li>\n<li aria-level=\"1\">Ne pas avoir osé être soi, toujours à cause du jugement d’autrui.</li>\n</ul>\n<p>D’ailleurs, si vous souhaitez vous libérer du regard des autres, n’hésitez pas à aller consulter le programme du formateur et auteur Didier PENISSARD, que vous trouverez juste ci-dessous :</p>\n<p>Je vous invite donc, le plus souvent possible, à vous imaginer sur votre lit de mort en vous demandant, si vous vous sentez concerné par une des situations ci-dessus. Si oui, entreprenez les actions nécessaires pour ne pas avoir de regrets. Vous verrez que votre peur de mourir va s’atténuer. </p>\n<h3>Pratiquer des techniques de relaxation </h3>\n<p>Une personne ayant peur de la mort est anxieuse. De ce fait, les techniques de relaxation ne lui feront que le plus grand bien. </p>\n<p>Bon nombre de méthodes de relaxation existent. À vous de voir lesquels pourraient vous correspondre. Vous pouvez tenter le yoga, la sophrologie, la respiration (apprendre, en fait, à bien respirer. N’hésitez pas à aller consulter mon <a href=\"/respiration\" target=\"_blank\" rel=\"noopener\" title=\"Respiration\">article</a> sur le sujet), la méditation. Mais attention. Si vous êtes extrêmement anxieux, la méditation peut empirer votre état, étant donné que vous n’avez pas l’habitude de regarder en vous. Cette pratique reste un outil très puissant, mais à utiliser, soit accompagné par un professionnel, soit après avoir pratiqué d’autres techniques de relaxation moins intenses avant. </p>\n<p>Enfin, certaines pratiques comme l’hypnose et l’EMDR peuvent fonctionner dans le cas de la thanatophobie. À vous de choisir ! </p>\n<a href=\"https://hypnocaments.com?partnerid=YK5muYugzSoIWDbDWRgT-Q\" title=\"Seances d hypnose en ligne\"><img decoding=\"async\" src=\"https://hypnocaments.com/image/banner_1_750.png\" alt=\"seance hypnose mp3\"></a>\n<h3>Philosopher un petit peu sur la mort </h3>\n<p>Enfin, posez-vous la question suivante. Aimeriez-vous être immortel ? Sur le coup, vous auriez tendance à dire que oui. Cependant, même si je suis persuadée que l’on peut toujours apprendre dans la vie, le fait d’être éternel doit finir par devenir bien ennuyeux. De plus, regardez, au bout d’un certain nombre d’années, toutes les croyances et expériences que vous avez accumulées. Voyez à quel point elles jouent sur la perception que vous avez de la vie. Imaginez alors tout ce que vous devriez endurer, tous les souvenirs que vous auriez si vous étiez immortel ! Pas certaine que ce serait là la clé du bonheur. </p>\n<p>Par conséquent, pour profiter au maximum de l’existence, nous avons besoin de nous rappeler que nous ne sommes pas éternels. Nous avons donc besoin de la mort pour exister. La mort est naturelle, n’en ayez plus peur ! </p>\n<p> </p>\n<p>J’espère que cet article a pu vous aider à <b>soigner la thanatophobie</b> dont vous êtes victime. Je vous souhaite de vivre enfin pleinement ! </p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'Soigner la Thanatophobie pour Retrouver le Bien-être','Ressentir la crainte de mourir est monnaie courante. En développer une obsession se nomme la thanatophobie. Comment soigner la thanatophobie ?','https://vivre-pleinement.fr/thanatophobie/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/thanatophobie\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/thanatophobie\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Soigner la Thanatophobie pour Retrouver le Bien-\\u00eatre\",\"datePublished\":\"2020-04-16T14:28:07+00:00\",\"dateModified\":\"2024-02-12T19:08:27+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/thanatophobie\\/\"},\"wordCount\":5411,\"commentCount\":2,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/thanatophobie\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/04\\/Soigner-thanatophobie.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/thanatophobie\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/thanatophobie\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/thanatophobie\\/\",\"name\":\"Soigner la Thanatophobie pour Retrouver le Bien-\\u00eatre\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/thanatophobie\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/thanatophobie\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/04\\/Soigner-thanatophobie.jpg\",\"datePublished\":\"2020-04-16T14:28:07+00:00\",\"dateModified\":\"2024-02-12T19:08:27+00:00\",\"description\":\"Ressentir la crainte de mourir est monnaie courante. En d\\u00e9velopper une obsession se nomme la thanatophobie. Comment soigner la thanatophobie\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/thanatophobie\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/thanatophobie\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/thanatophobie\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/04\\/Soigner-thanatophobie.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/04\\/Soigner-thanatophobie.jpg\",\"width\":640,\"height\":494,\"caption\":\"Comment soigner la thanatophobie ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/thanatophobie\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Soigner la Thanatophobie pour Retrouver le Bien-\\u00eatre\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2020-04-16 14:28:07',NULL,'2026-05-24 19:19:45','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (36,'Soigner un Traumatisme Psychologique pour se Sentir à Nouveau Revivre','traumatisme','Lorsque vous souffrez de troubles anxieux ou d’un autre autre trouble répétitif vous causant de la souffrance, vous êtes probablement victime d’un traumatisme. Et il faut bien comprendre que tant que vous l’aurez, vous ne pourrez aller de l’avant. Vous êtes en proie à des pensées irrationnelles répétitives, par exemple, la peur de faire du mal à vos proches. Vos relations amoureuses se soldent constamment par un échec, car vous tombez toujours sur le même type de partenaire. Vous revivez sans cesse, surtout la nuit, un événement tragique survenu dans votre existence, comme un abus sexuel. Vous ressentez des blocages dans votre vie que vous n’arrivez pas à dépasser ? Comment soigner un traumatisme psychologique ? \n','<p>Lorsque vous souffrez de <b>troubles anxieux</b> ou d’un autre autre trouble <b>répétitif </b>vous causant de la <b>souffrance</b>, vous êtes probablement victime d’un traumatisme. Et il faut bien comprendre que tant que vous l’aurez, vous ne pourrez aller de l’avant. Vous êtes en proie à des<b> pensées irrationnelles répétitives</b>, par exemple, la peur de faire du mal à vos proches. Vos relations <b>amoureuses </b>se soldent constamment par un <b>échec</b>, car vous tombez toujours sur le <b>même </b>type de partenaire. Vous <b>revivez </b>sans cesse, surtout la <b>nuit</b>, un événement <b>tragique </b>survenu dans votre existence, comme un abus sexuel. Vous ressentez des <b>blocages </b>dans votre vie que vous n’arrivez pas à dépasser ? Comment <b>soigner un traumatisme psychologique ? </b></p>\n<h2>Qu’est-ce qu’un trauma ?  </h2>\n<p>Il est très important de faire la distinction entre trauma et traumatisme. Parlons d’abord du trauma.</p>\n<p>Tout le monde, dans sa vie, subira un trauma, voire même, plusieurs. Il s’agit d’un événement malheureux, tragique, survenant dans l’existence d’un individu, lequel se sent, à ce moment, en grand danger physique et moral. Ce trauma vient littéralement bouleverser sa routine. </p>\n<p>Il peut s’agir d’une séparation, d’un décès, d’un accident, d’une maladie, etc. ou plus grave, d’un attentat subi, d’avoir été victime d’une prise d’otages, d’une fusillade, d’abus sexuels… bon nombre d’anciens combattants deviennent, d’ailleurs, des personnes traumatisées. </p>\n<p>Cependant, l’événement peut aussi sembler, de prime abord, insignifiant, comme une opération chirurgicale et ce, même si elle s’est déroulée convenablement. </p>\n<p>L’incident peut également avoir été oublié. C’est souvent le cas s’il a eu lieu à un âge où l’être humain n’avait pas encore la capacité de se souvenir. Comme lorsqu’il était nouveau-né. Ce bébé a pu, par exemple, être en proie à un trauma pendant l’accouchement, voire même, lors de la grossesse intra-utérine.</p>\n<p>En résumé, le trauma est un événement, plus ou moins grave survenu dans la vie d’un individu, qu’il s’en souvienne ou non. En tout cas, cette situation a déclenché, chez la personne, une sensation d’extrême danger l’ayant fait passer en mode survie. </p>\n<h2>Qu’est-ce qu’un traumatisme ?</h2>\n<p>C’est la manière dont l’individu a perçu le trauma. S’il a choisi la fuite ou le combat, normalement, le trauma ne se transforme pas en traumatisme. Cependant, s’il est resté figé pendant l’événement, le corps ne se libère pas de la tension accumulée et de là, le traumatisme peur s’installer. </p>\n<h3>Stopper la culpabilité <b> </b></h3>\n<p>Attention de ne pas tomber dans le piège suivant <i>: </i><i>« </i>telle personne a subi le même trauma que moi, mais n’a pas développé de traumatisme. Je suis donc moins bien qu’elle, plus faible ? »</p>\n<p>Chaque personne, de par son histoire, son éducation et son environnement, réagira différemment par rapport à la même situation. C’est normal et ça ne fait pas de vous quelqu’un de faible. Il est possible que l’événement en question fasse ressortir en vous des blessures plus profondes, vous faisant réagir de manière beaucoup plus forte que vos pairs. Cependant, vous posez probablement d’autres forces ailleurs qu’eux ne possèdent pas. Et puis, il suffit d’être un petit peu plus fragilisé à une période de votre vie pour que le trauma devienne un traumatisme.</p>\n<p>Il n’y a en fait pas de règles. Il n’existe pas, d’un côté, les forts ne vivant que des traumas et de l’autre, les faibles ne subissant que des traumatismes. En réalité, il y a juste des êtres humains, faisant tout leur possible pour évoluer. Donc, s’il vous plaît, ne culpabilisez pas. </p>\n<p>Pour savoir si vous souffrez réellement de traumatisme, voyez si vous vous reconnaissez dans l’un des points suivants. Si le traumatisme traîne depuis très longtemps dans votre vie, les symptômes peuvent paraître moins impressionnants. Cependant, ils n’en demeurent pas moins importants. </p>\n<h3>Sentiment de blocage et perte de confiance </h3>\n<p>Vous sentez que vous ne parvenez pas à évoluer dans votre vie. Que certaines choses restent bloquées en vous. Vous êtes ainsi en proie à une, voire plusieurs, insatisfaction(s) récurrente(s) et avez l’impression d’être tombé dans un schéma répétitif. Par exemple, vous pouvez souffrir d’anxiété chronique que nous n’arrivez pas à maîtriser et ce, quoi que vous fassiez. Vous trouvez que les thérapies marchent pour les autres, mais pas chez vous. Donc, vous ne vous trouvez pas normal. Vous ne vous sentez d’ailleurs pas capable de faire face à la vie et n’avez pas confiance en vous. Un autre exemple. À chaque fois que vous rencontrez un homme, c’est toujours pareil. Il finit constamment par vous tromper. Vous vous dites : « mais pourquoi je tombe SANS CESSE sur le même type d’homme ? ».</p>\n<h3>Hyperactivité sociale </h3>\n<p>Et oui, étrange non ? Vous pouvez ne même pas vous rendre compte d’avoir un traumatisme dans ces conditions, étant donné qu’être sociable est bien vu par la société. Vous n’êtes donc pas embêté par les autres. Cependant, lorsque vous souhaitez être constamment entouré et sortir sans cesse, car vous ne pouvez supporter de rester seul, c’est probablement le signe d’un traumatisme. Vous vous fuyez afin d’éviter de vous retrouver face à vos blessures profondes. </p>\n<h3>Symptômes récurrents </h3>\n<p>Si vous refoulez vos émotions, elles n’auront d’autre choix que de sortir par votre corps. Donc, si vous êtes régulièrement sujet à des symptômes physiologiques récurrents, il peut s’agir d’un traumatisme, bien souvent, inconscient. Vous pouvez, par exemple, souffrir de migraines chroniques, lesquelles vous empêchent littéralement de vous lever et de vivre votre vie normalement. Ou de troubles du sommeil vous provoquant des cauchemars répétés. </p>\n<h3>Un caractère difficile </h3>\n<p>Si vous faites partie des caractères difficiles ou si vous souffrez d’un trouble de personnalité, vous pouvez clairement ne pas être facile à vivre pour votre entourage. Vous pouvez revêtir un caractère agressif, colérique, susceptible, paranoïaque, autoritaire, tyrannique, etc. généralement, cette façon d’être cache un traumatisme. </p>\n<h3>Une hypersensibilité </h3>\n<p>L’hypersensibilité est clairement due, pour moi, à des blessures traumatiques du passé. Je vous laisserai aller consulter mon <a href=\"/hypersensibilite\" target=\"_blank\" rel=\"noopener\" title=\"Hypersensibilité \">article</a> à ce sujet. </p>\n<p>Il peut également s’agir d’un traumatisme si vous ne supportez pas les sons en général (ce qui se nomme la misophonie, en passant). Par exemple, vous détestez entendre le bruit du clavier, de quelqu’un qui mange ou des aiguilles de l’horloge la nuit. Tandis que certains n’y prêtent absolument pas attention, vous trouvez, de votre côté, ces bruits insupportables.  </p>\n<h3>Une dépendance affective </h3>\n<p>Quand vous cherchez constamment de l’amour à l’extérieur au lieu de le chercher à l’intérieur de vous-même, il peut également s’agir d’un traumatisme. Par exemple, vous avez un conjoint et vous vous dites « s’il me quitte ou qu’il meurt, je ne pourrai vivre sans lui, je me suiciderai ». <i>Votre façon de penser </i>indique, très probablement, qu’il existe un traumatisme. Vous pouvez aussi dépendre affectivement d’autres personnes. Vos parents, vos enfants, vos frères, vos sœurs, etc. il n’y a pas de règles.</p>\n<h3>Pas de sensation physique</h3>\n<p>Vous connaissez très probablement, dans votre entourage, des personnes vous indiquant ne jamais ressentir la douleur. Elles pensent d’ailleurs que c’est une force. Je n’en suis pas si sûre. Car il peut, en effet, s’agir d’un traumatisme, coupant la personne de toutes ses sensations. </p>\n<p>Certains individus ne ressentent également rien lors de l’acte sexuel. Là aussi, il s’agit vraisemblablement d’un traumatisme, d’un déni du corps. </p>\n<h2>La transmission transgénérationnelle des traumatismes</h2>\n<p>Quelquefois, un traumatisme peut apparaître transgénérationnel, c’est-à-dire, transmis par vos ancêtres. Vous pouvez hériter de blessures profondes de vos ascendants sur au moins trois générations. Il s’agit souvent de traumatismes apparaissant dans votre vie alors que tout a l’air d’aller bien. </p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"500\" height=\"333\" src=\"/storage/blog-images/Blocage-emotionnel.jpg\" alt=\"Stress post-traumatique \" title=\"Blocage-émotionnel\">\n<h2>Un blocage traumatique avant tout physiologique</h2>\n<p>Nous pouvons ne pas nous rappeler du traumatisme. C’est le cas pour un nouveau-né, par exemple, pour lequel le cerveau ne possède pas encore l’activité neuronale suffisante pour se souvenir. Mais si notre mémoire ne se souvient pas, comment un traumatisme peut-il apparaître ? Car notre corps, lui, se rappelle du danger ayant été ressenti à ce moment. </p>\n<h3>La différence fondamentale entre animaux et êtres humains </h3>\n<p>Il faut bien comprendre que votre traumatisme ne passera pas si votre corps ne l’évacue pas. L’être humain est une merveilleuse création, mais quelquefois, bien trop complexe. Le problème principal, en effet, est que nous ayons relayé notre côté instinctif au dernier plan, en y plaçant avant le mental, l’intelligence, la complexité, etc. l’homme n’arrive donc pas à se dégager naturellement d’un trauma.</p>\n<p>Savez-vous que les animaux, bien plus proches de leur instinct que nous, peuvent directement empêcher le traumatisme de s’installer ? Car en cas de tensions ressenties suite à un trauma, ils les évacuent spontanément. Sans mental ni intellect pour comprendre pourquoi c’est arrivé, comment, etc. </p>\n<h3>Le pouvoir insoupçonné du corps</h3>\n<p>Maintenant que vous comprenez que le corps a mémorisé le traumatisme, vous devinez que vous ne pouvez vous sentir bien dans votre corps dans le moment présent. C’est pourquoi vous tentez souvent de vous évader dans le passé ou dans le futur. Sauf qu’en agissant ainsi, vous êtes en proie à de grandes ruminations. </p>\n<p>Il a également été prouvé scientifiquement que le corps donne 4 fois plus d’informations au cerveau que l’inverse. C’est pourquoi, si votre organisme souffre de traumatisme et même avec la meilleure volonté du monde, vous n’arrivez pas à vous raisonner. Émotionnellement comme mentalement. Voilà d’où proviennent les angoisses irrationnelles que vous pouvez, quelquefois ressentir. Vous savez qu’elles sont absurdes, mais continuez à être effrayé par elles.</p>\n<h2>Faut-il connaître la cause du traumatisme pour guérir ?</h2>\n<p>Il est tentant de croire qu’en connaissant l’origine de votre traumatisme, vous y obtiendrez la clé vous permettant d’aller mieux. Admettons que vous ayez une peur panique de l’avion. Vous découvrez la raison de votre terreur : il y a 5 ans, vous avez vu un documentaire sur un avion en train de se crasher. Maintenant, pensez-vous que votre traumatisme va disparaître ? Non, bien évidemment. </p>\n<p>Vous pouvez également être tenté d’effectuer des recherches sur vos troubles pour comprendre d’où ils peuvent provenir. J’ai d’ailleurs commis cette erreur un bon paquet d’années. Sauf qu’en agissant ainsi, vous ne passez pas à l’action pour tenter de remédier au problème. Vous n’en restez qu’à la théorie, laquelle continue à vous procurer un sentiment de sécurité. Ce qui peut alors être considéré comme une fuite. </p>\n<p>De plus, si vous vous attardez à connaître la cause de vos maux, vous n’allez faire qu’explorer le passé. Sauf que ce n’est pas très bon de se focaliser sur lui, surtout s’il est douloureux. Le risque reste de sombrer dans une dépression. </p>\n<p>Et puis, même si vous êtes certain que tel événement a provoqué le traumatisme, en êtes-vous si sûr ? Cette situation peut, effectivement, être l’un des éléments déclencheurs, mais êtes-vous sûr qu’elle est bien la seule ?</p>\n<p>Comment être sûr qu’il s’agit de tel épisode et non d’un autre ? Et qu’est-ce que le fait de le savoir vous apporterait de plus ?   </p>\n<h2>Lien entre traumatisme et troubles anxieux </h2>\n<p>Si vous souffrez de troubles anxieux chroniques, il y a fort à parier qu’un traumatisme se cache derrière. Vous avez également pris conscience que si votre anxiété reste difficilement contrôlable, c’est parce que votre corps est traumatisé. Donc, vous pouvez faire disparaître votre angoisse en travaillant sur votre mental ou vos émotions. Cependant, cette action ne fonctionnera que si un travail sur le corps a été effectué au préalable. Nous sommes loin de penser que le corps demeure la cause première de nos maux, et c’est normal. Mais maintenant, vous le savez.</p>\n<p>Il suffit, par exemple, d’imaginer comment vous vous sentez lors d’un bon massage. Si votre corps est détendu, il y a de fortes chances que votre mental se sente mieux, lui aussi.  </p>\n<p>Enfin, le traumatisme faisant passer l’organisme en mode survie, vous pouvez, souffrir de symptômes chroniques. La fatigue chronique reste un très bon exemple de traumatisme. À cause de cette fatigue ressentie, vous pensez ne pas avoir le choix et donc, ne pouvoir vivre une journée forte en activité. Vous allez ainsi préférer rester chez vous, au calme, pensant que vous n’avez, de toute façon, pas les capacités d’agir autrement. </p>\n<h2>Comment soigner un traumatisme psychologique ?</h2>\n<p>Fort heureusement, vous pouvez vous libérer du traumatisme. Ce n’est pas une fatalité. Mais pour ce faire, il va falloir travailler autant sur le caractère physiologique que sur l’aspect psychique, en commençant, vous vous en doutez, par le côté physique. </p>\n<p>Par contre, on ne se débarrasse pas d’un traumatisme facilement, d’autant plus s’il dure depuis plusieurs années. Guérir peut prendre plusieurs années, surtout si vous vous êtes identifié à une difficulté chronique. Par exemple, si vous êtes atteint de troubles anxieux sévères, vous pouvez penser représenter l’angoisse originelle. Vous parlez probablement souvent de vous utilisant la phrase « je SUIS angoissé » plutôt que « j’AI un problème anxieux ». </p>\n<p>Le poids des mots demeure important. En parlant ainsi, vous pensez être votre angoisse. Par conséquent, quand elle disparaîtra un jour, vous pouvez ressentir un vide tellement puissant que vous pourriez retourner à votre état d’anxiété. Rien que pour être, de nouveau, quelqu’un. Ce n’est pas que vous choisissez de rester dans votre anxiété par victimisation ou autre. C’est parce que vous croyez n’être plus rien sans elle, vu que vous pensez être elle. Il sera déjà donc bon de vous désidentifier de votre angoisse en faisant attention aux mots que vous employez. </p>\n<h3>Pratiquer la méthode TRE </h3>\n<p>La méthode TRE reste une pratique assez méconnue en FRANCE. Elle est plus connue au CANADA. Elle peut être considérée comme une sorte de yoga du tremblement. Cette pratique consiste à faire faire à la personne différentes postures, lesquelles lui provoquent des petites secousses et tremblements involontaires. Il y a lieu, à ce moment, de laisser les tremblements se faire. Cette approche aide l’organisme à se débarrasser des tensions emmagasinées. C’est ce que font les animaux.</p>\n<p>Vous pouvez pratiquer cette méthode au moins trois fois par semaine, pendant <b>½ </b>heure à chaque séance. </p>\n<p>À force d’effectuer cette méthode, certaines pratiques, qui pouvaient ne pas marcher chez vous, pourront, maintenant, fonctionner, puisque le corps est apaisé. Il peut s’agir, par exemple, de la thérapie comportementale et cognitive.</p>\n<p>Pour plus de renseignements sur cette technique, n’hésitez pas à aller consulter le <a href=\"https://www.cyrinne.com\" target=\"_blank\" rel=\"noopener\" title=\"Cyrinne BEN MAMOU\">blog de Cyrinne BEN MAMOU.</a> Je vous laisse la découvrir en parcourant son site.</p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h3>Pratiquer des techniques de relaxation </h3>\n<p>Il est conseillé de pratiquer des techniques de relaxation, lesquelles vous aideront à apaiser votre corps. Vous pouvez, à cet égard, aller consulter mon <a href=\"/respiration\" target=\"_blank\" rel=\"noopener\" title=\"Respiration\">article sur la respiration.</a> Vous pouvez également pratiquer le yoga et apprendre à méditer. </p>\n<p>Mais attention à la méditation et surtout, si vous souffrez de traumatisme ! Elle risque, en effet, d’empirer votre problème au début. Car, vous êtes trop traumatisé pour aller introspecter, de manière sereine, vos blessures intérieures. Cette pratique reste donc conseillée, mais seulement quand vous commencez à arpenter le chemin de la résilience. Il vaut mieux déjà apprendre à renouer avec votre corps, doucement, mais sûrement, en pratiquant la méthode TRE, le yoga, la gymnastique douce, etc.</p>\n<h3>Manger sainement <b> </b></h3>\n<p>On est ce que l’on mange. Donc, si vous vous respectez, vous arriverez à manger sainement et votre corps ne s’en portera que mieux. Pour une alimentation saine, vous pouvez opter pour un rééquilibrage alimentaire. </p>\n<p>Connaissez-vous la synergie alimentaire ? Car niveau santé, perte de poids, énergie et ce, tout en mangeant sainement sans se priver, c’est le top. Cette méthode associe en réalité certains aliments entre eux pour parvenir à ces résultats. Je vous conseille vivement le programme nutrition de Rémi MOHA, coach sportif et nutrition diplômé. Vous pouvez toujours faire un saut sur son site, d’autant plus que celui-ci propose un guide gratuit : </p>\n<h3>Ressentir ses émotions</h3>\n<p>Les émotions demeurent vitales pour votre bien-être et pour vous débarrasser d’un traumatisme. Pour ceux qui se sont coupés de leurs émotions (anesthésie émotionnelle), voici comment vous pouvez procéder. Vous pouvez apprendre à ressentir les sensations physiques perçues lorsque vous ressentez une émotion, mais sans bien la comprendre. </p>\n<p>Par exemple, après un événement, vous commencez à ressentir une émotion, mais sans pouvoir la nommer. Vous vous posez donc cette question : « Qu’est-ce que je ressens dans mon corps ? » <i> </i>Là, vous sentez que votre mâchoire se crispe énormément. Vous pouvez alors en déduire que vous éprouvez de la colère. </p>\n<p>Le domaine émotionnel paraît simple. Mais je vous assure que peu de personnes parviennent à identifier leurs émotions. C’est, pour moi, un des points principaux que l’on devrait apprendre aux enfants lors de leur parcours scolaire. Espérons que le système éducatif puisse s’ouvrir, de plus en plus, à de nouvelles manières de vivre pleinement la scolarité…</p>\n<h3>Apprendre à s’aimer soi-même </h3>\n<p>Je vous laisse aller consulter mon <a href=\"/confiance-et-estime-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Confiance et estime de soi\">article sur la confiance et l’estime de soi</a> pour plus de renseignements à ce sujet. L’amour de soi reste en effet primordiale pour aller mieux. C’est grâce à elle que vous comprenez que vous pouvez rebondir après des échecs. Ou que les autres n’apparaissent pas si menaçants qu’ils en ont l’air (dans le cas de la phobie sociale, par exemple).</p>\n<p>Rester solide intérieurement est l’élément le plus important qui soit pour votre bien-être. </p>\n<img loading=\"lazy\" decoding=\"async\" width=\"640\" height=\"372\" src=\"/storage/blog-images/Trauma.jpg\" alt=\"Schema repetitif \" title=\"Trauma\">\n<h3>Sortir de l’isolement social </h3>\n<p>Lorsque vous souffrez de traumatisme, vous pouvez facilement vous couper du monde. Vous manquez de confiance en vous et ne croyez pas en vos ressources pour affronter ce qui sort de votre zone de confort. </p>\n<p>Vous pouvez penser que vous n’êtes pas isolé, car vous ne le subissez pas et qu’il s’agit juste d’un choix de votre part. C’est surtout le cas des personnes atteintes du trouble de la personnalité évitante. Cependant, même s’il est vrai que vous pouvez tout à fait être quelqu’un de casanier et d’introverti, vous avez tout de même besoin de contact social. Puisque nous sommes des animaux sociaux… Si, par exemple, vous vous sentez bien chez vous, mais que vous êtes atteint de phobie sociale dès que vous sortez, ce n’est peut-être pas un choix de votre part.</p>\n<p>Il est donc bon, même si vous préférez rester chez vous, de faire un minimum d’efforts pour vous créer un réseau social. Cependant, si vous êtes victime de traumatisme, n’hésitez pas à y aller progressivement. Inutile d’inviter tous les soirs 50 voisins si vous avez l’anxiété sociale ! Allez-y pas à pas, afin de retrouver, petit à petit, la joie des relations humaines. </p>\n<h3>Se libérer de la honte toxique </h3>\n<p>Lorsque vous souffrez de traumatisme, vous pouvez avoir honte de votre état et donc, vous isoler. Vous vous sentez anormal et inférieur aux autres. </p>\n<p>Vous avez également peur que les personnes de votre entourage découvrent vos problèmes. D’ailleurs, vous pensez qu’ils vous jugeront et vous rejetteront violemment. Ce qui nourrit, évidemment, votre sentiment de honte. Vous cachez ainsi vos troubles, en priant pour que personne ne les découvre. Quel lourd poids sur les épaules vous portez ! </p>\n<p>Il n’y a pas 36 solutions pour sortir de la honte. Il faut simplement rester vous-même. Demeurer authentique. Oser exprimer vos faiblesses, ce qui vous fait honte, à autrui. C’est là que vous verrez que les gens ne vous jugent pas aussi durement que vous le pensez. Ils possèdent d’ailleurs leurs propres secrets. Vous n’avez pas besoin de détailler vos fragilités à chaque personne que vous croisez dans la journée, bien entendu ! Il ne faut juste pas avoir peur que vos fragilités puissent être révélées au grand jour. </p>\n<p>Je comprends vos peurs. Ces craintes, bien qu’exagérées, sont tout de même fondées. Puisque vous rencontrerez forcément des gens intolérants aux personnes différentes d’eux et moqueurs. Mais ne vous attardez pas sur eux. Remerciez-les plutôt. Car ce sont eux qui vous permettent de travailler sur votre blessure de rejet. </p>\n<h3>Prendre ses responsabilités</h3>\n<p>Le risque, lorsque vous souffrez de traumatisme, est de facilement tomber dans la victimisation. Vous pouvez prononcer ce genre de phrases : « Après ce qu’il m’est arrivé, c’est normal que je me comporte de la sorte »<i>. </i>Non, ce n’est pas normal. Premièrement, certaines personnes vivant la même situation ne réagissent pas comme vous. Deuxièmement, si vous pensez ainsi, vous insinuez que vous ne pouvez aller mieux. Que c’est une fatalité. Qu’il faudrait effacer le passé, ce qui n’est, bien entendu, pas possible. Alors que guérir d’un traumatisme reste réalisable : il s’agit de la résilience. Sortir plus fort d’un événement malheureux. Donc, à vous de prendre les choses en main et de passer à l’action. Sinon, c’est certain qu’en pensant de la sorte, rien ne bougera. Car vous aurez donné votre pouvoir, non pas à vous, mais à l’extérieur et à la fatalité. Éléments que vous ne pouvez maîtriser. </p>\n<h3>Sortir de la culpabilité</h3>\n<p>Inutile de vous culpabiliser de vous trouver dans un état traumatique. Si vous ressentez une fatigue chronique, ne pensez pas que c’est juste de paresse et que l’épuisement ne demeure qu’une excuse que vous vous trouvez. </p>\n<p>N’écoutez surtout pas les personnes disant qu’il s’agit d’un manque de volonté et d’une preuve de victimisation de votre part. Si vous souffrez d’un trouble anxieux sévère et que vous choisissez de rester dedans, c’est seulement parce que vous vous êtes trop identifié à votre anxiété. De plus, le traumatisme s’est installé dans votre corps via un état de tension accumulée et maintenant coincé. Il apparaît clair que le souhait de ne plus être angoissé, par exemple, n’est pas suffisante. Votre volonté n’a ainsi pas de pouvoir, du moins, tant que l’organisme reste dans cet état de pression. Donc non, vos problèmes ne se trouvent pas dans votre tête. Qui chercherait volontairement à rester dans le mal-être ?</p>\n<h3>Stopper les ruminations mentales</h3>\n<p>Entraînez-vous régulièrement à couper court à vos ruminations mentales. Par contre, mieux vaut d’abord les analyser par le biais de vos émotions en vous demandant quels besoins fondamentaux ne sont pas satisfaits de votre côté. Là seulement, vous pourrez vous exercer à arrêter vos ruminations. En réalisant, par exemple, une activité, en attirant votre attention sur vos sens, en entamant une discussion légère avec une personne, etc. Car directement les stopper sans les comprendre peut être considéré comme un refoulement d’émotions. Je vous laisse, à cet égard, aller consulter mon <a href=\"/le-mal-a-dit\" target=\"_blank\" rel=\"noopener\" title=\"Le mal a dit\">article sur le lien entre troubles émotionnels et maladies. </a></p>\n<h3>Voir le verre à moitié plein </h3>\n<p>Lorsque vous souffrez de traumatisme, vous pouvez penser au passé (ruminations dépressives) et au futur (ruminations anxieuses). Cependant, entraînez-vous à voir le monde de manière plus positive. Comprenez que le monde n’est pas horrible. Il y a du positif dans ce monde aussi. De bonnes personnes, chaleureuses, solidaires, etc. Apprenez également à savourer ce que vous avez dans l’existence en arrêtant de vous concentrer sur ce qu’il vous manque. </p>\n<p>Sur ce point, les affirmations positives peuvent aider. Mais attention, pas n’importe lesquelles. Il faut surtout travailler sur celles qui sont souples et réalistes. Par exemple, si vous vous dites inlassablement « le monde est merveilleux, la vie est toujours belle », votre mental ne le croira pas. Ce n’est pas réaliste. Répétez-vous plutôt : « la vie est belle, mais quelquefois elle ne l’est pas. Elle est parfois injuste, mais c’est valable pour tout le monde. Le monde est seulement tel qu’il est, neutre ». En parlant ainsi, votre mental y accrochera plus, puisque c’est réaliste. Et vous ne serez plus tenté de déprimer inlassablement en répétant que le monde est atroce. Vous retrouverez un juste milieu. </p>\n<h3>Avoir un but dans la vie</h3>\n<p>Dans la vie, nous avons tendance à vouloir entrer dans les normes afin d’être acceptés. Cependant, en agissant ainsi, nous ne demeurons pas toujours authentiques. De ce fait, nos besoins profonds, par peur du regard des autres, ne sont pas satisfaits. Voilà pourquoi certaines personnes, ayant tout ce qu’il faut d’un point de vue normatif (maison, mari, enfant, chien, travail, voiture, etc.) pourront ressentir, un jour, un grand vide intérieur. Si vous éprouvez ce sentiment, c’est tout simplement parce que vous n’avez pas de buts. Vous vivez comme la société vous l’ordonne, mais pas comme vous, vous le voulez. </p>\n<p>À vous donc de découvrir ce qui vous fait vibrer dans votre vie et osez passer à l’action, même si vous vous écartez des normes. Avoir un vrai objectif va vraiment vous donner un regain de motivation et une envie de vivre spectaculaire. Vous pouvez aussi trouver un but qui pourrait aider bon nombre de personnes. Il est merveilleux de trouver un projet pouvant contribuer, ne serait-ce qu’à petite échelle, à construire un monde meilleur, non ? Il n’y a pas de buts meilleurs que d’autres. À vous de trouver le vôtre, tout simplement. </p>\n<h3>Choisir ses fréquentations</h3>\n<p>Lorsque vous souffrez de traumatisme, essayez, le plus possible, d’éviter certaines personnes. Surtout celles apparaissant négatives, anxieuses ou dépressives. Car si vous-même êtes ainsi, cette personne ne risque pas d’arranger votre état. Et effet, savez-vous que les énergies que dégagent les gens se ressentent et demeurent contagieuses ? Entourez-vous plutôt de personnes qui vous tirent vers le haut. Et évitez celles qui vous font vous sentir mal à l’aise, en manque d’énergie, anxieux, etc.</p>\n<h3>Profiter pleinement de la nature </h3>\n<p>La nature a un fort impact sur votre état de santé. Je pense que vous l’entendez bien assez, à la radio, à la télévision, dans les journaux, etc. oui, la nature est bonne pour votre santé. Rien que le soleil amène de la vitamine D. La nature vous fait reprendre contact avec ce qui est vraiment important. Elle vous permet de vous reconnecter avec la vraie vie. Avec tout ce qui n’a pas été créé par l’homme. Ce qui se trouvait déjà là bien avant nous. Ce à quoi nous sommes véritablement reliés. </p>\n<p>N’hésitez donc pas, dès que c’est possible, à sortir quand il fait beau. Vous devrez, peut-être au début du fait de l’isolement, vous forcer un peu. Mais je vous assure que le jeu en vaut la chandelle. </p>\n<h3>Analyser ses rêves</h3>\n<p>Je ne crois pas que tous les rêves aient forcément un sens. Mais ceux revenant fréquemment, à mon sens, en revêtent un. Par exemple, si vous rêvez, régulièrement, de vous trouver dans un groupe et que les gens vous laissent tomber systématiquement, je pense que ce n’est pas un simple rêve aléatoire. Il serait bon d’analyser plus en profondeur ce rêve, afin de savoir s’il ne cache pas une grande blessure d’abandon et de rejet. Les rêves peuvent donc, quelquefois, vous aiguiller sur ce qu’il conviendrait de travailler chez vous. </p>\n<h3>Envisager une thérapie </h3>\n<p>N’hésitez pas à vous faire aller consulter par un professionnel de la santé. Une psychothérapie, dont notamment la TCC, peut grandement vous aider. </p>\n<p>Si votre traumatisme est vraiment important, vous pouvez prendre des médicaments, comme les antidépresseurs ou les anxiolytiques. Mais mieux vaut que le traitement ne reste qu’une béquille, en attendant d’avoir à nouveau la force de passer à l’action. Car la prise de comprimés sur la durée peut cacher le véritable problème. </p>\n<p>Vous pouvez également tenter les médecines alternatives, qui peuvent constituer un très bon complément. Cependant, méfiez-vous des personnes voulant vous faire croire que vous ne guérirez qu’avec leur méthode et pas autrement. Ce n’est pas vrai. Beaucoup de solutions peuvent être envisagées pour vous soulager. Donc, attention à ce genre de propos, semblant sectaires. Ouvrez-vous aux expériences, oui, mais sans prêter forcément dévotion à une technique particulière.</p>\n<p>Ne vous découragez pas si vous ne trouvez pas, du premier coup, le thérapeute qui vous correspond. Tout est aussi une question de feeling, de caractère. Prenez donc le temps de le chercher. Vous n’êtes pas anormal si le courant ne passe pas avec une personne. Persévérez jusqu’à trouver la bonne. Cette recherche peut prendre beaucoup de temps. C’est, finalement, comme trouver le bon partenaire, le bon job, la maison idéale, etc.  </p>\n<p>Enfin, ne tombez pas dans le piège de penser qu’une personne aidante peut <b>soigner un traumatisme psychologique</b> sans que vous passiez à l’action de votre côté. En effet, elle va juste vous donner des clés. Ce sera à vous de réaliser le travail intérieur. Personne ne peut régler les problèmes à votre place. Vous êtes la seule personne à pouvoir prendre votre vie en main !</p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'Soigner un Traumatisme Psychologique pour se Sentir à Nouveau Revivre','Vous ressentez des blocages dans votre vie que vous n\'arrivez pas à les dépasser. Comment soigner un traumatisme psychologique ?','https://vivre-pleinement.fr/traumatisme/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/traumatisme\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/traumatisme\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Soigner un Traumatisme Psychologique pour se Sentir \\u00e0 Nouveau Revivre\",\"datePublished\":\"2020-04-12T14:02:34+00:00\",\"dateModified\":\"2024-02-13T17:14:19+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/traumatisme\\/\"},\"wordCount\":8358,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/traumatisme\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/04\\/Soigner-traumatisme-psychologique.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/traumatisme\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/traumatisme\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/traumatisme\\/\",\"name\":\"Soigner un Traumatisme Psychologique pour se Sentir \\u00e0 Nouveau Revivre\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/traumatisme\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/traumatisme\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/04\\/Soigner-traumatisme-psychologique.jpg\",\"datePublished\":\"2020-04-12T14:02:34+00:00\",\"dateModified\":\"2024-02-13T17:14:19+00:00\",\"description\":\"Vous ressentez des blocages dans votre vie que vous n\'arrivez pas \\u00e0 les d\\u00e9passer. Comment soigner un traumatisme psychologique\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/traumatisme\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/traumatisme\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/traumatisme\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/04\\/Soigner-traumatisme-psychologique.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/04\\/Soigner-traumatisme-psychologique.jpg\",\"width\":500,\"height\":333,\"caption\":\"Comment soigner un traumatisme psychologique ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/traumatisme\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Soigner un Traumatisme Psychologique pour se Sentir \\u00e0 Nouveau Revivre\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2020-04-12 14:02:34',NULL,'2026-05-24 19:19:45','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (37,'Quelle différence entre rancune et rancœur et comment s’en libérer ?','rancune-et-rancoeur','Parmi les émotions négatives que peut ressentir un être humain, il y a la rancune et la rancœur. Ces émotions peuvent prendre la forme d’une grande colère, d’un désir de vengeance voire même, d’une tristesse sourde. Le problème avec ces sentiments, c’est qu’ils peuvent ronger, petit à petit, un individu de l’intérieur. Vous avez coupé les ponts avec votre meilleur ami et ressentez maintenant une profonde haine à son égard. Vos beaux-parents vous ont fait des remarques négatives et depuis, vous ruminez toujours là-dessus, ce qui vous fait vivre une rage de fond constante. Vous êtes un adepte de la phrase : je pardonne, mais je n’oublie pas. La rancune et la rancœur nuisent à votre santé, physique comme mentale ? Quelle différence entre rancune et rancœur et comment vous libérer de ces sentiments dévastateurs ? \n','<p>Parmi les <b>émotions </b>négatives que peut ressentir un être humain, il y a la rancune et la rancœur. Ces émotions peuvent prendre la forme d’une grande <b>colère, </b>d’un désir de <b>vengeance</b> voire même, d’une<b> tristesse</b> sourde. Le problème avec ces sentiments, c’est qu’ils peuvent <b>ronger</b>, petit à petit, un individu de l’intérieur. Vous avez coupé les ponts avec votre meilleur ami et ressentez maintenant une profonde <b>haine </b>à son égard. Vos beaux-parents vous ont fait des <b>remarques </b>négatives et depuis, vous <b>ruminez </b>toujours là-dessus, ce qui vous fait vivre une rage de fond <b>constante</b>. Vous êtes un adepte de la phrase : <i>je </i><b><i>pardonne, </i></b><i>mais je </i><b><i>n’oublie pas</i></b><i>. </i>La rancune et la rancœur nuisent à votre <b>santé</b>, physique comme mentale ? <b>Quelle différence entre rancune et rancœur</b> et comment vous <b>libérer </b>de ces sentiments dévastateurs ? </p>\n<h2>Quelle différence entre rancune et rancœur : définition de la rancune </h2>\n<p>La rancune est une émotion que vous pouvez ressentir lorsqu’une personne vous a blessé. Il peut également s’agir d’une situation que vous trouvez injuste. Par conséquent, vous commencez à éprouver de la <a href=\"/colere\" target=\"_blank\" rel=\"noopener\" title=\"Colère\">colère</a>, laquelle, bien souvent, ne passe pas. Cette émotion s’installe donc de manière quotidienne dans votre vie, et vous n’arrivez pas à passer outre la blessure vous ayant été infligée. De ce fait, vous ressentez une envie de vengeance. Vous pensez que c’est le seul moyen de retrouver la paix. Vous allez don généralement blesser profondément l’autre autant qu’il vous a offensé. Sauf que malheureusement pour vous, le fait de réussir à vous venger ne soulagera en aucun cas votre peine. Vous n’irez pas mieux.</p>\n<h2>Définition de la rancœur  </h2>\n<p>Dans le fond, la rancune et la rancœur peuvent paraître assez similaires. Cependant, la rancœur s’exprime de manière plus visible. La colère s’y trouve en général plus intense. Même si elle cache, bien souvent, le vrai sentiment ressenti : la tristesse. D’ailleurs, je vous conseille vivement, dès que vous ressentez une émotion négative, de bien l’analyser afin de voir s’il n’y aurait pas une émotion plus sourde cachée derrière. Car c’est elle le véritable problème. </p>\n<p>La personne sujette à un profond ressentiment est une professionnelle de la rumination mentale. Elle repasse sans cesse la scène qui l’a blessé en boucle. Elle va s’imaginer, lors de cette scène, répondre différemment, attaquer l’autre avec animosité, etc. ou tout simplement se la remémorer telle quelle. Sauf qu’en agissant ainsi, le mental sera tellement puissant que les émotions demeureront exactement les mêmes que celles ayant été ressenties au moment de ce différend. Il peut s’agir de déception, de haine, de peur, etc. Ce cercle vicieux pousse donc la personne à ressasser, ruminer sans cesse et… à ne rien entreprendre du tout. Elle reste alors bloquée dans son mal-être.  </p>\n<h2>Les personnalités sujettes à la rancune et à la rancœur </h2>\n<p>Tout le monde a déjà ressenti ce genre de sentiments négatifs. Nous demeurons humains, après tout. Cependant, certains d’entre nous subissent ces émotions très souvent. Elles font presque même partie de leur caractère. </p>\n<p>Je vous invite d’ailleurs à aller consulter mon <a href=\"/troubles-de-la-personnalite\" target=\"_blank\" rel=\"noopener\" title=\"Troubles de la personnalité \">article sur les troubles de la personnalité.</a> Ils peuvent quelquefois expliquer certaines émotions et les attitudes néfastes qu’une personne peut adopter. Et parmi ces troubles de la personnalité, une personnalité reste particulièrement sujette à la rancune et à la rancœur : la personnalité passive-agressive. En effet, cette personne, bien souvent, ne dira pas ouvertement qu’elle est contrariée. Elle le fera comprendre de manière sournoise et détournée, par ses comportements ou ses non-dits. </p>\n<p>Il a également été observé que les personnes les plus enclines à la rancune et à la rancœur étaient celles possédant un égo important. Elles peuvent même apparaître orgueilleuses (l’orgueil représentant l’égo à son plus fort). Il s’agit donc d’individus fiers, autoritaires et ne souhaitant pas se soumettre aux autres. Ils ont la croyance, bien souvent et à tort, que ces sentiments donnent l’effet d’être quelqu’un de puissant, que les autres respectent. Or, ce n’est pas que les gens admirent ces personnes, mais plutôt qu’ils en ont peur. Ils confondent ainsi crainte et respect. </p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"269\" src=\"/storage/blog-images/Ressentiment.jpg\" alt=\"Animosité\" title=\"Ressentiment\">\n<h2>Les conséquences de la rancune et de la rancœur</h2>\n<p>Éprouver des sentiments de rancune et de rancœur sur le long terme peut avoir de lourdes conséquences sur votre vie mentale, physique et relationnelle. </p>\n<h3>Conséquences émotionnelles </h3>\n<p>Le problème en ressentant ce genre de sentiments, c’est que vous restez rarement objectif. L’autre est mauvais, vous vous êtes bon. Votre semblable vous a blessé, alors vous le blessez (même si ladite personne ne le fait souvent pas exprès). Vous ne voyez plus du tout les qualités de votre pair, mais plutôt ses défauts. Vous ne nous remettrez pas en question et n’êtes pas objectif sur la situation. C’est vous qui avez raison et l’autre tort, un point c’est tout. </p>\n<p>Forcément, en pensant ainsi sur le long terme, vous devenez colérique, puis triste. Et si ces émotions négatives ne sont pas traitées rapidement, le risque est que l’individu commence à perdre la confiance et l’estime qu’il a pour lui. Il peut aussi se retrouver à développer des troubles anxieux voire même, une dépression. </p>\n<h3>Conséquences somatiques </h3>\n<p>Le problème avec les émotions mal gérées, c’est qu’elles font, à la longue, apparaître des maux physiques. Ces problèmes peuvent être plus ou moins handicapants et plus ou moins dangereux pour votre santé. Ce fait apparaît également valable pour celui qui refoule ses sentiments. Par exemple, une personne qui coupe complètement les ponts avec quelqu’un en se persuadant que cette situation ne l’affecte pas. Ce déni émotif va forcément faire apparaître des troubles physiques, puisque toute émotion ne pouvant sortir le fera par le corps. Il peut y avoir : </p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">Les problèmes de sommeil, souvent dus à la colère, la rumination et la tristesse ;</li>\n<li aria-level=\"1\">Le manque d’énergie, fréquemment dû à des situations laissées telles quelles et donc, non terminées ; </li>\n<li aria-level=\"1\">Les maux de tête dus à la tension accumulée et au stress ;</li>\n</ul>\n<ul>\n<li aria-level=\"1\">Les soucis au cœur. Cette complication arrive souvent aux personnes jugeant durement autrui et prenant les choses trop à cœur ;</li>\n<li aria-level=\"1\">Le cancer, lequel reste l’ultime moyen que le corps a trouvé pour tenter de faire comprendre un message. Il a émis des messages via d’autres troubles somatiques moins importants, mais n’ayant pas été pris en compte par l’individu. Cette maladie provient donc de blessures très profondes non guéries et refoulées, lesquelles ont, petit à petit, rongé la personne de l’intérieur. </li>\n</ul>\n<p> </p>\n<p>Je vous laisse consulter mon <a href=\"/le-mal-a-dit\" target=\"_blank\" rel=\"noopener\" title=\"Le mal a dit \">article sur le lien entre émotions et maladies</a> pour plus d’informations. </p>\n<h3>Conséquences relationnelles </h3>\n<p>Quand une personne éprouve rancune et rancœur, ses relations restent le domaine le plus impacté.</p>\n<p>Si un individu ressent ce genre de sentiments, c’est que beaucoup de non-dits se sont instaurés dans la relation. Les émotions ne se sont donc pas exprimées, généralement par peur du conflit ou d’entendre des vérités, lesquelles pourraient nuire, voire stopper net, une relation. Malheureusement, c’est bien souvent ce que vous redoutez qui se produit, car l’émotion doit forcément sortir à un moment donné. Mais, elle sort trop tard et de manière bien trop agressive et excessive par rapport à la situation donnée. Ce qui pourra braquer la personne en face de vous, laquelle ne comprendra absolument pas cette réaction et pourrait ne pas tolérer cette manière de procéder. </p>\n<p>En réalité, un individu en proie à des sentiments de rancœur et rancune ne tolère pas ce braquage et refuse d’entendre des vérités qui pourraient le blesser. Par conséquent, il préfère faire preuve de froideur, d’aigreur voire même, couper les ponts. Il s’agit donc d’une fuite<b>, </b>laquelle ne résout malheureusement pas la situation. Ce qui est dommage avec ce manque de communication, c’est que la personne en face ne peut ni s’excuser ni se remettre en question. Étant donné qu’elle n’a obtenu aucune explication. Une relation aurait ainsi pu être sauvée.</p>\n<p>Par conséquent, bon nombre de relations dans votre vie risquent d’être impactées si vous agissez régulièrement de la sorte. Au risque de vous faire avoir une vision aigrie de l’existence et des gens en général.  </p>\n<h2>Conseils à appliquer à l’égard d’une personne rancunière </h2>\n<p>Quelquefois, ce n’est pas forcément vous qui êtes atteint par ces émotions de rancune et de rancœur. Il peut s’agir d’une personne de votre entourage. Cependant, avant de culpabiliser, posez-vous les questions suivantes :</p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">Ai-je fait quelque chose de mal ?</li>\n<li aria-level=\"1\">Si oui, puis-je m’excuser ou me rattraper ?</li>\n<li aria-level=\"1\">L’autre a-t-il aussi sa part de responsabilité ? </li>\n</ul>\n<p> </p>\n<p>Bien souvent, même si vous avez offensé quelqu’un, ce n’était pas volontaire. Il y a donc lieu de l’expliquer à la personne offensée. Vous pouvez également faire comprendre à l’autre que la communication aurait pu éviter ce conflit. Votre semblable comprendra ainsi qu’il ne s’agissait que d’une erreur d<b>’</b>interprétation et si chacun se remet en question, la relation ne pourra qu’en ressortir plus forte. </p>\n<h3>Ne pas prendre la responsabilité de la rancœur et de la rancune de l’autre</h3>\n<p>Quand un individu a la rancune tenace, il peut ne vous donner aucune chance de vous expliquer voire même, de vous excuser. Dans ces conditions, vous pouvez toujours faire le premier pas. Même si vous estimez ne pas avoir, normalement, à le faire. Car dites-vous bien que la personne faisant le premier pas est la plus intelligente. Cependant, si cette personne vous envoie à nouveau sur les roses et qu’elle ne souhaite pas la réconciliation, il est temps, pour vous, de faire le deuil de cette relation. Vous n’avez, en effet, pas à prendre la responsabilité de la rancœur de l’autre. Vous avez accompli ce que vous pouvez de votre côté et donc, n’avez pas à culpabiliser.</p>\n<h3>Garder sa dignité </h3>\n<p>Enfin, faites bien attention à la culpabilité malsaine. Certaines personnes exigeront que vous vous excusiez plus que de raison. Ils souhaitent vous humilier, vous punir et vous faire souffrir comme elle estime que vous devez souffrir après ce « préjudice » subi. Or, personne n’a le droit de venir entacher votre dignité ainsi. Vous n’avez à vous rabaisser auprès de quelqu’un en aucun cas. Fuyez ce genre de comportement toxique et cette hostilité. Demander pardon une fois est déjà énorme. Et si l’autre ne le comprend pas, tant pis pour lui.</p>\n<img decoding=\"async\" width=\"640\" height=\"426\" src=\"/storage/blog-images/Vengeance.jpg\" alt=\"Aigreur\" title=\"Vengeance\">\n<h2>Se libérer de la rancune et de la rancœur </h2>\n<p>Voici maintenant les solutions afin de vous aider à vous libérer de ces émotions destructrices. Car malgré la croyance populaire qui est qu’avec le temps, tout passe, ce n’est pas le cas. Ces sentiments, bien que moins impressionnants émotionnellement que la colère, n’en sont que plus dangereux, puisque plus stables. Ils alimentent ainsi la blessure déjà présente depuis longtemps. Ne comptez donc pas juste sur le temps pour régler vos problèmes. Passez plutôt à l’action, et ce, pour votre bien.</p>\n<h3>S’affirmer </h3>\n<p>Ces sentiments proviennent, à la base, d’un défaut de communication. L’idéal reste donc de vous affirmer dès qu’une situation vous dérange. En agissant de la sorte, vous comprendrez que vos interprétations apparaissent, la plupart du temps, infondées. Et si elles s’avèrent finalement correctes, vous pourrez alors avoir de réelles explications avec l’autre. L’Accord toltèque « ne pas faire de supposition » illustre d’ailleurs parfaitement cet état de fait. </p>\n<p>Ensuite et selon les éclaircissements reçus, vous pouvez choisir de garder contact avec la personne comme avant, ou, au contraire, de tourner la page. Vous aurez au moins été clair et honnête et pourrez ainsi passer à autre chose. </p>\n<p>Après, la communication peut ne pas être envisageable pour tout un tas de raisons. Par exemple, la personne ne souhaite plus vous parler, l’affirmation de soi n’a pas pu être réalisée en temps et en heure, etc. Dans ce cas, vous pouvez rédiger une lettre concernant l’individu ou la situation en cause. Dans ce courrier, n’hésitez pas à écrire absolument tout ce que vous avez sur le cœur, que vous l’envoyez ou pas. Cet exercice est en effet très libérateur. Il permet de faire sortir vos émotions malgré une affaire non résolue. De plus, préférez écrire à la main plutôt que sur ordinateur. Car les effets sur le cerveau ne sont pas les mêmes. L’impact de la lettre manuscrite sur le cerveau demeure bien plus important. </p>\n<h3>Pratiquer l’acceptation  </h3>\n<p>Je vous invite à consulter mon <a href=\"/lacher-prise-et-acceptation\" target=\"_blank\" rel=\"noopener\" title=\"Lâcher-prise et acceptation\">article sur le lâcher-prise et l’acceptation</a> pour plus de renseignements à ce sujet. Il y a donc lieu d’accepter la situation et quand conflit il y a eu avec une personne, évitez de commettre l’erreur de médire négativement sur elle à tout votre entourage. Cela n’aura pour effet que de vous faire stagner dans un sentiment de haine permanent. Car en agissant ainsi, vous n’acceptez pas les choses et ne pourrez passer à autre chose. </p>\n<p>Et surtout, si cette personne était très importante pour vous, elle n’a pas pu passer de toute blanche à toute noire. Votre vision à son sujet n’apparaît donc plus objective. Par conséquent, il y a lieu de respecter cet individu tout en continuant à avancer dans votre existence. Il a fait, pendant un temps, partie des personnes importantes sur votre chemin de vie. Mais vos chemins ne sont, maintenant, plus les mêmes. </p>\n<h3>Travailler sur ses blessures </h3>\n<p>Il s’agit là d’un des points les plus importants poussant une personne à ressentir des émotions de rancune et de rancœur. Car bien souvent, vous n’êtes pas rancunier dans tous les domaines. Il existe, en effet, des domaines qui vous touchent beaucoup plus et qui vous poussent à une rancœur et à une souffrance extrêmes. Donc, quand vous ressentez ces sentiments lors d’une situation conflictuelle, par exemple, vous pouvez vous poser cette question. « Ah, tiens, cette situation me touche énormément. C’est qu’il y a un point à travailler. Une blessure profonde s’est réactivée. Quelle douleur cet évènement ou cet individu a réveillée en moi ? »</p>\n<p>Car ce n’est pas directement la personne ou la situation qui est en cause. Mais bien une grande souffrance enracinée dans votre esprit, laquelle vient justement d’être ravivée par ladite personne ou situation. Donc, afin de vous défaire de ces émotions intenses, il y a lieu, avant toute chose, de vous introspecter.  </p>\n<p>La guérison des blessures demeure extrêmement importante si vous souhaitez sortir de certains schémas répétitifs. </p>\n<h3>Pratiquer le pardon véritable</h3>\n<p>Il est bon de faire le premier pas, que vous ayez tort ou non, et ce, rien que pour votre évolution personnelle. Même si mettre son égo de côté reste difficile. Mais cette attitude est nécessaire. Car la personne faisant le premier pas apparaît la plus intelligente. </p>\n<p>Avec la guérison de vos blessures, pardonner aux autres reste l’élément le plus vital pour vous libérer des sentiments de rancune et de rancœur. </p>\n<h3>Envisager une thérapie </h3>\n<p>Enfin, si vraiment votre rancune et votre rancœur vous gâchent la vie et que vous n’arrivez pas à vous en sortir seul, n’hésitez pas à aller voir un professionnel de la santé. Il n’y a aucune honte à se faire aider. C’est plutôt une preuve de force.</p>\n<p><b>Quelle différence entre rancune et rancœur ? </b>J’espère que cet article vous a aidé à y voir plus clair et que vous allez maintenant pouvoir vous libérer de ces fardeaux émotionnels ! </p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'Quelle différence entre rancune et rancœur et comment s’en libérer ?','La rancune et la rancœur sont des sentiments négatifs dévastateurs. Quelle différence entre rancune et rancœur et comment vous en libérer ?','https://vivre-pleinement.fr/rancune-et-rancoeur/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/rancune-et-rancoeur\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/rancune-et-rancoeur\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Quelle diff\\u00e9rence entre rancune et ranc\\u0153ur et comment s\\u2019en lib\\u00e9rer\\u2009?\",\"datePublished\":\"2020-03-21T16:29:45+00:00\",\"dateModified\":\"2024-02-13T17:15:24+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/rancune-et-rancoeur\\/\"},\"wordCount\":4577,\"commentCount\":2,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/rancune-et-rancoeur\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/03\\/Difference-rancune-rancoeur.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/rancune-et-rancoeur\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/rancune-et-rancoeur\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/rancune-et-rancoeur\\/\",\"name\":\"Quelle diff\\u00e9rence entre rancune et ranc\\u0153ur et comment s\\u2019en lib\\u00e9rer\\u2009?\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/rancune-et-rancoeur\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/rancune-et-rancoeur\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/03\\/Difference-rancune-rancoeur.jpg\",\"datePublished\":\"2020-03-21T16:29:45+00:00\",\"dateModified\":\"2024-02-13T17:15:24+00:00\",\"description\":\"La rancune et la ranc\\u0153ur sont des sentiments n\\u00e9gatifs d\\u00e9vastateurs. Quelle diff\\u00e9rence entre rancune et ranc\\u0153ur et comment vous en lib\\u00e9rer\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/rancune-et-rancoeur\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/rancune-et-rancoeur\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/rancune-et-rancoeur\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/03\\/Difference-rancune-rancoeur.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/03\\/Difference-rancune-rancoeur.jpg\",\"width\":640,\"height\":457,\"caption\":\"Quelle est la difference entre rancune et ranc\\u0153ur ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/rancune-et-rancoeur\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Quelle diff\\u00e9rence entre rancune et ranc\\u0153ur et comment s\\u2019en lib\\u00e9rer\\u2009?\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2020-03-21 16:29:45',NULL,'2026-05-24 19:19:45','2026-06-19 22:28:14');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (38,'Différence entre Dépersonnalisation et Déréalisation et Moyens d’en Guérir','depersonnalisation-et-derealisation','Lorsque vous souffrez de troubles anxieux, bon nombre de symptômes inconfortables peuvent apparaître. À ce sujet, je pense que les symptômes de dépersonnalisation et déréalisation restent de loin les manifestations les plus désagréables et effrayantes pouvant être ressenties dans l’anxiété. Ces troubles demeurent, en effet, très impressionnants et peuvent faire basculer l’individu dans une angoisse encore plus grande s’il ne comprend pas ce qui lui arrive. Un beau jour, vous vous réveillez en ayant l’impression de vous trouver constamment dans un rêve. Vous vous regardez dans le miroir et vous demandez si c’est bien vous : vous ne vous reconnaissez plus. Vous ressentez une peur panique à l’idée de ne plus redevenir comme avant. Vous ne supportez plus cet état de dépersonnalisation et déréalisation ? Quelle est la différence entre dépersonnalisation et déréalisation et comment vous en libérer ? \n','<p>Lorsque vous souffrez de <b>troubles anxieux</b>, bon nombre de symptômes inconfortables peuvent apparaître. À ce sujet, je pense que les symptômes de dépersonnalisation et déréalisation restent de loin les manifestations les plus <b>désagréables </b>et <b>effrayantes</b> pouvant être ressenties dans l’anxiété. Ces troubles demeurent, en effet, très<b> impressionnants </b>et peuvent faire basculer l’individu dans une angoisse encore plus grande s’il ne comprend pas ce qui lui arrive. Un beau jour, vous vous réveillez en ayant l’impression de vous trouver constamment dans un <b>rêve</b>. En vous regardant dans le <b>miroir,</b> vous demandez si c’est bien vous : vous ne vous <b>reconnaissez plus</b>. Vous ressentez une peur <b>panique </b>à l’idée de ne plus <b>redevenir </b>comme avant. Vous ne <b>supportez </b>plus cet état de dépersonnalisation et déréalisation ? Quelle est la <b>différence entre dépersonnalisation et déréalisation</b> et comment vous en libérer ? </p>\n<h2>Qu’est-ce que la dépersonnalisation et la déréalisation ?  </h2>\n<p>Avant d’aller plus loin, il est bon d’expliquer plus en détail ces troubles.</p>\n<h3>Comprendre que ces symptômes restent bénins</h3>\n<p>Les troubles de dépersonnalisation et déréalisation, quand vous en faites l’expérience, peuvent s’avérer extrêmement effrayants. Néanmoins, il faut vraiment que vous sachiez que ces sensations restent bénignes. Ce ne sont, en réalité, que des symptômes supplémentaires pouvant être ressentis par un grand anxieux. </p>\n<p>Cependant, comme leurs effets sur vous s’avèrent impressionnants, il y a de fortes chances que vous angoissiez encore plus qu’habituellement. D’où un cercle vicieux se mettant en place et alimentant, de ce fait, votre anxiété. </p>\n<h3>Une qualité de vie diminuée </h3>\n<p>Il est très important de comprendre de quoi vous souffrez exactement afin de vous rassurer. Vous éviterez ainsi de tomber dans ce cercle vicieux. Car pour les personnes ne comprenant pas ce qui se produit en eux, vivre normalement peut s’avérer impossible. Leur vie sociale, professionnelle et familiale peut se voir fortement impactée. Il existe donc un grand risque de handicap si vous n’êtes pas au courant de ce qui se passe en vous. Voilà pourquoi il est impératif, dans un premier temps, de comprendre ces symptômes. </p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img fetchpriority=\"high\" decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h3>La complémentarité éventuelle des deux troubles </h3>\n<p>Il faut savoir que vous pouvez ne souffrir que de dépersonnalisation. Ou que de déréalisation. Mais qu’également, les deux peuvent apparaître complémentaires. Tout dépend des personnes. Il n’y existe donc pas de modèle type ou de degré de gravité particulier si les deux surviennent régulièrement dans votre vie. </p>\n<h3>L’élément déclencheur et ces sensations </h3>\n<p>Il existe une explication à la venue de ces troubles. Tout dépend simplement de votre degré d’anxiété général. Plus elle est élevée, plus vous avez de chance de souffrir de dépersonnalisation et déréalisation. En réalité, quand votre niveau d’anxiété apparaît trop intense, votre cerveau n’arrive plus à en supporter les effets néfastes. Ce faisant et afin de vous protéger, car il pense, avant tout, à votre survie, il vous coupe de toutes vos sensations pour que l’angoisse diminue. Il ne s’agit ainsi que d’un mécanisme de protection de votre cerveau qui croit bien faire en tentant de vous soulager. Sauf qu’ensuite, vous ne vous sentez, effectivement, plus du tout comme avant. </p>\n<h2>Qui peut souffrir de dépersonnalisation et déréalisation ?</h2>\n<p>Les symptômes de dépersonnalisation et déréalisation peuvent donc survenir chez des individus présentant un degré trop élevé d’anxiété. Bien souvent, les personnes étant fréquemment dans la lune, partant « en astral », c’est-à-dire dans leur imagination et leurs pensées sont concernées. Elles ont effectivement habituellement un tempérament introverti, aimant se retrouver seules. Ces personnes peuvent être sujettes, au vu de leur habitude à trop réfléchir, aux <a href=\"/angoisse-stress-anxiete\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse stress anxiété \">troubles anxieux.</a></p>\n<p>Il y a également lieu d’analyser la durée des troubles de dépersonnalisation et déréalisation, ce qui pourrait donner un petit indice sur la gravité de votre anxiété. Par exemple, si vous vous retrouvez nez à nez avec un tigre, il y a de fortes chances que vous ressentiez ces sensations, puisque votre cerveau se met en mode survie. Cependant, après cet événement, ces symptômes disparaîtront. En fait, tous les êtres humains peuvent ressentir ces symptômes à un moment de leur vie. Rien qu’une très grande fatigue peut les enclencher. Mais ils passeront plus rapidement et avec plus de facilité.</p>\n<p>Malheureusement, ces troubles peuvent s’avérer chroniques si l’individu présente un niveau d’anxiété trop important de manière quotidienne. Dans ce cas-là, il est nécessaire de travailler sur le traumatisme ayant poussé la personne à devenir si anxieuse. Les troubles anxieux ne viennent pas sans raison. Les causes de traumatismes sont nombreuses : négligence ou maltraitance dans l’enfance, opération chirurgicale mal vécue, etc. même un événement bénin peut devenir traumatisant. Je vous laisse aller consulter mon <a href=\"/traumatisme\" target=\"_blank\" rel=\"noopener\" title=\"Traumatisme\">article</a> sur ce sujet.</p>\n<img decoding=\"async\" width=\"640\" height=\"415\" src=\"/storage/blog-images/Trouble-depersonnalisation.jpg\" alt=\"Sensation d’etrangete \" title=\"Trouble-dépersonnalisation\">\n<h2>Différence entre dépersonnalisation et déréalisation : les symptômes de la dépersonnalisation  </h2>\n<p>Dans une certaine mesure, certains symptômes peuvent se retrouver aussi bien dans la dépersonnalisation que dans la déréalisation. Certains, cependant, ne se retrouvent que dans un trouble. </p>\n<h3>La perte de plaisir </h3>\n<p>La personne souffrant de dépersonnalisation ne ressent plus correctement son corps. En effet, le cerveau se coupe, pour se protéger, de toute sensation. Par conséquent, ses 5 sens ne fonctionnent plus convenablement. Donc, forcément, l’individu éprouve beaucoup moins de sensations et de plaisir en général. Qu’il s’agisse de ses aliments préférés qu’il ingurgite, de ses passions, etc. </p>\n<h3>Sensations physiques désagréables</h3>\n<p>Une personne souffrant de dépersonnalisation ressent principalement des sensations physiques qu’elle ne trouve absolument pas normales. </p>\n<p>De manière générale, elle n’entretient plus le même rapport avec son corps. Quand elle se regarde dans une glace, elle a l’impression de ne plus se reconnaître et son corps lui apparaît tel un étranger. Elle peut d’ailleurs entretenir d’étranges ressentis avec certaines parties de son anatomie, comme apercevoir ses bras, mais avoir l’impression que ce ne sont pas les siens… Imaginez la frayeur qu’elle peut ressentir !</p>\n<p>Du fait de la grande anxiété qu’elle ressent à cet égard, elle peut donc développer d’autres symptômes. Elle peut ressentir, par exemple, une importante fatigue du fait que l’anxiété reste très énergivore. </p>\n<p>Sous l’effet également de cette anxiété et de cette fatigue, l’individu peut alors développer un sentiment d’irréalité. Cette perception lui donne la sensation que le monde est devenu étrange. Il peut même avoir l’impression de ne plus voir correctement, comme si un voile se dessinait devant ses yeux. Il présente, en réalité, à peu près les mêmes symptômes qu’une sorte de début de malaise, comme des vertiges et la sensation d’avoir un peu trop bu.</p>\n<h3>Sensations émotionnelles désagréables </h3>\n<p>La dépersonnalisation peut également influer sur vos émotions et même, sur votre mémoire. En effet, un trop-plein d’anxiété peut engendrer de grands troubles de la concentration. Ce qui fait qu’une personne n’arrive, quelquefois, pas à se souvenir d’un événement en particulier.</p>\n<h3>Ne plus se sentir acteur de sa vie </h3>\n<p>La personne souffrant de dépersonnalisation a également l’impression de ne plus contrôler son existence. Elle a en effet la sensation de se trouver à côté de son corps et donc, s’entend parler ou se voit pratiquer une activité, mais comme s’il ne s’agissait pas d’elle. On pourrait même dire qu’elle n’a plus vraiment le sentiment d’être en vie. De là peut être ressenti un étourdissement général, au niveau de son corps ou de ses émotions et sentiments.</p>\n<p>Nous entendons souvent dire qu’il faut être observateur de ses pensées afin d’éviter de trop s’identifier à elles pour prévenir toute rumination. Cependant, dans la dépersonnalisation, l’individu ne s’empêche pas de penser. Il se sent surtout spectateur de son enveloppe corporelle, ce qui peut, justement, augmenter sa panique et ses ruminations. En fait, il regarde juste sa vie et donc, n’agit plus dessus. Il observe également le monde de manière détachée, lequel lui paraît terne. Il peut s’intéresser au monde, mais a la désagréable impression de ne plus y appartenir.</p>\n<h2>Les symptômes de la déréalisation  </h2>\n<p>Voici les symptômes physiques et émotionnels que vous pouvez rencontrer dans le trouble de déréalisation.</p>\n<h3>Symptômes physiques </h3>\n<p>Un individu souffrant de déréalisation considère que tout ce qui se passe à l’extérieur de lui est irréel. Le monde lui semble être un rêve éveillé, ce qui lui donne une sensation générale d’étrangeté. Ses sens sont comme déformés et donc, la personne peut entendre les sons de manière diminuée ou augmentée. Même ses proches peuvent lui sembler être des inconnus. Les objets peuvent lui apparaître également plus grands ou plus petits que ce qu’ils sont réellement. Elle peut en outre trouver que le temps passe trop lentement ou au contraire, trop rapidement. Ces symptômes peuvent vraiment paraître insoutenables pour un individu. </p>\n<h3>Symptômes émotionnels  </h3>\n<p>Avec ces différentes sensations, la personne peut vraiment croire qu’elle devient folle. Car l’angoisse peut provoquer une perte de concentration et donc, une impression de ne plus réussir à réfléchir. L’individu peut également trouver étrangers des lieux qu’il a pourtant l’habitude de fréquenter. Il peut de surcroît penser ne plus éprouver de sentiment pour ses proches, vu qu’il a l’impression de ne plus les reconnaître. Tous ces symptômes peuvent ainsi mener à une trop anxiété, laquelle pouvant déboucher, à la longue, sur une dépression.</p>\n<h3>Ne plus se sentir acteur de sa vie </h3>\n<p>La déréalisation paralyse l’individu de manière plus cérébrale. Les ruminations rentrent beaucoup en jeu et s’avèrent inutiles. Car elles portent principalement sur des questions existentielles auxquelles il est impossible, à l’heure actuelle, de répondre. Comme, par exemple, savoir ce qu’il y a après la mort, se demander quel est le but ultime de la vie, etc. </p>\n<img loading=\"lazy\" decoding=\"async\" width=\"500\" height=\"667\" src=\"/storage/blog-images/Trouble-derealisation.jpg\" alt=\"Impression d’etre dans un reve \" title=\"Trouble-déréalisation\">\n<h2>Comment se libérer de la dépersonnalisation et de la déréalisation ? </h2>\n<p>Voyons maintenant ensemble les solutions pouvant être apportées à ces troubles handicapants et impressionnants. Car bien souvent, les personnes atteintes de dépersonnalisation et déréalisation pensent ne plus pouvoir retrouver leurs sensations d’antan. Ce qui est bien évidemment faux. Vous pouvez clairement vous en sortir et redevenir comme avant ! </p>\n<h3>Envisager une thérapie avec médicaments si besoin </h3>\n<p>Si vos symptômes vous semblent vraiment insupportables, n’hésitez pas à vous tourner vers un professionnel de la santé. Il est en effet bon de vous faire aider afin de réduire le trop-plein d’anxiété qui provoque ces symptômes. Un thérapeute peut vous donner des outils pour y arriver. </p>\n<p>Vous pouvez également coupler votre thérapie avec des médicaments si vous en ressentez le besoin. Toutefois, attention aux anxiolytiques. Ils peuvent en effet augmenter les sensations de dépersonnalisation et déréalisation.</p>\n<h3>Pratiquer l’acceptation</h3>\n<p>Je vous invite à aller consulter mon <a href=\"/lacher-prise-et-acceptation\" target=\"_blank\" rel=\"noopener\" title=\"Lâcher-prise et acceptation\">article</a> à ce sujet afin de vraiment comprendre la notion de lâcher-prise et d’acceptation. Cet article peut vous aider à ne pas augmenter le niveau de votre anxiété voire même, à le diminuer. </p>\n<p>Essayez cette méthode. Lorsque vos symptômes arrivent, ou même s’ils sont déjà installés, ne paniquez pas. Dites-vous plutôt cette phrase : « ça y est, ma dépersonnalisation/déréalisation arrive. C’est bon, je sais ce que c’est, j’ai l’habitude. Ce n’est qu’un trop-plein d’angoisse qui me provoque cette sensation. Donc, c’est ok. C’est vrai que c’est très désagréable, mais ces symptômes passeront ». </p>\n<p>Vous verrez qu’en acceptant vos symptômes de dépersonnalisation et déréalisation, ils se réduiront considérablement. Cette amélioration de votre état peut prendre plus ou moins de temps selon votre degré d’anxiété. Mais en faisant baisser progressivement votre angoisse, il est obligatoire que vos troubles s’amenuisent. </p>\n<h3>Dédramatiser la situation  </h3>\n<p>Plus vous paniquez à la venue de ces symptômes, plus votre anxiété va s’amplifier. Et vous savez bien que l’anxiété reste la cause de bon nombre de vos manifestations physiques et émotionnelles. C’est là que vous courrez le risque d’éprouver un trop-plein d’angoisse poussant votre cerveau à se protéger, vous couper de vos sensations et donc, augmenter vos troubles. Rappelez-vous que si ces sensations apparaissent extrêmement désagréables, elles ne sont cependant pas dangereuses. Vous ne deviendrez pas fou et ne mourrez pas. </p>\n<h3>Focaliser son attention</h3>\n<p>Pour éviter de dramatiser et de faire entrer en vous des ruminations incessantes, tâchez de focaliser votre attention quelque part. Si vous vous trouvez, par exemple, au restaurant en train de déjeuner avec des collègues et que cette sensation arrive, essayez de vous concentrer sur l’autre. Écoutez bien ce qu’il vous dit attentivement afin de lui répondre. Vous pouvez également observer les vêtements des personnes, leurs manies, etc. ou même focaliser votre regard sur le décor de la pièce. En fait, décentrez-vous de vous !</p>\n<p>Il en est de même quand vous pratiquez une activité. Prenons l’exemple du ménage. Effectuer une activité automatique et habituelle peut faire apparaître des ruminations. Focalisez plutôt votre attention sur les gestes que vous effectuez : passer une éponge sur une assiette, laver une vitre avec le produit lave-vitre, etc. Sentez les odeurs, voyez ce que vous accomplissez en éliminant la saleté. Et si vous pratiquez une activité qui vous passionne, soyez complètement dans ce que vous accomplissez. Vous y arriverez d’ailleurs facilement, puisque cette activité vous captive. Cet état s’appelle se trouver dans le flow. Et là, il y a peu de chances que vos symptômes pointent le bout de leur nez.</p>\n<h3>Se libérer des questions existentielles </h3>\n<p>Ces pensées étant des pensées qu’absolument tout le monde peut avoir, il est certain que vous ne pouvez les éviter. Par contre, vous avez la possibilité de les accepter puis de les laisser passer. Car le fait de trop cogiter sur des questions insolubles peut vraiment vous faire ressentir des sensations d’étrangeté et donc, faire apparaître les symptômes que vous redoutez tant. Par conséquent, la prochaine fois qu’une question existentielle se présente à vous, vous pouvez :</p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">Focaliser votre attention ailleurs ;  </li>\n<li aria-level=\"1\">Visualiser un énorme panneau-STOP, lequel vous aidera à passer à autre chose et à éviter les ruminations pouvant entraîner les troubles de dépersonnalisation et déréalisation.</li>\n</ul>\n<h3>Pratiquer des techniques de relaxation</h3>\n<p>Pour faire baisser votre angoisse, laquelle reste la cause de ces troubles, vous pouvez vous aider de bon nombre de techniques de relaxation. </p>\n<p>Vous pouvez déjà agir au niveau de votre respiration. En effet, une respiration lente et régulière régulera grandement votre organisme et par la même occasion, votre anxiété. N’hésitez pas à aller consulter mon <a href=\"/respiration\" target=\"_blank\" rel=\"noopener\" title=\"Respiration\">article</a> consacré à ce sujet afin d’obtenir toutes les informations utiles à cet égard. Vous y trouverez en outre des méthodes de respiration rapides et simples à pratiquer où que vous soyez.  </p>\n<p>Pour ma part, j’utilise principalement comme type de respiration la cohérence cardiaque et me sers d’un petit appareil, nommé ZENSPIRE, pour la pratiquer. En effet, celui-ci, grâce à une lumière ainsi qu’à une vibration, aide la personne à respirer correctement (ce qui n’est pas chose aisée au départ), c’est-à-dire de manière ample et profonde.</p>\n<p>Donc, si cela vous intéresse, je vous invite à cliquer sur le bouton ci-dessous, étant précisé que si vous passez commande, vous bénéficierez d’une réduction de 10 % en utilisant le code JL0620 :</p>\n<p>Ensuite, à vous de vous renseigner sur les différentes pratiques de relaxation pouvant vous correspondre. Vous pouvez opter pour le yoga, la sophrologie, l’acupuncture… la méditation reste également un puissant outil pour vous relaxer. Cependant, attention si vous êtes trop anxieux. Car cette technique peut, en effet, aggraver votre cas. </p>\n<p>En fait, si vous avez tendance à être trop dans le contrôle, le fait de totalement lâcher-prise, peut vraiment vous terrifier. En effet, comme votre intérieur est probablement dans la tourmente, trop regarder à l’intérieur de vous peut vous faire paniquer et vous provoquer une attaque de panique. Il y aurait déjà plutôt lieu de renouer avec votre corps et pratiquer des techniques de relaxation un peu plus conscientes. Le but est d’arriver à faire baisser votre anxiété avant de mettre en application une technique telle que la méditation.</p>\n<p> </p>\n<p>J’espère que cet article a pu vous faire comprendre la<b> différence entre dépersonnalisation et déréalisation.</b> Je sais, par expérience, que ces symptômes sont extrêmement désagréables. Mais ne baissez pas les bras, car vous pouvez les faire disparaître !</p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'Différence entre Dépersonnalisation et Déréalisation et Moyens d’en Guérir','La dépersonnalisation/déréalisation est un symptôme de l’anxiété. Quelle est la différence entre dépersonnalisation et déréalisation et comment en guérir ?','https://vivre-pleinement.fr/depersonnalisation-et-derealisation/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/depersonnalisation-et-derealisation\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/depersonnalisation-et-derealisation\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Diff\\u00e9rence entre D\\u00e9personnalisation et D\\u00e9r\\u00e9alisation et Moyens d\\u2019en Gu\\u00e9rir\",\"datePublished\":\"2020-02-16T16:10:13+00:00\",\"dateModified\":\"2024-02-13T17:16:35+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/depersonnalisation-et-derealisation\\/\"},\"wordCount\":5463,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/depersonnalisation-et-derealisation\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/02\\/Difference-depersonnalisation-derealisation.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/depersonnalisation-et-derealisation\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/depersonnalisation-et-derealisation\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/depersonnalisation-et-derealisation\\/\",\"name\":\"Diff\\u00e9rence entre D\\u00e9personnalisation et D\\u00e9r\\u00e9alisation et Moyens d\\u2019en Gu\\u00e9rir\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/depersonnalisation-et-derealisation\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/depersonnalisation-et-derealisation\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/02\\/Difference-depersonnalisation-derealisation.jpg\",\"datePublished\":\"2020-02-16T16:10:13+00:00\",\"dateModified\":\"2024-02-13T17:16:35+00:00\",\"description\":\"La d\\u00e9personnalisation\\/d\\u00e9r\\u00e9alisation est un sympt\\u00f4me de l\\u2019anxi\\u00e9t\\u00e9. Quelle est la diff\\u00e9rence entre d\\u00e9personnalisation et d\\u00e9r\\u00e9alisation et comment en gu\\u00e9rir ?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/depersonnalisation-et-derealisation\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/depersonnalisation-et-derealisation\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/depersonnalisation-et-derealisation\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/02\\/Difference-depersonnalisation-derealisation.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2020\\/02\\/Difference-depersonnalisation-derealisation.jpg\",\"width\":550,\"height\":364,\"caption\":\"Quelle est la difference entre depersonnalisation et derealisation ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/depersonnalisation-et-derealisation\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Diff\\u00e9rence entre D\\u00e9personnalisation et D\\u00e9r\\u00e9alisation et Moyens d\\u2019en Gu\\u00e9rir\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2020-02-16 16:10:13',NULL,'2026-05-24 19:19:45','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (39,'Les Différents Troubles de la Personnalité : les Comprendre et les Soulager','troubles-de-la-personnalite','Chaque être humain possède un caractère, nommé aussi personnalité. Elle se forge principalement avec les évènements de la vie, l’éducation et la génétique. Chaque personne a donc ses propres façons de réagir à une même situation. Il s’agit de mécanisme de défense. C’est pourquoi chaque individu reste unique, avec ses forces et faiblesses, ses qualités et ses défauts. Cependant, quelquefois, le tempérament d’un individu peut grandement le faire souffrir, lui et son entourage. C’est ce que l’on nomme communément un trouble de la personnalité. Vos proches vous disent souvent que vous avez un caractère difficile. Vous n’aimez pas la compagnie des autres et préférez rester dans votre bulle. Vous vous sentez un coup plein de vitalité et heureux, un coup dépressif. Vous suspectez souffrir d’un trouble de la personnalité ? Quels sont les différents troubles de la personnalité et comment les soulager ? \n','<p>Chaque être humain possède un <b>caractère</b>, nommé aussi <b>personnalité</b>. Elle se forge principalement avec les <b>évènements </b>de la vie, <b>l’éducation</b> et la <b>génétique</b>. Chaque personne a donc ses propres façons de <b>réagir </b>à une même <b>situation</b>. Il s’agit de <b>mécanisme de défense.</b> C’est pourquoi chaque individu reste <b>unique</b>, avec ses <b>forces </b>et <b>faiblesses</b>, ses <b>qualités </b>et ses <b>défauts</b>. Cependant, quelquefois, le tempérament d’un individu peut grandement le faire <b>souffrir</b>, lui et son <b>entourage</b>. C’est ce que l’on nomme communément un trouble de la personnalité. Vos proches vous disent souvent que vous avez un caractère <b>difficile</b>. Vous n’aimez pas la compagnie des autres et préférez rester dans votre <b>bulle</b>. Vous vous sentez un coup plein de vitalité et <b>heureux</b>, un coup <b>dépressif</b>. Vous <b>suspectez </b>souffrir d’un trouble de la personnalité ? Quels sont<b> les différents troubles de la personnalité </b>et comment les soulager ? </p>\n<h2>Qu’est-ce qu’un trouble de la personnalité ? </h2>\n<h3>Définition générale</h3>\n<p>La personnalité se développe par rapport à divers facteurs et se stabilise à l’adolescence. Cependant, quelquefois, certains traits négatifs de ladite personnalité peuvent s’aggraver, se rigidifier et se figer. Dans ces conditions, l’individu a de plus en plus de mal à s’adapter à la société. Il apparaît bien souvent différent de la <a href=\"/normes-sociales\" target=\"_blank\" rel=\"noopener\" title=\"Normes sociales \">norme sociale</a>, volontairement ou non. La personne peut ainsi rencontrer de grandes difficultés émotionnelles et relationnelles. Certains aspects de sa personnalité restent également immatures. Tous ces éléments peuvent donc provoquer une grande souffrance mentale chez elle. Souffrance pouvant développer, par exemple, des troubles anxieux chroniques.</p>\n<h3>La souffrance des proches </h3>\n<p>Bien souvent, la détresse n’impacte pas que l’individu. Les proches souffrent également beaucoup. Car ils se sentent impuissants à l’aider ont, quelquefois, bien du mal à le comprendre. Ils peuvent d’ailleurs éprouver de la colère à l’égard de la personne. Et aussi être interloqués par la contradiction donc elle peut faire preuve dans certains troubles de la personnalité. </p>\n<h3>Le degré de handicap et la comorbidité avec d’autres troubles de la personnalité</h3>\n<p>Un trouble de la personnalité n’est pas forcément une maladie mentale. La personne peut réussir à vivre avec sans que son caractère soit trop préjudiciable, à elle comme à son entourage. Le problème survient quand le trouble handicape trop sa vie et/ou celle d’autrui. De plus, un individu peut également souffrir de plusieurs troubles de la personnalité. Certains sont en effet fréquemment liés de par leur ressemblance. Une personne antisociale, par exemple, apparaîtra bien souvent aussi borderline. </p>\n<h3>Le degré d’insight</h3>\n<p>Certains troubles de la personnalité peuvent être plus handicapants que d’autres. C’est souvent le cas pour les troubles de la personnalité à faible insight (prise de conscience). En effet, comment voulez-vous travailler sur un trouble si vous n’en avez même pas conscience ?</p>\n<h2>D’où proviennent les différents troubles de la personnalité ? </h2>\n<p>Un trouble de la personnalité restant une aggravation de la personnalité, il provient plus ou moins des mêmes facteurs, tels que la génétique et l’éducation. Des cas de maltraitance et d’abus dans l’enfance, par exemple, peuvent rendre le futur adulte froid, sans sentiment. Présentant en effet une carence affective provenant de son enfance, cette personne est donc susceptible de développer une personnalité limite ou antisociale. </p>\n<p>Bien souvent également, l’éducation joue grandement sur l’estime qu’une personne peut avoir vis-à-vis d’elle-même. Une trop faible <a href=\"/confiance-et-estime-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Confiance et estime de soi\">estime de soi</a> peut avoir de lourdes conséquences mentales telles que, par exemple, faire développer une personnalité évitante, ou dépendante. Un amour de soi trop fort, à contrario, peut engendrer une personnalité narcissique. Une trop grande estime de soi apparaît tout aussi néfaste qu’une estime de soi fragile, toutes deux pouvant déclencher des troubles de la personnalité. Le tout est ainsi de s’estimer pleinement, c’est-à-dire ni trop ni trop peu.</p>\n<p>Enfin, un ou plusieurs traumatismes subis par un individu peuvent clairement jouer sur son bien-être, son développement personnel et donc, sur son tempérament. Bon nombre de troubles de la personnalité proviennent d’ailleurs de traumatismes non traités. Je vous laisse consulter mon <a href=\"/traumatisme\" target=\"_blank\" rel=\"noopener\" title=\"Traumatisme\">article sur le traumatisme</a> pour plus d’informations. </p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"428\" src=\"/storage/blog-images/Groupe-B-personnalites-impulsives.jpg\" alt=\"Groupe C personnalites effacees\" title=\"Groupe-B-personnalités-impulsives\">\n<h2>Troubles de la personnalité : groupes A, B et C  </h2>\n<h3>Groupe A : les personnalités distantes </h3>\n<h4>La personnalité paranoïaque </h4>\n<p>Comme son nom l’indique, la personne à tempérament paranoïaque apparaît extrêmement méfiante à l’égard des autres. Elle met fréquemment leur parole en doute et leur porte souvent de mauvaises intentions. Son comportement apparaît généralement irrationnel. </p>\n<p>Elle utilise souvent comme mécanisme de défense la projection. Il s’agit, dans ce mécanisme, de projeter sur autrui ses propres sentiments. Par exemple, elle pense qu’un individu est de mauvaise humeur, alors que c’est elle qui est de mauvaise humeur. Le fait d’ailleurs de subir des critiques est insupportable pour l’individu, étant donné qu’il demeure extrêmement susceptible. Il peut ainsi développer une forte rancune envers les personnes lui ayant fait du mal et peut, de ce fait, se montrer très agressif.</p>\n<p>D’ailleurs, si vous souhaitez justement que le regard des autres ne soit plus un drame pour vous, je vous invite à cliquer sur le bouton ci-dessous, afin de découvrir le programme de Didier PENISSARD à cet égard, coach, auteur et conférencier en développement personnel :</p>\n<p>Paradoxalement, cette personne possède un orgueil assez conséquent. Par conséquent, elle apparaît assez égocentrique et se croit habituellement supérieure à la masse, ce qui peut la rendre autoritaire. Ce sentiment de supériorité la pousse d’ailleurs à s’isoler, estimant les autres moins bons qu’elle. Elle se sent donc incomprise. Ce ressenti peut ainsi l’amener à l’isolement social. </p>\n<p>De plus, cette personnalité est bien souvent psychorigide et déteste subir des échecs. </p>\n<p>Si ce trouble n’est pas traité, la personne risque de développer divers troubles mentaux, tels que l’hypocondrie ou la dépression. Dans le pire des cas, la vraie maladie psychiatrique de la paranoïa peut s’installer.</p>\n<h4>La personnalité paranoïaque/sensitive </h4>\n<p>Il existe une autre forme de trouble de la personnalité paranoïaque, se nommant la personnalité sensitive. Cette personne possède également un orgueil développé, mais fait aussi preuve, paradoxalement, d’un grand manque d’estime pour elle-même. Elle souffre d’ailleurs beaucoup de son état, voyant bien souvent le verre à moitié vide. Et qui dit sensitivité dit émotivité, la personne sensitive peut ainsi, du fait du trop-plein d’énergie dépensé, se sentir asthénique (fatigue régulière et anormale). Sa sensibilité peut alors la faire se sentir différente des autres et donc, l’encourager au repli sur elle-même. </p>\n<h4>La personnalité schizoïde </h4>\n<p>La personnalité schizoïde ne se sent souvent bien qu’avec elle-même. Elle adore justement vivre dans son imaginaire, lequel demeure très riche. Elle se réfugie donc dans son monde intérieur. </p>\n<p>De ce fait, cette personne n’éprouve aucun intérêt pour les relations sociales, ne se sentant bien qu’avec elle-même. Elle se fiche d’appartenir ou non aux normes sociales. Les autres la voient d’ailleurs comme une personne froide, puisqu’elle n’exprime pas ses émotions. Elle ressent en outre peu de choses en elle. Elle manque de plaisir dans tous les domaines de sa vie.  </p>\n<p>Ce trouble de personnalité, s’il n’est pas traité, peut mener l’individu à la dépression ou peut être la voie d’évolution vers la schizophrénie. </p>\n<h4>La personnalité schizotypique </h4>\n<p>La personnalité schizotypique ne passe, en général, pas inaperçue. Car la personne peut présenter des comportements étranges qu’autrui peut remarquer. Elle peut en outre s’exprimer étrangement, avec des phrases pleines de métaphores. Elle peut d’ailleurs être persuadée de posséder un don particulier et en informer ardemment autrui. Cet individu peut aussi avoir une manière très particulière de s’habiller, un style bien original.</p>\n<p>Intérieurement, l’individu peut être en proie à des croyances et pensées bizarres. Il est d’ailleurs sujet aux pensées magiques et aux ruminations obsessionnelles. De par ses idées particulières, il fuit donc bien souvent les autres, le menant, par conséquent, à l’anxiété sociale. Cette personne n’a pas beaucoup d’amis, se méfiant de bon nombre de gens. Une pointe de paranoïa se trouve ainsi présente. De ce fait, elle a tendance à s’isoler.</p>\n<p>Au niveau corporel et sensoriel, la personnalité schizotypique peut fréquemment ressentir des sensations corporelles inhabituelles et donc, être victime de troubles de dépersonnalisation et de déréalisation. </p>\n<p>À la longue, si ce trouble de la personnalité n’est pas traité, la personne concernée peut sombrer dans la dépression, voire même dans certaines addictions, telles la toxicomanie. </p>\n<h3>Groupe B : Les personnalités impulsives</h3>\n<h4>La personnalité antisociale, psychopathe ou sociopathe  </h4>\n<p>Cette personne ne pense généralement pas aux autres et n’hésite pas à les écraser pour satisfaire ses besoins. Elle ne manque pas à user de manipulation à leur égard. Elle ressent aussi une grande colère en elle et ne tolère aucunement la frustration. Par conséquent, elle apparaît fréquemment indifférente aux Lois et ne les respecte, de ce fait, pas. Et même en se faisant avoir, elle ne tire jamais de leçons de ses erreurs et continue donc à en faire.</p>\n<p>Bien souvent, ce type de personnalité est adepte de substances illicites et, de par sa vie mouvementée, peut faire l’objet d’incarcérations et envisager le suicide.</p>\n<h4>La personnalité psychopathique </h4>\n<p>La personnalité psychopathique a bien souvent subi, dans son enfance, une carence affective. Résultat, à l’adolescence, elle plonge fréquemment dans la délinquance et semble sujette aux fugues. Plus tard, cette personnalité manquera cruellement d’empathie à l’égard de ses pairs et pourra donc faire preuve de beaucoup d’agressivité et de violence vis-à-vis d’eux. Car, étant donné qu’elle n’a jamais reçu d’amour, elle n’a aucun amour à offrir. Elle ne ressent de ce fait pas d’affection pour les autres et de fait, ne ressent jamais aucun remords en leur faisant du mal.</p>\n<p>Cet individu n’éprouve aucune culpabilité et aucune anxiété non plus. Sa vie apparaît bien souvent instable, puisqu’il fait preuve d’irresponsabilité. Ses relations restent également très superficielles, servant seulement à assouvir ses intérêts. Il apparaît aussi très orgueilleux et éprouve par conséquent de grandes difficultés à s’adapter aux normes sociales. </p>\n<p>Fréquemment, cette personne devient adepte de l’escroquerie et peut en outre sombrer dans l’alcool et la toxicomanie. Dans le pire des cas, cet individu peut même devenir marginal au point de nuire gravement à autrui, tel qu’en devenant, par exemple, violeur. </p>\n<p>Couramment, cette personnalité, de par sa vie mouvementée, peut tomber dans la dépression et rencontre, quelquefois, une mort précoce. </p>\n<h4>La personnalité sadique </h4>\n<p>Cette personnalité trouve généralement son bonheur et son excitation par le fait d’humilier les autres et de les terroriser. En leur mettant la pression intentionnellement, par exemple, lui donnant une sensation de contrôle à leur égard.</p>\n<p>Dans le pire des cas, cet individu peut devenir très agressif et commettre des actes cruels, juste pour son plaisir, allant même jusqu’à séquestrer autrui.</p>\n<h4>La personnalité borderline </h4>\n<p>Également appelée personnalité limite, qui est la structure entre la névrose et la psychose, le borderline est habituellement sujet à une importante blessure d’abandon. </p>\n<p>Il éprouve souvent de grandes difficultés dans sa vie. Ses relations demeurent fréquemment superficielles et instables, même s’il fait preuve, généralement, d’une grande sociabilité. Il peut en outre ressentir un fort mal-être s’exprimant par une angoisse générale, de l’agressivité, de l’hystérie, des TOCS, des phobies et une dépression. Ce mal-être peut aller, dans les cas extrêmes, jusqu’au suicide. Il est de plus un adepte des substances illicites au point de devenir toxicomane. L’alcoolisme peut également l’atteindre. Son état d’esprit négatif le pousse, quelquefois, à s’automutiler. </p>\n<h4>La personnalité histrionique</h4>\n<p>Ou personnalité hystérique. Cette personne éprouve un énorme besoin d’attention. Elle a, en réalité, une grande dépendance affective. Elle réalise alors tout ce qui se trouve en son pouvoir pour obtenir ce qu’elle veut, et peut donc apparaître très manipulatrice. Pour assouvir son besoin de considération, elle n’hésite pas à user de la séduction. Ses relations peuvent ainsi demeurer superficielles. Égocentrique, elle s’exprime souvent de manière théâtrale. </p>\n<p>Cet individu présente en fait des troubles émotionnels le rendant hyperémotif et colérique. Il ne tolère d’ailleurs pas la frustration. Il peut, de ce fait, être sujet aux troubles anxieux et aux somatisations. Quelquefois, si ces troubles émotionnels ne sont pas traités, il peut sombrer dans la dépression.</p>\n<p>Dans certains cas, cette personne présente également une personnalité psychopathique. Quand elle souhaite donc trop attirer l’attention, elle peut faire des crises d’agitation spectaculaires devant autrui. Elle sombre bien souvent dans diverses addictions. Il s’agit généralement d’une personnalité instable.</p>\n<h4>La personnalité narcissique </h4>\n<p>En général, cette personnalité se reconnaît aisément de l’extérieur. Elle apparaît en effet mégalomane, est certaine de sa beauté et éprouve un grand besoin d’être admirée. Très souvent, cette personne apparaît insupportable aux yeux d’autrui, vu sa tendance à se sentir extraordinaire pour la moindre action qu’elle entreprend. Sa propension à se montrer hautaine envers certains et à courir après les personnes qu’elle trouve « prestigieuses » ne manque pas de la rendre détestable. Elle mettra cependant de côté cette tendance si elle souhaite manipuler autrui. Elle manque en effet cruellement d’empathie et n’hésite pas à utiliser les autres pour arriver à ses fins. Cet individu est donc, bien évidemment, égoïste. Il ne se remet d’ailleurs jamais en question et explique le fait que les gens le détestent par de la jalousie mal placée de leur part.</p>\n<p>Je pense que vous avez déjà dû entendre parler des pervers narcissiques ? Eh bien, on peut dire qu’ils font partie de cette catégorie. On peut fréquemment rencontrer ce genre de personnes chez certains patrons, lesquels sont adeptes du harcèlement moral. Ces chefs n’hésitent pas à mettre une pression intense à leurs employés et à les humilier.</p>\n<p>Évidemment, ce type de personnalité cache une grande fragilité psychologique. Bien souvent, si tout ne fonctionne pas comme elle le souhaite, elle peut sombrer dans la drogue, la dépression. Elle peut aussi tomber dans l’anorexie, si obtenir un corps parfait devient une fixation pour elle. </p>\n<img decoding=\"async\" width=\"640\" height=\"426\" src=\"/storage/blog-images/Groupe-A-personnalites-distantes.jpg\" alt=\"Passif-agressif masochiste \" title=\"Groupe-A-personnalités-distantes\">\n<h3>Groupe C : Les personnalités effacées  </h3>\n<h4>La personnalité évitante </h4>\n<p>Cette personne est en proie à une grande blessure de rejet. De ce fait, elle n’a aucune estime pour elle et se sent clairement inférieure à ses pairs. Elle a ainsi énormément de difficultés à se sentir bien en société. Voulant à tout prix éviter de se trouver au centre de l’attention, elle se met bien souvent en retrait dans les situations sociales. Le risque est donc de fuir lesdites interactions sociales et de s’isoler de plus en plus, ce qui peut amener à l’agoraphobie. </p>\n<p>Cette personnalité ressent un profond mal-être intérieur, de par son manque d’estime pour elle. Elle est fréquemment également hypersensible et a extrêmement de mal à s’adapter à la nouveauté et à tout changement. De plus, tout obstacle négatif, même minime, reste très difficile à vivre pour elle. Vivre peut, en réalité, s’avérer être une épreuve de tous les jours. </p>\n<h4>La personnalité psychasthénique</h4>\n<p>Nous pouvons aussi l’appeler la personnalité dépressive. Ses pensées demeurent bien souvent pessimistes, ce qui peut l’amener à développer divers troubles, tels que les troubles anxieux, dont les TOC et l’hypocondrie. Mais également d’autres maux tels que la dépression ou le développement d’addictions comme l’alcool ou le tabac. Ses dépendances servent à soulager la culpabilité qu’elle peut ressentir à être ainsi, sans pour autant réussir à se ressaisir. </p>\n<p>Par conséquent, elle ne ressent pas beaucoup de plaisir en général et même dans le domaine sexuel. Son énergie étant concentrée sur ses états négatifs, elle se sent donc bien souvent sans vitalité, fatiguée. Elle n’a pas beaucoup de volonté pour changer son attitude. Elle se réfugie fréquemment dans son univers intérieur et imaginaire, ayant pour conséquence de lui faire manquer d’attention pour le monde réel. Cet individu a ainsi tendance à s’isoler. Quelquefois cependant, le contraire se produit. Cette personne peut en effet être très perfectionniste et donc, très agitée, et ce, afin que tout soit toujours parfait. De l’extérieur, elle peut sembler amaigrie. </p>\n<h4>La personnalité dépendante </h4>\n<p>Cet individu a développé une grande blessure d’abandon. Du coup, il fait tout pour ne pas être abandonné par autrui. Pour ce faire, il n’ose jamais exprimer ses besoins et opinions, de peur de ne pas être apprécié par les autres. Il fait généralement preuve de soumission, tout en prenant bien soin de ne jamais contrarier ses semblables. Le principal restant en effet, pour lui, de ne jamais être seul.<b> </b></p>\n<p>De plus, ayant une très faible estime d’elle-même, cette personne se sent incapable de gérer sa vie seule. Elle aime donc que les autres prennent les décisions à sa place, car elle ne pourrait supporter de prendre une mauvaise décision. Elle préfère également que l’on s’occupe d’elle, vu qu’elle pense que le gens gèrent forcément mieux ce qu’ils entreprennent qu’elle. Cette personnalité ressent le besoin d’être rassurée très souvent, ne croyant pas en elle-même. </p>\n<h4>La personnalité obsessionnelle-compulsive</h4>\n<p>Cette personnalité ne doit pas être confondue avec les TOC. Les deux peuvent en effet être liés, mais ce n’est pas toujours le cas. Cette personnalité, également nommée POC, aime suivre scrupuleusement les règles et les ordres de ses supérieurs, si elle en a. Il s’agit, en fait, de perfectionnisme. </p>\n<p>Cette personne a bien souvent du mal à se laisser aller. Elle ne prend pas vraiment plaisir à ce qu’elle fait. Car tout n’est que devoir pour elle. Donc, même si elle semble pratiquer un loisir, tel un sport, par exemple, elle ne voit pas cette activité comme un divertissement. Mais plutôt comme une tâche de plus à accomplir pour s’entretenir. Elle planifie d’ailleurs tout, la notion de lâcher-prise lui étant inconnue. Elle peut quelquefois s’intéresser au collectionnisme. Cet individu apparaît également très formel et n’apprécie pas les gens exprimant leurs émotions. </p>\n<p> Au travail<b>,</b> il est bien souvent difficile à vivre. Apparaissant autoritaire et sérieux, il se méfie grandement de ses pairs et surtout, de leurs capacités. Très rigide, il pense être le seul à effectuer correctement les tâches et refuse donc de déléguer. Et s’il le fait, il faut impérativement que le job soit réalisé à sa manière. De plus, étant un intellectuel, il a beaucoup de mal à pratiquer d’autres activités que son travail. </p>\n<h3>Groupe indéterminé </h3>\n<h4>La personnalité masochiste </h4>\n<p>Cette personne est une professionnelle de la culpabilité. Elle se sent responsable de tout ce qu’il se passe. Bien qu’il soit bon, en effet, de prendre ses responsabilités sans se victimiser, trop le faire n’est par contre pas recommandé. Au risque d’entrer dans une posture de victime. Son caractère est bien évidemment pessimiste. </p>\n<p>Cet individu se sacrifie souvent pour autrui dans le but d’assouvir son besoin de se sentir utile. Les autres peuvent même le voir comme une personne très humble. Cependant, ils sont loin de se douter que cette humilité n’est pas sincère. </p>\n<p>Enfin, cette personnalité, ne pensant pas mériter le bonheur, ne peut tolérer que des succès lui arrivent. Quand c’est le cas, elle fait tout pour saboter son bonheur et retomber dans ses démons. D’où le terme de masochiste. </p>\n<h4>La personnalité passive-agressive</h4>\n<p>Cette personnalité est en proie à un paradoxe. D’un côté, elle semble passive, dans le sens où elle n’aime pas le conflit et ne veut pas d’histoire. Et d’un autre côté, elle refuse de se soumettre à quiconque quand une situation la dérange. Résultat, elle passe légèrement à l’action, afin que les autres comprennent qu’ils la dérangent. Cependant, ils pourront être particulièrement agacés par cette façon de procéder, dans la mesure où la personne ne s’exprime pas explicitement. </p>\n<p>Il s’agit ainsi d’une agressivité s’exprimant, mais pas trop. D’où le paradoxe. C’est le cas, par exemple, d’un employé en voulant secrètement à son patron. Au lieu de lui dire clairement ce qui ne va pas, il préfère se mettre en arrêt-maladie régulièrement et surtout, lors des moments où il ne faudrait pas. Et si, par hasard, le chef lui demande directement des comptes, ce salarié est capable de faire semblant de ne pas comprendre. Il est donc très difficile d’appréhender un individu de ce genre. </p>\n<p>En réalité, cette personnalité à une propension à la lâcheté, en n’exprimant pas clairement ce qu’elle ressent. Mais elle a également une inclination au courage, en montrant son mécontentement. Sauf qu’elle ne s’exprime pas de la bonne manière. </p>\n<h2>Comment soulager les troubles de la personnalité ? </h2>\n<p>Les troubles de la personnalité ayant tendance à se figer avec le temps, il est difficile de travailler dessus. C’est surtout le cas pour les personnalités à faible insight, comme la personnalité narcissique. Car, si un individu ne voit aucun problème dans sa personnalité, comment pourrait-il changer ?</p>\n<p>Donc, pour ce genre de personnalité, il faudrait déjà passer par la case <a href=\"/antidepresseurs-et-anxiolytiques\" target=\"_blank\" rel=\"noopener\" title=\"Antidépresseurs et anxiolytiques\">médicaments</a>, pouvant l’aider, en effet, à prendre conscience de son trouble.</p>\n<p>Ensuite et afin que votre tempérament ne vous gâche plus la vie, sachez que des thérapies telles que la psychothérapie et la psychanalyse peuvent grandement vous prêter main-forte. La méthode EMDR aurait également fait ses preuves dans les troubles de la personnalité. </p>\n<p>Enfin et surtout, augmentez la conscience de votre trouble au maximum. Il n’y a en effet qu’ainsi que vous pourrez aller mieux. Pour ce faire, il est indispensable de prendre vos responsabilités et de ne plus rejeter la faute sur les autres. Ne prenez plus votre éducation comme la cause de tout votre mal-être. Car si vous restez bloqué à l’extérieur de vous alors que nous n’avez aucun contrôle sur l’extérieur, vous ne pourrez changer. </p>\n<p> </p>\n<p>Mais surtout, gardez la foi. Si vous travaillez dessus, <b>les différents troubles de la personnalité</b> n’en seront plus un. Vous aurez une personnalité, certes, mais qui n’impactera plus sur votre bien-être et celui des autres. </p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'Les Différents Troubles de la Personnalité : les Comprendre et les Soulager','Quelquefois, le tempérament d’un individu peut grandement le faire souffrir. Quels sont les différents troubles de la personnalité et comment les soulager ?','https://vivre-pleinement.fr/troubles-de-la-personnalite/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/troubles-de-la-personnalite\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/troubles-de-la-personnalite\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Les Diff\\u00e9rents Troubles de la Personnalit\\u00e9\\u00a0: les Comprendre et les Soulager\",\"datePublished\":\"2019-12-29T18:54:22+00:00\",\"dateModified\":\"2024-02-13T19:21:17+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/troubles-de-la-personnalite\\/\"},\"wordCount\":6583,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/troubles-de-la-personnalite\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/12\\/Differents-troubles-personnalite.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/troubles-de-la-personnalite\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/troubles-de-la-personnalite\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/troubles-de-la-personnalite\\/\",\"name\":\"Les Diff\\u00e9rents Troubles de la Personnalit\\u00e9\\u00a0: les Comprendre et les Soulager\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/troubles-de-la-personnalite\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/troubles-de-la-personnalite\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/12\\/Differents-troubles-personnalite.jpg\",\"datePublished\":\"2019-12-29T18:54:22+00:00\",\"dateModified\":\"2024-02-13T19:21:17+00:00\",\"description\":\"Quelquefois, le temp\\u00e9rament d\\u2019un individu peut grandement le faire souffrir. Quels sont les diff\\u00e9rents troubles de la personnalit\\u00e9 et comment les soulager\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/troubles-de-la-personnalite\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/troubles-de-la-personnalite\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/troubles-de-la-personnalite\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/12\\/Differents-troubles-personnalite.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/12\\/Differents-troubles-personnalite.jpg\",\"width\":641,\"height\":359,\"caption\":\"Comment soulager les differents troubles de la personnalite ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/troubles-de-la-personnalite\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Les Diff\\u00e9rents Troubles de la Personnalit\\u00e9\\u00a0: les Comprendre et les Soulager\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-12-29 18:54:22',NULL,'2026-05-24 19:19:45','2026-06-19 22:28:14');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (40,'Bien Commencer un Rééquilibrage Alimentaire, Pourquoi est-ce Important ?','reequilibrage-alimentaire','Partout, nous entendons parler de la nécessité d’avoir une alimentation saine pour une bonne santé physique et mentale. Certains d’entre nous optent pour des régimes et d’autres, pour un rééquilibrage alimentaire. Beaucoup pensent que la notion de rééquilibrage alimentaire ne reste que du marketing. Personnellement, je ne le pense pas. Vous perdez du poids pendant une diète, mais finissez toujours pas reprendre des kilos. Vous en avez assez de vous frustrer avec un régime qui vous affame, vous ne tenez donc pas sur le long terme. Votre objectif est de mieux manger, mais vous ne savez pas du tout comment vous y prendre. Vous souhaitez vous nourrir sainement tout en gardant le plaisir culinaire ? Comment bien commencer un rééquilibrage alimentaire ? \n','<p>Partout, nous entendons parler de la nécessité d’avoir une <b>alimentation saine </b>pour une bonne <b>santé physique</b> et <b>mentale</b>. Certains d’entre nous optent pour des <b>régimes </b>et d’autres, pour un rééquilibrage alimentaire. Beaucoup pensent que la notion de rééquilibrage alimentaire ne reste que du <b>marketing</b>. Personnellement, je ne le pense pas. Vous <b>perdez </b>du <b>poids </b>pendant une diète, mais finissez toujours pas <b>reprendre </b>des kilos. Vous en avez assez de vous <b>frustrer </b>avec un régime qui vous affame, vous ne tenez donc pas sur le<b> long terme.</b> Votre objectif est de <b>mieux </b>manger, mais vous ne <b>savez pas</b> du tout comment vous y prendre. Vous souhaitez vous nourrir <b>sainement </b>tout en gardant le <b>plaisir </b>culinaire ? Comment<b> bien commencer un rééquilibrage alimentaire ? </b></p>\n<h2>Bien commencer un rééquilibrage alimentaire pour la diminution des troubles anxieux </h2>\n<p>La nutrition peut clairement jouer sur la fréquence et la sévérité de vos <a href=\"/angoisse-stress-anxiete\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse stress anxiété \">troubles anxieux.</a> Je ne dis pas qu’avoir une alimentation 100 % saine fera disparaître définitivement votre angoisse. Car l’anxiété reste un trouble émotionnel complexe déclenché par bon nombre de facteurs, tels que les expériences de la vie, l’éducation, la génétique, etc., mais il a été démontré scientifiquement que certaines denrées peuvent atténuer vos problèmes d’anxiété, vu qu’elles présentent des composants apportant de nombreux bienfaits pour votre cerveau.</p>\n<p>Je vous en donne quelques-unes ici, étant précisé que je ne rentrerai pas dans des explications scientifiques poussées sur le pourquoi de leurs bénéfices, n’étant pas scientifique. Je vous invite donc à parcourir le Net si vous souhaitez approfondir vos connaissances sur un composant en particulier.</p>\n<p>Parmi les aliments à privilégier que je vous cite plus bas, ils possèdent tous au moins un des composants ci-dessous participant au bien-être de votre corps et de votre esprit. Les voici :</p>\n<p> </p>\n<p>– Le tryptophane est un composant de la sérotonine, qui est un neurotransmetteur de votre cerveau agissant sur le plaisir, le bonheur, la joie. La banane, par exemple, en comporte ;  </p>\n<p>– La dopamine et la noradrénaline vous amènent de l’énergie. Vous pouvez également les libérer en pratiquant un sport ; </p>\n<p>– Le fer. Vous pouvez en trouver dans les légumineuses ;</p>\n<p>– La vitamine B ; </p>\n<p>– Le magnésium marin. Vous n’en trouverez pas dans les aliments, mais vous pouvez en trouver dans une pharmacie. Ce minéral est connu pour calmer l’anxiété. Il vous donnera donc un petit coup de pouce ; </p>\n<p>– Les oméga-3. Vous en obtiendrez dans les poissons gras, tels que le saumon. </p>\n<h2>Différence entre régime et rééquilibrage alimentaire  </h2>\n<p>La plupart des individus font un amalgame entre le rééquilibrage alimentaire et le régime, sauf que ce n’est pas pareil. Voyons ensemble les différences fondamentales existant entre les deux.</p>\n<h3>Les carences et frustrations du régime</h3>\n<p>Qui dit régime dit diminuer les calories que vous ingurgitez. Résultat, le corps ne détient pas assez de nutriments et tombe en carence. Dans ce cas-là, vous manquez d’énergie et vous le ressentirez fortement si vous entamez une séance de sport. Car la fatigue se fera ressentir et vous aurez bien du mal à vous surpasser.</p>\n<p>De plus, restriction = frustration. C’est terrible d’aller dormir en ressentant une sensation de fringale et de ventre vide. Nous pensons maladroitement que c’est le meilleur moyen de mincir, sauf que tout ce que nous faisons à ce moment-là, c’est d’affamer notre corps. Il faut bien se dire que si l’organisme a faim, ce n’est pas par caprice. C’est qu’il ressent le besoin de recharger ses batteries. Donc, si vous ne l’écoutez pas, deux conséquences vont se dessiner pour vous.</p>\n<h4>Première conséquence </h4>\n<p>La première, c’est que psychologiquement, vous vous sentirez très frustré. Rien que le fait de vous empêcher un plaisir va profondément vous compliquer la vie en la rendant rigide. Vous allez apparaître de mauvaise humeur et à force de vous interdire des aliments sans arrêt, vous allez forcément craquer dès la moindre contrariété. Vous mangerez peut-être même plus qu’auparavant ! Il faut bien se dire que la nourriture ne doit pas représenter une tare ou une frustration. Elle est naturelle et doit rester un plaisir. Inutile donc de vous frustrer, ce qui ne fera que vous culpabiliser si vous craquez et diminuer votre confiance en vous.</p>\n<h4>Deuxième conséquence</h4>\n<p>La deuxième conséquence, c’est qu’en affamant votre organisme en pensant le faire maigrir, c’est tout le contraire qui se produit. En réalité, quand le corps se trouve en carence, il se sent en danger, car il se croit en famine. Pour se protéger, il stocke alors le gras afin de pouvoir « survivre » avec ses réserves. Donc, votre corps ne brûle pas les graisses. Il les conserve. C’est la raison pour laquelle vous n’arrivez pas à maigrir. Au début, certes, vous pourrez obtenir des résultats avec le régime hypocalorique. Vous pourrez même perdre facilement 3-4 kg la première semaine ! Mais sachez qu’il s’agit surtout d’eau que vous perdrez. Vous verrez bien vite que vous finirez par stagner. </p>\n<h3>Les bienfaits du rééquilibrage alimentaire </h3>\n<p>Contrairement au régime, le rééquilibrage alimentaire ne compte pas les calories. Il permet à votre corps d’ingurgiter de meilleurs nutriments pour son bon fonctionnement, et ce, sans ressentir la moindre frustration et sensation de faim. D’autre part, nous avons tous tendance à souvent manger les mêmes aliments. En entamant un rééquilibrage, vous découvrirez de nouvelles recettes à préparer, très goûteuses, que vous n’auriez jamais pensé cuisiner auparavant ! </p>\n<p>De plus, le rééquilibrage alimentaire n’interdit aucun aliment. Vous avez clairement le droit de manger gras, sucré ou salé quelquefois. Il faudra juste le faire plus occasionnellement en ne se jetant pas sur la première friandise venue. Mais, j’insiste là-dessus : aucune nourriture n’est interdite !</p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"479\" src=\"/storage/blog-images/Regime.jpg\" alt=\"Alimentation saine \" title=\"Régime\">\n<h2>Les aliments à privilégier dans un rééquilibrage alimentaire </h2>\n<p>Afin de vous aider à appliquer une meilleure alimentation dans votre quotidien, je vous donne ci-dessous une liste, non exhaustive bien évidemment, d’aliments à privilégier. J’ai compartimenté ladite liste en différentes rubriques. </p>\n<h3>1— Aliments </h3>\n<h4>Protéines </h4>\n<ul>\n<li aria-level=\"1\">Viande : dinde, poulet, bœuf, porc ; </li>\n<li aria-level=\"1\">Oeuf ; </li>\n<li aria-level=\"1\">Tofu, seitan, tempeh (notamment pour les personnes végétariennes) ;</li>\n<li aria-level=\"1\">Poissons : saumon, sardine, maquereau, hareng, thon, anchois. </li>\n</ul>\n<h4>Fruits </h4>\n<p>Banane, orange… globalement, tous les fruits sont permis.</p>\n<h4>Produits laitiers </h4>\n<p>Lait, yaourt nature, grec, fromage blanc 0 % de matière grasse…</p>\n<h4>Céréales </h4>\n<p>Avoine.</p>\n<h4>Huiles et épices</h4>\n<p>Soja (sauf le soja sucré), et globalement, tous les épices dont le curcuma, le curry, les graines de sésame, etc. ainsi que bon nombre d’huiles, telles qu’huile d’olive, de coco, de tournesol, etc. </p>\n<h4>Aliments comportant du « bon » gras </h4>\n<ul>\n<li aria-level=\"1\">Noix, noisettes, amandes ;</li>\n<li aria-level=\"1\">Beurre de cacahuète.</li>\n</ul>\n<h4>Légumineuses </h4>\n<p>Patate douce, lentilles corail, haricots rouges…</p>\n<h4>Féculents dont aliments complets</h4>\n<p>Riz complet, pâtes complètes, pain complet, pain de seigle, quinoa, boulgour, épeautre… </p>\n<h4>Légumes </h4>\n<p>Tous les légumes sont permis ! Légume-feuille, haricots, courgette…</p>\n<h4>Friandise tolérable</h4>\n<p>Chocolat noir, avec 75 % de cacao minimum.</p>\n<h3>2 — Boissons</h3>\n<h4>En général</h4>\n<p>Principalement de l’eau !</p>\n<h4>Boissons chaudes </h4>\n<ul>\n<li aria-level=\"1\">Infusions : camomille, mélisse, verveine…</li>\n<li aria-level=\"1\">Thé vert.</li>\n</ul>\n<h2>Les aliments à bannir dans un rééquilibrage alimentaire</h2>\n<p>Voyons maintenant quelques aliments à bannir, ou à ingérer plus occasionnellement. Certains d’entre eux, en effet, peuvent vous faire grossir, mais pas seulement. Vu qu’ils ne comportent pas beaucoup de nutriments sains, ils peuvent également perturber votre organisme, comme votre transit, rendant la digestion difficile. Vous pouvez ainsi ressentir de la fatigue. </p>\n<h3>Le sucre raffiné</h3>\n<p>Le sucre reste votre pire ennemi. Nous le trouvons malheureusement maintenant dans quasiment tous les aliments, donc, vous ne pourrez pas l’éliminer définitivement. Cependant, il est urgent de le réduire, car il reste clairement l’ennemi principal de votre organisme. Il vous fait grossir et peut provoquer, à la longue, des maladies, telles que le diabète, par exemple. C’est en réalité une <a href=\"/addictions\" target=\"_blank\" rel=\"noopener\" title=\"Addictions \">drogue</a>. Il s’agit sans hésitation de la substance dont vous aurez le plus de mal à vous passer. </p>\n<p>En effet, les aliments sucrés ont bon goût. Ils sont appétissants. D’ailleurs, quand vous mangez une nourriture sucrée, vous ressentez un pic d’énergie temporaire. Néanmoins, cet état baisse rapidement, ce qui a pour conséquence de faire augmenter les hormones du stress telles que le cortisol. De plus, un aliment sucré comporte des nutriments insuffisants pour votre organisme. Votre ventre n’est donc pas suffisamment rempli et vous ressentirez très vite, à nouveau, la faim. </p>\n<p>Cependant, votre corps a tout de même besoin de sucre. Mais de bon sucre. Tel que le fructose, que l’on retrouve dans les fruits. Par contre, contrairement à ce que l’on peut penser, les fruits sont bons pour la santé, mais du fait de leur teneur en sucre, ne sont pas à consommer à l’excès. </p>\n<p>Il y a donc lieu d’éliminer le plus possible le sucre raffiné et non le sucre naturel. Le sucre raffiné est le sucre blanc que vous trouvez principalement en magasin, ou dans les plats préparés, les glaces, les pâtisseries, les bonbons, les sodas, etc.</p>\n<p>Vous pouvez toujours vous autoriser quelques friandises occasionnellement. N’en abusez juste pas trop.</p>\n<h3>Les aliments et boissons industriels</h3>\n<p> </p>\n<p>Étant donné que le sucre raffiné reste présent en grandes quantités dans les plats industriels, évitez-les au maximum. Il y a d’ailleurs dans ces plats bon nombre d’autres cochonneries. Donc, les plats tout faits juste à réchauffer restent à proscrire et à manger seulement pour dépanner exceptionnellement. Méfiez-vous aussi des plats préparés allégés vous promettant une perte de poids. Car ils restent tout de même des plats remplis de conservateurs et ne possèdent souvent pas assez d’éléments nutritifs, rendant votre corps carencé. </p>\n<p>Évitez également les fast-food, sauf un de temps à autre si vraiment vous le désirez. Mais pourquoi, au lieu de commander un hamburger de fast-food, ne pas le réaliser vous-même, avec des ingrédients que vous aurez choisis ? Votre burger apparaîtra bien plus sain !</p>\n<p>Idem pour les boissons. Si vous êtes un adepte du jus d’orange le matin, évitez d’acheter les bouteilles toutes faites dans les magasins, lesquelles sont remplies de sucres ajoutés et de cochonneries. Pressez plutôt une orange vous-même et vous verrez que votre jus d’orange s’en trouvera bien plus succulent et surtout, on ne peut plus naturel !</p>\n<h3>L’alcool </h3>\n<p>Il est inutile d’interdire l’alcool. Mais il vaut mieux n’en boire qu’occasionnellement. Car l’alcool contient du sucre. Après, il est vrai que certains alcools apparaissent moins sucrés que d’autres. C’est le cas pour la bière ou le vin, par exemple. À vous donc, si vraiment vous souhaitez en consommer tout de même, de le faire avec modération. </p>\n<h3>Le fromage </h3>\n<p>J’ai mis le fromage dans cette catégorie, mais il n’est pas vraiment à bannir. Il est en effet conseillé d’en manger dans le cadre d’un rééquilibrage alimentaire, étant donné qu’il est bourré de calcium. Un bon nutriment pour votre organisme, donc. Comme tout produit laitier. En général, tout type de fromage peut être consommé. Mais, toujours avec modération, car c’est tout de même un aliment gras. La quantité autorisée dans une journée représente normalement 30 g.</p>\n<h3>Les aliments trop gras </h3>\n<p>Vous aimez savourer de bons plats traditionnels, tels qu’une bonne choucroute, ou une tartiflette ? Pas de soucis. Mais pas trop souvent non plus, j’entends. Car ces plats demeurent extrêmement gras et caloriques. Ils doivent donc vraiment rester occasionnels. </p>\n<p>C’est pareil pour le beurre. Vous avez le droit d’en manger, même tous les jours, dans le cadre d’un rééquilibrage alimentaire. Mais ne comptez pas plus de 10 g par jour.</p>\n<h3>Le café</h3>\n<p>Je sais que beaucoup nombre d’entre vous aiment boire un bon café, voire plusieurs au cours d’une journée. Ce n’est pas interdit. Cependant, il est conseillé de ne pas consommer plus de deux tasses de café par jour, étant donné qu’il reste excitant. </p>\n<p>D’ailleurs, je vous donne ici une petite astuce pour réduire votre consommation de sucre, si vous aimez le café en y ajoutant systématiquement un sucre. </p>\n<p>Par exemple, si vous prenez habituellement deux cafés par jour avec un sucre dans chacun, essayez maintenant de les boire sans sucre. Je vous assure que vous prendrez l’habitude de le faire sans ressentir de frustration, et ce, bien que le goût soit différent au début. Imaginez le résultat en une semaine. Deux sucres de moins en une journée = 2 X 7 = 14 sucres en moins ! Ce qui n’est pas négligeable. D’ailleurs, pour la petite anecdote, savez-vous qu’un vrai amateur de café ne met jamais de sucre dedans, afin d’en savourer au maximum le goût véritable ? </p>\n<img decoding=\"async\" width=\"640\" height=\"640\" src=\"/storage/blog-images/Manger-sainement.jpg\" alt=\"Nutritionniste \" title=\"Manger-sainement\">\n<h2>Exemple de programme journalier dans un rééquilibrage alimentaire </h2>\n<p>Voici maintenant un exemple de programme journalier afin de vous donner des idées pour organiser vos repas quotidiens. Il y a cependant deux choses particulières à connaître avant :</p>\n<p>La première, c’est que quand je parle « d’un fruit », il faut savoir que certains fruits, au vu de leur petite taille, ne sont pas considérés comme tels. C’est le cas, exemple, des clémentines et des kiwis. Donc, si vous aimez les clémentines, il faudra en manger 2 afin que cette portion puisse être considérée comme un fruit. </p>\n<p>La deuxième, c’est que je ne mentionnerai pas ici la quantité exacte de ce que vous devez consommer. Tout simplement, car les quantités dépendent de votre sexe, de votre poids initial, de votre âge, etc. en fait, tous les programmes sont personnalisés. Ainsi, si vous souhaitez suivre un programme vous correspondant totalement, il serait judicieux de prendre attache avec une diététicienne pour ce faire. Pour ma part, je suis passée par le site en ligne <a href=\"https://www.makemehealthy.fr/\">https://www.makemehealthy.fr/</a> j’ai pu en apprendre beaucoup grâce à ce site. Je sais maintenant comment bien manger et peux donc continuer seule sur ce chemin. </p>\n<h3>Petit-déjeuner </h3>\n<p>Nous avons souvent tendance à sauter le petit-déjeuner ou à manger très peu et surtout, de nombreux gâteaux industriels. Donc, nous sommes rapidement affamés au cours de la matinée et manquons vite d’énergie. Avec un bon repas le matin, vous n’aurez aucune sensation de faim jusqu’à 12 h. J’ai d’ailleurs été très surprise au début : </p>\n<p> </p>\n<p>– Fromage blanc 0 % de matière grasse, avec un carré de chocolat noir 75 % de cacao à émietter ;</p>\n<p>– 2 clémentines ;</p>\n<p>– Du pain complet beurré ; </p>\n<p>– Un café si vous le souhaitez.</p>\n<h3>Déjeuner du midi  </h3>\n<p>Étant donné que votre assiette sera composée de tous les nutriments nécessaires à votre organisme, vous allez très vite vous sentir rassasié !</p>\n<p>Votre plat doit donc être composé comme suit : </p>\n<p> </p>\n<p>– 50 % de légumes, 25 % de protéines et 25 % de féculents ;</p>\n<p>– Un fruit.</p>\n<h3>Collation </h3>\n<p>Entre le midi et le soir, il est vraiment difficile de ne pas avoir envie de grignoter. La collation vous aide donc à tenir jusqu’au soir. Avec le rééquilibrage alimentaire, vous ne ressentirez aucune sensation de faim dans la journée. Et quand vous commencerez à l’avoir, il sera l’heure de passer à table !</p>\n<p> </p>\n<p>– Amandes ou noisettes ; </p>\n<p>– Une compote sans sucre ajouté (avec le goût des fruits, vous ne ressentirez d’ailleurs aucun manque de sucre) ; </p>\n<p>– Un café si vous le désirez.</p>\n<h3>Dîner  </h3>\n<p>Le dîner est censé être plus léger. Au moins par rapport au déjeuner. La quantité de protéines doit normalement être réduite de moitié par comparaison au midi. Par exemple, si vous avez pris 100 g de protéines le midi, il est donc préconisé d’en consommer 50 g le soir : </p>\n<p> </p>\n<p>– 50 % de légumes, 25 % de protéines et 25 % de féculents ;</p>\n<p>– 30 g de fromage ;</p>\n<p>– Une infusion dans la soirée si vous le désirez.</p>\n<h2>Les difficultés rencontrées dans un rééquilibrage alimentaire</h2>\n<p>Le rééquilibrage alimentaire peut donc vraiment vous changer la vie. Cependant, il y a deux points que je souhaite approfondir ici. Et ce, afin d’éviter le craquage inutile. </p>\n<h3>L’organisation </h3>\n<p>Je ne vous cache pas que vous alimenter plus sainement prend plus de temps. Déjà, si vous souhaitez des légumes frais, il conviendra d’aller aux courses plus souvent. Ensuite, vos proches ne mangent pas forcément comme vous. Il vous faudra donc une bonne organisation pour cuisiner pour tout le monde. Il conviendra aussi, si vous travaillez, de vous préparer un repas la veille pour le lendemain midi. </p>\n<p>C’est sûr qu’aller chercher un fast-food reste bien moins contraignant ! Avec lui, pas besoin de faire de vaisselle et comme son nom l’indique, il se mange rapidement et reste très appétissant. Car le gras a bon goût. Mais il s’agit là de la solution de facilité. En effet, manger ainsi donne une sensation de récompense, mais qui n’apparaît malheureusement que temporaire. C’est le principe de la gratification immédiate que j’explique dans mon <a href=\"/confiance-et-estime-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Confiance et estime de soi\">article sur la confiance en soi. </a></p>\n<h3>Supporter le regard des autres </h3>\n<p>Lorsque vous entamez un rééquilibrage alimentaire, vous pouvez passer pour un extraterrestre aux yeux des autres. Car en mangeant plus sainement, vous allez éviter les croissants au travail, les restaurants entre collègues, etc. Vous serez susceptible d’être jugé, vu que vous ne mangerez plus comme la plupart des individus. Après, il ne s’agit pas de devenir psychorigide et intransigeant. Vous pouvez aller au restaurant avec vos collaborateurs de temps en temps, 1 fois par semaine, par exemple. Mais pas tous les jours. Il y aura donc lieu de travailler sur votre capacité à tolérer le <a href=\"/jugement-des-autres\" target=\"_blank\" rel=\"noopener\" title=\"Jugement des autres\">regard des autres. </a></p>\n<p>D’ailleurs, à ce sujet, je vous conseille le programme de Didier PENISSARD, auteur, conférencier et coach en développement personnel. N’hésitez pas à cliquer sur le bouton ci-dessous :</p>\n<h2>Astuces pour éviter de craquer pendant un rééquilibrage alimentaire </h2>\n<p>Je finirai cet article en vous donnant quelques petites astuces afin de ne pas céder à diverses tentations que vous regretterez par la suite. </p>\n<h3>Différencier la gourmandise de la faim  </h3>\n<p>Lorsque vous avez une folle envie d’ingurgiter un aliment en particulier, posez-vous la question suivante. Est-ce parce que vous venez de l’apercevoir alors qu’il y a une minute, vous n’y songiez même pas ? Il s’agit donc là de gourmandise. Ou sinon, attendez au moins 30 minutes avant de le consommer. Si ça se trouve, au bout des 30 minutes, vous n’y penserez plus. Il s’agissait ici également de gourmandise. Par contre, si vous y pensez encore après 30 minutes, c’est peut-être que votre corps a vraiment besoin de cet aliment ; et ce, quelles qu’en soient les raisons. Inutile donc de culpabiliser. Vous pouvez vous autoriser à succomber à une petite tentation. </p>\n<h3>Se demander s’il s’agit de faim ou de soif </h3>\n<p>Savez-vous que quand vous ressentez une sensation de faim, parfois, il s’agit plutôt de soif ? Vous pouvez tenter l’expérience. La prochaine fois que vous éprouvez une fringale, buvez un grand verre d’eau et attendez. Quelquefois, votre corps avait juste besoin de s’hydrater. Sauf qu’il ne l’exprime pas toujours de la bonne manière. D’ailleurs, en parlant d’hydratation, envisagez de boire au moins entre 1,5 et 2 litres d’eau par jour. L’eau reste en effet très importante pour votre organisme, composé lui-même d’énormément de quantité d’eau. </p>\n<h3>S’aider d’une application </h3>\n<p>Avant d’entamer un rééquilibrage alimentaire, j’avais commencé un régime hypocalorique. Bien que cette méthode ne soit pas conseillée, le fait de me servir d’une application comptant les calories de chaque aliment m’a tout de même permis de beaucoup apprendre. Je me demandais auparavant comment j’avais pu prendre du poids. Eh bien, en me rendant compte de la quantité de nourriture et des calories que j’ingurgitais grâce à l’application, plus rien ne m’étonnait ! </p>\n<p>Maintenant, avec le rééquilibrage alimentaire, les aliments sains n’apparaissant eux-mêmes pas très caloriques, je ne me sers plus trop de cette application. Je peux cependant quelquefois l’utiliser afin d’effectuer un mixte entre elle et le rééquilibrage. Ainsi, je peux continuer à manger sainement tout en m’autorisant quelques écarts. Pour information, l’application que j’utilise se nomme « Foodvisor ».</p>\n<h3>Prendre ses mensurations au lieu de se peser </h3>\n<p>Quelquefois, même en mangeant sainement, vous avez l’impression de ne pas perdre de poids ou même, d’en prendre ! Cette situation peut donc vous démoraliser et vous redonner l’envie de manger comme auparavant. </p>\n<p>Cependant, le poids ne veut rien dire, car il peut représenter votre masse musculaire et non votre graisse. Vous pensez ainsi stagner alors que vous mincissez tout de même. Sauf que vous ne le voyez pas sur la balance. Ce cas peut être valable si vous faites de la musculation, par exemple. Vous pouvez, en pratiquant ce sport, prendre 3 kg, mais qui ne représenteront que du muscle. Donc, inutile de vous démoraliser, vous n’avez pas grossi. Pour vous rendre compte d’une amélioration, il y a lieu de prendre vos mensurations à certaines zones principales, telles qu’aux bras, au ventre, aux cuisses, aux hanches, etc. vous pourrez être surpris du résultat ! </p>\n<p>Et si vous souhaitez découvrir une autre méthode alimentaire, je vous invite à vous intéresser à Rémi MOHA, coach sportif et de nutrition diplômé, lequel est l’auteur du livre intitulé “Synergie Alimentaire”. Cette méthode constiste à combiner certains aliments entre eux afin de pouvoir bénéficier pleinement de leurs nutriments et de gagner en santé, énergie et même, en perte de poids ! Si vous souhaitez en savoir plus, c’est ici :</p>\n<p>Vous verrez que <b>bien commencer un rééquilibrage alimentaire</b> ne vous apportera que de nombreux bénéfices. Pourquoi donc ne pas agir maintenant ? </p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'Bien Commencer un Rééquilibrage Alimentaire, Pourquoi est-ce Important ?','Vous souhaitez vous nourrir sainement tout en gardant le plaisir culinaire ? Comment bien commencer un rééquilibrage alimentaire ?','https://vivre-pleinement.fr/reequilibrage-alimentaire/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/reequilibrage-alimentaire\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/reequilibrage-alimentaire\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Bien Commencer un R\\u00e9\\u00e9quilibrage Alimentaire, Pourquoi est-ce Important\\u2009?\",\"datePublished\":\"2019-12-21T23:20:53+00:00\",\"dateModified\":\"2024-02-13T17:18:07+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/reequilibrage-alimentaire\\/\"},\"wordCount\":7623,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/reequilibrage-alimentaire\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/12\\/Bien-commencer-reequilibrage-alimentaire.jpg\",\"articleSection\":[\"D\\u00e9veloppement personnel\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/reequilibrage-alimentaire\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/reequilibrage-alimentaire\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/reequilibrage-alimentaire\\/\",\"name\":\"Bien Commencer un R\\u00e9\\u00e9quilibrage Alimentaire, Pourquoi est-ce Important\\u2009?\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/reequilibrage-alimentaire\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/reequilibrage-alimentaire\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/12\\/Bien-commencer-reequilibrage-alimentaire.jpg\",\"datePublished\":\"2019-12-21T23:20:53+00:00\",\"dateModified\":\"2024-02-13T17:18:07+00:00\",\"description\":\"Vous souhaitez vous nourrir sainement tout en gardant le plaisir culinaire\\u2009? Comment bien commencer un r\\u00e9\\u00e9quilibrage alimentaire\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/reequilibrage-alimentaire\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/reequilibrage-alimentaire\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/reequilibrage-alimentaire\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/12\\/Bien-commencer-reequilibrage-alimentaire.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/12\\/Bien-commencer-reequilibrage-alimentaire.jpg\",\"width\":550,\"height\":366,\"caption\":\"Comment bien commencer un reequilibrage alimentaire ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/reequilibrage-alimentaire\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Bien Commencer un R\\u00e9\\u00e9quilibrage Alimentaire, Pourquoi est-ce Important\\u2009?\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-12-21 23:20:53',NULL,'2026-05-24 19:19:45','2026-06-19 22:28:14');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (41,'Vivre dans l’Instant Présent pour Ressentir la Vie Intensément','vivre-linstant-present','Vous avez déjà dû entendre parler de l’instant présent. Il s’agit en effet d’un sujet de développement personnel devenu universel à notre époque. Bon nombre d’entre nous emploient d’ailleurs diverses citations à cet égard, dont la fameuse carpe diem. Cependant, nous avons tendance à penser que vivre le moment présent n’est réservé qu’aux sages confirmés. Dès le levé, vous ne pensez qu’aux tâches que vous allez devoir réaliser dans la journée. Votre mental fourmille sans cesse. Vous passez un excellent instant en famille et d’un coup, vous ruminez sur un dossier que vous devez terminer d’urgence le lendemain au travail. Ce bon moment est donc gâché. Vous n’arrivez pas à dormir la nuit car repensez à un conflit que vous avez eu avec un ami la veille. Vous aimeriez savourer votre vie ? Comment vivre dans l’instant présent ? \n','<h2>Comment vivre l\'instant présent ?</h2>\n<p>« Vis l\'instant présent », « lâche prise », « savoure le moment »… On vous le répète sans jamais vous expliquer <i>comment</i> faire concrètement. Pourtant, vivre le moment présent n\'est pas un don réservé aux moines bouddhistes : c\'est une compétence qui se cultive, par de petits exercices accessibles à tous.</p>\n<p>Voici l\'essentiel, en trois idées :</p>\n<ul>\n<li><b>Ramenez votre attention à vos sens.</b> Ce que vous voyez, entendez, touchez maintenant : le présent passe toujours par le corps, jamais par le mental.</li>\n<li><b>Acceptez vos pensées sans les suivre.</b> Vivre l\'instant présent, ce n\'est pas faire le vide, c\'est cesser de courir derrière le passé et le futur — souvent la vraie source de l\'<a href=\"/blog/angoisse-stress-anxiete\">anxiété</a>.</li>\n<li><b>Entraînez-vous chaque jour</b>, par la <a href=\"/blog/respiration\">respiration</a>, la gratitude ou le <a href=\"/blog/lacher-prise-et-acceptation\">lâcher-prise</a>.</li>\n</ul>\n<p>Plus bas, vous trouverez <b>11 exercices concrets</b> pour y parvenir, à intégrer à votre quotidien dès aujourd\'hui.</p>\n<p>Vous avez déjà dû entendre parler de l’instant présent. Il s’agit en effet d’un sujet de <b>développement personnel </b>devenu universel à notre époque. Bon nombre d’entre nous emploient d’ailleurs diverses citations à cet égard, dont la fameuse <strong><em>carpe d</em></strong><b><i><strong>iem</strong>.</i></b> Cependant, nous avons tendance à penser que vivre le moment présent n’est réservé qu’aux <b>sages</b> confirmés. Dès le levé, vous ne pensez qu’aux <b>tâches </b>que vous allez devoir réaliser dans la journée. Votre <b>mental </b>fourmille sans cesse. Vous passez un <b>excellent instant</b> en famille et d’un coup, vous <b>ruminez </b>sur un dossier que vous devez terminer d’urgence le lendemain au travail. Ce bon moment est donc <b>gâché</b>. Vous n’arrivez pas à <b>dormir </b>la nuit car repensez à un <b>conflit </b>que vous avez eu avec un ami la veille. Vous aimeriez <b>savourer </b>votre vie ? Comment <b>vivre dans l’instant présent ? </b></p>\n<h2>Vivre dans l’instant présent, ça veut dire quoi ?  </h2>\n<p>Avez-vous déjà vécu dans le présent ? En réalité, vivre le moment en prenant conscience de toutes nos sensations apparaît pratiquement inconcevable. Car nos 5 sens demeurent en activité. Par conséquent, se focaliser sur le goût, l’odeur, le toucher, la vue et le son en même temps relève de l’impossible. Si vous arrivez à vous concentrer sur au moins un de vos sens, vous pourrez goûter à l’instant présent.</p>\n<p>Vivre l’instant s’apparente ainsi au fait de ressentir une partie de soi intensément, au point de rentrer dans un état de flow. Il s’agit donc de rester connecté au monde et non pas à sa tête et à ses pensées.</p>\n<p>Enfin, vivre dans l’instant, c’est également avoir la capacité d’accepter la situation dans laquelle vous vous trouvez à l’instant T. C’est-à-dire, soit de la savourer si vous vous sentez heureux, soit d’entreprendre des actions pour modifier votre condition si vous ne vous sentez pas en joie. Car le fait d’agir pour changer une situation inconfortable vous aidera à supporter le présent. En effet, passer à l’action peut provoquer un état de flow, lequel vous redonnera espoir. Vous pourrez vous éviter bon nombre de souffrances psychologiques.</p>\n<h2>Pourquoi vivre le moment présent ?  </h2>\n<p>Savez-vous vraiment pourquoi vivre dans l’instant présent est bénéfique ? Tout simplement car en vivant dans le présent, vous ne vivez ni dans le passé ni dans le futur. Mais est-ce si grave de rester dans le passé ou dans le futur ?</p>\n<p>Lorsque vous vivez dans le futur ou dans le passé, c’est que vous utilisez trop votre mental. Et trop cogiter ou ruminer n’est pas bon. Par contre, certaines personnes prennent trop en grippe le mental, en le comparant à un poison et souhaitant le bannir définitivement. Sauf qu’il fait partie de nous. Il s’agit de l’ego, certes, mais il ne faut pas complètement le jeter à la poubelle non plus. D’ailleurs, on ne le peut pas. Car c’est tout de même grâce à lui que l’on peut réfléchir, agir, travailler, être productif, pratiquer des activités, s’affirmer, créer une société, etc.</p>\n<p>Il n’y a donc pas lieu de haïr le mental. Il faut juste savoir bien l’utiliser. C’est là que vivre dans le passé ou dans le futur peut s’avérer dangereux. </p>\n<h3>Vivre dans le passé </h3>\n<p>Quand une personne vit dans le passé, elle se fige automatiquement. Car comment voulez-vous agir dans le présent si vous êtes constamment tourné vers le passé qui, de toute façon, ne pourra être changé ? Penser sans arrêt au passé n’est donc pas bénéfique pour vous. En effet, soit vous pensez que c’était mieux avant et ainsi, vous vous laissez happer par votre passé. Soit vous n’en avez pas digéré un événement, ce qui a pu faire apparaître un traumatisme. Dans ce cas, vous êtes en proie à des schémas répétitifs se déroulant dans votre mental, ce qui vous fige totalement. </p>\n<p>Dans tous les cas, vivre dans le passé vous rend inapte à agir. Attention cependant de ne pas tomber dans le piège du déni du passé. Certaines personnes, en effet, font comme si le passé n’existait pas, le renient, et ce, afin d’éviter toute souffrance. Sauf qu’en agissant ainsi, vous niez la personne que vous êtes devenue. Et par quels chemins vous l’êtes devenu, surtout. </p>\n<p>Ce que vous devez faire, en réalité, c’est vivre dans le présent, mais tout en acceptant votre passé. Apprendre des expériences passées et des erreurs commises afin de pouvoir vous remettre en question et de ce fait, d’évoluer. Car si vous niez, par exemple, un traumatisme de votre passé, vous pouvez être certain qu’il se manifestera dans le présent. Donc non pour le déni et oui pour le passage à l’action. </p>\n<p>Par conséquent, trop vivre dans le passé peut rendre la personne sujette à de fortes ruminations et donc, à la dépression.</p>\n<h3>Vivre dans le futur</h3>\n<p>La personne vivant dans le futur vit dans son imagination. Par conséquent, si une personne est anxieuse, elle s’imagine forcément un futur noir. Le seul truc que nous oublions, c’est que le futur n’existe pas. Donc, pourquoi penser à ce qui, finalement, n’existe pas ? </p>\n<p>Bien évidemment, le futur n’est pas totalement à blâmer. Par exemple, si vous avez de grands projets, il est nécessaire de vous imaginer un minimum le futur afin d’établir un plan d’action. Il s’agit là d’une bonne façon de songer au futur. </p>\n<p>Par conséquent, mal utiliser votre mental vous rend anxieux en imaginant un avenir sombre. Par contre, vous servir de votre mental correctement vous pousse à imaginer l’avenir que vous souhaitez, tout en entreprenant des actions pour l’atteindre. </p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"439\" src=\"/storage/blog-images/Pleine-conscience.jpg\" alt=\"Instant T\" title=\"Pleine-conscience\">\n<h2>Est-il possible de vivre continuellement en pleine conscience ? </h2>\n<p>Il est préférable d’opter pour la vie dans l’instant T. Cependant, il ne faut pas oublier que notre société moderne n’est pas de tout repos. Nous vivons en effet une existence stressante à bien des égards. Donc oui, il serait bon de vivre constamment dans le présent, mais ce n’est pas toujours praticable.  </p>\n<p>Mais ce n’est pas tout. Il est vrai que lorsque nous observons les animaux en général, ils ont clairement l’air, contrairement à nous, de vivre dans le présent. Car ils restent très proches de leur instinct. Leur but premier reste finalement d’assouvir leurs besoins primaires. </p>\n<p>De plus, avez-vous déjà lu ce genre de phrases dans des magazines de développement personnel ? : « faites comme les enfants, retrouvez votre âme d’enfant, vivez pleinement le moment dans la joie et la bonne humeur ». </p>\n<h3>La comparaison de l’homme avec l’animal</h3>\n<p>Concernant les animaux, l’être humain possède une chose de plus qu’eux. L’intelligence, que l’on peut nommer le mental, l’ego. L’être humain pense donc constamment. Vous pouvez, si vous le souhaitez, l’expérimenter par vous-même en pratiquant une séance de méditation. Il est fort probable que faire le vide s’avère complètement impossible pour vous. Vous verrez en effet défiler un nombre incalculable de pensées. Vous ne pouvez en effet arrêter de penser. Ce que la méditation vous apprend, en réalité, c’est de lâcher-prise sur ces pensées. De les laisser passer, tel un nuage dans le ciel. Elle ne peut vous apprendre à ne plus penser du tout. </p>\n<h3>La comparaison de l’adulte avec l’enfant </h3>\n<p>Il est fort probable que nous ayons gardé une part d’enfant en nous. Cependant, il ne faut pas oublier que l’enfant n’a pas la vie d’un adulte. Un enfant, s’il vit dans une famille un minimum structurée, n’a pas vraiment de problème. De plus, un petit a tout à apprendre de l’existence. Bien sûr qu’il est alors plus émerveillé pour tout. Car tout n’est qu’apprentissage pour lui. Il a donc une plus grande aisance à vivre dans le présent. </p>\n<p>Et puis, l’enfant va également avoir une éducation et va faire des expériences dans son environnement. Il développera ainsi une personnalité propre, avec des mécanismes de défense. Puis, en devenant grand, les responsabilités deviennent beaucoup plus grandes : construire une famille, la nourrir, etc. On ne peut donc décemment pas, en tant qu’adulte, vivre avec l’esprit pur d’un enfant. En tant qu’adulte, il est bien plus difficile de vivre dans l’instant présent. </p>\n<h2>Est-il toujours recommandé de vivre dans l’instant présent ?</h2>\n<p>Vivre dans l’instant présent est ainsi vivement conseillé. Cependant, je pense que deux points peuvent donner lieu à réflexion. </p>\n<p>Le premier point c’est que, quelquefois, l’imagination peut permettre à une personne de s’évader, le temps que l’événement qu’elle subit dans le sur le moment se termine. Par exemple, admettons qu’un salarié se fasse sévèrement sermonner par son patron. Et surtout, de manière injustifiée. Il sent qu’il va craquer. Il ne va pas bien du tout. Pour se calmer, il s’imagine rentrer chez lui le soir et retrouver sa femme qui lui aura préparé son plat préféré. Rien que le fait d’imaginer cette scène lui donne un sentiment de joie, de calme et de plénitude intense. Son attitude l’aide donc à gérer ses émotions lors de l’événement désagréable en train de se produire. </p>\n<p>Le deuxième point peut survenir dans le cas d’une personne souffrant de <a href=\"/traumatisme\" target=\"_blank\" rel=\"noopener\" title=\"Traumatisme\">traumatisme</a>, qui souffre de troubles anxieux ou qui n’a pas confiance en elle. On dit bien qu’il n’existe pas d’angoisse dans le présent. Je trouve pourtant que c’est faux. Car dans l’instant T, c’est aussi là qu’il convient de passer à l’action. Et vous savez bien que quelquefois, agir peut angoisser, si vous souffrez d’un quelconque trouble. Vous pouvez alors vous mettre une sacrée pression sur le moment ce qui peut vous faire perdre vos moyens. Comme une personne ayant trop le trac pour parler devant son auditoire, par exemple. Il y a donc déjà lieu de travailler un minimum sur vos traumatismes afin de pouvoir vivre pleinement l’instant. </p>\n<img decoding=\"async\" width=\"640\" height=\"409\" src=\"/storage/blog-images/Moment-present.jpg\" alt=\"Flow\" title=\"Moment-présent\">\n<h2>Comment vivre le moment présent ?  </h2>\n<p>À l’exception de certaines situations, il est bénéfique de vivre dans l’instant T aussi souvent que possible. Mais, vu que nous n’avons pas été élevés ainsi, nous devrons alors fournir des efforts pour parvenir à ce but. Je vous donne ici certaines idées d’action que vous pouvez entreprendre afin d’atteindre le plus souvent possible la sensation de plénitude survenant en vivant dans le présent.</p>\n<h3>Opter pour la nouveauté </h3>\n<p>Bien souvent, nous aimons la sécurité, et c’est parfaitement normal. Après tout, qui aime vivre dans l’insécurité ? Cependant, quelquefois, trop de routine peut nous empêcher de savourer l’instant présent. Je pense que vous l’avez déjà expérimenté. Par exemple, pouvez remarquer que, lors de votre premier jour de travail, bien que vous soyez extrêmement angoissé, cette sensation va s’atténuer avec la nouveauté. Car quand une activité apparaît nouvelle pour nous, nous devons nous adapter. Et pour ce faire, nous devons nous habituer et donc, apprendre. Votre concentration sera ainsi dirigée vers le changement et l’apprentissage, ce qui vous aidera plus facilement à entrer dans un état de flow. </p>\n<p>Tandis que quand vous réalisez des tâches quotidiennes de manière machinale, comme faire le ménage, vous verrez qu’une myriade de pensées pourront survenir dans votre esprit. C’est d’ailleurs souvent dans ces moments de routine que vous êtes le plus susceptible de <a href=\"/ruminations\" target=\"_blank\" rel=\"noopener\" title=\"Ruminations\">ruminer</a>. </p>\n<p>Par conséquent, n’hésitez pas à entreprendre des activités nouvelles. Si vous avez un tempérament anxieux, vous éprouvez des difficultés au début. Mais à un moment donné, vous arriverez à faire diminuer votre état d’anxiété en vivant votre instant de flow. Le fait de passer à l’action aura pour avantage d’augmenter votre périmètre de sécurité et donc, votre confiance en vous et au monde.</p>\n<h3>Se détourner de soi </h3>\n<p>Les ruminations peuvent souvent vous empêcher de vivre le présent. Lorsqu’elles surviennent, tentez de détourner votre attention de vous-même. Si vous vous trouvez avec d’autres personnes, par exemple, essayez de discuter avec une personne en vous concentrant vraiment sur elle et sur ce qu’elle vous dit. Vous verrez que vous arriverez à vivre l’instant T en parlant avec elle, ce qui vous détournera donc de vous et ainsi, de vos pensées.</p>\n<h3>Entrer dans un état de flow </h3>\n<p>La sensation de flow survient lorsque vous êtes concentré sur une occupation. Vous avez probablement déjà ressenti cet état quand vous effectuez une activité que vous aimez. Si vous adorez cuisiner, vous vous concentrez intensément sur cette activité, et ce, avec joie. Vous verrez d’ailleurs que ce moment passera très vite. Tandis que si vous êtes en train de vous embêter au travail, le temps vous semblera infini. </p>\n<p>À vous donc d’essayer d’entrer dans cet état de flow le plus souvent possible. D’abord, avec des occupations qui vous passionnent. Ensuite, avec des activités <b>« </b>normales <b>»</b>, comme faire le ménage, par exemple. Enfin, vous pourrez peut-être, avec de l’entraînement, entrer dans le flow en n’effectuant rien de particulier, et ce, sans vous ennuyer. Juste en profitant de l’instant tout en ressentant vos émotions et votre corps.</p>\n<h3>Pratiquer des techniques de respiration </h3>\n<p>Je vous invite à aller consulter mon <a href=\"/respiration\" target=\"_blank\" rel=\"noopener\" title=\"Respiration\">article</a> sur la respiration afin d’avoir plus de renseignements à ce sujet. Avoir une bonne respiration vous aidera à vivre l’instant T en vous entraînant à ressentir votre corps. </p>\n<p>Personnellement, la méthode que j’utilse pour bien respirer est la cohérence cardiaque. J’utilise pour ce faire ZENSPIRE, un appareil qui, grâce à ses lumières et vibrations, me permet d’apprendre à respirer profondément et amplement. Eh oui, bon nombre d’entre nous ne savent plus respirer naturellement. Souvent, nous respirons de manière artificielle, ce qui entretient le stress. Si vous êtes intéressé par ce produit, c’est juste ici, étant précisé qu’en passant commande, vous bénéficierez, grâce au code JL0620, d’une remise de 10 % :</p>\n<h3>Pratiquer le lâcher-prise </h3>\n<p>Qui dit vivre dans l’instant présent dit mettre de côté son mental. Du moins, ne pas trop le faire carburer comme pour la dépression ou les troubles anxieux. Pour ce faire, il est impératif de lâcher-prise. N’hésitez pas à aller consulter mon <a href=\"/lacher-prise-et-acceptation\" target=\"_blank\" rel=\"noopener\" title=\"Lâcher-prise et acceptation \">article</a> à cet égard. Car le lâcher-prise est clairement le contraire d’être trop dans son mental. Nous utilisons en effet bien souvent trop notre mental comme mécanisme de défense afin d’éprouver une illusion de contrôle sur notre environnement. </p>\n<p>Cependant, le lâcher-prise veut bien dire « lâcher votre prise ». Par conséquent, cesser de trop penser et entreprendre des actions sans en attendre un quelconque résultat. À vous donc d’agir pour la bonne cause, mais sans rien attendre en retour. Ayez confiance en la vie. Elle vous le rendra. </p>\n<p>Enfin, bien souvent, le mental vous tend un piège : celui de vous identifier à vos pensées. C’est ce qui déclenche bon nombre de troubles anxieux, notamment la phobie d’impulsion. Par exemple, vous avez une pensée étrange vous traversant l’esprit, telle que « pourrais-je tuer cette personne avec ce couteau que j’ai dans les mains actuellement ? » Et vous vous identifiez à elle au lieu de la laisser passer. De ce fait, vous pensez avoir un potentiel de tueur, alors qu’il s’agit juste d’une pensée banale que tout le monde peut avoir. Mais, vu que vous n’avez tout simplement pas laissé filer cette pensée, votre mental l’a attrapé, en vous faisant croire toutes sortes de choses aberrantes à votre sujet. </p>\n<h3>Ressentir de la gratitude </h3>\n<p>Ce petit exercice peut également vous aider à vivre dans l’instant présent. Par exemple, quand vous sentez que vous ruminez, faites une liste d’au moins 5 éléments pour lesquels vous avez éprouvé de la gratitude au cours de votre journée. Un compliment de votre supérieur, un sourire d’une personne inconnue, une bonne glace que vous avez mangée, etc. Ou avoir une maison, une famille, un mari aimant, etc.</p>\n<p>Nous avons tous tendance à oublier ce qui reste essentiel pour nous en ne voyant que le négatif. Il va donc vraiment falloir vous efforcer de voir le verre à moitié plein plutôt qu’à moitié vide. </p>\n<h3>Apprendre à sourire </h3>\n<p>Lorsque vous vous sentez aigri ou tendu, essayez de sourire. Vous verrez qu’en souriant, vous aurez bien du mal à continuer de penser de manière négative ! Nous avons en effet trop tendance à oublier notre corps. Alors qu’il peut clairement, s’il est détendu, faire du bien à notre esprit. </p>\n<h3>Pratiquer la visualisation </h3>\n<p>La visualisation reste une méthode très efficace pour vous permettre d’acquérir de meilleures pensées et donc, d’avoir confiance en vous. Et vous savez d’ailleurs très bien, si vous souffrez de troubles anxieux, que la visualisation est très puissante. Car la façon dont vous imaginez le pire dans le futur vous pousse vraiment à y croire puisque tout y est. Les sensations corporelles, les émotions, les images, etc. Il en va de même si vous rejouez des scènes négatives dans le passé, lesquelles vous font vivre de la rancœur. </p>\n<p>Vous savez donc bien que la visualisation marche. Sauf que vous ne l’utilisez pas de la bonne manière. Il existe cependant des techniques de visualisation vous apportant tout le contraire, c’est-à-dire bien-être et confiance. Si, par exemple, vous pratiquez une technique de respiration, vous pouvez imaginer absorber, en inspirant, un amas d’ondes positives. Puis, en expirant, vous pouvez imaginer une longue traînée noire sortir de votre corps, représentant vos émotions négatives. À vous d’imaginer des choses bénéfiques qui vous parlent.</p>\n<h3>Pratiquer la méditation </h3>\n<p>La méditation reste de loin le meilleur exercice pour vous permettre de vivre dans l’instant présent. Elle vous entraîne, en effet, à laisser passer vos pensées de manière naturelle afin qu’elles ne puissent atteindre votre mental. Elle vous aide également à prendre conscience de votre corps dans son ensemble.</p>\n<p>Cependant, la méditation ne convient pas à tout le monde, du moins, pas à n’importe quel moment. C’est d’autant plus vrai si vous souffrez de véritables troubles anxieux, qui proviennent bien souvent de traumatismes non résolus. Votre mental demeure donc trop bouillonnant. Par conséquent, le fait de méditer et de trop entrer en vous peut terriblement vous angoisser. Car votre intérieur demeure, pour l’instant, bien trop tempétueux. Il va ainsi déjà falloir, si vous souhaitez méditer, calmer votre anxiété et vous libérer un minimum de vos traumatismes.</p>\n<h3>Pratiquer le yoga</h3>\n<p>Si vous souhaitez vivre l’instant présent le plus souvent possible, il est primordial, en premier lieu, de ressentir votre corps. En effet, combien d’entre nous prennent vraiment le temps d’écouter leur corps ? Si vous portez votre attention sur votre respiration, vous remarquerez qu’elle apparaît bien souvent coupée et artificielle. Il en va de même pour notre corps en général. Nous l’utilisons généralement automatiquement, sans nous en rendre compte, de manière automatique. Cependant, en en prenant conscience, vous verrez que vous arriverez beaucoup plus à vivre dans le présent. </p>\n<p>Le yoga peut grandement vous aider. Par contre, pour profiter au maximum de ses bienfaits, il faut effectuer les exercices consciemment et pas machinalement. Ce moment doit devenir votre instant de détente, en prenant conscience de votre corps et de votre respiration. C’est vraiment ainsi que vous pourrez expérimenter la sensation de flow merveilleuse de l’ici et maintenant.</p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img loading=\"lazy\" decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h3>S’adonner à différents petits exercices quotidiens </h3>\n<p>Enfin, voici diverses petites astuces qui vous aideront encore plus à vivre dans le moment présent.</p>\n<p>Quand vous pratiquez une activité routinière, comme faire la vaisselle, essayez de dire à voix haute ce que vous êtes en train d’accomplir. Par exemple : « je prends cette assiette et je mets de la lessive dessus. Je frotte et ensuite, je rince ». En agissant ainsi, vous verrez que vous arriverez mieux à vous concentrer sur ce que vous effectuez, et ce, sans que vos pensées ne s’éparpillent. Car lorsqu’elles se dispersent automatiquement, surtout si vous êtes atteint de troubles anxieux, elles sont forcément négatives. Ce processus vous aide donc à éviter d’enclencher le mécanisme de la rumination.</p>\n<p>Enfin, vous pouvez sentir la colère monter lors d’une situation de la vie courante, comme vous trouver dans les bouchons, par exemple. Profitez justement de ce moment, que vous pensez perdu en le rendant utile. Car étant donné que votre énervement ne fera pas avancer les voitures plus vite, il ne sert à rien d’opter pour ce genre de comportement, non ? Donc, pourquoi ne pas profiter de ce moment pour améliorer vos techniques de respiration ? Vous pouvez également essayer de ressentir votre corps et vos émotions. Au lieu et place de la colère, vous pouvez clairement choisir la détente. </p>\n<p>Ne trouvez-vous pas qu’il y a bon nombre d’avantages à <b>vivre dans l’instant présent </b>? À vous de jouer, maintenant ! </p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'Vivre l\'Instant Présent : 11 Exercices Concrets pour y Arriver','Vivre l\'instant présent, ça veut dire quoi, et comment faire vraiment ? 11 exercices simples de pleine conscience pour sortir du mental et apaiser l\'anxiété.','https://vivre-pleinement.fr/vivre-linstant-present/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/vivre-linstant-present\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/vivre-linstant-present\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Vivre dans l\\u2019Instant Pr\\u00e9sent pour Ressentir la Vie Intens\\u00e9ment\",\"datePublished\":\"2019-12-14T17:52:02+00:00\",\"dateModified\":\"2024-02-12T19:23:09+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/vivre-linstant-present\\/\"},\"wordCount\":6020,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/vivre-linstant-present\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/12\\/Vivre-instant-present.jpg\",\"articleSection\":[\"D\\u00e9veloppement personnel\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/vivre-linstant-present\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/vivre-linstant-present\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/vivre-linstant-present\\/\",\"name\":\"Vivre dans l\\u2019Instant Pr\\u00e9sent pour Ressentir la Vie Intens\\u00e9ment\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/vivre-linstant-present\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/vivre-linstant-present\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/12\\/Vivre-instant-present.jpg\",\"datePublished\":\"2019-12-14T17:52:02+00:00\",\"dateModified\":\"2024-02-12T19:23:09+00:00\",\"description\":\"Nous pensons vivre le moment pr\\u00e9sent n\\u2019est r\\u00e9serv\\u00e9 qu\\u2019aux sages confirm\\u00e9s. Vous aimeriez savourer votre vie\\u2009? Comment vivre dans l\\u2019instant pr\\u00e9sent\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/vivre-linstant-present\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/vivre-linstant-present\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/vivre-linstant-present\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/12\\/Vivre-instant-present.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/12\\/Vivre-instant-present.jpg\",\"width\":640,\"height\":640,\"caption\":\"Comment vivre dans l\\u2019instant present ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/vivre-linstant-present\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Vivre dans l\\u2019Instant Pr\\u00e9sent pour Ressentir la Vie Intens\\u00e9ment\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-12-14 17:52:02',NULL,'2026-05-24 19:19:45','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (42,'Confiance en Soi et Estime de Soi : la Racine du Bien-être Profond','confiance-et-estime-de-soi','Partout, nous entendons parler de confiance en soi et estime de soi. Effectivement, ces concepts restent incontestablement la racine du bien-être. La confiance en soi n’est jamais acquise. Il faut tous les jours travailler dessus afin de l’augmenter ou de la préserver. Vous pouvez aussi très bien avoir confiance en vous et réussir dans votre vie grâce à vos capacités, mais n’avoir aucune estime pour vous. Vous avez l’impression que vous aimez plus vos proches qu’ils ne vous aiment. Vous vous sentez incapable dans certains domaines de votre existence et de ce fait, n’évoluez pas dans ces domaines. Une grande peur vous bloque. Les critiques sur votre travail vous fendent le cœur. Vous vous croyez incompétent et vous vous dévalorisez beaucoup. Vous en avez assez de vivre ainsi ? Comment augmenter votre confiance et votre estime de vous ? \n','<p>Partout, nous entendons parler de <b>confiance en soi et estime de soi</b>. Effectivement, ces concepts restent incontestablement la <b>racine </b>du <b>bien-être.</b> La confiance en soi n’est jamais<b> acquise. </b>Il faut tous les jours <b>travailler </b>dessus afin de l’augmenter ou de la préserver. Vous pouvez aussi très bien avoir confiance en vous et réussir dans votre vie grâce à vos capacités, mais n’avoir aucune estime pour vous. Vous avez <b>l’impression </b>que vous <b>aimez </b>plus vos <b>proches </b>qu’ils ne vous aiment. Vous vous sentez <b>incapable </b>dans certains <b>domaines </b>de votre existence et de ce fait, <b>n’évoluez pas</b> dans ces domaines. Une grande <b>peur </b>vous bloque. Les <b>critiques </b>sur votre travail vous fendent le cœur. Vous vous croyez <b>incompétent </b>et vous vous <b>dévalorisez </b>beaucoup. Vous en avez assez de vivre ainsi ? Comment <b>augmenter </b>votre confiance et votre estime de vous ? </p>\n<h2>Confiance en soi et estime de soi : qu’est-ce que c’est ? </h2>\n<p>La personne ayant confiance en elle croit en l’avenir. Elle se sait, au plus profond d’elle, capable d’affronter toutes les situations qui se présenteront. Elle se sent ainsi en sécurité dans son corps et dans sa tête. De ce fait, elle fera preuve d’une grande résilience quand des événements négatifs surviendront. Certains se victimiseront et se laisseront abattre, tandis que d’autres prendront leurs responsabilités et agiront sur ce qui se trouve en leur pouvoir afin d’évoluer.<b> </b></p>\n<p>L’individu a donc une bonne confiance en ses facultés et les met par conséquent en œuvre facilement. Mais il a également conscience de ses faiblesses et ne craint pas à renoncer si une tâche lui paraît trop difficile, et ce, sans se dévaloriser pour autant. Il apprend plutôt à travailler sur ses fragilités. Il n’hésite pas à dire aux autres qu’il ne maîtrise pas un sujet, qu’il ne sait pas tout, et ce, sans ressentir de honte. Car il estime qu’il est normal de ne pas tout savoir. </p>\n<p>Enfin, cette personne, ayant une grande foi en ses capacités, prend facilement des risques mesurés afin d’atteindre ses objectifs. Elle n’a donc pas peur du changement, car elle a conscience qu’elle doit obligatoirement passer par la nouveauté si elle souhaite évoluer. Elle s’adapte ainsi aisément aux milieux dans lesquels elle se trouve. </p>\n<h2>Qu’est-ce que l’estime de soi ? </h2>\n<p>Une personne ayant de l’estime pour elle ressent de l’amour pour elle. Elle accorde une grande importance aux valeurs intérieures plutôt qu’extérieures. Il n’est pas question ici d’avoir foi en ses compétences ou en ses capacités. Elle fait tout pour se respecter autant qu’elle respecte les autres. Elle ne se juge en effet pas inférieure à ses pairs et pense donc avoir les mêmes droits qu’eux. </p>\n<p>De ce fait, elle ne se laisse pas influencer si ses importants ne correspondent pas à ce qu’autrui attend d’elle, et ce, peu importe ce qu’il se dit sur elle. Cette personne a ainsi la même personnalité avec tout le monde, dans n’importe quel milieu. Elle reste <a href=\"/etre-authentique\" target=\"_blank\" rel=\"noopener\" title=\"être authentique\">authentique</a> et ne porte pas de masque. </p>\n<p>Et vu que la personne vit en accord avec ses valeurs, le regard des autres l’atteint bien moins, car elle reste stable émotionnellement. Par conséquent, elle tolère de commettre quelquefois des erreurs, et ce, sans craindre le quand dira-t-on. Elle peut donc demander de l’aide si elle en ressent le besoin, et ce, sans avoir peur de passer pour quelqu’un de faible. Elle n’a d’ailleurs pas de problème pour rire d’elle-même de temps en temps. Ce n’est pas une personne susceptible. </p>\n<p>Enfin, vu qu’elle se porte de l’amour, elle accepte facilement les compliments d’autrui, sans douter de leur sincérité et de leur véracité. Car étant donné qu’elle s’estime, elle se sent digne d’être estimée, à son tour, par autrui. </p>\n<p> </p>\n<h2>Les causes du manque de confiance et d’estime de soi </h2>\n<p>Comment expliquer que certaines personnes ont l’air de posséder ces capacités de manière innée, tandis que d’autres peinent à les acquérir ? Tout simplement, car nous n’avons pas tous été logés à la même enseigne.</p>\n<h3>Les parents </h3>\n<p>Les parents jouent un très grand rôle dans le développement de la confiance et de l’estime de l’enfant. Les surprotecteurs, par exemple, en effectuant tout à la place de leur bambin, même s’ils pensent bien faire, ne procèdent pas de la bonne manière. En agissant ainsi, ils insinuent à l’enfant qu’il demeure incapable d’effectuer la moindre tâche seul. Comment voulez-vous que ce petit apprenne à avoir confiance en lui dans ces conditions ? Certains parents peuvent également avoir des paroles blessantes à l’égard de leur enfant, comme : « tu n’y arriveras pas, laisse-moi faire ». </p>\n<p>Idem pour ceux qui ne montrent pas leurs sentiments à l’égard de leurs enfants. Ils peuvent donc se sentir mal aimés. Ils pensent alors qu’ils ne sont pas dignes d’amour. De ce fait, ils n’arrivent pas à développer de l’estime pour eux-mêmes. Voici deux exemples, mais il y en a des myriades d’autres.</p>\n<h3>Les professeurs </h3>\n<p> </p>\n<p>Il ne faut pas non plus oublier le milieu scolaire. Les professeurs jouent aussi un rôle très important. Certains d’entre eux peuvent avoir des comportements et des phrases extrêmement blessantes à l’égard d’un élève pouvant, par exemple, éprouver des difficultés. Et ces enseignants, au lieu de l’accompagner, peuvent le rabaisser, l’humilier et donc, écraser la confiance ou l’estime que l’écolier pourrait avoir pour lui-même.</p>\n<h3>L’effet de groupe </h3>\n<p>L’effet de groupe, tel que le harcèlement, qu’il soit scolaire ou autre, peut laisser de véritables traumatismes à l’enfant. Le sentiment d’être rejeté par un clan empiète clairement sur l’estime et la confiance en soi. Par exemple, pour un enfant, voir qu’il est toujours choisi en dernier dans une équipe en sport et en plus, par dépit, peut vraiment être difficile à vivre.   </p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"426\" src=\"/storage/blog-images/Amour-de-soi.jpg\" alt=\"S\'aimer\" title=\"Amour-de-soi\">\n<h2>Les conséquences d’un manque de confiance et d’estime de soi  </h2>\n<h3>Manque de confiance en soi </h3>\n<p>Un manque de confiance en soi se remarque surtout au niveau des capacités d’une personne. En effet, un individu manquant de confiance en ses aptitudes craint généralement le succès. Si, par exemple, un poste à prestige lui est proposé, il peut refuser cette offre. La peur qu’il ressent fait qu’il n’essaie même pas, étant donné que pour lui, il n’est pas apte à assumer ce poste. Il évitera alors bon nombre de situations de la sorte, ce qui, malheureusement, lui fera passer à côté de multiples opportunités. Ce sont donc bien souvent des personnes se contentant d’emplois à bas salaire, avec le moins de responsabilités possible. </p>\n<p>Et si tant est que l’individu accepte tout de même ce job, il ressentira un fort sentiment d<b>’</b>imposture. Il pensera duper les autres et piquer la place de quelqu’un qui mériterait plus ce poste que lui. Un grand manque de confiance en soi peut ainsi mener la personne à ne prendre aucun risque et à vivre dans une routine monotone, ne lui promettant aucunement une vie meilleure.</p>\n<h3>Manque d’estime de soi </h3>\n<p>Il existe plus de conséquences négatives au fait de manquer d’estime de soi, provenant bien souvent d’une peur du regard des autres. </p>\n<h4>Intolérance aux jugements des autres</h4>\n<p>Si une personne ne s’aime pas et qu’elle ne croit pas avoir de la valeur, elle va automatiquement rechercher de l’amour à l’extérieur et de fait, chez autrui. C’est une façon pour elle de se sentir importante. Et puisque l’amour des autres reste primordial pour elle, elle a donc du mal à tolérer la critique, laquelle est perçue comme un manque d’affection de leur part.</p>\n<p>Du coup, elle souhaite paraître parfaite aux yeux d’autrui. Et pour ce faire, elle se pense obligée de se justifier en permanence sur ses comportements, ses goûts ou ses choix dès lors qu’elle sent qu’une personne la juge négativement. Elle n’assume pas qui elle est vraiment. </p>\n<p>Par conséquent, cet individu est généralement un adepte du déni. C’est-à-dire qu’il nie souvent éprouver des difficultés et ne parle pas de ses problèmes à autrui. Tout simplement, car passer pour quelqu’un de faible ou de fragile reste inconcevable pour lui. </p>\n<p>Enfin, cette personne a la fâcheuse tendance à se comparer défavorable à autrui, ce qui a pour effet de faire baisser encore plus l’estime qu’elle se porte. Je vous laisse prendre connaissance de mon <a href=\"/se-comparer-aux-autres\" target=\"_blank\" rel=\"noopener\" title=\"Se comparer aux autres\">article</a> rédigé à cet égard. </p>\n<p>D’ailleurs, concernant la peur du jugement d’autrui. j’ai justement un programme à vous conseiller. Lequel a été créé par Didier PENISSARD, auteur et coach en développement personnel. N’hésitez pas à aller y jeter un oeil :</p>\n<h4>Opter pour des mécanismes de défense inadaptés </h4>\n<p>Le regard des autres pousse certains d’entre nous à choisir des mécanismes de défense très étranges, lesquels font se réaliser ce qu’ils ne souhaitent pourtant pas. Pour être plus claire, il s’agit, pour une personne, d’opter pour un comportement désagréable afin d’être sûre de ne pas être aimée par ses pairs. </p>\n<p>Mais pourquoi se comporte-t-elle ainsi alors que son souhait le plus cher reste d’être aimée ? Car elle reste persuadée que ses semblables ne l’apprécient pas. Du coup, pour éviter cette souffrance insoutenable, elle privilégie une conduite dont elle sait qu’elle attirera les foudres d’autrui. Ce faisant, elle se dit : « si les autres ne m’estiment pas, c’est parce que j’ai moi-même voulu qu’ils ne m’aiment pas ». Elle pense donc contrôler la situation. Elle agit en fait de la sorte afin de protéger son estime personnelle, du moins, le peu qu’il lui reste. </p>\n<p>Il y a également des personnes qui attirent les foudres des autres en voulant systématiquement avoir raison. En réalité, cette attitude représente aussi un mécanisme de défense dans le but de se rassurer. En se faisant croire demeurer supérieures à leurs pairs en pensant avoir la science infuse. </p>\n<h4>L’isolement et la dépendance </h4>\n<p>Enfin, il y existe deux comportements pouvant également être adoptés, paradoxaux, mais tout aussi inadaptés l’un que l’autre. En effet, certaines personnes se croient mal aimées de tout le monde et préfèrent rester seules le plus souvent possible. Car il n’y a qu’avec elles-mêmes qu’elles se sentent un minimum bien. En effet, le regard d’autrui leur apparaît insupportable, puisqu’il est, pour elles, toujours, négatif. </p>\n<p>Tandis que certaines personnes ne s’aimant pas cherchent l’amour d’autrui à tout prix. Elles peuvent, de ce fait, devenir fort dépendantes des autres, les coller et penser n’être rien sans eux. Une grande angoisse d’abandon résonne en elles. </p>\n<h4>L’impossibilité d’opter pour des plaisirs à long terme </h4>\n<p>Vu qu’une personne manquant d’estime pour elle se sent mal, elle cherche systématiquement à combler cet état par un plaisir immédiat. Elle n’a donc pas la capacité d’opter pour des plaisirs à long terme. Elle se jette sur la nourriture ou sur un verre d’alcool, par exemple, dès qu’elle ressent de la contrariété. </p>\n<p>Tout engagement à long terme comme, par exemple, arrêter de fumer, suivre des régimes, faire du sport, etc. apparaît impossible à honorer pour elle. Car, pour ce genre d’engagements, il faut rester patient<b>, </b>apprendre à tolérer la frustration et avoir confiance en des retombées positives, mais qui surviendront dans l’avenir. Il y a lieu d’avoir confiance en l’existence. </p>\n<p>Tandis qu’une personne ne marchant qu’aux plaisirs immédiats souhaite un résultat tout de suite. Dès qu’elle se sent frustrée, vu qu’elle n’a pas d’estime pour elle, elle se croit incapable de supporter cette frustration ressentie. Et vu qu’elle n’a pas foi en la vie et qu’elle voit l’avenir d’un œil sombre, elle ne compte pas sur cet avenir pour lui apporter du bien-être. Par précaution, elle préfère ressentir du plaisir tout de suite.</p>\n<h3>Conséquences valables pour les deux </h3>\n<p>Quand quelqu’un présente un manque d’estime ou de confiance, il est bien souvent frustré. Ce qui est normal, car, vu qu’il ne saisit aucune opportunité et n’ose pas aller de l’avant, il a tendance à se plaindre, sans passer à l’action pour remédier au problème. Il peut donc tomber dans le cercle vicieux de la victimisation. D’ailleurs, le fait d’être hypersensible au regard de l’autre le rend extrêmement susceptible. </p>\n<p>Cette personne demeure de plus constamment dans le passé, en se rappelant ses traumatismes ou, au contraire, en se disant que « c’était mieux avant ». Elle commet ainsi l’erreur de ne pas vivre dans le présent. Elle vit également souvent dans le futur, en s’imaginant ce qu’il pourrait arriver de négatif. Elle peut donc souffrir de troubles anxieux, étant donné qu’un individu angoissé vit principalement dans le futur. </p>\n<img decoding=\"async\" width=\"960\" height=\"540\" src=\"/storage/blog-images/Avoir-confiance-en-soi.jpg\" alt=\"Croire en soi \" title=\"Avoir-confiance-en-soi\">\n<h2>Comment améliorer la confiance et l’estime de soi ?</h2>\n<h3>Passer à l’action </h3>\n<p>Si vous ne vous sentez pas capable, c’est que vous n’avez pas assez expérimenté. Vous aimez vivre en sécurité, comme tout le monde. Cependant, la nouveauté provoque en vous un sentiment d’insécurité insoutenable. De ce fait, vous privilégiez la routine et le déjà-vu afin de vous protéger et continuer à vous sentir bien. </p>\n<p>Mais toutes vos habitudes viennent forcément de situations inédites à la base, et que vous avez adoptées et maîtrisées avec le temps. Donc, par exemple, si vous allez changer de travail, dites-vous bien que c’est tout à fait normal de ressentir de la peur, vu qu’il s’agit de l’inconnu. Mais ne pensez-vous pas que l’inconnu va devenir connu ? Lors des premiers mois à votre nouveau job, vous allez sans doute vous sentir assez déboussolé. Vous allez en effet devoir prouver votre valeur à autrui et faire vos marques. Mais au bout de 6 mois, tout sera devenu habituel et routinier. De ce fait, l’inconnu va devenir connu.</p>\n<p>Par conséquent, si vous souhaitez augmenter votre sentiment de confort, il va falloir expérimenter, très souvent, de nouvelles situations. Elles deviendront ensuite des habitudes. Ce faisant, vous augmenterez considérablement votre cercle de sécurité et sortirez donc de l’isolement et de la peur de prendre des risques. </p>\n<h3>S’intéresser au développement personnel </h3>\n<p>Afin d’augmenter votre confiance et votre estime de vous, il est primordial de changer les croyances que vous avez développées, au fil du temps, à votre égard. Pour vous y aider, vous pouvez réaliser ce petit exercice. Prenez un papier et un stylo et listez toutes vos réussites. Parmi vos plus grands succès, souvenez-vous des sensations que vous avez ressenties à ces moments-là. Rappelez-vous alors que vous êtes capable d’accomplir ce dont vous vous pensiez, auparavant, incapable. Cet exercice boostera votre confiance en vous. </p>\n<p>En effet, quand vous réussissez une étape que vous vous sentiez vraiment inapte à franchir à la base, vous allez ressentir une sensation très particulière. Vous vous sentirez si fier que votre confiance en vous va monter en flèche. Vous allez vous sentir pousser des ailes et vous aurez la force de soulever des montagnes. Vous ne vous reconnaîtrez plus !</p>\n<p>Enfin, je vous invite également à consulter mes articles sur le <a href=\"/lacher-prise-et-acceptation\" target=\"_blank\" rel=\"noopener\" title=\"Lâcher-prise et acceptation\">lâcher-prise et l’acceptation</a> ainsi que sur <a href=\"/affirmation-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Affirmation de soi\">l’affirmation de soi.</a> Ils pourront grandement vous aider dans votre quête de confiance et d’estime. </p>\n<h3>Pratiquer des techniques de relaxation</h3>\n<p>Pour aider, il existe également de nombreuses techniques de relaxation que vous pouvez pratiquer. La méditation peut être tentée, à condition de ne pas être trop anxieux. Car une personne trop anxieuse ne supporte pas de regarder trop intensément à l’intérieur d’elle. La tornade s’y trouve trop forte. La méditation peut donc, dans ces conditions, aggraver son cas. </p>\n<p>Vous pouvez ainsi déjà essayer des pratiques moins profondes, mais très efficaces, telles que la sophrologie ou des méthodes de respiration comme la cohérence cardiaque.</p>\n<p>D’ailleurs, si vous souhaitez pratiquer la cohérence cardiaque, je vous conseille, afin de vous y aider (car oui, bien respirer, cela s’apprend !), d’utiliser l’appareil ZENSPIRE, que j’utilise également. Celui-ci, élu produit de l’année 2020<strong>,</strong> grâce à sa vibration et à sa lumière, vous permet d’apprendre à respirer profondément afin d’atteindre la relaxation voulue.</p>\n<p>Pour découvrir ce produit, vous pouvez cliquer sur le bouton ci-dessous, étant précisé que si vous souhaitez passer commande, vous bénéficierez d’une remise de 10 % en utilisant le code JL0620. Bonne respiration !</p>\n<p>L’hypnose peut également vous aider à modifier vos croyances négatives, vu qu’elle agit sur l’inconscient. Cette technique utilise aussi souvent la visualisation. C’est-à-dire créer des images imaginaires vous apportant du bien-être.</p>\n<a href=\"https://hypnocaments.com?partnerid=YK5muYugzSoIWDbDWRgT-Q\" title=\"Seances d hypnose en ligne\"><img decoding=\"async\" src=\"https://hypnocaments.com/image/banner_1_750.png\" alt=\"seance hypnose mp3\"></a>\n<h3>Intégrer un groupe </h3>\n<p>Ce qui peut vraiment vous aider également, c’est le fait d’appartenir à un groupe. Si vous manquez d’estime de vous, envisager une thérapie de groupe reste un très bon exercice. Cette méthode vous aidera à témoigner devant autrui et à voir que vous n’êtes pas le seul à souffrir et que les autres ne vous jugent pas forcément négativement. Au contraire, vous vous sentirez épaulé et soutenu par vos pairs. </p>\n<p>Si vous manquez de confiance en vous, le théâtre peut également être un excellent exercice pour vous. Le fait de jouer un personnage vous permettra de ne pas prendre les choses personnellement. Et par la même occasion, vous apprendrez ainsi à vous affirmer, à vous exprimer devant bon nombre de personnes. Vous trouverez en vous des capacités que vous n’avez, jusqu’alors, pas soupçonné avoir. </p>\n<h3>Envisager l’aide d’un professionnel </h3>\n<p>Si vous en ressentez le besoin, n’hésitez pas à aller consulter un professionnel de la santé. Les TCC peuvent grandement vous aider à changer votre système de croyances, et à agir. Pourquoi pas également tenter une psychanalyse, laquelle vous permettra de comprendre l’origine de vos troubles.</p>\n<p>À vous maintenant de passer à l’action avec les moyens qui semblent le plus vous correspondre. <b>Confiance en soi et estime de soi : </b>vous n’avez pas idée à quel point ces concepts vont transformer votre vie ! </p>\n<p><a href=\"https://amzn.to/44C4TVA\">Visitez Amazon pour vous procurer le livre </a>de Christophe André « Imparfaits, libres et heureux : pratiques de l’estime de soi ».</p>\n<p>(Lien rémunéré par Amazon)</p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'Confiance en Soi et Estime de Soi : la Racine du Bien-être Profond','Confiance en soi et estime de soi restent incontestablement la racine du bien-être. Comment augmenter votre confiance et votre estime de vous ?','https://vivre-pleinement.fr/confiance-et-estime-de-soi/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/confiance-et-estime-de-soi\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/confiance-et-estime-de-soi\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Confiance en Soi et Estime de Soi\\u00a0: la Racine du Bien-\\u00eatre Profond\",\"datePublished\":\"2019-12-08T15:40:01+00:00\",\"dateModified\":\"2024-02-12T19:26:25+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/confiance-et-estime-de-soi\\/\"},\"wordCount\":5656,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/confiance-et-estime-de-soi\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/12\\/Confiance-estime.jpg\",\"articleSection\":[\"D\\u00e9veloppement personnel\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/confiance-et-estime-de-soi\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/confiance-et-estime-de-soi\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/confiance-et-estime-de-soi\\/\",\"name\":\"Confiance en Soi et Estime de Soi\\u00a0: la Racine du Bien-\\u00eatre Profond\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/confiance-et-estime-de-soi\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/confiance-et-estime-de-soi\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/12\\/Confiance-estime.jpg\",\"datePublished\":\"2019-12-08T15:40:01+00:00\",\"dateModified\":\"2024-02-12T19:26:25+00:00\",\"description\":\"Confiance en soi et estime de soi restent incontestablement la racine du bien-\\u00eatre. Comment augmenter votre confiance et votre estime de vous\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/confiance-et-estime-de-soi\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/confiance-et-estime-de-soi\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/confiance-et-estime-de-soi\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/12\\/Confiance-estime.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/12\\/Confiance-estime.jpg\",\"width\":500,\"height\":375,\"caption\":\"Comment augmenter la confiance en soi et l\\u2019estime de soi ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/confiance-et-estime-de-soi\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Confiance en Soi et Estime de Soi\\u00a0: la Racine du Bien-\\u00eatre Profond\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-12-08 15:40:01',NULL,'2026-05-24 19:19:45','2026-06-19 22:28:14');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (43,'Quels sont les 5 Accords Toltèques ? Explications de leurs Bienfaits','accords-tolteques','Avez-vous entendu parler des accords toltèques ? Ces accords étaient au nombre de 4, avant de monter depuis peu à 5. La personne qui les a mis en valeur est Don Miguel Ruiz, auteur des livres de développement personnel Les 4 accords toltèques et plus récemment, le cinquième accord toltèque. Ce matin, votre collègue n’apparaît pas très bavard et vous vous demandez ce que vous avez fait de mal. Vous aimez bien une personne, mais soudainement, un de vos proches la critique sur des aspects que vous n’aviez même pas remarqués. Sans vous en rendre compte, vous devenez de plus en plus exécrable envers elle. Vous avez échoué à un examen et vous pensez maintenant nul et sans valeur. De nombreuses situations vous gâchent la vie au quotidien ? Quels sont les 5 accords toltèques qui vous aideront à vous épanouir radicalement ?\n','<h2>Quels sont les 5 accords toltèques, en résumé ?</h2>\n<p>Avant d\'entrer dans le détail, voici les <b>5 accords toltèques</b> popularisés par Don Miguel Ruiz, ces règles de vie issues de la sagesse mexicaine ancestrale pour vous libérer des croyances qui vous font souffrir :</p>\n<ol>\n<li><b>Que votre parole soit impeccable</b> — parlez avec intégrité, ne dites que ce que vous pensez vraiment.</li>\n<li><b>Quoi qu\'il arrive, n\'en faites pas une affaire personnelle</b> — ce que les autres disent parle d\'eux, pas de vous.</li>\n<li><b>Ne faites aucune supposition</b> — osez poser des questions plutôt que d\'imaginer le pire et de <a href=\"/blog/ruminations\">ruminer</a>.</li>\n<li><b>Faites toujours de votre mieux</b> — un mieux qui change selon les jours, sans <a href=\"/blog/perfectionnisme\">perfectionnisme</a> ni culpabilité.</li>\n<li><b>Soyez sceptique, mais apprenez à écouter</b> — le cinquième accord : gardez votre discernement.</li>\n</ol>\n<p>Appliqués au quotidien, ces accords sont de véritables outils contre le <a href=\"/blog/jugement-des-autres\">jugement des autres</a> et l\'anxiété sociale. Voyons maintenant chacun d\'eux en détail, avec des exemples concrets.</p>\n<p>Avez-vous entendu parler des accords toltèques ? Ces accords étaient au nombre de 4, avant de monter depuis peu à 5. La personne qui les a mis en valeur est <b>Don Miguel Ruiz,</b> auteur des livres de développement personnel <b><i>Les 4 accords toltèques</i></b> et plus récemment, <b><i>le cinquième accord toltèque.</i></b> Ce matin, votre <b>collègue </b>n’apparaît pas très <b>bavard </b>et vous vous demandez ce que vous avez fait de <b>mal</b>. Vous <b>aimez </b>bien une personne, mais soudainement, un de vos proches la <b>critique </b>sur des aspects que vous n’aviez même pas <b>remarqués</b>. Sans vous en rendre compte, vous devenez de plus en plus <b>exécrable </b>envers elle. Vous avez échoué à un <b>examen </b>et vous pensez maintenant <b>nul </b>et sans valeur. De nombreuses situations vous <b>gâchent </b>la vie au quotidien ?<b> Quels sont les 5 accords toltèques</b> qui vous aideront à vous <b>épanouir </b>radicalement ?</p>\n<h2>Quels sont les 5 accords toltèques et à quoi servent-ils ? </h2>\n<h3>Chacun vit dans son propre rêve </h3>\n<p>Comme l’auteur l’indique dans son livre, nous naissons tous purs et sans <a href=\"/croyances\" target=\"_blank\" rel=\"noopener\" title=\"Croyances \">croyance</a> particulière. Cependant, du fait de notre éducation et de nos événements de vie, nous développons chacun une individualité. Avec ses goûts, ses forces, ses faiblesses et ses croyances propres. Certaines personnes possèdent des caractères similaires et dans ce cas, s’entendent souvent bien entre elles. Mais quelquefois, nous avons affaire à des personnalités diamétralement opposées à la nôtre. Et dans ce cas, nous avons tendance à montrer de l’intolérance, car nous ne comprenons pas qu’une personne puisse penser d’une manière totalement différente de la nôtre. </p>\n<p>Nous avons tous été conditionnés et avons une perception de l’existence en général. Mais, vu que tout être humain reste unique, absolument tout le monde a une vision de la vie différente de la nôtre. En effet, personne n’a eu exactement la même vie, les mêmes événements, etc. Et c’est à partir de là que les êtres humains se compliquent l’existence pour rien. Lorsqu’ils jugent les individus différents de lui. C’est-à-dire, tout le monde.</p>\n<h3>Vivre en harmonie avec autrui et avec soi</h3>\n<p>Vous admettrez bien que vous vous prenez tous les jours le chou pour des événements insignifiants, non ? Alors qu’ils pourraient clairement vous passer au-dessus de la tête si vous appliquez les accords toltèques, qui ne restent que du bon sens. Vous verrez cependant qu’il est très difficile de les mettre en application, du fait de vos conditionnements. Mais si vous pratiquez les accords toltèques dans votre vie régulièrement, vous vous déconditionnerez petit à petit de vos mécanismes de défense. Jusqu’à devenir une meilleure version de vous-même, beaucoup plus épanouie.</p>\n<p>Ne pensez-vous pas qu’il existe bien assez de problèmes dans l’existence pour s’en rajouter sans arrêt de nouveaux ? Examinons maintenant ces 5 accords.</p>\n<h2>Premier accord toltèque : que votre parole soit impeccable </h2>\n<p>« Parlez avec intégrité, ne dites que ce que vous pensez. N’utilisez pas la parole contre vous ni pour médire sur autrui ».</p>\n<h3>Explications </h3>\n<p>L’auteur tient ici à nous mettre en garde sur le poids que les mots peuvent avoir sur autrui et envers nous. Car lorsque nous disons « ce ne sont que des mots », ce n’est pas vrai. Vous savez, tout comme moi, que les mots peuvent blesser et peuvent ronger une personne, jusqu’à lui provoquer une rancune terrible à l’égard de quelqu’un. Un manque de confiance en elle général voire même, des maladies. Les mots possèdent ainsi une très grande force, faites très attention quand vous les utilisez. </p>\n<p>Vu que la parole a donc un fort pouvoir, il y a lieu de prendre soin de vous avec un discours intérieur vous valorisant et non l’inverse. De ce fait, vous améliorerez votre confiance en vous.</p>\n<p>Et là où la mise en application de cet accord risque d’être très difficile, c’est au niveau de la médisance. Car, qui ne médit pas ? La plupart des individus aiment d’ailleurs les commérages. Tant que ces <a href=\"/jugement-des-autres\" target=\"_blank\" rel=\"noopener\" title=\"Jugement des autres\">jugements</a> ne les touchent pas, bien entendu ! Nous médisons même sans nous en rendre compte. Essayez donc de ne plus médire.</p>\n<p>Mais vu que tout le monde critique tout le monde, vous risquez de vous sentir seul, quelquefois, en ne rentrant pas dans le jeu des critiques. Certaines personnes pourront en effet se désintéresser de vous, car vous n’aurez pas de commérage à raconter. Certains pourront même vous envier, du fait qu’ils n’arrivent pas eux-mêmes à cesser de critiquer. Mais ne vous laissez pas abattre, continuez sur ce chemin et donnez l’exemple. Vous contribuerez ainsi à un monde meilleur, puisque les autres feront, à force, comme vous.</p>\n<h3>Cas concrets </h3>\n<p>Attention : quand l’auteur indique qu’il convient de dire ce que l’on pense, il ne veut pas dire qu’il faut absolument tout exprimer. Par exemple, si vous pensez que Nicole est une abrutie, pas besoin de le verbaliser. Ce jugement ne ferait que la blesser et n’est pas forcément vrai. Par contre, si vous souhaitez émettre une critique constructive à quelqu’un, vous pouvez le faire sans hésiter. Cependant, attention à trouver les bons mots. </p>\n<p>Par exemple, si votre ami Paul apparaît trop jaloux avec sa compagne, vous pouvez lui dire ce genre de phrase. « Paul, je pense que quelquefois, ta jalousie va un peu trop loin et qu’elle nuit au bonheur de ta partenaire. Voudrais-tu en parler ? Nous pouvons même te prendre un rendez-vous avec un thérapeute, si tu veux ».</p>\n<p>Concernant notre discours intérieur, il est bien souvent dû à des phrases blessantes que nous avons entendues dans le passé. L’auteur prend l’exemple, dans son livre, d’une petite fille qui adorait chanter. Sa mère, en rentrant du travail, de mauvaise humeur et fatiguée, s’est énervée. Elle lui a dit « arrête de chanter avec ta voix de crécelle » ! Depuis, l’enfant, devenue adulte, n’a plus jamais chanté, persuadée d’avoir « une voix de crécelle ». Ce qui est malheureux, c’est que sa maman ne le pensait même pas. Elle était juste fatiguée. Mais n’a pas pris conscience du poids de ses mots. </p>\n<p>Concernant la médisance, voici un petit exercice que vous pouvez appliquer. Dès que vous sentez que vous avez envie de juger une personne, remplacez tout de suite ladite critique par un bon côté de sa personnalité. Votre colère à son égard va s’apaiser.</p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"426\" src=\"/storage/blog-images/Don-Miguel-Ruiz.jpg\" alt=\"Les 4 accords tolteques \" title=\"Don-Miguel-Ruiz\">\n<h2>Deuxième accord toltèque : quoi qu’il arrive, n’en faites jamais une affaire personnelle </h2>\n<p>« Ce que les autres disent et font n’est qu’une projection de leur propre réalité. Lorsque vous êtes immunisé contre cela, vous n’êtes plus victime de souffrances inutiles ».</p>\n<h3>Explications </h3>\n<p>Chaque individu a sa propre perception du monde, sa vérité. Et tout le monde pense connaître la vérité absolue, alors qu’aucune vérité ne l’est. Chacun a donc du mal avec le fait qu’une autre personne puisse penser différemment. Par conséquent, nous faire critiquer par autrui nous fait prendre les choses personnellement. Cet accord nous sert de ce fait à passer outre la critique, afin qu’elle n’ait pas de conséquences négatives sur nous. </p>\n<p>L’idée est alors de se dire que quand une personne vous juge sur un de vos comportements, c’est son opinion à elle. Son avis reste le sien. Vous n’êtes d’ailleurs pas forcément comme elle le prétend. Il faut ainsi laisser l’individu avec sa pensée, laquelle lui appartient et ne vous concerne pas. Prenez donc de la distance avec le jugement d’autrui, comme s’il n’avait rien à voir avec vous. </p>\n<p>Après, si une critique vous apparaît constructive, rien ne vous empêche, bien évidemment, d’en tenir compte.</p>\n<p>Et pour vous aider à dépasser la critique, je vous recommande le programme de Didier PENISSARD, coach, conférencier et auteur dans le développement personnel. Si cela vous intéresse, n’hésitez pas à cliquer sur le bouton ci-dessous :</p>\n<h3>Cas concrets</h3>\n<p>Imaginons que vous apprenez, par un de vos collègues, qu’une collègue a dit de vous que vous étiez quelqu’un d’égoïste. Bon… et vous, pensez-vous que vous l’êtes également ? Si tel est le cas, vous pouvez peut-être le voir cette critique comme constructive et travailler sur ce défaut. Mais si vous lui donnez un coup de main dès qu’elle a trop de travail, devez-vous prendre à cœur cette remarque ? </p>\n<p>Et d’ailleurs, si dans votre vie en général, vous ne vous trouvez pas égoïste, pourquoi vous vexer avec ce jugement ? C’est juste ce que pense votre collègue, laquelle détient sa propre vérité. Ce n’est en aucun cas LA vérité. Vous n’êtes pas ainsi et pouvez tourner la page. </p>\n<p>Et puis, dites-vous que vous pouvez être quelquefois égocentrique. Tout le monde l’est de temps en temps. Même si certains vous disent ne jamais l’être. Et parfois, vous faites aussi preuve d’une grande générosité. Vous êtes en effet bien plus complexe que vous ne le pensez : vous possédez des milliers de comportements et de facettes différents en vous. Ne vous laissez donc pas définir par une personne, ne vous attardez pas sur le regard des autres ! </p>\n<h2>Troisième accord toltèque : ne faites aucune supposition</h2>\n<p>« Ayez le courage de poser des questions et d’exprimer vos vrais désirs. Communiquez clairement avec les autres pour éviter tristesse, malentendus et drames ».</p>\n<h3>Explications </h3>\n<p>C’est vraiment une habitude que nous avons tous tendance à avoir et qui génère une grande source de stress et de souffrance. Pourtant, cette manie de supposer peut être si facilement changée !</p>\n<p>Deux situations peuvent se présenter. La première apparaît quand vous utilisez le mécanisme de projection. C’est-à-dire que quelquefois, vous êtes de telle humeur, mais ne le remarquez même pas. Et vous allez projeter directement votre état d’esprit sur l’autre, en vous faisant croire que ladite humeur vient de lui. </p>\n<p>La deuxième situation intervient lorsque vous interprétez une phrase ou un comportement qu’une personne a eu envers vous de manière négative. Cependant, au lieu de jouer cartes sur table avec la personne, vous préférez ne rien dire, ruminer dans votre coin, continuer à vous faire des films. Donc généralement, la relation avec ladite personne en prendra un coup, du fait de nombreux non-dits de part et d’autre. </p>\n<p>Cette situation demeure extrêmement fréquente, car l’être humain a beaucoup de mal avec la confrontation. Pourtant, la communication reste primordiale pour éviter ce genre de contexte. Elle reste le seul moyen de constater que bien souvent, vos suppositions apparaissaient infondées et que vous vous êtes fait des films pour rien. Et si vraiment vous avez correctement supposé, vous pourrez au moins clarifier la situation avec la personne concernée et faire la paix. En vous <a href=\"/affirmation-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Affirmation de soi\">affirmant</a> ainsi, vous verrez que vous serez très respecté.</p>\n<h3>Cas concrets</h3>\n<p>Vous vous réveillez aigri. Au travail, vous trouvez que votre patron est aigri et de plus, il vous a à peine dit bonjour. Mais quelle mouche l’a piqué et qu’a-t-il contre vous ? Vraiment, vous ne supportez pas les gens aigris ! Vous allez donc ressasser dans votre coin, en pensant que votre chef vous a mis de mauvaise humeur, alors que vous l’étiez dès le départ. Vous avez projeté votre état d’esprit maussade sur lui.</p>\n<p>Votre belle-mère vous a fait une réflexion sur votre façon de vivre. Elle a, d’après vous, insinué que vous étiez casanier. Et ce tempérament, pour elle, n’est pas bien vu. Au lieu de ruminer et de maudire votre belle-maman, pourquoi ne pas lui faire part de ce que vous avez compris ? Et que ses propos vous ont blessé ? Vous verrez qu’elle n’a peut-être pas du tout eu l’intention de vous faire du mal, qu’elle plaisantait et que votre personnalité ne la dérange pas. En désamorçant directement le conflit en parlant calmement, la situation ne s’aggravera pas et vous l’oublierez. Vous éviterez ainsi de tomber dans la rancœur, laquelle pouvant déclencher, à la longue, des maladies.</p>\n<img decoding=\"async\" width=\"640\" height=\"412\" src=\"/storage/blog-images/Domestication.jpg\" alt=\"Le cinquieme accord tolteque \" title=\"Domestication\">\n<h2>Quatrième accord toltèque : faites toujours de votre mieux</h2>\n<p> « Votre mieux change d’instant en instant. Quelles que soient les circonstances, faites simplement de votre mieux et vous éviterez de vous juger ».</p>\n<h3>Explications </h3>\n<p>Notre humeur est un peu comme la météo. Un jour, il pleut à torrents, un autre jour il fait merveilleusement beau… Bref, nos humeurs peuvent changer et fluctuer très rapidement. Et de ce fait, notre vitalité également.</p>\n<p>Il y a bien sûr les événements de la vie, positifs et négatifs, qui peuvent impacter la santé mentale et physique de l’individu. Mais il y a aussi des jours où, vous ne savez pas pourquoi, en vous levant, ça ne va pas. Vous vous sentez fatigué, énervé, angoissé… alors que pourtant, vous avez bien dormi et que la veille, vous vous sentiez vraiment en forme. </p>\n<p>Cet accord convient bien aux <a href=\"/perfectionnisme\" target=\"_blank\" rel=\"noopener\" title=\"Perfectionnisme\">perfectionnistes</a>, qui se donnent à 100 % constamment, et ce, quel que soit leur état. Cependant, en agissant ainsi, ils risquent tout simplement de trop tirer sur la corde, jusqu’au jour où leur corps ne répondra plus. </p>\n<p>Par contre, ne pas agir du tout par paresse n’est pas mieux. Car vu que nous ne faisons pas de notre mieux, nous regretterons le fait de ne pas avoir assez agi. Nous nous jugerons.</p>\n<p>Il y a donc lieu de trouver un juste milieu, et ce, en tenant compte de votre état de santé du moment. Il faut donner le meilleur de vous en chaque circonstance, mais en vous rappelant que votre niveau de mieux d’aujourd’hui sera peut-être 50 % moins élevé que le mieux d’hier. Le tout est ainsi d’agir de manière équilibrée, sans paresse et sans trop tirer sur la corde.</p>\n<h3>Cas concrets</h3>\n<p>Vous vous levez avec une gastro. Vous devez aller au travail et comptez travailler aussi intensément que la veille, où vous vous sentiez en pleine forme. Croyez-vous vraiment que vous serez productif comme la veille, votre journée dans les toilettes au travail ? Dans ce cas précis, il y a lieu de ne pas tirer sur la corde. Il serait plutôt judicieux de choisir d’appeler votre travail pour lui faire part de votre absence aujourd’hui. Vous pourrez ainsi vous reposer et récupérer.</p>\n<p>Vous désirez vraiment trouver un job, mais n’avez pas envie de chercher. De ce fait, vous passez vos journées devant la télévision, en pleine déprime en vous plaignant de votre sort. Dans ce cas contraire, vous n’en faites clairement pas assez et le travail ne viendra pas sonner à votre porte. Il y a donc lieu de sortir de votre paresse et de prendre plusieurs heures par jour à la recherche effective d’un emploi.</p>\n<p>Vous vous levez avec de grands troubles anxieux et une grande fatigue, et ce, sans raison apparente. Vous appréhendez fortement votre journée de travail qui s’annonce alors que la veille, tout allait bien. Dans ce cas, il va falloir y aller mollo, aujourd’hui, au travail. Dites-vous bien que vous ne serez peut-être pas aussi productif que la veille et que ce n’est pas grave. Il y aura des jours meilleurs. Vous appliquez donc, dans ce cas, l’équilibre. </p>\n<h2>Cinquième accord toltèque : soyez sceptique, mais apprenez à écouter </h2>\n<p>« Ne vous croyez pas vous-même, ni personne d’autre. Utilisez la force du doute pour remettre en question tout ce que vous entendez : est-ce vraiment la vérité ? Écoutez l’intention qui sous-tend les mots et vous comprendrez le véritable message ».</p>\n<h3>Explications </h3>\n<p>Quand vous vous dénigrez, vous n’êtes pas obligé de vous croire. Car ce n’est bien souvent pas la vérité. C’est seulement votre réalité, provenant de croyances négatives dues à votre éducation et aux phrases qu’autrui a pu prononcer à votre égard. Mais peut-être qu’il existe d’autres vérités, à savoir, que d’autres personnes vous trouvent exceptionnel ? </p>\n<p>Ensuite, cet accord souhaite surtout travailler sur l’effet de masse en société. Il vous aide à rester vous-même, en ayant vos propres opinions, et ce, sans laisser votre authenticité se faire neutraliser par la norme sociale. En effet, même si un groupe pense possède un préjugé sur telle personne, ne le suivez pas automatiquement. Apprenez d’abord à connaître cette personne sans préjugés et vous verrez si ce qui est dit sur elle est bien la vérité.</p>\n<p>Il est effectivement important de vous faire votre propre opinion. Car bien souvent, l’effet de groupe reste une solution de facilité. Les individus s’en prennent à un bouc émissaire afin qu’eux-mêmes ne deviennent pas la cible d’attaques. Ils ne connaissent même pas la personne, mais qu’importe, ils pensent comme la bande. Leur comportement leur donne un sentiment de sécurité. Cet effet de masse se retrouve dans bon nombre de domaines. Professionnel, scolaire… Il n’y a d’ailleurs qu’à observer la cruauté dont de jeunes élèves peuvent faire preuve à l’égard de leur « proie ».</p>\n<h3>Cas concrets</h3>\n<p>Vous vous trouvez très bête, car vous avez commis une erreur dans un dossier au travail. Vous perdez donc votre confiance en vous. Pourtant, vous détenez un BAC + 8 et un job prestigieux. Vous êtes admiré par vos collègues. Pensez-vous que vous êtes vraiment stupide ? </p>\n<p>Il y a un nouvel employé dans votre service. Tous vos camarades vous mettent en garde. Il est bizarre. Il ne parle pas, apparaît antisocial, pas sympathique. Vous allez faire connaissance avec lui et surprise ! Vous le trouvez, de votre côté, extrêmement gentil. Il n’est juste pas trop à l’aise en société et fait preuve de timidité. Mais une fois en confiance, il a beaucoup de discussion. Il est très intelligent et sera, vous le savez, quelqu’un sur qui vous pourrez compter. Bravo ! Vous n’avez pas suivi la masse et gardez ainsi votre liberté personnelle !</p>\n<p> </p>\n<p><b>Quels sont les 5 accords toltèques</b> et comment peuvent-ils vous faire évoluer dans la vie ? Je pense que vous l’avez compris avec cet article. Grâce à eux, vous allez vraiment gagner en intelligence émotionnelle, calmer votre mental, votre ego et connaître la paix intérieure. Ce n’est que du bon sens, mais vous verrez qu’il est très difficile de les mettre en œuvre. Cependant, avec de l’entraînement, vous y arriverez. </p>\n<p><a href=\"https://amzn.to/42wAW7t\">Visitez Amazon pour vous procurer le livre</a> de Don Miguel Ruiz « Les quatre accords toltèques : la voie de la liberté personnelle ».</p>\n<p>(Lien rémunéré par Amazon)</p>\n<p><a href=\"https://amzn.to/41dPfNi\">Visitez Amazon pour vous procurer le livre</a> de Don Miguel Ruiz « Le 5e accord toltèque : la voie de la maîtrise de soi ».</p>\n<p>(Lien rémunéré par Amazon)</p>\n<p>(Si mon travail vous aide 🙂)</p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img loading=\"lazy\" decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n','published',1,'Les 5 Accords Toltèques : Résumé et Comment les Appliquer','Quels sont les 5 accords toltèques de Don Miguel Ruiz ? Résumé clair de chaque accord et conseils concrets pour les appliquer au quotidien et vivre plus librement.','https://vivre-pleinement.fr/accords-tolteques/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/accords-tolteques\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/accords-tolteques\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Quels sont les 5\\u00a0Accords Tolt\\u00e8ques\\u2009? Explications de leurs Bienfaits\",\"datePublished\":\"2019-11-26T20:50:52+00:00\",\"dateModified\":\"2024-02-13T17:19:35+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/accords-tolteques\\/\"},\"wordCount\":5508,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/accords-tolteques\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/11\\/5-accords-tolteques.jpg\",\"articleSection\":[\"D\\u00e9veloppement personnel\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/accords-tolteques\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/accords-tolteques\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/accords-tolteques\\/\",\"name\":\"Quels sont les 5\\u00a0Accords Tolt\\u00e8ques\\u2009? Explications de leurs Bienfaits\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/accords-tolteques\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/accords-tolteques\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/11\\/5-accords-tolteques.jpg\",\"datePublished\":\"2019-11-26T20:50:52+00:00\",\"dateModified\":\"2024-02-13T17:19:35+00:00\",\"description\":\"De nombreuses situations vous g\\u00e2chent la vie au quotidien\\u2009? Quels sont les 5 accords tolt\\u00e8ques qui vous aideront \\u00e0 vous \\u00e9panouir radicalement\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/accords-tolteques\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/accords-tolteques\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/accords-tolteques\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/11\\/5-accords-tolteques.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/11\\/5-accords-tolteques.jpg\",\"width\":500,\"height\":333,\"caption\":\"Quels sont les 5 accords tolteques et a quoi servent-ils ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/accords-tolteques\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Quels sont les 5\\u00a0Accords Tolt\\u00e8ques\\u2009? Explications de leurs Bienfaits\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-11-26 20:50:52',NULL,'2026-05-24 19:19:45','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (44,'Vaincre le Perfectionnisme pour Acquérir le Bien-être','perfectionnisme','Vous êtes un insatisfait chronique voulant tout contrôler ? Vous êtes peut-être un perfectionniste. Le perfectionnisme est un tempérament que la personne acquiert petit à petit pour diverses raisons. Bien souvent, le perfectionniste aura été élevé par des parents qui le sont eux-mêmes. Nous pouvons comparer ce trait de caractère avec la personnalité du type 1 de l’ennéagramme. Il ne faut cependant pas confondre ce tempérament avec la personnalité obsessionnelle compulsive, faisant partie des troubles de la personnalité. Au travail, vous ne supportez pas vos collègues qui ne sont pas rigoureux. Quand vous faites le ménage chez vous, vous vous sentez constamment frustré, car vous avez l’impression qu’il reste toujours des éléments à nettoyer. Vous organisez parfaitement votre emploi du temps et vous prenez très mal le moindre imprévu. Votre caractère vous met des bâtons dans les roues ? Comment vaincre le perfectionnisme ? \n','<p>Vous êtes un<b> insatisfait</b> chronique voulant tout contrôler ? Vous êtes peut-être un perfectionniste. Le perfectionnisme est un <b>tempérament </b>que la personne acquiert petit à petit pour diverses raisons. Bien souvent, le perfectionniste aura été élevé par des <b>parents </b>qui le sont eux-mêmes. Nous pouvons comparer ce trait de caractère avec la personnalité du <b>type 1 de l’ennéagramme.</b> Il ne faut cependant pas confondre ce tempérament avec la <b>personnalité obsessionnelle compulsive,</b> faisant partie des <b>troubles de la personnalité.</b> Au <b>travail</b>, vous ne supportez pas vos <b>collègues </b>qui ne sont pas <b>rigoureux</b>. Quand vous faites le <b>ménage </b>chez vous, vous vous sentez constamment <b>frustré, </b>car vous avez l’impression qu’il reste toujours des éléments à <b>nettoyer</b>. Vous organisez parfaitement votre <b>emploi du temps </b>et vous prenez très mal le moindre <b>imprévu</b>. Votre caractère vous met des bâtons dans les roues ? Comment <b>vaincre le perfectionnisme </b>? </p>\n<h2>Qu’est-ce que le perfectionnisme ?</h2>\n<p>Les perfectionnistes ne sont jamais satisfaits, étant donné qu’ils visent la perfection et qu’elle n’existe pas. Leur insatisfaction chronique entraîne donc de la frustration. Ils n’apparaissent jamais véritablement heureux. </p>\n<p>Le perfectionnisme peut s’étendre à tous les domaines, mais aussi à un seul domaine en particulier. Tout dépend de l’individu et de son parcours de vie.</p>\n<p>Ces personnes utilisent fréquemment les termes « il faut, je dois », etc., car elles agissent principalement par devoir. Elles ne se laissent jamais aller. Elles ont ainsi forcément constamment de nouvelles tâches à accomplir, puisque l’on peut toujours en trouver d’autres avant de pouvoir vaquer à des activités distrayantes et se reposer. Repos qui n’arrive donc, bien souvent, jamais. </p>\n<p>Elles sont également adeptes du « tout ou rien » et du « tout est noir ou blanc ». Pas de nuance de gris possible. Par exemple, si une personne débute un régime et craque pour manger un paquet de bonbons, elle culpabilisera beaucoup par ce manque de contrôle. Elle pensera avoir raté complètement sa diète, alors qu’il peut ne s’agir que d’une petite faiblesse temporaire, car nous restons humains, après tout. Cependant, l’erreur se trouve intolérable pour elle.</p>\n<p>Enfin, ces individus sont en général de bons épargnants. Ils ne dépensent pas énormément, car « on ne sait jamais ce qui peut arriver ». Ils restent très prudents. </p>\n<h2>La recherche de perfection au travail </h2>\n<p>Là où le perfectionnisme se manifeste fréquemment, c’est dans le monde du travail. En effet, le perfectionniste désirant la perfection, il pense ainsi avoir de la valeur dans la performance, laquelle reste mesurable. </p>\n<p>Il choisira souvent un job en fonction du prestige social qu’il pourra lui apporter, ce qui lui donnera l’illusion de perfection. Le métier ne sera donc pas vraiment choisi par passion, laquelle n’est pas toujours assez parfaite pour eux et surtout, aux yeux de la société. </p>\n<p>Le travail peut devenir son principal moteur. De ce fait, il peut devenir fortement dépendant de son emploi, en travaillant sans cesse. Se détendre devient impensable pour lui et il sera hors de question qu’il perde son temps à avoir des loisirs ou même, à partir en vacances. Cette attitude pourra provoquer, à la longue et dans certains cas, un <a href=\"/burn-out\" target=\"_blank\" rel=\"noopener\" title=\"Burn-out\">burn-out.</a></p>\n<p>Enfin, comme le perfectionniste aime que tout soit parfait, il éprouvera une peur panique de commettre des erreurs. Cette idée reste vraiment inconcevable pour lui. Par conséquent, chaque tâche à entreprendre peut lui sembler énorme. Car étant donné qu’elle doit être réalisée à la perfection, le perfectionniste peut procrastiner. Il peut reporter la tâche, et ce, afin d’être sûr de trouver le bon moment pour pouvoir la réaliser parfaitement. Certains, mais pas tous, peuvent même souffrir de lenteur obsessionnelle lorsqu’ils réalisent la moindre tâche, du fait de leur besoin de perfection. </p>\n<h2>Le perfectionnisme et les relations sociales </h2>\n<p>Lorsqu’une personne apparaît trop perfectionniste, les relations sociales peuvent s’avérer très compliquées. </p>\n<p>En effet, cet individu est très entêté, aimant contredire et voulant toujours avoir raison. Ce qui peut, à la longue, agacer son entourage.</p>\n<p>Ledit entourage ne peut d’ailleurs lui lancer la moindre critique, même constructive. Le perfectionniste reste effectivement très sensible au jugement et se mettra donc facilement sur la défensive. Il peut avoir des tendances agressives et apparaîtra très souvent <a href=\"/rancune-et-rancoeur\" target=\"_blank\" rel=\"noopener\" title=\"Rancune et rancoeur \">rancunier</a>. Cependant, la rancune est un sentiment dévastateur, pouvant lui faire ressentir du plaisir à voir certaines personnes échouer.</p>\n<p>D’ailleurs, si vous êtes très sensible au regard des autres, je vous suggère de suivre le programme de Didier PENISSARD, coach et auteur dans le domaine du développement personnel. Si cela vous intéresse, n’hésitez pas à jeter un oeil à son programme en cliquant sur le bouton ci-dessous :</p>\n<p>Le perfectionnisme a aussi la fâcheuse manie à penser être le seul à correctement réaliser les tâches, domestiques comme professionnelles. Il refusera donc fréquemment que quelqu’un d’autre effectue les tâches à sa place, quitte à être débordé. Les autres n’approuvent pas vraiment qu’il puisse les juger ainsi et peuvent se sentir clairement rabaissés par lui. </p>\n<p>D’ailleurs, c’est bien souvent ce que le perfectionniste pensera. Que les gens sont médiocres. Il aura alors tendance à s’isoler et à trop se méfier de ses pairs, qu’il ne pense, de toute façon, pas à sa hauteur.  </p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"640\" src=\"/storage/blog-images/Parfait.jpg\" alt=\"Controle \" title=\"Parfait\">\n<h2>Les avantages du perfectionnisme </h2>\n<p>Être perfectionniste comporte bien évidemment de bons côtés. On peut se fier à ce genre d’individu. Il respecte constamment ses engagements et ne vous laissera jamais tomber. Ce sera généralement un très bon ami, sur qui vous pourrez toujours compter. D’ailleurs, si vous vous donnez rendez-vous à 14 heures dans 7 jours environ, pas besoin de le lui rappeler, il viendra le jour indiqué et pile à l’heure. Pas de retard ou de faux-bond possible avec lui.</p>\n<p>De plus, du fait de son besoin de contrôle, ce sera un individu extrêmement responsable. Il aime prendre sa vie en main en passant à l’action. Il sera loin de demeurer passif et ira au front. On ne s’ennuie pas avec lui. Il est toujours en activité en vue de réaliser sans cesse des actions constructives sans jamais perdre de temps inutilement. </p>\n<p>Il faut également souligner la persévérance dont le perfectionniste fait preuve quand il entreprend une activité. En général, il mettra le paquet pour accomplir son but et ne lâchera rien. C’est un passionné. </p>\n<p>Cependant, quand cette personnalité prend beaucoup trop de place, les inconvénients prennent malheureusement le dessus. En effet, bien qu’il soit honorable de faire preuve de rigueur, de fiabilité et de détermination, vouloir trop atteindre la perfection se solde forcément par un échec. Car la perfection n’existe pas.</p>\n<h2>Les inconvénients de la recherche de perfection </h2>\n<h3>Un grand manque d’estime et de confiance en soi </h3>\n<p>Le gros problème avec les perfectionnistes, c’est qu’ils ne reconnaissent jamais le chemin qu’ils ont déjà parcouru. Ce qu’ils ont accompli de bien passe à la trappe, car ils préfèrent se concentrer sur les maladresses qu’ils ont pu commettre. Ils se le reprochent sans cesse, étant donné que pour eux, l’erreur demeure inacceptable, puisqu’elle représente tout le contraire de la perfection. </p>\n<p>Et ne parlons même pas de l’échec, qui n’est absolument pas envisageable pour eux. En effet, d’après eux, l’échec veut dire qu’ils ne sont pas de bonnes personnes, qu’ils ne sont pas assez bien. </p>\n<p>Cependant, tout le monde commettra des erreurs dans sa vie ou subira des échecs. Mais ce fait reste clairement plus intolérable pour un perfectionniste que pour une personne plus souple. Il pensera manquer de ressources et ne pas être assez compétent. De là pourra s’installer un grand manque de confiance et d’estime de lui. Et on sait bien que l’insuffisance de confiance et d’estime reste la racine de tout trouble. Il se sent coupable d’être si mauvais d’après lui et une grande honte le ronge. </p>\n<h3>De l’anxiété et de la dépression </h3>\n<p>L’individu pourra quelquefois développer des troubles anxieux. En effet, le perfectionniste adore la routine et avoir un agenda bien planifié. Il déteste les imprévus. De ce fait, il peut se sentir déstabilisé si son planning change et peut fortement s’agacer. Et si le besoin de routine demeure vraiment trop fort, il pourra éprouver de fortes difficultés pour s’adapter à la nouveauté, ce qui pourra faire apparaître des phases dépressives. </p>\n<p>Une dépression peut s’installer s’il ne se concentre que sur ce qui lui manque au lieu de se concentrer sur ce qu’il a construit jusqu’à maintenant. Comme se plaindre de posséder une moins belle voiture que le voisin alors qu’il a une famille adorable, une jolie maison, etc. </p>\n<p>Le perfectionniste reste un contrôlant. S’il souhaite tout diriger, c’est juste pour se protéger. L’impression de contrôle lui donne l’illusion qu’il peut maîtriser tous les événements de sa vie. C’est un sentiment de peur et d<b>’</b>insécurité qui le pousse à contrôler. Et quand cette peur est vraiment trop intense, elle peut se manifester sous forme de TOCS.</p>\n<p>Le fait de vouloir avoir le pouvoir sur tout et d’apparaître irréprochable l’incite quelquefois à désirer un corps parfait. Il est d’ailleurs adepte des régimes stricts, au vu des consignes rigoureuses à respecter. Mais malheureusement, certaines personnes fonctionnant ainsi peuvent basculer dans des troubles alimentaires tels que l’anorexie, la boulimie, etc.</p>\n<p>Bien évidemment, l’anxiété et la dépression sont souvent accompagnées d’insomnies. Ce qui sera loin de rassurer le perfectionniste, qui s’énervera tout seul dans son lit à ressasser les conséquences d’un éventuel manque de sommeil. Même si peur et colère ne l’aideront pas à tomber dans les bras de Morphée…</p>\n<h3>Une retenue émotionnelle </h3>\n<p>Le perfectionniste, comme son nom l’indique, souhaite être parfait. Et pour lui, exprimer ses sentiments ne rime pas avec perfection. Il laisse cette attitude aux gens fragiles ou mal élevés. Mais le perfectionniste le sait très bien : il ressent, lui aussi, des émotions. Même s’il fait tout pour ne pas les ressentir. Il fait donc tout pour les cacher, ce qui peut lui valoir une apparence très froide et peu chaleureuse. Les individus ont d’ailleurs en général du mal à aller vers lui. </p>\n<p>Il ne parlera ainsi pas de ses problèmes à autrui, car en parler montrerait à son entourage qu’il est imparfait, et c’est intolérable pour lui. </p>\n<h3>Une fragilité </h3>\n<p>La retenue émotionnelle du perfectionniste représente un masque censé le protéger. Derrière s’y cache une grande sensibilité. Il prend d’ailleurs à cœur tous les aléas de l’existence, ce qui peut alors le rendre moins résistant et plus fragile que les autres. Mais attention, fragilité ne veut pas dire faiblesse. </p>\n<p>Le perfectionnisme comporte donc de nombreux inconvénients, pouvant faire beaucoup de torts. Mais il ne faut cependant pas jeter la pierre à ce caractère. Car bien maîtrisé, il peut devenir un véritable atout. Pour ce faire, je vais vous donner des solutions afin de vous permettre de mieux le maîtriser. D’autant plus qu’en baissant votre perfectionnisme maladif, vous verrez que d’autres troubles que vous pouvez éventuellement avoir concomitamment s’atténueront, voire, disparaîtront. </p>\n<img decoding=\"async\" width=\"640\" height=\"426\" src=\"/storage/blog-images/Perfection.jpg\" alt=\"Maitrise \" title=\"Perfection\">\n<h2>Comment vaincre le perfectionnisme ?</h2>\n<h3>Accepter l’erreur et l’échec  </h3>\n<p>Pour faire baisser le perfectionnisme, il faut déjà réussir à ne plus diaboliser l’erreur ou l’échec. Car de toute façon, tout le monde commet des impairs et subira des échecs dans son existence. Ceux qui ne subissent rien sont des personnes passives, se contentant d’être spectatrices de leur vie. Elles ne prennent aucun risque et ne passent pas à l’action. Forcément, comment pourraient-elles commettre des maladresses ?  </p>\n<p>Donc, en sachant que l’erreur est humaine et obligatoire, de même que l’échec, le perfectionniste doit maintenant revoir la notion d’échec et d’erreur. Par exemple, au travail, n’avez-vous pas remarqué que si votre patron ou un collègue souligne que vous avez commis une faute, il y a de grandes probabilités que vous ne la commettiez plus ? Tandis que si personne ne vous dit rien, il y a également de fortes chances pour que vous continuiez à la commettre. L’erreur vous permet ainsi d’évoluer.</p>\n<p>Il en est de même pour l’échec. Si un projet tombe à l’eau, par exemple, vous pourrez analyser la situation afin de comprendre ce qui clochait. Vous pourrez alors apprendre de cet échec pour grandir. </p>\n<p>Donc, au lieu de vous croire stupide et mauvais, ressentez plutôt de la gratitude envers vos échecs et vos erreurs. Car ils restent le meilleur moyen pour vous de progresser dans votre existence. Vous pensez sérieusement qu’une personne obtenant tout, tout cuit dans le bec et sans rien entreprendre, a des chances de se remettre en question et d’évoluer ? Que fera-t-elle quand elle devra, un jour, devenir autonome ? </p>\n<p>Pour vous aider à réussir à penser de la sorte, je vous invite à consulter mon <a href=\"/lacher-prise-et-acceptation\" target=\"_blank\" rel=\"noopener\" title=\"Lâcher-prise et acceptation\">article</a> sur l’acceptation et le lâcher-prise. </p>\n<h3>Comprendre que personne n’est parfait</h3>\n<p>Personne n’est parfait et donc, vous non plus. Tout le monde est humain et est constitué de la même manière. Paradoxalement, chaque personne, de par son histoire de vie et des expériences vécues, demeure unique. Par conséquent, vous n’êtes pas supérieur aux autres. Mais le contraire reste vrai aussi. Vos semblables ne sont pas mieux que vous. Chacun possède juste des forces et faiblesses différentes, c’est tout. Donc, vous pouvez quelquefois rencontrer quelqu’un apparaissant meilleur que vous dans un domaine. Ce qui ne veut pas dire que votre valeur, en tant que personne, se trouve inférieure à la sienne.</p>\n<h3>Accepter ses faiblesses</h3>\n<p>Vous devez apprendre à accepter vos vulnérabilités, en augmentant concomitamment vos forces. En les acceptant, vous apprendrez à avoir confiance en vous et de ce fait, vous vous sentirez beaucoup moins blessé quand des critiques surviendront à votre égard. Vous ne les prendrez pas tant à cœur, surtout celles non constructives, car vous saurez ce que vous valez. </p>\n<h3>Revoir ses priorités</h3>\n<p>Au lieu de vouloir être parfait en vous trouvant sur tous les fronts, au risque de développer un burn-out, apprenez à revoir vos priorités. Là, c’est à vous de voir ce qui vous importe le plus dans votre vie. Votre famille ? Votre travail ? Vos passions ? Classez ensuite vos priorités et tenez-vous-y. Le perfectionniste aimant l’organisation, le fait d’établir une liste de ses importants et d’organiser son agenda en conséquence l’aidera grandement. </p>\n<h3>Apprendre à bien respirer </h3>\n<p>Vu que bien souvent le perfectionniste se met trop la pression, sa respiration doit sans doute se trouver médiocre. Pourtant, bien respirer l’aiderait à retrouver son calme quand il le désire. Pour plus d’informations, n’hésitez pas à consulter mon <a href=\"/respiration\" target=\"_blank\" rel=\"noopener\" title=\"Respiration\">article</a> à ce sujet. </p>\n<p>Personnellement, je pratique la respiration grâce à la cohérence cardiaque. J’utilise pour ce faire l’appareil ZENSPIRE, lequel émet de la lumière ainsi que des vibrations afin de me permettre de respirer pleinement et surtout, correctement. Car oui, bien respirer s’apprend et nous avons presque tous, devenus adultes, oublié de bien respirer.</p>\n<p>Donc, si vous êtes intéressé par ce produit, c’est juste ci-dessous, étant précisé que pour une commande passée avec le code JL0620,<b> </b>une remise immédiate de 10 % vous sera accordée :</p>\n<h3>Se faire aider psychologiquement  </h3>\n<p>Enfin, si vraiment ce trait de caractère vous dépasse et vous fait trop souffrir, n’hésitez pas à vous faire aider par un professionnel de la santé. Ce n’est pas une faiblesse ! C’est plutôt une force d’entreprendre des actions pour résoudre ses problèmes. Les TCC sont conseillées pour <b>vaincre le perfectionnisme.</b> En effet, le thérapeute vous aidera à transformer vos schémas de pensées en des croyances plus souples. </p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'Vaincre le Perfectionnisme pour Acquérir le Bien-être','Vous êtes un insatisfait chronique voulant tout contrôler ? Vous êtes peut-être un perfectionniste. Comment vaincre le perfectionnisme ?','https://vivre-pleinement.fr/perfectionnisme/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/perfectionnisme\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/perfectionnisme\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Vaincre le Perfectionnisme pour Acqu\\u00e9rir le Bien-\\u00eatre\",\"datePublished\":\"2019-11-21T20:03:46+00:00\",\"dateModified\":\"2024-02-13T17:21:00+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/perfectionnisme\\/\"},\"wordCount\":4725,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/perfectionnisme\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/11\\/Vaincre-perfectionnisme.png\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/perfectionnisme\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/perfectionnisme\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/perfectionnisme\\/\",\"name\":\"Vaincre le Perfectionnisme pour Acqu\\u00e9rir le Bien-\\u00eatre\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/perfectionnisme\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/perfectionnisme\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/11\\/Vaincre-perfectionnisme.png\",\"datePublished\":\"2019-11-21T20:03:46+00:00\",\"dateModified\":\"2024-02-13T17:21:00+00:00\",\"description\":\"Vous \\u00eates un insatisfait chronique voulant tout contr\\u00f4ler\\u2009? Vous \\u00eates peut-\\u00eatre un perfectionniste. Comment vaincre le perfectionnisme\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/perfectionnisme\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/perfectionnisme\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/perfectionnisme\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/11\\/Vaincre-perfectionnisme.png\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/11\\/Vaincre-perfectionnisme.png\",\"width\":640,\"height\":479,\"caption\":\"Comment vaincre le perfectionnisme ? Comment vaincre le perfectionnisme ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/perfectionnisme\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Vaincre le Perfectionnisme pour Acqu\\u00e9rir le Bien-\\u00eatre\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-11-21 20:03:46',NULL,'2026-05-24 19:19:45','2026-06-19 22:28:14');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (45,'Susceptibilité Pathologique : Stopper ce Trait de Caractère pour être Heureux','susceptibilite','Tout le monde est susceptible, c’est humain. Cependant, certaines personnes possèdent une susceptibilité hyper développée qui est loin de leur faciliter le quotidien. Elles souffrent de ce trait de caractère. Certaines peuvent même ne pas être conscientes de l’être. Et en plus de faire souffrir l’individu concerné, votre entourage est aussi affecté. Si une personne vous fait une critique constructive, vous le prenez tout de même très mal. Vos proches doivent constamment marcher sur des œufs avec vous et faire très attention à leur propos. En effet, vous les interprétez bien souvent négativement. Vous vous plaignez que vos semblables vous cachent des éléments et n’apparaissent pas totalement francs avec vous : ils ont bien trop peur de votre réaction. Votre susceptibilité pathologique gâche votre existence et par la même occasion, celle de vos proches ? Comment vous en libérer ? \n','<h2>Comment arrêter d\'être susceptible ?</h2>\n<p>Si vous êtes ici, c\'est sans doute que vous en avez assez de vous sentir blessé pour un rien, de ressasser une phrase pendant des heures, de gâcher de belles relations à cause d\'une réaction que vous regrettez ensuite. La bonne nouvelle, c\'est que la susceptibilité n\'est pas une fatalité gravée dans votre caractère : c\'est une <b>réaction de protection</b> que vous avez apprise, et que vous pouvez désapprendre.</p>\n<p>En quelques mots, arrêter d\'être susceptible passe par trois prises de conscience :</p>\n<ul>\n<li><b>Comprendre que la remarque de l\'autre parle de lui, pas de vous.</b> Ce qui vous blesse, ce n\'est pas la phrase : c\'est l\'écho qu\'elle réveille en vous.</li>\n<li><b>Aller voir la blessure qui se cache dessous.</b> La susceptibilité est presque toujours la partie visible d\'une <a href=\"/blog/blessure-de-rejet\">blessure plus ancienne</a> — de rejet, d\'abandon ou d\'<a href=\"/blog/soigner-blessure-dinjustice\">injustice</a>.</li>\n<li><b>Renforcer votre socle intérieur</b>, en travaillant votre <a href=\"/blog/confiance-et-estime-de-soi\">confiance en vous</a>, pour que le regard des autres cesse d\'avoir autant de pouvoir sur vous.</li>\n</ul>\n<p>C\'est exactement ce que nous allons voir, étape par étape, dans cet article.</p>\n<p>Tout le monde est susceptible, c’est <b>humain</b>. Cependant, certaines personnes possèdent une susceptibilité <b>hyper développée</b> qui est loin de leur faciliter le quotidien. Elles <b>souffrent </b>de ce trait de caractère. Certaines peuvent même ne pas être <b>conscientes </b>de l’être. Et en plus de faire souffrir l’individu concerné, votre entourage est aussi affecté. Si une personne vous fait une critique <b>constructive</b>, vous le prenez tout de même très <b>mal</b>. Vos proches doivent constamment marcher sur des <b>œufs </b>avec vous et faire très <b>attention </b>à leur propos. En effet, vous les interprétez bien souvent <b>négativement</b>. Vous vous <b>plaignez </b>que vos semblables vous <b>cachent </b>des éléments et n’apparaissent pas totalement <b>francs </b>avec vous : ils ont bien trop peur de votre <b>réaction</b>. Votre<b> susceptibilité pathologique</b> <b>gâche </b>votre existence et par la même occasion, celle de vos proches ? Comment vous en <b>libérer </b>? </p>\n<h2>Qu’est-ce que la susceptibilité pathologique ?</h2>\n<p>La susceptibilité, c’est le fait de surréagir à la moindre remarque d’autrui. Par rapport à la personnalité de l’individu, les réactions demeurent différentes. Il peut y avoir de l’agression directe, comme se mettre en colère ouvertement. L’individu peut également exprimer son mécontentement de manière plus indirecte, mais visible, telle que bouder. Ce qui ne fait pas avancer la situation et peut provoquer, à la longue et à force de ruminations, de la rancœur à l’égard de l’autre. Enfin, il pourra se sentir honteux après une critique et se replier sur lui-même, et ce, sans avoir, au préalable, exprimé ce qu’il ressentait.</p>\n<p>Par contre, un individu peut très bien apparaître susceptible par rapport à certains sujets seulement, ceux le touchant tout particulièrement. </p>\n<p>Par exemple, si la personne se trouve fragile et que cette pensée engendre chez elle une blessure importante, si quelqu’un a le malheur de le dire, c’est la catastrophe. Déjà, elle aura l’impression d’avoir été démasquée malgré ses efforts pour le cacher et de plus, l’autre va appuyer, sans le savoir, sur une plaie profonde. La personne va alors croire qu’elle a raison, qu’elle est bel et bien fragile, vu que les autres le disent aussi. Son estime d’elle-même n’ira donc pas en s’arrangeant. </p>\n<p>Cependant, si quelqu’un prétend qu’elle est égoïste et que ce n’est pas le cas ou qu’elle ne le pense pas d’elle-même, elle n’en tiendra, en général, pas rigueur. La critique lui passe au-dessus de sa tête. </p>\n<p>Voyons maintenant les trois types de personnalités pouvant présenter ce trait de caractère.</p>\n<h3>Le timide </h3>\n<p>Le timide n’aura en général pas une grande confiance et estime de lui. Il se pense automatiquement inférieur à ses pairs. Le fait d’avoir des remarques d’autrui peut alors l’amener à devenir susceptible. En effet, vu qu’il ne s’aime pas suffisamment, il cherche à combler ce vide par l’amour des autres. Une réflexion lui étant faite est donc synonyme de rejet et de manque d’affection de la part de ses semblables. Ce qui est bien évidemment intolérable pour lui, étant donné que c’est ce qu’il recherche.</p>\n<h3>Le narcissique </h3>\n<p>La personnalité narcissique est souvent l’apanage des enfants-rois devenus adultes-rois, voire adultes-tyrans. Ces adultes possèdent généralement un fort égo et se pensent supérieurs aux autres. Ils méritent donc forcément, d’après eux, un traitement différent. Cependant, ils se rendront vite compte que ce n’est pas le cas et que le monde autour d’eux est loin de répondre à toutes leurs attentes. Ils pourront ainsi développer un caractère très susceptible. En effet, étant donné qu’ils sont supérieurs à tous, personne n’a le droit de leur dire quoi que ce soit. </p>\n<h3>Le paranoïaque </h3>\n<p>La personnalité paranoïaque (à ne pas confondre avec la vraie maladie psychotique qu’est la paranoïa) utilise souvent le mécanisme de projection. C’est-à-dire qu’elle projette ses propres sentiments sur les autres et n’a pas conscience que ce qu’elle ressent ne vient que de son propre état interne. </p>\n<p>Par exemple, une personne se sent de mauvaise humeur en se levant le matin. Quand elle arrive au travail, elle trouve que son patron n’a pas l’air de se trouver dans de bonnes dispositions. Alors qu’en réalité, il va très bien. C’est juste qu’elle projette sur lui son propre moral maussade du moment. </p>\n<p>Certaines personnes utilisent ce mécanisme très souvent, en se méfiant de tout et en pensant que les autres leur veulent du mal, les trouvent grosses, bêtes, fragiles, etc. alors que ce n’est pas du tout le cas et que ce sont plutôt elles qui pensent ce genre de propos sur elles-mêmes. </p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"632\" height=\"640\" src=\"/storage/blog-images/Susceptible.jpg\" alt=\"Agressivite \" title=\"Susceptible\">\n<h2>Origine de la susceptibilité  </h2>\n<p>Même si tout le monde reste un peu susceptible, le fait de l’être de manière extrême trouve forcément son origine quelque part.</p>\n<h3>Le traumatisme conscient ou inconscient </h3>\n<p>La susceptibilité peut venir à la suite d’un événement non digéré par l’individu. Prenons l’exemple d’une personne ayant été victime de harcèlement scolaire. Si elle a été insultée sur son physique, plus tard, elle pourra ne pas supporter la moindre critique sur son apparence. Le fait d’émettre un jugement à ce sujet peut faire revivre à la personne des scènes douloureuses étant survenues à l’enfance. Voilà pourquoi elle surréagit autant.</p>\n<p>La seule manière de sortir de ce cercle vicieux reste de travailler sur le traumatisme. Cependant, ce trouble peut quelquefois demeurer inconscient. Dans ce cas, il faudra œuvrer plus en profondeur sur soi. Vous pouvez aller consulter mon <a href=\"/traumatisme\" target=\"_blank\" rel=\"noopener\" title=\"Traumatisme\">article</a> sur le traumatisme si vous souhaitez en savoir plus. </p>\n<h3>L’hypersensibilité </h3>\n<p>Je vous invite en premier lieu à aller sur mon <a href=\"/hypersensibilite\" target=\"_blank\" rel=\"noopener\" title=\"Hypersensibilité\">article</a> concernant l’hypersensibilité afin de bien comprendre ce tempérament. Après l’avoir lu, vous comprendrez donc qu’hyperémotivité et susceptibilité sont souvent liées, ce qui est normal. En effet, une personne hypersensible voit ses émotions exacerbées, se trouve à fleur de peau. Elle surréagit exactement comme l’individu susceptible. </p>\n<p>La susceptibilité peut également provenir d’un sentiment d’infériorité dû à un manque de confiance en soi, poussant au besoin de reconnaissance et d’amour de la part des autres. </p>\n<p> </p>\n<h2>Ce que pensent les gens moins susceptibles  </h2>\n<p>Bien souvent, la personne susceptible, par ses comportements, veut faire passer comme message qu’elle s’est sentie blessée, non respectée voire, humiliée. Cependant, elle ne s’y prend pas de la bonne manière, même si elle pense le contraire. Elle ne s’affirme pas, mais boude, agresse, se replie sur elle-même, etc. d’ailleurs, en ayant ce genre de comportement, le susceptible remarque que les autres n’osent plus rien lui dire. Il peut croire que cette réaction d’autrui vient de son fort caractère. Il se pense ainsi respecté alors que ce n’est pas forcément le cas. Cette croyance l’encourage de ce fait à continuer de réagir de la sorte.  </p>\n<p>Cependant, si son entourage n’ose plus rien dire, ce n’est pas par peur ou par respect. C’est surtout qu’il ne sait plus sur quel pied danser. Ce genre d’attitude l’agace et donc, il peut en venir à ne plus rien dire du tout. Il peut même penser que ce type de comportement apparaît enfantin, ridicule ou égocentrique. </p>\n<h2>Liens entre susceptibilité et troubles anxieux  </h2>\n<p>Une personne susceptible n’est pas forcément anxieuse. Cependant, ces deux éléments peuvent être liés. Car l’anxiété reflète de la même façon une mauvaise gestion des émotions, c’est un trouble émotionnel. Et vu que le susceptible surréagit, c’est que lui aussi ne maîtrise pas bien ses émotions. </p>\n<p>Une personne souffrant de troubles anxieux peut donc également apparaître susceptible dans le sens où elle se sent anormale et fragile. Elle peut alors être profondément blessée à cet égard et réagir de manière extrême si quelqu’un lui fait ce genre de réflexion. </p>\n<p> </p>\n<img decoding=\"async\" width=\"960\" height=\"635\" src=\"/storage/blog-images/Vexation.jpg\" alt=\"Hypersensibilite\" title=\"Vexation\">\n<h2>Comment soigner la susceptibilité pathologique ?  </h2>\n<p>Nous allons maintenant voir ensemble les solutions afin d’atténuer ce trait de personnalité. Vous verrez que vous vivrez beaucoup mieux ensuite. </p>\n<h3>Travailler votre confiance en vous </h3>\n<p>La confiance en soi est la racine du bien-être psychologique. Une personne manquant de confiance en elle sera donc sujette à certains troubles plus ou moins importants, au regard du degré de manque de confiance. Je vous invite à aller consulter <a href=\"/confiance-et-estime-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Confiance et estime de soi\">l’article</a> que j’ai rédigé à ce sujet sur la confiance en soi, laquelle s’avère primordiale pour vous débarrasser de ce trouble. </p>\n<h3>Vous affirmer  </h3>\n<p>S’affirmer va un peu de pair avec la confiance et l’estime de soi, vu qu’il s’agit d’un mode de communication sain. Je vous invite par conséquent à lire mon article à ce sujet. </p>\n<p>Ainsi, dès que vous vous sentez blessé, il ne faut pas avoir peur de le dire à l’autre, mais votre discours doit opter pour le style affirmatif. Car si vous gardez tout pour vous, votre susceptibilité n’ira pas en s’arrangeant et vous accumulerez de la rancœur. </p>\n<h3>Comprendre que les gens ont d’autres préoccupations que vous  </h3>\n<p> </p>\n<p>Bien souvent, une personne susceptible a besoin de l’amour de ses semblables pour se sentir bien, étant donné qu’elle ne s’en donne pas assez. Elle fait donc extrêmement attention au regard des autres. Trop attention d’ailleurs. Je vous invite à cet égard à aller sur mon <a href=\"/jugement-des-autres\" target=\"_blank\" rel=\"noopener\" title=\"Jugement des autres \">article</a> concernant le jugement d’autrui. Il faut bien que vous compreniez que même si, au pire des cas, quelqu’un vous critique, son intérêt sera vite portée sur quelqu’un d’autre. Parce que vous n’êtes pas son centre du monde. Et qu’elle a aussi d’autres occupations, du moins, j’espère pour elle. Car si elle parle de vous constamment, c’est que vous l’intéressez probablement et qu’elle éprouve un mal-être intérieur. </p>\n<p>Et si le regard des autres est trop difficile à supporter pour vous, Didier PENISSARD, coach et auteur en développement personnel, peut vous aider, grâce à son programme, à passer outre cela. N’hésitez pas à aller jeter un oeil audit programme en cliquant sur le bouton ci-dessous :</p>\n<h3>Ressentir vos blessures </h3>\n<p>Quand une personne critique un point de votre personnalité, je vous invite à réaliser cet exercice, dans l’immédiat ou un peu plus tard dans la journée. Mais faites-le, car ressentir ses émotions reste extrêmement important. Il ne faut surtout pas rester dans le déni, lequel peut avoir, à la longue, des conséquences vraiment néfastes sur vous. J’ai d’ailleurs rédigé un article sur le refoulement des émotions.</p>\n<h4>1 — Ressentir vos émotions </h4>\n<p>Le principe de cet exercice est le suivant. Quand vous vous sentez blessé par une réflexion que quelqu’un a pu vous faire, posez-vous et prenez le temps de ressentir. Tout d’abord, mettez un ou des mots sur ce que vous ressentez. Vous sentez-vous anxieux ? Triste ? Choqué ? Frustré ? Furieux ? Vous l’aurez compris, il vous faut nommer vos émotions, c’est très important. </p>\n<p>Ensuite, prenez le temps d’analyser vos ressentis par rapport à la personne. Vous sentez-vous trahi ? Abandonné ? Blâmé ? Ridiculisé ? Sali ? </p>\n<h4>2 — Ressentir vos sensations physiques </h4>\n<p>Après avoir nommé vos ressentis, mettez maintenant des mots sur les sensations corporelles ressenties à ce moment. Quelquefois, rien que le fait de repenser à une scène vous ayant blessé peut vous faire ressentir les mêmes sensations physiques ! Votre cœur a commencé à palpiter ? Vous avez senti des bouffées de chaleur monter ? Vous vous êtes mis à trembler ? Avez-vous eu des vertiges ? Ou une sensation d’irréalité autour de vous ? </p>\n<h4>3 — Trouver vos blessures</h4>\n<p>Ensuite, posez-vous la question suivante : de quoi avez-vous peur pour vous dans cette situation ? D’être rejeté ? Trahi ? Humilié ? Abandonné ? Que l’on apparaisse injuste envers vous ? </p>\n<p>Ressentir vos blessures, c’est en prendre conscience. Les conscientiser vous servira alors à entreprendre des actions efficaces correspondant aux blessures concernées. En effet, si vous niez vos souffrances, le chemin que vous pouvez emprunter pour y trouver une solution s’avèrera souvent être le mauvais. </p>\n<p>Cette étape vous permettra donc de prendre la bonne direction. </p>\n<h3>Réagir avec humour  </h3>\n<p>Si vous vous sentez attaqué, tentez de le prendre avec humour ou de sortir une blague à l’autre, même si c’est dur pour vous. Car le rire, bien souvent, apaise les tensions. Après, c’est sûr qu’il va vous falloir un peu d’entraînement, mais que perdez-vous à essayer ?</p>\n<h3>Comprendre que votre entourage ne vous veut que du bien </h3>\n<p>Nous avons tendance à oublier cet état de fait. Un proche qui vous aime ne veut que votre bien. Donc, s’il vous fait une critique, c’est qu’elle est forcément constructive. Alors, au lieu de tout de suite monter sur vos grands chevaux, posez-vous et réfléchissez à ce que votre proche vient de vous dire. Ses paroles n’ont été prononcées qu’en vue de vous faire évoluer. </p>\n<h3>Apprendre à respirer </h3>\n<p>J’ai également rédigé un article sur la respiration, car elle reste très importante pour réguler vos émotions et vos symptômes corporels. Effectivement, en inspirant et expirant profondément, votre système nerveux va automatiquement se calmer. En plus, c’est un exercice que vous pouvez réaliser à chaque instant, puisqu’il n’y a, en effet, rien de plus naturel que la respiration ! </p>\n<p></p>\n<p>Si vous souhaitez apprendre à bien respirer, je vous conseille le produit ZENSPIRE, que j’utilise pour pratiquer la cohérence cardiaque, technique de respiration extrêment efficace. Grâce à la lumière et à la vibration que ce petit appareil émet, vous respirerez de mieux en mieux. Car oui, il y a vraiment une façon de respirer pour atteindre un état de relaxation profonde. </p>\n<p>Je vous invite donc à cliquer sur le bouton ci-dessous pour découvrir ZENSPIRE, étant précisé que si vous souhaitez commander ce produit, vous bénéficierez d’une remise de 10 % grâce au code JL0620. Alors, profitez-en ! </p>\n<h3>Pratiquer la méditation  </h3>\n<p>La méditation est une technique de relaxation. Elle est d’ailleurs liée à la respiration, puisque les deux procurent une sensation de détente. Après, libre à vous de choisir une autre méthode de relaxation qui vous correspond plus, telle que le yoga, la sophrologie, etc. Car je sais que certaines personnes peuvent paniquer pendant la méditation, n’ayant pas l’habitude de regarder profondément en eux. Il ne faut pas oublier que le but de la détente reste de réguler vos émotions et de prendre soin de votre corps. </p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img loading=\"lazy\" decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h3>Envisager une thérapie </h3>\n<p>Si vraiment votre susceptibilité vous fait trop souffrir, n’hésitez pas à vous faire aider par un professionnel de la santé. La psychanalyse reste recommandée pour ce cas. Le thérapeute vous aidera en effet à comprendre le mécanisme de votre <b>susceptibilité pathologique</b> et son origine.</p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'Susceptibilité : Comment Arrêter d\'Être Susceptible et S\'en Libérer','Vous prenez tout mal, vous ruminez la moindre remarque ? La susceptibilité cache souvent d\'anciennes blessures. Voici comment vous en libérer, pas à pas.','https://vivre-pleinement.fr/susceptibilite/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/susceptibilite\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/susceptibilite\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Susceptibilit\\u00e9 Pathologique\\u00a0: Stopper ce Trait de Caract\\u00e8re pour \\u00eatre Heureux\",\"datePublished\":\"2019-11-10T15:57:52+00:00\",\"dateModified\":\"2022-08-01T20:29:10+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/susceptibilite\\/\"},\"wordCount\":4959,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/susceptibilite\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/11\\/Susceptibilite-pathologique.png\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/susceptibilite\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/susceptibilite\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/susceptibilite\\/\",\"name\":\"Susceptibilit\\u00e9 Pathologique\\u00a0: Stopper ce Trait de Caract\\u00e8re pour \\u00eatre Heureux\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/susceptibilite\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/susceptibilite\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/11\\/Susceptibilite-pathologique.png\",\"datePublished\":\"2019-11-10T15:57:52+00:00\",\"dateModified\":\"2022-08-01T20:29:10+00:00\",\"description\":\"Certaines personnes poss\\u00e8dent une susceptibilit\\u00e9 hyper d\\u00e9velopp\\u00e9e. Votre susceptibilit\\u00e9 pathologique g\\u00e2che votre existence\\u2009? Comment vous en lib\\u00e9rer\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/susceptibilite\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/susceptibilite\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/susceptibilite\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/11\\/Susceptibilite-pathologique.png\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/11\\/Susceptibilite-pathologique.png\",\"width\":640,\"height\":452,\"caption\":\"Comment soigner la susceptibilite pathologique ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/susceptibilite\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Susceptibilit\\u00e9 Pathologique\\u00a0: Stopper ce Trait de Caract\\u00e8re pour \\u00eatre Heureux\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-11-10 15:57:52',NULL,'2026-05-24 19:19:45','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (46,'Les Bienfaits de la Respiration sur le Corps et l’Esprit','respiration','Quoi de plus naturel que la respiration ? En effet, respirer est vital pour l’être humain. D’ailleurs, c’est tellement instinctif que vous ne vous rendez même pas compte de votre respiration. Elle ne vous gêne pas du tout et fait partie de vos automatismes. De vous. Seulement, elle peut aussi se retourner contre vous par le fait de ne pas respirer correctement. De la bloquer involontairement, ou de l’accélérer. Par conséquent, elle peut faire apparaître bon nombre de symptômes somatiques ennuyeux. Lorsque vous êtes stressé, vous vous surprenez quelquefois à couper votre respiration. Vous faites une crise d’angoisse. Tout s’accélère dans votre organisme et vous pensez mourir, vous ne savez pas comment faire pour aller mieux. Vous ressentez un stress chronique. Quels sont les bienfaits de la respiration et comment pouvez-vous en profiter ? \n','<p>Quoi de plus <b>naturel </b>que la respiration ? En effet, respirer est<b> vital </b>pour l’être humain. D’ailleurs, c’est tellement instinctif que vous ne vous rendez même pas compte de votre respiration. Elle ne vous gêne pas du tout et fait partie de vos<b> automatismes</b>. De vous. Seulement, elle peut aussi se<b> retourner</b> contre vous par le fait de ne pas respirer correctement. De la <b>bloquer </b>involontairement, ou de <b>l’accélérer</b>. Par conséquent, elle peut faire apparaître bon nombre de symptômes <b>somatiques</b> ennuyeux. Lorsque vous êtes <b>stressé</b>, vous vous surprenez quelquefois à <b>couper </b>votre respiration. Vous faites une <b>crise d’angoisse. </b>Tout s’accélère dans votre organisme et vous pensez <b>mourir</b>, vous ne savez pas comment faire pour aller mieux. Vous ressentez un stress <b>chronique</b>. Quels sont<b> les bienfaits de la respiration </b>et comment pouvez-vous en profiter ? </p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img fetchpriority=\"high\" decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h2>Le lien entre une mauvaise respiration et les troubles anxieux</h2>\n<p>Lorsque vous souffrez de <a href=\"/angoisse-stress-anxiete\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse stress anxiété\">troubles anxieux</a>, bon nombre de symptômes somatiques peuvent se manifester. Par conséquent, en plus des manifestations émotionnelles, votre corps souffre semblablement. Les deux sont clairement liés. Car en étant angoissé, tout s’active dans votre corps. Votre cœur peut s’emballer, votre transit également, etc., et bien évidemment, votre respiration aussi. Mais contrairement à votre cœur ou votre transit que vous pouvez difficilement contrôler, vous pouvez directement agir sur votre respiration.</p>\n<p>En résumé, plus vous respirez rapidement, plus votre métabolisme s’accélère et fait apparaître une myriade de troubles physiques. Et au contraire, plus vous respirez calmement, plus votre métabolisme va se réguler, ce qui calmera totalement votre corps et donc, vos symptômes somatiques. </p>\n<p>Lorsque vous souffrez d’anxiété, votre respiration est mauvaise. Elle reste très superficielle et vous pouvez même vous surprendre à penser « tiens, j’ai l’impression que ma respiration se bloque de temps à autre ». Et en cas de crise de panique, vous respirez beaucoup trop vite. Si vous régulez votre respiration, vous verrez donc que votre corps et votre esprit s’en trouveront apaisés.</p>\n<h2>La respiration thoracique </h2>\n<p>Cette respiration est presque devenue universelle. En effet, la plupart des individus l’utilisent et pourtant, elle n’a rien de naturel ! Elle consiste à n’utiliser que le haut de votre poitrine, la cage thoracique, afin de respirer. Cependant, ne se servir que de cette partie rend la respiration superficielle et parfois même, la bloque. </p>\n<p>Et le fait de peu respirer entraîne un manque d’oxygène pour les cellules, ainsi qu’une mauvaise élimination des toxines.</p>\n<p>Pourquoi donc la plupart d’entre nous recourent à cette respiration alors qu’elle n’apparaît pas innée ? Car notre société contemporaine, prônant la course après le temps et donc, le stress quasi permanent, a un rôle à jouer. En effet, c’est ce stress constant qui nous a, petit à petit, appris à mal respirer. Heureusement, ce n’est pas une fatalité. Un nouvel apprentissage reste possible. </p>\n<img decoding=\"async\" width=\"640\" height=\"426\" src=\"/storage/blog-images/Respiration-thoracique.jpg\" alt=\"Respiration profonde \" title=\"Respiration thoracique\">\n<h2>Les bienfaits de la respiration profonde </h2>\n<p>Puisque bien respirer régule l’organisme et l’esprit, vous pourrez ressentir une sensation de détente. Et cette sensation n’est pas un effet placebo. Votre corps se sent réellement mieux en étant plus relaxé. Et puis, le fait de prendre le temps de bien respirer vous protège et vous éloigne quelques instants du tumulte du quotidien. Et je pense que cette évasion reste indispensable pour vous sentir bien. Car vous verrez que si vous vous éloignez un peu de ce mode de vie « course quotidienne et ininterrompue », votre <a href=\"/fatigue-mentale\" target=\"_blank\" rel=\"noopener\" title=\"Fatigue mentale\">fatigue, nerveuse</a> comme physique, va s’atténuer.</p>\n<p>La respiration possède donc un effet calmant. Elle reste un anxiolytique naturel. C’est plutôt une bonne nouvelle si vous souhaitez éviter les médicaments, non ? Ou toute autre addiction d’ailleurs. Car cet anxiolytique ne comporte même pas d’effets secondaires ! </p>\n<p>Enfin, pratiquer certaines techniques de respiration a de très bonnes conséquences pour vos, notamment abdominaux, lesquels se retrouvent comme « massés ». </p>\n<p>Voyons donc maintenant les deux principaux types de respirations qu’il y a lieu d’utiliser le plus souvent possible dans votre vie afin de vous permettre d’aller mieux. Je vous invite déjà à maîtriser la première avant de passer à la deuxième, laquelle apparaît un peu plus complexe à appliquer. </p>\n<h3>La respiration abdominale </h3>\n<p>La plupart d’entre nous n’utilisent pas cette respiration, mais savez-vous qu’elle reste la plus naturelle ? Pour preuve, vous n’avez qu’à regarder un bébé dormir ou votre animal domestique. Comment respire-t-il ? Surtout en utilisant son ventre. C’est tout de même malheureux d’avoir oublié notre respiration instinctive, en plus de l’avoir remplacée par une respiration artificielle, thoracique. </p>\n<p>Toujours est-il qu’avec de l’entraînement, vous pourrez recommencer à respirer naturellement. Voici les différentes étapes pour ce faire :  </p>\n<p> </p>\n<p>1— Inspirez par le nez, sans forcer, de la manière la plus naturelle possible, et ce, tout en gonflant l’abdomen. </p>\n<p>2 — Expirez ensuite en dégonflant le ventre, par la bouche si vous voulez. </p>\n<p> </p>\n<p>Pour vous aider à sentir votre ventre se gonfler et se dégonfler et surtout, pour savoir si vous effectuez l’exercice correctement, vous pouvez mettre une main dessus.</p>\n<h3>La respiration profonde </h3>\n<p>Après avoir bien maîtrisé la respiration abdominale, vous pouvez maintenant essayer la respiration profonde, qui se trouve un cran au-dessus. La différence avec le premier exercice, c’est que cette méthode ne jette pas complètement à la poubelle la respiration thoracique. En fait, elle combine respirations abdominale et thoracique. Elle sollicite tout l’organisme. Voici les étapes à pratiquer. Vous pouvez commencer à vous entraîner en étant couché, car vous pourrez mieux ressentir les différentes zones de votre corps sollicitées.  </p>\n<p> </p>\n<p>1— Inspirez par le nez, sans forcer, de la manière la plus naturelle qui soit, et ce, tout en gonflant le ventre. Après que le ventre soit gonflé, continuez d’inspirer en faisant passer votre respiration par le thorax.</p>\n<p>2— Expirez ensuite en détendant le plus possible vos épaules, puis en dégonflant le torse et enfin, l’abdomen. Vous pouvez expirer par la bouche. </p>\n<img loading=\"lazy\" decoding=\"async\" width=\"500\" height=\"354\" src=\"/storage/blog-images/Coherence-cardiaque.jpg\" alt=\"Respiration abdominale \" title=\"Cohérence-cardiaque\">\n<h2>La cohérence cardiaque </h2>\n<p>Pour retrouver une bonne respiration, il faudra vous entraîner très régulièrement. L’entraînement reste sans conteste très important, car c’est par ce biais que votre respiration deviendra naturelle.</p>\n<p>En effet, si vous attendez de vous trouver en pleine crise d’angoisse pour pratiquer l’exercice, vous risquez d’avoir beaucoup de mal à réguler votre organisme. Vous pouvez même ne pas y arriver, car votre corps est beaucoup trop tendu à ce moment et vous n’aurez d’autre choix que d’attendre que les symptômes passent tout seul. L’entraînement régulier vous aidera en fait à ne pas faire apparaître d’attaque de panique, en en éliminant directement les premières manifestations par une bonne respiration.</p>\n<p>Et ne dites pas que vous n’avez pas le temps de vous entraîner. Dans la mesure où votre respiration demeure naturelle, vous pouvez apprendre à la contrôler partout. Je vous donne des exemples : dans une salle d’attente, en attendant à une caisse de magasin, dans un embouteillage, aux toilettes, etc. Et si vous ne l’avez pas, il va falloir en trouver, car rien ne demeure plus important que votre santé, non ? </p>\n<h3>L’application Respirelax </h3>\n<p>Il existe sur internet énormément d’exercices de respiration à pratiquer. À vous de voir quels exercices vous correspondent le mieux. Je vous parlerai, dans cet article, de la méthode que j’utilise. La cohérence cardiaque.</p>\n<p>Je trouve cette méthode vraiment efficace, car elle emploie la respiration profonde. De plus, sur votre téléphone portable, vous pouvez trouver des applications vous permettant de réaliser cet exercice. Notamment l’application « Respirelax ». Il s’agit d’une goutte qui monte et qui descend, tout en émettant un son dès qu’elle le fait, et ce, afin de vous aider à réguler votre respiration. Vous pouvez également y ajouter une musique si vous le souhaitez et sélectionner la durée des inspirations/expirations. Car la durée ne procure pas les mêmes effets et c’est donc à vous de la choisir par rapport à ce que vous voulez ressentir, c’est-à-dire : </p>\n<p> </p>\n<p>– Vous sentir dynamisé : 6 inspirations et 4 expirations en secondes ;</p>\n<p>– Vous sentir relaxé : 4 inspirations et 6 expirations en secondes ; </p>\n<p>– Ou vous sentir équilibré : 5 inspirations et 5 expirations en secondes. </p>\n<h3>Durée de l’exercice </h3>\n<p>Vous pouvez choisir la durée totale de la pratique. Voici mon conseil. Si vous êtes quelqu’un au tempérament anxieux, mais que votre angoisse ne vous gâche pas trop la vie, pratiquez 15 minutes dans votre journée. 5 minutes le matin, 5 le midi et 5 le soir.</p>\n<p>Par contre, si vous êtes un grand angoissé, souffrant de troubles anxieux qui vous handicapent fortement au quotidien, essayez de passer la durée de l’exercice à 30 minutes. 10 minutes le matin, 10 le midi et 10 le soir. Je vous conseille d’ailleurs d’effectuer la dernière séance juste avant de vous coucher. En effet, la sensation de détente que vous éprouverez à ce moment fera apparaître beaucoup plus rapidement le sommeil. Cette technique aide beaucoup à lutter contre les<a href=\"/insomnie\" target=\"_blank\" rel=\"noopener\" title=\"Insomnie\"> insomnies. </a></p>\n<h3>Comment bien réaliser la cohérence cardiaque ? </h3>\n<p>Après avoir choisi entre les modes équilibré/relaxé/dynamisé ainsi que la durée de l’exercice, il vous faut maintenant suivre le mouvement de la goutte avec votre respiration. </p>\n<p>Prenons l’exemple de la méthode équilibré, c’est-à-dire 5/5. Il y a lieu de mettre en application la respiration profonde. Votre inspiration durera 5 secondes et votre expiration également. Essayez de pratiquer une respiration fluide, qui signifie ne pas effectuer de pause entre l’inspiration et l’expiration. </p>\n<p>En bonus, vous pouvez appliquer des techniques de visualisation. Quand vous inspirez, vous pouvez visualiser votre souffle monter au milieu de votre poitrine, vers votre cœur. Ensuite, en expirant, imaginez votre souffle descendre dans votre ventre. </p>\n<p>Vous pouvez même y ajouter des images. Par exemple, à l’inspiration, vous pouvez vous représenter mentalement une image vous procurant du bonheur et du calme. La plage, un moment en famille, une nourriture que vous appréciez, etc. À l’expiration, vous pouvez imaginer que tout ce qui est négatif en vous sort de votre organisme.</p>\n<p>Avec de l’entraînement, vous arriverez à concilier respirations avec visualisations. Vous découvrirez alors <b>les bienfaits de la respiration</b> sur votre corps et votre esprit.</p>\n<p>Enfin, ce que je vous conseille mis à part l’application Respirelax, c’est l’appareil que j’utilise personnellement, se nommant <a href=\"/zenspire/\" target=\"_blank\" rel=\"noopener\" title=\"Zenspire\">ZENSPIRE</a>. Si vous souhaitez pratiquer la méthode de la cohérence cardiaque, c’est vraiment le top. En effet, ce petit appareil, grâce à la lumière et aux vibrations qu’il émet, vous aidera grandement à réaliser cette méthode au mieux. Si cela vous intéresse, n’hésitez pas à cliquer sur le bouton ci-dessous, étant précisé que si vous passez commande, vous obtiendrez une réduction immédiate de 10 % en utilisant le code JL0620. Cela vaut le coup, non ?</p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'Les Bienfaits de la Respiration sur le Corps et l’Esprit','La respiration peut se retourner contre vous par le fait de ne pas respirer correctement. Quels sont les bienfaits de la respiration ? Comment en profiter ?','https://vivre-pleinement.fr/respiration/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/respiration\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/respiration\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Les Bienfaits de la Respiration sur le Corps et l\\u2019Esprit\",\"datePublished\":\"2019-11-05T17:45:25+00:00\",\"dateModified\":\"2024-02-13T17:22:21+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/respiration\\/\"},\"wordCount\":3304,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/respiration\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/11\\/Bienfaits-respiration.jpg\",\"articleSection\":[\"D\\u00e9veloppement personnel\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/respiration\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/respiration\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/respiration\\/\",\"name\":\"Les Bienfaits de la Respiration sur le Corps et l\\u2019Esprit\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/respiration\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/respiration\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/11\\/Bienfaits-respiration.jpg\",\"datePublished\":\"2019-11-05T17:45:25+00:00\",\"dateModified\":\"2024-02-13T17:22:21+00:00\",\"description\":\"La respiration peut se retourner contre vous par le fait de ne pas respirer correctement. Quels sont les bienfaits de la respiration ? Comment en profiter\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/respiration\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/respiration\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/respiration\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/11\\/Bienfaits-respiration.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/11\\/Bienfaits-respiration.jpg\",\"width\":500,\"height\":354,\"caption\":\"Quels sont les bienfaits de la respiration ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/respiration\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Les Bienfaits de la Respiration sur le Corps et l\\u2019Esprit\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-11-05 17:45:25',NULL,'2026-05-24 19:19:45','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (47,'L’Importance de l’Affirmation de Soi pour s’Epanouir','affirmation-de-soi','L’importance de l’affirmation de soi n’est plus à démonter. Elle reste, de toute évidence, le meilleur mode de communication existant. Comme tous les comportements, elle n’est pas innée et s’apprend. Rares sont en effet les personnes ayant eu pour modèle dans l’enfance un exemple d’affirmation de soi. Il faut bien reconnaître que peu de monde arrive à s’affirmer. L’affirmation de soi peut également varier par rapport à votre humeur du jour, votre motivation, votre énergie actuelle, etc. lorsqu’une personne vous agace, vous êtes directement agressif avec elle. Vous dites tout ce que vous pensez aux autres, sans penser que vos propos peuvent les blesser. Vous détestez le conflit et prenez la fuite quand vous le sentez arriver. Vos méthodes de communication ont un impact négatif sur votre vie. Et si vous vous mettiez à vous affirmer ?\n','<p><b>L’importance de l’affirmation de soi</b> n’est plus à démontrer. Elle reste, de toute évidence, le <b>meilleur </b>mode de <b>communication </b>existant. Comme tous les comportements, elle n’est pas innée et<b> s’apprend</b>. <b>Rares </b>sont en effet les personnes ayant eu pour <b>modèle </b>dans l’enfance un exemple d’affirmation de soi. Il faut bien reconnaître que peu de monde arrive à s’affirmer. L’affirmation de soi peut également <b>varier </b>par rapport à votre humeur du jour, votre motivation, votre énergie actuelle, etc. lorsqu’une personne vous <b>agace</b>, vous êtes directement <b>agressif </b>avec elle. Vous dites <b>tout </b>ce que vous pensez aux autres, sans penser que vos <b>propos </b>peuvent les <b>blesser</b>. Vous détestez le <b>conflit </b>et prenez la <b>fuite </b>quand vous le sentez arriver. Vos méthodes de communication ont un impact <b>négatif </b>sur votre vie. Et si vous vous mettiez à vous affirmer ?</p>\n<h2>Qu’est-ce que l’affirmation de soi ? </h2>\n<p>L’affirmation de soi, c’est la capacité que possède un individu à pouvoir communiquer de manière saine, en se respectant et en respectant ses pairs. Les vrais leaders utilisent principalement ce comportement. </p>\n<p>En cas de situation conflictuelle, la personne affirmative se défendra sans avoir besoin d’être sur la défensive. Elle possède donc du caractère, mais arrive à s’exprimer tout en prenant en considération les droits des autres.</p>\n<p>Cette personne ose également exprimer ses propres opinions, même si elles apparaissent différentes de la <a href=\"/normes-sociales\" target=\"_blank\" rel=\"noopener\" title=\"Normes sociales\">norme sociale.</a> Elle assume qui elle est et n’a pas peur du regard des autres.</p>\n<p>La personne affirmative se donnera le droit d’avoir des limites pour lui permettre d’écouter ses besoins, et tant pis si les gens ne le comprennent pas. </p>\n<p>L’individu affirmatif ne se sentira pas supérieur ou inférieur à autrui. Il aura ainsi tendance à avoir un comportement égal avec tout le monde, et ce, quel que soit le niveau hiérarchique, les compétences de chacun, etc. il respectera chaque personne de la même manière. </p>\n<p>Cette personne se gardera également la possibilité de revenir sur une décision, et ce, même si le changement d’avis est très mal perçu par l’entourage. Car elle peut, comme tout le monde, faire des erreurs et répondre à la hâte et changer d’opinion après mûre réflexion. C’est un droit, et elle se l’octroie sans culpabiliser par la suite. </p>\n<h2>L’importance de l’affirmation de soi pour maximiser ses chances de succès </h2>\n<p>Lorsque vous vous affirmez, vous n’êtes pas sûr à 100 % d’obtenir ce que vous souhaitez. Tout simplement, car votre interlocuteur a aussi des droits et des envies qu’il peut appliquer et qui peuvent être différents des vôtres. Mais sans aucun doute le moyen de communication le plus adapté pour obtenir ce que vous voulez tout en respectant l’autre. Même si vous n’obtenez pas forcément ce que vous désirez, un compromis peut toujours être possible avec l’autre, d’autant plus s’il utilise le même mode de communication.  </p>\n<h2>Les avantages de l’affirmation de soi</h2>\n<p>L’affirmation de soi reste le mode de communication le plus adapté et comporte de nombreux avantages.</p>\n<h3>L’augmentation de la confiance en soi </h3>\n<p>S’entraîner à s’affirmer entraîne l’individu à oser s’exprimer ou adopter des comportements qui n’auraient pas été envisageables pour lui. Tous ces exercices développeront sa confiance en lui. Et on sait que la <a href=\"/confiance-et-estime-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Confiance et estime de soi \">confiance en soi</a> reste la condition sine qua non pour ressentir du bien-être et pouvoir gérer les émotions négatives, notamment les troubles anxieux.</p>\n<h3>Gagner le respect des autres</h3>\n<p>Bien souvent, les autres seront admiratifs envers votre attitude, car ce n’est malheureusement pas le comportement le plus simple à adopter et le plus suivi par autrui. Le fait de réussir à vous affirmer sans agressivité, à oser exprimer vos besoins et opinions donnera une image de vous positive. Vos semblables vont clairement ressentir votre confiance en vous et ne pourront que vous respecter. </p>\n<h3>Obtenir plus facilement ce que l’on souhaite </h3>\n<p>Vous exprimer clairement, calmement, et ce, tout en restant agréable et respectueuse avec la personne vous donnera de bonnes chances d’obtenir ce que vous désirez. En effet, si la personne vous apprécie, il n’y a pas vraiment de raison d’essuyer un refus de sa part.</p>\n<p>Par exemple, vous avez un patron tyrannique qui vous insulte d’incapable en vous ordonnant de finir tel dossier avant la fin de la journée. Je pense que vous aurez beaucoup moins envie de vous en occupez qu’avec un boss vous respectant, vous appréciant et vous le demandant gentiment, non ?</p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"442\" src=\"/storage/blog-images/Passivite.jpg\" alt=\"Agressivite \" title=\"Passivité\">\n<h2>Les 4 styles de communication</h2>\n<p>Les autres modes de communication existants ne sont en général pas adaptés et viennent très souvent d’une faible confiance en soi. Cependant, vous pouvez manquer de confiance en vous dans tel domaine et apparaître très confiant dans un autre. Le comportement inadéquat se retrouvera donc plus particulièrement dans la branche où vous manquez de confiance. Parfois, c’est un manque de confiance en soi général qui peut frapper une personne. Dans ce cas, elle présentera très souvent une attitude inadaptée. </p>\n<p>Heureusement, une personne peut changer de comportement, car autrement, elle ne pourrait pas apprendre à s’affirmer. Mais quelquefois, elle peut apparaître très passive à la base puis d’un seul coup, adopter une conduite agressive régulière, du fait d’en avoir assez de ne plus se faire respecter. </p>\n<p>C’est d’ailleurs souvent lorsque vous adoptez un mauvais comportement que vous vous en prenez à nos proches. Ils sont généralement des boucs émissaires, puisque vous n’osez pas clairement exprimer votre frustration à la personne concernée. Il est donc temps de ne plus faire trinquer vos proches de vos humeurs maussades en réalisant les actions nécessaires. </p>\n<h3>La communication passive </h3>\n<p>Une personne passive n’ose pas dire ce qu’elle pense, de peur d’être rejetée. Bien souvent, les gens la pensent timide et sans caractère. Sa discrétion fera que quelquefois, ils oublieront même son existence ou la prendront en pitié.</p>\n<p>Le conflit demeure en outre insupportable pour elle. Cette peur peut provenir de croyances erronées. Par exemple, si elle demandait à son voisin de faire moins de bruit, elle passerait pour une personne agressive. Dans ce cas,<a href=\"/croyances\" target=\"_blank\" rel=\"noopener\" title=\"Croyances\"> son schéma de pensées</a> est à revoir. </p>\n<p>Cet individu n’osera d’ailleurs jamais dire non. Cette attitude peut donc déclencher, au travail par exemple, un burn-out. </p>\n<p>Cependant, un individu passif peut se mettre à opter pour le comportement agressif s’il en a assez de ne pas se faire respecter. Ce changement d’attitude arrive de plus souvent.</p>\n<h3>La communication agressive </h3>\n<p>Quand une personne est agressive, elle défend ses idées, ce qui est déjà un bon début. Cependant, elle ne prend pas en compte les sentiments de l’autre et ainsi, empiète sur ses droits. Par conséquent, elle peut devenir égoïste et ne penser qu’à ses droits, sans se soucier d’autrui. </p>\n<p>Bien souvent, un individu agressif aura un problème d’ego et aura donc du mal à vouloir changer de comportement. Il pense en effet qu’être offensif permet de se sentir supérieur et plus important que l’autre. Il remarque qu’avec cette attitude, il est beaucoup plus respecté et que les gens évitent de le chercher. Cependant, ce qu’il croit être du respect est plutôt de la peur ou du dégoût à son encontre. </p>\n<p>Car à force d’être constamment sur la défensive, l’agressif se rendra compte, au fil du temps, que les personnes l’esquivent de plus en plus. En effet, le fait d’être méchant n’aide pas à faire venir autrui vers soi. Il n’y a d’ailleurs pas de mystère. Les gens se comportent avec vous comme vous vous comportez avec eux. Aimeriez-vous passer du temps avec une personne qui vous parle toujours mal ? J’en doute. Il y a donc lieu de travailler sur cette croyance.</p>\n<a href=\"https://hypnocaments.com?partnerid=YK5muYugzSoIWDbDWRgT-Q\" title=\"Seances d hypnose en ligne\"><img decoding=\"async\" src=\"https://hypnocaments.com/image/banner_1_750.png\" alt=\"seance hypnose mp3\"></a>\n<h3>Le comportement passif-agressif </h3>\n<p>Il s’agit d’un mixte entre les deux premiers comportements. La personne apparaît passive, dans le sens où elle n’ose pas exprimer son mécontentement. Mais elle présente également un côté agressif, car elle ne souhaite tout de même pas se laisser faire et entreprend des actions pour ce faire. Cependant, ces actions ne sont pas bien comprises par autrui, étant donné qu’elles sont effectuées de manière indirecte. C’est un peu comme lancer constamment des piques à quelqu’un qui ne comprend pas vraiment pourquoi. La situation ne risque pas de s’améliorer si une conversation franche n’a pas lieu. </p>\n<p>Par exemple, un salarié peut être mécontent de la façon dont son patron le traite. En guise de rébellion, si son supérieur lui donne un dossier assez important à terminer, il va le faire traîner volontairement. </p>\n<h3>Le comportement du manipulateur</h3>\n<p>Le souhait d’un manipulateur est de toujours arriver à ses fins et il n’hésitera pas à utiliser des personnes pour ce faire, qu’il considère d’ailleurs comme ses objets. Il est très égoïste et intelligent. En général, son petit jeu marche très bien un certain temps, car cet individu passe habituellement très bien aux yeux d’autrui. Il est souriant, s’adapte à la personnalité de l’autre, est poli, charmant.</p>\n<p>Cependant, à force de mensonges et de manipulations, les gens commenceront à douter de sa sincérité. Quand cette personne sera démasquée, les gens ne lui feront plus confiance et s’en éloigneront. Son masque étant tombé, le calculateur pourra commencer à devenir agressif.</p>\n<img decoding=\"async\" width=\"640\" height=\"426\" src=\"/storage/blog-images/4-styles-communication.png\" alt=\"Manipulation\" title=\"4-styles-communication\">\n<h2>Comment s’affirmer ?  </h2>\n<p>Étant donné que l’affirmation de soi reste un comportement qui s’apprend, je vais vous donner quelques clés pour vous y aider.</p>\n<h3>Apprendre à dire non sans se justifier </h3>\n<p>Écouter vos besoins est primordial pour votre bien-être, et tant pis si les autres ne le comprennent pas. </p>\n<p>Prenons un exemple. Vous avez prévu de passer un vendredi soir chez vous à vous relaxer. Cependant, vous êtes invité par un ami, mais n’avez ni l’envie ni l’énergie d’y aller. Bien souvent, dans ces cas-là, les personnes osent dire non, mais mentent. Le problème avec le mensonge, c’est que l’individu va toujours trouver des contre-arguments à ce que vous avancez. « tu fais régime ? Ok, quels aliments souhaites-tu que je te prépare ? » </p>\n<p>Tandis que si vous êtes sincère en restant ferme dans votre décision, la personne ne pourra plus rien vous rétorquer. Si vous dites la vérité dans le respect de l’autre, comme « ce soir, je suis trop fatigué et je n’ai vraiment pas envie », que voulez-vous que la personne vous réponde ? Si elle se vexe, tant pis, vous n’avez pas à prendre la responsabilité de ses émotions. Agir en se vexant signifie qu’elle est un peu égoïste et qu’elle ne respecte pas vos besoins.</p>\n<p>L’homme libre ose exprimer ses besoins sans se justifier. Pour apprendre à devenir souverain de son existence, il va falloir apprendre à vous libérer du <a href=\"/jugement-des-autres\" target=\"_blank\" rel=\"noopener\" title=\"Jugement des autres \">regard de l’autre.</a> Avant d’être bien avec les autres, il faut être bien avec soi-même. Comment être bien avec vous-même si vous n’écoutez pas vos importants ? Il ne s’agit pas d’égoïsme. L’égocentrisme signifie faire ce que l’on veut, mais en portant préjudice à l’autre, en l’écrasant. De toute manière, quoi que vous fassiez, vous ferez forcément des mécontents. Autant alors faire ce que vous voulez vraiment, non ? </p>\n<p>Et si vous souhaitez un coup de main pour vous libérer du jugement des autres, je vous conseille vivement le programme de Didier PENISSARD, coach, auteur et conférencier dans le domaine du développement personnel. N’hésitez pas à aller le découvrir en cliquant sur le bouton ci-dessous :</p>\n<h3>Corriger sa posture et le ton de sa voix</h3>\n<p>Le premier élément qu’un individu juge chez l’autre, c’est son apparence. Nous le faisons d’ailleurs tous et c’est tout à fait normal, vu que nous ne connaissons pas de prime abord la personne. Et il faut bien avouer que bon nombre de caractéristiques se voient directement par rapport à la posture de la personne.</p>\n<p>Par exemple, vous voyez débarquer quelqu’un avec la tête baissée, le dos courbé, parlant doucement et ayant une démarche nonchalante. Vous vous doutez que cet individu n’a pas une très bonne estime de lui. </p>\n<p>Tandis que vous apercevez un individu souriant, avec un regard franc (mais non hostile), une voix affirmative, se tenant bien droit et avec le pas assuré. Vous pensez à coup sûr qu’il a confiance en lui.</p>\n<p>Il est donc important de prendre conscience de la façon de vous tenir, de marcher et de vous exprimer afin de pouvoir modifier ce qui ne va pas. Car si une bonne estime de soi se reflète dans la posture, le ton de la voix, etc., le cas inverse est vrai également. C’est-à-dire que s’entraîner à vous tenir correctement peut vous faire vous sentir mieux. </p>\n<h3>Comprendre que les autres ne se trouvent pas dans votre tête </h3>\n<p>Même si un proche vous connaît bien, il ne se trouve pas dans votre tête. Par exemple, si vous rentrez et que le dîner ne semble pas prêt alors que votre mari se trouvait à la maison et que vous le prenez très mal, il va falloir le lui dire. Il n’est pas censé savoir que vous n’allez pas apprécier. Il n’est pas bon de trop faire de suppositions. Vous exprimer de manière claire évitera ainsi bien des conflits, au lieu de penser que le proche aurait dû deviner votre pensée. Car il ne se trouve pas dans notre tête, tout comme vous ne vous trouvez pas dans la sienne. Arrêtez donc la divination et exprimez-vous convenablement.</p>\n<h3>Comprendre qu’il n’est pas bon de toujours tout dire  </h3>\n<p>Pendant longtemps, j’ai cru que dire tout ce que l’on pensait à la personne concernée était une preuve de franchise. Or, j’ai compris par la suite qu’il n’était pas toujours bon de tout exprimer. En effet, bien qu’il faille vous exprimer afin de vous faire respecter, si certains éléments ne nous concernent pas directement, pas besoin de les exprimer à tout va. Par exemple, si votre sœur n’a pas, selon vous, de très bons goûts vestimentaires, inutile de le lui notifier. En fait, il vaut mieux garder pour soi tout ce qui peut blesser inutilement les autres, sauf si une situation empiète sur votre propre bien-être. Il faut apprendre à respecter les autres dans leurs qualités et leurs défauts, qui peuvent être différents des nôtres.</p>\n<h3>Utiliser le « je » lors d’une confrontation avec l’autre </h3>\n<p>Quand vous décidez de vous confronter à une personne par rapport à un comportement de sa part qui vous déplaît et vous porte préjudice, c’est un bon début. Attention cependant à la manière dont vous l’exprimez. Il faut en réalité toujours employer le « je » en exprimant votre ressenti, plutôt que d’utiliser le « tu » qui accuse l’autre, lui donnant la sensation d’être attaqué et agressé. La façon de vous exprimer aura donc un impact sur la réaction de l’autre. Par exemple, si vous dites : « tu es complètement idiot », votre propos n’aura forcément pas le même impact que si vous prononcez cette phrase : « j’ai trouvé ton comportement stupide cet après-midi ». Vous ne trouvez pas ?</p>\n<p> </p>\n<p>Voici les principales méthodes qui vous aideront à vous affirmer. Ce chemin ne sera pas toujours facile, mais dès lors que vous avez compris<b> l’importance de l’affirmation de soi,</b> vous savez que le jeu en vaut la chandelle. </p>\n<p> </p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'L’Importance de l’Affirmation de Soi pour s’Epanouir','L’importance de l’affirmation de soi n’est plus à démontrer. Ce mode de communication peut s\'apprendre. Et si vous vous mettiez à vous affirmer ?','https://vivre-pleinement.fr/affirmation-de-soi/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/affirmation-de-soi\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/affirmation-de-soi\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"L\\u2019Importance de l\\u2019Affirmation de Soi pour s\\u2019Epanouir\",\"datePublished\":\"2019-10-27T13:54:22+00:00\",\"dateModified\":\"2024-02-12T19:37:10+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/affirmation-de-soi\\/\"},\"wordCount\":4779,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/affirmation-de-soi\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/10\\/Importance-affirmation-soi.jpg\",\"articleSection\":[\"D\\u00e9veloppement personnel\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/affirmation-de-soi\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/affirmation-de-soi\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/affirmation-de-soi\\/\",\"name\":\"L\\u2019Importance de l\\u2019Affirmation de Soi pour s\\u2019Epanouir\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/affirmation-de-soi\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/affirmation-de-soi\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/10\\/Importance-affirmation-soi.jpg\",\"datePublished\":\"2019-10-27T13:54:22+00:00\",\"dateModified\":\"2024-02-12T19:37:10+00:00\",\"description\":\"L\\u2019importance de l\\u2019affirmation de soi n\\u2019est plus \\u00e0 d\\u00e9montrer. Ce mode de communication peut s\'apprendre. Et si vous vous mettiez \\u00e0 vous affirmer\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/affirmation-de-soi\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/affirmation-de-soi\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/affirmation-de-soi\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/10\\/Importance-affirmation-soi.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/10\\/Importance-affirmation-soi.jpg\",\"width\":640,\"height\":426,\"caption\":\"Comprendre l\'importance de l\\u2019affirmation de soi\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/affirmation-de-soi\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"L\\u2019Importance de l\\u2019Affirmation de Soi pour s\\u2019Epanouir\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-10-27 13:54:22',NULL,'2026-05-24 19:19:45','2026-06-19 22:28:14');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (48,'Évacuer sa Colère Intérieure pour Retrouver le Bien-être','colere','La colère reste une émotion naturelle et si elle existe, c’est qu’elle possède un intérêt pour la survie de l’espèce. Là où le bât blesse, c’est quand l’individu n’arrive plus à la maîtriser, ce qui nuit donc à son bien-être, mais également à ceux des autres. La colère peut en effet avoir de lourdes conséquences, aussi bien physiques que mentales, si elle n’est pas maîtrisée. Lorsqu’une personne vous regarde dans la rue, vous vous sentez tout de suite agressé. Vous devenez hystérique sur la route dès qu’une voiture vous passe devant. Si vous êtes énervé envers une personne, vous avez envie de lui faire mal autant qu’elle vous a fait souffrir. Votre colère vous empoisonne l’existence ? Comment évacuer sa colère intérieure ? \n','<p>La colère reste une émotion <b>naturelle</b> et si elle existe, c’est qu’elle possède un <b>intérêt </b>pour la survie de l’espèce. Là où le bât blesse, c’est quand l’individu n’arrive plus à la <b>maîtriser</b>, ce qui nuit donc à son <b>bien-être, </b>mais également à ceux des <b>autres</b>. La colère peut en effet avoir de lourdes conséquences, aussi bien <b>physiques </b>que <b>mentales</b>, si elle n’est pas maîtrisée. Lorsqu’une personne vous regarde dans la rue, vous vous sentez tout de suite <b>agressé</b>. Vous devenez <b>hystérique </b>sur la route dès qu’une <b>voiture </b>vous passe devant. Si vous êtes énervé envers une personne, vous avez envie de lui faire <b>mal autant </b>qu’elle vous a fait souffrir. Votre colère vous <b>empoisonne </b>l’existence ? Comment <b>évacuer sa colère intérieure ? </b></p>\n<h2>Qu’est-ce que la colère ?</h2>\n<p>La colère reste une émotion instinctive chez l’être humain. Il s’agit d’une émotion reptilienne, primitive, qui reflète la facette animale de l’homme. Elle est donc normale.</p>\n<p>La colère peut poser problème lorsque vous n’arrivez plus à la contrôler. Dans ce cas, vous pouvez commencer à ressentir de la haine et l’exprimer en pleine figure à votre interlocuteur. Des agressions verbales, voire physiques, peuvent ainsi apparaître. À ce stade, vous avez perdu tout votre côté rationnel. </p>\n<p>Vous avez déjà dû en faire l’expérience. Quand vous êtes énervé, il n’est pas toujours bon de vous exprimer directement, au risque de le regretter plus tard. </p>\n<p>Enfin, il faut savoir que la colère peut revêtir différentes formes. Elle possède également différents degrés. La colère peut donc aller de la simple irritabilité à une rage folle et incontrôlable. Elle peut aussi prendre la forme d’une rancune, de la <a href=\"/je-suis-jaloux\" target=\"_blank\" rel=\"noopener\" title=\"Je suis jaloux\">jalousie</a>, etc.</p>\n<h2>Liens entre irascibilité et troubles anxieux  </h2>\n<p>Si une personne colérique n’est pas forcément anxieuse, on retrouve tout de même ces deux critères chez bon nombre d’individus.</p>\n<p>Bien souvent, les personnes souffrant de troubles anxieux ne sont pas comprises par l’entourage. Elles peuvent donc commencer à éprouver de la colère face à l’incompréhension de leurs proches. En effet, ils peuvent faire passer, comme message subliminal, que l’anxiété n’est que psychologique et qu’il suffit d’un peu de volonté pour la faire disparaître.</p>\n<p>De plus, la personne souffrant de troubles anxieux peut vraiment se sentir démoralisée de ne pas arriver à aller mieux. Effectivement, une anxiété quotidienne diminue l’énergie de l’individu de façon considérable, lequel se sentira donc beaucoup plus souvent fatigué que la moyenne. Cette fatigue, ce découragement et cette impuissance peuvent alors déclencher la colère.</p>\n<p>Enfin, un individu en colère peut ressentir des symptômes impressionnants, se rapprochant de la crise d’angoisse. </p>\n<h2>Les symptômes de la colère </h2>\n<p>La colère, comme toute émotion négative, peut déclencher divers symptômes désagréables. Voici les principaux symptômes : </p>\n<h3>Symptômes physiques </h3>\n<p>– Palpitations ;</p>\n<p>– Bouffées de chaleur ; </p>\n<p>– Oppression de la cage thoracique ;</p>\n<p>– Fourmillements ;</p>\n<p>– Vertiges ;</p>\n<p>– Difficultés à respirer ;</p>\n<p>– Tremblements ;</p>\n<p>– Sueur ;</p>\n<p>– Gorge sèche ; </p>\n<p>– Fait d’élever la voix ;</p>\n<p>– Crispation ;</p>\n<p>– Front plissé ;</p>\n<p>– Yeux exorbités.</p>\n<h3>Symptômes émotionnels </h3>\n<p>– Panique ;</p>\n<p>– Sentiment de perdre le contrôle.</p>\n<p> </p>\n<p>Ces symptômes se rapprochent donc bien de ceux décrivant la crise d’angoisse dans le cas d’une personne atteinte de troubles anxieux.</p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"435\" src=\"/storage/blog-images/Agressivite.png\" alt=\"Fureur\" title=\"Agressivité\">\n<h2>Les conséquences de la colère sont plus graves que ses causes  </h2>\n<p>La colère reste une émotion normale et saine lorsqu’elle est maîtrisée par l’individu. Cependant, si vous n’arrivez pas à la maîtriser, les conséquences qui s’en suivront pourront s’avérer délicates. </p>\n<p>Bien souvent, quand un individu est énervé contre quelqu’un, il n’ose pas lui en parler directement. Il va généralement s’énerver et critiquer ladite personne à un tiers. Ce comportement, en plus d’entretenir la colère, ne résoudra pas le conflit.</p>\n<p>De plus, en contenant sa colère auprès de la personne concernée, le risque est de la reporter sur autrui, qui n’aura rien demandé ! Ce mécanisme s’appelle la goutte qui fait déborder le vase et malheureusement, il s’enclenche fréquemment contre la mauvaise personne. Imaginez le sentiment d’injustice que l’individu peut développer à votre égard ! Le danger demeure donc de blesser inutilement des personnes et de vous faire, par la même occasion, des ennemis.</p>\n<p>Plus grave encore, vous pouvez vraiment perdre le contrôle au point d’infliger des blessures physiques à autrui. Cette attitude peut avoir de lourdes conséquences par la suite que vous regretterez au plus haut point, telles que plainte portée à votre encontre, problèmes judiciaires, etc.</p>\n<h2>Refouler son agressivité   </h2>\n<p>Quelquefois, vous pourrez observer que certaines personnes semblent maîtriser leurs émotions de sorte que rien ne semble les atteindre. Elles ne se mettent jamais en colère. Tout a l’air de leur passer au-dessus de la tête. Elles apparaissent calmes et sereines. Toujours aimables avec autrui. Je pense que vous en connaissez, des personnes se comportant ainsi ? À moins qu’il s’agisse de vous ? </p>\n<p>En réalité, si certaines personnes apparaissent effectivement plus sages, il s’agit bien souvent d’une façade. En effet, la colère restant une émotion naturelle, il est obligatoire de la ressentir de temps à autre. Le tout reste de l’exprimer fermement et dans le respect d’autrui. </p>\n<p>Donc, si une personne prétend ne jamais éprouver de colère, c’est impossible. Elle vous ment. Elle refoule tout simplement cette émotion, car on lui a sûrement appris dès l’enfance que ne pas gérer ses émotions paraissait pour de la sauvagerie et que ce n’était pas digne d’une personne « classe ». </p>\n<p>Cette personne peut également refouler son agressivité de peur de passer pour une personne méchante et de ce fait, de ne plus être aimée. Peut-être qu’une peur de l’abandon se cache derrière ce sentiment ?</p>\n<p>Par conséquent, inhiber sa colère apparaît tout aussi toxique que de ne pas savoir la maîtriser. De plus, <a href=\"/le-mal-a-dit\" target=\"_blank\" rel=\"noopener\" title=\"Le mal a dit \">refouler ses émotions</a> et les nier n’est jamais bon pour le corps. En effet, il a besoin de les sortir afin de ne pas les imprimer en lui. Autrement, le risque est, à la longue, d’attraper des maladies.</p>\n<h2>Le piège de la fureur</h2>\n<p>Quelquefois, certaines personnes colériques ne veulent tout simplement pas apprendre à maîtriser leur colère, du fait de leurs croyances. En effet, certains individus croient dur comme fer qu’exprimer leur agressivité les fait passer pour des personnes à fort caractère, qui ne se laissent pas faire. Elles sont en réalité fières de leur colère. Donc forcément, pourquoi vouloir la changer ?</p>\n<p>Sauf que ce genre de croyances apparaît erroné. Penser de la sorte n’aide pas à l’apparition de croyances bénéfiques. Car s’énerver aussi promptement cache une blessure et une vulnérabilité chez la personne. Certains individus ne seront ainsi pas dupes et ne vous percevront pas nécessairement comme vous aimeriez qu’ils vous perçoivent. </p>\n<p>Et de plus, demeurer colérique et agressif avec les gens ne vous amènera pas leur considération. En effet, beaucoup confondent respect et admiration avec peur et dégoût, ce qui n’est pas du tout pareil. Vous obtenez forcément le retour de bâton. Une personne que vous agressez ou que vous tyrannisez ne pourra jamais vous admirer. Elle ne pourra éprouver que des émotions négatives à votre égard et jamais de la vie du respect. </p>\n<img decoding=\"async\" width=\"960\" height=\"717\" src=\"/storage/blog-images/Rage.jpg\" alt=\"Haine\" title=\"Rage\">\n<h2>Comment évacuer sa colère intérieure ?  </h2>\n<p>Voici maintenant les solutions pouvant être envisagées afin d’apprendre à maîtriser votre colère.</p>\n<h3>S’en aller un temps </h3>\n<p>En cas de conflit avec quelqu’un, si vous sentez vraiment que vous n’arrivez pas à maîtriser votre colère envers lui et que vous allez le regretter, il est préférable de quitter la pièce et d’aller prendre l’air. Ce n’est pas de la fuite. C’est tout simplement éviter la catastrophe. Une fois que vous vous serez calmé, une discussion plus sereine pourra avoir lieu avec votre interlocuteur. Réagir ainsi constitue une preuve d’intelligence de votre part. </p>\n<h3>Apprendre à bien respirer </h3>\n<p>Quand vous êtes en colère, vous pouvez diriger votre attention sur votre souffle en inspirant et expirant profondément. La respiration possède un effet très calmant, ralentissant progressivement l’organisme. Je vous laisse consulter mon <a href=\"/respiration\" target=\"_blank\" rel=\"noopener\" title=\"Respiration\">article</a> à ce sujet. </p>\n<p>Pour ma part, afin de bien respirer, je pratique la méthode de la cohérence cardiaque. J’utilise pour ce faire Zenspire, qui est un petit appareil émettant des vibrations et lumières pour m’aider à bien réguler ma respiration. Car oui, nous sommes très nombreux à ne plus savoir respirer correctement. Si vous êtes intéressé par ce produit que j’utilise tous les soirs, c’est juste ici, étant précisé que si vous passez commande, vous bénéficierez d’une remise immédiate de 10 % grâce au code JL0620 : </p>\n<h3>Rediriger son attention</h3>\n<p> </p>\n<p>Dès que vous sentez la colère monter, vous pouvez rediriger votre attention sur n’importe quoi d’autre. Le paysage si vous êtes à l’extérieur, les objets se trouvant dans votre champ de vision, vous remémorer un souvenir agréable, etc. finalement, sur tout ce qui peut vous distancier de l’objet de votre colère.  </p>\n<h3>Se confier </h3>\n<p> </p>\n<p>Vous confier à un membre de votre famille, un ami, un collègue, etc. sur l’objet de votre colère peut vous aider à vous calmer. Une écoute bienveillante peut en effet apparaître très utile. Attention cependant à ne pas vous attaquer à vos proches en vous confiant. N’oubliez pas qu’ils n’y peuvent rien ! </p>\n<h3>Accorder une place au rire </h3>\n<p> </p>\n<p>Si vous vous mettez en colère facilement, c’est peut-être que vous prenez la vie un peu trop au sérieux. Alors, pourquoi ne pas apprendre à rire de vous-même ? En vous respectant et sans vous humilier, bien entendu. Il s’agit en effet d’un bon outil pour faire retomber la tension. </p>\n<p>Aussi, essayez de sourire dans une situation où vous sentez l’agressivité monter, même si cette attitude peut paraître étrange pour votre interlocuteur si vous vous vous trouvez en plein conflit avec lui. Mais avez-vous déjà entendu quelqu’un s’énerver et sourire en même temps ? C’est impossible, n’est-ce pas ? Donc, apprenez à sourire et vous sentirez la tension diminuer. </p>\n<p>Dans la continuité, si vous sentez la colère arriver, pourquoi ne pas partir pour aller pratiquer une activité divertissante ? Rire et se mettre en colère sont en effet deux émotions incompatibles, pas vrai ?</p>\n<p>Enfin, si vous êtes en train d’avoir une discussion conflictuelle avec une personne, pourquoi ne pas l’imaginer d’un seul coup de manière amusante ? Par exemple, avec un nez de clown, toute nue, sur son toilette, etc. Difficile de garder votre sérieux dans ces conditions, non ?</p>\n<h3>Pratiquer des techniques de relaxation et des médecines alternatives </h3>\n<p>De nombreuses techniques de relaxation existent de nos jours. À vous d’essayer d’en pratiquer certaines et de voir lesquelles vous correspondent le mieux et vous apportent le plus de paix intérieure. Il peut s’agir de yoga, de méditation. Mais également de médecines alternatives telles que sophrologie, acupuncture, etc.</p>\n<h3>Pratiquer une activité physique régulière </h3>\n<p>Le sport stimule la production d’endorphines, lesquelles sont des hormones apportant calme et bien-être. De plus, pratiquer une activité sportive peut permettre à certaines personnes de maîtriser leur grande colère intérieure. Certaines se mettent à la boxe, par exemple, qui représente un moyen pour elles d’exprimer leur colère sans porter préjudice à autrui, puisqu’il s’agit d’une pratique encadrée et réglementée. </p>\n<h3>Prendre la responsabilité de sa colère </h3>\n<p>Prenons l’exemple d’une situation où une voiture passe devant vous en vous faisant une queue de poisson. Pourquoi certains laissent couler alors que d’autres explosent de rage, quitte à suivre l’autre véhicule ? Ce n’est donc pas l’évènement le problème, mais bien la perception que vous avez de cet évènement. Il faut bien comprendre que rien ni personne n’est la cause de votre colère. Il est facile d’accuser les éléments extérieurs. Mais malheureusement, tant que vous le ferez, vous n’arriverez pas à maîtriser votre agressivité, car la solution se trouve en vous. Vous devez prendre la responsabilité de votre colère. </p>\n<h3>Entreprendre une thérapie </h3>\n<p>Si votre colère vous pose vraiment de gros problèmes, il va falloir réaliser un travail plus en profondeur sur vous-même. Pour ce faire, vous pouvez vous faire aider par un professionnel de la santé. Les TCC peuvent bien fonctionner pour ce type d’émotion, notamment pour le côté cognitif. Car le thérapeute remettra en cause vos croyances néfastes vous faisant vivre de la colère en vue de les remplacer par d’autres plus bénéfiques. Cette thérapie vous aidera grandement à voir les choses différemment et avec plus de recul à l’avenir. </p>\n<h3>Apprendre à pardonner </h3>\n<p>Quelquefois, nous n’arrivez pas à passer outre votre colère, parce que vous avez un sentiment de <a href=\"/rancune-et-rancoeur\" target=\"_blank\" rel=\"noopener\" title=\"Rancune et rancoeur\">rancune</a> installé depuis bien longtemps vis-à-vis d’une personne. Cependant, vous ne pouvez continuer à vous ronger de l’intérieur ainsi. Par conséquent, il va falloir entamer un processus de pardon en y allant à votre rythme. Car il est évident que certaines situations restent plus faciles à pardonner que d’autres. Le pardon vous permettra de retrouver votre libre arbitre et ne plus être l’esclave de votre fureur.</p>\n<p> </p>\n<p><b>Évacuer sa colère intérieure </b>est donc possible et avec les conseils de cet article, vous allez y arriver ! </p>\n<p>(Si mon travail vous aide 🙂)</p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img loading=\"lazy\" decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n','published',1,'Évacuer sa Colère Intérieure pour Retrouver le Bien-être','La colère reste une émotion naturelle, mais elle peut aussi empoisonner l\'existence. Comment évacuer sa colère intérieure ?','https://vivre-pleinement.fr/colere/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/colere\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/colere\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"\\u00c9vacuer sa Col\\u00e8re Int\\u00e9rieure pour Retrouver le Bien-\\u00eatre\",\"datePublished\":\"2019-10-21T18:42:38+00:00\",\"dateModified\":\"2024-02-13T17:23:35+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/colere\\/\"},\"wordCount\":4598,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/colere\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/10\\/Evacuer-colere-interieure.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/colere\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/colere\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/colere\\/\",\"name\":\"\\u00c9vacuer sa Col\\u00e8re Int\\u00e9rieure pour Retrouver le Bien-\\u00eatre\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/colere\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/colere\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/10\\/Evacuer-colere-interieure.jpg\",\"datePublished\":\"2019-10-21T18:42:38+00:00\",\"dateModified\":\"2024-02-13T17:23:35+00:00\",\"description\":\"La col\\u00e8re reste une \\u00e9motion naturelle, mais elle peut aussi empoisonner l\'existence. Comment \\u00e9vacuer sa col\\u00e8re int\\u00e9rieure\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/colere\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/colere\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/colere\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/10\\/Evacuer-colere-interieure.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/10\\/Evacuer-colere-interieure.jpg\",\"width\":606,\"height\":640,\"caption\":\"Comment evacuer sa colere interieure ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/colere\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"\\u00c9vacuer sa Col\\u00e8re Int\\u00e9rieure pour Retrouver le Bien-\\u00eatre\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-10-21 18:42:38',NULL,'2026-05-24 19:19:45','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (49,'Changer son Système de Croyances afin d’Acquérir le Bien-être','croyances','Tout le monde possède des croyances. Le problème survient lorsqu’elles sont limitantes, limitant les capacités d’un individu. La plupart des troubles anxieux prennent racine dans des croyances limitantes. En effet, si la personne possède des croyances profondes néfastes à son égard, il va être difficile pour elle de s’estimer. Et il est certain que le manque d’estime de soi reste le terreau de tout mal-être psychologique. Vous vous sentez incapable d’entreprendre une certaine activité. Vous avez un peu de ventre. Votre rêve est d’obtenir un ventre plat, car à ce qu’il paraît, il s’agit du corps parfait. Vous vous trouvez inférieur aux autres. Des croyances ancrées vous gâchent la vie ? Comment changer son système de croyances ?\n','<p>Tout le monde possède des croyances. Le problème survient lorsqu’elles sont <b>limitantes</b>, limitant les <b>capacités</b> d’un individu. La plupart des<b> troubles anxieux </b>prennent <b>racine </b>dans des croyances limitantes. En effet, si la personne possède des croyances profondes néfastes à son égard, il va être difficile pour elle de <b>s’estimer.</b> Et il est certain que le manque d’estime de soi reste le terreau de tout mal-être psychologique. Vous vous sentez <b>incapable </b>d’entreprendre une certaine activité. Vous avez un peu de <b>ventre</b>. Votre rêve est d’obtenir un ventre <b>plat, </b>car à ce qu’il paraît, il s’agit du corps <b>parfait</b>. Vous vous trouvez <b>inférieur </b>aux autres. Des croyances ancrées vous <b>gâchent </b>la vie ? Comment <b>changer son système de croyances ?</b></p>\n<p></p>\n<h2>Qu’est-ce qu’une croyance en psychologie ? </h2>\n<p>Chaque personne possède ses propres croyances. Une croyance, à la base, n’est pas bonne ou mauvaise en soi. Une personne n’est donc pas supérieure à une autre si ses croyances se trouvent différentes.</p>\n<p>Par contre, certaines d’entre elles tirent l’individu vers le haut alors que d’autres deviennent de véritables blocages pour lui, l’empêchant d’évoluer et de vivre pleinement sa vie. Si, une croyance vous rend mal à l’aise, anxieux, triste, etc. c’est qu’elle est limitante et qu’il convient de la changer. Au contraire, si une croyance vous fait vous sentir bien, c’est que vous vous trouvez sur la bonne voie et que vous pouvez la garder.</p>\n<p>D’autre part, certaines croyances ne sont pas forcément cohérentes ou rationnelles. Je pense plus particulièrement au <a href=\"/toc-troubles-obsessionnels-compulsifs\" target=\"_blank\" rel=\"noopener\" title=\"Troubles obsessionnels compulsifs \">TOC superstitieux</a>, où le sujet croit que s’il ne réalise pas telle action, un malheur s’abattra sur lui et sa famille. Il ne peut s’empêcher de s’accrocher à sa croyance, même s’il sait, au fond, qu’elle est irrationnelle. </p>\n<p>Enfin, il faut savoir que les croyances erronées peuvent changer avec le temps et heureusement ! Sinon, personne ne pourrait évoluer ou se débarrasser de ses troubles. Après, il est vrai que plus une croyance est ancrée et plus il sera long et difficile de la remplacer. </p>\n<h2>Comment s’installent les croyances ? </h2>\n<p>Tout le monde possède donc des croyances. Cependant, elles ne s’enracinent pas toutes de la même manière. Voici ci-dessous les principales causes de l’apparition d’une croyance : </p>\n<h3>La culture </h3>\n<p>Elle demeure la cause la plus naturelle des croyances. En effet, qu’il s’agisse de tribus, de nations ou de régions, chacune d’entre elles a établi une normale sociale générale, pour laquelle ses habitants y adhèrent de façon naturelle. Notre culture nous fait apprendre une langue natale, célébrer certains évènements, établit des Lois propres à elle, etc. la personne possède donc une perception de l’existence par rapport à sa culture, son peuple natal. Ces croyances apparaîtront toutes naturelles pour elle. </p>\n<h3>L’environnement </h3>\n<p>L’environnement intervient sur une échelle bien plus petite que la culture. Mais c’est surtout là que bon nombre de croyances se mettent en place, lesquelles font apparaître la personnalité de l’individu. L’environnement premier d’une personne reste sa famille et plus particulièrement ses parents. Ce sont eux qui lui donneront une vision générale de la vie et qui l’éduqueront. Viennent ensuite les croyances provenant de l’école et des amis qu’il rencontre. Puis du conjoint, du travail, etc. le milieu touche l’individu de manière plus personnelle que la culture. </p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img fetchpriority=\"high\" decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h3>Un traumatisme </h3>\n<p>Ce qui peut faire apparaître une croyance bien souvent nuisible reste l’apparition d’un <a href=\"/traumatisme\" target=\"_blank\" rel=\"noopener\" title=\"Traumatisme\">traumatisme</a>. Il peut se déclencher suite à un trauma qu’une personne a vécu. Cette blessure peut provenir d’expériences passées dans l’enfance, ce qui renforcera encore plus la croyance, mais aussi dans n’importe quel moment de la vie d’un individu. Il peut s’agir d’un décès d’un proche, d’une maladie, d’un accident, etc. finalement, de tout ce qui peut chambouler de façon négative un individu. Chaque personne subira dans son existence un voire plusieurs traumas. Ce qui est logique, car la vie n’est pas un long fleuve tranquille, et ce, pour tout le monde. Cependant, si la personne n’arrive pas à le surmonter et y pense constamment, ce trauma peut devenir un schéma de pensée traumatique et donc, une croyance.</p>\n<h3>La répétition d’un comportement ou d’une situation </h3>\n<p>Ce type de croyance peut survenir à n’importe quel moment de la vie, du moment qu’il y a une répétition, mais principalement, au cours de l’enfance. Il s’agira bien souvent de l’éducation reçue qui fera adopter des comportements et des schémas de pensées répétitifs à l’enfant, lesquels deviendront une habitude et donc, une croyance. Elle peut ainsi être bénéfique comme néfaste. C’est d’ailleurs fréquemment dans l’enfance qu’apparaissent les premiers troubles anxieux et les phobies. Ils peuvent être dus, par exemple, aux phrases incessantes que peut prononcer un parent, telles que : le monde est dangereux, tu es fragile, si tu prends froid dehors tu vas attraper la mort ; etc.</p>\n<p>Il conviendra bien entendu de travailler sur vous afin de changer les croyances limitantes en les remplaçant par des croyances plus bénéfiques pour votre épanouissement.</p>\n<img decoding=\"async\" width=\"640\" height=\"378\" src=\"/storage/blog-images/Schema-pensees.jpg\" alt=\"Croyances limitatives \" title=\"Schéma-pensées\">\n<h2>Les croyances positives </h2>\n<p>Toutes les croyances bénéfiques vous tirent vers le haut, boostent votre <a href=\"/confiance-et-estime-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Estime de soi\">estime de vous,</a> vous permettent d’avancer dans la vie et vous font vous sentir bien quand vous y pensez. Qu’elles soient vraies ou fausses importe peu. L’essentiel, c’est de ressentir du bien-être.</p>\n<p>Par exemple, une personne peut croire fort au karma, à la roue qui tourne. Personne ne sait si ce concept est véridique. Mais une mère perdant son enfant pourra mieux s’en sortir si elle pense qu’il s’agit du karma par rapport à son ancienne existence qu’une maman ne croyant en rien du tout. Le sentiment de détresse ne sera pas le même. Dans le premier cas, la mère sera bien évidemment abattue. Cependant, elle pourra beaucoup plus rapidement faire son deuil en enclenchant plus vite le processus d’acceptation.</p>\n<p> </p>\n<h3>Les fausses croyances bénéfiques</h3>\n<p>Attention à certains cas. Quelquefois, vous pouvez penser avoir une croyance qui est bénéfique pour vous alors qu’il n’en est rien. </p>\n<p>Par exemple, vous pouvez tomber dans le piège de mouvements sectaires vous faisant adhérer à des croyances vous semblant bénéfiques alors que c’est tout le contraire. Dans ce cas, ce sont surtout vos proches qui se rendent compte que la situation se trouve anormale. Bien souvent, vous ne les écoutez pas et votre état général se dégrade. Car certaines sectes refusent même que la personne soigne une de ses maladies.</p>\n<p>De plus, attention à l’ego. Vous pouvez par exemple penser, au travail, que vous restez le meilleur et n’hésitez pas à écraser les autres. Vous aurez l’impression de vous sentir bien, d’avoir un faux sentiment de supériorité. Sauf qu’il ne s’agit pas d’un bon comportement et qu’il faudrait surtout vous remettre en question afin de ne pas continuer à blesser autrui. Effectivement, vous avez le droit de commettre des erreurs, c’est humain. Mais le plus important, c’est d’en prendre conscience en se remettant en question.</p>\n<h3>Comment reconnaître une croyance bénéfique ?</h3>\n<p>Quand vous possédez une croyance et que vous souhaitez savoir si vous devez la conserver ou la remplacer, vous pouvez vous poser les questions suivantes :</p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">Est-ce que je me sens bien quand je pense à cette croyance ?</li>\n<li aria-level=\"1\">Puis-je nuire aux autres avec cette croyance ?</li>\n<li aria-level=\"1\">Est-ce que cette croyance me fait avancer ?</li>\n<li aria-level=\"1\">Cette croyance augmente-t-elle l’estime que j’ai pour moi ?</li>\n<li aria-level=\"1\">Est-ce que cette croyance me permet d’accepter plus facilement les épreuves de l’existence ?</li>\n<li aria-level=\"1\">Cette croyance m’aide-t-elle à aimer la vie ?</li>\n<li aria-level=\"1\">Est-ce que je possède encore mon libre arbitre avec cette croyance ? </li>\n</ul>\n<h2>Les croyances limitantes</h2>\n<p>Les croyances limitantes représentent l’inverse des croyances bénéfiques… À partir du moment où elles vous tirent vers le bas, vous font manquer d’estime et de confiance en vous et vous font stagner dans la vie et vous handicapent. Vous vous sentez bien évidemment mal quand vous y pensez.</p>\n<p>Je vous invite donc à vous poser les questions du paragraphe plus haut afin d’être fixé sur le type de croyances que vous possédez. </p>\n<p>Je vais vous donner l’exemple d’une personne qui souffre de TOC. Elle a peur qu’il arrive une catastrophe à son enfant si elle ne retouche pas tel objet 30 fois.  </p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">Est-ce que je me sens bien quand je pense à cette croyance ? <i>Si je réalise cette action, j’éprouve un soulagement temporaire. L’angoisse revient très vite. Je ressens de l’anxiété pour cette croyance.</i></li>\n<li aria-level=\"1\">Puis-je nuire aux autres avec cette croyance ? <i>Pas directement. Cependant, si mes proches doivent participer à mes rituels, mon TOC peut porter préjudice à leur bien-être. </i></li>\n<li aria-level=\"1\">Est-ce que cette croyance me permet d’avancer ? <i>Non. Elle me fait perdre énormément de temps et me laisse dans un schéma répétitif. </i></li>\n<li aria-level=\"1\">Est-ce que cette croyance augmente l’estime que j’ai pour moi ? En aucune façon<i>. Car je me sens esclave de mes compulsions. </i></li>\n<li aria-level=\"1\">Est-ce que cette croyance me permet d’accepter plus facilement les épreuves de l’existence ? Nullement<i>. Elle montre surtout que j’ai une peur atroce qu’il arrive un drame à mon enfant. </i></li>\n<li aria-level=\"1\">Cette croyance m’aide-t-elle à aimer la vie ? <i>Non. Car elle entretient un sentiment d’angoisse permanent. Je me dis d’ailleurs souvent pourquoi moi et pas les autres ?</i><i> </i></li>\n<li aria-level=\"1\">Est-ce que je possède encore mon libre arbitre avec cette croyance ? Aucunement<i>. Je demeure esclave de mes rituels.</i></li>\n</ul>\n<img decoding=\"async\" width=\"640\" height=\"426\" src=\"/storage/blog-images/Croyances-limitantes.jpg\" alt=\"Croyances negatives \" title=\"Croyances limitantes\">\n<h2>Comment changer son système de croyances ? </h2>\n<p>Vous devrez débusquer au maximum vos croyances limitatives afin d’acquérir le bien-être. </p>\n<p>En effet, si vous n’en avez pas conscience, vous continuerez à toujours emprunter les mêmes chemins qui ne vous permettent pas d’avancer. Pour vous y aider, je vous invite à remplir le questionnaire ci-dessus. </p>\n<p>Ensuite, sachez que la nature a horreur du vide. Donc, vous ne pouvez pas juste dire : « j’ai pris conscience de ma croyance erronée, je vais pouvoir l’effacer. » Dites-vous bien que vous ne pourrez pas faire disparaître une croyance négative sans la remplacer par une nouvelle croyance plus positive. Autrement, elle reviendra automatiquement.</p>\n<p>Vous devez ainsi prendre de nouvelles habitudes, entreprendre des actions innovantes et adopter de nouveaux schémas de pensées. Sachez que rien ne s’effectuera du jour au lendemain. Vos croyances négatives elles-mêmes ne se sont pas installées en un claquement de doigts, mais par la faute de mauvaises habitudes de pensées et/ou de comportements. Il sera d’autant plus difficile de les faire disparaître si elles sont présentes depuis longtemps. Mais rien n’est impossible. Ne désespérez pas si vous rechutez quelquefois. Après tout, mieux vaut entreprendre des actions pour s’en sortir que ne rien accomplir du tout, non ?</p>\n<p>Si vous ne savez pas trop comment vous y prendre, vous pouvez entamer une psychothérapie comme la TCC, laquelle s’avère très utile pour remplacer votre système de croyance. Elle peut également s’accoupler avec une prise médicamenteuse si vraiment le changement apparaît trop difficile à réaliser pour vous. </p>\n<p>Je vous invite enfin à naviguer dans ma rubrique <a href=\"/category/developpement-personnel\" target=\"_blank\" rel=\"noopener\" title=\"Développement personnel\">« développement personnel »</a> qui pourra vous aider à acquérir de nouvelles croyances bénéfiques. Elle vous aidera aussi à développer un bel état d’esprit et un mental solide. </p>\n<p> </p>\n<p><b>Changer son système de croyances</b> est donc possible avec de la persévérance, des exercices pratiques et de la volonté. Vous verrez une vie nouvelle s’ouvrir à vous. Vos nouvelles valeurs et croyances vous feront voir l’existence avec optimisme, gratitude et bienveillance. </p>\n<p>(Si mon travail vous aide) 🙂</p>\n<a href=\"https://hypnocaments.com?partnerid=YK5muYugzSoIWDbDWRgT-Q\" title=\"Seances d hypnose en ligne\"><img decoding=\"async\" src=\"https://hypnocaments.com/image/banner_1_750.png\" alt=\"seance hypnose mp3\"></a>','published',1,'Changer son Système de Croyances afin d’Acquérir le Bien-être','Tout le monde possède des croyances. Le problème survient lorsqu’elles limitent les capacités d’un individu. Comment changer son système de croyances ?','https://vivre-pleinement.fr/croyances/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/croyances\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/croyances\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Changer son Syst\\u00e8me de Croyances afin d\\u2019Acqu\\u00e9rir le Bien-\\u00eatre\",\"datePublished\":\"2019-10-15T19:25:01+00:00\",\"dateModified\":\"2024-02-13T19:26:03+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/croyances\\/\"},\"wordCount\":3484,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/croyances\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/10\\/Changer-systeme-croyances.jpg\",\"articleSection\":[\"D\\u00e9veloppement personnel\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/croyances\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/croyances\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/croyances\\/\",\"name\":\"Changer son Syst\\u00e8me de Croyances afin d\\u2019Acqu\\u00e9rir le Bien-\\u00eatre\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/croyances\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/croyances\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/10\\/Changer-systeme-croyances.jpg\",\"datePublished\":\"2019-10-15T19:25:01+00:00\",\"dateModified\":\"2024-02-13T19:26:03+00:00\",\"description\":\"Tout le monde poss\\u00e8de des croyances. Le probl\\u00e8me survient lorsqu\\u2019elles limitent les capacit\\u00e9s d\\u2019un individu. Comment changer son syst\\u00e8me de croyances\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/croyances\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/croyances\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/croyances\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/10\\/Changer-systeme-croyances.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/10\\/Changer-systeme-croyances.jpg\",\"width\":640,\"height\":303,\"caption\":\"Comment changer son systeme de croyances ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/croyances\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Changer son Syst\\u00e8me de Croyances afin d\\u2019Acqu\\u00e9rir le Bien-\\u00eatre\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-10-15 19:25:01',NULL,'2026-05-24 19:19:45','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (50,'Sortir du Burn-out et Retrouver la Paix, c’est Possible','burn-out','Qui n’a jamais entendu parler du burn-out ? C’est un terme qui revient régulièrement, notamment dans le monde du travail. Il s’agit d’un trouble créé par la société moderne hyper-compétitrice et matérialiste possédant comme principale valeur l’argent. Il lui faut donc un rendement et une productivité toujours plus grands. De plus, l’ère actuelle n’aide pas l’individu à trouver du travail facilement comme autrefois. Tout le monde peut être concerné par le surmenage professionnel, notamment les employés d’entreprises, mais aussi les patrons. Un matin, vous devez vous lever pour aller travailler, mais… vous n’y arrivez pas. Vous pensez de plus en plus à votre métier pendant votre temps libre et ressentez une boule au ventre. Vous rentrez du travail de plus en plus tard. Votre job vous rend malade ? Comment sortir du burn-out ?\n','<p>Qui n’a jamais entendu parler du burn-out ? C’est un terme qui revient régulièrement, notamment dans le monde du <b>travail</b>. Il s’agit d’un trouble créé par la <b>société </b>moderne <b>hyper-compétitrice</b> et <b>matérialiste possédant</b> comme principale valeur <b>l’argent</b>. Il lui faut donc un rendement et une <b>productivité </b>toujours plus grands. De plus, l’ère actuelle n’aide pas l’individu à trouver du travail <b>facilement </b>comme autrefois. <b>Tout le monde</b> peut être concerné par le surmenage professionnel, notamment les employés d’entreprises, mais aussi les patrons. Un <b>matin</b>, vous devez vous <b>lever </b>pour aller travailler, mais… vous<b> n’y arrivez pas. </b>Vous <b>pensez </b>de plus en plus à votre métier pendant votre <b>temps libre </b>et ressentez une <b>boule au ventre</b>. Vous rentrez du travail de plus en plus <b>tard</b>. Votre job vous rend <b>malade </b>? Comment <b>sortir du burn-out ?</b></p>\n<h2>Qu’est-ce que le burn-out ?</h2>\n<p>Le burn-out peut toucher tous les domaines de la vie. On parle bien de burn-out parental. Cependant, dans cet article, nous nous attarderons plus particulièrement sur l’épuisement professionnel. </p>\n<h3>Les signes avant-coureurs du surmenage professionnel </h3>\n<p>Une personne salariée travaille dans un bureau. Si tout allait bien au début, elle voit bien que ses objectifs de travail se trouvent de plus en plus inatteignables et qu’elle n’arrive plus à se mettre à jour. Elle se sent submergée. Pour contrer ce problème, elle décide d’effectuer de plus en plus d’heures supplémentaires, fréquemment non rémunérées. De plus, elle ne parvient plus à trouver de soutien auprès de ses collègues, lesquels apparaissent d’humeur massacrante. Tout le monde commence à se tirer dans les pattes. Elle se distancie ainsi de ses collaborateurs afin de ne pas trop en souffrir. Et c’est pareil pour le patron, qui se trouve constamment dans un état d’esprit maussade, jamais satisfait et qui en met plein la figure à ses employés. Ils n’en font, d’après lui, jamais assez. </p>\n<p>Rien ne va plus dans son travail. Le travailleur comprend bien que le boss devient de plus en plus exigeant et que tout se transforme en course à la productivité. Il a cependant trop peur de se faire licencier s’il n’en fait pas assez. Il aimerait chercher un autre job, mais craint tomber sur pire que son poste actuel. Il sait qu’il est très difficile de trouver un emploi et commence à se sentir perdu. </p>\n<h3>L’arrivée du burn-out</h3>\n<p>Peu à peu, un cercle vicieux s’installe. C’est le début du burn-out. Le salarié commence à s’apercevoir d’une baisse de ses performances. On peut commencer à le lui reprocher. Lui qui avait une vie normale jusqu’alors se rend compte qu’il ne parvient plus à se ressourcer en dehors du travail. Le soir, il n’arrive pas à se détendre et pense au travail. Son week-end en pâtit et enfin, ses vacances. Mais cet employé continue avec bravoure d’affronter son job, de « survivre » émotionnellement. Jusqu’au jour où… son corps lâche, soit par une intense et soudaine <a href=\"/angoisse-stress-anxiete\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse stress anxiété\">crise de panique</a>, soit par une incapacité à se lever au réveil. Le burn-out s’est installé. </p>\n<h2>Les symptômes de l’épuisement professionnel </h2>\n<p>Afin que vous puissiez facilement savoir si vous êtes concerné par le burn-out, il convient de déceler rapidement les principaux symptômes pour pouvoir agir au plus vite.</p>\n<h3>Symptômes physiques </h3>\n<p>– Maladies de la peau (apparition de taches rouges, eczéma, etc.) ;</p>\n<p>– Palpitations ; </p>\n<p>– Tensions musculaires pouvant provoquer des migraines, maux de ventre et de dos très difficiles à supporter, pouvant amener à une baisse de productivité.</p>\n<h3>Symptômes mentaux et émotionnels </h3>\n<p>– Troubles alimentaires (ne plus réussir à se nourrir ou au contraire, trop manger) ; </p>\n<p>– Prise de substances telles qu’alcool, médicaments, etc. pour essayer de se détendre ; </p>\n<p>– Troubles du sommeil (<a href=\"/insomnie\" target=\"_blank\" rel=\"noopener\" title=\"Insomnie\">insomnies</a>) ; </p>\n<p>– Troubles sexuels ; </p>\n<p>– Difficultés à réaliser des tâches simples ou quotidiennes dues au manque de concentration ; </p>\n<p>– Baisse des capacités de travail ;</p>\n<p>– Pertes de mémoire ; </p>\n<p>– Indécision due à la faible estime de soi ; </p>\n<p>– Perte de confiance en soi ; </p>\n<p>– Pleurs ; </p>\n<p>– Fatigue physique anormale ; </p>\n<p>– Humeur maussade ; </p>\n<p>– Irritabilité ; </p>\n<p>– Angoisses, ruminations incessantes et idées noires pouvant aller parfois jusqu’au suicide ; </p>\n<p>– Absentéisme de plus en plus régulier.</p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"960\" height=\"678\" src=\"/storage/blog-images/Epuisement-emotionnel.jpg\" alt=\"Surmenage \" title=\"Epuisement-émotionnel\">\n<h2>Qui peut être concerné par le burn-out ?</h2>\n<p>Le burnout peut toucher tout le monde. Il faut dire que le contexte du travail d’aujourd’hui augmentent la probabilité de souffrir de ce problème. Normalement, si vous avez de bonnes conditions de travail, vous ne déclencherez pas de burn-out. Si vous occupez un emploi ardu ou inintéressant, vous pouvez compenser cette situation avec des collègues bienveillants et une bonne ambiance. Si vous n’avez cependant pas la chance d’avoir de bons collaborateurs, mais que vous êtes passionné par votre job, vous pourrez peut-être faire avec. Mais si vous ne détenez aucun des deux, attention au risque de burn-out. </p>\n<p>De plus, avoir un faible salaire et une grosse surcharge de travail peut empirer le problème. Certains patrons abusent de leurs salariés, les humilient afin d’oublier leur propre mal-être et ne les rémunèrent même pas de leurs heures supplémentaires. Ils demandent des objectifs à atteindre qu’ils savent eux-mêmes inatteignables. Si l’employé se sent malmené et dévalorisé en permanence, et ce, en étant tout le temps à 100 %, il n’arrivera plus à fonctionner sur le long terme. Il y a donc généralement un gros souci de management au sein de l’entreprise. Ce n’est ainsi bien souvent pas vous le problème, mais les conditions de travail.</p>\n<p>Le comble, c’est que les personnes sujettes au burn-out sont habituellement les meilleurs employés et les plus endurants au stress à la base. Ils se donnent en général à fond dans leur job, sont responsables et les patrons savent qu’ils peuvent leur faire confiance. Mais ils sont aussi très critiques et <a href=\"/perfectionnisme\" target=\"_blank\" rel=\"noopener\" title=\"Perfectionnisme\">perfectionnistes</a> envers eux-mêmes. Ces traits de caractère peuvent représenter un atout, mais lors de conditions de travail déplorables, ils peuvent devenir un véritable handicap.  </p>\n<h2>Les préjugés sur le burn-out </h2>\n<p>On pense souvent à tort que le burn-out ne concerne que des cadres, ayant un bon salaire, mais une charge de travail considérable, travaillant quasiment jour et nuit. Cependant, même des salariés touchant le SMIC peuvent subir une pression insoutenable dans leur job, une très mauvaise ambiance et une charge énorme de travail. Le syndrome d’épuisement professionnel peut concerner tout le monde, ouvriers, cadres et patrons et tous les corps de métiers.</p>\n<p>Il s’agit plutôt d’un état général de la société englobant piètre organisation, relations déplorables et trop grande quantité de travail voire même, poste inintéressant. En réalité, le point capital pouvant déclencher le burn-out reste sans aucun doute un management déplorable, voire inexistant. Car si bon management il y a, très peu de problèmes il y aura. </p>\n<h2>Les autres troubles pouvant être confondus avec le burn-out </h2>\n<p>Il y a lieu de ne pas confondre le burn-out avec d’autres troubles pouvant lui être associés. En effet, un bon diagnostic équivaut à trouver plus rapidement une bonne piste de guérison.</p>\n<h3>La dépression</h3>\n<p>Certains confondent le burn-out avec la dépression. Bien que les symptômes peuvent sembler similaires, il ne s’agit pas du même trouble. Le burn-out concerne un domaine particulier, fréquemment le milieu professionnel. Par conséquent, dès que la personne arrivera à améliorer le domaine touché, elle ira directement mieux. </p>\n<p>La dépression, quant à elle, touche les domaines de la vie en général. C’est un mal-être plus profond, lequel doit être pris en charge rapidement. Après, il est vrai qu’un épuisement émotionnel non traité peut mener à la dépression, au vu de la grande <a href=\"/fatigue-mentale\" target=\"_blank\" rel=\"noopener\" title=\"Fatigue mentale\">fatigue psychique</a> éprouvée et du stress chronique. C’est en effet la chronicité qui plongera la personne dans de mauvaises habitudes. Ces habitudes nocives impacteront d’abord son domaine, pour ensuite s’attaquer à tous les domaines de sa vie, ce qui pourra la rendre dépressive. </p>\n<h3>Le brown-out </h3>\n<p>Il y a également le brown out, assez proche du burn-out, mais pas tout à fait similaire. Il s’agit surtout d’un manque total de sens et d’intérêt pour son travail, conduisant la personne à se poser la question de son utilité au sein de l’entreprise. Le travail peut effectivement apparaître répétitif, mais aussi trop éloigné de ses valeurs personnelles. Cette personne ne parvient plus à vivre à l’encontre de ses valeurs. Elle ne veut pas vivre en ayant l’impression de perdre tout ce temps à se trouver inutile. Si elle n’entreprend aucune action curative, une dépression peut également commencer à s’installer. </p>\n<h3>Le bore-out </h3>\n<p>Le bore-out présente également des similarités avec ses pairs. Mais dans ce cas, il n’y aura généralement pas de stress, voire même, pas assez ! La personne n’a en effet pas assez de travail. Elle passe donc son temps à… regarder l’heure tourner. Et si vous avez déjà vécu cette situation, vous pouvez sûrement comprendre à quel point il peut être horrible de passer des journées entières ainsi. Bien évidemment également, si vous ne traitez pas ce mal-être, une dépression peut survenir. </p>\n<img decoding=\"async\" width=\"800\" height=\"529\" src=\"/storage/blog-images/Syndrome-epuisement-professionnel.jpg\" alt=\"Epuisement professionnel\" title=\"Syndrome-épuisement-professionnel\">\n<h2>Comment sortir du burn-out ?</h2>\n<p>Comme pour tout type de trouble, il existe des solutions pour se débarrasser de l’épuisement émotionnel. Il y aura des actions concrètes à réaliser, mais aussi un état d’esprit à acquérir. </p>\n<h3>La thérapie cognitivo-comportementale (TCC)</h3>\n<p> </p>\n<p>Les TCC sont les plus à même à vous aider à soigner ce problème. Le thérapeute va en effet vous donner des pistes pour voir l’existence autrement et modifier vos croyances négatives sur le travail et sur vous-même. Cette thérapie constituera un bon support pour vous permettre d’acquérir un meilleur état d’esprit et remonter la pente. Par contre, je ne pense pas qu’il soit nécessaire de coupler ladite thérapie avec des médicaments. En effet, comme précisé plus haut, si vous arrivez à gérer le domaine de votre vie qui ne vous satisfait pas, le burn-out et ses symptômes partiront d’eux-mêmes.</p>\n<h3>Posséder des à-côtés</h3>\n<p>Dans la vie, il vaut mieux ne pas tout miser sur un seul domaine, car s’il flanche, c’est tout votre être qui s’en trouve perturbé. Prenons une maman qui arrête de travailler, de voir du monde, de pratiquer des activités pour s’occuper pleinement de ses enfants. Elle est heureuse de mener cette existence qui ne tourne qu’autour de ses enfants. Seulement voilà, quand ils deviendront grands et feront leur vie, comment pensez-vous qu’elle réagira ? </p>\n<p>Ne misez donc pas tout sur un unique domaine même s’il vous apporte du bonheur. La vie demeure tellement imprévisible que si la situation changeait, vous seriez dévasté. Essayez de concilier travail, amour, amitié, activité, famille, etc. ainsi, si un plan de votre existence ne vous satisfait plus, en ayant du soutien et d’autres à-côtés tout aussi importants à vos yeux ou presque, vous remonterez la pente bien plus facilement. </p>\n<h3>Changer de travail </h3>\n<p>Quand vous acceptez un poste, vous acceptez son environnement. C’est vous qui devez vous adapter à lui et pas l’inverse. Vous ne détenez donc que très peu de marge de manœuvre et de maîtrise sur votre lieu de travail. </p>\n<p>Par conséquent, si vos collègues apparaissent infects, vous ne pourrez rien y faire. Et si votre patron l’est, encore moins ! Et si vous trouvez votre job insupportable, c’est pareil. Ainsi, si vous ne vous sentez vraiment pas bien dans cet environnement, vous n’aurez d’autre choix que de changer de travail. </p>\n<p>Cependant, vous pouvez avoir trop peur des conséquences que ce changement pourrait avoir, car vous vous dites que l’herbe ne sera sans doute pas plus verte ailleurs. Vous pensez également que si vous ne convenez pas à votre nouvel emploi, vous risquez le licenciement. Vous appréhendez de ne plus pouvoir nourrir votre famille et de finir à la rue. </p>\n<p>Si vous avez de très mauvaises conditions de travail, il sera très difficile d’en trouver de pires ailleurs, non ? Et si c’est le cas, vous pourrez toujours rechercher un job autre part ou vous mettre en arrêt de travail pour le faire.</p>\n<p>Dites-vous bien que vous ne nourrirez plus longtemps votre famille si vous continuez à tirer sur la corde. Le résultat sera que vous vous rendrez malade et que vous ne pourrez, à un moment donné, plus aller travailler. </p>\n<p>Alors, n’hésitez pas. Et ne pensez surtout pas au suicide. Aucune profession ne mérite que vous y laissiez votre vie ! Si vous vous sentez vraiment mal, mettez-vous en arrêt-maladie et allez consulter afin de déjà prendre plus de recul. Vous valez bien plus qu’un métier. Créez votre vie, intéressez-vous à d’autres domaines. L’existence est tellement vaste ! </p>\n<h3>Le travail n’est pas fait pour tout le monde </h3>\n<p>Je pense que le travail n’est pas fait pour tout le monde. En effet, au travail, les gens se mettent en mode « mon côté le plus déplaisant ». Ils cachent leurs émotions, car émotions et productivité n’apparaissent pas compatibles pour une société. </p>\n<p>Il vaut donc mieux pour vous que tout se passe toujours bien dans votre vie ! Effectivement, vous avez beau être le meilleur élément de la boîte, si vous faites, un jour, une dépression, vous deviendrez pour eux le plus mauvais et vous pourrez dire au revoir à l’entreprise. </p>\n<p>Le côté robotisation ne va ainsi pas à tout le monde. Je pense d’ailleurs aux personnes hypersensibles. Car ceux n’ayant aucun mal à écraser l’autre et demeurant très compétitifs arriveront peut-être plus à vivre dans la société et encore, mieux vaut pour eux que tout aille bien dans leur vie ! </p>\n<p>Je crois donc que de plus en plus de personnes peinent à supporter l’univers du travail. Et c’est normal, car, qu’on le veuille ou non, l’être humain est constamment soumis à des émotions. Par conséquent, si vous pensez que vous n’avez pas l’impression que le travail soit fait pour vous, vous n’êtes pas le seul à le penser ainsi. Vous n’êtes pas faible ou anormal. </p>\n<p> </p>\n<p>À vous maintenant de passer à l’action et de changer d’état d’esprit afin de <b>sortir du burn-out </b>! </p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'Sortir du Burn-out et Retrouver la Paix, c’est Possible','Tout le monde peut être concerné par le surmenage professionnel, employés comme patrons. Votre job vous rend malade ? Comment sortir du burn-out ?','https://vivre-pleinement.fr/burn-out/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/burn-out\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/burn-out\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Sortir du Burn-out et Retrouver la Paix, c\\u2019est Possible\",\"datePublished\":\"2019-10-04T19:22:23+00:00\",\"dateModified\":\"2024-02-13T17:24:54+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/burn-out\\/\"},\"wordCount\":4347,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/burn-out\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/10\\/Sortir-burn-out.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/burn-out\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/burn-out\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/burn-out\\/\",\"name\":\"Sortir du Burn-out et Retrouver la Paix, c\\u2019est Possible\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/burn-out\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/burn-out\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/10\\/Sortir-burn-out.jpg\",\"datePublished\":\"2019-10-04T19:22:23+00:00\",\"dateModified\":\"2024-02-13T17:24:54+00:00\",\"description\":\"Tout le monde peut \\u00eatre concern\\u00e9 par le surmenage professionnel, employ\\u00e9s comme patrons. Votre job vous rend malade\\u2009? Comment sortir du burn-out\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/burn-out\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/burn-out\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/burn-out\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/10\\/Sortir-burn-out.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/10\\/Sortir-burn-out.jpg\",\"width\":800,\"height\":450,\"caption\":\"Comment sortir du burn-out ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/burn-out\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Sortir du Burn-out et Retrouver la Paix, c\\u2019est Possible\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-10-04 19:22:23',NULL,'2026-05-24 19:19:45','2026-06-19 22:28:14');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (51,'Se Libérer de la Jalousie et de la Comparaison pour une Vie Sereine','se-comparer-aux-autres','Qui ne s’est jamais comparé aux autres ? La comparaison sociale demeure naturelle pour l’être humain. En effet, à des époques lointaines, c’était bien souvent l’homme le plus fort qui survivait et surtout, les individus respectant les normes. Les autres souhaitant se rebeller ou vivre à contre-courant périssaient fréquemment. Il est vrai que cette période apparaît révolue. Cependant, cette habitude est largement restée. Qui plus est, la société actuelle prônant la compétitivité et le fait de devoir être le meilleur à tout prix n’arrange rien. Votre ami a un travail mieux payé que le vôtre. Votre voisine est toute mince et pourtant, elle mange bien plus que vous. Vous pensez que votre copine a plus réussi que vous, puisqu’elle a fondé une famille et pas vous. Le sentiment de jalousie vous ronge ? Comment se libérer de la jalousie et de la comparaison ? \n','<p>Qui ne s’est jamais comparé aux autres ? La comparaison sociale demeure<b> naturelle </b>pour l’être humain. En effet, à des époques <b>lointaines</b>, c’était bien souvent l’homme le plus <b>fort </b>qui survivait et surtout, les individus respectant les <b>normes</b>. Les autres souhaitant se <b>rebeller </b>ou vivre à contre-courant <b>périssaient fréquemment</b>. Il est vrai que cette période apparaît <b>révolue</b>. Cependant, cette habitude est largement <b>restée</b>. Qui plus est, la <b>société </b>actuelle prônant la <b>compétitivité </b>et le fait de devoir être le meilleur à tout prix n’arrange rien. Votre ami a un <b>travail </b>mieux <b>payé </b>que le vôtre. Votre voisine est toute <b>mince </b>et pourtant, elle <b>mange </b>bien plus que vous. Vous pensez que votre copine a plus <b>réussi </b>que vous, puisqu’elle a fondé une <b>famille </b>et pas vous. Le sentiment de jalousie vous <b>ronge </b>? Comment <b>se libérer de la jalousie et de la comparaison ? </b></p>\n<h2>Pourquoi ne pas se comparer aux autres ?</h2>\n<p>Il nous est déjà tous arrivé de nous comparer à autrui. Mais bien souvent, nous ne le faisons pas de la bonne manière. Nous pensons être inférieurs à telle personne dans tel domaine et ne faisons rien pour y remédier, mis à part demeurer envieux et perdre sa confiance.  </p>\n<p>N’est-ce pas une grande perte de temps pour vous de réagir ainsi ? Plutôt qu’essayer de réaliser des actions concrètes afin d’évoluer, vous vous plaignez de votre infériorité par rapport à l’autre. Le temps que vous passez à <a href=\"/ruminations\" target=\"_blank\" rel=\"noopener\" title=\"Ruminations\">ruminer</a> n’est donc pas utilisé pour entreprendre une action constructive. Le temps est précieux alors s’il vous plaît, ne le passez pas à vous dévaloriser. </p>\n<p>La dévalorisation de soi baisse de plus en plus votre estime de vous et vous fait perdre toute confiance en vous. Vous devez posséder à la base une faible estime de vous-même pour vous comparer sans arrêt négativement. Le souci, c’est qu’avoir une très basse estime de soi engendre d’importantes difficultés dans la vie. C’est d’ailleurs, pour moi, le problème principal dans tout type de trouble, qui ne pourra que vous faire rater de grandes opportunités dans votre existence.</p>\n<p>Enfin, le fait de vous comparer négativement à vos pairs vous fait ressentir des émotions négatives vis-à-vis d’eux, comme une <a href=\"/je-suis-jaloux\" target=\"_blank\" rel=\"noopener\" title=\"Je suis jaloux\">grande jalousie</a>, de la colère, du ressentiment, de la culpabilité, etc. Et croyez-moi, entretenir ce genre de sentiments sur le long terme peut s’avérer destructeur. </p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"640\" src=\"/storage/blog-images/Envie.jpg\" alt=\"Rivalite \" title=\"Envie\">\n<h2>Pourquoi est-ce inutile de se comparer aux autres ? </h2>\n<p>Vous avez donc compris que, sauf en cas de comparaison saine (voir paragraphe un peu plus bas), vous comparer à autrui ne vous apportera rien. Vous vous sentirez juste mal dans votre peau. Je vais maintenant vous indiquer pourquoi il est vain de vous comparer à vos semblables.</p>\n<h3>Tout le monde est différent</h3>\n<p>Chacun possède sa propre perception de l’existence et du bonheur. Certaines personnes apparaissent très matérialistes et possèdent des biens hors de prix. D’autres ne le sont pas et s’adonnent plus à des activités créatives ou spirituelles. Mais ces individus ne sont pas mieux ou moins bien que les autres. Ils se trouvent juste opposés. </p>\n<p>Par conséquent, tant que vous vivez en adéquation avec ce qui vous rend heureux, c’est tout bon, et ce, même si vous ne suivez pas les normes. Il est donc inutile d’essayer de vivre de la pareillement que la plupart des personnes de la société si cette façon de vivre ne vous apporte pas de bonheur. Personne ne va vous exterminer. Vous ne vivez plus dans des temps reculés. Alors, vivez ! Mis à part le <a href=\"/jugement-des-autres\" target=\"_blank\" rel=\"noopener\" title=\"Jugement des autres\">jugement des autres</a>, que risquez-vous ? Et de toute manière, dites-vous bien que tout le monde critique tout le monde, et ce, même si vous feignez d’être dans les normes. </p>\n<p>D’ailleurs, si vous avez du mal à supporter le <strong>jugement des autres,</strong> je vous suggère le <strong>programme</strong> de <strong>Didier PENISSARD, coach, auteur et conférencier</strong> dans le domaine du <strong>développement personnel.</strong> Pour aller plus loin donc, c’est juste ci-dessous : </p>\n<h3>Certains ont plus de chance que d’autres </h3>\n<p>Il est vrai que nous ne naissons pas tous égaux. Dans des temps lointains, personne ne se posait vraiment de questions par rapport à son existence. Le fils du roi prenait sa place, le garçon d’un forgeron reprenait son magasin, etc. l’avenir de quelqu’un était plus ou moins tracé dès la naissance. Cependant, nous sommes maintenant plus libres de nos mouvements. Un enfant de roturier peut très bien devenir une star, un fils d’homme richissime peut sombrer dans la débauche et la pauvreté… Nous avons plus la possibilité d’être acteurs de nos vies qu’auparavant. </p>\n<p>Après, il est vrai qu’il sera beaucoup plus difficile pour une personne roturière de devenir célèbre qu’un individu avec des parents eux-mêmes célèbres. Voilà pourquoi je dis que nous ne sommes pas tous égaux. Donc oui, certaines personnes ont plus de chances que d’autres, c’est un fait. Certaines situations peuvent même sembler injustes. Inutile de le nier ou de s’en morfondre. Il faut accepter que dans certains domaines, vous devrez travailler beaucoup, beaucoup, beaucoup plus que d’autres. Mais dites-vous bien que rien n’est impossible. Vous pouvez accéder au niveau de cette personne. Ne trouvez-vous pas que vous aurez beaucoup plus de mérite d’atteindre vos rêves en vous en étant donné les moyens plutôt que de naître avec une cuillère en argent dans la bouche ?</p>\n<h3>On ne connaît pas les autres</h3>\n<p>Vous enviez le mari de votre amie, qui a l’air extraordinaire. Ou le salaire de votre frère. Et les enfants de votre voisine, qui sont si gentils et bien élevés. Et le travail de votre cousine qui est si passionnant par rapport au vôtre. Rien ne va dans votre vie et tout va mieux chez les autres. Penser ainsi est un véritable cercle vicieux, car être jaloux de tout ne vous apportera rien, sauf du mal-être et des pensées négatives. </p>\n<p>Rappelez-vous que personne n’est parfait. Certaines personnes ont probablement des forces que vous n’avez pas, c’est un fait. Mais peut-être ont-elles aussi des faiblesses que vous ne possédez pas. En réalité, personne n’est mieux que personne. Nous sommes juste tous différents. </p>\n<p>Et surtout, dites-vous bien que ce que vous critiquez fréquemment chez un individu n’est que son masque social. Bien souvent, vous ne savez pas du tout qui il est réellement au fond de lui. Vous avez donc une représentation erronée de lui. Ou incomplète, en tout cas. Et surtout, il s’agit d’une image qui peut être temporaire. Car tout le monde évolue et change avec le temps et les expériences. Ce que vous jugez chez quelqu’un est en constante évolution.</p>\n<p>Vu que vous ne connaissez pas la personne, qui vous dit qu’elle est heureuse dans sa vie ? Et si son mari n’était pas aussi gentil qu’il y paraît, une fois la porte fermée ?</p>\n<p>Méfiez-vous également des réseaux sociaux où l’on peut réaliser de très belles photographies, de beaux montages, etc. Les personnes montrent généralement le meilleur d’elles-mêmes, surjouent leur vie et embellissent la réalité. Par conséquent, ne croyez pas que leur existence ressemble à s’y méprendre à celle qu’elles exposent sur internet. C’est très souvent loin d’être le cas.</p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h2>Quand peut-on se comparer aux autres ?</h2>\n<p>Il n’est donc pas utile de vous comparer à autrui. Cependant, dans certaines circonstances, vous pouvez le faire. </p>\n<p>Par exemple, votre sœur a un corps parfait et pourtant, mange autant que vous. Vous trouvez cette situation insupportable. L’injustice ici, c’est qu’elle s’alimente autant que vous sans prendre un seul gramme alors que vous, c’est directement 1 kg que vous prenez. Mais n’avez-vous vraiment aucune emprise sur la situation ? Eh si. Déjà, acceptez le fait que votre morphologie n’est pas comme celle de votre frangine. Ensuite, entreprenez des actions afin d’obtenir le même corps qu’elle. Faites du sport, entamez un rééquilibrage alimentaire, etc. Dans ce cas-là, vous comparer à elle vous servira à envisager des actions concrètes pour réaliser votre objectif, qui reste d’obtenir un corps idéal. </p>\n<p>Si vous vous retrouvez dans cet exemple, c’est-à-dire, que vous souhaitez prendre soin de votre corps par le biais de votre <strong>alimentation</strong>, vous pouvez aller vous renseigner sur la méthode se nommant la <strong>synergie alimentaire.</strong> Celle-ci a été créée par <strong>Rémi MOHA, coach sportif et nutrition diplômé</strong>, lequel a également rédigé un livre à ce sujet. En résumé, cette méthode, en <strong>combinant</strong> certains aliments entre eux, permet un regain <strong>d’énergie</strong>, de <strong>perdre du poids</strong> et de <strong>booster votre santé.</strong> Pour plus d’informations sur cette méthode, je vous invite à cliquer sur le bouton ci-dessous : </p>\n<p>Vous n’êtes pas satisfait de votre salaire ? Vous pouvez demander une augmentation, de nouvelles fonctions, changer de job, devenir entrepreneur, pratiquer une activité annexe en plus de votre travail, etc.  </p>\n<p>Il convient donc d’entreprendre des actions dès qu’une situation de votre vie vous met mal à l’aise, et ce, en vue de la remplacer. Vous pouvez vous servir de ce que vous admirez chez l’autre afin de le prendre pour modèle et d’arriver à obtenir la même chose. Le jalouser n’aura pour conséquence que de vous faire du mal inutilement. </p>\n<h2>Les troubles anxieux et la comparaison sociale </h2>\n<p>Si vous vous trouvez sur ce blog, c’est probablement car vous souffrez d’anxiété. Il est vrai que bon nombre de personnes n’en souffrent pas. Vous aurez donc tendance à penser que la vie demeure bien plus facile pour elles, puisque les actions qu’elles entreprennent ne leur demandent pas une énergie folle. Ce n’est cependant pas parce qu’elles n’endurent pas de troubles anxieux qu’elles ne se comparent pas négativement à autrui aussi. Et qu’elles sont plus heureuses que vous. Ne voyez pas l’angoisse comme un handicap, mais comme un moteur pour vous aider à évoluer encore plus. </p>\n<p>Prenez l’exemple des personnes handicapées motrices. Elles ne se plaignent pas de leur sort malgré le regard des autres et le fait qu’elles se savent bien moins loties que certains. Cependant, elles réalisent souvent de beaux exploits, exploits que bon nombre d’individus sans problème ne sauraient réaliser. Il n’y a qu’à voir les personnes pratiquant des championnats paralympiques. </p>\n<p>Donc oui, l’anxiété peut augmenter la difficulté des obstacles que vous devrez gérer dans votre vie. C’est là que peut survenir votre sentiment d’injustice. Mais rien n’est impossible ! Vous aurez juste à travailler plus dur que certains sur certains points, mais vous pouvez le faire. </p>\n<img loading=\"lazy\" decoding=\"async\" width=\"640\" height=\"581\" src=\"/storage/blog-images/Comparer-autres.png\" alt=\"Comparaison sociale \" title=\"Comparer-autres\">\n<h2>Comment réussir à se libérer de la jalousie et de la comparaison ?</h2>\n<p>Vous arrivez maintenant à faire la différence entre une comparaison néfaste et bénéfique. Je ne vous invite bien évidemment qu’à pratiquer celle qui est bénéfique. C’est un état d’esprit qui deviendra habituel avec de l’entraînement. Je vais également vous donner quelques astuces ci-dessous afin de vous faciliter l’exercice.</p>\n<h3>Exprimez votre gratitude</h3>\n<p>Tous les soirs, notez 5 éléments de votre journée qui vous ont permis de vous épanouir. Ces éléments peuvent représenter une preuve d’amour d’un de vos proches, un bon repas, votre belle vie de couple, etc. Et relisez-les régulièrement. Bien souvent, quand vous vous comparez négativement aux autres, vous ne vous rendez même plus compte de ce que vous possédez. Vous faites une fixation sur ce que vous pensez ne pas avoir. Apprenez donc à apprécier tout ce que vous avez de beau dans votre existence. Une maison, un conjoint qui vous aime, des amis, etc. </p>\n<h3>Notez l’évolution de votre vie</h3>\n<p>Prenez conscience que votre vie actuelle, mis à part évènements dramatiques et hors de votre contrôle, c’est vous qui l’avez construite, avec une succession de choix que vous avez réalisés. Si vous avez une belle relation de couple, fondé une famille avec la personne aimée, rencontré des amis, acheté une maison, etc. dites-vous que c’est grâce à une bonne partie de vos actions. Comprenez que vous êtes capable de construire votre existence et notez tout ce que vous avez construit de bon pour vous. Votre estime de vous s’en trouvera renforcée et vous pourrez retrouver <a href=\"/confiance-et-estime-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Confiance et estime de soi\">confiance en vous. </a></p>\n<p>Je n’ai pas repris ici le fait de réaliser des actions concrètes et de sortir de votre zone de confort afin de vraiment construire la vie que vous désirez. Ce que bon nombre de personnes n’accomplissent d’ailleurs pas, se contentant de suivre la norme. </p>\n<p>Il convient également de renforcer l’estime que vous avez de vous afin d’accomplir lesdites actions. </p>\n<p>De là, vous verrez qu’en menant réellement l’existence dont vous rêvez, vous ne penserez même plus à vous comparer aux autres. Vous allez vous sentir mieux en travaillant sur votre épanouissement personnel. </p>\n<p><b>Se libérer de la jalousie et de la comparaison </b>peut donc avoir lieu grâce au passage à l’action. À vous de jouer ! </p>\n<p>(Si mon travail vous aide 🙂)</p>','published',1,'Se Libérer de la Jalousie et de la Comparaison pour une Vie Sereine','Qui ne s’est jamais comparé aux autres ? La comparaison demeure naturelle pour l’être humain. Comment se libérer de la jalousie et de la comparaison ?','https://vivre-pleinement.fr/se-comparer-aux-autres/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/se-comparer-aux-autres\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/se-comparer-aux-autres\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Se Lib\\u00e9rer de la Jalousie et de la Comparaison pour une Vie Sereine\",\"datePublished\":\"2019-10-01T19:00:06+00:00\",\"dateModified\":\"2024-02-12T19:44:50+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/se-comparer-aux-autres\\/\"},\"wordCount\":3919,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/se-comparer-aux-autres\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/10\\/Liberer-jalousie-comparaison.jpg\",\"articleSection\":[\"D\\u00e9veloppement personnel\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/se-comparer-aux-autres\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/se-comparer-aux-autres\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/se-comparer-aux-autres\\/\",\"name\":\"Se Lib\\u00e9rer de la Jalousie et de la Comparaison pour une Vie Sereine\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/se-comparer-aux-autres\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/se-comparer-aux-autres\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/10\\/Liberer-jalousie-comparaison.jpg\",\"datePublished\":\"2019-10-01T19:00:06+00:00\",\"dateModified\":\"2024-02-12T19:44:50+00:00\",\"description\":\"Qui ne s\\u2019est jamais compar\\u00e9 aux autres\\u2009? La comparaison demeure naturelle pour l\\u2019\\u00eatre humain. Comment se lib\\u00e9rer de la jalousie et de la comparaison\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/se-comparer-aux-autres\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/se-comparer-aux-autres\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/se-comparer-aux-autres\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/10\\/Liberer-jalousie-comparaison.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/10\\/Liberer-jalousie-comparaison.jpg\",\"width\":640,\"height\":426,\"caption\":\"Comment se liberer de la jalousie et de la comparaison ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/se-comparer-aux-autres\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Se Lib\\u00e9rer de la Jalousie et de la Comparaison pour une Vie Sereine\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-10-01 19:00:06',NULL,'2026-05-24 19:19:45','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (52,'Insomnie et Difficultés d’Endormissement : Causes et Solutions','insomnie','Bon nombre de personnes connaîtront un jour des périodes d’insomnie et notamment celles souffrant de troubles anxieux et de dépression. Beaucoup d’individus cherchent des méthodes pour mieux dormir. Le repos demeure indispensable au bon fonctionnement de notre organisme. C’est à ce moment que le corps peut retrouver son énergie. C’est également là que le cerveau se nettoie en éliminant les déchets produits au cours de la journée. Voilà pourquoi manquer de sommeil peut s’avérer redoutable. En allant vous coucher, vous êtes pris de ruminations incessantes vous empêchant de dormir, car vous pensez à vos soucis. Vous vous réveillez le matin et il vous reste au moins 3 heures à dormir, mais impossible de vous rendormir : vous angoissez bien trop par rapport à la journée qui s’annonce. Vous souffrez d’insomnie et de difficultés d’endormissement ? Comment retrouver des nuits paisibles ? \n','<p>Bon nombre de personnes connaîtront un jour des périodes d’insomnie et notamment celles souffrant de <b>troubles anxieux</b> et de <b>dépression</b>. Beaucoup d’individus cherchent des <b>méthodes </b>pour mieux <b>dormir</b>. Le repos demeure <b>indispensable </b>au bon fonctionnement de notre organisme. C’est à ce moment que le corps peut retrouver son <b>énergie</b>. C’est également là que le <b>cerveau </b>se <b>nettoie</b> en éliminant les déchets produits au cours de la journée. Voilà pourquoi manquer de sommeil peut s’avérer <b>redoutable</b>. En allant vous coucher, vous êtes pris de <b>ruminations </b>incessantes vous empêchant de dormir, car vous pensez à vos <b>soucis</b>. Vous vous réveillez le <b>matin </b>et il vous reste au moins 3 heures à dormir, mais <b>impossible </b>de vous <b>rendormir </b>: vous <b>angoissez </b>bien trop par rapport à la <b>journée </b>qui s’annonce. Vous souffrez d’<b>insomnie et de difficultés d’endormissement ? </b>Comment retrouver des<b> nuits paisibles </b>? </p>\n<h2>Les différents types d’insomnie </h2>\n<p>L’insomniaque, contrairement à ce que l’on peut croire, n’est pas quelqu’un qui ne dort pas de la nuit. Il dormira généralement toujours un peu, soit 3 ou 4 heures environ. Cependant, toutes les insomnies ne se ressemblent pas. Je vais vous en détailler les principales ici afin que vous puissiez vous retrouver dans celle qui vous « correspond ».</p>\n<h3>L’insomnie passagère </h3>\n<p>Avant toute chose, sachez que l’insomnie peut se trouver temporaire. Voilà pourquoi généralement tout le monde en a déjà fait les frais. Par exemple, la veille d’un examen important, une personne peut peiner à trouver le sommeil. Dans ce cas, ce trouble disparaîtra après l’épreuve en question. De même, après un incident tragique et traumatique, l’insomnie passagère sera tout à fait normale. Il faudra juste la surveiller de près, car elle peut devenir chronique si l’événement n’arrive pas à être digéré.</p>\n<h3>L’insomnie chronique sévère </h3>\n<p>L’insomnie chronique peut survenir après un événement traumatisant. Par contre, elle apparaît principalement présente chez les personnes souffrant de <a href=\"/angoisse-stress-anxiete\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse stress anxiété \">troubles anxieux</a> ou de dépression. Ces personnes pourront appréhender fortement le moment de dormir et de là, un cercle vicieux s’installe. </p>\n<h3>L’insomnie d’endormissement </h3>\n<p>Ce type d’insomnie touchera plus les personnes anxieuses. En effet, puisqu’elles présentent une bonne tendance à la <a href=\"/ruminations\" target=\"_blank\" rel=\"noopener\" title=\"Ruminations\">rumination</a>, le fait de se retrouver dans le noir et dans le calme apparaîtra propice à l’apparition de ce trouble. </p>\n<h3>L’insomnie due à un sommeil léger</h3>\n<p>Certaines personnes dorment la nuit, mais quasiment tout le temps de manière légère. Elles restent donc fréquemment sujettes aux réveils nocturnes (peut-être même à des <a href=\"/angoisses-nocturnes\" target=\"_blank\" rel=\"noopener\" title=\"Angoisses nocturnes\">angoisses nocturnes</a>) et aux rêves ou cauchemars. Certaines également vont beaucoup aux toilettes la nuit, ce qui coupe l’endormissement (souvent dû à de l’anxiété). En résumé, les coupures sont régulières, ce qui les empêche d’avoir un sommeil réparateur.</p>\n<p> </p>\n<h3>L’insomnie matinale </h3>\n<p>Ce type d’insomnie touche principalement les personnes à humeur dépressive et atteintes de troubles anxieux. Elles s’endorment en général très rapidement et passent une bonne nuit, et ce, jusqu’à 3-4 heures du matin environ. Elles éprouveront, à partir de là, beaucoup de difficultés pour se rendormir, même si elles sont fatiguées et se rendormiront généralement juste avant de se lever. En réalité, vers 4 h aux aurores, la journée approche. La personne appréhende alors son déroulement qui reste inconnu. Le sommeil la rassure quelquefois, car il n’y a pas besoin de se donner à fond comme à son travail, par exemple. C’est donc l’angoisse qui recommence. La personne peut même se sentir incapable de gérer la journée qui s’annonce. Elle manque d’énergie à peine levée. </p>\n<p>Il y a en réalité une explication scientifique à ce phénomène. En fait, à 4 h du matin environ, c’est là que le corps produit le plus de mélatonine. Cette hormone sert à vous aider dans votre endormissement. Voilà pourquoi à cette heure-là, vous avez beaucoup de mal à penser de manière rationnelle. Il peut donc y avoir énormément de scénarios catastrophes et anxieux se déroulant dans votre tête.</p>\n<p> </p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"430\" src=\"/storage/blog-images/Trouble-sommeil.png\" alt=\"Insomniaque \" title=\"Trouble-sommeil\">\n<h2>Les conséquences de l’insomnie  </h2>\n<p>L’insomnie n’est pas une maladie. Elle représente juste un symptôme d’un problème plus profond, tel qu’un trouble anxieux. Cependant, elle peut clairement faire beaucoup de torts à la personne concernée. Voici les principales manifestations pouvant apparaître en cas d’insomnie régulière : </p>\n<p>\n</p>\n<p>– Fatigue, somnolence et bâillements ;</p>\n<p>– Irritabilité ;</p>\n<p>– Perte de mémoire et de concentration ce qui peuvent conduire, dans les cas les plus importants, à une absence au travail ou à une forte baisse de productivité ; </p>\n<p>– Courbatures ;</p>\n<p>– Apparition de migraines ;</p>\n<p>– Troubles digestifs ; </p>\n<p>– Manque de vigilance sur la route ;  </p>\n<p>– Moins bon système immunitaire et donc, tendance à attraper plus de virus, maladies, etc. ; </p>\n<p>– Faim accentuée, ce qui peut entraîner des problèmes de poids.</p>\n<p> </p>\n<h2>Les causes profondes et légères de l’insomnie et des difficultés d’endormissement</h2>\n<p>L’insomnie ne constitue qu’un symptôme d’un mal-être plus profond. Ainsi, pour qu’elle disparaisse pour de bon, il convient de trouver la ou les cause(s) de son apparition. Toutefois, les raisons n’apparaissent pas forcément profondes. De petits réglages et changements dans le quotidien peuvent totalement faire disparaître ce trouble. Il faut savoir que si les causes apparaissent profondes, vous serez plus sujet à développer de l’insomnie chronique. Dans ce cas, il va être plus fastidieux d’éliminer la source du problème.</p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h3>Les causes profondes de l’insomnie </h3>\n<p><b>– </b>Anxiété et/ou dépression ;</p>\n<p>– Surmenage au travail. Dans ce cas, il convient de trouver une solution au problème que vous rencontrez dans votre job. Car si vous ne le faites pas, vous risquez le burn-out qui mène souvent à la dépression ;</p>\n<p>– Décalage horaire. Je mets cet élément dans cette catégorie, car les horaires décalés vont fréquemment de pair avec un travail de nuit, par exemple. Dans ce cas, à vous de voir si ce rythme de vie vous correspond. Sur le long terme, mieux vaut chercher une autre option. Il est en effet prouvé scientifiquement que travailler de nuit n’est pas bon et naturel pour l’être humain. Par contre, si c’est un décalage horaire dû à un voyage, inutile de s’en faire. Vous retrouverez le sommeil rapidement ;</p>\n<p>– Alcool. Boire de l’alcool peut rendre la personne somnolente et généralement, elle s’endormira vite. Cependant, elle se réveillera vers 3 – 4 h du matin réussir à se rendormir, ou du moins, très difficilement. J’ai mis la boisson dans cette catégorie, car trop boire, bien évidemment, cache un mal-être profond, tel que troubles anxieux et/ou dépression ;</p>\n<p>– Envie d’uriner fréquemment. Si j’ai mis cette cause dans cette rubrique, c’est qu’elle concerne souvent les gens atteints d’anxiété ;</p>\n<p>– Douleur(s) physique(s). Les maux physiques peuvent vraiment vous empêcher de dormir. À vous de voir si elles peuvent avoir un lien avec votre état émotionnel (voilà pourquoi je les ai mises dans cette partie). Sinon, à vous de faire le nécessaire afin que ces douleurs soient traitées médicalement parlant. </p>\n<h3>Les causes légères d’un sommeil agité  </h3>\n<p>– Repas copieux le soir. Il est conseillé de manger léger en soirée. Autrement, la digestion peut s’opérer difficilement la nuit ;</p>\n<p>– Trop de lumière. Il est recommandé de dormir dans un endroit sombre. Essayez de cacher les multiprises pouvant émettre de la lumière, l’éclairage d’ordinateur, etc. ;</p>\n<p>– Bruits ambiants. Ils peuvent vous irriter et donc, vous empêcher de trouver le sommeil ;</p>\n<p>– Tabac. À éviter le soir. Il est en effet considéré comme un excitant ;</p>\n<p>– Sport. Évitez le sport au crépuscule. Car même si faire de l’exercice est bon pour la santé, l’activité physique stimule la production de dopamine, laquelle redonne du pep’s et diminue la sensation de fatigue ; </p>\n<p>– Jeux vidéos. Ils peuvent exciter la personne avant qu’elle aille au lit, obligeant le cerveau à rester actif et à réfléchir. La télévision n’est pas forcément plus conseillée. Cependant, elle rend plus passif. L’endormissement peut donc intervenir plus rapidement ;</p>\n<p>– Dormir à des heures irrégulières. Si vous dormez à des heures régulières (si vous le pouvez, même le week-end), vous habituerez votre cerveau et il saura quand l’heure du coucher ou du lever interviendra. En installant une routine de sommeil, les hormones du sommeil pourront se déclencher plus facilement ;</p>\n<p>– Trop de siestes la journée. Il est bon de faire une petite sieste, entre 15 minutes et une heure environ. En dormant plus, vous risquez d’avoir beaucoup de mal à trouver le sommeil au moment du coucher.</p>\n<p>– Caféine. À éviter le soir, surtout si vous souffrez de troubles anxieux et d’insomnie, puisqu’elle reste un excitant. </p>\n<h2>Les préjugés sur le sommeil </h2>\n<p>Vous pouvez quelquefois penser que certaines personnes sont insomniaques, car elles n’ont pas les mêmes habitudes de sommeil que vous. Mais ce n’est pas toujours vrai. En général, l’être humain adulte a besoin de 7 à 8 heures de repos par nuit. Mais cette généralité ne reste qu’une norme. Ce nombre d’heures ne va pas forcément vous convenir. À vous de voir combien de temps vous avez besoin de dormir pour vous sentir bien.</p>\n<p>Certains individus, par exemple, sont considérés comme de petits dormeurs. Ils peuvent se coucher vers 23 h et se lever à 4 h sans problème et avec beaucoup d’énergie. D’autres auront besoin de 10 heures de sommeil, ce qui ne veut pas dire que ces personnes ont un problème.</p>\n<p>Les personnes âgées sombrent moins dans le sommeil profond. Elles se retrouvent facilement réveillées par des bruits. Elles ont également besoin de moins d’heures de sommeil, puisqu’elles effectueront plus de siestes dans la journée.</p>\n<img decoding=\"async\" width=\"640\" height=\"426\" src=\"/storage/blog-images/Sommeil-agite.jpg\" alt=\"Ne pas reussir a s’endormir \" title=\"Sommeil-agité\">\n<h2>Comment soigner l’insomnie ?</h2>\n<p>Pour régler ce trouble, je vous encourage premièrement à voir si vous pouvez y trouver des causes légères. De là, peut-être qu’un simple changement d’habitude vous suffira et je vous le souhaite ! </p>\n<p>Si les raisons apparaissent plus profondes, je vous invite à consulter les <a href=\"/blog\" target=\"_blank\" rel=\"noopener\" title=\"Blog\">différents articles de ce blog</a>, notamment concernant les troubles anxieux. Les solutions qui seront évoquées auront en effet bien souvent un lien avec la disparition de votre insomnie.  </p>\n<p>Cependant, je vous donne quelques petites astuces ci-dessous.</p>\n<p> </p>\n<p>1— Certaines personnes tentent les centres de sommeil. Pourquoi ne pas vous y intéresser si votre insomnie demeure vraiment difficile à gérer ?</p>\n<p>2 — Si vous n’arrivez pas à vous endormir, au lieu de cogiter dans votre lit, levez-vous. Regardez la télévision, lisez, pratiquez une petite activité, et ce, quelle que soit l’heure. Le sommeil comportant des cycles, dès que vous sentez la fatigue vous gagner à nouveau, retournez vous coucher.</p>\n<p>3 — Le soir, dès que vous vous commencez à fatiguer, allez dormir, c’est le bon moment. Si vous n’y allez pas, vous pouvez sentir la fatigue passer. Vous vous trouvez donc dans un autre cycle. Cependant, si vous allez vous coucher à ce moment, vous ne dormirez pas. Il est recommandé d’attendre qu’un nouveau cycle de sommeil fasse son apparition.</p>\n<p>4— Enfin, rappelez-vous une chose. Il est tout à fait normal que vous soyez sujet à des angoisses incontrôlables et irrationnelles la nuit et surtout, vers 3 – 4 h du matin. Il est donc inutile d’essayer de vous calmer et de rationaliser. Vous ne pouvez qu’accepter <b>l</b>a situation et laisser-passer cette sensation désagréable. </p>\n<p> </p>\n<p>J’espère que cet article pourra vous aider à soigner votre <b>insomnie et vos difficultés d’endormissement </b>et vous souhaite dorénavant d’agréables nuits ! </p>\n<p>(Si mon travail vous aide 🙂) </p>\n<a href=\"https://hypnocaments.com?partnerid=YK5muYugzSoIWDbDWRgT-Q\" title=\"Seances d hypnose en ligne\"><img decoding=\"async\" src=\"https://hypnocaments.com/image/banner_1_750.png\" alt=\"seance hypnose mp3\"></a>','published',1,'Insomnie et Difficultés d’Endormissement : Causes et Solutions','Beaucoup d’individus cherchent des méthodes pour mieux dormir. Vous souffrez d’insomnie et de difficultés d’endormissement ? Comment vous en libérer ?','https://vivre-pleinement.fr/insomnie/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/insomnie\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/insomnie\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Insomnie et Difficult\\u00e9s d\\u2019Endormissement : Causes et Solutions\",\"datePublished\":\"2019-09-24T18:57:45+00:00\",\"dateModified\":\"2024-02-13T17:26:01+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/insomnie\\/\"},\"wordCount\":3561,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/insomnie\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/09\\/Insomnie-difficultes-endormissement.png\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/insomnie\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/insomnie\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/insomnie\\/\",\"name\":\"Insomnie et Difficult\\u00e9s d\\u2019Endormissement : Causes et Solutions\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/insomnie\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/insomnie\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/09\\/Insomnie-difficultes-endormissement.png\",\"datePublished\":\"2019-09-24T18:57:45+00:00\",\"dateModified\":\"2024-02-13T17:26:01+00:00\",\"description\":\"Beaucoup d\\u2019individus cherchent des m\\u00e9thodes pour mieux dormir. Vous souffrez d\\u2019insomnie et de difficult\\u00e9s d\\u2019endormissement\\u2009? Comment vous en lib\\u00e9rer ?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/insomnie\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/insomnie\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/insomnie\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/09\\/Insomnie-difficultes-endormissement.png\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/09\\/Insomnie-difficultes-endormissement.png\",\"width\":640,\"height\":423,\"caption\":\"Comment soigner l\\u2019insomnie ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/insomnie\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Insomnie et Difficult\\u00e9s d\\u2019Endormissement : Causes et Solutions\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-09-24 18:57:45',NULL,'2026-05-24 19:19:45','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (53,'Lâcher-prise Emotionnel : une Clé Essentielle pour être Heureux','lacher-prise-et-acceptation','Le lâcher-prise et l’acceptation restent des termes extrêmement employés de nos jours. On pourrait même penser qu’il s’agit d’une mode. Bon nombre de livres pullulent sur ces sujets. Ces notions apparaissent nécessaires si vous souhaitez améliorer votre vie. Le comportement d’un de vos proches vous horripile et vous faites tout pour le changer. Vous êtes focalisé sur son attitude qui ne vous plait pas. Vous avez organisé depuis de nombreux mois un superbe séjour, mais un imprévu de dernière minute survient. Ce séjour est donc annulé. Vous vous en rendez malade et n’acceptez pas cette situation. Vous venez de passer des examens et attendez nerveusement les résultats qui n’arriveront que dans deux semaines. Ces deux semaines se passent alors péniblement, puisque vous angoissez énormément. Vous aimerez que votre existence devienne fluide ? Comment accéder au lâcher-prise émotionnel ? \n','<p>Le<b> lâcher-prise</b> et<b> l’acceptation restent</b> des termes extrêmement employés de nos jours. On pourrait même penser qu’il s’agit d’une <b>mode</b>. Bon nombre de <b>livres </b>pullulent sur ces sujets. Ces notions apparaissent nécessaires si vous souhaitez améliorer votre vie. Le <b>comportement </b>d’un de vos proches vous <b>horripile </b>et vous faites tout pour le <b>changer</b>. Vous êtes <b>focalisé </b>sur son attitude qui ne vous plait pas. Vous avez organisé depuis de nombreux mois un superbe <b>séjour</b>, mais un imprévu de dernière minute survient. Ce séjour est donc <b>annulé</b>. Vous vous en rendez <b>malade </b>et n’acceptez pas cette situation. Vous venez de passer des <b>examens </b>et attendez nerveusement les <b>résultats </b>qui n’arriveront que dans deux semaines. Ces deux semaines se passent alors péniblement, puisque vous <b>angoissez </b>énormément. Vous aimeriez que votre existence devienne <b>fluide </b>? Comment accéder au <b>lâcher-prise émotionnel ? </b></p>\n<h2>Qu’est-ce que le lâcher-prise émotionnel ?  </h2>\n<p>Tout le monde entend parler de ces termes de nos jours, qui peuvent être mal interprétés. Certaines personnes confondent lâcher-prise et acceptation avec résignation, abandon, voire même, échec. Or, ce n’est pas du tout le cas. </p>\n<p>Le lâcher-prise et l’acceptation représentent plutôt un état d’esprit et de perception de l’existence. Et quand vous vous sentez <a href=\"/angoisse-stress-anxiete\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse stress anxiété \">anxieux et stressé</a>, c’est bien votre interprétation qui apparaît exagérée ou erronée.</p>\n<p>Vous savez d’ailleurs que dans les moments d’anxiété, vous détestez ne pas connaître les résultats à l’avance. Vous souhaitez tout contrôler. Et justement, lâcher-prise et accepter les événements sont tout le contraire de votre attitude. </p>\n<p>Il s’agit d’accepter les situations de la vie telles qu’elles se présentent, sans <a href=\"/ruminations\" target=\"_blank\" rel=\"noopener\" title=\"Ruminations\">ruminer</a> longuement dessus afin de pouvoir avancer. L’objectif est également d’apporter des actions concrètes sur ce que vous pouvez maîtriser.</p>\n<h2>Cas de lâcher-prise et d’acceptation </h2>\n<h3>Cas n° 1 </h3>\n<p><i>Situation :</i> C’est vos vacances, enfin ! Vous avez réservé une semaine à LA ROCHELLE. Le hic, c’est qu’il a plu durant tout le séjour, ce qui vous a empêché de tirer pleinement profit de vos congés. Vous n’avez pas pu réaliser certaines activités et êtes limite plus déprimé qu’avant de partir. Vous auriez presque envie de rentrer chez vous. La seule semaine de l’année où vous pouvez vraiment en profiter, tout est gâché. Vous êtes dégoûté…</p>\n<p> </p>\n<p><i>Pratique :</i> C’est sûr, c’est dommage. Mais à la limite, si vous désirez que le beau temps soit garanti, partez dans un autre pays ! L’ouest de la FRANCE, en effet, est toujours risqué niveau soleil. Vous le saurez pour la prochaine fois. Et à ce que je sache, la pluie n’a jamais tué personne. C’est vrai que c’est dommage, car pour aller à la plage ou à la mer, c’est plus compliqué. Mais il y a tellement d’autres activités que vous pouvez réaliser ! Donc, il convient d’accueillir la situation et de tout de même entreprendre les activités que vous avez prévues, et ce, en faisant avec la météo. Comme ça, vous aurez réussi à décompresser tout en profitant de vos vacances. Vous aurez déconnecté. </p>\n<p> </p>\n<p><i>Bilan : </i>Dans ce cas concret, vu que vous ne pouvez contrôler le temps, mieux vaut l’accepter. À vous par contre d’agir pour pratiquer malgré tout des activités. Lors de vos prochains congés, vous choisirez une autre destination. En changeant donc de perception, vous arriverez à passer d’agréables vacances.</p>\n<h3>Cas n°2</h3>\n<p><i>Situation </i>: Je ne supporte plus mon frère. Il se mêle sans arrêt de ce qui ne le regarde pas. Il vient chez moi et s’autorise à déplacer des objets, puisque, selon lui, ils sont mieux à telle place. Je le trouve envahissant, car il débarque sans prévenir. Il désire contrôler mon existence. De plus, il ose faire des réflexions sur mon mode de vie. Il pense avoir la science infuse et veut toujours avoir raison, avec ses leçons de morale. Je vais bien lui faire comprendre que ses comportements sont intolérables et que c’est moi qui l’aurais, le dernier mot ! </p>\n<p> </p>\n<p><i>Pratique :</i> Concernant le fait que votre frère passe à l’improviste et se permet de toucher des objets dans votre maison, c’est inacceptable. C’est votre espace privé et vous ne pouvez rester sans rien faire. À vous de lui parler avec <a href=\"/affirmation-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Affirmation de soi\">affirmation</a> afin qu’il change d’attitude. </p>\n<p>Par contre, vous ne pouvez pas vraiment agir sur les réflexions d’autrui. Vu que votre frère n’a pas la même façon de penser que vous, il sera porté à vous critiquer. À vous de lâcher-prise à ce sujet. Vous pouvez, en revanche, lui préciser que ses remarques sont blessantes et qu’il pourrait, à l’avenir, les garder pour lui. Sauf si ses critiques apparaissent constructives, bien évidemment. </p>\n<p>A ce sujet, je vous invite à découvrir le <strong>programme</strong> de <strong>Didier PENISSARD, coach, auteur et conférencier en développement personnel.</strong> Ledit programme vous aidera grandement à surmonter votre <strong>peur du jugement.</strong> C’est ici que ça se passe :</p>\n<p>Bilan : Le lâcher-prise consiste à se dire que quoi que l’on fasse, on ne peut changer les gens. Comme eux ne pourront nous changer. À vous de modifier votre perception sur la <a href=\"/jugement-des-autres\" target=\"_blank\" rel=\"noopener\" title=\"Jugement des autres\">critique</a> humaine, laquelle demeure malheureusement universelle. Vous pouvez passer à l’action à partir du moment où la personne empiète sur votre vie privée en souhaitant diriger votre existence. Dans ce cas-là, à vous de vous affirmer.</p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"501\" src=\"/storage/blog-images/Acceptation.jpg\" alt=\"Accueillir \" title=\"Acceptation\">\n<h2>Différence entre le lâcher-prise et la pensée positive </h2>\n<p>Certains confondent le lâcher-prise avec la pensée positive. La pensée positive est un concept poussant à penser sans arrêt positivement, quelle que soit la situation. Toujours voir le verre à moitié plein plutôt qu’à moitié vide. Pratiquer de l’autosuggestion, telle que « tout va bien aller, il y a pire dans la vie, je vais réussir », etc.</p>\n<p>Le lâcher-prise, quant à lui, prône le fait de ne pas essayer d’agir sur ce qui se trouve hors de votre contrôle. Cependant, si une situation tragique survient, comme le décès d’un proche, vous avez le droit de ressentir une profonde tristesse, et ce, pendant tout le temps qui vous apparaît nécessaire. Vous avez le droit d’avoir des pensées négatives. </p>\n<p>Je ne suis pas trop fan de la notion de pensée positive. Il est vrai qu’il est bon de s’efforcer à voir le verre à moitié vide plutôt qu’à moitié plein. Par contre, l’être humain va vivre des émotions positives quand il se sent heureux et des émotions qui lui font du mal quand il se sent malheureux. C’est ainsi. </p>\n<p>Se faire croire que tout va bien alors que c’est faux s’appelle du déni. Et il n’est pas conseillé de refouler ses émotions. Il est donc judicieux d’exprimer vos sentiments négatifs et de vous donner le droit de ne pas systématiquement aller bien. Ce n’est pas un signe de faiblesse, bien au contraire. La personne qui vous dit qu’elle se porte toujours bien vous ment. Après, vous n’êtes pas obligé de crier vos émotions négatives sur tous les toits. Vous pouvez déjà pleurer un bon coup, même seul. Le principal, c’est de ne pas vous faire croire que tout va continuellement bien. </p>\n<h2>Les bienfaits du lâcher-prise émotionnel sur les troubles anxieux</h2>\n<p>Le gros problème de l’anxieux, c’est qu’il veut toujours tout contrôler. Pas forcément, car il désire le pouvoir. C’est surtout que contrôler le rassure. Il aime en général les vies routinières, bien rangées et sécurisantes. Les cas extrêmes se retrouvent d’ailleurs dans les TOC. Donc, en cas d’imprévu, c’est la catastrophe. </p>\n<p>Avec le lâcher-prise, il va enfin prendre conscience qu’on ne peut malheureusement tout contrôler. Il réussira à relativiser plus facilement, à moins se mettre en colère et ne paniquera plus en cas de petits pépins routiniers. Il comprendra qu’il ne peut changer une personne. Cette personne ressentira alors moins de rancœur à son égard et arrivera même à l’accepter telle qu’elle est et lui pardonner, si des blessures lui avaient été infligées.</p>\n<p>Si vous comprenez que vous faire du souci sur d’éventuelles catastrophes ne changera rien et que vous cessez de ruminer en profitant pleinement de l’instant, vous êtes devenu un adepte du lâcher-prise.</p>\n<p>C’est pareil pour les symptômes de l’angoisse. Plus vous essayez de les contrôler et plus ils vont s’aggraver. Forcément, vu que vous paniquez encore plus, en vous mettant la pression qu’il « ne faut pas » que votre situation s’aggrave. Tandis que si vous écoutez les manifestations de votre corps en les accueillant et en comprenant qu’elles vont passer, vos symptômes vont disparaître beaucoup plus rapidement.</p>\n<img decoding=\"async\" width=\"640\" height=\"423\" src=\"/storage/blog-images/Confiance.jpg\" alt=\"Foi\" title=\"Confiance\">\n<p>Pratiquer le <b>lâcher-prise émotionnel </b>et l’acceptation des événements tels qu’ils se présentent demandent un entraînement considérable. Notamment dans la société actuelle prônant compétitivité, pouvoir, forte personnalité (s’énerver, être agressif) et donc, contrôle. </p>\n<p>Les principales notions à retenir sont agir quand on le peut puis faire confiance à la vie pour la suite. Elles paraissent simples, mais pour l’être humain, sont très compliquées à mettre en application.</p>\n<p>Et lorsqu’il s’agit d’une relation conflictuelle avec quelqu’un, c’est également compliqué. Nous aurons en effet facilement tendance à vouloir blesser l’autre autant qu’il nous a blessé. Nous avons plus souvent l’esprit de vengeance que de pardon. Tentez de vous affirmer quand il le faut, bien évidemment, mais évitez de souhaiter changer l’autre : apprenez à lui pardonner. </p>\n<p> Vous le remarquerez, lâcher-prise et accepter est un travail quotidien, qui vous demandera persévérance et courage. Quelquefois, vous rechuterez. Mais ce n’est pas grave. Vous arriverez à évacuer le stress, à calmer votre mental et à retrouver la sérénité : vous atteindrez la stabilité émotionnelle. </p>\n<p>(Si mon travail vous aide) 🙂</p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img loading=\"lazy\" decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n','published',1,'Lâcher-prise Emotionnel : une Clé Essentielle pour être Heureux','Le lâcher-prise est un terme fréquemment employé. Vous aimeriez que votre existence devienne fluide ? Comment accéder au lâcher-prise émotionnel ?','https://vivre-pleinement.fr/lacher-prise-et-acceptation/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/lacher-prise-et-acceptation\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/lacher-prise-et-acceptation\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"L\\u00e2cher-prise Emotionnel : une Cl\\u00e9 Essentielle pour \\u00eatre Heureux\",\"datePublished\":\"2019-09-17T17:30:46+00:00\",\"dateModified\":\"2024-02-13T19:28:12+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/lacher-prise-et-acceptation\\/\"},\"wordCount\":2952,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/lacher-prise-et-acceptation\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/09\\/Lacher-prise-emotionnel.jpg\",\"articleSection\":[\"D\\u00e9veloppement personnel\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/lacher-prise-et-acceptation\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/lacher-prise-et-acceptation\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/lacher-prise-et-acceptation\\/\",\"name\":\"L\\u00e2cher-prise Emotionnel : une Cl\\u00e9 Essentielle pour \\u00eatre Heureux\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/lacher-prise-et-acceptation\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/lacher-prise-et-acceptation\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/09\\/Lacher-prise-emotionnel.jpg\",\"datePublished\":\"2019-09-17T17:30:46+00:00\",\"dateModified\":\"2024-02-13T19:28:12+00:00\",\"description\":\"Le l\\u00e2cher-prise est un terme fr\\u00e9quemment employ\\u00e9. Vous aimeriez que votre existence devienne fluide\\u2009? Comment acc\\u00e9der au l\\u00e2cher-prise \\u00e9motionnel\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/lacher-prise-et-acceptation\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/lacher-prise-et-acceptation\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/lacher-prise-et-acceptation\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/09\\/Lacher-prise-emotionnel.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/09\\/Lacher-prise-emotionnel.jpg\",\"width\":640,\"height\":426,\"caption\":\"Comment arriver au lacher prise emotionnel ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/lacher-prise-et-acceptation\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"L\\u00e2cher-prise Emotionnel : une Cl\\u00e9 Essentielle pour \\u00eatre Heureux\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-09-17 17:30:46',NULL,'2026-05-24 19:19:45','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (54,'Hypocondrie Sévère : Soigner ce Trouble Invalidant pour Retrouver la Joie','hypocondrie','Certaines personnes souffrant de troubles anxieux peuvent souffrir d’hypocondrie. Il s’agit de la peur excessive d’attraper une maladie grave. En effet, avec tout ce que nous entendons dans les médias et avec Internet où chacun peut établir son propre diagnostic, relativiser devient difficile. Ce trouble reste une véritable phobie où la personne voit le mal partout, même là où il n’y en a pas. Vous ressentez une bosse près du sein et vous voyez déjà avec un cancer incurable. Vous avez un bouton sur la lèvre et Internet vous explique qu’il peut s’agir d’une tumeur. Le discours rassurant de votre médecin ne vous aide pas. Vous allez donc en voir plusieurs en cherchant presque à ce que l’un d’entre eux vous dise : oui, c’est sérieux. Cette phobie constitue un réel handicap pour vous ? Comment se libérer de l’hypocondrie sévère ? \n','<p>Certaines personnes souffrant de<b> troubles anxieux</b> peuvent souffrir d’hypocondrie. Il s’agit de la peur excessive d’attraper une <b>maladie grave.</b> En effet, avec tout ce que nous entendons dans les <b>médias </b>et avec <b>Internet </b>où chacun peut établir son propre <b>diagnostic</b>, relativiser devient difficile. Ce trouble reste une véritable <b>phobie </b>où la personne voit le mal partout, même là où il n’y en a pas. Vous ressentez une <b>bosse </b>près du sein et vous voyez déjà avec un <b>cancer </b>incurable. Vous avez un <b>bouton </b>sur la lèvre et Internet vous explique qu’il peut s’agir d’une <b>tumeur</b>. Le discours <b>rassurant </b>de votre médecin ne vous aide pas. Vous allez donc en voir <b>plusieurs </b>en cherchant presque à ce que l’un d’entre eux vous dise : oui, c’est sérieux. Cette phobie constitue un réel <b>handicap </b>pour vous ? Comment se libérer de l’<b>hypocondrie sévère ? </b></p>\n<h2>Qu’est-ce que l’hypocondrie sévère ? </h2>\n<p>Une personne atteinte d’hypocondrie a généralement un tempérament anxieux à la base. Elle présente des réactions disproportionnées lorsqu’elle ressent le moindre symptôme. Elle peut aussi avoir la phobie d’être ou de tomber gravement malade sans raison particulière. Elle peut également avoir peur « d’attraper » une maladie mentale grave, telle qu’une psychose.</p>\n<p>Elle peut aller consulter un médecin au moins une fois par semaine. Elle a souvent tendance à vouloir différents avis médicaux et donc, à prendre d’autres rendez-vous. Il ne faut pas oublier que cette personne doute de ce que lui disent les médecins. De ce fait, elle ne sera jamais pleinement rassurée et ira même jusqu’à effectuer bon nombre d’examens afin de s’assurer que tout va bien, comme une IRM, un scanner, etc. Malheureusement, cette attitude ne la rassurera qu’un temps et elle s’affolera à nouveau très vite. </p>\n<p>Le cercle vicieux, c’est qu’à force d’angoisser à ce point, cette personne pourra être sujette à des crises de panique où elle pensera véritablement mourir. Elle ne sait pas que les manifestations d’une crise d’angoisse ne sont pas dangereuses. Cependant, elles apparaissent impressionnantes, ce qui fait penser à l’hypocondriaque qu’il a raison d’agir ainsi. </p>\n<p>Il va de ce fait développer de nouveaux symptômes, ce qui pourra entraîner, à la longue, une anxiété chronique et en conséquence, une hypocondrie sévère. </p>\n<p>Il s’auto-auscultera constamment et angoissera sans cesse. Il pourra donc contracter d’autres troubles anxieux et pourra même, si son état persiste, sombrer dans une dépression.</p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"454\" src=\"/storage/blog-images/Hypocondriaque.jpg\" alt=\"Peur d’attraper des maladies\" title=\"Hypocondriaque\">\n<h2>Pourquoi devient-on hypocondriaque ?  </h2>\n<p>Il n’y a pas de cause prédéfinie à l’apparition de ce trouble. Voici les causes qui peuvent vous correspondre : </p>\n<h3>Une enfance surprotégée </h3>\n<p>Quelquefois, une personne atteinte d’hypocondrie a fréquemment été malade plus jeune. En effet, si l’enfant a été trop protégé, son organisme apparaissait peut-être plus fébrile que ses camarades expérimentant la vie. Ce qui fera donc penser aux parents, souvent déjà anxieux à la base, voire, peut-être même, hypocondriaques, que leur enfant est bel est bien fragile. Ils voudront alors le surprotéger encore plus, puisqu’ils auront peur que le petit attrape une maladie grave. Ils peuvent échouer à contenir leur anxiété devant lui en lui balançant leurs peurs à la figure, comme, par exemple : « tu as un vertige ? Mon Dieu, j’espère que ce n’est pas une méningite ! ». De ce fait, leur comportement risque fortement d’être reproduit par leur descendance. </p>\n<h3>Une hypersensibilité</h3>\n<p>Une personne avec un tempérament hypersensible pourra plus facilement que les autres développer des troubles anxieux et donc, de l’hypocondrie. Je vous laisse aller voir mon <a href=\"/hypersensibilite\" target=\"_blank\" rel=\"noopener\" title=\"Hypersensibilité\">article</a> sur le sujet.</p>\n<h3>Une peur de vieillir et donc, de mourir</h3>\n<p>Quand la personne hypocondriaque a peur d’attraper une maladie, ce n’est bien généralement pas le rhume. Il s’agit très fréquemment d’une affection grave, voire, mortelle. De ce fait, c’est bien la <a href=\"/thanatophobie\" target=\"_blank\" rel=\"noopener\" title=\"Thanatophobie\">crainte de la mort</a> qui se cache là-dessous. Et très souvent également, c’est en avançant de plus en plus dans l’âge que l’hypocondrie s’aggrave ou que la personne peut commencer à développer ce trouble. En effet, plus nous vieillissons, plus nous voyons bien que notre corps n’est plus le même qu’avant. La vieillesse fait clairement penser à une lente décrépitude jusqu’à la mort. Il y a donc lieu de fouiller de ce côté-là.</p>\n<a href=\"https://hypnocaments.com?partnerid=YK5muYugzSoIWDbDWRgT-Q\" title=\"Seances d hypnose en ligne\"><img decoding=\"async\" src=\"https://hypnocaments.com/image/banner_1_750.png\" alt=\"seance hypnose mp3\"></a>\n<h3>Un traumatisme</h3>\n<p>L’hypocondrie peut également surgir à la suite d’un traumatisme, tel que le décès d’un proche atteint d’une maladie grave, par exemple. C’est là que l’individu peut commencer à se poser beaucoup de questions sur la mort et de fait, développer une peur panique des maladies. En fait, l’être humain ne peut se faire une idée précise de la mort. Du coup, il se croit immortel. Et vu que la société actuelle rend ce sujet tabou (tout dépend dans quel pays, mais en FRANCE, ce sujet reste tabou), la personne pense qu’elle ne sera jamais concernée par la mort. Le fait donc perdre un proche oblige à la personne à réfléchir à ce sujet et de là, la phobie peut apparaître.</p>\n<h3>Des troubles anxieux</h3>\n<p>Bien souvent, une personne atteinte d’hypocondrie est déjà affectée de troubles anxieux. Ce qui apparaît logique, vu que l’hypocondrie reste de l’angoisse exagérée portant sur les maladies. De plus, un individu n’est pas toujours atteint que d’un seul trouble anxieux. Dans certains cas, l’anxiété de la personne se déplace et pourra prendre la forme de multiples troubles anxieux, tels que le TAG, les TOC, la phobie sociale, etc.</p>\n<h3>Internet, la télévision, les médias</h3>\n<p>N’allez surtout pas sur Internet si vous êtes hypocondriaque. Nous avons tous tendance à le faire dès que nous éprouvons un petit symptôme. De plus, dans notre société actuelle, nous pouvons avoir accès instantanément à bon nombre d’informations. Nous pouvons donc avoir lire les descriptions de toutes les maladies. Vous pouvez effectivement taper le mot « aphte » et vous arriverez à tomber sur le cancer de la bouche. </p>\n<p>Mais mettez-vous bien dans la tête que vous ne pouvez établir un diagnostic de vous-même juste en allant sur Internet. Rien ne pourra remplacer le diagnostic personnalisé d’un vrai médecin. En effet, la plupart d’entre nous n’avons pas fait d’étude en médecine. Et la plupart des contenus que vous visitez regroupent des informations bien trop générales pour pouvoir établir un diagnostic personnalisé. De plus, tout le monde peut créer tel site et parler de telle maladie, sauf que tous ces créateurs de sites ne sont pas forcément des professionnels. De ce fait, ne prenez pas tout au pied de la lettre et méfiez-vous de la crédibilité des sites sur lesquels vous tombez.</p>\n<p>Idem pour la télévision. Avec les publicités choc sur le cancer par exemple, ou les séries médicales où il n’y a que de graves maladies, il est difficile de rester positif. Évitez donc ce genre d’émissions ou de pubs au maximum si vous êtes atteint d’hypocondrie.</p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h2>Les conséquences de la phobie d’attraper une maladie </h2>\n<h3>L’apparition de maladies </h3>\n<p>Ne prenez pas peur en lisant ce titre. Mais je crois sincèrement que l’être humain est capable de se créer des maladies s’il ressent un grand mal-être refoulé. Après, ce n’est pas parce que vous attrapez un rhume qu’il existe une signification cachée derrière. Vous ne vous êtes peut-être pas assez couvert, tout simplement ! Mais regardez le nombre de symptômes que vous pouvez provoquer rien qu’en vivant une crise de panique : vertiges, nausées, diarrhée, etc. Il est donc évident que l’équilibre émotionnel a un lien avec le corps. La science l’a d’ailleurs démontré pour certaines maladies telles que les ulcères, la rectocolite hémorragique, la maladie de Crohn, etc. lesquelles arrivent souvent suite à une anxiété prolongée ou à un grand choc. </p>\n<h3>Une vie sociale fortement impactée </h3>\n<p>Certaines personnes atteintes d’hypocondrie ressentent un tel mal-être qu’elles ne veulent plus sortir de chez elles de peur d’attraper une maladie. Par conséquent, leur vie sociale peut s’en trouver lourdement impactée. Quelquefois, elles ne seront même plus capables d’aller travailler. Une agoraphobie peut alors s’installer. Leurs relations personnelles peuvent s’en trouver fortement perturbées, du fait que les proches se sentiront impuissants en n’arrivant pas à les aider. Ils pourront ainsi penser que l’hypocondrie de la personne n’est que psychologique et qu’elle se victimise. </p>\n<h3>Un véritable mal-être</h3>\n<p>Du fait de l’incompréhension des autres et de l’incapacité à faire face au monde extérieur, la personne peut peu à peu perdre son estime d’elle-même. Elle risque alors de se retrouver avec des troubles anxieux supplémentaires, voire même, une dépression.</p>\n<img decoding=\"async\" width=\"640\" height=\"400\" src=\"/storage/blog-images/Peur-maladies.jpg\" alt=\"Crainte excessive d’etre en mauvaise sante \" title=\"Peur-maladies\">\n<h2>Comment soigner l’hypocondrie ? </h2>\n<p>Comme pour tout trouble anxieux, de multiples solutions peuvent être envisagées et il est même préférable de les combiner. </p>\n<h3>Vous faire aider par un professionnel de la santé</h3>\n<p>Les thérapies et notamment les TCC ont fait leurs preuves pour ce genre de troubles. Si la personne éprouve cependant trop de difficultés à gérer son mal-être, une médication en complément peut être envisagée. Mais seulement en tant que béquille, car il est nécessaire de travailler sur le fond du problème. Il ne faut pas prendre le médicament de manière isolée, ce qui ne servirait effectivement à rien, mis à part à devenir dépendant d’un traitement, et ce, peut-être même à vie.</p>\n<h3>Ne jamais regarder ses symptômes sur Internet </h3>\n<p>Cessez également de chercher des informations sur Internet. Même si c’est très difficile au début, peu à peu, vous perdrez cet automatisme néfaste. Car vous allez sur Internet en espérant être rassuré et vous savez très bien que c’est tout le contraire qui se produit. Vous verrez qu’en perdant cette habitude, vous <a href=\"/ruminations\" target=\"_blank\" rel=\"noopener\" title=\"Ruminations\">ruminerez</a> de moins en moins sur vos pensées anxiogènes et les laisserez donc de plus en plus passer. </p>\n<h3>Pratiquer des techniques de relaxation et des médecines alternatives</h3>\n<p>Vous pouvez également pratiquer tout type de relaxation qui pourrait vous correspondre, tel que la sophrologie, la méditation, le yoga, etc. Une bonne respiration reste également très importante pour diminuer vos symptômes anxieux. C’est même primordial.</p>\n<p>Et si vous désirez vous relaxer naturellement grâce à votre respiration, je vous conseille de pratiquer la cohérence cardiaque. C’est la méthode que j’utilise personnellement et je m’aide, pour ce faire, d’un petit appareil nommé Zenspire. Celui-ci, grâce à ses lumières et vibrations, vous apprend à respirer profondément et ce, afin de retrouver votre respiration de bébé, seule respiration pouvant relaxer pleinement votre corps.</p>\n<p>Si vous êtes intéressé par ce produit, je vous invite à cliquer sur le bouton ci-dessous, étant précisé que si vous passer commande, vous bénéficierez d’une <strong>remise de 10 %</strong> grâce au code <strong>JL0620</strong> :</p>\n<p>Vous pouvez aussi tenter un traitement homéopathique, par exemple. Ou pourquoi pas essayer des médecines alternatives, telles que l’EMDR, l’hypnose, l’acupuncture, etc.</p>\n<h3>Pratiquer le lâcher-prise et l’acceptation</h3>\n<p>Le principal travail que vous aurez à fournir et le <a href=\"/lacher-prise-et-acceptation\" target=\"_blank\" rel=\"noopener\" title=\"Lâcher-prise et acceptation\">lâcher-prise et l’acceptation.</a> Par exemple, un médecin vous a détecté un nodule et vous attendez deux semaines avant de passer une échographie. Au lieu de tomber en dépression durant cette période, tentez de vous dire la chose suivante. « OK, j’ai un nodule, mais le médecin me dit qu’il ne pense pas que ce soit un cancer, il me fait passer un examen juste par précaution. Donc pas besoin de s’inquiéter. De toute façon, je dois accepter le fait de devoir attendre 2 semaines avant de connaître les résultats. Je vais alors éviter d’y penser jusqu’à ce moment, puisque réfléchir sur ce nodule ne changera strictement rien à la situation. Il y a lieu de lâcher-prise et de profiter de mes journées du mieux que je peux. » </p>\n<p>La solution par excellence est d’accomplir ce qui se trouve en votre pouvoir (dans ce cas, prendre rapidement rendez-vous). Puis, vu que vous devez ensuite attendre deux semaines, ce n’est ainsi plus de votre ressort et il convient à ce moment de lâcher-prise. </p>\n<p>Dans cet exemple, vous avez donc agi de votre côté de la bonne manière et de l’autre, vous faites confiance à la vie en apprenant à tolérer l’incertitude. C’est compliqué, c’est vrai, mais il s’agit vraiment de la meilleure façon de penser pour vous en sortir.</p>\n<h3>Travailler sur l’estime de soi</h3>\n<p>Une solide estime de soi demeure primordiale pour se débarrasser de tout type de troubles anxieux. En ressentant de l’amour pour vous, vous comprendrez que vous n’êtes pas plus fragile qu’un autre. Ou que vous n’allez pas attraper plus de maladies que d’autres. Qu’avoir ce problème ne fait pas de vous quelqu’un d’anormal ou de moins bien qu’un autre. Que l’<b>hypocondrie sévère reste</b> un trouble anxieux qui se soigne et que vous y arriverez ! </p>\n<p>(Si vous aimez mon travail 🙂)</p>','published',1,'Hypocondrie Sévère : Soigner ce Trouble Invalidant pour Retrouver la Joie','L\'hypocondrie est la peur excessive d’attraper une maladie grave. Cette phobie constitue un réel handicap Comment se libérer de l’hypocondrie sévère ?','https://vivre-pleinement.fr/hypocondrie/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/hypocondrie\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/hypocondrie\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Hypocondrie S\\u00e9v\\u00e8re : Soigner ce Trouble Invalidant pour Retrouver la Joie\",\"datePublished\":\"2019-09-10T18:54:57+00:00\",\"dateModified\":\"2024-02-12T19:50:54+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/hypocondrie\\/\"},\"wordCount\":4469,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/hypocondrie\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/09\\/Hypocondrie-severe.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/hypocondrie\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/hypocondrie\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/hypocondrie\\/\",\"name\":\"Hypocondrie S\\u00e9v\\u00e8re : Soigner ce Trouble Invalidant pour Retrouver la Joie\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/hypocondrie\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/hypocondrie\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/09\\/Hypocondrie-severe.jpg\",\"datePublished\":\"2019-09-10T18:54:57+00:00\",\"dateModified\":\"2024-02-12T19:50:54+00:00\",\"description\":\"L\'hypocondrie est la peur excessive d\\u2019attraper une maladie grave. Cette phobie constitue un r\\u00e9el handicap Comment se lib\\u00e9rer de l\\u2019hypocondrie s\\u00e9v\\u00e8re\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/hypocondrie\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/hypocondrie\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/hypocondrie\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/09\\/Hypocondrie-severe.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/09\\/Hypocondrie-severe.jpg\",\"width\":1280,\"height\":853,\"caption\":\"Comment soigner l\\u2019hypocondrie severe ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/hypocondrie\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Hypocondrie S\\u00e9v\\u00e8re : Soigner ce Trouble Invalidant pour Retrouver la Joie\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-09-10 18:54:57',NULL,'2026-05-24 19:19:45','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (55,'Apprendre à se Détacher du Regard des Autres pour se Sentir Libre','jugement-des-autres','Nous sommes des milliards d’êtres humains sur terre et chacun possède sa personnalité. Certaines personnes nous ressemblent, d’autres vont apparaître différentes. Nous restons, en tout cas, uniques. Cependant, une chose nous lie tous : le jugement des autres. Tout le monde a effectivement une fâcheuse tendance à juger autrui, ce qui peut avoir de grosses conséquences sur le bonheur et la confiance en soi de tout un chacun. Vous entendez sans cesse des critiques autour de vous, mais bizarrement, jamais sur vous. Quand vous apprenez qu’un ami vous a critiqué dans le dos, vous éprouvez une forte trahison et n’arrivez pas à vous en remettre. Vous avez pris cette critique trop à cœur. Vous passez un agréable repas avec votre belle-famille et tout à coup, votre belle-mère vous lance un pic gratuit sans raison. Le regard de l’autre vous pèse-t-il au point de presque développer une anxiété sociale ? Comment apprendre à se détacher du regard des autres ?  \n','<p>Nous sommes des <b>milliards </b>d’êtres humains sur terre et chacun possède sa <b>personnalité</b>. Certaines personnes nous <b>ressemblent</b>, d’autres vont apparaître <b>différentes</b>. Nous restons, en tout cas, <b>uniques</b>. Cependant, une chose nous lie tous : le <b>jugement des autres. </b>Tout le monde a effectivement une fâcheuse tendance à juger autrui, ce qui peut avoir de grosses conséquences sur le bonheur et la confiance en soi de tout un chacun. Vous entendez sans cesse des <b>critiques </b>autour de vous, mais bizarrement, <b>jamais </b>sur vous. Quand vous apprenez qu’un ami vous a critiqué dans le <b>dos</b>, vous éprouvez une forte <b>trahison </b>et n’arrivez pas à vous en remettre. Vous avez pris cette critique trop à <b>cœur</b>. Vous passez un agréable <b>repas </b>avec votre belle-famille et tout à coup, votre belle-mère vous lance un <b>pic gratuit</b> sans raison. Le regard de l’autre vous pèse-t-il au point de presque développer une <b>anxiété sociale </b>? Comment <b>apprendre à se détacher du regard des autres ?</b>  </p>\n<h2>Pourquoi jugeons-nous les autres ? </h2>\n<h3>Des croyances différentes </h3>\n<p>Nous sommes tellement nombreux sur terre que personne ne peut se ressembler. Vous rencontrerez dans votre vie des individus possédant le même genre de centres d’intérêt que vous une personnalité semblable. Ils pourront donc devenir vos amis, même s’ils ne seront pas à 100 % identiques à vous. Ils présenteront généralement un parcours et une éducation similaires.</p>\n<p>Cependant, d’autres personnes apparaîtront tellement différentes que vous pourrez ne pas comprendre leur façon d’agir. Une forme d’intolérance pourra alors se dessiner. Vos parents vous ont probablement inculqué certaines <a href=\"/croyances\" target=\"_blank\" rel=\"noopener\" title=\"Croyances\">croyances</a> sur ce qui est bien et mal de faire ou d’être. </p>\n<p>Par exemple, vous contenez toujours vos émotions, car vos éducateurs vous ont appris que les personnes exprimant leurs sentiments étaient des mal élevées et ne savaient pas se tenir. Vous allez donc automatiquement juger négativement une personne s’énervant en public en disant ce qu’elle pense. Vous pouvez même éprouver de la colère à son égard.</p>\n<h3>Juger autrui, c’est se juger </h3>\n<p>Bien souvent, quand un comportement d’une personne vous agace énormément, c’est qu’il résonne en vous. Avez-vous déjà remarqué que certains défauts d’autrui ne vous posent pas de problème ? Par exemple, si une personne apparaît profondément narcissique et que vous n’avez pas ce trait de caractère, ces comportements peuvent vous faire sourire. Par contre, si vous avez tendance à tout vouloir contrôler et à donner des ordres, un individu vous faisant subir la même chose pourra vraiment vous faire sortir de vos gonds. </p>\n<h3>Pour appartenir au groupe</h3>\n<p>Il est normal de bien vouloir s’entendre avec autrui. Pour appartenir à une communauté, bien souvent, l’être humain est plus ou moins obligé de participer à certains commérages. En effet, la médisance, contre toute attente, peut renforcer certains liens et créer des affinités. Vous critiquez plus par automatisme ou par habitude qu’autre chose quand vous souhaitez intégrer un groupe. Dans votre job, par exemple, vos collègues s’intéresseront beaucoup plus à vos propos si vous êtes Madame/Monsieur scoop que si vous êtes le médiateur et le sage répandant la bonne parole. C’est vraiment dommage, mais c’est malheureusement ainsi. Les gens aiment les histoires, car elles leur permettent de passer le temps au travail et de rendre la journée un peu plus palpitante.</p>\n<h3>Pour se rassurer</h3>\n<p>En jugeant autrui avec d’autres personnes, vous pensez être protégé, car vous ne constituez pas la cible des critiques. Du moins, pour cette fois, puisque cette sensation de protection ne reste que momentanée. Vous savez pertinemment au fond de vous que vous êtes tout autant critiqué de votre côté. Vous entendez en effet des remarques négatives sur tout votre entourage, sauf sur vous. Tout le monde juge tout le monde, mais fait en sorte que rien ne se sache. </p>\n<p>De même, critiquer quelqu’un permet de vous croire momentanément supérieur à lui en pensant que vos défauts sont moins importants. En réalité, vous êtes rassuré que les autres possèdent aussi des lacunes.</p>\n<p>Enfin, bien souvent, quand une personne critique beaucoup, c’est parce qu’elle pense être également beaucoup critiquée. Par conséquent, il s’agit d’une protection de sa part. Un peu comme si elle souhaitait juger un individu par avance au cas où elle subirait des critiques de ce même individu. Elle évite ainsi d’être déçue et blessée. Donc, au contraire, une personne ayant tendance à se moquer du jugement des autres sera plus portée à vivre sa vie pleinement, à passer à l’action et de fait, ne ressentira pas le besoin de critiquer à son tour. Elle portera son attention sur autre chose : le fait d’avancer, d’être actrice de son existence.</p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"250\" src=\"/storage/blog-images/Jugement-autres.jpg\" alt=\"Medisance\" title=\"Jugement-autres\">\n<h2>D’où vient la peur d’être jugé ? </h2>\n<h3>Le réveil d’anciennes blessures </h3>\n<p>Comme le dit si bien le proverbe, ce qu’on ne sait pas ne blesse pas. En apprenant qu’une personne vous a critiqué par-derrière, ou même si elle le fait ouvertement devant vous, son attitude peut réouvrir de grosses blessures que vous avez déjà. J’ai créé sur mon blog une <a href=\"/category/blessures-de-lame\" target=\"_blank\" rel=\"noopener\" title=\"Blessures de l\'âme\">catégorie sur les blessures de l’âme,</a> car il est primordial de les connaître pour devenir conscient et entamer un processus de guérison de votre enfant intérieur.</p>\n<p>Pour information tout de même, si une personne vous critique négativement, vous pouvez vous sentir : trahi, humilié, abandonné, rejeté, ou ressentir une grande injustice.</p>\n<p>Par conséquent, le fait de ne pas guérir vos blessures peut vraiment vous porter préjudice. En effet, vous pouvez développer de la rancune, de la tristesse, un gros manque d’estime de vous, de la colère refoulée et donc, beaucoup de souffrance. Le problème, si vous ne traitez pas ces émotions et qu’elles perdurent, elles pourront clairement vous ronger de l’intérieur, et ce, au sens propre comme au figuré. Vous pouvez déclencher de véritables troubles psychologiques, tels que la dépression, par exemple, ou de graves maladies, telles qu’un cancer.</p>\n<h3>Une perte de l’estime de soi </h3>\n<p>Si une personne vous fait du mal étant donné qu’elle vous trouve différent, elle vous fait passer comme message que vous demeurez inférieur à elle. Cependant, il n’en est rien. Car malgré nos différences, personne n’est meilleur que personne. Mais malheureusement, l’être humain a tendance à penser ainsi. </p>\n<p>Par contre, si vous avez déjà une faible estime de vous-même, ladite critique va vraiment vous faire croire à votre infériorité. Vous allez donc vous créer des croyances négatives et de là, ne pourrez qu’aller de moins en moins bien et développer un sentiment de dévalorisation. En effet, <a href=\"/confiance-et-estime-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Confiance et estime de soi\">l’amour de soi</a> demeure primordiale pour trouver la paix intérieure.</p>\n<h3>La peur de finir sa vie seul</h3>\n<p>Vous avez peur qu’un jugement sur vous signifie que vous n’êtes pas aimé. Et étant donné que l’humain est un animal social, il a besoin de plaire et ne pourra supporter cette croyance d’être détesté. </p>\n<p>Si vous possédez ce genre de croyances, c’est que la critique vous a vraiment fait mal au niveau de votre être le plus profond. Pourtant, bien souvent, la personne qui vous critique ne juge qu’un de vos comportements (par exemple, si vous êtes souvent en retard) et non votre personne entière. Attention donc de bien faire la différence entre les deux.</p>\n<img decoding=\"async\" width=\"1280\" height=\"1154\" src=\"/storage/blog-images/Critiques.jpg\" alt=\"Commerages\" title=\"Critiques\">\n<h2>Comment apprendre à se détacher du regard des autres ? </h2>\n<p>Comme vous pouvez le constater, il est important de ne pas prendre à cœur ce que les gens peuvent penser de vous. Leurs critiques doivent vous passent au-dessus. Même si elles provoquent en vous des contrariétés, ce qui est humain, ne restez pas bloqué dessus. Vous éviterez ainsi de développer un sentiment de rancune, lequel reste un véritable frein pour acquérir le bien-être. Il faut donc vivre votre vie pleinement en cessant d’avoir peur du jugement des autres. Comment faire face au regard des autres ? </p>\n<h3>Accepter que vous serez jugé toute votre vie et constamment</h3>\n<p>C’est un peu malheureux, mais je peux vous assurer qu’il s’agit d’une vérité. Tout le monde vous jugera, et ce, constamment<b>.</b> Et même vos proches ! Il en va ainsi de l’être humain, lequel a besoin de juger pour toutes les raisons citées ci-dessus. Et c’est bien évidemment pareil pour les autres, qui seront toujours jugés eux aussi et par tout le monde. Il y a donc un gros travail <a href=\"/lacher-prise-et-acceptation\" target=\"_blank\" rel=\"noopener\" title=\"Lâcher-prise et acceptation\">d’acceptation et de</a><a href=\"/lacher-prise-et-acceptation\" target=\"_blank\" rel=\"noopener\" title=\"Lâcher-prise et acceptation\"> lâcher-prise</a> sur soi à réaliser de ce côté. Car si vous ne pouvez en effet changer autrui, vous pouvez par contre modifier votre façon de percevoir le jugement des gens pour aller mieux.</p>\n<p>Dites-vous bien également que quand des individus apprécieront ce que vous êtes ou faites, d’autres désapprouveront totalement. Nous demeurons en effet tous différents et même si l’on pense que certains sont comme nous, ce n’est pas vrai. Ils resteront quand même distincts sur certains points. Et c’est la différence qui entraîne les jugements incessants.</p>\n<p>Nous pouvons prendre comme exemple les célébrités ayant des fans qui les idolâtrent d’un côté et ce que nous appelons des « haters », de l’autre. Ces « haters », bien que les détestant, se mêlent tout de même de leur vie et les suivent.</p>\n<p>Dites-vous donc bien qu’il est impossible d’être aimé par tout le monde, et ce, même si vous êtes le plus grand sage de la terre. Il y aura toujours un camp pour vous et contre vous. C’est le principe de la dualité. Et c’est ainsi. Inutile alors de ressentir la crainte de déplaire.</p>\n<h3>Comprendre que les autres émettent des jugements de valeur </h3>\n<p>Quand une personne vous juge, c’est souvent sur une attitude que vous utilisez fréquemment et qui apparaît différente du sien. Les gens tolèrent rarement la différence et seront donc portés à juger facilement. </p>\n<p>Par contre, ces individus ne jugent pas votre être profond, vu qu’ils ne le connaissent pas ! Au mieux, ils portent des jugements hâtifs sur un comportement ou l’image sociale que vous dégagez sur le moment. Au final, ils ne vous jugent pas réellement, mais critiquent seulement une petite facette de votre personnalité, soit 5 % environ de ce vous représentez véritablement. Pas de quoi s’affoler, donc. </p>\n<p> </p>\n<h3>Remarquer que la personne critique par automatisme</h3>\n<p>La personne vous critique peut-être seulement pour appartenir à un groupe. En effet, vu que les absents ont tort, vous représentez peut-être le sujet de conversation de l’instant (eh oui, désolée). Ces critiques sont donc automatiques.</p>\n<h3>Vous apercevoir qu’une personne critique pour se rassurer </h3>\n<p>Une personne peut également vous critiquer, car elle est persuadée que vous le faites de votre côté. Dans ce cas, le jugement de l’autre constitue une protection de sa part due au manque d’estime qu’il a pour lui-même.</p>\n<h3>Vous rendre compte qu’une personne ressent de la jalousie </h3>\n<p>Il faut également le dire : si quelqu’un vous critique fréquemment, c’est que vous le préoccupez. Il peut effectivement vous envier si, par exemple, vous arrivez à vous exprimer sans avoir peur des conséquences alors que lui s’en sent incapable. Essayez de rechercher sur quoi cette personne pourrait vous jalouser et je suis sûre que vous arriverez à trouver de petits éléments. </p>\n<a href=\"https://hypnocaments.com?partnerid=YK5muYugzSoIWDbDWRgT-Q\" title=\"Seances d hypnose en ligne\"><img decoding=\"async\" src=\"https://hypnocaments.com/image/banner_1_750.png\" alt=\"seance hypnose mp3\"></a>\n<h3>Comprendre que la personne n’admet pas avoir le même comportement</h3>\n<p>Les gens n’aiment en général pas assumer leurs défauts. Ils vont donc détester cette part de vous qui est comme la leur. De ce fait, si une personne vous critique sur un comportement, essayez de voir si elle n’aurait pas tendance à revêtir également la même attitude que vous.</p>\n<p> </p>\n<h3>Remarquer que la personne se sent mal dans sa peau </h3>\n<p>Je suis certaine de ce que j’affirme. Plus un individu critique les autres et plus il se sent mal dans sa peau. Regardez autour de vous les personnes heureuses. Je ne pense pas qu’elles passent leur existence à juger constamment. Analysez aussi une personne qui semble prendre sa vie en main, être actrice de sa vie, entreprendre des tas d’activités, pour elle-même et pour faire avancer le monde. En général, ce genre d’individus n’a pas beaucoup le temps de s’attarder sur les regards des gens. </p>\n<p>Attention, je ne dis pas que dès que nous critiquons, nous nous sentons mal dans notre peau, car malheureusement, nous le faisons tous. Je pense plutôt aux personnes critiquant constamment et trouvant des défauts chez tout le monde sans arrêt, les rendant finalement aigries. Elles sont probablement plus souffrantes que la moyenne. </p>\n<h3>Vous demander ce que le jugement change concrètement dans votre vie </h3>\n<p>Même si un individu vous a blessé avec une remarque qu’il vous a faite, demandez-vous réellement ce que ce jugement négatif va véritablement changer dans votre existence. Allez-vous perdre votre travail ? Votre famille ? Une catastrophe naturelle va-t-elle s’abattre ? Non, pas vrai ? Mis à part la rancœur que vous pourrez éprouver et les films que vous pourrez vous faire dans votre tête, rien de dramatique ne va arriver dans votre vie. </p>\n<p>Et même si la personne vous critique constamment auprès de tout le monde, pensez-vous que ses jugements négatifs vont vraiment changer votre existence ? C’est elle qui est en train de se rendre malade à penser négativement sans arrêt sur quelqu’un. Et se préoccuper des autres ainsi prouve qu’elle n’a pas vraiment d’occupations enrichissantes… </p>\n<p>Enfin, il en va de votre responsabilité de percevoir cette remarque comme une simple remarque, point. À vous de ne pas en faire tout un plat et de vous concentrer sur vos objectifs dans la vie. Vous n’avez pas le temps de vous soucier des jugements des autres si vous osez évoluer. Même si quelqu’un vous critique, demain sera la même journée qu’aujourd’hui. Ce jugement d’autrui ne changera pas la face du monde. Si une critique apparaît constructive, pourquoi pas. Sinon, au revoir. Vous n’avez pas de temps à perdre avec le regard des gens et la méchanceté gratuite. Vous avez tant de belles choses à construire !</p>\n<p> </p>\n<p><b>Apprendre à se détacher du regard des autres</b> est donc possible, et je vous souhaite vraiment d’être heureux. Vous verrez que la qualité de votre vie va grandement s’améliorer, vous allez vous sentir mieux. </p>\n<p>Pour aller plus loin sur ce sujet, je vous suggère le <strong>programme</strong> de <strong>Didier PENISSARD, auteur, conférencier et coach en développement personnel.</strong> Vous pouvez le trouver en cliquant sur le bouton ci-dessous :</p>\n<p>Si vous aimez mon travail 🙂</p>','published',1,'Apprendre à se Détacher du Regard des Autres pour se Sentir Libre','Tout le monde a tendance à juger autrui, ce qui peut avoir de lourdes conséquences sur le bien-être. Comment apprendre à se détacher du regard des autres ?','https://vivre-pleinement.fr/jugement-des-autres/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/jugement-des-autres\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/jugement-des-autres\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Apprendre \\u00e0 se D\\u00e9tacher du Regard des Autres pour se Sentir Libre\",\"datePublished\":\"2019-09-03T20:39:27+00:00\",\"dateModified\":\"2024-02-13T19:29:35+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/jugement-des-autres\\/\"},\"wordCount\":4503,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/jugement-des-autres\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/09\\/Apprendre-detacher-regard-autres.png\",\"articleSection\":[\"D\\u00e9veloppement personnel\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/jugement-des-autres\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/jugement-des-autres\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/jugement-des-autres\\/\",\"name\":\"Apprendre \\u00e0 se D\\u00e9tacher du Regard des Autres pour se Sentir Libre\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/jugement-des-autres\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/jugement-des-autres\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/09\\/Apprendre-detacher-regard-autres.png\",\"datePublished\":\"2019-09-03T20:39:27+00:00\",\"dateModified\":\"2024-02-13T19:29:35+00:00\",\"description\":\"Tout le monde a tendance \\u00e0 juger autrui, ce qui peut avoir de lourdes cons\\u00e9quences sur le bien-\\u00eatre. Comment apprendre \\u00e0 se d\\u00e9tacher du regard des autres\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/jugement-des-autres\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/jugement-des-autres\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/jugement-des-autres\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/09\\/Apprendre-detacher-regard-autres.png\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/09\\/Apprendre-detacher-regard-autres.png\",\"width\":603,\"height\":640,\"caption\":\"Comment se liberer du regard des autres ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/jugement-des-autres\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Apprendre \\u00e0 se D\\u00e9tacher du Regard des Autres pour se Sentir Libre\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-09-03 20:39:27',NULL,'2026-05-24 19:19:45','2026-06-19 22:28:14');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (56,'Guérir d’un Trouble Anxieux Généralisé, c’est Possible','trouble-anxieux-generalise','Le trouble anxieux généralisé, communément appelé TAG, est un type de trouble anxieux. Il touche principalement les femmes. Les personnes touchées ont généralement un tempérament bileux à la base. Ce trait de personnalité s’est cependant aggravé pour devenir un véritable mal-être. Il peut en effet considérablement nuire à la qualité de vie de l’individu, qui passe son temps à se faire du souci pour presque tout. Votre fils a 5 minutes de retard et vous l’imaginez déjà mort. Dès que votre mari prend la route, vous pensez sans cesse à l’accident, mortel bien évidemment. Bien dormir, vous ne connaissez pas, puisque vous appréhendez toute la nuit votre journée de travail du lendemain. Quand votre téléphone sonne, vous répondez toujours avec appréhension, car craignez une nouvelle terrible. Ce TAG vous épuise et vous mine le moral ? Comment guérir d’un trouble anxieux généralisé ? \n','<h2>Trouble anxieux généralisé : comment s\'en sortir ?</h2>\n<p>Vous vivez avec une inquiétude permanente, une boule au ventre qui ne vous lâche pas, l\'impression d\'anticiper sans cesse le pire. Le <b>trouble anxieux généralisé</b> (TAG) est épuisant — mais ce n\'est ni une fatalité, ni un trait de caractère immuable. On peut s\'en sortir, et le plus souvent <b>sans s\'enfermer à vie dans les médicaments</b>.</p>\n<p>S\'en libérer durablement repose sur trois leviers complémentaires :</p>\n<ul>\n<li><b>Comprendre le mécanisme de l\'anxiété</b> pour cesser de la nourrir, plutôt que de lutter contre elle.</li>\n<li><b>Apaiser le corps</b>, par la <a href=\"/blog/respiration\">respiration</a> et la relaxation, car le TAG s\'ancre autant dans le corps que dans le mental.</li>\n<li><b>Travailler le terrain en profondeur</b> : <a href=\"/blog/cause-des-troubles-anxieux\">les causes</a>, le rapport à l\'incertitude, et parfois un accompagnement thérapeutique.</li>\n</ul>\n<p>Voyons d\'abord ce qu\'est précisément le TAG, puis comment en guérir, étape par étape.</p>\n<p>Le trouble anxieux généralisé, communément appelé <b>TAG, </b>est un type de <b>trouble anxieux</b>. Il touche principalement les <b>femmes</b>. Les personnes touchées ont généralement un <b>tempérament bileux </b>à la base. Ce trait de personnalité s’est cependant <b>aggravé </b>pour devenir un véritable mal-être. Il peut en effet considérablement nuire à la qualité de vie de l’individu, qui passe son temps à se faire du <b>souci </b>pour presque <b>tout</b>. Votre fils a 5 minutes de <b>retard </b>et vous l’imaginez déjà <b>mort</b>. Dès que votre mari prend la <b>route</b>, vous pensez sans cesse à <b>l’accident, mortel</b> bien évidemment. Bien <b>dormir</b>, vous ne connaissez pas, puisque vous <b>appréhendez </b>toute la nuit votre journée de <b>travail </b>du lendemain. Quand votre <b>téléphone </b>sonne, vous répondez toujours avec appréhension, car craignez une nouvelle <b>terrible</b>. Ce TAG vous <b>épuise </b>et vous mine le <b>moral </b>? Comment <b>guérir d’un trouble anxieux généralisé ? </b></p>\n<h2>Qu’est-ce qu’un trouble anxieux généralisé ? </h2>\n<p>Tout le monde est anxieux. L’anxiété est normale. C’est elle qui vous permet de réagir rapidement en cas de véritable danger. Cependant, elle peut devenir pathologique à partir du moment où la personne doit accomplir de gros efforts pour vivre normalement. À partir de là, nous pouvons suspecter un début de TAG.</p>\n<p>Se faire du souci est normal dans le monde actuel prônant compétitivité, performance, matérialisme, etc. où il faut rester le meilleur, le plus fort. Nous nous mettons donc généralement une énorme pression pour essayer d’avoir l’image que la société prône.  </p>\n<p>Cependant, pour une personne étant atteinte de TAG, tout peut devenir rapidement handicapant, car elle s’inquiètera quotidiennement et sans cesse sur tous les sujets. Par exemple, elle pourra avoir peur qu’il arrive sans arrêt quelque chose de grave à ses enfants, son mari, etc. en voiture notamment, ou que ses proches tombent gravement malades. </p>\n<p>Le trouble anxieux généralisé se manifestera surtout dans les situations courantes de la vie. L’individu appréhendera tout ce qui pourrait mal se passer. C’est donc la principale différence avec les pensées irrationnelles et tordues que l’on peut retrouver dans les TOC. </p>\n<p>Par contre, une personne atteinte de TAG pourra très bien développer d’autres troubles anxieux tels que justement les TOC, la phobie sociale, les attaques de panique, etc. Ce cas est loin d’être rare ! Et forcément, vu que l’anxiété demeure un cercle vicieux, plus la personne se fait du souci, plus elle essaie de contrôler son trouble et plus elle rumine. Il est donc fréquent que différentes affections apparaissent concomitamment. </p>\n<h2>Trouble anxieux généralisé et somatisation </h2>\n<p>Bien entendu, l’anxiété a un énorme lien avec les symptômes physiques et émotionnels que vous allez probablement ressentir. Je les liste ici afin que vous soyez rassuré sur leur provenance. Les principales manifestations peuvent être les suivants : </p>\n<p> </p>\n<h3>Trouble anxieux généralisé avec symptômes physiques </h3>\n<ul>\n<li aria-level=\"1\">Fatigue, manque d’énergie, et ce, régulièrement (à force d’angoisser, votre corps ne détient plus d’énergie, ce n’est donc pas qu’une sensation) ;</li>\n<li aria-level=\"1\">Tensions musculaires pouvant en outre provoquer de fortes douleurs de dos, par exemple (ce qui peut davantage faire peur aux hypocondriaques) ;</li>\n<li aria-level=\"1\">Troubles digestifs ;</li>\n<li aria-level=\"1\">Éruptions cutanées comme des taches rougeâtres sur la peau, du psoriasis, de l’urticaire, etc. ;</li>\n<li aria-level=\"1\">Maux de tête voire migraine, ce qui peut même empêcher la personne de réaliser ses activités quotidiennes ;</li>\n<li aria-level=\"1\">Envie d’uriner fréquente, ce qui peut angoisser encore plus les personnes présentant un trouble de l’anxiété sociale. Ce symptôme peut aussi empêcher la personne de dormir convenablement s’il survient la nuit ;</li>\n<li aria-level=\"1\">Palpitations. </li>\n</ul>\n<h3>Trouble anxieux généralisé avec symptômes émotionnels </h3>\n<ul>\n<li aria-level=\"1\">Sentiment d’être à bout de nerfs, irritable et avoir la crainte de perdre le contrôle et de faire une crise de nerfs ; </li>\n<li aria-level=\"1\">Difficulté à se concentrer et problèmes de mémoire (ce qui est vicieux, car la personne anxieuse risque de vraiment penser devenir folle et aura encore plus peur) ;</li>\n<li aria-level=\"1\"><a href=\"/insomnie\" target=\"_blank\" rel=\"noopener\" title=\"Insomnie\">Insomnie</a> (endormissement rapide, mais réveil en début de matinée sans pouvoir se rendormir par exemple, ou angoisse nocturne, matinale, etc.) La personne apparaîtra donc de plus en plus irritable et aura également plus de mal à se concentrer suite au manque de sommeil.</li>\n</ul>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"960\" height=\"640\" src=\"/storage/blog-images/Souci-permanent.jpg\" alt=\"Inquietude excessive \" title=\"Souci-permanent\">\n<h2>Les conséquences du TAG</h2>\n<p>Par conséquent, tous ces symptômes affaiblissent le système immunitaire de la personne. Elle peut donc être plus sujette à certaines maladies que les autres telles que les rhumes de l’hiver, par exemple.</p>\n<p>À force de demeurer sous tension, les personnes voudront probablement se détendre et certaines iront même jusqu’à boire <a href=\"/addictions\" target=\"_blank\" rel=\"noopener\" title=\"Addictions\">plus d’alcool que de raison ou prendre des substances illicites. </a></p>\n<p>Certaines n’arriveront plus à vivre normalement, à aller travailler, à voir du monde, etc. ou devront accomplir d’énormes efforts pour y arriver, ce qui peut mener à une grande fatigue psychique.</p>\n<p>Le risque principal, si ce trouble s’aggrave et n’est pas traité, est que la personne sombre dans une dépression. En effet, si elle ne possède plus d’énergie et commence à se dire qu’elle ne peut rien réaliser et perd donc espoir, il y a des chances de connaître cette complication.</p>\n<h2>Les causes du TAG</h2>\n<p>Comme souvent pour un trouble, il n’y a rarement qu’une seule cause prédéfinie, mais plusieurs causes s’établissant sur la durée. </p>\n<p>La personne possédera fréquemment à la base un tempérament anxieux. Il y a donc une part de génétique.</p>\n<p>De plus, l’éducation dont notamment des parents angoissés pourront aggraver le trait de personnalité avec des habitudes anxiogènes. À la longue, l’anxiété chronique peut apparaître. </p>\n<p>De même, certains évènements tragiques de la vie, tels le décès d’un proche, une maladie grave comme un cancer, un licenciement, un divorce, etc. pourront développer un TAG.</p>\n<img decoding=\"async\" width=\"960\" height=\"640\" src=\"/storage/blog-images/TAG.jpg\" alt=\"Insecurite \" title=\"TAG\">\n<h2>Comment guérir d’un trouble anxieux généralisé ? </h2>\n<p>Heureusement, il existe des solutions afin de venir à bout de votre anxiété généralisée. Voici les principales : </p>\n<h3>La thérapie cognitivo-comportementale </h3>\n<p>En effet, la TCC aidera la personne à se détourner de ses ruminations et à lâcher-prise sur les soucis où elle ne peut avoir de contrôle. Elle s’exercera sur le fait de laisser passer ses pensées, ce qui réduira clairement l’anxiété. Je vous laisse prendre connaissance de mon <a href=\"/psychotherapie-et-psychanalyse\" target=\"_blank\" rel=\"noopener\" title=\"Psychothérapie et psychanalyse\">article</a> sur les thérapies.</p>\n<h3>Certains médicaments tels que les antidépresseurs ou les anxiolytiques</h3>\n<p>Quelquefois, la prise d’un traitement peut apparaître nécessaire si la personne commence à déprimer et n’arrive plus à vivre une vie normale. Je vous laisse lire mon <a href=\"/antidepresseurs-et-anxiolytiques\" target=\"_blank\" rel=\"noopener\" title=\"Antidépresseurs et anxiolytiques\">article</a> sur ce sujet.</p>\n<h3>Les techniques de relaxation</h3>\n<p>Il existe beaucoup de méthodes de relaxation afin de détendre votre corps et votre esprit. Et vu que l’anxiété lie troubles physiques et émotionnels, cette pratique ne sera qu’un gros plus pour vous.</p>\n<p>Vous pouvez déjà pratiquer des techniques de respiration. En effet, rien de tel que la respiration pour calmer profondément votre organisme et de fait, vos émotions. Un article est pleinement consacré à ce sujet, car je trouve qu’il est primordial d’en parler.</p>\n<p> </p>\n<p>La technique de respiration que j’utilise personnellement est la cohérence cardiaque. Grâce à l’appareil ZENSPIRE émettant des vibrations et de la lumière, j’ai appris à respirer profondément et à réguler mon organisme comme il le faut. Si vous souhaitez en savoir plus sur ce produit, n’hésitez pas à cliquer sur le bouton ci-dessous, étant précisé que si vous passez commande, une remise de 10 % vous sera accordée et ce, en utilisant le code JL0620<b></b><b> :</b></p>\n<p>Vous pouvez également vous adonner au yoga, qui peut être un bon moyen de vous détendre tout en réalisant des gestes souples avec votre corps. </p>\n<p>La méditation est aussi vivement recommandée contre l’anxiété. Cette technique est en effet en plein essor. Il y en a plusieurs types, mais celle étant conseillée pour l’angoisse est celle où la personne prête attention à ses pensées, mais tout en les laissant passer. </p>\n<p>Vous pouvez de plus essayer la méthode JACOBSON. Elle consiste à contracter vos muscles puis à les relâcher, en vous focalisant sur la sensation de détente que le relâchement procure.</p>\n<p>Il y a également la sophrologie, l’acupuncture, etc.</p>\n<p>À vous de vous renseigner sur mon blog et ailleurs afin de trouver la ou les méthodes qui marcheront sur vous. Il y a en a en effet tellement ! Inutile de vous dire que vous ne vous relaxerez jamais assez, donc n’hésitez pas à tenter plein de techniques !</p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img loading=\"lazy\" decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h3>Intégrer un groupe de parole présentant le même type de problème</h3>\n<p>Pourquoi ne pas essayer de trouver dans votre région un groupe de parole présentant le même genre de troubles que vous ? Rien de tel que de parler pour aller mieux et surtout, pour se sentir compris, ce qui est rarement le cas avec des proches qui n’ont pas ces soucis. Après, attention de vous tirer vers le haut pour chercher à vous en sortir et non de vous victimiser tous ensemble. C’est pourquoi il est préférable que le groupe de parole soit encadré par un professionnel. </p>\n<p>Attention aussi aux forums sur Internet. Ils vous rassurent sur le coup, mais deviennent ensuite comme une drogue et vous avez sans arrêt besoin de vous faire rassurer. De plus, ce que vous lirez vous fera très souvent extrêmement peur. </p>\n<p> </p>\n<h3>Changer ses habitudes de vie </h3>\n<p>En étant anxieux, vous pouvez prendre de très mauvaises habitudes telles que fumer, par exemple. Réduire, voire même, arrêter votre consommation de cigarette si vous le pouvez ne pourra que vous être bénéfique.</p>\n<p>L’alcool demeure également un faux-ami. En effet, en prenant un verre, la personne se détendra et ses pensées apparaîtront plus positives et sereines. Vu que l’alcool reste un anxiolytique naturel, cette réaction est normale. Cependant, boire peut vite devenir un piège, la personne pensant qu’elle ne peut aller bien qu’en buvant. D’où le risque accru d’alcoolisme. Et malheureusement, en buvant, elle ira effectivement bien sur le coup, mais toutes ses ruminations reviendront aussitôt les effets de la boisson passés. Ce n’est donc pas la solution.</p>\n<p>Je mets également le café dans les habitudes nocives, car cette substance, si elle n’apparaît pas dangereuse, ne fait pas de bien à la personne angoissée. Elle provoque souvent chez elle d’ailleurs des palpitations. Ce n’est pas étonnant, étant donné que le café reste un excitant. C’est pourquoi il n’est pas conseillé pour un individu souffrant d’anxiété chronique. Il n’a en effet pas besoin d’angoisser davantage. Si vous en êtes accro, vous n’êtes pas forcément obligé de ne plus en consommer du tout. Essayer déjà de limiter la prise de caféine. Je pense que vous obtiendrez vite des résultats.</p>\n<h3>Faire du sport </h3>\n<p>Le sport est bien connu pour augmenter la production d’endorphine. Cette hormone procure du plaisir et de la détente. Inutile de vous dire qu’elle se trouve forcément bénéfique pour une personne anxieuse avec une humeur dépressive. Cependant, il se peut que vous ayez du mal à commencer le sport en ressentant une grosse baisse d’énergie. Même si c’est difficile au début, allez-y petit à petit et vous verrez que votre tonus reviendra progressivement.</p>\n<p>L’exercice physique favorise également le sommeil suite à l’activité intensive pratiquée par le corps. Que du bon donc pour les personnes avec des tendances insomniaques.</p>\n<h3>Manger sain </h3>\n<p>La nutrition a un rôle prépondérant pour une bonne santé physique et émotionnelle. Je dis toujours que l’on se nourrit comme on se respecte. De ce fait, plus vous aurez une solide estime de vous-même et plus vous serez tenté de donner à votre organisme de bons aliments. Le corps possédera donc tous les nutriments nécessaires et forcément, votre santé mentale s’améliorera. </p>\n<p>Vous avez tout de même le droit de manger sucré ou gras de temps à autre. Il ne faut pas tomber dans l’abus. Mais essayez d’avoir un mode d’alimentation sain au moins la plupart du temps. </p>\n<p>Vous pouvez d’ores et déjà commencer à réduire le sucre. Il demeure en effet très néfaste pour votre santé. Le sucre raffiné, j’entends, que vous trouvez dans tous les plats préparés, transformés, gras, ainsi que dans les sucreries, etc. Votre corps en a besoin, mais pas de ce type de sucre. Essayez déjà de le supprimer de votre café quotidien ou de votre tisane et de réduire le jus d’orange tout fait en bouteille. Ce genre de petites habitudes sera un bon début.  </p>\n<p>D’ailleurs, pour vous aider à bien vous <strong>alimenter</strong>, je vous conseille le programme de <strong>Rémi MOHA, coach sportif</strong> et<strong> auteur du livre <em>“Synergie alimentaire”</em>.</strong> Si vous ne connaissez pas encore cette façon de s’alimenter, c’est le moment de vous y intéresser. Car en effet, la synergie alimentaire, de par certaines <strong>combinaisons</strong> entre plusieurs <strong>aliments</strong>, apportera à votre organisme beaucoup <strong>d’énergie</strong>, une <strong>très bonne santé</strong> et vous aidera même à <strong>perdre du poids.</strong> Pour découvrir la synergie alimentaire, c’est ici : </p>\n<p>Je vous ai donc donné certaines clés pour <b>guérir d’un trouble anxieux généralisé.</b> À vous de jouer ! </p>\n<p>Si vous aimez mon travail 🙂</p>','published',1,'Trouble Anxieux Généralisé : Comment S\'en Sortir Durablement','Le trouble anxieux généralisé (TAG) vous épuise à force de tout anticiper ? Comprenez ses causes et découvrez comment vous en sortir, naturellement et durablement.','https://vivre-pleinement.fr/trouble-anxieux-generalise/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/trouble-anxieux-generalise\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/trouble-anxieux-generalise\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Gu\\u00e9rir d\\u2019un Trouble Anxieux G\\u00e9n\\u00e9ralis\\u00e9, c\\u2019est Possible\",\"datePublished\":\"2019-08-29T16:32:47+00:00\",\"dateModified\":\"2024-02-13T17:27:24+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/trouble-anxieux-generalise\\/\"},\"wordCount\":4326,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/trouble-anxieux-generalise\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/08\\/Guerir-trouble-anxieux-generalise.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/trouble-anxieux-generalise\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/trouble-anxieux-generalise\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/trouble-anxieux-generalise\\/\",\"name\":\"Gu\\u00e9rir d\\u2019un Trouble Anxieux G\\u00e9n\\u00e9ralis\\u00e9, c\\u2019est Possible\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/trouble-anxieux-generalise\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/trouble-anxieux-generalise\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/08\\/Guerir-trouble-anxieux-generalise.jpg\",\"datePublished\":\"2019-08-29T16:32:47+00:00\",\"dateModified\":\"2024-02-13T17:27:24+00:00\",\"description\":\"La personne souffrant de trouble anxieux g\\u00e9n\\u00e9ralis\\u00e9 passe son temps \\u00e0 se faire du souci pour presque tout. Comment gu\\u00e9rir d\\u2019un trouble anxieux g\\u00e9n\\u00e9ralis\\u00e9\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/trouble-anxieux-generalise\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/trouble-anxieux-generalise\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/trouble-anxieux-generalise\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/08\\/Guerir-trouble-anxieux-generalise.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/08\\/Guerir-trouble-anxieux-generalise.jpg\",\"width\":720,\"height\":720,\"caption\":\"Comment guerir d\\u2019un trouble anxieux generalise ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/trouble-anxieux-generalise\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Gu\\u00e9rir d\\u2019un Trouble Anxieux G\\u00e9n\\u00e9ralis\\u00e9, c\\u2019est Possible\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-08-29 16:32:47',NULL,'2026-05-24 19:19:45','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (57,'Angoisse et Culpabilité Permanente : se Libérer de cette Emotion Toxique','culpabilite','Lorsque vous souffrez de troubles anxieux, vous subissez bien souvent une double peine : l’angoisse et la culpabilité d’être dans cet état. Il est important d’en parler, car angoisse et culpabilité permanente ne font pas bon ménage. En période de crise d’anxiété, vos proches ne comprennent pas et vous disent qu’un tout petit peu de volonté résoudra votre problème. Ils vous précisent que l’anxiété reste un choix et que vous pouvez vous réveiller un matin en prenant la décision de ne plus être anxieux et vous ne le serez plus. Vos proches vous pensent fragile. Avec ces discours, il est tout à fait normal de culpabiliser. Vous l’aurez compris, la culpabilité est la première chose à bannir pour aller mieux et avancer. Comment ne plus prendre à cœur les propos des autres ? Comment vous libérer de ce sentiment de culpabilité ? \n','<p>Lorsque vous souffrez de troubles anxieux, vous subissez bien souvent une<b> double peine </b>: l’angoisse et la culpabilité d’être dans cet état. Il est important d’en parler, car <b>angoisse et culpabilité permanente</b> ne font pas bon ménage. En période de crise d’anxiété, vos proches ne <b>comprennent pas</b> et vous disent qu’un tout petit peu de <b>volonté </b>résoudra votre problème. Ils vous précisent que l’anxiété reste un <b>choix </b>et que vous pouvez vous réveiller un matin en prenant la <b>décision </b>de ne plus être anxieux et vous ne le serez plus. Vos proches vous pensent <b>fragile</b>. Avec ces discours, il est tout à fait <b>normal </b>de culpabiliser. Vous l’aurez compris, la culpabilité est la première chose à <b>bannir </b>pour aller mieux et avancer. Comment ne plus prendre à <b>cœur </b>les propos des autres ? Comment vous <b>libérer </b>de ce sentiment de culpabilité ? </p>\n<h2>Le mécanisme de la culpabilité  </h2>\n<p>La culpabilité est un sentiment qui va souvent de pair avec l’anxiété. Effectivement, tout le monde peut ressentir de l’anxiété, car c’est naturel. Mais concernant l’angoisse pathologique, elle ne touche que certains d’entre nous. </p>\n<p>Néanmoins, lorsqu’une personne souffre de <a href=\"/angoisse-stress-anxiete\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse stress anxiété\">trouble anxieux</a> particulièrement invalidant, les personnes n’en souffrant pas ne comprennent pas. Il faut cependant comprendre que l’être humain est ainsi fait. Quand il ne comprend pas, il ne tolère pas. Par exemple, vous ne comprenez pas qu’une personne puisse avoir une véritable phobie des bananes, au point de hurler ou de pleurer quand elle en voit une ou doit en toucher une. Cette situation vous fait sourire et vous pensez que cet individu exagère. Vous commencez donc à avoir un tas de préjugés sur elle. D’autant plus si vous êtes une personne non anxieuse. </p>\n<p>Cependant, cette façon de réagir constitue l’expression de votre intolérance, car vous ne connaissez pas l’histoire de la personne et ne vous trouvez pas dans ses baskets. Si vous aviez vécu exactement la même existence qu’elle, nul doute que vous seriez comme elle. Il y a une forme d’égocentrisme de croire que vous, en ayant vécu sa vie, vous auriez beaucoup mieux géré la situation. </p>\n<p>La culpabilité a donc deux principales raisons d’exister. La première demeure la pression sociale qui fait bien comprendre à une personne qu’elle ne tolère pas notre état d’angoisse. La deuxième raison se trouve dans les blessures que vous avez acquises depuis l’enfance, comme, par exemple, la peur d’être abandonné.</p>\n<h2>Angoisse et culpabilité permanente, un frein à l’épanouissement </h2>\n<p><b> </b></p>\n<p>Souffrir d’angoisses profondes n’est pas évident. La personne n’a pas choisi de se trouver dans cet état. D’autant qu’elle peut souvent être plus sujette au <a href=\"/jugement-des-autres\" target=\"_blank\" rel=\"noopener\" title=\"Jugement des autres\">regard des autres.</a> Donc, quand ils la jugent, la personne va se sentir encore plus mal. Elle va se mettre la pression, croyant qu’elle fait exprès de se comporter ainsi, d’après ce que ses semblables lui disent. Elle fera tout pour faire plaisir à son entourage et pour prouver qu’elle peut maîtriser sa panique. </p>\n<p>Cependant, plus on tente de contrôler l’anxiété et plus elle se renforcera. L’individu va donc se sentir encore plus mal et de fait, les autres le comprendront encore moins et la culpabilité s’aggravera. Vous voyez le cercle vicieux ? Bien entendu, la personne peut se décourager et ne plus avoir d’énergie pour affronter son anxiété. Ce qui peut l’amener à la dépression. </p>\n<p>D’ailleurs, pour vous soulager du <strong>regard des autres</strong>, je peux vous conseiller le <strong>programme</strong> de <strong>Didier PENISSARD, coach, conférencier et auteur</strong> dans le domaine du <strong>développement personnel.</strong> Si vous voulez en savoir plus, n’hésitez pas à cliquer sur le bouton ci-dessous : </p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"428\" src=\"/storage/blog-images/Autopunition.jpg\" alt=\"Auto-accusation\" title=\"Autopunition\">\n<h2>Les préjugés sur l’anxiété et les réponses à donner pour stopper la culpabilité</h2>\n<p>Je vais lister ici les principaux préjugés que les gens peuvent infliger à la personne angoissée. Bien évidemment, vous remarquerez que ces préjugés ne peuvent que dénigrer la personne souffrant d’angoisse diffuse et la faire culpabiliser. Je vous donnerai en dessous de chaque idée reçue ce que vous pouvez répondre à ces gens-là ou ce que vous devez vraiment retenir afin que ce genre de réflexions ne vous touche plus. De ce fait, votre culpabilité disparaîtra. Car tant que vous éprouverez de la culpabilité, vous ne pourrez guérir de votre angoisse constante.  </p>\n<h3>N° 1 : Les personnes anxieuses apparaissent faibles</h3>\n<p>Tout le monde peut souffrir un jour de troubles anxieux. Il suffit d’un <a href=\"/traumatisme\" target=\"_blank\" rel=\"noopener\" title=\"Traumatisme\">évènement traumatique.</a> Donc, la terre entière n’est peuplée que de personnes faibles ?</p>\n<p>De plus, quand une personne vit une crise de panique, imaginez l’état dans lequel elle peut se trouver. Je ne souhaiterais même pas cette affection à mon pire ennemi ! Si la personne non anxieuse pouvait prendre votre corps dans ces moments, elle verrait qu’il faut avoir un courage exemplaire pour tout de même avancer. Se lever, aller au travail, vivre sa journée comme d’habitude, etc.</p>\n<p>En effet, le cerveau ne fait pas la différence entre une peur réelle, telle qu’un tigre devant soi, ou une crainte irrationnelle. De fait, il considère les deux de la même manière et le principe combat/fuite s’applique pour les deux. C’est comme si, au final, vous choisissiez de combattre le félin. Est-ce une faiblesse ? </p>\n<p>L’anxiété peut donc venir d’une fragilité due à divers évènements de la vie. Mais il ne faut pas la confondre avec la faiblesse. La fragilité représente, en quelque sorte, le talon d’Achille de votre personnalité. Et sachez que tout le monde à des points faibles ! La faiblesse, au contraire, serait de demeurer dans cet état, sans demander d’aide, s’en complaire, rester chez soi, ne pas se remettre en question et ne pas chercher de moyens pour aller mieux.</p>\n<p>Par contre, certaines fois, l’anxiété peut sembler trop puissante. Si vous ne vous trouvez pas dans un bon mood, vous pouvez choisir la fuite. Ce n’est pas honteux. C’est humain et cet évitement ne fait pas de vous une personne faible. L’important reste de s’en rendre compte et de travailler sur ce problème pour réussir, un jour, à le vaincre. </p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h3>N° 2 : Il y a bien pire dans la vie que l’anxiété. Pourquoi se mettre dans cet état ?</h3>\n<p>L’anxiété n’est pas grave à la base, mais peut épuiser à la longue votre système immunitaire et faire apparaître des maladies plus ou moins graves. </p>\n<p>Donc, l’anxiété peut être considérée comme importante. Si la personne ne peut même plus sortir de chez elle, mener une existence normale et qu’elle sombre dans une dépression avec idées suicidaires, c’est assez sérieux vous ne trouvez pas ? </p>\n<p>Le souci, c’est que les individus voient les problèmes physiques, mais non mentaux. Le mental, c’est dans la tête pour eux. L’anxiété ne se voit pas, donc n’existe pas. Pourtant, le mental et le corps sont bien reliés. Il n’y a qu’à voir le nombre impressionnant de soucis physiologiques et somatiques que peut avoir un individu atteint d’anxiété. </p>\n<p>Il y a toujours pire que soit. Mais puisqu’il y a constamment pire, nous n’avons jamais le droit d’apparaître malheureux ou d’aller mal ? Je pense que tout le monde est triste de temps en temps, non ?</p>\n<p>Imaginez la culpabilité qu’une personne peut ressentir, alors qu’elle n’arrive pas à s’en sortir avec ses troubles, quand vous lui dites : « tu as tout pour être heureux ». C’est vraiment atroce ! Cette phrase montre juste votre manque d’empathie et de tolérance à son égard et je vous souhaite de ne jamais connaître cet état ! Comment voulez-vous que celle-ci aille mieux en entendant vos propos ? Vous êtes clairement en train de lui dire qu’elle le fait exprès !</p>\n<p>Personnellement, je me suis retrouvée certaines fois dans de tels états que si j’agissais réellement de la sorte pour me faire victimiser, je pense que je n’en serais pas arrivée là ! J’aurais trouvé des moyens faisant bien moins souffrir, c’est certain ! </p>\n<h3>N° 3 : Tout est dans la tête. Alors un peu de volonté ! </h3>\n<p>Avec cette phrase, vous insinuez que la personne fait exprès de se comporter ainsi et de subir et qu’un tout petit peu de volonté permettrait de résoudre le problème. Or, l’anxiété reste avant tout un tempérament acquis dès la naissance. Par rapport à l’éducation, à l’environnement et aux évènements de la vie, la personne pourra vivre normalement avec son anxiété ou au contraire, connaître de véritables troubles. </p>\n<p>Il s’agit donc déjà d’une personnalité. C’est comme si je disais à une personne égocentrique de se faire toute petite pour que l’on ne la remarque pas. Vous pensez qu’elle y arriverait ? </p>\n<p>Peut-être effectivement qu’à force de travailler sur son trouble, le narcissique ferait des efforts et parviendrait à exister autrement. Cependant, son tempérament demeurera toujours présent. C’est pareil pour le caractère anxieux. Vous pouvez œuvrer dessus afin que l’anxiété ne vous empêche pas de vivre pleinement. Par contre, vous resterez dans tous les cas plus anxieux ou inquiets qu’une personne n’ayant pas du tout ce type de personnalité.</p>\n<p>D’autant plus que si ce n’est qu’une histoire de volonté, pourquoi bon nombre de personnes prennent des médicaments et que la plupart du temps, le traitement fonctionne ? De ce fait, il existe bien un dérèglement au niveau du cerveau, une sorte d’alarme ayant été déréglée, sonnant sans arrêt. </p>\n<p> Si tout était une question de volonté dans la vie, tout le monde vivrait heureux, riche, en bonne santé, aimerait toujours son prochain. Ce serait l’univers des bisounours et il n’y aurait donc aucun problème dans ce monde. Cependant, c’est bien loin d’être le cas, non ? </p>\n<p> </p>\n<h3>N° 4 : L’anxiété reste un choix. Il faut juste décider de ne plus être anxieux</h3>\n<p>Donc, la personne a choisi de ressentir un mal-être et peut, en un claquement de doigts, décider d’aller mieux du jour au lendemain. J’imagine bien la culpabilité que vous devez éprouver si vous entendez ce genre de propos. </p>\n<p>L’être humain pense tout d’abord à lui, quoi qu’on en dise et souhaite avant tout sa survie et son bonheur. Il veut souffrir le moins possible. Pourquoi donc choisirait-il le sentiment d’angoisse, vu toute la souffrance qu’il peut lui infliger ?  </p>\n<p>C’est comme si l’on disait à une personne atteinte du diabète : « il faut que tu choisisses de ne plus avoir cette maladie ». Effectivement, elle a peut-être provoqué cette maladie en s’alimentant mal, mais maintenant, peut-elle choisir d’en guérir ou doit-elle vivre avec au mieux ? </p>\n<p>C’est pareil pour l’anxiété. C’est un mélange de tempérament, d’environnement, d’éducation et d’un éventuel traumatisme qui ont rendu la personne anxieuse. Elle ne l’a pas choisie. Elle peut choisir de travailler sur ses peurs afin de les rendre supportables, mais ne sera jamais la personne la plus optimiste et casse-cou de l’univers.</p>\n<img loading=\"lazy\" decoding=\"async\" width=\"526\" height=\"640\" src=\"/storage/blog-images/Troubles-anxieux.jpg\" alt=\"Angoisse\" title=\"Troubles anxieux\">\n<p>Je vous ai donné les clés afin de ne pas tomber dans le schéma <b>angoisse et culpabilité permanente. </b>Ce n’est pas de votre faute si vous souffrez de troubles anxieux. La seule responsabilité que vous pouvez avoir maintenant est de travailler sur votre angoisse intense pour la rendre supportable et pouvoir mener une vie normale. Ne vous culpabilisez pas si vous n’y arrivez pas dans l’immédiat. Accomplissez tout ce que vous pouvez par rapport à l’énergie actuelle que vous avez. La guérison viendra petit à petit.</p>\n<p>En ce qui concerne le regard de l’autre, il faudra apprendre à travailler sur votre éventuelle angoisse sociale pour faire fi de tous les jugements qui peuvent être émis à votre encontre. Essayez également de ne pas en vouloir aux autres. Ils ne savent pas. Donc, ils apparaissent intolérants. En effet, comme je l’ai déjà précisé, l’être humain est ainsi fait. Il juge tout et tout le monde, surtout si c’est un mode de fonctionnement différent du sien. Vous réagissez d’ailleurs de la même manière. On peut comprendre l’autre seulement si l’on vit la même chose. C’est le seul moyen. Dites-vous donc qu’une personne non anxieuse ne vous comprendra jamais. Il y a ainsi un grand travail <a href=\"/lacher-prise-et-acceptation\" target=\"_blank\" rel=\"noopener\" title=\"Lâcher-prise et acceptation\">d’acceptation</a> à réaliser, car vous ne pourrez rien y changer.</p>\n<p>Il y aura également un gros travail d’estime de vous à effectuer afin de cesser de vous sentir coupable à tout bout de champ.</p>\n<p>Vous verrez qu’une fois la culpabilité effacée de votre vie, vous arriverez beaucoup mieux à travailler sur votre angoisse permanente. Quel sentiment de légèreté vous ressentirez !</p>\n<p>Si vous aimez mon travail 🙂</p>','published',1,'Angoisse et Culpabilité Permanente : se Libérer de cette Emotion Toxique','Angoisse et culpabilité permanente ne font pas bon ménage. Comment ne plus prendre à cœur les propos des autres ? Comment vous libérer de la culpabilité ?','https://vivre-pleinement.fr/culpabilite/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/culpabilite\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/culpabilite\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Angoisse et Culpabilit\\u00e9 Permanente : se Lib\\u00e9rer de cette Emotion Toxique\",\"datePublished\":\"2019-08-24T19:42:18+00:00\",\"dateModified\":\"2024-02-13T19:31:05+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/culpabilite\\/\"},\"wordCount\":3543,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/culpabilite\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/08\\/Angoisse-culpabilite-permanente.png\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/culpabilite\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/culpabilite\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/culpabilite\\/\",\"name\":\"Angoisse et Culpabilit\\u00e9 Permanente : se Lib\\u00e9rer de cette Emotion Toxique\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/culpabilite\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/culpabilite\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/08\\/Angoisse-culpabilite-permanente.png\",\"datePublished\":\"2019-08-24T19:42:18+00:00\",\"dateModified\":\"2024-02-13T19:31:05+00:00\",\"description\":\"Angoisse et culpabilit\\u00e9 permanente ne font pas bon m\\u00e9nage. Comment ne plus prendre \\u00e0 c\\u0153ur les propos des autres\\u2009? Comment vous lib\\u00e9rer de la culpabilit\\u00e9\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/culpabilite\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/culpabilite\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/culpabilite\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/08\\/Angoisse-culpabilite-permanente.png\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/08\\/Angoisse-culpabilite-permanente.png\",\"width\":869,\"height\":720,\"caption\":\"Comment eviter la culpabilite dans les troubles anxieux ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/culpabilite\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Angoisse et Culpabilit\\u00e9 Permanente : se Lib\\u00e9rer de cette Emotion Toxique\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-08-24 19:42:18',NULL,'2026-05-24 19:19:45','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (58,'Les Différentes Addictions : les Comprendre et s’en Libérer','addictions','Contrairement à ce que l’on peut penser, les addictions peuvent facilement entrer dans la vie d’une personne. Bon nombre d’individus peuvent y être sujets à un moment de leur existence. Ce comportement pathologique peut nuire considérablement au mode de fonctionnement des personnes et peut avoir une répercussion sur leurs proches. Vous aimez prendre un verre de temps à autre, mais remarquez que depuis quelque temps, vous augmentez progressivement votre consommation. Vous buvez dans la coupelle des autres pour boire dès qu’ils tournent le dos afin d’avoir plus de quantité d’alcool. Les jeux vidéos sont votre passion. Cependant, lorsqu’un ami sonne chez vous, vous faites semblant de ne pas vous trouver à votre domicile pour pouvoir continuer à jouer tranquillement. Vous voulez arrêter de fumer, mais quand vous commencez, vous ressentez le manque et devenez très agressif. Vous adorez réaliser des dépenses, mais à chaque fin de mois, c’est pareil : vous êtes à découvert. Si vous ne réalisez pas d’achats, vous vous sentez vide, triste. Quelles sont les différentes addictions pouvant impacter la vie des personnes ? Comment s’en libérer et retrouver la liberté ? \n','<p>Contrairement à ce que l’on peut penser, les addictions peuvent <b>facilement </b>entrer dans la vie d’une personne. Bon nombre d’individus peuvent y être sujets à un <b>moment </b>de leur existence. Ce comportement pathologique peut <b>nuire </b>considérablement au mode de fonctionnement des personnes et peut avoir une répercussion sur leurs <b>proches</b>. Vous aimez prendre un verre de temps à autre, mais remarquez que depuis quelque temps, vous <b>augmentez </b>progressivement votre consommation. Vous buvez dans la coupelle des <b>autres </b>pour boire dès qu’ils tournent le dos afin d’avoir plus de quantité d’alcool. Les<b> jeux vidéos</b> sont votre passion. Cependant, lorsqu’un <b>ami </b>sonne chez vous, vous faites <b>semblant </b>de ne pas vous trouver à votre domicile pour pouvoir continuer à jouer tranquillement. Vous voulez arrêter de <b>fumer, </b>mais quand vous commencez, vous ressentez le <b>manque </b>et devenez très <b>agressif</b>. Vous adorez réaliser des <b>dépenses, </b>mais à chaque fin de mois, c’est pareil : vous êtes à <b>découvert</b>. Si vous ne réalisez pas d’achats, vous vous sentez <b>vide, triste.</b> Quelles sont <b>les différentes addictions</b> pouvant impacter la vie des personnes ? Comment s’en libérer et retrouver la <b>liberté </b>? </p>\n<h2>Qu’est-ce qu’une addiction ?  </h2>\n<p>Il s’agit d’une habitude, généralement nocive, qui prend de plus en plus de place dans la vie d’un individu. Bien souvent, l’accoutumance s’installe à son insu sans qu’il en ait véritablement conscience. C’est d’ailleurs fréquemment les proches qui peuvent commencer à s’apercevoir qu’il y a un problème. </p>\n<p>L’addiction peut être plus ou moins prononcée et donc plus ou moins impacter l’existence de la personne, mais aussi de ses proches. Vous verrez effectivement plus bas qu’il y a des addictions plus acceptables par la société et qui sont ainsi plus difficiles à défaire, car elles deviennent limite la norme. D’autres apparaissent plus honteuses et la personne peut alors se trouver plus sujette à la culpabilité et la honte, ce qui peut la mener à l’isolement voire même, à la dépression. </p>\n<p>Certaines addictions ont donc l’air d’être plus graves que d’autres du fait qu’elles soient moins tolérées par la <a href=\"/normes-sociales\" target=\"_blank\" rel=\"noopener\" title=\"Normes sociales\">norme sociale.</a> Cependant, pour moi, elles restent toutes importantes et doivent être rapidement traitées. Certaines dépendances que l’individu pense déshonorantes pourront même être plus facilement soignées, étant donné qu’elles seront prises en charge. Pour les addictions les mieux acceptées, il y aura habituellement concomitamment un faible insight (faible prise de conscience) qui fera que la personne restera souvent comme elle est. </p>\n<h2>L’addiction est-elle une faiblesse ?  </h2>\n<p>Mettez-vous d’ailleurs également une chose en tête. Ce n’est pas parce que vous souffrez d’une ou plusieurs dépendance(s) que vous êtes quelqu’un de faible. C’est complètement faux. C’est plutôt une habitude prise à un certain moment de votre vie où vous vous sentiez plus vulnérable ou où vous vouliez vous comporter comme les autres. Cette habitude a été adoptée par votre cerveau et de fait, vous pensez que vous ne pouvez plus vivre sans. Dites-vous bien que tout le monde peut avoir des addictions. Il n’y a donc pas les gens forts d’un côté et les faibles de l’autre. </p>\n<h2>Les différentes addictions bien acceptées par la société</h2>\n<h3>L’addiction à la cigarette </h3>\n<p>La cigarette reste pour moi l’addiction la plus populaire. En effet, combien de personnes de votre entourage fument, malgré le fait de dépenser beaucoup d’argent à cet égard ? Et que figurent sur les paquets des images terribles et des phrases telles que « fumer tue » ? </p>\n<p>Souvent, la personne commence le tabac à l’adolescence, pour faire comme tout le monde ou, car elle n’a pas confiance en elle. De là s’installe une habitude néfaste. Elle se croit obligée de prendre une pause toutes les heures ou de fumer dès qu’elle se trouve stressée. Le tabac est devenu un handicap.</p>\n<p>Étant donné que bon nombre de personnes fument, cette addiction est bien tolérée et l’individu ne se sent pas rejetée, au contraire. La cigarette rend les soirées plus conviviales, elle détend, etc. certains trouvent même que fumer fait classe. Elle représente une drogue légale. </p>\n<p>De ce fait et du fait d’une prise de conscience très faible, la personne continue donc de rester dépendante sans trop se poser de questions. Certaines essaient fréquemment d’arrêter. Mais, comme le fond du problème n’est pas traité, l’addiction revient, plus forte encore, dès que la routine s’installe à nouveau ou qu’une pointe de stress fait son apparition. C’est ce qui explique les rechutes dans de nombreux cas. Il est rare qu’une personne n’y touche plus jamais.</p>\n<h3>Les achats compulsifs </h3>\n<p>Dès qu’une personne se sent mal ou souhaite se récompenser, elle peut le faire de cette manière : en achetant sans arrêt ce qui ne se trouve pas nécessaire pour elle. De ce fait, elle craquera à la moindre pub apparaissant sur son iPhone et apparaîtra heureuse de son achat. Malheureusement, ce bonheur demeurera de courte durée et elle sera obligée de recommencer encore et encore. Ses comptes bancaires peuvent clairement en pâtir et dans les cas les plus maladifs, elle peut vraiment finir par s’endetter de plus en plus. </p>\n<p>Cette addiction est bien acceptée par la société, qui est axée principalement sur le matérialisme.</p>\n<h3>La dépendance aux nouvelles technologies </h3>\n<p>Cette dépendance est quasiment normale pour une société basée principalement sur les nouvelles technologies. Nous sommes en effet presque tous concernés dans notre génération : nous ne pourrions nous passer de notre téléphone. </p>\n<p>Il faut dire que la vie a également changé. Nous sommes en effet plus sujets aux déplacements, à l’échange téléphonique, etc. jusque-là, pourquoi pas. Le problème, c’est quand la technologie devient une véritable addiction. Combien de personnes sortent de chez elles, mais sont collées à leur portable et ne parlent même pas aux gens avec qui elles se trouvent ? Je vois personnellement très souvent cette situation. </p>\n<p>Le danger réside bien dans le fait de ne plus penser qu’aux technologies et ne plus du tout profiter de ce que la nature et les vrais plaisirs de la vie nous offrent. Nous pouvons donc passer à côté de belles choses, lesquelles restent les plus simples. </p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"426\" src=\"/storage/blog-images/Dependance.jpg\" alt=\"Accoutumance \" title=\"Dépendance\">\n<h2>Les différentes addictions moins bien acceptées par la société </h2>\n<h3>La dépendance à l’alcool</h3>\n<p>La personne peut commencer à prendre un verre pour faire comme tout le monde ou parce qu’elle a des soucis. L’alcoolisme n’est pas forcément boire une bouteille de porto par jour. On peut être considéré comme alcoolique à partir du moment où l’on boit, ne serait-ce qu’un verre de vin par jour, et ce, sans pouvoir s’en passer. C’est alors devenu une habitude néfaste. Autant dire que bon nombre de personnes peuvent être concernées ! </p>\n<p>L’alcool reste tout de même assez dangereux. C’est pour moi un anxiolytique naturel. La personne anxieuse va souvent plonger inconsciemment dedans, car boire la détend au premier abord. Cependant, l’anxiété reviendra ensuite de plus belle, ce qui montre donc que ce n’est pas la solution. </p>\n<p>La consommation d’alcool peut aussi faire de gros ravages sur la santé et notamment sur le foie. L’individu peut se désociabiliser petit à petit et croit ne pouvoir vivre sans. Elle peut même devenir malheureuse et dépressive en buvant. Les effets du lendemain sont terribles (la fameuse gueule de bois). La mauvaise solitude peut la gagner. C’est un véritable cercle vicieux, car souvent, la personne possède un faible insight et pense qu’elle ne boit pas trop. </p>\n<p>Être alcoolique est généralement mal perçu par la société, car la personne passe pour quelqu’un de dépressif, fragile, sans projet, etc. je parle là de l’alcoolisme maladif. En effet, quand on ne boit pas du tout d’alcool, c’est également mal vu ! Nous passons pour des gens coincés, qui ne profitent pas de la vie, alors que je trouve au contraire qu’il est génial de pouvoir s’en passer, non ? C’est plutôt une force pour moi.</p>\n<h3>L’addiction à la drogue </h3>\n<p>C’est un peu le même principe que pour l’alcool et la cigarette concernant le démarrage de cette addiction. La société ne tolère pas ces substances, puisqu’elles demeurent illégales.</p>\n<p>Idem que pour l’alcool, après avoir ressenti du bien-être lors de la prise de drogues (cannabis, cocaïne, ecstasy, héroïne, etc.)., les problèmes reviennent de force. Il s’agit du même cercle vicieux.</p>\n<p>La consommation de substances illicites répétée peut avoir un lourd impact sur la santé de l’individu et surtout, sur son cerveau. La personne peut en effet développer des troubles psychotiques et risque aussi l’overdose. </p>\n<p> </p>\n<h3>L’accoutumance aux médicaments</h3>\n<p>Je parle principalement des médicaments tels que les anxiolytiques ou les antidépresseurs. Sur le long terme, ces traitements mènent souvent à la dépendance. Il est donc nécessaire d’en prendre conscience et d’effectuer un début de sevrage avec un professionnel de la santé. Je vous laisse prendre connaissance de mon <a href=\"/antidepresseurs-et-anxiolytiques\" target=\"_blank\" rel=\"noopener\" title=\"Antidépresseurs et anxiolytiques\">article</a> à ce sujet. </p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h3>L’addiction aux jeux vidéos</h3>\n<p>L’individu accro à ces jeux de hasard voudra souvent fuir le monde réel. Jouer à des jeux n’est pas un mal en soi si cette activité permet de nous détendre. Tout est, comme je l’ai dit, une question d’équilibre. Cependant, une personne jouant jour et nuit sans rien accomplir d’autre et se renfermant sur elle-même a un souci d’addiction. Je connais une personne qui jouait constamment chez elle. Dès que l’on toquait chez elle, elle faisait croire qu’elle ne se trouvait pas à son domicile. Je pense qu’à partir de ce moment, il y a un gros problème. Comme je l’ai dit, dans ce cas-là, de l’aide apparaît nécessaire. Il nous faut tout de même en effet un minimum de contact social, car nous sommes des animaux sociaux.</p>\n<p>La société actuelle voit d’un mauvais œil les personnes jouant aux jeux vidéos. Même en jouant un petit peu, surtout quand nous sommes une femme, ce qui est mon cas, nous passons vite pour des personnes geeks, sans vie extérieure, ringardes, enfantines.</p>\n<h3>L’addiction aux jeux d’argent </h3>\n<p>La personne peut essayer de jouer et va peut-être même gagner. De là, elle pensera qu’elle peut gagner sans cesse. Ce comportement peut bien évidemment aller très loin. Je connais le cas d’un individu jouant sans arrêt au casino sans le dire à sa compagne. Un jour, il a malheureusement été dans l’obligation d’hypothéquer sa maison. Imaginez le choc qu’a dû avoir sa femme ! Inutile de vous préciser qu’ils sont maintenant séparés. Le jeu peut avoir des conséquences dramatiques, car sans argent, tout peut devenir très vite catastrophique.</p>\n<p>Il y a bien évidemment d’autres types d’addictions que je ne détaille pas dans cet article, mais dont les répercussions apparaissent tout aussi néfastes. Par exemple, faire le ménage à outrance, trop aimer le sexe, travailler frénétiquement, trop faire de sport, manger sans retenue, etc. Finalement, tout ce qui demeure excessif.</p>\n<h2>Pourquoi devient-on addict ?</h2>\n<p>Bien souvent, une addiction cache un mal-être bien plus profond. </p>\n<p>Par exemple, je pense que presque tout le monde a déjà essayé de fumer pour faire comme les autres. Mais certains n’en ont pas été dépendants pour autant et ont arrêté aussi facilement qu’ils ont commencé. Pourquoi donc certains en deviennent addicts et pas d’autres ? </p>\n<p>Certaines addictions peuvent donner à la personne un sentiment de détente. La plupart réduisent, du moins semblent réduire temporairement leur <a href=\"/angoisse-stress-anxiete\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse stress anxiété \">anxiété</a>. C’est donc un piège d’utiliser l’addiction dès lors que l’on se sent anxieux, tendu, mal.</p>\n<p>Une personne peut également avoir des dépendances, car elles lui permettent de fuir un peu la réalité de sa vie qu’elle pense médiocre. Par conséquent, au lieu d’effectuer des actions concrètes pour remédier à son mal-être, elle fuira le problème avec une activité addictive. </p>\n<p>Un individu peut aussi sombrer dans une dépendance pour tenter d’oublier un événement marquant de son passé. Il ne travaillera donc pas sur lui pour résoudre son souci, mais tentera de le rendre invisible, comme s’il n’avait jamais existé. </p>\n<p>Ce genre de difficulté peut ainsi concerner toute personne à un moment de sa vie. Mais essayer de le cacher n’est pas la solution, au risque de le voir s’amplifier encore plus. </p>\n<p>Par conséquent, il y a à la base de la dépendance un problème plus profond qu’il convient de traiter. C’est seulement comme cela que la personne aura la force de faire face à ses addictions.</p>\n<img loading=\"lazy\" decoding=\"async\" width=\"1280\" height=\"972\" src=\"/storage/blog-images/Addict.jpg\" alt=\"Accro\" title=\"Addict\">\n<h2>Comment se débarrasser d’une addiction ?  </h2>\n<p>Déjà, tout dépend si la personne a conscience ou non de son trouble. Si elle n’en a pas conscience, la guérison va prendre plus de temps et souvent, seul l’entourage pourra réagir.</p>\n<p>Si elle souhaite vraiment se libérer de son problème, plusieurs solutions peuvent être envisagées. </p>\n<p>J’ai entendu dire que l’hypnose marchait assez bien pour certaines addictions telles que la cigarette. Cette affirmation ne m’étonne pas, vu que cette pratique travaille sur l’inconscient. C’est l’outil idéal pour entamer une introspection qui s’avère primordiale pour se débarrasser d’une addiction. </p>\n<p>Dans le cas de consommation de drogue ou d’alcoolisme, il sera quelquefois nécessaire de passer par la prise de certains médicaments. Attention cependant à ne pas en devenir dépendant. Il faut donc vous faire suivre par un professionnel de la santé. </p>\n<p>Entreprendre une thérapie peut aussi aider. Je vous laisse lire mon <a href=\"/psychotherapie-et-psychanalyse\" target=\"_blank\" rel=\"noopener\" title=\"Psychothérapie et psychanalyse\">article</a> sur le sujet. </p>\n<p>Vous pouvez de même recourir à des médecines douces comme la sophrologie, l’homéopathie, etc.</p>\n<p>Les techniques de relaxation telles que la méditation peuvent pareillement être très utiles.</p>\n<p>Pour certaines addictions, vous pouvez également vous inscrire à un groupe d’entraide. Vous y trouverez des personnes ayant le même genre de problèmes et pourrez ainsi vous entraider, ce qui est génial, car en même temps, vous créerez du lien social. Attention cependant à vous soutenir et à ne pas réaliser l’inverse, c’est-à-dire vous victimiser et rechuter ensemble. </p>\n<p> </p>\n<p>Voici donc<b> les différentes addictions </b>pouvant vous impacter. À vous maintenant de vous en libérer !  </p>\n<a href=\"https://hypnocaments.com?partnerid=YK5muYugzSoIWDbDWRgT-Q\" title=\"Seances d hypnose en ligne\"><img decoding=\"async\" src=\"https://hypnocaments.com/image/banner_1_750.png\" alt=\"seance hypnose mp3\"></a>','published',1,'Les Différentes Addictions : les Comprendre et s’en Libérer','Les addictions peuvent facilement entrer dans la vie d’une personne. Quelles sont les différentes addictions existantes et comment s’en libérer ?','https://vivre-pleinement.fr/addictions/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/addictions\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/addictions\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Les Diff\\u00e9rentes Addictions : les Comprendre et s\\u2019en Lib\\u00e9rer\",\"datePublished\":\"2019-08-14T21:36:46+00:00\",\"dateModified\":\"2024-02-12T19:57:49+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/addictions\\/\"},\"wordCount\":4155,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/addictions\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/08\\/Differentes-addictions.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/addictions\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/addictions\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/addictions\\/\",\"name\":\"Les Diff\\u00e9rentes Addictions : les Comprendre et s\\u2019en Lib\\u00e9rer\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/addictions\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/addictions\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/08\\/Differentes-addictions.jpg\",\"datePublished\":\"2019-08-14T21:36:46+00:00\",\"dateModified\":\"2024-02-12T19:57:49+00:00\",\"description\":\"Les addictions peuvent facilement entrer dans la vie d\\u2019une personne. Quelles sont les diff\\u00e9rentes addictions existantes et comment s\\u2019en lib\\u00e9rer ?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/addictions\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/addictions\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/addictions\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/08\\/Differentes-addictions.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/08\\/Differentes-addictions.jpg\",\"width\":640,\"height\":640,\"caption\":\"Comment se liberer de ses addictions ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/addictions\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Les Diff\\u00e9rentes Addictions : les Comprendre et s\\u2019en Lib\\u00e9rer\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-08-14 21:36:46',NULL,'2026-05-24 19:19:45','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (59,'Être Casanier : Apprendre à être Fier de ce Tempérament','etre-casanier','Être casanier est souvent mal perçu par la société, qui considère en effet les gens casaniers comme antisociaux et bizarres. Ce qui risque de fragiliser la personne aimant rester chez elle, laquelle culpabilise alors de faire ce qu’elle aime. De ce fait, beaucoup de personnes sortent uniquement pour faire comme tout le monde. Vous aimez rester chez vous, car vous avez une multitude d’activités et passions se trouvant à votre domicile. Les fêtes avec de nombreux individus que vous ne connaissez pas ? Vous n’en voyez pas l’intérêt, d’autant plus que les conversations risquent d’être superficielles et inutiles. Vous travaillez toute la semaine donc le peu de temps que vous avez, vous voulez le passer là où vous vous sentez le mieux : dans votre foyer. Finalement, votre mode de vie vous rend heureux. Sauf que vous avez l’impression d’être grandement jugé à cet égard. Vous avez honte d’être casanier et ne vous trouvez pas être normal ? Comment être fier de votre tempérament qui comporte de nombreux avantages ? \n','<p><b>Être casanier</b> est souvent mal perçu par la <b>société, </b>qui considère en effet les gens casaniers comme <b>antisociaux </b>et <b>bizarres</b>. Ce qui risque de fragiliser la personne aimant rester chez elle, laquelle<b> culpabilise </b>alors de faire ce qu’elle aime. De ce fait, beaucoup de personnes sortent uniquement pour <b>faire comme tout le monde.</b> Vous aimez rester chez vous, car vous avez une multitude d’activités et <b>passions </b>se trouvant à votre domicile. Les <b>fêtes </b>avec de nombreux individus que vous ne connaissez pas ? Vous n’en voyez pas <b>l’intérêt,</b> d’autant plus que les conversations risquent d’être superficielles et inutiles. Vous <b>travaillez </b>toute la semaine donc le peu de temps que vous avez, vous voulez le passer là où vous vous sentez le mieux : dans votre foyer. Finalement, votre mode de vie vous rend <b>heureux</b>. Sauf que vous avez l’impression d’être grandement <b>jugé </b>à cet égard. Vous avez <b>honte </b>d’être casanier et ne vous trouvez pas être <b>normal </b>? Comment être <b>fier </b>de votre tempérament qui comporte de nombreux <b>avantages </b>? </p>\n<h2>Que signifie être casanier ? </h2>\n<p>C’est tout simplement aimer rester chez soi. Cet individu apparaît bien souvent introverti et a besoin de se ressourcer, 80 % du temps, dans son cocon.</p>\n<p>Cette personne se sent en effet généralement bien avec elle-même et trouve beaucoup d’occupations chez elle. Elle est beaucoup portée sur la lecture, les activités créatives, telles que le dessin, la peinture, la création de blog, le bricolage, etc. Elle apprécie en général le développement personnel et l’introspection. Et il n’y a effectivement que dans le calme que l’on peut travailler sur soi-même. Il y a tellement de choses à faire quand on arrive à apprécier la solitude ! Cet individu aime être posé à regarder un film par exemple, en prenant une petite tisane, ou même, faire du sport, cuisiner… enfin, plein d’activités comme tout le monde, finalement ! </p>\n<p>D’ailleurs, si vous vous intéressez au <strong>dessin</strong>, que vous souhaitez vous <strong>perfectionner</strong>, apprendre d’autres styles de dessins ou que vous êtes tout simplement un <strong>débutant</strong> souhaitant apprendre à réaliser sa <strong>passion</strong>, j’ai un excellent site à vous recommander, lequel vous propose des cours. Personnellement, je pense avoir un très bon niveau de dessin, mais je n’ai par contre jamais réussi à dessiner des portraits ! Et vous pouvez apprendre tout cela en cliquant sur le lien ci-dessous :</p>\n<p>Elle ne trouve quelquefois pas beaucoup d’avantages à sortir, pensant que c’est une perte de temps et que ça ne lui apporte rien. Ce n’est pas son truc. Ce n’est pas pour autant que la personne casanière est misanthrope ou ne reçoit jamais d’invités en vivant comme un ermite. Souvent, elle aime recevoir des convives chez elle. Il ne faut donc pas tout confondre. Ce n’est pas forcément quelqu’un d’antisocial, loin de là ! </p>\n<h2>Les avantages à être une personne casanière  </h2>\n<h3>Apprendre à se connaître </h3>\n<p>Bien souvent, les gens courent après la vie afin de penser le moins possible. On entend fréquemment des phrases comme : « je n’arrête pas de courir, je n’ai pas le temps pour moi, quelle vie speed, je ne peux même pas me poser une seconde ». </p>\n<p>Mais vous savez, je pense que ces personnes aiment cette vie, sinon, elles ne pourraient continuer ainsi ! Elles se hâtent afin de ne pas réfléchir à ce qu’elles ressentent intérieurement, car elles ont justement peur d’elles-mêmes. De ne ressentir que du vide. Et surtout, quand on souhaite vraiment se connaître, on apprend aussi à écouter ses véritables besoins. Et c’est là que le bât peut blesser si leurs importants sont différents de la norme. De peur d’être rejetées par la société, elles préfèrent alors faire comme tout le monde : courir sans se questionner. </p>\n<p>Pour moi, il n’y a aucun souci si une personne aime ce mode de vie. C’est à partir du moment où elle s’en plaint que c’est embêtant. On aimerait donc leur poser la question suivante : « Mais si vous le faites, c’est que vous le voulez bien, non ? »</p>\n<p>Par contre, en apprenant à se connaître et en écoutant véritablement ses propres besoins, c’est là que l’on devient vraiment heureux. Il faut néanmoins mettre de côté sa peur du rejet. Dans tous les cas, en restant soi-même, on sera forcément rejeté. Mais croyez-moi, en plus de vous rendre plus fort, cette attitude en vaut réellement la peine. Vous atteindrez la liberté intérieure. C’est ce qu’il y a de plus important pour expérimenter le véritable bonheur.</p>\n<h3>Un attrait pour le développement personnel</h3>\n<p>Je ne dis pas qu’être casanier signifie être meilleur que les autres. Personne n’est supérieur à un autre ! C’est juste un trait de caractère. Cependant, généralement en tout cas, l’individu casanier aimera travailler sur lui-même et donc, deviendra plus conscient. Il se passionnera souvent pour le développement personnel, ce qui lui permettra, avec de l’entraînement, à plus lâcher-prise pour les petites broutilles de l’existence. Il apprendra la tolérance vis-à-vis des personnes différentes de lui et sera à l’écoute des gens. Par conséquent, il arrivera à mener une vie plus sereine, loin du brouhaha du quotidien. Et quand il devra faire face au tumulte, il le fera avec plus de calme et de sérénité. </p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img fetchpriority=\"high\" decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h3>Connaître et apprécier la solitude </h3>\n<p>En appréciant la solitude, on apprend à se connaître et donc, à savoir exactement ce qui nous correspond. Nous n’avons pas besoin d’une occupation à tout prix pour ne pas déprimer, nous sommes bien avec nous-mêmes et apprenons à nous aimer et croyez-moi, c’est très important.</p>\n<p>Certaines personnes ne comprennent vraiment pas que d’autres apprécient d’être seules de temps en temps. Ce comportement reflète une fragilité de leur part. Il ne faut pas oublier que nous naissons et mourons seuls. Personne ne va nous accompagner dans l’au-delà. C’est donc une force de pouvoir apprécier d’être seul parfois et une faiblesse de se trouver dans l’incapacité de pouvoir le faire. Cette attitude prouve que la personne a une grande crainte qu’elle cherche à refouler par une activité constante, ou qu’elle a peur d’elle-même. De ne pas avoir de but.</p>\n<p>Il convient cependant de ne pas confondre le fait d’affectionner être solitaire de temps à autre et réellement souffrir de solitude. Il est vraiment important d’avoir tout de même du lien social, car nous sommes des animaux sociaux. Dans ce cas-là, si un individu en souffre, il doit trouver comment améliorer sa situation. Il peut, par exemple, s’inscrire dans une association, un club, etc. </p>\n<p>Il ne faut également pas non plus que le mode de vie casanier cache un comportement phobique ou agoraphobe. Dans ce cas, il faudra tout de même se forcer à sortir un petit peu pour guérir ces troubles. Cependant, si c’est juste un tempérament, vivez comme vous le souhaitez !</p>\n<h3>De moindres dépenses </h3>\n<p>Eh oui. Le fait de moins sortir veut dire moins d’essence, moins d’argent dépensé pour les restaurants, les achats compulsifs, etc. Cependant, vous avez le droit d’aimer prendre l’air et aller manger un morceau, si c’est ce que vous aimez faire. C’est juste que le casanier aura probablement moins besoin de dépenser, ce qui peut représenter un avantage pour le compte bancaire. </p>\n<p> </p>\n<img decoding=\"async\" width=\"960\" height=\"546\" src=\"/storage/blog-images/aimer-rester-chez-soi.jpg\" alt=\"Pantouflard\" title=\"aimer-rester-chez-soi\">\n<h2>Les inconvénients à préférer rester chez soi </h2>\n<h3>Le regard des autres</h3>\n<p>Quand vous êtes casanier, c’est assez difficile à supporter. En effet, 80 % de la population ne l’est pas ou feint de ne pas l’être. De ce fait, posséder ce tempérament sera forcément critiqué. Passer pour un bizarre, un marginal, voire même, un dépressif. Car vu que la plupart des individus déprimeraient s’ils se retrouvaient seuls, ils pensent donc que cette façon de penser apparaît valable pour tous. Bien sûr, ils sont loin de s’imaginer que c’est tout le contraire ! </p>\n<p>Ce n’est d’ailleurs pas parce que vous êtes casanier que vous êtes antisocial. Introverti probablement, mais c’est tout. Ce trait de caractère ne vous empêche pas d’aimer recevoir des convives et de mettre le nez dehors. Vous avez juste moins besoin de sortir et ressentez la nécessité de recharger votre batterie chez vous.</p>\n<p>Les autres pourront tout de même vous juger négativement, puisque dans la société moderne, vous vous devez de passer votre temps à l’extérieur et de voir du monde. Sinon, vous passez pour une personne qui n’a pas de vie, un « petit vieux », car il inconcevable pour les gens que vous puissiez avoir un nombre incalculable d’activités chez vous.</p>\n<p>Le problème donc, ce n’est pas votre façon de vivre, car vous l’aimez. C’est vraiment le <a href=\"/jugement-des-autres\" target=\"_blank\" rel=\"noopener\" title=\"Jugement des autres \">regard des autres</a> qui peut vous porter préjudice. Mais rappelez-vous que l’opinion des autres ne représente qu’un point de vue. Qu’est-ce que ce jugement va concrètement changer à votre existence ? Pas grand-chose, n’est-ce pas ? Il ne tient qu’à vous de ne pas donner de pouvoir à leur avis.</p>\n<p> </p>\n<h3>L’oisiveté </h3>\n<p>Un casanier aime rester chez lui. Cependant, si vous ne faites que regarder la télé par exemple, il serait bon de vous trouver des activités supplémentaires afin de vous permettre d’être plus passionné. Pourquoi pas une activité créatrice, comme le bricolage, le dessin, la peinture, l’écriture, etc. Ou pourquoi pas une occupation extérieure, comme faire partie d’une association, d’un club sportif ou autre ? Ou travailler sur vous-même pour mieux vous connaître ? Vous verrez ainsi qu’il est merveilleux d’avoir des buts dans la vie.</p>\n<h3>D’éventuels troubles anxieux </h3>\n<p>Vous pouvez aimer d’être casanier, mais attention de ne pas subir le fait de ne pas sortir. C’est-à-dire que dès que vous sortez, même si vous accomplissez un petit effort pour ce faire, vous ne devez normalement pas ressentir un profond malaise. Sinon, cette appréhension veut peut-être dire que vous souffrez d’un<a href=\"/angoisse-stress-anxiete\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse stress anxiété\"> trouble anxieux</a> comme la <a href=\"/phobie-sociale\" target=\"_blank\" rel=\"noopener\" title=\"Phobie sociale\">phobie sociale.</a> Dans ce cas, n’hésitez pas à aller voir un spécialiste pour résoudre le problème.</p>\n<h3>Une souffrance </h3>\n<p>Vous ne devez pas subir votre mode de vie casanier, vous devez apprécier de l’être. Si vous le subissez, c’est peut-être que ce tempérament ne vous correspond pas. Dans ce cas, à vous de faire en sorte de trouver des activités extérieures. Vous n’avez pas à rester dans votre souffrance ! </p>\n<img loading=\"lazy\" decoding=\"async\" width=\"640\" height=\"480\" src=\"/storage/blog-images/Introversion.jpg\" alt=\"Solitaire\" title=\"Introversion\">\n<h2>Comment être fier de son tempérament casanier ?  </h2>\n<p>Il faut déjà vous dire qu’être casanier est un tempérament, comme le fait d’aimer sortir sans cesse. Aucun des deux comportements n’est mieux que l’autre, tant que la personne est heureuse dans sa vie. </p>\n<p>Dites-vous bien que vous êtes un être humain avec des qualités et des défauts, comme tout le monde. </p>\n<p>Après, ce tempérament reste assez mal vu dans notre société. Mais vous savez, la plupart des personnes sont comme vous, mais n’osent pas s’affirmer et de ce fait, font comme la plupart des individus. Vous avez donc un sacré courage et une sacrée force pour vous montrer tel que vous êtes, vu que votre trait de personnalité ne correspond pas à la <a href=\"/normes-sociales\" target=\"_blank\" rel=\"noopener\" title=\"Normes sociales \">norme sociale. </a></p>\n<p>Le fait également d’être seul avec vous-même un certain nombre d’heures, voire des journées est loin d’être donné à tout le monde ! Cette aptitude prouve que vous avez de l’estime pour vous en étant capable de passer du temps avec vous, contrairement aux personnes souhaitant fuir la réalité à leur manière. </p>\n<p>Ne vous pensez donc pas différent ou anormal par rapport aux autres. Il n’en est rien. C’est important de le préciser. Personne ne vous rejette. C’est vous qui vous êtes mis cette idée en tête. Ceux qui jugent négativement votre situation n’ont tout simplement pas ce mode de vie, mais ils peuvent tout de même vous apprécier. </p>\n<p>Par conséquent, faites ce que vous voulez, lisez le bouquin que vous adorez tant sous votre plaid et avec votre petit thé, profitez pleinement de cet instant présent. C’est la définition de l’existence : faire ce que vous aimez en vivant le moment à fond, et ce, quoi qu’en pensent les autres ! </p>\n<p><b>Être casanier </b>n’a donc rien de honteux. C’est un tempérament comme un autre. Soyez-en fier ! </p>\n<p>Si vous aimez mon travail 🙂</p>','published',1,'Être Casanier : Apprendre à être Fier de ce Tempérament','Être casanier est souvent mal perçu par la société, qui considère les gens casaniers comme antisociaux et bizarres. Comment être fier de votre tempérament ?','https://vivre-pleinement.fr/etre-casanier/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/etre-casanier\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/etre-casanier\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"\\u00catre Casanier : Apprendre \\u00e0 \\u00eatre Fier de ce Temp\\u00e9rament\",\"datePublished\":\"2019-08-12T18:50:45+00:00\",\"dateModified\":\"2024-02-12T19:59:53+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/etre-casanier\\/\"},\"wordCount\":3812,\"commentCount\":8,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/etre-casanier\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/08\\/etre-casanier.jpg\",\"articleSection\":[\"D\\u00e9veloppement personnel\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/etre-casanier\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/etre-casanier\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/etre-casanier\\/\",\"name\":\"\\u00catre Casanier : Apprendre \\u00e0 \\u00eatre Fier de ce Temp\\u00e9rament\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/etre-casanier\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/etre-casanier\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/08\\/etre-casanier.jpg\",\"datePublished\":\"2019-08-12T18:50:45+00:00\",\"dateModified\":\"2024-02-12T19:59:53+00:00\",\"description\":\"\\u00catre casanier est souvent mal per\\u00e7u par la soci\\u00e9t\\u00e9, qui consid\\u00e8re les gens casaniers comme antisociaux et bizarres. Comment \\u00eatre fier de votre temp\\u00e9rament ?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/etre-casanier\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/etre-casanier\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/etre-casanier\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/08\\/etre-casanier.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/08\\/etre-casanier.jpg\",\"width\":640,\"height\":456,\"caption\":\"Comment etre fier de son temperament casanier ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/etre-casanier\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"\\u00catre Casanier : Apprendre \\u00e0 \\u00eatre Fier de ce Temp\\u00e9rament\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-08-12 18:50:45',NULL,'2026-05-24 19:19:45','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (60,'Caractéristiques des Hypersensibles : se Comprendre pour Vivre Heureux','hypersensibilite','Certaines personnes souffrant de troubles anxieux peuvent également se trouver sujettes à l’hypersensibilité. Ce n’est pas un trouble, mais un tempérament acquis dès la naissance ou survenant après des expériences de vie douloureuses. Elle concerne 15 à 20 % de la population. La personne hypersensible peut éprouver de grandes difficultés à vivre dans le monde actuel. En effet, la société moderne pousse les gens à cacher leur sensibilité et à se montrer forts en toute circonstance. L’hyperémotivité est donc considérée comme une faiblesse. Chaque critique vous blesse profondément, vous ruminez dessus pendant des jours voire des années. Vos émotions apparaissent difficilement maîtrisables, vous avez l’impression d’être une cocotte-minute pouvant exploser à tout moment. Vous êtes une vraie éponge émotionnelle et les émotions des autres vous impactent. Quelles sont les principales caractéristiques des hypersensibles ? Comment se sentir à sa place et vivre pleinement dans un monde moins sensible ?\n','<p>Certaines personnes souffrant de <b>troubles anxieux</b> peuvent également se trouver sujettes à <b>l’hypersensibilité. </b>Ce n’est pas un trouble, mais un<b> tempérament </b>acquis dès la <b>naissance </b>ou survenant après des <b>expériences de vie douloureuses.</b> Elle concerne<b> 15 à 20 % </b>de la population. La personne hypersensible peut éprouver de grandes <b>difficultés </b>à vivre dans le <b>monde actuel. </b>En effet, la société moderne pousse les gens à <b>cacher </b>leur sensibilité et à se montrer <b>forts </b>en toute circonstance. L’hyperémotivité est donc considérée comme une <b>faiblesse</b>. Chaque <b>critique </b>vous <b>blesse </b>profondément, vous <b>ruminez </b>dessus pendant des jours voire des années. Vos <b>émotions apparaissent </b>difficilement <b>maîtrisables</b>, vous avez l’impression d’être une <b>cocotte-minute</b> pouvant exploser à tout moment. Vous êtes une vraie <b>éponge émotionnelle</b> et les émotions des autres vous impactent. Quelles sont les principales<b> caractéristiques des hypersensibles ? </b>Comment se sentir à sa place et vivre pleinement dans un monde moins sensible ?</p>\n<h2>Qu’est-ce que l’hypersensibilité ?</h2>\n<p>L’hypersensibilité se définit comme une sensibilité plus haute que la moyenne. La personne ressent tout de manière excessive et son entourage ne le comprend pas forcément. Ce trait de personnalité peut vraiment devenir un avantage si l’individu réussit à le maîtriser. Cependant, si ce n’est pas le cas, il peut se trouver inadapté au monde. Les principales caractéristiques de cette particularité sont les suivantes : </p>\n<p> </p>\n<ul>\n<li aria-level=\"1\">Une passion pour le développement personnel ;</li>\n<li aria-level=\"1\">Une façon de réagir excessive, qu’elle soit positive ou négative ;</li>\n<li aria-level=\"1\">Une préférence pour la solitude ;</li>\n<li aria-level=\"1\">Une attirance pour les sports individuels ;</li>\n<li aria-level=\"1\">Une tendance aux <a href=\"/angoisse-stress-anxiete\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse stress anxiété \">troubles anxieux</a> et/ou dépressifs (mais pas toujours) ;</li>\n<li aria-level=\"1\">Un sentiment d’anormalité, de décalage vis-à-vis des autres ;</li>\n<li aria-level=\"1\">Un manque de confiance en soi et d’estime de soi ;</li>\n<li aria-level=\"1\">Une plus grande empathie ;</li>\n<li aria-level=\"1\">Une forte sensibilité au regard de l’autre ;</li>\n</ul>\n<p>D’ailleurs, si vous souhaitez apprendre à gérer le <strong>regard des autres,</strong> je vous suggère le programme de<strong> Didier PENISSARD, auteur, coach et conférencier</strong> dans le domaine du <strong>développement personnel.</strong> Si cela vous intéresse, c’est juste ici : </p>\n<ul>\n<li aria-level=\"1\">Une préférence pour un espace clos au travail ;</li>\n<li aria-level=\"1\">Des pleurs plus fréquents (de joie ou de tristesse) ;</li>\n<li aria-level=\"1\">L’impossibilité de regarder des films d’horreur ;</li>\n<li aria-level=\"1\">Des possibilités de tomber dans des <a href=\"/addictions\" target=\"_blank\" rel=\"noopener\" title=\"Addictions\">excès</a> (alcool, drogue, cigarette, nourriture, etc.) ;</li>\n<li aria-level=\"1\">Hypersensibilité aux odeurs, aux sons, à la lumière, aux textiles, aux aliments, etc.</li>\n</ul>\n<p> </p>\n<p>Voilà les traits principaux pouvant être rencontrés chez une personne hypersensible. Certains peuvent être un véritable atout et d’autres, un sacré inconvénient. C’est sur les aspects plus négatifs qu’il va falloir travailler et sur le fait d’améliorer vos qualités afin de pouvoir sentir que cette hypersensibilité, vous avez de la chance de l’avoir. À vous de jouer ! </p>\n<h2>Caractéristiques des hypersensibles avantageuses </h2>\n<p>La personne hypersensible aura souvent comme passion le développement personnel. En effet, du fait qu’elle puisse se sentir anormale, anxieuse et en décalage avec les autres, elle en aura besoin pour aller bien. De ce fait, avec toutes les connaissances qu’elle accumulera, elle deviendra forcément plus consciente et arrivera mieux à lâcher-prise et à être bien dans sa peau.</p>\n<p>Du coup, l’individu hypersensible apparaît très empathique. Il arrivera à décrypter l’humeur des gens sans qu’ils n’en parlent. Il trouvera l’individu qui pleure dans la pièce, même si 200 personnes s’y trouvent. Les autres arriveront facilement à se confier, se sentiront écoutés profondément. </p>\n<p>De plus, quand la personne hypersensible ressent du positif, elle vit ce moment à fond. Elle ressentira donc plus le bonheur de vivre à cet instant-là qu’une personne vivant machinalement. </p>\n<p>De même, elle agira avec son cœur. De ce fait, elle vivra une vie en accord avec ses besoins profonds, ce que bon nombre de gens seront incapables d’accomplir. En effet, même si elle se soucie énormément du regard de l’autre, ce jugement ne la bloquera généralement pas pour effectuer ce dont elle a le plus besoin et envie. </p>\n<p>Enfin, elle n’aura, contrairement à la majorité de la population, pas de problème avec la solitude. Certains individus détestent la solitude. Dès qu’ils se trouvent seuls, ils dépriment, angoissent, se sentent vides, etc. C’est pourquoi beaucoup de personnes doivent sans cesse s’occuper et surtout, en dehors de chez elles, afin de ne pas ressentir leur vide intérieur. L’hypersensible n’a pas ce problème, car son intérieur représente justement une grande richesse pour lui.</p>\n<p> </p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"640\" height=\"200\" src=\"/storage/blog-images/Hyperemotivite.jpg\" alt=\"Sensibilite exacerbee\" title=\"Hyperémotivité\">\n<h2>Inconvénients de l’hyperémotivité </h2>\n<p>La personne hypersensible est une éponge émotionnelle. Elle va se sentir mal en compagnie de quelqu’un qui dégagera de l’énergie négative. Elle pourra aussi se sentir submergée, par exemple, dans un nouveau job où elle ressent intensément la mauvaise ambiance qui y règne. </p>\n<p>Concernant le domaine du travail, elle éprouvera beaucoup de difficultés à travailler dans un open space. Les raisons sont nombreuses : passages de personnes quasi systématiques, manque d’intimité, bruits ambiants, tels que les cliquetis du clavier, les discussions de couloirs, etc. </p>\n<p>De plus, une situation qui contrariera un individu moins sensible perturbera au plus haut point l’hypersensible, qui pourra aller jusqu’à ruminer des jours durant et s’en rendre malade. </p>\n<p>L’hyperémotive préfère la solitude, ce qui peut constituer une importante source d’enrichissement personnel. Mais attention de ne pas tomber dans l’extrême à ne plus voir grand monde, ce qui pourrait engendrer d’autres malaises comme la phobie sociale, l’agoraphobie, etc. </p>\n<p>Du coup, la personne hypersensible peut développer des troubles anxieux qui peuvent, à la longue, l’épuiser et la mener à une dépression. Ce n’est bien évidemment pas valable pour tous les hypersensibles. </p>\n<p>Du fait de trop cogiter et afin de soulager leur anxiété, certains en arriveront même à consommer des substances illicites ou à avoir besoin de boire de l’alcool. Ils font en effet office d’anxiolytique naturel. Bien entendu, ce n’est également pas le cas de tout le monde.</p>\n<p>Enfin, l’hypersensible aura tendance à se sentir en décalage et anormal vis-à-vis des autres. C’est un peu normal, étant donné que ce trait de personnalité touche seulement entre 15 et 20 % de la population. Du coup, un grand manque de confiance en soi pourra en découler. </p>\n<p><b></b></p>\n<h2>Transformer sa sensibilité exacerbée en véritable don </h2>\n<p>Il est vrai que dans la société actuelle basée sur le matérialisme, la compétitivité, l’égoïsme, etc. il est difficile pour un hypersensible d’y trouver sa place. En effet, le monde moderne fait passer ce type de tempérament pour une faiblesse. Sauf que c’est tout le contraire. Si vous arrivez à maîtriser ce trait, la vie apparaîtra tellement meilleure et savoureuse !</p>\n<p>Il faut déjà être à l’écoute de vos propres besoins et changer ce qui ne va pas du tout dans votre existence. Les personnes hypersensibles, ressentant plus les sensations négatives, oseront plus le changement, bien qu’il les perturbe bien plus que les autres. La plupart des personnes se posent moins de questions et pourront plus facilement rester dans une vie qui ne leur convient pas. <a href=\"/etre-authentique\" target=\"_blank\" rel=\"noopener\" title=\"être authentique\">Vivre de manière authentique</a> est le premier point pour vivre une vie libre et heureuse, et l’hypersensible aura beaucoup plus de facilité à le faire. </p>\n<p>De plus, il faut également réaliser un travail profond sur <a href=\"/confiance-et-estime-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Confiance et estime de soi\">l’estime de soi et la confiance en soi,</a> qui manquent souvent à la personne hypersensible. Cependant, si possédait ces qualités, elle se trouverait beaucoup moins sujette à la rumination, aux troubles anxieux, à la dépression, etc.</p>\n<p>Vous pouvez aussi pratiquer des techniques de relaxation et des médecines alternatives. Vous pouvez en outre vous faire aider par un professionnel de la santé, tel qu’un psychothérapeute. Pourquoi pas également d’un médicament, s’il n’est pris que temporairement ? </p>\n<img decoding=\"async\" width=\"640\" height=\"426\" src=\"/storage/blog-images/Hypersensibilite.jpg\" alt=\"Eponge emotionnelle \" title=\"Hypersensibilité\">\n<h2>Hypersensibilité et égo spirituel  </h2>\n<p>Je suis également hypersensible et il est facile de se croire l’élite de la société. De se monter le bourrichon avec d’autres hypersensibles en se disant que les gens apparaissent moins évolués que nous, que nous sommes des êtres à part, moins nombreux et meilleurs. Vous l’avez certainement déjà pensé. Sauf que c’est faux. Nous sommes des êtres humains comme les autres. Nous ne sommes en aucun cas supérieurs à eux ni inférieurs, d’ailleurs.</p>\n<p>Nous pensons effectivement que les gens ne comprennent rien, qu’ils se cachent derrière leur personnalité matérialiste. Mais il existe également un deuxième type d’égo qui se nomme l’égo spirituel. C’est le fait de se sentir supérieur, spirituellement, à autrui, de par ses connaissances, spirituelles donc, que certaines personnes n’ont pas. Est-ce mieux que la personnalité matérialiste ? Non, car c’est aussi l’égo qui parle. </p>\n<p>Par exemple, un chirurgien méprise ses secrétaires, car elles ont fait moins d’études. En pensant comme lui, mais sur le plan subtil, vous en faites de même. Ce n’est pas parce que vous avez plus de connaissances dans le développement personnel que vous valez plus que les autres. Vous êtes tout simplement un être plus conscient.</p>\n<p>J’ai parlé de ma façon de voir les autres, lorsque mon égo spirituel se trouvait bien présent, à une personne. Elle a prononcé une phrase qui m’a vraiment ouvert les yeux. « J’étais comme toi avant. Mais tu verras, avec l’âge et les expériences, que les personnes différentes de toi ont des qualités que toi tu n’as pas. Et vice-versa ! Elles peuvent de ce fait t’apporter beaucoup. Tu apprendras à les apprécier. »</p>\n<p>Et qu’est-ce que c’est vrai ! </p>\n<p> </p>\n<p>Vous reconnaissez-vous dans les<b> caractéristiques des hypersensibles </b>? Si oui, retenez que votre hypersensibilité, dès lors que vous apprendrez à la maîtriser, devient un véritable cadeau. </p>\n<p><a href=\"https://amzn.to/3NOCVjf\">Visitez Amazon pour vous procurer le livre</a> de Elaine N. Aron « Ces gens qui ont peur d’avoir peur : mieux comprendre l’hypersensibilité ».</p>\n<p>(Lien rémunéré par Amazon)</p>\n<p>Si mon travail vous aide 🙂</p>','published',1,'Caractéristiques des Hypersensibles : se Comprendre pour Vivre Heureux','L’hypersensibilité concerne 15 à 20 % de la population. Quelles sont les caractéristiques des hypersensibles ? Comment vivre dans un monde moins sensible ?','https://vivre-pleinement.fr/hypersensibilite/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/hypersensibilite\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/hypersensibilite\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Caract\\u00e9ristiques des Hypersensibles : se Comprendre pour Vivre Heureux\",\"datePublished\":\"2019-08-06T15:31:23+00:00\",\"dateModified\":\"2024-02-12T20:01:54+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/hypersensibilite\\/\"},\"wordCount\":2954,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/hypersensibilite\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/08\\/Caracteristiques-hypersensibles.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/hypersensibilite\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/hypersensibilite\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/hypersensibilite\\/\",\"name\":\"Caract\\u00e9ristiques des Hypersensibles : se Comprendre pour Vivre Heureux\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/hypersensibilite\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/hypersensibilite\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/08\\/Caracteristiques-hypersensibles.jpg\",\"datePublished\":\"2019-08-06T15:31:23+00:00\",\"dateModified\":\"2024-02-12T20:01:54+00:00\",\"description\":\"L\\u2019hypersensibilit\\u00e9 concerne 15 \\u00e0 20 % de la population. Quelles sont les caract\\u00e9ristiques des hypersensibles\\u2009? Comment vivre dans un monde moins sensible\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/hypersensibilite\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/hypersensibilite\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/hypersensibilite\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/08\\/Caracteristiques-hypersensibles.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/08\\/Caracteristiques-hypersensibles.jpg\",\"width\":640,\"height\":427,\"caption\":\"Quels sont les caracteristiques des hypersensibles ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/hypersensibilite\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Caract\\u00e9ristiques des Hypersensibles : se Comprendre pour Vivre Heureux\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-08-06 15:31:23',NULL,'2026-05-24 19:19:45','2026-06-19 22:28:14');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (61,'Être Vrai et Authentique pour Devenir Véritablement Heureux','etre-authentique','Tous les êtres humains ont une personnalité profonde avec laquelle ils se sentent naturellement bien et heureux. Cependant, demeurer authentique quotidiennement s’avère quasi impossible pour de nombreuses personnes, qui portent différents masques la plupart du temps pour être acceptées par leurs pairs. Vous n’osez pas parler de vos manies ou de vos goûts aux autres de peur qu’ils vous trouvent ridicule. Vous vous forcez constamment à pratiquer des activités qui ne vous conviennent pas juste pour ne pas décevoir vos proches. Votre existence vous paraît terne. Il y a énormément d’inconvénients sur le long terme à porter un masque. Pour que votre vie reste une source d’épanouissement constante, il convient d’être vrai et authentique. Comment rendre votre vie riche avec de vraies relations ? Comment prendre confiance en vous grâce à une existence en accord avec votre nature ? \n','<p>Tous les êtres humains ont une <b>personnalité profonde </b>avec laquelle ils se sentent naturellement bien et heureux. Cependant, demeurer authentique quotidiennement s’avère quasi impossible pour de nombreuses personnes, qui portent différents <b>masques</b> la plupart du temps pour être <b>acceptées </b>par leurs pairs. Vous n’osez pas parler de vos manies ou de vos goûts aux autres de peur qu’ils vous trouvent ridicule. Vous vous forcez constamment à pratiquer des activités qui ne vous conviennent pas juste pour ne pas décevoir vos proches. Votre existence vous paraît terne. Il y a énormément <b>d’inconvénients</b> sur le long terme à porter un masque. Pour que votre vie reste une source <b>d’épanouissement</b> constante, il convient d’<b>être vrai et authentique. </b>Comment rendre votre vie riche avec de <b>vraies relations </b>? Comment prendre <b>confiance </b>en vous grâce à une existence en accord avec votre nature ?  </p>\n<h2>Que signifie être vrai et authentique ? </h2>\n<p>Être authentique, c’est tout simplement rester soi-même. Chaque personne est différente et certaines possèdent une originalité encore plus prononcée que d’autres. </p>\n<p>En tout cas, la personne spontanée s’assume telle qu’elle est, avec ses qualités et ses défauts, ses forces et ses faiblesses. </p>\n<p>Elle écoutera ses besoins, fera ce qu’elle a envie (sauf si ses actions nuisent gravement aux autres, ce qui est rarement le cas). Elle osera exprimer ce qu’elle pense vraiment, sans pour autant apparaître désagréable. Cet individu pourra affirmer pleinement ses goûts, même s’ils ne correspondent pas aux normes.<b> </b></p>\n<p>Finalement, cette personne est libre. </p>\n<h2>Les avantages à être soi </h2>\n<p>Il existe des avantages à se montrer tel que l’on est. Quels sont-ils ? </p>\n<h3>La confiance en soi </h3>\n<p>La personne libre se sentira bien et heureuse dans ses baskets, car elle sera elle-même. Elle réussira à développer sa confiance en elle, ce qui reste primordial pour le bien-être général.</p>\n<p>Avoir confiance en soi se remarque. Une grande assurance n’est pas gravée sur le front d’un individu, certes, mais elle se voit directement sur lui. Physiquement, il apparaît généralement souriant, s’exprime bien, a une bonne posture, etc. Mentalement, il dégage une énergie positive, ce qui se reflètera dans les actions qu’il entreprendra. En ayant <a href=\"/confiance-et-estime-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Confiance et estime de soi \">confiance en vous</a>, vous allez gagner la confiance des autres. C’est obligatoire. </p>\n<h3>Le courage </h3>\n<p>Je parle d’individu charismatique et courageux. En effet, avez-vous remarqué que dans beaucoup de situations, il en faut toujours un premier pour que les autres suivent ? Par exemple, sur une piste de danse, personne n’ose se lancer quand elle est vide. Il suffit d’une personne pour le faire et tout le monde suit juste après. </p>\n<h3>La passion </h3>\n<p>Cette personne mènera une vie heureuse vu qu’elle écoutera ses propres besoins et ce, sans être égoïste pour autant. On dit toujours qu’il faut déjà être bien soi-même avant d’aider les autres et c’est vrai. Elle écoutera ses désirs et fera en sorte que sa vie soit passionnante.</p>\n<h3>L’affirmation de soi </h3>\n<p>Les émotions ne seront pas refoulées chez elle, car elle saura <a href=\"/affirmation-de-soi\" target=\"_blank\" rel=\"noopener\" title=\"Affirmation de soi\">dire respectueusement qu’une situation la dérange.</a> Les conflits seront donc résolus facilement et agréablement, sans rancune, rumination ou haine postérieure persistante. </p>\n<p>Elle ne ressentira pas de honte ou d’autres troubles, car elle assumera ses faiblesses sans se soucier du regard des autres. </p>\n<p>Elle osera exprimer ses goûts même s’ils ne correspondent pas aux normes sociales. En général, elle sera surprise des effets que son attitude peut avoir. Par exemple, avez-vous déjà remarqué que si vous osez extérioriser un goût particulier, certaines personnes oseront dire également : « ah, moi aussi ! » alors qu’elles ne l’auraient jamais dévoilé d’elles-mêmes à la base, ressentant bien trop de peurs ou de timidité ? Et souvent, vous n’auriez jamais pensé qu’elles auraient pu avoir les mêmes goûts que vous. C’est un peu le même principe que la piste de danse. </p>\n<h3>La tolérance </h3>\n<p>L’individu apprendra en général la tolérance, car il s’aimera comme il est et du coup, acceptera également les autres pour ce qu’ils sont.</p>\n<h3>Un entourage bienveillant </h3>\n<p>Enfin, la personne authentique saura que son entourage l’aime pour ce qu’elle est véritablement et non pour ce qu’elle prétend être, pour son argent, son image, etc. ses relations seront donc sincères et profondes. Elle connaîtra ainsi l’amour véritable, clé fondamentale pour le bonheur.</p>\n<h2>Les inconvénients à être vrai</h2>\n<p>Je dis qu’être authentique veut « tout simplement » dire rester soi-même. Cependant, certains inconvénients montrent que le devenir n’est justement pas si « simple » qu’il n’y paraît.</p>\n<h3>Le sentiment de rejet </h3>\n<p>Lorsque vous osez rester vous-même, les autres n’en feront pas toujours de même. Résultat, ils resteront plus dans les normes sociales, qui représentent environ 80 % de la population. Du coup, en faisant partie des 20 % restants, il y a de fortes chances que vous vous sentiez anormal ou rejeté. Cependant, ce ne sera que votre ressenti, car ce n’est pas forcément le cas. </p>\n<h3>La méchanceté </h3>\n<p>Malheureusement, quand vous décidez de devenir vous-même, vous pouvez attirer la méchanceté. Certaines personnes vous jugeront de manière extrêmement virulente sur vos goûts.</p>\n<p>En général, si un individu réagit si fortement, c’est vous venez mettre en lumière un côté de sa personnalité qui le dérange. Car une personne heureuse n’a pas besoin de rabaisser ses semblables pour se rassurer sur sa supériorité. Elle sait que tout le monde est différent et que ce n’est pas pour autant qu’une personne est mieux qu’une autre.</p>\n<p>Bien souvent dans le cas de l’authenticité, le problème d’un individu restera la jalousie. En effet, il est fort possible qu’il jalouse votre capacité à réussir à être vous-même alors que lui-même n’en est pas capable. </p>\n<p>Ne vous laissez donc surtout pas déstabiliser par ce genre de personne. Ce cas ne constitue pas une généralité. </p>\n<h3>Être attaqué profondément </h3>\n<p>Certaines personnes savent pertinemment qu’elles jouent un rôle et comptent y rester. Quand on leur demande pourquoi, elles répondent ce genre de phrase : « nous sommes constamment critiqués. Donc au moins, lorsque nous sommes jugés, ce sera sur notre masque social et non sur notre nature profonde. »</p>\n<p>Ces individus, comme nous tous d’ailleurs, ressentent une grande terreur à l’idée d’être blessés sur leur être profond. Ainsi, pour éviter de souffrir, ils préfèreront mentir et se créer une fausse personnalité qui leur servira d’armure pour encaisser les attaques. En gros, le jugement des autres visera une personnalité qu’ils auront inventée. Les critiques les atteindront alors beaucoup moins.</p>\n<h3>Ne pas être aimé par tout le monde </h3>\n<p>Quand vous êtes vous-mêmes, forcément, vous ne plairez pas à tout le monde. Il faut avoir le courage d’autoriser les autres à vous blesser profondément. C’est une étape nécessaire pour être vous.</p>\n<p>Effectivement, je ne connais personne qui n’a jamais été jugé. C’est humain. Nous le faisons tous. Certains plus que d’autres si leur mal-être se trouve plus profond. Nous avons en effet tendance à critiquer tous ceux apparaissant différents de nous, c’est-à-dire… tout le monde ! Même si certaines personnes possèdent plus ou moins des traits de votre personnalité, elles restent tout de même différentes. Il faudra donc obligatoirement travailler sur votre aptitude à <a href=\"/jugement-des-autres\" target=\"_blank\" rel=\"noopener\" title=\"Jugement des autres \">accepter le regard d’autrui</a> sans vous dévaloriser. </p>\n<p>Dites-vous que de toute manière, quoi que vous fassiez, vous serez critiqué. Et vu les bienfaits que procure la capacité à être vous-même, autant vous y affairer dès maintenant, non ?</p>\n<p>Et pour vous aider dans cette quête de longue haleine qu’est d’accepter le regard des autres, je vous propose d’aller consulter le programme de Dider PENISSARD, coach et auteur en développement personnel, que vous trouverez en cliquant sur le bouton ci-dessous :</p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"1000\" height=\"662\" src=\"/storage/blog-images/masque-social.jpg\" alt=\"Norme sociale\" title=\"masque-social\">\n<h2>Les avantages à cacher son authenticité en portant un masque social </h2>\n<p>Si autant de personnes cachent leur vraie personnalité en portant un masque social, c’est qu’elles en retirent plusieurs avantages. Quelles sont-ils ? </p>\n<h3>Se sentir comme tout le monde </h3>\n<p>En portant un masque social, vous ferez partie de la <a href=\"/normes-sociales\" target=\"_blank\" rel=\"noopener\" title=\"Normes sociales \">norme, représentant 80 % de la population.</a> De là, vous ne ressentirez pas d’exclusion et aurez toutes les chances de répondre correctement aux attentes des autres, vu que vous aurez les mêmes que les leurs.  </p>\n<p>Vos pairs vous laisseront tranquille et vous pourrez vivre tranquillement. Vous vous sentirez appartenir au groupe. </p>\n<p>Pourquoi ce besoin d’appartenance à tout prix ? Je pense que cette nécessité vient de notre inconscient, par rapport aux vestiges que nous ont laissés nos ancêtres. En effet, dans des temps immémoriaux, les personnes trop différentes se faisaient exclure du clan et ce rejet les menait inéluctablement à la mort. Sauf qu’aujourd’hui, ce fait ne se trouve plus vraiment d’actualité…</p>\n<h3>Détenir une protection</h3>\n<p>En vous faisant critiquer sur votre personnage et non sur votre véritable personne, vous ne serez pas blessé profondément. Votre image sociale vous sert donc d’armure. </p>\n<h2>Les inconvénients à réprimer sa véritable personnalité </h2>\n<p>Cacher sa personnalité comporte de nombreux inconvénients et pas des moindres. Quels sont-ils ?</p>\n<h3>Le refoulement de ses véritables besoins et désirs</h3>\n<p>Si vous rêvez de devenir chanteur, vous entendrez forcément dans votre entourage (sauf si vos parents sont également artistes) : « redescends sur terre, arrête d’être idéaliste, trouve-toi un vrai métier, comme banquier par exemple. » Du coup, vous faites ce que les autres vous disent pour rester dans les 80 % de la population, c’est-à-dire vous orienter vers des jobs normaux, en ayant une vie normale. </p>\n<p>C’est un exemple comme un autre. Si votre existence ne correspond pas à vos véritables désirs, vous risquez de le regretter un jour. Je suis sûre que vous avez déjà entendu ce genre de discours, ou que vous le dites vous-même : « tout va bien. J’ai un travail satisfaisant, une belle maison, une superbe voiture, un mari, deux enfants, un chat, un chien, etc., mais je ressens un grand vide en moi. Je manque de joie de vivre, de passion. Stop, j’arrête de me plaindre, j’ai une vie normale dont tout le monde rêve, ce sentiment passera. »</p>\n<p>Cependant, votre mal-être ne s’estompera pas et risquera même de s’aggraver. Car vous avez tout simplement refoulé vos vrais besoins et vous vivez selon ce qu’il convient d’accomplir pour rester dans les normes et non en fonction de vos véritables désirs.</p>\n<h3>Une vie monotone </h3>\n<p>Vous avez une existence normale. Pas de rêve. Pas de but. Vous laissez ces bêtises aux idéalistes. Votre vie n’est pas géniale, mais elle n’est pas horrible non plus. Elle est moyenne quoi. Et vous faites avec en restant dans votre zone de confort.</p>\n<p>Forcément, comment voulez-vous ressentir du pep’s et de la niaque en pensant ainsi ? Ah oui, mais au moins, vous êtes comme tout le monde, c’est le principal, non ? Moui, mais du coup, pourquoi ressembler à vos semblables ne vous rend-il pas heureux alors ? Car même si les autres vous acceptent, ils continuent de vivre leur vie sans se soucier de la vôtre. Et vous en faites de même. Sauf que vous ne vivez pas la vie que vous désirez. Et le comble, c’est que vous apprenez que même en faisant tout pour être comme les autres, vous vous faites tout de même critiquer par eux ! Comment osent-ils ! </p>\n<h3>Ne pas forcément s’entourer des bonnes personnes </h3>\n<p>Quand vous portez un masque social, vous avez tendance à cacher votre véritable personnalité et à prendre celle qui correspond le plus aux normes. Du coup, les personnes que vous allez côtoyer ne correspondront pas forcément à ce que vous êtes réellement. Résultat, on entend souvent des phrases de ce genre : « cette personne ne me connaissait que pour les sorties. Elle m’a déçue, je ne la pensais pas ainsi. Elle m’a trahie. Je trouve qu’elle a changé. Elle a profité de moi, etc. »</p>\n<p>Au cours de votre existence, vous rencontrerez beaucoup de gens, mais la plupart d’entre eux ne seront que de passage. Certains prétendent même que l’on ne peut garder un ami pour la vie. À moins que l’on prenne des chemins différents, ce qui peut effectivement arriver, je pense que l’on peut conserver un ami pour la vie. Encore faut-il lui avoir dévoilé sa véritable personnalité ! Sinon, c’est sûr qu’à un moment, l’amitié s’estompera. </p>\n<p>Les personnes que vous pensez donc de passage ou traîtresses sont tout simplement des gens avec qui vous avez joué un rôle sans oser vous montrer véritablement. </p>\n<img decoding=\"async\" width=\"900\" height=\"463\" src=\"/storage/blog-images/Authenticite.jpg\" alt=\"Vraie personnalite \" title=\"Authenticité\">\n<p>Il a donc plus d’avantages sur le long terme à être vous plutôt que votre personnage. </p>\n<p>Après, n’imaginez pas qu’il soit possible d’être vous-même 24 h/24. Toute situation ne s’y prête pas. Par exemple, au travail, vous êtes obligé de vous adapter un minimum à votre entreprise. Vous ne pouvez pas dire tout haut ce que vous pensez sans arrêt, comme exprimer à un collègue que vous ne pouvez pas le sentir. Sinon, bonjour l’ambiance !</p>\n<p>Il ne faut en effet pas tout confondre. Vous pouvez rester vous-même, mais pas au détriment des autres. Toute vérité n’est pas forcément bonne à dire si vos propos blessent profondément l’autre.</p>\n<p>Le principal, c’est de pouvoir vivre en prenant en compte vos véritables besoins, et ce, sans avoir peur du regard des autres et tout en essayant de les préserver. Apprenez à<b> être vrai et authentique</b> et vous verrez que votre vision de la vie va nettement s’améliorer. Vous allez reprendre confiance.</p>\n<p>Si vous aimez mon travail 🙂</p>','published',1,'Être Vrai et Authentique pour Devenir Véritablement Heureux','Pour que votre vie reste une source d’épanouissement, il convient d’être vrai et authentique. Comment vivre une existence en accord avec votre nature ?','https://vivre-pleinement.fr/etre-authentique/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/etre-authentique\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/etre-authentique\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"\\u00catre Vrai et Authentique pour Devenir V\\u00e9ritablement Heureux\",\"datePublished\":\"2019-07-30T16:50:16+00:00\",\"dateModified\":\"2024-02-12T20:04:03+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/etre-authentique\\/\"},\"wordCount\":4729,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/etre-authentique\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/07\\/etre-vrai-authentique.jpg\",\"articleSection\":[\"D\\u00e9veloppement personnel\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/etre-authentique\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/etre-authentique\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/etre-authentique\\/\",\"name\":\"\\u00catre Vrai et Authentique pour Devenir V\\u00e9ritablement Heureux\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/etre-authentique\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/etre-authentique\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/07\\/etre-vrai-authentique.jpg\",\"datePublished\":\"2019-07-30T16:50:16+00:00\",\"dateModified\":\"2024-02-12T20:04:03+00:00\",\"description\":\"Pour que votre vie reste une source d\\u2019\\u00e9panouissement, il convient d\\u2019\\u00eatre vrai et authentique. Comment vivre une existence en accord avec votre nature\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/etre-authentique\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/etre-authentique\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/etre-authentique\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/07\\/etre-vrai-authentique.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/07\\/etre-vrai-authentique.jpg\",\"width\":800,\"height\":569,\"caption\":\"Est-ce utile de rester vrai et authentique ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/etre-authentique\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"\\u00catre Vrai et Authentique pour Devenir V\\u00e9ritablement Heureux\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-07-30 16:50:16',NULL,'2026-05-24 19:19:45','2026-06-19 22:28:14');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (62,'Guérir de l’Anxiété Sociale pour Retrouver la Paix Intérieure','phobie-sociale','La phobie sociale est loin d’être rare. Cependant, c’est un trouble pouvant être extrêmement handicapant, empêchant réellement un individu de vivre. En effet, nous sommes des animaux sociaux et sommes obligés de vivre un minimum en société. De ce fait, cette angoisse rend l’adaptation au monde très difficile. Le regard des autres vous apparaît insupportable. Dès que vous sortez de chez vous, vous avez une peur panique de vomir ou d’avoir une diarrhée devant les autrui, et ce, sans trouver d’issue de secours. Vous rougissez facilement et avec donc une crainte extrême que la personne qui vous parle le remarque. Vous n’en pouvez plus de vivre ainsi ? Comment guérir de l’anxiété sociale ? \n','<p>La <b>phobie sociale </b>est loin d’être <b>rare</b>. Cependant, c’est un trouble pouvant être extrêmement <b>handicapant</b>, empêchant réellement un individu de vivre. En effet, nous sommes des <b>animaux sociaux</b> et sommes obligés de vivre un minimum en société. De ce fait, cette angoisse rend l’adaptation au monde très difficile. Le <b>regard des autres</b> vous apparaît insupportable. Dès que vous sortez de chez vous, vous avez une peur panique de <b>vomir </b>ou d’avoir une <b>diarrhée </b>devant les autrui, et ce, sans trouver d’<b>issue de secours.</b> Vous <b>rougissez </b>facilement et avec donc une crainte extrême que la personne qui vous parle le <b>remarque</b>. Vous n’en pouvez plus de vivre ainsi ? Comment <b>guérir de l’anxiété sociale ? </b></p>\n<h2>Qu’est-ce que l’anxiété sociale ? </h2>\n<p>Ce trouble, comme son nom l’indique, constitue une phobie, pouvant prendre des formes plus ou moins importantes. La principale appréhension de l’individu reste le regard de l’autre, qu’il pense constamment braqué sur lui. Il est en effet persuadé que son semblable le jugera mal et a peur de déclencher sur lui une situation qui le rendra honteux vis-à-vis d’autrui. </p>\n<p>L’individu évite alors tout contact avec les autres, ce qui peut appauvrir ses relations. Il peut se cantonner à ses principaux proches, avec qui il se sent le plus en sécurité. Cet individu apparaîtra souvent casanier, évitant au plus la population, car il ne voit pas l’utilité nouer des liens éphémères et futiles. </p>\n<p>Il aimera donc son cocon et dans les cas les plus graves, n’arrivera même plus à sortir et à mener une vie normale. </p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img fetchpriority=\"high\" decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h2>Quelles formes peut prendre la phobie sociale ? </h2>\n<p>L’anxiété sociale peut se manifester de différentes façons. Voici les principales apparences qu’elle peut revêtir. </p>\n<h3>L’émétophobie  </h3>\n<p>Il s’agit de la peur de voir les autres régurgiter ou de vomir soi-même, et ce, devant tout le monde. C’est une phobie très fréquente. </p>\n<p>Contrairement à certaines angoisses qui ne se réalisent pas (comme la phobie l’impulsion), cette phobie le peut… mais n’ayez crainte, car il y a des solutions pour la maîtriser ! </p>\n<p>Indiscutablement, les nausées/le vomissement peuvent constituer un effet de l’attaque de panique et lorsque vous souffrez d’émétophobie, vous pouvez évidemment déclencher une <a href=\"/angoisse-stress-anxiete\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse stress anxiété \">crise d’angoisse</a> en public et avoir ce symptôme.</p>\n<p>Je sais de quoi je parle, car j’ai eu cette phobie vers l’âge de 13 ans, au collège. Je n’allais plus en cours par peur de vomir. Le matin, je me levais en me trouvant déjà en crise de panique. Mon métabolisme tout entier s’emballait et de ce fait, au moment du petit-déjeuner, je n’arrivais pas à manger. Perte d’appétit et surtout, envie de vomir. Étrangement, quand ma mère me disait « Reste à la maison », je pétais la forme le restant de la journée ! Et rebelote le lendemain matin… </p>\n<p>La personne a donc surtout peur de régurgiter devant tout le monde si elle stresse trop. </p>\n<p>Résultat, elle va éviter le plus possible l’extérieur et les événements publics, de peur de vomir devant les autres. </p>\n<p>Il y a dans cette peur une phobie d’être rejeté par ses pairs, en y ressentant de la honte.</p>\n<p>Enfin, le fait de manger et de vomir ensuite, ou de ne pas beaucoup se nourrir de peur de régurgiter, va affaiblir la personne et l’amaigrir. Il peut donc y avoir de fortes conséquences pour la santé sur le long terme. </p>\n<img decoding=\"async\" width=\"1000\" height=\"997\" src=\"/storage/blog-images/Phobie-sociale.jpg\" alt=\"Peur du regard des autres\" title=\"Phobie-sociale\">\n<h3>La laxophobie </h3>\n<p>C’est un peu le même principe que pour l’émétophobie, mais il s’agit là de la peur d’être pris de diarrhées en public et de ne pouvoir accéder aux toilettes à temps. </p>\n<p>Idem que pour l’angoisse de vomir, la diarrhée peut se déclencher du fait du métabolisme accéléré lorsque vous angoissez trop.</p>\n<p>La personne évitera donc au plus les sorties ou, si elle sort de temps en temps, se rassurera en prenant avec elle des médicaments pour ce problème. Elle fera en sorte de trouver des w.c. à proximité.</p>\n<p>Il s’agit aussi d’une phobie très fréquente.</p>\n<h3>L’éreutophobie</h3>\n<p>C’est la crainte de rougir en public. </p>\n<p>Tout le monde peut rougir et ce n’est pas que le sentiment de peur qui peut provoquer ce rougissement. Il peut également survenir lors d’une émotion de tristesse, de colère, etc.</p>\n<p>Il s’agit généralement de personnes ne souhaitant pas exprimer leurs émotions et voulant les garder secrètes. Cependant, en essayant de les cacher, ces sentiments refoulés peuvent apparaître sur leur corps. Quand vous voyez une personne rougir, vous devinez qu’elle ressent une émotion très forte au même moment. De la gêne, de la honte, de la colère, etc.</p>\n<p>En refoulant l’émotion, elle va devoir se trouver une autre porte de sortie en s’exprimant sur votre corps. </p>\n<p>Pour ma part, j’ai la peau ultra-sensible. Tout le monde arrive à savoir quand je suis trop stressée. Ce stress se reflète directement sur le haut de ma poitrine : de grosses taches rouges apparaissent et s’en vont dès que la source d’anxiété disparaît. </p>\n<p>Eh oui, vos émotions s’expriment, que vous le vouliez ou non, sur votre corps. </p>\n<h2>Les causes du trouble d’anxiété sociale </h2>\n<p>La phobie sociale provient fréquemment de l’enfance. L’enfant aura pu être trop surprotégé du monde extérieur et aura donc énormément de mal avec le contact social. Les parents apparaîtront eux-mêmes en général souvent <a href=\"/etre-casanier\" target=\"_blank\" rel=\"noopener\" title=\"Casanier \">casaniers</a>. </p>\n<p>Elle peut aussi provenir d’un élément déclencheur et <a href=\"/traumatisme\" target=\"_blank\" rel=\"noopener\" title=\"Traumatisme\">traumatisant</a> en public. Pour ma part, mon émétophobie est apparue suite à un événement de la sorte. J’étais au collège et de plus en plus mal à l’aise. Je ne faisais que trembler et, avec du recul, j’ai compris qu’il s’agissait d’une crise d’angoisse. Résultat, j’ai vomi devant pas mal d’élèves dans la cour de récréation.</p>\n<p>D’autres auront, par exemple, régurgité suite à une gastro, mais ce moment aura été tellement désagréable pour eux (ne plus réussir à respirer, être écœuré, etc.) qu’ils auront la phobie de vomir à nouveau.</p>\n<p>Une copine avait une fois eu envie d’uriner en classe. Elle avait demandé au professeur de sortir et il avait refusé. Résultat, elle avait fait pipi… dans sa culotte.</p>\n<p>Ensuite, entre chaque cours et même si elle n’en ressentait pas le besoin, elle devait impérativement aller aux toilettes pour essayer d’uriner. Si elle ne le pouvait pas, une grosse crise d’angoisse s’ensuivait. </p>\n<p>Dans ces cas, il s’agit donc d’un épisode ou la personne a ressenti de la honte en public. Pourtant, personne ne l’avait insulté et ne lui en avait tenu rigueur et pour moi non plus d’ailleurs ! </p>\n<h2>La différence entre phobie sociale et tempérament casanier </h2>\n<p>Que les choses soient claires : vous avez le droit de préférer vous trouver chez vous plutôt qu’à l’extérieur. Le problème, c’est quand vous ne voulez plus sortir du tout ou qu’en sortant, vous ressentez une grande angoisse chaque fois. </p>\n<p>En réalité, il y a deux types de personnalités : les introvertis et les extravertis. L’un n’est pas moins bien ou mieux que l’autre, il s’agit juste d’une personnalité. </p>\n<p>La personne introvertie aura besoin de 80 % de calme avec elle-même et de 20 % de contact social. Si elle passe une journée hyper mouvementée et si elle ressort également le soir, elle risque d’être vraiment très mal, irritable, fatiguée, voire, de subir une crise de panique. Il faudra plutôt qu’elle prenne le temps de se ressourcer le soir avec elle-même, dans son cocon.</p>\n<p>En revanche, une personne extravertie aura besoin de l’inverse : 80 % de contact social et 20 % de calme. Donc, après une journée très intense, elle sortira encore au crépuscule pour voir du monde ! C’est son moyen à elle pour se ressourcer. Par contre, si elle reste toute une journée seule, par exemple, elle risque fortement d’angoisser et de déprimer.</p>\n<h2>L’importance d’entretenir des liens sociaux malgré la phobie sociale</h2>\n<p>Que vous le vouliez ou non, vous êtes un animal social et votre nature profonde souhaite nouer des liens. Ce sont juste votre environnement, votre éducation et vos expériences qui vous ont conditionné à avoir la peur de l’autre. Mais cet état n’est pas naturel. Nous avons tous besoin des autres. Dire le contraire ne reflète qu’un égo qui s’exprime.</p>\n<p>Comme je le répète, vous avez le droit de vous accorder plus de moments de calme que d’autres. Il peut s’agir de votre personnalité. Mais surtout, ne vous fermez pas complètement à autrui ! Même si vous trouvez que sortir est inutile, car des conversations futiles ne servent absolument à rien pour vous, détrompez-vous. Vous pourrez, qui sait, nouer des liens avec cette personne, voire une profonde amitié par la suite. Plus vous sortez de votre cocon, plus les occasions s’offriront à vous. Il faut donc, même si vous n’en avez pas envie, aller vous promener de temps en temps, ne serait-ce qu’un peu. Inviter du monde par exemple ou aller aux invitations, vous inscrire à une salle de sport, à une association, etc. Réaliser au moins une petite activité collective dans la semaine vous coupant de vos habitudes. Vous verrez que votre phobie sociale va diminuer. </p>\n<img loading=\"lazy\" decoding=\"async\" width=\"937\" height=\"720\" src=\"/storage/blog-images/Trouble-anxiete-sociale.jpg\" alt=\"Peur du jugement \" title=\"Trouble-anxiété-sociale\">\n<h2>Les solutions pour guérir de l’anxiété sociale  </h2>\n<p>Heureusement, il existe des solutions pour soigner ce trouble anxieux invalidant. Les voici : </p>\n<h3> La thérapie comportementale et cognitive</h3>\n<p>Les TCC restent recommandées pour ce trouble. En effet, le problème de la phobie sociale, c’est que la personne n’ose plus sortir. Les TCC l’aideront donc à passer à l’action en lui faisant pratiquer des exercices de plus en plus difficiles. Tout dépend du degré d’anxiété de la personne. Il faut cependant y aller par étape, au risque d’avoir une peur trop forte et d’éviter encore plus les situations sociales par la suite. </p>\n<p>Il s’agira par exemple déjà de sortir devant chez soi. Puis de se rendre à la boulangerie seul. Ensuite, de se déplacer dans une boutique. Puis en ville, puis au restaurant jusqu’à partir en voyage à l’étranger, etc. C’est à la personne de fixer ses propres objectifs, du plus simple au plus difficile, en se récompensant après chaque réussite. </p>\n<p>Si les exercices s’avèrent trop difficiles, les TCC peuvent être couplées avec des médicaments, mais seulement s’il y a impossibilité de réaliser les exercices.</p>\n<h3>Ne plus se soucier du regard des autres</h3>\n<p>La phobie sociale prend littéralement sa source dans la façon dont vous percevez le <a href=\"/jugement-des-autres\" target=\"_blank\" rel=\"noopener\" title=\"Jugement des autres \">regard des autres. </a></p>\n<p>Premièrement, pensez-vous que les gens ne rougissent pas quelquefois, ou ne vomissent pas, ou n’ont pas la diarrhée ? Tout le monde a déjà vécu ces situations, car nous restons humains. Il n’y a donc pas de honte à avoir à cet égard. </p>\n<p>Deuxièmement, si vraiment un jour votre « drame » arrive, en général, vos semblables ne seront pas moqueurs. Ils essayeront de vous aider, de voir si tout va bien, s’il faut appeler les urgences, etc. c’est comme quand une personne tombe dans les pommes. Est-ce que les gens sont autour d’elle à se moquer ou volent-ils en général à son secours ? C’est la deuxième option, non ? D’ailleurs, pensez-vous vraiment que les autres vont parler toute leur vie de votre « humiliation » ? Je ne pense pas. Si tel est le cas, c’est qu’ils n’ont vraisemblablement pas une existence bien passionnante… </p>\n<p>De plus, sachez que tout le monde a un peu peur de l’image qu’il peut donner vis-à-vis d’autrui. Par conséquent, les gens se poseront également des questions de leur côté et de ce fait, ne penseront pas toujours à vous juger. Les autres ont aussi beaucoup de préoccupations personnelles, leur vie ne tourne pas autour de la vôtre. Ils seront loin de penser constamment à vous !</p>\n<p>Enfin, dites-vous bien que quoi que vous fassiez, vous serez de toute façon jugé. C’est la nature humaine qui veut ça. Vous jugez également. Donc, pourquoi finalement ne pas rester vous-même ? </p>\n<p>Et si vous souhaitez un petit coup de pouce afin de vous libérer du <strong>regard des autres</strong>, je vous suggère le <strong>programme</strong> de <strong>Didier PENISSARD, coach, auteur et conférencier en développement personnel</strong>, que vous trouverez en cliquant sur le bouton ci-dessous :</p>\n<h3>Focaliser son attention </h3>\n<p>Quand vous allez vous confronter à votre phobie, essayez de ne plus penser à vous, à votre corps, mais au monde qui vous entoure. Par exemple, si vous êtes invité à une soirée, au lieu de réfléchir sur ce qu’il pourrait vous arriver de honteux et de ruminer, regardez les autres, leurs habits, le décor, etc. Ce faisant, vous arrêterez de focaliser votre attention sur vous et les symptômes n’apparaîtront pas ou se réduiront considérablement. </p>\n<h3>Réguler sa respiration pour calmer l’attaque de panique</h3>\n<p>Si vous commencez à avoir la nausée ou que vous allez bientôt devoir aller aux toilettes, c’est que votre métabolisme est trop accéléré. Il y a cependant une façon de le calmer. En général, pendant une crise, ne sentez-vous pas que votre respiration est coupée ? Il suffit de bien réguler votre souffle, d’inspirer et d’expirer calmement. Il faudra plusieurs minutes avant que le métabolisme reprenne son état normal, mais je vous assure que ce conseil fonctionne. Savoir respirer est primordial pour soigner l’anxiété.</p>\n<p>Et justement, pour bien <strong>respirer</strong>, je pratique personnellement la<strong> cohérence cardiaque</strong>. Et pour m’y aider, j’utilise un petit appareil se nommant <a href=\"/zenspire/\" target=\"_blank\" rel=\"noopener\" title=\"Zenspire\"><strong>ZENSPIRE</strong></a>, lequel émet des <strong>vibrations</strong> et de la <strong>lumière</strong> afin de m’aider à respirer <strong>profondément</strong> et <strong>naturellement</strong>. Car oui, beaucoup de personnes ont oublié de bien respirer ! Si ce petit appareil vous intéresse, n’hésitez pas à cliquer sur le bouton ci-dessous, étant précisé que si vous passez <strong>commande</strong>, vous bénéficierez d’une <strong>réduction immédiate de 10 %</strong> en utilisant le code <strong>JL0620</strong> :</p>\n<p>Voilà les principales clés pour <b>guérir de l’anxiété sociale.</b> A vous de jouer maintenant !</p>\n<p><a href=\"https://amzn.to/42AcKBe\">Visitez Amazon pour vous procurer le livre</a> de Vincent Trybou « Comprendre et traiter l’anxiété sociale : nouvelles approches en TCC ».</p>\n<p>(Lien rémunéré par Amazon)</p>\n<p>Si vous appréciez mon travail 🙂</p>','published',1,'Guérir de l’Anxiété Sociale pour Retrouver la Paix Intérieure','La phobie sociale est un trouble pouvant être extrêmement handicapant. Vous n’en pouvez plus de vivre ainsi ? Comment guérir de l’anxiété sociale ?','https://vivre-pleinement.fr/phobie-sociale/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/phobie-sociale\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/phobie-sociale\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Gu\\u00e9rir de l\\u2019Anxi\\u00e9t\\u00e9 Sociale pour Retrouver la Paix Int\\u00e9rieure\",\"datePublished\":\"2019-07-21T16:16:39+00:00\",\"dateModified\":\"2024-02-13T19:33:42+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/phobie-sociale\\/\"},\"wordCount\":4482,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/phobie-sociale\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/07\\/Guerir-anxiete-sociale.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/phobie-sociale\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/phobie-sociale\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/phobie-sociale\\/\",\"name\":\"Gu\\u00e9rir de l\\u2019Anxi\\u00e9t\\u00e9 Sociale pour Retrouver la Paix Int\\u00e9rieure\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/phobie-sociale\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/phobie-sociale\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/07\\/Guerir-anxiete-sociale.jpg\",\"datePublished\":\"2019-07-21T16:16:39+00:00\",\"dateModified\":\"2024-02-13T19:33:42+00:00\",\"description\":\"La phobie sociale est un trouble pouvant \\u00eatre extr\\u00eamement handicapant. Vous n\\u2019en pouvez plus de vivre ainsi\\u2009? Comment gu\\u00e9rir de l\\u2019anxi\\u00e9t\\u00e9 sociale\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/phobie-sociale\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/phobie-sociale\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/phobie-sociale\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/07\\/Guerir-anxiete-sociale.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/07\\/Guerir-anxiete-sociale.jpg\",\"width\":700,\"height\":739,\"caption\":\"Comment guerir de l\\u2019anxiete sociale ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/phobie-sociale\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Gu\\u00e9rir de l\\u2019Anxi\\u00e9t\\u00e9 Sociale pour Retrouver la Paix Int\\u00e9rieure\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-07-21 16:16:39',NULL,'2026-05-24 19:19:45','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (63,'Reprendre du Pouvoir sur sa Vie : le Meilleur Moyen d’être Heureux','devenir-responsable','L’existence n’est pas un long fleuve tranquille et il est vrai que tout le monde ne part pas sur un même pied d’égalité. Certaines personnes, de par leur passé et des différentes expériences qu’elles ont vécues, ont développé des traumatismes. Elles peuvent maintenant souffrir de maladies physiques et psychologiques, comme les troubles anxieux, la dépression, etc. Le problème, c’est qu’elles s’identifient à leurs difficultés et de ce fait, deviennent victimes de leur vie. Cependant, il existe une solution à leur souffrance : la prise de responsabilité. Vous sentez que vous subissez votre existence et en avez assez ? Comment reprendre du pouvoir sur sa vie ? \n','<p>L’existence n’est pas un long fleuve tranquille et il est vrai que tout le monde ne part pas sur un même pied <strong>d’égalité.</strong> Certaines personnes, de par leur passé et des différentes expériences qu’elles ont vécues, ont développé des<strong> traumatismes.</strong> Elles peuvent maintenant souffrir de maladies physiques et psychologiques, comme les troubles anxieux, la dépression, etc. Le problème, c’est qu’elles s’identifient à leurs difficultés et de ce fait, deviennent <strong>victimes</strong> de leur vie. Cependant, il existe une solution à leur souffrance : la prise de responsabilité. Vous sentez que vous subissez votre existence et en avez assez ? Comment<b> reprendre du pouvoir sur sa vie ? </b></p>\n<h2>La victimisation, le contraire de la prise de responsabilités </h2>\n<p>Lorsque vous souffrez de <a href=\"/angoisse-stress-anxiete\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse stress anxiété\">troubles anxieux</a> qui handicapent votre quotidien, vous pouvez avoir tendance à adopter le système de pensées suivant : « pourquoi moi ? Pourquoi suis-je si différent ? Pourquoi n’ai-je pas moi aussi droit au bonheur ? C’est à cause de mes parents, à coup sûr. De mon environnement. De mes professeurs. Des autres en général. À cause, à cause…»</p>\n<p>De là peut s’enclencher l’habitude à vous victimiser par rapport à votre état. Résultat, vous vous empêtrez de plus en plus dans votre anxiété, laquelle devient votre seconde nature.</p>\n<p>Le problème, c’est que si vous reportez toute la faute sur l’extérieur, comment voulez-vous avoir le pouvoir de transformer votre vie ? Vous pouvez en effet travailler sur vous-même, mais en aucun cas changer les personnes ou certaines circonstances. Il est donc vain de tout reporter en dehors de vous.</p>\n<h2>Ne pas prendre ses responsabilités en accusant ses parents</h2>\n<p>Quand vous possédez un travers vraiment gênant et handicapant, vous vous dites forcément que c’est de la faute de l’éducation que vous avez reçue.</p>\n<p>J’avoue que, comme le dit la célèbre chanson, « on ne choisit pas ses parents, on ne choisit pas sa famille ». Alors, il va falloir faire avec ce que vous avez. </p>\n<p>Vous n’avez pas la famille la plus parfaite au monde et c’est normal, car la perfection n’existe pas. Vous avez donc des défauts qui peuvent provenir d’elle, c’est un fait. </p>\n<p>Il est également vrai qu’aucune éducation n’est similaire. Voici les 4 principaux types de parents que vous pouvez avoir.</p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"960\" height=\"720\" src=\"/storage/blog-images/Victimisation.jpg\" alt=\"Calimero\" title=\"Victimisation\">\n<h3>Un père et une mère équilibrés </h3>\n<p>Certains d’entre nous auront plus de chance et grandiront dans un modèle familial avec une structure de base saine, équilibrée. Ils ne développeront normalement pas de trouble névrotique ou autre, auront une vie (hors éléments tragiques, j’entends) normale. Je dirais qu’il s’agit d’une grande majorité de la population, 80 % environ.</p>\n<p>Ces personnes n’auront aucun problème pour rentrer dans les normes sociales. Elles seront donc en général « normales ».</p>\n<h3>Des parents surprotecteurs </h3>\n<p>Certains auront une famille surprotectrice (comme la mienne). L’amour ne manque en général pas dans cette famille, ce qui est déjà magnifique. Cependant, les parents réaliseront généralement tout à la place de l’enfant et le surprotègeront à outrance. Résultat, le petit ne saura rien accomplir par lui-même et surtout, s’en sentira incapable. Il aura un peu l’impression de se trouver dans une sorte de prison dorée : heureux chez lui, mais paniqué à l’extérieur. Comme un lion ayant grandi dans une cage et découvrant la savane pour la première fois des années plus tard. Cet animal aura certainement de grosses difficultés d’adaptation par rapport à ses congénères.</p>\n<p>En général, ce type d’enfant aura tendance à développer des troubles névrotiques, anxieux, voire peut-être même dépressifs à l’âge adulte, car tous les événements « normaux » de la vie lui paraîtront insurmontables. Il n’aura pas confiance en lui. Il aura une prédisposition à l’hypersensibilité et se sentira en marge des autres, inadapté au monde.</p>\n<h3>Une famille exigeante</h3>\n<p>Ce type de parents ne sera généralement jamais satisfait de ce qu’accomplira leur enfant. Il aura tendance à prononcer ce genre de phrases : « 17/20 ? OK, mais pourquoi Patrick a eu 19, lui ? »</p>\n<p>Résultat, l’enfant ressentira un poids énorme sur ses épaules qu’il ne pourra jamais évacuer, car, quoi qu’il accomplisse, ce ne sera jamais assez bon. </p>\n<p>Ce type d’enfants deviendra alors <a href=\"/perfectionnisme\" target=\"_blank\" rel=\"noopener\" title=\"Perfectionnisme\">perfectionniste</a> et développera peut-être même une personnalité obsessionnelle, une rigidité extrême. Il n’arrivera jamais à lâcher-prise, voudra toujours être le premier, le meilleur. Il paraîtra souvent froid, distant et ne sera pas vraiment joyeux. </p>\n<p>En effet, quand vous êtes perfectionniste, vous ne pouvez être heureux, car la perfection n’existe pas…</p>\n<p>Rien ne va donc jamais pour ce genre de personnes, qui ressent de la frustration permanente et un manque certain de joie de vivre dans sa vie. Il pourra également développer des troubles anxieux.</p>\n<h3>Des parents violents et indifférents </h3>\n<p>C’est le genre de parents qui ne donnera pas de tendresse à son enfant et ça, c’est dramatique. C’est très difficile pour un petit de souffrir de carence affective. Au risque de paraître niaise, je pense que ce dont un enfant a besoin essentiellement, c’est d’amour.</p>\n<p>Certains iront même jusqu’à porter la main sur leur enfant, voir même, pratiquer l’inceste… Le petit pensera que s’il se fait frapper, c’est qu’il a fait quelque chose de mal. Il va donc culpabiliser, alors qu’il n’en est rien. Difficile pour lui de vivre pleinement sa vie d’adulte dans ces conditions ! </p>\n<p>Ce type d’enfant pourra être, en tant qu’adulte, extrêmement perturbé, ne rien oser entreprendre. Il n’aura absolument pas confiance en lui, se sentira anormal. Parfois, certains reproduisent ce que les parents ont fait, mais heureusement, c’est souvent tout l’inverse. Ces adultes apparaîtrons peut-être surprotecteurs avec leur enfant, car ils ne voudront surtout pas qu’il vive la même chose. </p>\n<p>Quelquefois, ils développeront de plus importantes perturbations, comme les troubles psychotiques, l’état limite… ils pourront également consommer de la drogue et beaucoup d’alcool, etc., mais ce n’est pas une généralité. Certains s’en sortent très bien !</p>\n<h2>Prendre ses responsabilités en pardonnant à ses parents</h2>\n<p>Tous les parents, sauf cas exceptionnels, souhaitent le meilleur pour leur enfant. Cependant, ils s’y prennent par rapport à ce qu’eux ont appris, donc, pas forcément bien. Eux aussi ont leurs blessures et <a href=\"/traumatisme\" target=\"_blank\" rel=\"noopener\" title=\"Traumatisme\">traumatismes</a> inconscients, voilà pourquoi certaines fois, ils se fourvoient. </p>\n<h3>Pardonner à un parent surprotecteur </h3>\n<p>Un parent surprotecteur aura généralement une personnalité très anxieuse, inculquée par ses propres parents, lesquels auront probablement été éduqués également de la sorte, etc. Vu qu’il croit que tous les drames possibles peuvent arriver, il protégera beaucoup trop l’enfant, mais pensera bien faire. En effectuant tout à sa place, il estimera faciliter la vie du petit et la rendre merveilleuse, simple. Au début, ce sera vrai. Cependant, à l’âge adulte, l’enfant aura un mal fou à s’adapter au monde.</p>\n<h3>Excuser un parent exigeant</h3>\n<p>Idem pour les parents exigeants, qui ont été élevés eux-mêmes par des parents perfectionnistes. Ils croient donc bien faire et en contrôlant à ce point leur enfant, pensent qu’il suivra forcément un bon chemin, fera automatiquement de bonnes études, obtiendra un poste prestigieux, etc. Son image sociale doit refléter la réussite. Sauf que quelquefois, l’enfant se sentira tellement prisonnier qu’il accomplir exactement l’inverse de ce que souhaitent ses parents. Il pourra aussi réaliser ce qu’ils désirent, mais portera de ce fait un masque social et n’arrivera pas à exprimer sa vraie personnalité.</p>\n<h3>Pardonner à un parent violent et indifférent </h3>\n<p>Les parents violents et indifférents auront généralement eu une éducation extrêmement difficile et dysfonctionnelle. Ils reproduiront également ce qu’ils ont appris. Il est beaucoup plus compliqué de pardonner à ce genre de parents. On se demande en effet pourquoi ils ont mis des enfants au monde si c’est pour les détester ou les maltraiter. Il faut pourtant essayer de les pardonner, ne serait-ce que pour soi, pour pouvoir avancer. Se dire qu’ils ne font que reproduire ce qu’ils ont eux-mêmes subi et qu’au fond, ce sont forcément des personnes malheureuses. À l’évidence, plus on demeure malheureux, plus on risque d’adopter de mauvais comportements. Et puis, maintenant que vous vous trouvez sur cette terre, vous ne pouvez plus rien y changer. Donc, pourquoi ne pas essayer de vivre votre vie pleinement ? </p>\n<h2>Exemples de situations du point de vue d’une victime</h2>\n<p>Souvent, vous avez tendance à vous comparer aux autres par rapport à certaines circonstances, fréquemment négatives, et vous victimiser à cet égard. Voici 5 exemples : </p>\n<p></p>\n<p>– Elle a eu une famille normale et moi non. Forcément, elle a une vie correcte et moi je galère avec mes troubles anxieux ! Quel monde injuste ! </p>\n<p>– J’ai perdu mon père à 15 ans et elle, à 50 ans, a encore ses deux parents ! Elle ne sait pas ce que c’est de souffrir ! Cette chanceuse aura été heureuse toute son existence et moi non !</p>\n<p>– Elle vient d’être embauchée et moi je suis là depuis 5 ans. Je lui demande son salaire et elle gagne plus que moi, c’est une blague ! Quelle garce, quel boulot ingrat, je hais le monde du travail ! </p>\n<p>– Elle peut manger ce qu’elle veut sans grossir, alors que moi, je mange un hamburger, je prends un kilo ! La justice n’est vraiment pas la même pour tous…</p>\n<p>– J’ai la maladie de Crohn alors que mon amie n’a aucun problème de santé. Elle ne comprend donc pas à quel point la vie peut être difficile avec une maladie ! </p>\n<img decoding=\"async\" width=\"800\" height=\"533\" src=\"/storage/blog-images/Responsabilite.jpg\" alt=\"Liberte \" title=\"Responsabilité\">\n<h2>Reprendre du pouvoir sur sa vie en changeant ses pensées </h2>\n<p>Voici maintenant comment, au lieu de vous victimiser en prononçant ces phrases, vous pouvez prendre vos responsabilités.  </p>\n<h3>L’injustice familiale </h3>\n<p>Je ne suis pas partie d’un aussi bon pied qu’elle, c’est vrai, mais j’ai déjà vécu des choses plus difficiles. Je détiens ainsi plus d’armes pour affronter ce genre de moments, car le fait d’aller mal va me donner envie de travailler sur moi, en me mettant à m’intéresser au développement personnel et donc, à devenir plus consciente. À force, j’acquerrai la liberté intérieure que bon nombre de personnes ne possèdent pas.</p>\n<h3>L’épreuve du décès précoce </h3>\n<p>Certains perdent leur enfant, ont perdu leurs deux parents… si on commence ainsi, on peut toujours trouver pire et mieux que nous. Le fait de connaître la mort plus tôt peut peut-être même aider à l’accepter et à ne pas la rendre taboue comme le font la plupart des personnes. Car, il faut bien le dire, tout le monde meurt donc, peu importe quand arrive ce moment. Nous n’avons aucune prise sur la mort. </p>\n<h3>La jalousie professionnelle</h3>\n<p>Elle, au moins, a négocié son salaire d’entrée de jeu et elle a bien raison. Si je n’ai pas eu le courage d’en faire autant, ce n’est pas son problème. Il faut bien se dire qu’une fois dans l’entreprise, il est très difficile de négocier ses revenus par la suite ! Donc si je ne suis pas contente et que j’estime ne pas gagner assez, à moi de passer à l’action en allant voir mon employeur. Si je ne suis pas augmentée, alors je n’ai qu’à changer de travail. En tant que salariée, je n’atteindrai de toute manière jamais une augmentation de + 100 %, ce ne sera que minime. Donc, si mon salaire ne me convient pas, je n’ai qu’à commencer à me renseigner sur comment lancer mon propre business.</p>\n<h3>La prise de poids facile </h3>\n<p>C’est l’occasion pour moi de me lancer, par exemple, dans un rééquilibrage alimentaire. Je mangerai sainement et en me mettant à me nourrir de beaucoup moins de cochonneries que les autres, j’aurai une bonne santé, un beau corps et me sentirai bien dans ma peau. J’aurai confiance en moi. Il ne faut pas oublier qu’on est ce que l’on mange. C’est-à-dire que les personnes mal dans leur peau auront tendance à s’alimenter et à boire n’importe comment, car elles essayeront de compenser leur mal-être par un élément extérieur et dans ce cas, la nourriture. Sauf que le bien-être ne marche que le temps de manger ladite cochonnerie…</p>\n<p>D’ailleurs, si vous souhaitez mieux vous <strong>alimenter</strong>, vous pouvez aller vous renseigner sur <strong>Rémi MOHA, coach sportif et de nutrition diplômé et auteur du livre intitulé <em>“La synergie alimentaire”.</em></strong> Cette méthode, qui combine différents aliments, vous permettra de pouvoir manger <strong>sainement</strong> et de manière <strong>variée</strong>. Ce qui aura pour conséquence d’augmenter votre capital <strong>santé</strong>, d’améliorer votre <strong>sommeil</strong>, votre <strong>énergie</strong>…et même de vous faire perdre du <strong>poids</strong>. </p>\n<p>Bref, si cela vous intéresse, je vous invite à cliquer sur le bouton ci-dessous afin de pouvoir profiter du programme de Rémi MOHA : </p>\n<h3>L’expérience de la maladie </h3>\n<p>Il s’agit d’une croyance, mais je suis persuadée que <a href=\"/le-mal-a-dit\" target=\"_blank\" rel=\"noopener\" title=\"Le mal a dit\">nous nous provoquons (inconsciemment bien sûr), la plupart de nos maladies</a>. Certaines personnes se trouvent à un stade terminal de cancer, donc, tant que la maladie ne condamne pas, pourquoi vociférer ? À moi d’apprendre le message qu’elle souhaite me faire passer, de me soigner en conséquence et surtout, me dire que la plupart des individus connaîtront au moins un problème, plus ou moins grave, de santé dans leur existence.</p>\n<p> </p>\n<p>Peu importe l’éducation que vous avez eue ou ce qu’il vous est arrivé de fâcheux. Vous n’y pouvez rien maintenant. Pas le choix d’avancer et d’agir, car, autrement, en remettant la faute sur l’extérieur, vous ne pourrez jamais changer et resterez malheureux et dans votre statut de victime toute votre vie.</p>\n<p>Vous pouvez penser que la vie est injuste. Oui, elle l’est souvent. Tout le monde ne semble pas être logé à la même enseigne. Par contre, elle n’est pas injuste qu’avec vous. Elle l’est avec tout le monde, et ce, de temps à autre. Évitez donc de perdre votre temps et votre énergie en prononçant des phrases telles que « je ne supporte pas l’injustice », car malheureusement, elle apparaîtra de temps en temps sur votre chemin. </p>\n<p>Pour<b> reprendre du pouvoir sur sa vie,</b> il convient de passer à l’action afin de rendre son existence meilleure. Il ne tient qu’à vous et vous seul, de prendre vos responsabilités. Personne ne le fera pour vous. Vous pouvez vous faire aider si vous en ressentez le besoin, bien entendu, mais n’attendez pas que la personne aidante effectue tout le travail à votre place. Vous êtes la seule personne qui peut réellement vous guérir. Sortez maintenant de votre statut de victime, prenez-en au moins conscience et prenez vos responsabilités en passant à l’action. C’est la première étape de la guérison. </p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img loading=\"lazy\" decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<p>Si vous aimez mon travail 🙂</p>','published',1,'Reprendre du Pouvoir sur sa Vie : le Meilleur Moyen d’être Heureux','Vous sentez que vous subissez votre existence et en avez assez ? Comment reprendre du pouvoir sur sa vie ? Par la prise de responsabilité.','https://vivre-pleinement.fr/devenir-responsable/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/devenir-responsable\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/devenir-responsable\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Reprendre du Pouvoir sur sa Vie : le Meilleur Moyen d\\u2019\\u00eatre Heureux\",\"datePublished\":\"2019-07-16T19:12:51+00:00\",\"dateModified\":\"2024-02-13T19:34:51+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/devenir-responsable\\/\"},\"wordCount\":4780,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/devenir-responsable\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/07\\/Reprendre-pouvoir-vie.jpg\",\"articleSection\":[\"D\\u00e9veloppement personnel\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/devenir-responsable\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/devenir-responsable\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/devenir-responsable\\/\",\"name\":\"Reprendre du Pouvoir sur sa Vie : le Meilleur Moyen d\\u2019\\u00eatre Heureux\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/devenir-responsable\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/devenir-responsable\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/07\\/Reprendre-pouvoir-vie.jpg\",\"datePublished\":\"2019-07-16T19:12:51+00:00\",\"dateModified\":\"2024-02-13T19:34:51+00:00\",\"description\":\"Vous sentez que vous subissez votre existence et en avez assez\\u2009? Comment reprendre du pouvoir sur sa vie\\u2009? Par la prise de responsabilit\\u00e9.\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/devenir-responsable\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/devenir-responsable\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/devenir-responsable\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/07\\/Reprendre-pouvoir-vie.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/07\\/Reprendre-pouvoir-vie.jpg\",\"width\":700,\"height\":463,\"caption\":\"Comment cesser le role de victime en prenant ses responsabilites ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/devenir-responsable\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Reprendre du Pouvoir sur sa Vie : le Meilleur Moyen d\\u2019\\u00eatre Heureux\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-07-16 19:12:51',NULL,'2026-05-24 19:19:46','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (64,'La Phobie d’Impulsion : une Peur ou une Envie ?','les-phobies-dimpulsion','La phobie d’impulsion fait partie des troubles anxieux. C’est le trouble le plus difficile à soigner. Les personnes atteintes de ce mal-être ont souvent honte d’en parler, ce qui alimente leur angoisse. Il s’agit d’une peur irrationnelle accompagnée d’une hantise du passage à l’acte. La personne pense posséder un fond malsain et tordu. Vous croyez être un meurtrier ou un pédophile caché, ou redoutez d’être dépressif et suicidaire. Vous avez vraiment l’impression que vous allez commettre un drame qui chamboulera toute votre existence. Enfin, vous pensez réellement que votre angoisse est un désir masqué et que vous risquez de perdre le contrôle à tout instant. La phobie d’impulsion, une peur ou une envie ? Comment vous en libérer ?\n','<p>La phobie d’impulsion fait partie des <b>troubles anxieux.</b> C’est le trouble le plus <b>difficile à soigner.</b> Les personnes atteintes de ce mal-être ont souvent <b>honte </b>d’en parler, ce qui alimente leur angoisse. Il s’agit d’une peur <b>irrationnelle </b>accompagnée d’une hantise du <b>passage à l’acte.</b> La personne pense posséder un fond <b>malsain </b>et tordu. Vous croyez être un <b>meurtrier </b>ou un <b>pédophile caché,</b> ou redoutez d’être <b>dépressif </b>et <b>suicidaire</b>. Vous avez vraiment l’impression que vous allez commettre un drame qui chamboulera toute votre existence. Enfin, vous pensez réellement que votre angoisse est un désir masqué et que vous risquez de <b>perdre le contrôle</b> à tout instant. La <b>phobie d’impulsion, une peur ou une envie ?</b> Comment vous en <b>libérer </b>?</p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img fetchpriority=\"high\" decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h2>Les principales formes de la phobie d’impulsion </h2>\n<p>La phobie d’impulsion peut se fixer sur un ou plusieurs thèmes. Une personne peut avoir une peur immense d’être homosexuelle alors que pour une autre, cette angoisse ne lui viendrait même pas à l’esprit. Elle aura par contre une crainte démesurée d’être pédophile. Voici ici les principales formes que ce <a href=\"/angoisse-stress-anxiete\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse stress anxiété \">trouble anxieux</a> peut revêtir. </p>\n<h3>La peur de tuer, de faire du mal à autrui </h3>\n<p>Cette peur peut provenir soudainement, en regardant un couteau par exemple ou en étant en train de partager un repas. Vous pouvez vous demander : « et si je prenais ce couteau et que je tuais la personne avec moi ? »</p>\n<p>De là, grosse panique. Vous considérez en effet que cette idée est anormale, que vous devenez un tueur en série ou que vous avez depuis toujours eu des désirs de meurtre cachés.</p>\n<p>De ce fait, vous éviterez soigneusement tout objet tranchant de peur de perdre le contrôle et de vraiment passer à l’acte. Vous pouvez même éviter l’individu que vous avez peur de tuer. Souvent, il s’agit de proches très chers à votre cœur.</p>\n<p>En plus de ces évitements, vous n’arrêtez pas de <a href=\"/ruminations\" target=\"_blank\" rel=\"noopener\" title=\"Ruminations\">ruminer de manière obsessionnelle</a> sur ces idées, qui, pensez-vous, reflètent un esprit malsain et tordu. </p>\n<p>La personne n’ose bien évidemment pas en parler, de peur d’aller en prison ou de finir dans un hôpital psychiatrique. Le mal-être se trouve absolu, sans compter la culpabilité d’avoir ce genre de pensées s’y ajoutant.</p>\n<p>Une autre variante de cette peur peut être celle d’avoir soudainement des comportements plus qu’inappropriés en public, comme être pris de fou rire lors d’un enterrement, insulter une personne sans raison, perdre le contrôle devant tout le monde. </p>\n<h3>La peur de se suicider </h3>\n<p>Il s’agit du même type d’angoisse que la précédente. Par contre, cette fois, la crainte de la violence est retournée contre soi. </p>\n<p>La personne a peur de désirer mettre fin à ses jours et évitera soigneusement tous les endroits/objets, etc. qui pourraient l’aider à accomplir ce qu’elle pense vouloir. </p>\n<p>De même, bon nombre d’idées obsessionnelles vont se mettre en place. La personne tentera sans cesse de se rassurer sur le fait qu’elle ne souhaite pas passer à l’acte. Le problème, c’est que cette technique ne marche qu’un temps et que le besoin de réassurance réapparaît continuellement.</p>\n<h3>La peur de ne plus aimer </h3>\n<p>Je classe ce <a href=\"/toc-troubles-obsessionnels-compulsifs\" target=\"_blank\" rel=\"noopener\" title=\"Troubles obsessionnels compulsifs\">TOC</a> dans la phobie d’impulsion, car la personne a clairement peur de quitter son conjoint. Il y a donc un acte qu’elle a l’angoisse de poser malgré elle. </p>\n<p>Tout va bien dans le couple, mais la personne va soudainement se retrouver avec une pensée intrusive comme « est-ce que j’aime vraiment mon partenaire ? »</p>\n<p>De là, elle va tout faire pour tester l’amour qu’elle lui porte : l’examiner de A à Z (ex. : est-il assez beau, intelligent, gentil, drôle, etc., par rapport à d’autres ?) et analyser ses sentiments envers lui qui lui sembleront forcément moindres. En effet, l’anxiété sera telle qu’elle étouffera l’émotion d’amour qui est porté à son partenaire. L’amour demeure pourtant bien présent, mais masqué. Ce qui fait d’autant plus penser à l’individu qu’il n’a plus de sentiment. Il ruminera donc sans cesse afin d’essayer de se rassurer sur ses sentiments, mais bien entendu, cette réassurance ne se trouvera que provisoire. </p>\n<p>Certaines personnes quittent même leur conjoint subitement à cause de ce TOC, mais le regrettent très rapidement pour finalement retourner ensuite avec leur bien-aimé. </p>\n<h3>La peur d’être pédophile </h3>\n<p>Cette peur survient souvent lors d’une pensée intrusive en présence d’un enfant. Cet enfant peut être le vôtre, ou non, ou vos petits-enfants, en les prenant sur vos genoux par exemple. Vous pouvez vous dire soudainement « et si j’aimais les enfants ? »</p>\n<p>De là, immense panique, car bien en entendu, la pédophilie est très sévèrement punie et répugne les gens.</p>\n<p> En plus de ces ruminations, la personne peut croire ressentir des sensations en présence d’enfants, comme de l’excitation. Cependant, il n’en est rien : c’est l’angoisse qui crée cette sensation. </p>\n<p>L’individu fera donc tout pour les éviter, se distancier d’eux au maximum et ne cessera de ruminer, pensant que ses pensées sont de la pédophilie cachée.</p>\n<p> </p>\n<h3>La peur d’être homosexuel </h3>\n<p>C’est un peu le même système que pour la peur précédente, mais concernant l’homosexualité. </p>\n<p>Tout survient lors d’une pensée intrusive irrationnelle « et qui me dit que je n’aime pas les personnes du même sexe que moi ? »</p>\n<p>De là, la personne ne cessera d’essayer de se rassurer auprès des autres ou sur ses propres pensées. Les ruminations mentales sont lancées. </p>\n<p>Elle peut même se mettre à regarder des films pornographiques homosexuels, afin de se tester et de voir s’ils peuvent effectivement lui faire de l’effet.</p>\n<p>Une autre variante de cette peur peut être la celle de vouloir changer de sexe, de devenir transexuel.</p>\n<img decoding=\"async\" width=\"561\" height=\"720\" src=\"/storage/blog-images/Terreur-perte-controle.png\" alt=\"Ruminations\" title=\"Terreur-perte-contrôle\">\n<h2>Phobie d’impulsion, peur ou envie : avis de la psychanalyse </h2>\n<p>La psychanalyse n’est pas vraiment armée pour traiter la phobie d’impulsion. Certains prétendent que les phobies d’impulsion proviennent d’un conflit intérieur entre avoir envie de passer à l’acte et ne pas le faire par crainte de représailles. </p>\n<h3>Phobie d’impulsion : la fausse théorie du désir caché  </h3>\n<p>Entendre ou lire ce genre de propos peut être dramatique pour certaines personnes. Je pense qu’il faut développer cette idée afin de bien comprendre ce qu’elle veut réellement faire passer comme message. </p>\n<p>Admettons que vous ayez la phobie de tuer votre mère, qui est une personne très chère à vos yeux. Pensez-vous vraiment que vous en avez le désir, mais que vous vous retenez de le faire ?</p>\n<p>Quand vous avez la volonté d’entreprendre une action, vous ressentez ce désir et surtout, vous n’en avez pas peur. Par exemple, vous avez envie d’une crème glacée, vous la visualisez, jubilez d’avance et planifiez les actions que vous allez entreprendre afin de pouvoir réaliser votre souhait. Prendre la voiture, vous garer au centre-ville, aller chez le marchand de glace. Le tout, sans aucune anxiété… vous voyez où je veux en venir ?</p>\n<p> Un tueur programmant un meurtre n’angoisse pas. Il réagira un peu comme pour le cas de la glace, c’est-à-dire en jubilant par avance et en planifiant l’acte qu’il souhaite accomplir sans scrupule.</p>\n<p>En gros, avoir peur ne veut pas dire qu’il y a un désir caché derrière ! Par exemple, une personne ayant la phobie des araignées les aime-t-elle au fond ? Un individu ayant la hantise de se faire cambrioler a-t-il vraiment le fantasme d’être cambriolé ? Non, pas vrai ?</p>\n<p>En vous tenant près du vide, quelquefois, vous vous sentez attiré par lui. Ce n’est pas pour autant que vous avez envie de sauter ! </p>\n<h3>Phobie d’impulsion : le signe d’une colère refoulée </h3>\n<p>La phobie d’impulsion ne cache donc pas une folie cachée. Par contre, il peut y avoir une <a href=\"/colere\" target=\"_blank\" rel=\"noopener\" title=\"Colère\">colère</a> refoulée en vous, non résolue, s’exprimant par cette peur particulière, de tuer votre mère par exemple. Pourtant, cette angoisse n’a absolument rien à voir avec l’objet de la colère réprimée. Vous voyez ce que je veux dire ? À vous de trouver de quoi il en retourne en réalisant un grand travail intérieur sur vous. </p>\n<p>De plus, je pense que nous avons tous déjà eu des pensées violentes, peut-être même de meurtre ! C’est humain. Par exemple, si l’on nous manque de respect sur la route, nous passe devant dans une file d’attente… Et là, éprouvez-vous l’angoisse de passer à l’acte ? Non, car vous en avez vraiment envie, ne serait-ce qu’un court instant, mais vous n’allez pas le faire pour autant. Donc si vous ne passez pas à l’acte même, en en ressentant brièvement le désir, pourquoi passeriez-vous à l’acte en en ayant peur et surtout, sans le vouloir ? </p>\n<p>Après, effectivement, vous pouvez tout de même ressentir de l’appréhension en ayant concomitamment la volonté de réaliser une action, mais c’est différent. Par exemple, une personne devant tenir un discours devant une foule pourra avoir la tentation de le faire, au fond, mais en ressentira un trac intense. Ce genre de cas est plutôt considéré comme du stress positif. L’individu ne ressent pas d’angoisse extrême et négative comme dans le cas de la phobie d’impulsion. </p>\n<h2>Phobie d’impulsion, peur ou envie : avis des TCC</h2>\n<p>Les TCC sont mieux adaptées aux phobies d’impulsion, car elles aident à rationaliser les pensées que vous pouvez avoir et à passer l’action afin de modifier lesdites pensées.</p>\n<p>Pour la thérapie comportementale et cognitive, absolument tout le monde a des pensées intrusives de temps en temps, comme : « tiens et si je plantais le couteau posé sur la table dans le torse de mon voisin ? » Mais en général, les personnes s’étonnent de leur pensée étrange un court instant et passent à autre chose.</p>\n<p>Par contre, les personnes anxieuses vont directement s’agripper à cette pensée, en se disant : « comment je peux avoir ce genre de pensées ? C’est que je ne suis pas normale, je suis une tueuse, au fond, etc. » et c’est parti pour le commencement de ruminations incessantes. Voilà ce qui déclenche la phobie d’impulsion par rapport aux individus non anxieux. Le fait de ne pas laisser passer sa pensée, de s’y accrocher et de ruminer encore et encore dessus en cherchant sa signification, alors qu’il n’y en a tout simplement pas. Il s’agit juste d’une pensée. D’une surestimation de l’importance accordée à ses propres pensées. Une trop grande angoisse, en somme.</p>\n<img decoding=\"async\" width=\"960\" height=\"678\" src=\"/storage/blog-images/Pensees-intrusives.png\" alt=\"Pensees obsessionnelles \" title=\"Pensées-intrusives\">\n<h2>Les solutions pour guérir de la phobie d’impulsion </h2>\n<p>Les TCC sont conseillées pour traiter ce trouble. Elles peuvent être accompagnées d’un traitement médicamenteux si la personne n’arrive vraiment plus à vivre normalement. </p>\n<p>Vu que les phobies d’impulsion proviennent juste de pensées, l’exercice principal consistera à ne pas vous accrocher à cette pensée. À arrêter la mauvaise habitude de vouloir automatiquement l’analyser en la laissant simplement passer. Comme lorsque vous regardez un paysage défiler assis dans un train. Si vous maîtrisez cet exercice, vous pouvez être certain que la phobie d’impulsion n’arrivera pas. </p>\n<p>Cependant, si vous avez ce système de pensées depuis longtemps, il va probablement vous falloir du temps afin que cette technique fasse effet. Vous devrez donc vous entraîner audit exercice encore et encore, et ce, de manière régulière.</p>\n<p>Si la phobie d’impulsion s’accompagne de compulsions, comme, par exemple, éviter la cuisine de peur d’y trouver un couteau, l’objectif va être de travailler sur ces rituels. Retourner progressivement dans la cuisine jusqu’à pouvoir à nouveau toucher un couteau puis cuisiner avec sans crainte.</p>\n<p>Il existe également un gros manque d’estime de soi dans ce trouble. En effet, les personnes atteintes de cette affection. semblent croire que leurs pensées reflètent un côté très sombre et caché chez elles. Si elles avaient confiance en elles, elles auraient conscience de leur valeur et du fait qu’elles ne souhaitent pas passer à l’acte.</p>\n<p>Cette phobie apparaît chez une personnalité très anxieuse. Il est donc bon de se lancer dans la pratique d’exercices de relaxation, méditation…</p>\n<p>En complément, vous pouvez également vous faire aider, par des thérapies alternatives, comme l’hypnose, l’EMDR, les soins énergétiques, etc. à vous de trouver ce qui vous correspond le mieux.</p>\n<p>La <b>phobie d’impulsion, une peur ou une envie ? </b>Je pense qu’à la lecture de cet article, vous détenez la réponse à cette question. La phobie d’impulsion, comme son nom l’indique, n’est qu’une phobie et certainement pas un désir. Vous pouvez donc vous être rassuré à ce sujet et surtout, vous entraîner à laisser passer ces pensées, surtout dues à votre tempérament anxieux. Souvenez-vous : vous êtes normal. </p>\n<p>Sachez que j’ai rédigé un livre numérique à ce sujet, s’intitulant « Soigner le TOC de la phobie d’impulsion à l’aide de traitements naturels : 12 fiches pratiques pour vous accompagner  ». Si vous souhaitez en savoir plus ou vous procurer mon livre, c’est juste ici : </p>\n<p><a href=\"https://amzn.to/42cWUwH\">Visitez Amazon pour vous procurer le livre</a> de Edith Rosset « Mieux vivre avec une phobie d’impulsion grâce aux thérapies brèves ».</p>\n<p>(Lien rémunéré par Amazon)</p>\n<a href=\"https://hypnocaments.com?partnerid=YK5muYugzSoIWDbDWRgT-Q\" title=\"Seances d hypnose en ligne\"><img decoding=\"async\" src=\"https://hypnocaments.com/image/banner_1_750.png\" alt=\"seance hypnose mp3\"></a>\n<p>(Si vous aimez mon travail) 🙂</p>','published',1,'La Phobie d’Impulsion : une Peur ou une Envie ?','Vous pensez que votre angoisse est un désir masqué et que vous risquez de perdre le contrôle à tout instant. La phobie d’impulsion, une peur ou une envie ?','https://vivre-pleinement.fr/les-phobies-dimpulsion/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/les-phobies-dimpulsion\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/les-phobies-dimpulsion\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"La Phobie d\\u2019Impulsion : une Peur ou une Envie\\u2009?\",\"datePublished\":\"2019-07-13T19:36:48+00:00\",\"dateModified\":\"2024-02-13T19:36:07+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/les-phobies-dimpulsion\\/\"},\"wordCount\":4007,\"commentCount\":43,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/les-phobies-dimpulsion\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/07\\/phobie-impulsion-peur-envie.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/les-phobies-dimpulsion\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/les-phobies-dimpulsion\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/les-phobies-dimpulsion\\/\",\"name\":\"La Phobie d\\u2019Impulsion : une Peur ou une Envie\\u2009?\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/les-phobies-dimpulsion\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/les-phobies-dimpulsion\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/07\\/phobie-impulsion-peur-envie.jpg\",\"datePublished\":\"2019-07-13T19:36:48+00:00\",\"dateModified\":\"2024-02-13T19:36:07+00:00\",\"description\":\"Vous pensez que votre angoisse est un d\\u00e9sir masqu\\u00e9 et que vous risquez de perdre le contr\\u00f4le \\u00e0 tout instant. La phobie d\\u2019impulsion, une peur ou une envie\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/les-phobies-dimpulsion\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/les-phobies-dimpulsion\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/les-phobies-dimpulsion\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/07\\/phobie-impulsion-peur-envie.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/07\\/phobie-impulsion-peur-envie.jpg\",\"width\":700,\"height\":467,\"caption\":\"La phobie d\\u2019impulsion est-elle une peur ou une envie ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/les-phobies-dimpulsion\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"La Phobie d\\u2019Impulsion : une Peur ou une Envie\\u2009?\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-07-13 19:36:48',NULL,'2026-05-24 19:19:46','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (65,'Quelle est la Différence entre un Anxiolytique et un Antidépresseur ?','antidepresseurs-et-anxiolytiques','Les troubles anxieux ne sont pas que « dans la tête ». Ils sont considérés comme une maladie quand ils deviennent trop handicapants. Comme pour toute maladie, le médecin ou un psychiatre peut prescrire deux sortes de médicaments pour réduire l’anxiété : l’anxiolytique et l’antidépresseur. Vos troubles anxieux vous empêchent réellement de vivre une vie normale. Vous souhaitez prendre un traitement temporaire pour vous soulager, mais vous ne savez pas quel médicament choisir ? Quelle est la différence entre un anxiolytique et un antidépresseur ?  \n','<p>Les <b>troubles anxieux </b>ne sont pas que <b>« </b><b>dans la tête </b><b>»</b><b>.</b> Ils sont considérés comme une <b>maladie </b>quand ils deviennent trop <b>handicapants</b>. Comme pour toute maladie, le <b>médecin </b>ou un <b>psychiatre </b>peut prescrire deux sortes de médicaments pour réduire l’anxiété : l’anxiolytique et l’antidépresseur. Vos troubles anxieux vous empêchent réellement de vivre une vie <b>normale</b>. Vous souhaitez prendre un traitement temporaire pour vous soulager, mais vous ne savez pas quel médicament choisir ? <b>Quelle est la différence entre un anxiolytique et un antidépresseur ?  </b></p>\n<h2>Informations sur les anxiolytiques </h2>\n<p>Les anxiolytiques, nommés également benzodiazépines, sont conseillés pour ceux en proie à des<a href=\"/angoisse-stress-anxiete\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse stress anxiété \"> troubles anxieux</a> chroniques handicapants. Si les individus n’arrivent plus à vivre « normalement » à cause de leur anxiété, ils peuvent se tourner vers cette solution. Ils agissent comme des tranquillisants et peuvent aider en cas de crise de panique.</p>\n<h3>Inconvénients des anxiolytiques </h3>\n<p>Comme pour chaque médicament, les anxiolytiques peuvent déclencher des effets secondaires : somnolence (il est en effet déconseillé de prendre le volant), problèmes de concentration, vertiges, maux de tête, troubles de la libido, constipation, diarrhée, nausées, crampes, tremblements, etc. </p>\n<p>Le problème également, c’est que ces médicaments rendent souvent dépendant. Du coup, quand une personne souhaite arrêter le traitement, il peut y avoir des effets secondaires dus au sevrage très fort et elle peut se sentir encore plus anxieuse qu’avant.</p>\n<h3>Mon avis sur les anxiolytiques </h3>\n<p>Pour ma part, je ne pense pas que ce médicament guérisse quoi que ce soit. En effet, il s’agit juste d’un tranquillisant que vous pouvez prendre si vraiment une crise d’angoisse aiguë arrive. Cependant, vous n’avez pas besoin d’un traitement pour soulager une attaque de panique. Vous pouvez pratiquer des techniques de respiration, qui font l’objet d’un <a href=\"/respiration\" target=\"_blank\" rel=\"noopener\" title=\"Respiration \">article</a> de ce blog. </p>\n<p>De plus, je connais des personnes pour qui la prise de ces comprimés peut provoquer l’effet inverse : au lieu de les calmer, ils angoissent terriblement, car elles se sentent complètement déconnectées de la réalité quand elles en prennent un.</p>\n<p>Ces médicaments ont également pas mal d’effets indésirables, dont notamment la somnolence. Prendre le volant sera alors à éviter et vous pouvez vous sentir très mou pour réaliser vos activités quotidiennes. </p>\n<p>Essayez aussi de ne pas en faire une habitude. En effet, l’accoutumance à ce genre de médicaments arrive vite et il ne faudrait pas que votre corps en réclame à chaque coucher.</p>\n<p>Ce n’est donc pas ce médicament qui vous guérira. Vous pouvez être sûrs que quand ses effets positifs se seront dissipés, vos troubles reviendront, car, comme d’habitude, il n’y aura que la forme de soignée et non le fond.</p>\n<p>En fait, les anxiolytiques peuvent être comparés à de l’alcool : vous êtes stressé, vous buvez un coup, vous voyez les choses sans stress, de manière positive, vous apparaissez joyeux et le lendemain, vous avez de nouveau votre personnalité anxieuse. Eh, oui, l’alcool ne soigne pas non plus sur le long terme… C’est un peu comme une fuite.</p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"720\" height=\"720\" src=\"/storage/blog-images/Traitement.jpg\" alt=\"Medicament \" title=\"Traitement\">\n<h2>Informations sur les antidépresseurs </h2>\n<p>Non, les antidépresseurs ne sont pas destinés qu’aux dépressions, contrairement à ce que l’on peut penser. Ils peuvent se trouver très utiles dans le cadre de troubles anxieux invalidants. IIs sont très souvent prescrits pour les TOC. En effet, la personne n’a quelquefois pas la force de réaliser l’exercice. Ce médicament lui servira donc de béquille afin de lui permettre d’avoir le courage de le réaliser.</p>\n<h3>Inconvénients des antidépresseurs  <b> </b></h3>\n<p>Comme tout médicament de ce genre, les antidépresseurs peuvent déclencher bon nombre d’effets secondaires, notamment en début de traitement et à son arrêt ou à sa diminution : sécheresse de la bouche, difficultés sexuelles, prise ou perte de poids, baisse de tension, anxiété accrue, constipation, somnolence ou au contraire, excitation, etc. De plus, attention également quand vous prenez le volant ! </p>\n<p>Quand les manifestations anxieuses apparaissent trop importantes, des anxiolytiques sont souvent prescrits en complément des antidépresseurs en attendant que les symptômes se stabilisent. </p>\n<p>En gros, les symptômes du début peuvent rendre l’individu encore plus mal qu’il ne l’était. D’autre part, il est compliqué de savoir à l’avance quel médicament sera adapté pour telle personne. Il faut donc tester, ou diminuer la dose, attendre un peu pour voir si l’état se stabilise. Sinon, si les symptômes sont trop importants, diminuer la dose ou changer de traitement et ainsi de suite, jusqu’à trouver celui qui convient.</p>\n<p>Enfin, comme dit précédemment, le sevrage peut apparaître très difficile et certaines personnes gardent le traitement à vie, car n’arrivent plus à vivre sans. </p>\n<h3>Mon avis sur les antidépresseurs </h3>\n<p>Avant toute prise de traitement, il faut bien réfléchir. Je pense qu’il convient d’y songer en dernier recours, si la personne ne parvient plus à agir, n’a plus du tout de volonté (dépression) ou que ses <a href=\"/toc-troubles-obsessionnels-compulsifs\" target=\"_blank\" rel=\"noopener\" title=\"Troubles obsessionnels compulsifs \">troubles obsessionnels compulsifs</a> sont si invalidants qu’elle n’arrive même plus à sortir de chez elle. Dans ces cas, bien évidemment qu’il est préférable d’en prendre plutôt que de rester inactif et plein de désespoir. </p>\n<p>Par contre, il est préférable d’aller voir un psychiatre plutôt qu’un médecin généraliste pour vous les faire prescrire. Pour le psychiatre, c’est son métier, il connaît ces médicaments par cœur et a plus de chances de trouver celui qui vous conviendra le mieux directement. Surtout, le suivi reste très régulier et dès que vous n’allez pas bien, il pourra modifier le traitement. </p>\n<p>Le médecin généraliste peut vous en prescrire, bien sûr, mais la surveillance ne demeurera pas la même. En effet, la personne peut se retrouver du jour au lendemain sans antidépresseur après 3 mois de traitement, vu elle pensera aller mieux et n’ira plus voir son docteur, ce qui est bien évidemment très dangereux. Un arrêt brutal est vivement déconseillé lors de la prise d’antidépresseur, car les symptômes de sevrage peuvent vraiment être très difficiles à supporter.</p>\n<p>De plus, je ne suis pas sûre qu’en prendre fasse que l’individu règle ses soucis. Il n’y a qu’à aller faire un tour sur des forums de santé pour y remarquer des personnes en proie à la dépression ou à des angoisses terribles, prenant déjà des antidépresseurs. </p>\n<h2>Informations sur les somnifères, différents d’un anxiolytique et d’un antidépresseur </h2>\n<p>Si vous vivez vraiment une période stressante et que vous souffrez <a href=\"/insomnie\" target=\"_blank\" rel=\"noopener\" title=\"Insomnie \">d’insomnie</a>, pourquoi ne pas en prendre ? Le sommeil reste en effet très important.</p>\n<p>Par contre, idem que pour les anxiolytiques et les antidépresseurs, cette prise ne doit demeurer que temporairement. Sinon, l’accoutumance sera de mise et la personne se pensera incapable de s’endormir sans médicament.</p>\n<h2>Préjugés sur la prise d’anxiolytique et d’antidépresseur</h2>\n<p>Il y a toujours dans l’entourage un super-héros tenant ce style de propos : « les antidépresseurs/anxiolytiques ? C’est pour les faibles ! Moi je suis fort, je ne prendrai jamais une pilule ! »</p>\n<p>Mais s’il venait à perdre tout ce qui compte pour lui sur cette terre, j’éprouve un gros doute sur sa capacité à tout gérer sans médicaments. Pour moi, il s’agit de fierté mal placée, vous ne devez pas écouter ce genre de discours culpabilisant. </p>\n<p>Il convient en effet différencier la fragilité et la faiblesse : l’éducation, l’environnement, un traumatisme, etc. peuvent rendre une personne fragile, c’est vrai. Il faut apprendre à accepter cette différence. </p>\n<p>Cependant, les personnes fragiles qui vont de l’avant constamment en dépit de leur grande souffrance apparaissent beaucoup plus fortes pour moi que les individus sans aucun problème psychologique. Elles prouvent que malgré leurs fragilités, elles sont vaillantes, braves et courageuses, bien plus que bon nombre de personnes !</p>\n<p>Une personne faible, quant à elle, peut être fragile, ou non d’ailleurs ! Mais elle n’ose rien entreprendre, ne passe pas à l’action, reste dans ses habitudes, souhaite se fondre dans la masse pour être comme les autres… ne se permet pas d’exprimer sa véritable personnalité, ses vrais besoins, de peur d’être rejetée… Vous voyez la différence entre la faiblesse et la fragilité ?</p>\n<img decoding=\"async\" width=\"550\" height=\"367\" src=\"/storage/blog-images/Benzodiazepine.jpg\" alt=\"Bequille\" title=\"Benzodiazépine\">\n<p>Ce que je veux dire, c’est qu’il ne faut absolument pas vous culpabiliser de prendre des médicaments si vous en ressentez la nécessité. Prendre un traitement ne fait pas de vous une personne faible ! Les personnes prétendument solides se réfugient souvent dans l’alcool, pourquoi d’après vous ? Pourquoi ne peuvent-elles pas s’empêcher de boire leur verre journalier, ou leur apéritif le week-end ? Pourquoi en ont-elles besoin pour se détendre si elles sont si fortes qu’elles le prétendent ? Croyez-vous qu’elles soient juste accros au goût de l’alcool ? Méfiez-vous des apparences. La vraie personne forte n’a pas besoin de le prouver aux autres déjà. Il ne faut pas oublier que la boisson représente aussi une drogue légale, comme les médicaments.</p>\n<p>C’est comme si vous diriez à une personne diabétique : « la honte, tu dois prendre de l’insuline, ton pancréas n’est même pas capable d’accomplir le travail, tu es très faible ». Cette phrase n’a pas de sens, pas vrai ?</p>\n<p>\n</p>\n<p>J’espère que vous avez pu comprendre <b>quelle est la différence entre un anxiolytique et un antidépresseur. </b>Retenez bien que ces médicaments ont des avantages comme des inconvénients et que surtout, en prendre ne signifie aucunement que vous êtes quelqu’un faible. Si vous sentez vraiment que vous n’arrivez plus à fonctionner normalement, mieux vaut en prendre sur une durée limitée. Vous arriverez ainsi à reprendre du poil de la bête et pourrez continuer ensuite à emprunter le chemin du développement personnel en toute sérénité.</p>\n<p> </p>\n<p>(Si vous souhaitez soutenir mon travail 🙂)</p>\n<a href=\"https://hypnocaments.com?partnerid=YK5muYugzSoIWDbDWRgT-Q\" title=\"Seances d hypnose en ligne\"><img decoding=\"async\" src=\"https://hypnocaments.com/image/banner_1_750.png\" alt=\"seance hypnose mp3\"></a>','published',1,'Quelle est la Différence entre un Anxiolytique et un Antidépresseur ?','Vous souhaitez prendre un traitement temporaire pour soulager vos troubles anxieux. Quelle est la différence entre un anxiolytique et un antidépresseur ?','https://vivre-pleinement.fr/antidepresseurs-et-anxiolytiques/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/antidepresseurs-et-anxiolytiques\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/antidepresseurs-et-anxiolytiques\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Quelle est la Diff\\u00e9rence entre un Anxiolytique et un Antid\\u00e9presseur\\u2009?\",\"datePublished\":\"2019-06-30T13:23:40+00:00\",\"dateModified\":\"2024-02-13T19:37:32+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/antidepresseurs-et-anxiolytiques\\/\"},\"wordCount\":3056,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/antidepresseurs-et-anxiolytiques\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/06\\/Difference-anxiolytique-antidepresseur-1.jpg\",\"articleSection\":[\"D\\u00e9veloppement personnel\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/antidepresseurs-et-anxiolytiques\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/antidepresseurs-et-anxiolytiques\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/antidepresseurs-et-anxiolytiques\\/\",\"name\":\"Quelle est la Diff\\u00e9rence entre un Anxiolytique et un Antid\\u00e9presseur\\u2009?\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/antidepresseurs-et-anxiolytiques\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/antidepresseurs-et-anxiolytiques\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/06\\/Difference-anxiolytique-antidepresseur-1.jpg\",\"datePublished\":\"2019-06-30T13:23:40+00:00\",\"dateModified\":\"2024-02-13T19:37:32+00:00\",\"description\":\"Vous souhaitez prendre un traitement temporaire pour soulager vos troubles anxieux. Quelle est la diff\\u00e9rence entre un anxiolytique et un antid\\u00e9presseur\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/antidepresseurs-et-anxiolytiques\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/antidepresseurs-et-anxiolytiques\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/antidepresseurs-et-anxiolytiques\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/06\\/Difference-anxiolytique-antidepresseur-1.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/06\\/Difference-anxiolytique-antidepresseur-1.jpg\",\"width\":800,\"height\":468,\"caption\":\"Comment differencier l\\u2019anxiolyique de l\\u2019antidepresseur ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/antidepresseurs-et-anxiolytiques\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Quelle est la Diff\\u00e9rence entre un Anxiolytique et un Antid\\u00e9presseur\\u2009?\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-06-30 13:23:40',NULL,'2026-05-24 19:19:46','2026-06-19 22:28:14');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (66,'TOC et Pensées Intrusives : les Comprendre et s’en Libérer','toc-troubles-obsessionnels-compulsifs','Quand vous souffrez de troubles anxieux, vous pouvez souffrir de TOC, qui est un état mental particulièrement invalidant. La personne en proie aux TOC peut avoir des comportements répétitifs et/ou des actes mentaux qu’elle n’arrive pas à chasser, ce qui lui provoque une immense culpabilité. La majorité de la population touchée n’ose pas en parler, ressentant une grande honte. Les TOC non traités peuvent baisser considérablement la confiance et l’estime qu’une personne a d’elle-même et la mener à la dépression. Vous avez des TOC et pensées intrusives et ces troubles impactent fortement votre vie ? Et si vous lisiez cet article jusqu’au bout pour comprendre ce trouble anxieux et pour vous en libérer ? \n','<p>Quand vous souffrez de <b>troubles anxieux,</b> vous pouvez souffrir de TOC, qui est un état mental particulièrement <b>invalidant</b>. La personne en proie aux TOC peut avoir des <b>comportements répétitifs</b> et/ou des<b> actes mentaux</b> qu’elle n’arrive pas à <b>chasser</b>, ce qui lui provoque une immense <b>culpabilité</b>. La majorité de la population touchée n’ose pas en parler, ressentant une grande <b>honte</b>. Les TOC non traités peuvent baisser considérablement la <b>confiance et l’estime </b>qu’une personne a d’elle-même et la mener à la <b>dépression</b>. Vous avez des <b>TOC et pensées intrusives</b> et ces troubles impactent fortement votre vie ? Et si vous lisiez cet article jusqu’au bout pour comprendre ce trouble anxieux et pour vous en <b>libérer </b>? </p>\n<h2>Définition générale des TOC et des pensées intrusives </h2>\n<p>Le TOC est une pathologie psychiatrique pouvant survenir dès l’enfance, prenant souvent de l’ampleur à l’adolescence. Il s’agit d’abord de pensées obsessionnelles dont la personne n’arrive pas à se défaire. <a href=\"/angoisse-stress-anxiete\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse stress anxiete\">L’angoisse</a> va augmenter. Ces idées fixes peuvent faire souffrir la personne au point où celle-ci pense avoir atteint ses limites. Elle peut commencer à pratiquer des compulsions. Ces compulsions sont des rituels pour soulager les obsessions et donc, l’anxiété devenue insoutenable.</p>\n<p>Le problème dans cette affection, c’est que les individus gâchent leur vie et leur temps. En effet, leurs pratiques peuvent durer plusieurs heures dans la journée. Les individus sont conscients de leur trouble, mais ne peuvent s’empêcher d’exécuter leurs gestes pour se rassurer. Il est donc inutile de les culpabiliser. C’est plus fort qu’eux.</p>\n<h2>Les causes principales d’apparition des TOC et des pensées obsessionnelles </h2>\n<p>En réalité, même le domaine médical a du mal à trancher à ce sujet. Les causes peuvent être génétiques, environnementales, neuropsychologiques (hyperfonctionnement d’une zone précise du cerveau, manque de neurotransmetteur dont notamment la sérotonine)… On ne peut donc être vraiment sûrs de ce qui provoque cette pathologie. Je pense qu’il s’agit surtout d’un ensemble et qu’il faut d’ores et déjà posséder un terrain anxieux. Ensuite, par rapport aux expériences de vie et à l’environnement d’un individu, il pourra ou non développer un TOC. C’est surtout une certaine personnalité qui se forge et qui, à force, fera apparaître ce problème. </p>\n<h2>Trait de caractère spécifique aux personnes souffrant de TOC </h2>\n<p>Il semble que les personnes souffrant de TOC soient des <a href=\"/perfectionnisme\" target=\"_blank\" rel=\"noopener\" title=\"Perfectionnisme\">hyper perfectionnistes</a> souhaitant avoir constamment la maîtrise de leur vie. Or, étant donné que l’incertitude fait partie de l’existence, il est donc impossible de tout savoir à l’avance. Les imprévus arriveront certainement de temps à autre. C’est justement là le problème. Le TOC représente la maladie du doute. Quand une pensée les effraie, elles utilisent les rituels, qui sont une espèce de contrôle magique leur faisant croire que tout ira bien…</p>\n<p>Il y a en effet dans le TOC une sorte de pensée magique de l’enfant. (Ex. : si je réussis à rattraper mon bus, ma journée à l’école se passera bien.) Sauf qu’en général, les adultes mettent un peu de côté ce raisonnement. Cependant, certaines personnes l’ont pris comme stratégie principale. Ce moyen a dû être, à un moment crucial de leur vie, le seul ayant réussi à les apaiser. </p>\n<p>Le problème, c’est qu’au lieu d’apaiser la personne (enfin, cette solution l’apaise, mais temporairement), le TOC reprendra de plus belle et s’amplifiera même. L’individu voudra de plus en plus se sentir rassasié.</p>\n<p> </p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img fetchpriority=\"high\" decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h2>Les principales formes du TOC</h2>\n<p>Bien qu’il existe autant de types de TOC que de personnes différentes sur cette planète, les TOC se regroupent tout de même dans des thèmes spécifiques. Voici une liste non exhaustive des TOC dont vous pouvez souffrir.</p>\n<h3>L’obsession de contamination</h3>\n<p>Dans ce trouble, il ne s’agit pas que d’une personne maniaque. Non. Cela peut aller bien plus loin. La personne pourra se laver plusieurs fois par jour, et ce, pendant des heures, pensant qu’elle est contaminée ou sale. Les microbes déclenchent une panique démesurée chez elle. Elle pourra nettoyer 20 fois sa maison s’il le faut et ce rituel peut devenir un véritable supplice pour les proches. Il s’agira donc plus d’une obsession d’hygiène.</p>\n<p>Il existe également une autre peur de la contamination, mais d’un point de vue plus « psychologique ». Si un individu est pessimiste ou atteint d’une maladie, la personne va éviter de la fréquenter de trop près au risque « d’attraper » son pessimisme ou sa maladie. Il possède donc un caractère superstitieux.</p>\n<img decoding=\"async\" width=\"594\" height=\"640\" src=\"/storage/blog-images/Trouble-obsessionnel-compulsif.jpg\" alt=\"Nevrose \" title=\"Trouble-obsessionnel-compulsif\">\n<h3>L’obsession du doute et de l’erreur </h3>\n<p>Dans ce cas-là, la personne, en partant au travail par exemple, va arriver 1 heure en retard, car elle va vérifier 100 fois que sa porte d’entrée est bien fermée, ou que le gaz n’est pas ouvert. Elle va également allumer/éteindre la lumière un nombre impressionnant de fois pour être sûre que tout est ok.  </p>\n<p>Les causes de ces compulsions peuvent être la peur d’un cambrioleur, que la maison prenne feu, que la facture d’électricité apparaisse exorbitante, etc.</p>\n<p>En réalité, ces personnes craignent l’erreur en particulier. Une secrétaire, par exemple, pourra ouvrir à nouveau une enveloppe qu’elle avait fermée pour bien vérifier qu’il n’y ait pas de fautes dans son courrier. Elle relira 20 fois le même mot pour s’assurer qu’il s’agit bien de ce mot qui est écrit.</p>\n<p>Par contre, ces rituels ne veulent pas dire que la personne est bête ou n’a pas de mémoire. Elle SAIT pertinemment avoir bien fait les choses, mais doute d’elle-même surtout, n’a pas confiance en elle et a une peur insoutenable de l’erreur, qu’elle ne tolère pas.</p>\n<h3>L’obsession de malheur et de superstition </h3>\n<p>Dans ce TOC, l’individu a une crainte excessive qu’un drame se produise, pour lui ou ses proches. Il n’arrivera pas à se rassurer, vu que l’avenir reste incertain. Pour soulager son angoisse, il va mettre en place des rituels, comme toucher un objet un certain nombre de fois, compter mentalement, etc. </p>\n<p>Vu qu’il demeure assez superstitieux, il n’aimera pas certains chiffres, certaines couleurs et devra ainsi « conjurer le sort » avec des compulsions.  </p>\n<p>Il croit alors que penser à quelque chose de catastrophique peut faire survenir cette catastrophe et pour empêcher ce prétendu désastre, il imaginera une pratique capable de « l’écarter ». </p>\n<p>La personne pense donc qu’une responsabilité énorme pèse sur ses épaules, alors qu’il n’en est rien. Elle ne supporte surtout pas l’inconnu et ne peut tolérer le 1 % qui ferait qu’un drame puisse arriver. Elle a surtout peur, en réalité, de la mort ou d’une tragédie imminente.</p>\n<h3>L’obsession de symétrie </h3>\n<p>Ce TOC peut s’apparenter quelque peu au TOC superstitieux, dans la mesure où l’individu peut se dire « si je ne dispose pas cet objet parfaitement, je risque d’avoir un accident grave ». De même, l’individu peut ne jamais bouger un objet de peur que son geste porte malheur.</p>\n<p>Cependant, dans l’ensemble, ce sont des personnes obsédées à l’idée que tout doit être rangé correctement et surtout, de manière symétrique. Elles peuvent passer des heures à mettre en place les objets. Il s’agit surtout de personnes hyper perfectionnistes. </p>\n<h3>L’obsession d’accumulation</h3>\n<p>Je classe cette incommodité dans les TOC, mais sachez depuis peu que cette pathologie demeure maintenant distincte du TOC. On la nomme la<b> « </b>syllogomanie ». </p>\n<p>La personne atteinte de ce trouble ne peut pas se séparer d’un objet, autrement, elle ressent une trop grande angoisse. Alors, elle le garde. C’est ainsi qu’elle peut se retrouver avec 70 parapluies chez elle par exemple, car « on ne sait jamais, ils peuvent servir…»</p>\n<p>Je connais en effet quelqu’un se trouvant incapable de jeter les prospectus qu’il avait retrouvés dans sa boîte aux lettres depuis des années. Des cartons remplis de publicités diverses envahissent donc son appartement. Les invités ont de quoi être surpris…</p>\n<h3>Les obsessions agressives </h3>\n<p>Ce TOC reste de loin le plus difficile à guérir. Il s’agit surtout d’obsessions. La personne a des pensées totalement contraires à sa vraie nature, son sens moral. Par exemple : angoisse de se suicider, d’assassiner quelqu’un, de laisser échapper des insultes dans un moment très inapproprié, d’avoir un fou rire pendant un enterrement, d’être pédophile, etc. </p>\n<p>C’est le plus difficile à traiter, car le plus délicat à assumer. Dire à un individu lambda que l’on a peur de « tuer quelqu’un » est sans nul doute assez compliqué à expliquer.  </p>\n<p>Concernant cette peur, elle a maintenant un nom à part entière. Il s’agit de la phobie d’impulsion. </p>\n<p>Sachez cependant que le passage à l’acte est considéré comme nul. En effet, une personne souhaitant anéantir quelqu’un n’éprouvera aucun état d’âme, un suicidaire serait au contraire soulagé d’en finir, etc. </p>\n<p>Il y a donc dans ce trouble un cruel manque de confiance en soi et tout ce qui se dit dans les médias n’arrange rien. « Si telle personne a commis une chose atroce, qu’est-ce qui l’a fait basculer ? En serais-je également capable aussi ? »</p>\n<p>Mais s’il vous plaît, cessez de regarder les informations si vous êtes trop anxieux, car elles  ne font qu’intensifier votre anxiété. Le plus grand problème des actualités, c’est qu’elles ne contiennent que celles traitant du malheur dans le monde et oublient totalement ce qu’il s’y passe de génial. Comment voulez-vous donc penser plus positivement ou du moins, de manière plus neutre, si vous vous trouvez acculé de nouvelles malheureuses à chaque instant ? </p>\n<img decoding=\"async\" width=\"800\" height=\"420\" src=\"/storage/blog-images/Obsessions.jpg\" alt=\"Compulsions\" title=\"Obsessions\">\n<h2>Les solutions pour se libérer des TOC et pensées intrusives  </h2>\n<p>Je vais détailler ici les 3 solutions principales pour se libérer de ce trouble anxieux. Pour compléter cette lecture et notamment en ce qui concerne la solution n° 2, je vous invite à naviguer dans ma rubrique développement personnel. Vous allez y trouver de nombreuses autres clés vous permettant d’aller mieux. </p>\n<h3>Se faire aider par un professionnel de la santé </h3>\n<p>Les principaux traitements des TOC résident dans la <a href=\"/psychotherapie-et-psychanalyse\" target=\"_blank\" rel=\"noopener\" title=\"Psychotherapie et psychanalyse\">thérapie comportementale et cognitive (TCC)</a> couplée à la prise d’antidépresseurs. </p>\n<p>Les TCC serviront à la personne à passer à l’action sur ce qui lui fait peur au plus haut point et ce, accompagnée de son thérapeute. Par exemple, un individu ayant l’obsession de contamination devra se laver les mains 90 fois au lieu de 100, puis 80, puis 70, etc. Quand le moment affreux de réaliser les compulsions surviendra (car il apparaîtra forcément), il devra s’armer de courage et ne pas céder. Il devra donc rester dans l’inconfort jusqu’à ce qu’il comprenne qu’il en est capable. </p>\n<p>Le thérapeute traitera également les pensées cognitives forcément erronées de la personne. Par exemple : « ma fille a 5 minutes de retard, elle a sûrement eu un problème sur la route, elle est décédée, je ne survivrais jamais ». Cette pensée catastrophiste pourrait être remplacée par : « elle est en retard depuis 5 minutes seulement. Elle est prudente, je peux lui faire confiance, elle est sortie un tas de fois et tout s’est toujours très bien passé, un accident n’est pas systématiquement mortel, etc. ». En gros, il faut dans ces moments vous forcer à trouver des réponses plus raisonnables et rationnelles, et ce, jusqu’à ce que cette nouvelle façon de voir devienne une habitude.</p>\n<p>Prendre parallèlement un <a href=\"/antidepresseurs-et-anxiolytiques\" target=\"_blank\" rel=\"noopener\" title=\"Antidepresseurs et anxiolytiques\">antidépresseur,</a> pourquoi pas ? Je suis pour seulement si la personne n’arrive pas à effectuer l’exercice. Là, le traitement servira de béquille, car il n’y a pas le choix pour avancer (mais la prise doit demeurer temporaire). Cependant, n’attendez pas qu’un médicament accomplisse des miracles si nous ne travaillez pas dur sur vous afin de vous libérer de vos croyances, blocages et traumatismes qui ont installé le TOC.</p>\n<h3>Comprendre que le TOC ne représente qu’un symptôme </h3>\n<p>En effet, le TOC ne représente qu’un symptôme, et non le problème de fond. Pour les TOC modérés, c’est assez flagrant : la personne est gonflée à bloc, ultra positive à l’idée de commencer sa thérapie. Elle arrivera donc à diminuer ses compulsions, voire à ne plus en effectuer du tout : c’est l’excitation du début. Cependant, au fil du temps, quand la routine s’installera de nouveau, l’envie d’y sombrer encore sera de plus en plus fréquente et sachez une chose. Vous craquez une fois, vous êtes foutu : Les TOC réapparaîtront en masse. Céder équivaut à avoir réalisé 10 pas en avant pour 50 en arrière… </p>\n<p>Et si un malheur surgit (ex. : vous apprenez la maladie grave d’un proche), vous pourrez être sûr que les troubles obsessionnels compulsifs referont leur apparition, vu qu’il s’agit d’un soulagement à votre anxiété trop intense. </p>\n<p>Vous devez donc pour moi traiter le vrai problème de fond pour que le TOC disparaisse pour de bon.</p>\n<h3>Envisager des traitements spécifiques </h3>\n<p>Enfin, quand les TOC demeurent beaucoup trop sévères et qu’aucun médicament ou thérapie ne fonctionne, certains traitements comme l’électrostimulation et la stimulation cérébrale profonde restent envisageables. Il convient cependant d’y penser en dernier recours seulement. </p>\n<h2>Ce qu’il faut retenir :</h2>\n<ul>\n<li aria-level=\"1\">Le TOC reste un trouble pouvant s’avérer particulièrement handicapant ;</li>\n<li aria-level=\"1\">Non traités, les<strong> TOC et pensées intrusives</strong> peuvent mener à une forte perte de confiance et d’estime de soi, ainsi qu’à la dépression ;</li>\n<li aria-level=\"1\">Le TOC regroupe généralement des obsessions et des compulsions ;</li>\n<li aria-level=\"1\">Les causes sont souvent multifactorielles ;</li>\n<li aria-level=\"1\">Les personnes souffrant de TOC sont habituellement perfectionnistes et souhaitent détenir un contrôle total sur leur vie ;</li>\n<li aria-level=\"1\">Le trouble obsessionnel compulsif peut revêtir plusieurs formes ;</li>\n<li aria-level=\"1\">Le TOC se soigne. </li>\n</ul>\n<p><a href=\"https://amzn.to/3NP31CR\">Visitez Amazon pour vous procurer le livre </a>de Vincent Trybou et de Anne-Hélène Clair « Comprendre et traiter les TOC : 3e éd. : données actuelles et nouvelles perspectives ».</p>\n<p>(Lien rémunéré par Amazon)</p>\n<p><a href=\"https://amzn.to/44Gvl0k\">Visitez Amazon pour vous procurer le livre</a> de Franck Lamagnère « TOC ou pas TOC ? Reconnaître un trouble obsessionnel compulsif et le guérir ».</p>\n<p>(Lien rémunéré par Amazon)</p>\n<a href=\"https://hypnocaments.com?partnerid=YK5muYugzSoIWDbDWRgT-Q\" title=\"Seances d hypnose en ligne\"><img decoding=\"async\" src=\"https://hypnocaments.com/image/banner_1_750.png\" alt=\"seance hypnose mp3\"></a>\n<p>Si vous aimez mon travail, vous pouvez me faire un don sur Tipeee. Même 1 euros fait toute la différence pour moi. Avec ce geste, je saurai que je vous aide un minimum sur votre chemin de développement personnel🙂</p>','published',1,'TOC et Pensées Intrusives : les Comprendre et s’en Libérer','Vous avez des TOC et pensées intrusives ? Et si vous lisiez cet article jusqu’au bout pour comprendre ce trouble anxieux et pour vous en libérer ?','https://vivre-pleinement.fr/toc-troubles-obsessionnels-compulsifs/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/toc-troubles-obsessionnels-compulsifs\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/toc-troubles-obsessionnels-compulsifs\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"TOC et Pens\\u00e9es Intrusives : les Comprendre et s\\u2019en Lib\\u00e9rer\",\"datePublished\":\"2019-06-25T19:50:21+00:00\",\"dateModified\":\"2024-02-13T19:38:37+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/toc-troubles-obsessionnels-compulsifs\\/\"},\"wordCount\":4664,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/toc-troubles-obsessionnels-compulsifs\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/06\\/TOC-pensees-intrusives.jpg\",\"articleSection\":[\"Angoisse et anxi\\u00e9t\\u00e9\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/toc-troubles-obsessionnels-compulsifs\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/toc-troubles-obsessionnels-compulsifs\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/toc-troubles-obsessionnels-compulsifs\\/\",\"name\":\"TOC et Pens\\u00e9es Intrusives : les Comprendre et s\\u2019en Lib\\u00e9rer\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/toc-troubles-obsessionnels-compulsifs\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/toc-troubles-obsessionnels-compulsifs\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/06\\/TOC-pensees-intrusives.jpg\",\"datePublished\":\"2019-06-25T19:50:21+00:00\",\"dateModified\":\"2024-02-13T19:38:37+00:00\",\"description\":\"Vous avez des TOC et pens\\u00e9es intrusives\\u2009? Et si vous lisiez cet article jusqu\\u2019au bout pour comprendre ce trouble anxieux et pour vous en lib\\u00e9rer\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/toc-troubles-obsessionnels-compulsifs\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/toc-troubles-obsessionnels-compulsifs\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/toc-troubles-obsessionnels-compulsifs\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/06\\/TOC-pensees-intrusives.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/06\\/TOC-pensees-intrusives.jpg\",\"width\":720,\"height\":720,\"caption\":\"Analyser et guerir des TOC et pensees obsessionnelles\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/toc-troubles-obsessionnels-compulsifs\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"TOC et Pens\\u00e9es Intrusives : les Comprendre et s\\u2019en Lib\\u00e9rer\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-06-25 19:50:21',NULL,'2026-05-24 19:19:46','2026-06-19 22:42:51');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (67,'Psychanalyse et Psychothérapie : Quelles Différences Entre les Deux ?','psychotherapie-et-psychanalyse','L’angoisse et l’anxiété sont des troubles qui se sont installés, au fil du temps ou suite à un trauma. Ces troubles de santé mentale peuvent devenir une vraie souffrance psychique. Ils peuvent en effet empêcher la personne de construire sa vie, de travailler, de sortir de chez elle. À force de fatigue psychologique, ce handicap peut également mener à la dépression. Pour éviter d’en arriver là, il vaut mieux prendre les choses en main au plus vite. C’est alors que les soins thérapeutiques peuvent s’avérer utiles. Vous vous trouvez dans ce cas, souhaitez vous faire aider, mais êtes submergé par le nombre incalculable des différentes techniques de bien-être se trouvant autour de vous. Vous pouvez hésiter entre deux formes de thérapie principales. Psychanalyse ou psychothérapie ? Par le biais de quelle thérapie allez-vous guérir ? \n','<p><b>L’angoisse et l’anxiété</b> sont des troubles qui se sont <b>installés</b>, au fil du temps ou suite à un <b>trauma</b>. Ces troubles de santé mentale peuvent devenir une vraie <b>souffrance psychique</b>. Ils peuvent en effet empêcher la personne de construire sa vie, de travailler, de sortir de chez elle. À force de fatigue psychologique, ce handicap peut également mener à la <b>dépression</b>. Pour éviter d’en arriver là, il vaut mieux prendre les choses en main au plus vite. C’est alors que les <b>soins thérapeutiques</b> peuvent s’avérer utiles. Vous vous trouvez dans ce cas, souhaitez vous faire aider, mais êtes submergé par le nombre incalculable des <b>différentes techniques</b> de bien-être se trouvant autour de vous. Vous pouvez hésiter entre deux formes de thérapie principales. <b>Psychanalyse ou psychothérapie ?</b> Par le biais de quelle thérapie allez-vous <b>guérir </b>?</p>\n<h2>Les préjugés sur les thérapies </h2>\n<p>N’avez-vous pas remarqué comme il est difficile de dire aux autres que vous avez déjà été voir un thérapeute ? Quand vous osez l’exprimer, certains s’inquiètent. Ils vous trouvent bizarre ou vous demandent tout de suite si vous avez un problème. Ils s’interrogent sur le pourquoi vous avez besoin d’une thérapie au lieu de parler à des proches par exemple. Donc, très souvent, les individus préfèrent le cacher, d’autant plus s’ils prennent des médicaments. Il est tout de même rare qu’une personne avoue avoir déjà consulté, même si de nos jours, probablement grâce à l’expansion du développement personnel, les gens commencent à l’assumer davantage sans crainte. </p>\n<p>D’ailleurs, où se trouve la honte à aller se faire aider au niveau du mental ? Quand vous avez une gastro par exemple, est-ce honteux de rendre visite à un médecin ? Non. Alors, pourquoi cela le serait-il avec des <a href=\"/angoisse-stress-anxiete\" target=\"_blank\" rel=\"noopener\" title=\"Angoisse stress anxiété \">problèmes anxieux</a> ? Il n’y a qu’à voir le nombre de psychologues installés et le temps qu’il faut, quelquefois, pour obtenir un rendez-vous, qui peut être trois mois plus tard. C’est que bon nombre de personnes consultent, pas vrai ?</p>\n<p>Méfiez-vous également des apparences. En entrant parfois dans des discussions plus sérieuses et plus profondes, vous vous rendrez compte que la personne en face de vous commence à se livrer et à vous avouer, par exemple, qu’elle se trouve sous antidépresseur, qu’elle consulte… alors que l’image que vous aviez d’elle laissait présager tout le contraire. Laissez donc tomber les préjugés et n’hésitez pas à consulter si c’est seulement le regard des autres qui vous fait peur.</p>\n<p>D’ailleurs, si vous souhaitez vous libérer du <strong>regard des autres,</strong> n’hésitez pas à vous tourner vers le <strong>programme</strong> de <strong>Didier PENISSARD, coach, auteur et conférencier en développement personnel.</strong> Vous pouvez le découvrir en cliquant sur le bouton ci-dessous :</p>\n<h2>Les proches ne sont pas des professionnels de la santé </h2>\n<p>Vous avez beau entendre tout autour de vous que les psychologues ne servent à rien et qu’ils sont plus fous que vous, ils restent des professionnels de la santé. Ils ont suivi de longues études pour arriver où ils sont. Ils ont d’énormes connaissances en la matière, suivent même des cours scientifiques sur la complexité du cerveau et surtout, aident énormément de personnes mal dans leur peau. Par conséquent, ils ont forcément déjà dû recevoir un cas similaire au vôtre. </p>\n<p>Ensuite, ces thérapeutes ne sont pas de votre famille et ne sont pas vos amis. Ils n’ont donc pas de gants à prendre avec vous vu qu’ils ne vous connaissent pas et ne font pas partie de votre cercle relationnel. Ils restent extrêmement objectifs, beaucoup plus que certains de vos proches. Vous arriverez ainsi plus facilement à donner du crédit à leurs paroles qu’à une personne que vous connaissez bien, où vous penserez probablement « si elle dit cela, c’est qu’elle veut me rassurer, ne pas me blesser, etc.»</p>\n<p>Certaines personnes n’osent justement pas se confier à leurs proches, de peur de leur réaction ou de les ennuyer. Le fait de tout garder en vous ne sera donc vraiment pas bon, car il faut, à un moment donné, laisser sortir vos émotions, vos souffrances. Dans ce cas, un soin thérapeutique sera effectivement le bienvenu. </p>\n<p>Enfin, certains individus ont un grand besoin de se faire rassurer et d’en parler sans cesse à leur entourage, au risque, en effet, de le fatiguer. Même s’il fait preuve, à la base, d’une grande empathie, mieux vaut également aller consulter.</p>\n<h2>Zoom sur la psychanalyse </h2>\n<p>Dans cette partie, vous allez en apprendre plus sur l’approche psychanalytique. Vous pourrez alors savoir si la spécialisation psychanalytique est faite pour vous.  </p>\n<h3>Définition de la psychanalyse </h3>\n<p>Le courant psychanalytique a été inventé par Sigmund FREUD, que vous devez tous connaître, en 1922. Elle s’oriente beaucoup plus sur l’inconscient de la personne. </p>\n<p>Dans cette thérapie, il n’y a pas vraiment d’actions à entreprendre. C’est le fameux concept du divan : le psychanalyste se tait et laisse parler l’individu durant toute la séance, et ce, afin que celui-ci puisse trouver des réponses en lui-même, à force de s’exprimer sur chaque période de sa vie. Il pourra peut-être, au fil du temps, découvrir le moment où il a refoulé une émotion dans son corps, ou un <a href=\"/traumatisme\" target=\"_blank\" rel=\"noopener\" title=\"Traumatisme\">évènement traumatique</a>, ce qui aurait enclenché les nombreux blocages qu’il peut avoir aujourd’hui…</p>\n<h3>Les patients concernés par la psychanalyse</h3>\n<p>Cette thérapie est beaucoup plus adaptée aux personnes atteintes de névrose. Tout le monde est névrosé, mais certains individus, suite à un événement, à une éducation ou à leur environnement, « décompensent » dans leur structure névrotique. De là surviennent les troubles anxieux handicapants. Elle apparaît donc utile à une personne névrosée, mais ne comprenant pas toujours très bien d’où vient son problème.</p>\n<p>Cependant, elle n’est pas spécialement conseillée pour les individus souffrant de dépressions sévères. Ceux-ci, du fait de leur maladie, sont moins à même enclins à  travailler sur eux-mêmes avec lucidité, du fait que tout leur paraît noir. Il faudra déjà soigner la dépression avant toute chose. </p>\n<img fetchpriority=\"high\" decoding=\"async\" width=\"720\" height=\"720\" src=\"/storage/blog-images/Therapeute.jpg\" alt=\"Analyse \" title=\"Thérapeute\">\n<h3>Les avantages de la psychanalyse </h3>\n<p>Cette solution permet à l’individu de s’exprimer à cœur ouvert, ce qui lui fera d’ores et déjà le plus grand bien. Elle lui permettra de dialoguer avec lui-même afin de lui faire prendre conscience de certaines choses qu’il avait refoulées, ce qui peut l’amener à la guérison. En effet, les rendez-vous avec soi ne sont pas forcément monnaie courante.</p>\n<p>Vous pouvez aussi, si vous vous en sentez capables, essayer de vous psychanalyser vous-même, en prenant un peu de temps pour vous et en vous posant les bonnes questions si cela vous suffit. Cependant, vous ne serez pas toujours objectif avec vous-même, c’est pourquoi une personne extérieure reste souvent préférable. </p>\n<h3>Les inconvénients de la psychanalyse</h3>\n<p>La cure analytique n’est pas forcément plus coûteuse qu’une autre. Cependant, le nombre de séances nécessaires peut être affreusement élevé. Une psychanalyse peut en effet durer des années, donc gare au porte-monnaie !</p>\n<h2>Focus sur la psychothérapie </h2>\n<p>Si vous pensez qu’entreprendre une psychothérapie peut constituer une solution pour retrouver le bien-être, vous pourrez en avoir confirmation en lisant ce qui suit. </p>\n<h3>Définition de la psychothérapie </h3>\n<p>On l’appelle également la thérapie comportementale et cognitive (TCC) ou thérapie brève.</p>\n<p>Solution radicalement opposée à la psychanalyse, la psychothérapie se fiche complètement du pourquoi vous vous trouvez dans cet état à l’heure actuelle. Elle souhaite vous faire atteindre rapidement vos objectifs en vous forçant à passer à l’action fréquemment et de façon répétée, et ce, malgré le mal-être que vous pouvez ressentir pendant l’exercice, jusqu’à ce que votre problème soit résolu. Il s’agit de la partie comportementale. </p>\n<p>En plus de se focaliser sur l’activité, celle-ci tente de changer les croyances de la personne en lui faisant entrevoir des pensées plus positives ou plus rationnelles, et ce, également de manière répétitive par le biais d’exercices. C’est la partie cognitive.</p>\n<h3>Les personnes intéressées par la psychothérapie </h3>\n<p>Cette solution convient bien aux troubles anxieux, mais peut surtout s’avérer efficace contre certains troubles mentaux spécifiques, tels que :</p>\n<p>– Les phobies (exemple : un individu agoraphobe aura comme exercice de sortir de plus en plus souvent et de plus en plus loin, et ce, malgré son intense mal-être à ce moment);</p>\n<p>– Les <a href=\"/toc-troubles-obsessionnels-compulsifs\" target=\"_blank\" rel=\"noopener\" title=\"Troubles obsessionnels compulsifs \">TOC</a> (exemple : une personne qui se lave les mains 100 fois par jour devra effectuer ce geste de moins en moins régulièrement sans effectuer ses rituels, et ce, malgré l’immense inconfort qu’elle aura à subir lors de ces exercices);</p>\n<p>– Les dépendances (tabagisme, alcoolisme…).</p>\n<p>Le fait de pratiquer ces activités malgré la sensation de catastrophe imminente vous prouvera qu’il n’est rien arrivé de grave finalement et surtout, que vous êtes capables de bien plus que vous ne le pensez. </p>\n<h3>Les avantages de la psychothérapie </h3>\n<p>Cette solution reste beaucoup plus rapide que la psychanalyse. Le problème peut être résolu en seulement quelques séances. Le but de la thérapie est de permettre à la personne de passer à l’action et de prendre confiance en ses capacités. L’échange avec le psychothérapeute se trouve beaucoup plus agréable, car il est beaucoup plus actif. Le suivi et les exercices qu’il donne peuvent motiver l’individu à atteindre ses objectifs. </p>\n<h3>Les inconvénients de la psychothérapie</h3>\n<p>Entamer une psychothérapie est une solution. Cependant, elle ne traite que la forme et non le fond. C’est pourquoi une personne pensant être guérie se mettra parfois à rechuter. Ce peut-être le cas de quelqu’un souffrant de TOC se remettant à ritualiser suite à un trauma, alors qu’il n’effectuait plus ces actions depuis des mois… Et il suffit de recommencer un seul et unique rituel pour que tout redémarre et quelquefois encore plus violemment. C’est parce que le problème de fond, lui, demeure toujours là. </p>\n<p>De plus, les exercices peuvent sembler tellement difficiles à réaliser pour certains qu’une prise <a href=\"/antidepresseurs-et-anxiolytiques\" target=\"_blank\" rel=\"noopener\" title=\"Antidépresseurs et anxiolytiques \">d’antidépresseurs ou d’anxiolytiques</a> est souvent couplée à cette thérapie. Prendre des médicaments ne doit pas devenir une habitude. Cette prise ne s’avère utile qu’un temps, si l’anxiété vous empêche réellement de mener une vie normale. Le médicament constituera donc une béquille temporaire permettant d’effectuer ces actions.</p>\n<img loading=\"lazy\" decoding=\"async\" width=\"860\" height=\"530\" src=\"/storage/blog-images/Therapie.jpg\" alt=\"Psychologue\" title=\"Thérapie\">\n<h2>Bien choisir sa thérapie entre psychanalyse et psychothérapie</h2>\n<p>Vous avez probablement entendu que la psychanalyse n’est plus à la mode, qu’elle est devenue inutile et chronophage. Les TCC apparaissent très tendance aujourd’hui. Il est vrai qu’elles peuvent s’avérer très bénéfiques au vu des résultats rapides qu’il peut y avoir. Pour moi, les deux ont leurs avantages et inconvénients et ne tapent pas aux mêmes endroits. L’une est plus centrée sur la forme et l’autre plus sur le fond. Je pense que les deux se complètent.</p>\n<p> Effectivement, si vous découvrez le pourquoi de vos blocages, mais que vous n’accomplissez rien pour aller mieux, le savoir n’arrangera rien. Aussi, si vous envisagez une orientation thérapeutique, mais sans comprendre les dessous du problème, vous pouvez être sûr d’une chose. Lors d’un évènement important (déménagement, décès, changement de travail, mariage, etc.), vous allez rechuter. Et peut-être encore plus que la fois précédente.  </p>\n<p> En conclusion, je trouve cela dommage qu’il y ait souvent deux écoles antagonistes prônant chacune sa méthode. Pour moi, il s’agit de deux faces d’une même pièce. Si l’une des thérapies vous apparaît plus profitable au début par rapport à votre problème, commencez par celle-ci. Envisagez ensuite l’autre solution afin de détenir toutes les cartes en main. </p>\n<p> </p>\n<p>Alors, entre<b> psychanalyse et psychothérapie</b>, avez-vous choisi ?  </p>\n<p>Si vous avez apprécié cet article, n’hésitez pas à me laisser un petit commentaire. Vous pouvez également m’écrire via le formulaire de contact si vous en ressentez le besoin et me rejoindre sur mes réseaux sociaux : </p>\n<p>Si mon travail vous aide à vous sentir mieux, vous pouvez me faire un petit donc sur Tipeee : </p>','published',1,'Psychanalyse et Psychothérapie : Quelles Différences Entre les Deux ?','Vous envisagez d\'entreprendre une thérapie. Psychanalyse ou psychothérapie ? Par le biais de quelle thérapie allez-vous guérir de vos troubles ?','https://vivre-pleinement.fr/psychotherapie-et-psychanalyse/','index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1','{\"@context\":\"https:\\/\\/schema.org\",\"@graph\":[{\"@type\":\"Article\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/psychotherapie-et-psychanalyse\\/#article\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/psychotherapie-et-psychanalyse\\/\"},\"author\":{\"name\":\"Laura B.\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"headline\":\"Psychanalyse et Psychoth\\u00e9rapie : Quelles Diff\\u00e9rences Entre les Deux\\u2009?\",\"datePublished\":\"2019-06-23T15:35:51+00:00\",\"dateModified\":\"2024-02-13T19:39:51+00:00\",\"mainEntityOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/psychotherapie-et-psychanalyse\\/\"},\"wordCount\":3956,\"commentCount\":0,\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/psychotherapie-et-psychanalyse\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/06\\/Psychanalyse-psychotherapie.jpg\",\"articleSection\":[\"D\\u00e9veloppement personnel\",\"Tous les articles\"],\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"CommentAction\",\"name\":\"Comment\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/psychotherapie-et-psychanalyse\\/#respond\"]}]},{\"@type\":\"WebPage\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/psychotherapie-et-psychanalyse\\/\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/psychotherapie-et-psychanalyse\\/\",\"name\":\"Psychanalyse et Psychoth\\u00e9rapie : Quelles Diff\\u00e9rences Entre les Deux\\u2009?\",\"isPartOf\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\"},\"primaryImageOfPage\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/psychotherapie-et-psychanalyse\\/#primaryimage\"},\"image\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/psychotherapie-et-psychanalyse\\/#primaryimage\"},\"thumbnailUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/06\\/Psychanalyse-psychotherapie.jpg\",\"datePublished\":\"2019-06-23T15:35:51+00:00\",\"dateModified\":\"2024-02-13T19:39:51+00:00\",\"description\":\"Vous envisagez d\'entreprendre une th\\u00e9rapie. Psychanalyse ou psychoth\\u00e9rapie\\u2009? Par le biais de quelle th\\u00e9rapie allez-vous gu\\u00e9rir de vos troubles\\u2009?\",\"breadcrumb\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/psychotherapie-et-psychanalyse\\/#breadcrumb\"},\"inLanguage\":\"fr-FR\",\"potentialAction\":[{\"@type\":\"ReadAction\",\"target\":[\"https:\\/\\/vivre-pleinement.fr\\/psychotherapie-et-psychanalyse\\/\"]}]},{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/psychotherapie-et-psychanalyse\\/#primaryimage\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/06\\/Psychanalyse-psychotherapie.jpg\",\"contentUrl\":\"https:\\/\\/vivre-pleinement.fr\\/wp-content\\/uploads\\/2019\\/06\\/Psychanalyse-psychotherapie.jpg\",\"width\":650,\"height\":487,\"caption\":\"Comment choisir entre psychanalyse et psychotherapie ?\"},{\"@type\":\"BreadcrumbList\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/psychotherapie-et-psychanalyse\\/#breadcrumb\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Accueil\",\"item\":\"https:\\/\\/vivre-pleinement.fr\\/\"},{\"@type\":\"ListItem\",\"position\":2,\"name\":\"Psychanalyse et Psychoth\\u00e9rapie : Quelles Diff\\u00e9rences Entre les Deux\\u2009?\"}]},{\"@type\":\"WebSite\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#website\",\"url\":\"https:\\/\\/vivre-pleinement.fr\\/\",\"name\":\"Vivre pleinement - se lib\\u00e9rer des troubles anxieux\",\"description\":\"Tous les outils pour les personnes anxieuses\",\"publisher\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\"},\"potentialAction\":[{\"@type\":\"SearchAction\",\"target\":{\"@type\":\"EntryPoint\",\"urlTemplate\":\"https:\\/\\/vivre-pleinement.fr\\/?s={search_term_string}\"},\"query-input\":{\"@type\":\"PropertyValueSpecification\",\"valueRequired\":true,\"valueName\":\"search_term_string\"}}],\"inLanguage\":\"fr-FR\"},{\"@type\":[\"Person\",\"Organization\"],\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/9531c732ed8e6dc21fabd45ef13fe956\",\"name\":\"Laura B.\",\"image\":{\"@type\":\"ImageObject\",\"inLanguage\":\"fr-FR\",\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\",\"url\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"contentUrl\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/3a3185faec01cebd9b6ceeb6932d9254cdb93d927d4808f35a2deece5c48dd11?s=96&d=mm&r=g\",\"caption\":\"Laura B.\"},\"logo\":{\"@id\":\"https:\\/\\/vivre-pleinement.fr\\/#\\/schema\\/person\\/image\\/\"}}]}','2019-06-23 15:35:51',NULL,'2026-05-24 19:19:46','2026-06-19 21:01:43');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `content`, `status`, `comments_enabled`, `seo_title`, `seo_description`, `seo_canonical`, `seo_robots`, `seo_schema_json`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES (68,'Stress, Anxiété ou Angoisse ? Les Différences Fondamentales','angoisse-stress-anxiete','Tout le monde ressent de la peur. Après tout, c’est une émotion humaine ayant aidé considérablement nos ancêtres de la préhistoire, lorsque leur survie se trouvait régulièrement en jeu. Cependant, il existe 3 types de peurs dont leur impact sur l’individu est plus ou moins prononcé. Vous avez probablement dû déjà l’expérimenter : vous ressentez un véritable mal-être, mais n’arrivez pas à mettre de mot dessus. Vous ne savez donc pas si la crainte ressentie est bénigne, passagère ou si elle est à prendre plus au sérieux. Il est de ce fait primordial de différencier ces peurs, car même si vous pouvez souffrir des trois, leur survenue reste très différente et le moyen de les gérer aussi. Stress, anxiété ou angoisse ? De quoi souffrez-vous et comment vous en libérer ? \n','<p>Tout le monde ressent de la <b>peur</b>. Après tout, c’est une émotion <b>humaine </b>ayant aidé considérablement nos ancêtres de la préhistoire, lorsque leur survie se trouvait régulièrement en jeu. Cependant, il existe <b>3</b> types de peurs dont leur <b>impact </b>sur l’individu est plus ou moins prononcé. Vous avez probablement dû déjà l’expérimenter : vous ressentez un véritable mal-être, mais n’arrivez pas à mettre de <b>mot </b>dessus. Vous ne savez donc pas si la crainte ressentie est<b> bénigne, passagère</b> ou si elle est à prendre plus au <b>sérieux</b>. Il est de ce fait primordial de <b>différencier </b>ces peurs, car même si vous pouvez souffrir des trois, leur survenue reste très différente et le moyen de les gérer aussi. <b>Stress, anxiété ou angoisse ?</b> De quoi souffrez-vous et comment vous en <b>libérer </b>? </p>\n<h2>Définition du stress </h2>\n<p>Le stress survient en vue d’un épisode stressant à venir, ou peut devenir chronique, si l’on a un travail prenant par exemple. Et la société d’aujourd’hui n’arrange pas les choses ! </p>\n<p>Nous pouvons en effet affirmer que quasiment toutes les personnes sont stressées ou connaissent des périodes d’agitation dans leur vie.</p>\n<p>Le stress peut évidemment déclencher des symptômes psychosomatiques de la même manière que l’angoisse et l’anxiété. Cependant, dès que l’événement préoccupant aura disparu ou aura été réglé, il disparaît lui aussi. C’est donc plus un désagrément ponctuel et non un trouble à proprement parler. Il existe également le « bon » stress, comme à l’approche d’un examen, d’un entretien d’embauche, d’un rencard, etc. … </p>\n<p>Il ne faut tout de même pas le sous-estimer et le traiter au plus vite, car l’individu peut à la longue s’épuiser, déclencher un burn-out et la nervosité chronique peut amener à une angoisse constante. </p>\n<a href=\"http://go.laura542.neoaid.12.1tpe.net\" rel=\"nofollow sponsored noopener\" target=\"_blank\"><img fetchpriority=\"high\" decoding=\"async\" width=\"300\" height=\"250\" src=\"/storage/blog-images/yoga_300x250.gif\" alt=\"Yoga\" title=\"yoga_300x250\"></a>\n\n<h2>Manifestation de l’anxiété </h2>\n<p>L’anxiété vient quant à elle d’un événement réel, mais la peur éprouvée est beaucoup plus exagérée. La personne se rendra excessivement malade et sera en proie à des ruminations mentales très importantes. Ce trouble sera vécu comme un véritable handicap. </p>\n<p>Il peut se définir comme suit : « mon enfant a 15 minutes de retard, que se passe-t-il ? Lui est-il arrivé quelque chose de grave ? Un accident ? Est-il mort ? Je ne pourrais survivre à cela »… En gros, il s’agit de questions que la personne se crée sans obtenir de réponse précise, ce qui engendre une énorme nervosité et beaucoup de ruminations. On peut aussi l’appeler le souci.<b> </b></p>\n<p>Elle s’inquiète pour une situation concrète. Un autre exemple : « Que va-t-il se passer au travail aujourd’hui ? Je suis seul et dois gérer bon nombre de patients, je panique et si je n’arrive pas à m’en sortir ? Et si je fais une faute lourde ? Et si on me licencie ? Comment pourrais-je subvenir aux besoins de ma famille ? On pourrait finir à la rue ! C’est terrible, je ne peux le supporter, etc. »… voyez comme les ruminations peuvent aller loin…</p>\n<p>Vous l’avez donc compris, l’anxiété est une peur consciente par rapport à une situation où vous vous inquiétez plus que de raison. Elle peut d’ailleurs se transformer en <a href=\"/trouble-anxieux-generalise\" target=\"_blank\" rel=\"noopener\" title=\"Trouble anxieux généralisé \">anxiété généralisée.</a></p>\n<h2>Description de l’angoisse  </h2>\n<p>L’angoisse, c’est un peu plus compliqué. Elle peut se définir comme suit : « tout se passe bien, je viens de finir de manger, je fais la vaisselle et tout à coup, j’ai la sensation de me trouver dans un rêve, de perdre le contrôle. J’ai des palpitations cardiaques, un sentiment d’étouffement, je commence à avoir des tremblements, j’ai peur de devenir fou. Je ressens un malaise profond. J’ai l’impression que ça n’ira jamais mieux <b>: </b>mais que m’arrive-t-il ? »</p>\n<p>L’angoisse est un mal inconscient<b>,</b> qui peut survenir sans crier gare et sans raison apparente. L’exemple décrit ci-dessus peut s’apparenter à une crise d’angoisse. Mais pourquoi ressentir une terreur imminente quand tout va bien ? </p>\n<p> Car il y a un mal-être profond installé depuis bien longtemps, bien souvent traumatique. Une souffrance refoulée. Cette souffrance peut provenir de la petite enfance, de l’adolescence et même de la naissance ou de la vie intra-utérine ! Il faut bien se dire une chose : ce n’est pas parce qu’on ne se souvient pas que le corps n’imprime pas. Là est bien le problème ! </p>\n<p>L’angoisse profonde peut d’ailleurs prendre la forme de phobie, d’agoraphobie, d’attaque de panique, de phobie sociale, de TOC (trouble obsessionnel compulsif), etc. </p>\n<img loading=\"lazy\" decoding=\"async\" width=\"960\" height=\"640\" src=\"/storage/blog-images/Nervosite.jpg\" alt=\"Agitation \" title=\"Nervosité\">\n<h2>Stress, anxiété ou angoisse : conseils pour s’en libérer </h2>\n<p>Puisque ces trois peurs comportent des différences, voyons ensemble les moyens les plus efficaces pour vous en libérer. </p>\n<h3>Soulager l’anxiété </h3>\n<p>Pour calmer l’anxiété permanente, le mieux reste d’apprendre à <a href=\"/lacher-prise-et-acceptation\" target=\"_blank\" rel=\"noopener\" title=\"Lâcher-prise et acceptation \">lâcher-prise</a>, car c’est le mental qui carbure. Il faut donc arrêter de contrôler et faire confiance à la vie. </p>\n<p>Je vous invite bien évidemment à étayer vos connaissances en allant dans la rubrique <a href=\"/category/developpement-personnel\" target=\"_blank\" rel=\"noopener\" title=\"Développement personnel \">« développement personnel »</a>. De là, vous y trouverez de nombreux articles qui vous permettront d’apprivoiser ce trouble émotionnel, de passer au-dessus et de trouver des solutions. </p>\n<h3>Calmer l’angoisse </h3>\n<p>Quand vous souffrez d’angoisse, il faut absolument comprendre d’où celle-ci provient pour aller mieux. Or, cela n’est pas toujours évident, car souvent, comme expliqué ci-dessus, cette angoisse est inconsciente. Je pense que la psychanalyse est un bon début (s’il l’on pense pouvoir trouver d’où elle peut provenir). Je vous invite à consulter <a href=\"/psychotherapie-et-psychanalyse/\" target=\"_blank\" rel=\"noopener\" title=\"Psychothérapie et psychanalyse \">l’article</a> que j’ai rédigé à ce sujet pour plus d’informations, puisque certaines personnes condamnent trop vite la cette thérapie alors que selon moi, elle semble utile dans certains cas. Vous pouvez également effectuer votre propre psychanalyse si vous vous pensez capable de vous débrouiller seul.</p>\n<p>Il faut savoir qu’une angoisse est souvent due à un traumatisme, qui n’est qu’un trauma (événement malheureux de la vie) non digéré et refoulé, revenant sans arrêt tel un fantôme et empêchant la personne de vivre sereinement.</p>\n<p>Les soins énergétiques peuvent aussi énormément aider. Le meilleur moyen de trouver un thérapeute pratiquant l’énergétique dans votre région reste le bouche-à-oreille.</p>\n<p>Enfin, l’angoisse provient de manière certaine d’une des 5 blessures de l’âme dont l’être humain peut être victime. Il s’agit des blessures de rejet, d’abandon, d’humiliation, de trahison et d’injustice. J’ai également créé des articles sur ce sujet dans la rubrique « développement personnel. » Il faudra donc découvrir les vôtres afin de pouvoir les traiter. Celles-ci peuvent être la base de vos différents traumatismes.</p>\n<h3>Réduire le stress </h3>\n<p>Puisque le stress est souvent passager, c’est dans ces moments-là qu’il faut réussir à vous accorder du temps pour vous chouchouter. Pour diminuer cette sensation de nervosité, vous pouvez : </p>\n<p></p>\n<ul>\n<li aria-level=\"1\">Apprendre à bien respirer et pratiquer des techniques de relaxation et de la méditation;</li>\n<li aria-level=\"1\">Aller marcher dans la nature;</li>\n<li aria-level=\"1\">Écouter de la musique relaxante;</li>\n<li aria-level=\"1\">Rire, car il a été démontré scientifiquement que même un faux sourire procure des émotions positives; </li>\n<li aria-level=\"1\">Écrire vos soucis sur un journal avant d’aller vous coucher : il est prouvé que l’écriture allège l’esprit;</li>\n<li aria-level=\"1\">Faire du sport, car l’activité physique libère des endorphines, hormones du bien-être.</li>\n</ul>\n<img loading=\"lazy\" decoding=\"async\" width=\"480\" height=\"720\" src=\"/storage/blog-images/Panique.jpg\" alt=\"Terreur \" title=\"Panique\">\n<p>Vous l’avez donc compris, si vous souhaitez aller mieux, il va déjà falloir trouver de quel trouble vous souffrez exactement : <b>stress, anxiété ou angoisse</b>, ou parfois les trois si vous vous trouvez dans ce cycle anxieux depuis longtemps.</p>\n<p>Ensuite, allez chercher les solutions qui figurent dans ce blog par rapport à votre problème et mettez-les en application, et ce, régulièrement. Ne vous découragez pas si vous n’allez pas en meilleure forme tout de suite, vous êtes dans une situation qui est devenue une habitude depuis peut-être des années. Il n’y a que la régularité qui vous permettra de guérir. </p>\n<p>Vous pourrez même penser quelquefois que vos efforts ont été vains, que vous rechutez et que tout cela n’a servi à rien. Une rechute est tout à fait normale. Je me répète, mais il va falloir déshabituer votre mental à ruminer de manière anxieuse et cela ne se fait pas du jour au lendemain.</p>\n<p>Enfin, si l’angoisse semble trop difficile à gérer, comme je vous l’ai déjà dit, n’hésitez surtout pas à vous faire aider par un professionnel de la santé. Vous pourrez également pratiquer en parallèle des médecines alternatives.</p>\n<p>Mais surtout, sachez que le bonheur se trouve entre vos mains. Les autres pourront vous soutenir, mais ne guériront pas vos troubles à votre place. </p>\n<p>Courage, vous allez y arriver ! </p>\n<p> </p>\n<p>Si vous avez aimé cet article, vous pouvez me laisser un petit commentaire. Et si vous désirez échanger avec moi plus en profondeur, vous pouvez m’écrire via le formulaire de contact ou me rejoindre sur mes réseaux sociaux. </p>\n<p>Si vous souhaitez me soutenir et me donner de la force car vous aimez mon travail, vous pouvez me faire un don.</p>\n<p><a href=\"https://amzn.to/41a4VB2\">Visitez Amazon pour vous procurer le livre </a>de Christophe André « Psychologie de la peur : craintes, angoisses et phobies ».</p>\n<p>(Lien rémunéré par Amazon)</p>','published',1,'Stress, Anxiété ou Angoisse ? Les Différences Fondamentales','Vous ressentez un mal-être mais n\'arrivez pas à mettre de mot dessus. Stress, anxiété ou angoisse ? De quoi souffrez-vous et comment vous en libérer ?','https://vivre-pleinement.fr/angoisse-stress-anxiete/','index, follow, 